window.BIBLE_DATA = {"meta": {"version": "krv", "translation": "개역한글", "source": "네비게이토 주제별 성경암송 카드집(5·8·60·100·180·900구절)", "verified_against": "개역한글 대조 완료 (getbible korean)", "total": 1495}, "versions": [{"id": "krv", "name": "개역한글", "year": 1961}, {"id": "kkjv", "name": "한글킹제임스", "year": 2011}, {"id": "web", "name": "WEB (English)", "year": 2000}], "defaultVersion": "krv", "collections": [{"name": "DEP 242구절", "short": "242구절 · DEP", "count": 242}, {"name": "180구절 주제별 성경 암송", "short": "180구절 · 주제별", "count": 180}, {"name": "5구절 그리스도와의 새출발", "short": "5구절 · 새출발", "count": 5}, {"name": "8구절 그리스도와의 동행", "short": "8구절 · 동행", "count": 8}, {"name": "60구절 주제별 성경 암송", "short": "60구절 · 주제별", "count": 60}, {"name": "확립 100구절", "short": "100구절 · 확립", "count": 100}, {"name": "무장 900구절", "short": "900구절 · 무장", "count": 900}], "verses": [{"id": 1, "coll": "5구절 그리스도와의 새출발", "sub": ["구원의 확신"], "book": "요한일서", "chap": 5, "verse": "11-12", "ref": "요한일서 5:11-12", "texts": {"krv": "또 증거는 이것이니 하나님이 우리에게 영생을 주신 것과 이 생명이 그의 아들 안에 있는 그것이니라 아들이 있는 자에게는 생명이 있고 하나님의 아들이 없는 자에게는 생명이 없느니라", "kkjv": "또 그 증언은 이것이니 곧 하나님께서 우리에게 영원한 생명을 주신 것과 이 생명이 그분의 아들 안에 있다는 것이니라. 아들이 있는 자에게는 생명이 있고 하나님의 아들이 없는 자에게는 생명이 없느니라.", "web": "The testimony is this, that God gave to us eternal life, and this life is in his Son. He who has the Son has the life. He who doesn’t have God’s Son doesn’t have the life."}}, {"id": 2, "coll": "5구절 그리스도와의 새출발", "sub": ["기도 응답의 확신"], "book": "요한복음", "chap": 16, "verse": "24", "ref": "요한복음 16:24", "texts": {"krv": "지금까지는 너희가 내 이름으로 아무것도 구하지 아니하였으나 구하라 그리하면 받으리니 너희 기쁨이 충만하리라", "kkjv": "지금까지는 너희가 내 이름으로 아무것도 구하지 아니하였으나 구하라. 그리하면 너희가 받으리니 이로써 너희 기쁨이 충만하리라.", "web": "Until now, you have asked nothing in my name. Ask, and you will receive, that your joy may be made full."}}, {"id": 3, "coll": "5구절 그리스도와의 새출발", "sub": ["승리의 확신"], "book": "고린도전서", "chap": 10, "verse": "13", "ref": "고린도전서 10:13", "texts": {"krv": "사람이 감당할 시험밖에는 너희에게 당한 것이 없나니 오직 하나님은 미쁘사 너희가 감당치 못할 시험당함을 허락지 아니하시고 시험당할 즈음에 또한 피할 길을 내사 너희로 능히 감당하게 하시느니라", "kkjv": "사람에게 공통적으로 있는 시험 외에는 너희가 어떤 시험도 당하지 아니하였나니 하나님은 신실하사 너희가 감당할 수 있는 것 이상으로 시험 당하는 것을 너희에게 허락하지 아니하시고 또한 그 시험과 함께 피할 길을 내사 너희가 능히 그것을 감당하게 하시느니라.", "web": "No temptation has taken you except what is common to man. God is faithful, who will not allow you to be tempted above what you are able, but will with the temptation also make the way of escape, that you may be able to endure it."}}, {"id": 4, "coll": "5구절 그리스도와의 새출발", "sub": ["사죄의 확신"], "book": "요한일서", "chap": 1, "verse": "9", "ref": "요한일서 1:9", "texts": {"krv": "만일 우리가 우리 죄를 자백하면 저는 미쁘시고 의로우사 우리 죄를 사하시며 모든 불의에서 우리를 깨끗케 하실 것이요", "kkjv": "만일 우리가 우리의 죄들을 자백하면 그분께서는 신실하시고 의로우사 우리의 죄들을 용서하시며 모든 불의에서 우리를 깨끗하게 하시느니라.", "web": "If we confess our sins, he is faithful and righteous to forgive us the sins, and to cleanse us from all unrighteousness."}}, {"id": 5, "coll": "5구절 그리스도와의 새출발", "sub": ["인도의 확신"], "book": "잠언", "chap": 3, "verse": "5-6", "ref": "잠언 3:5-6", "texts": {"krv": "너는 마음을 다하여 여호와를 의뢰하고 네 명철을 의지하지 말라 너는 범사에 그를 인정하라 그리하면 네 길을 지도하시리라", "kkjv": "¶네 마음을 다하여 주를 신뢰하고 네 자신의 명철을 의지하지 말지어다. 네 모든 길에서 그분을 인정하라. 그리하면 그분께서 네 행로들을 지도하시리라.", "web": "Trust in Yahweh with all your heart, and don’t lean on your own understanding. In all your ways acknowledge him, and he will make your paths straight."}}, {"id": 6, "coll": "8구절 그리스도와의 동행", "sub": ["그리스도 안의 생활"], "book": "요한복음", "chap": 15, "verse": "5", "ref": "요한복음 15:5", "texts": {"krv": "나는 포도나무요 너희는 가지니 저가 내 안에 내가 저 안에 있으면 이 사람은 과실을 많이 맺나니 나를 떠나서는 너희가 아무것도 할 수 없음이라", "kkjv": "나는 포도나무요 너희는 가지니라. 사람이 내 안에 거하고 내가 그 안에 거하면 바로 그 사람은 많은 열매를 맺나니 나 없이는 너희가 아무것도 할 수 없느니라.", "web": "I am the vine. You are the branches. He who remains in me, and I in him, the same bears much fruit, for apart from me you can do nothing."}}, {"id": 7, "coll": "8구절 그리스도와의 동행", "sub": ["하나님의 말씀에 의한 생활"], "book": "사도행전", "chap": 20, "verse": "32", "ref": "사도행전 20:32", "texts": {"krv": "지금 내가 너희를 주와 및 그 은혜의 말씀께 부탁하노니 그 말씀이 너희를 능히 든든히 세우사 거룩케 하심을 입은 모든 자 가운데 기업이 있게 하시리라", "kkjv": "이제 형제들아, 내가 너희를 하나님과 그분의 은혜의 말씀에 맡기노니 이 말씀이 너희를 능히 든든히 세워 거룩히 구별된 모든 자들 가운데서 너희에게 상속 유업을 주리라.", "web": "Now, brothers, I entrust you to God, and to the word of his grace, which is able to build up, and to give you the inheritance among all those who are sanctified."}}, {"id": 8, "coll": "8구절 그리스도와의 동행", "sub": ["하나님의 성령에 의한 생활"], "book": "로마서", "chap": 8, "verse": "14", "ref": "로마서 8:14", "texts": {"krv": "무릇 하나님의 영으로 인도함을 받는 그들은 곧 하나님의 아들이라", "kkjv": "하나님의 영에 의해 인도 받는 자들은 다 하나님의 아들들이니", "web": "For as many as are led by the Spirit of God, these are children of God."}}, {"id": 9, "coll": "8구절 그리스도와의 동행", "sub": ["믿음에 의한 생활"], "book": "고린도후서", "chap": 5, "verse": "7", "ref": "고린도후서 5:7", "texts": {"krv": "이는 우리가 믿음으로 행하고 보는 것으로 하지 아니함이로라", "kkjv": "(우리는 믿음으로 걷고 보는 것으로 걷지 아니하노라.)", "web": "for we walk by faith, not by sight."}}, {"id": 10, "coll": "8구절 그리스도와의 동행", "sub": ["사랑에 의한 생활"], "book": "요한일서", "chap": 4, "verse": "11", "ref": "요한일서 4:11", "texts": {"krv": "사랑하는 자들아 하나님이 이같이 우리를 사랑하셨은즉 우리도 서로 사랑하는 것이 마땅하도다", "kkjv": "사랑하는 자들아, 하나님께서 우리를 이처럼 사랑하셨은즉 우리도 서로 사랑하는 것이 마땅하니라.", "web": "Beloved, if God loved us in this way, we also ought to love one another."}}, {"id": 11, "coll": "8구절 그리스도와의 동행", "sub": ["그리스도인의 교제하는 생활"], "book": "요한일서", "chap": 1, "verse": "7", "ref": "요한일서 1:7", "texts": {"krv": "저가 빛 가운데 계신것 같이 우리도 빛 가운데 행하면 우리가 서로 사귐이 있고 그 아들 예수의 피가 우리를 모든 죄에서 깨끗하게 하실 것이요", "kkjv": "그러나 그분께서 빛 가운데 계신 것 같이 만일 우리가 빛 가운데 걸으면 우리가 서로 교제하고 또 그분의 아들 예수 그리스도의 피가 모든 죄에서 우리를 깨끗하게 하느니라.", "web": "But if we walk in the light, as he is in the light, we have fellowship with one another, and the blood of Jesus Christ, his Son, cleanses us from all sin."}}, {"id": 12, "coll": "8구절 그리스도와의 동행", "sub": ["증인으로서의 생활"], "book": "베드로전서", "chap": 3, "verse": "15", "ref": "베드로전서 3:15", "texts": {"krv": "너희 마음에 그리스도를 주로 삼아 거룩하게 하고 너희 속에 있는 소망에 관한 이유를 묻는 자에게는 대답할 것을 항상 예비하되 온유와 두려움으로 하고", "kkjv": "오직 너희 마음속에서 주 하나님을 거룩히 구별하고 너희에게 너희 속에 있는 소망의 이유를 묻는 모든 사람에게 온유함과 두려움으로 대답할 것을 항상 예비하며", "web": "But sanctify the Lord God in your hearts; and always be ready to give an answer to everyone who asks you a reason concerning the hope that is in you, with humility and fear:"}}, {"id": 13, "coll": "8구절 그리스도와의 동행", "sub": ["후히 드리는 생활"], "book": "고린도후서", "chap": 9, "verse": "7", "ref": "고린도후서 9:7", "texts": {"krv": "각각 그 마음에 정한 대로 할 것이요 인색함으로나 억지로 하지 말지니 하나님은 즐겨 내는 자를 사랑하시느니라", "kkjv": "저마다 자기 마음속에 정한 대로 낼 것이요, 마지못해 하거나 억지로 하지 말지니 하나님은 즐거이 내는 자를 사랑하시느니라.", "web": "Let each man give according as he has determined in his heart; not grudgingly, or under compulsion; for God loves a cheerful giver."}}, {"id": 14, "coll": "60구절 주제별 성경 암송", "sub": ["새로운 삶", "중심되신 그리스도"], "book": "고린도후서", "chap": 5, "verse": "17", "ref": "고린도후서 5:17", "texts": {"krv": "그런즉 누구든지 그리스도 안에 있으면 새로운 피조물이라 이전 것은 지나갔으니 보라 새것이 되었도다", "kkjv": "그런즉 누구든지 그리스도 안에 있으면 그는 새로운 창조물이라. 옛 것들은 지나갔으니, 보라, 모든 것이 새롭게 되었도다.", "web": "Therefore if anyone is in Christ, he is a new creation. The old things have passed away. Behold, all things have become new."}}, {"id": 15, "coll": "60구절 주제별 성경 암송", "sub": ["새로운 삶", "중심되신 그리스도"], "book": "갈라디아서", "chap": 2, "verse": "20", "ref": "갈라디아서 2:20", "texts": {"krv": "내가 그리스도와 함께 십자가에 못박혔나니 그런즉 이제는 내가 산 것이 아니요 오직 내 안에 그리스도께서 사신 것이라 이제 내가 육체 가운데 사는 것은 나를 사랑하사 나를 위하여 자기 몸을 버리신 하나님의 아들을 믿는 믿음 안에서 사는 것이라", "kkjv": "내가 그리스도와 함께 십자가에 못 박혀 있으나 그럼에도 불구하고 사노라. 그러나 내가 아니요 그리스도께서 내 안에 사시느니라. 나는 지금 내가 육체 안에서 사는 삶을, 나를 사랑하사 나를 위해 자신을 주신 하나님의 아들의 믿음으로 사노라.", "web": "I have been crucified with Christ, and it is no longer I that live, but Christ living in me. That life which I now live in the flesh, I live by faith in the Son of God, who loved me, and gave himself up for me."}}, {"id": 16, "coll": "60구절 주제별 성경 암송", "sub": ["새로운 삶", "그리스도께 순종"], "book": "로마서", "chap": 12, "verse": "1", "ref": "로마서 12:1", "texts": {"krv": "그러므로 형제들아 내가 하나님의 모든 자비하심으로 너희를 권하노니 너희 몸을 하나님이 기뻐하시는 거룩한 산 제사로 드리라 이는 너희의 드릴 영적 예배니라", "kkjv": "그러므로 형제들아, 내가 하나님의 긍휼을 힘입어 너희에게 간청하노니 너희는 너희 몸을 거룩하고 하나님께서 받으실 만한 살아 있는 희생물로 드리라. 그것이 너희의 합당한 섬김이니라.", "web": "Therefore I urge you, brothers, by the mercies of God, to present your bodies a living sacrifice, holy, acceptable to God, which is your spiritual service."}}, {"id": 17, "coll": "60구절 주제별 성경 암송", "sub": ["새로운 삶", "그리스도께 순종"], "book": "요한복음", "chap": 14, "verse": "21", "ref": "요한복음 14:21", "texts": {"krv": "나의 계명을 가지고 지키는 자라야 나를 사랑하는 자니 나를 사랑하는 자는 내 아버지께 사랑을 받을 것이요 나도 그를 사랑하여 그에게 나를 나타내리라", "kkjv": "내 명령들을 가지고 그것들을 지키는 자가 나를 사랑하는 자니 나를 사랑하는 자는 내 아버지께 사랑을 받을 것이요, 나도 그를 사랑하여 그에게 나를 나타내리라, 하시니라.", "web": "One who has my commandments, and keeps them, that person is one who loves me. One who loves me will be loved by my Father, and I will love him, and will reveal myself to him.”"}}, {"id": 18, "coll": "60구절 주제별 성경 암송", "sub": ["새로운 삶", "말씀"], "book": "디모데후서", "chap": 3, "verse": "16", "ref": "디모데후서 3:16", "texts": {"krv": "모든 성경은 하나님의 감동으로 된 것으로 교훈과 책망과 바르게 함과 의로 교육하기에 유익하니", "kkjv": "모든 성경 기록은 하나님의 영감으로 주신 것으로 교리와 책망과 바로잡음과 의로 교육하기에 유익하니", "web": "Every Scripture is God-breathed and profitable for teaching, for reproof, for correction, and for instruction in righteousness,"}}, {"id": 19, "coll": "60구절 주제별 성경 암송", "sub": ["새로운 삶", "말씀"], "book": "여호수아", "chap": 1, "verse": "8", "ref": "여호수아 1:8", "texts": {"krv": "이 율법책을 네 입에서 떠나지 말게 하며 주야로 그것을 묵상하여 그 가운데 기록한 대로 다 지켜 행하라 그리하면 네 길이 평탄하게 될 것이라 네가 형통하리라", "kkjv": "너는 이 율법 책을 네 입에서 떠나지 말게 하며 밤낮으로 그것을 묵상하여 그 안에 기록된 모든 것에 따라 지켜 행하라. 그리하면 네가 네 길을 형통하게 하며 또한 크게 성공하리라.", "web": "This book of the law shall not depart out of your mouth, but you shall meditate on it day and night, that you may observe to do according to all that is written therein: for then you shall make your way prosperous, and then you shall have good success."}}, {"id": 20, "coll": "60구절 주제별 성경 암송", "sub": ["새로운 삶", "기도"], "book": "요한복음", "chap": 15, "verse": "7", "ref": "요한복음 15:7", "texts": {"krv": "너희가 내 안에 거하고 내 말이 너희 안에 거하면 무엇이든지 원하는 대로 구하라 그리하면 이루리라", "kkjv": "너희가 내 안에 거하고 내 말들이 너희 안에 거하면 너희가 원하는 바를 구하라. 그러면 그것이 너희에게 이루어지리라.", "web": "If you remain in me, and my words remain in you, you will ask whatever you desire, and it will be done for you."}}, {"id": 21, "coll": "60구절 주제별 성경 암송", "sub": ["새로운 삶", "기도"], "book": "빌립보서", "chap": 4, "verse": "6-7", "ref": "빌립보서 4:6-7", "texts": {"krv": "아무것도 염려하지 말고 오직 모든 일에 기도와 간구로 너희 구할 것을 감사함으로 하나님께 아뢰라 그리하면 모든 지각에 뛰어난 하나님의 평강이 그리스도 예수 안에서 너희 마음과 생각을 지키시리라", "kkjv": "아무것도 염려하지 말고 오직 모든 일에서 기도와 간구로 너희가 요청할 것들을 감사와 더불어 하나님께 알리라. 그리하면 모든 이해를 뛰어넘는 하나님의 평강이 그리스도 예수님을 통해 너희 마음과 생각을 지키시리라.", "web": "In nothing be anxious, but in everything, by prayer and petition with thanksgiving, let your requests be made known to God. And the peace of God, which surpasses all understanding, will guard your hearts and your thoughts in Christ Jesus."}}, {"id": 22, "coll": "60구절 주제별 성경 암송", "sub": ["새로운 삶", "교제"], "book": "마태복음", "chap": 18, "verse": "20", "ref": "마태복음 18:20", "texts": {"krv": "두세 사람이 내 이름으로 모인 곳에는 나도 그들 중에 있느니라", "kkjv": "두세 사람이 내 이름으로 함께 모인 곳에 나도 거기에 그들의 한가운데 있느니라, 하시니라.", "web": "For where two or three are gathered together in my name, there I am in their midst.”"}}, {"id": 23, "coll": "60구절 주제별 성경 암송", "sub": ["새로운 삶", "교제"], "book": "히브리서", "chap": 10, "verse": "24-25", "ref": "히브리서 10:24-25", "texts": {"krv": "서로 돌아보아 사랑과 선행을 격려하며 모이기를 폐하는 어떤 사람들의 습관과 같이 하지 말고 오직 권하여 그날이 가까움을 볼수록 더욱 그리하자", "kkjv": "서로를 살펴보아 사랑과 선한 행위에 이르도록 격려하며 어떤 사람들의 습관과 같이 우리의 함께 모이는 일을 폐하지 말고 서로 권면하되 그 날이 다가옴을 너희가 볼수록 더욱 그리하자.", "web": "Let us consider how to provoke one another to love and good works, not forsaking our own assembling together, as the custom of some is, but exhorting one another; and so much the more, as you see the Day approaching."}}, {"id": 24, "coll": "60구절 주제별 성경 암송", "sub": ["새로운 삶", "증거"], "book": "마태복음", "chap": 4, "verse": "19", "ref": "마태복음 4:19", "texts": {"krv": "말씀하시되 나를 따라 오너라 내가 너희로 사람을 낚는 어부가 되게 하리라 하시니", "kkjv": "그분께서 그들에게 이르시되, 나를 따르라. 내가 너희를 사람들을 낚는 어부가 되게 하리라, 하시니", "web": "He said to them, “Come after me, and I will make you fishers for men.”"}}, {"id": 25, "coll": "60구절 주제별 성경 암송", "sub": ["새로운 삶", "증거"], "book": "로마서", "chap": 1, "verse": "16", "ref": "로마서 1:16", "texts": {"krv": "내가 복음을 부끄러워하지 아니하노니 이 복음은 모든 믿는 자에게 구원을 주시는 하나님의 능력이 됨이라 첫째는 유대인에게요 또한 헬라인에게로다", "kkjv": "내가 그리스도의 복음을 부끄러워하지 아니하노니 이는 그 복음이 믿는 모든 자를 구원에 이르게 하는 하나님의 권능이기 때문이라. 먼저는 유대인에게요 또한 그리스인에게로다.", "web": "For I am not ashamed of the Good News of Christ, for it is the power of God for salvation for everyone who believes; for the Jew first, and also for the Greek."}}, {"id": 26, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 전파함", "모든 사람이 죄를 범함"], "book": "로마서", "chap": 3, "verse": "23", "ref": "로마서 3:23", "texts": {"krv": "모든 사람이 죄를 범하였으매 하나님의 영광에 이르지 못하더니", "kkjv": "모든 사람이 죄를 지어 하나님의 영광에 이르지 못하더니", "web": "for all have sinned, and fall short of the glory of God;"}}, {"id": 27, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 전파함", "모든 사람이 죄를 범함"], "book": "이사야", "chap": 53, "verse": "6", "ref": "이사야 53:6", "texts": {"krv": "우리는 다 양 같아서 그릇 행하여 각기 제 길로 갔거늘 여호와께서는 우리 무리의 죄악을 그에게 담당시키셨도다", "kkjv": "우리는 다 양 같아서 길을 잃고 각각 자기 길로 갔거늘 주께서는 우리 모두의 불법을 그에게 담당시키셨도다.", "web": "All we like sheep have gone astray. Everyone has turned to his own way; and Yahweh has laid on him the iniquity of us all."}}, {"id": 28, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 전파함", "죄의 형벌"], "book": "로마서", "chap": 6, "verse": "23", "ref": "로마서 6:23", "texts": {"krv": "죄의 삯은 사망이요 하나님의 은사는 그리스도 예수 우리 주 안에 있는 영생이니라", "kkjv": "죄의 삯은 사망이나 하나님의 선물은 예수 그리스도 우리 주를 통해 얻는 영원한 생명이니라.", "web": "For the wages of sin is death, but the free gift of God is eternal life in Christ Jesus our Lord."}}, {"id": 29, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 전파함", "죄의 형벌"], "book": "히브리서", "chap": 9, "verse": "27", "ref": "히브리서 9:27", "texts": {"krv": "한 번 죽는 것은 사람에게 정하신 것이요 그 후에는 심판이 있으리니", "kkjv": "한 번 죽는 것은 사람들에게 정해진 것이요 이것 뒤에는 심판이 있나니", "web": "Inasmuch as it is appointed for men to die once, and after this, judgment,"}}, {"id": 30, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 전파함", "그리스도가 형벌을 받음"], "book": "로마서", "chap": 5, "verse": "8", "ref": "로마서 5:8", "texts": {"krv": "우리가 아직 죄인 되었을 때에 그리스도께서 우리를 위하여 죽으심으로 하나님께서 우리에게 대한 자기의 사랑을 확증하셨느니라", "kkjv": "우리가 아직 죄인이었을 때에 그리스도께서 우리를 위해 죽으심으로 하나님께서 우리를 향한 자신의 사랑을 당당히 제시하시느니라.", "web": "But God commends his own love toward us, in that while we were yet sinners, Christ died for us."}}, {"id": 31, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 전파함", "그리스도가 형벌을 받음"], "book": "베드로전서", "chap": 3, "verse": "18", "ref": "베드로전서 3:18", "texts": {"krv": "그리스도께서도 한 번 죄를 위하여 죽으사 의인으로서 불의한 자를 대신하셨으니 이는 우리를 하나님 앞으로 인도하려 하심이라 육체로는 죽임을 당하시고 영으로는 살리심을 받으셨으니", "kkjv": "그리스도께서도 죄들로 인하여 한 번 고난을 받으사 의로운 자로서 불의한 자를 대신하셨으니 이것은 그분께서 육체 안에서 죽임을 당하셨으되 성령으로 말미암아 살아나셔서 우리를 하나님께로 데려가려 하심이라.", "web": "Because Christ also suffered for sins once, the righteous for the unrighteous, that he might bring you to God; being put to death in the flesh, but made alive in the spirit;"}}, {"id": 32, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 전파함", "선행으로 구원받지 못함"], "book": "에베소서", "chap": 2, "verse": "8-9", "ref": "에베소서 2:8-9", "texts": {"krv": "너희가 그 은혜를 인하여 믿음으로 말미암아 구원을 얻었나니 이것이 너희에게서 난 것이 아니요 하나님의 선물이라 행위에서 난 것이 아니니 이는 누구든지 자랑치 못하게 함이니라", "kkjv": "너희가 믿음을 통해 은혜로 구원을 받았나니 그것은 너희 자신에게서 난 것이 아니요 하나님의 선물이니라. 행위에서 난 것이 아니니 이것은 아무도 자랑하지 못하게 하려 함이라.", "web": "for by grace you have been saved through faith, and that not of yourselves; it is the gift of God, not of works, that no one would boast."}}, {"id": 33, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 전파함", "선행으로 구원받지 못함"], "book": "디도서", "chap": 3, "verse": "5", "ref": "디도서 3:5", "texts": {"krv": "우리를 구원하시되 우리의 행한바 의로운 행위로 말미암지 아니하고 오직 그의 긍휼하심을 좇아 중생의 씻음과 성령의 새롭게 하심으로 하셨나니", "kkjv": "그분께서 우리를 구원하시되 우리가 행한 의로운 행위로 하지 아니하시고 오직 자신의 긍휼에 따라 다시 태어남의 씻음과 성령님의 새롭게 하심으로 하셨고", "web": "not by works of righteousness, which we did ourselves, but according to his mercy, he saved us, through the washing of regeneration and renewing by the Holy Spirit,"}}, {"id": 34, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 전파함", "그리스도를 모셔야 함"], "book": "요한복음", "chap": 1, "verse": "12", "ref": "요한복음 1:12", "texts": {"krv": "영접하는 자 곧 그 이름을 믿는 자들에게는 하나님의 자녀가 되는 권세를 주셨으니", "kkjv": "그분을 받아들인 자들 곧 그분의 이름을 믿는 자들에게는 다 하나님의 아들이 되는 권능을 그분께서 주셨으니", "web": "But as many as received him, to them he gave the right to become God’s children, to those who believe in his name:"}}, {"id": 35, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 전파함", "그리스도를 모셔야 함"], "book": "요한계시록", "chap": 3, "verse": "20", "ref": "요한계시록 3:20", "texts": {"krv": "볼지어다 내가 문 밖에 서서 두드리노니 누구든지 내 음성을 듣고 문을 열면 내가 그에게로 들어가 그로 더불어 먹고 그는 나로 더불어 먹으리라", "kkjv": "보라, 내가 문에 서서 두드리노니 누구든지 내 음성을 듣고 문을 열면 내가 그에게로 들어가 그와 함께 만찬을 먹고 그는 나와 함께 먹으리라.", "web": "Behold, I stand at the door and knock. If anyone hears my voice and opens the door, then I will come in to him, and will dine with him, and he with me."}}, {"id": 36, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 전파함", "구원의 확신"], "book": "요한일서", "chap": 5, "verse": "13", "ref": "요한일서 5:13", "texts": {"krv": "내가 하나님의 아들의 이름을 믿는 너희에게 이것을 쓴 것은 너희로 하여금 너희에게 영생이 있음을 알게 하려 함이라", "kkjv": "내가 하나님의 아들의 이름을 믿는 너희에게 이것들을 쓴 것은 너희에게 영원한 생명이 있음을 너희가 알게 하고 또 하나님의 아들의 이름을 너희가 믿게 하려 함이라.", "web": "These things I have written to you who believe in the name of the Son of God, that you may know that you have eternal life, and that you may continue to believe in the name of the Son of God."}}, {"id": 37, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 전파함", "구원의 확신"], "book": "요한복음", "chap": 5, "verse": "24", "ref": "요한복음 5:24", "texts": {"krv": "내가 진실로 진실로 너희에게 이르노니 내 말을 듣고 또 나 보내신 이를 믿는 자는 영생을 얻었고 심판에 이르지 아니하나니 사망에서 생명으로 옮겼느니라", "kkjv": "진실로 진실로 내가 너희에게 이르노니, 내 말을 듣고 또 나를 보내신 분을 믿는 자는 영존하는 생명이 있고 또 정죄에 이르지 아니하리니 사망에서 생명으로 옮겨졌느니라.", "web": "“Most certainly I tell you, he who hears my word, and believes him who sent me, has eternal life, and doesn’t come into judgment, but has passed out of death into life."}}, {"id": 38, "coll": "60구절 주제별 성경 암송", "sub": ["하나님을 의뢰함", "성령"], "book": "고린도전서", "chap": 3, "verse": "16", "ref": "고린도전서 3:16", "texts": {"krv": "너희가 하나님의 성전인 것과 하나님의 성령이 너희 안에 거하시는 것을 알지 못하느뇨", "kkjv": "너희가 하나님의 성전인 것과 하나님의 영께서 너희 안에 거하시는 것을 너희가 알지 못하느냐?", "web": "Don’t you know that you are a temple of God, and that God’s Spirit lives in you?"}}, {"id": 39, "coll": "60구절 주제별 성경 암송", "sub": ["하나님을 의뢰함", "성령"], "book": "고린도전서", "chap": 2, "verse": "12", "ref": "고린도전서 2:12", "texts": {"krv": "우리가 세상의 영을 받지 아니하고 오직 하나님께로 온 영을 받았으니 이는 우리로 하여금 하나님께서 우리에게 은혜로 주신 것들을 알게 하려 하심이라", "kkjv": "이제 우리가 세상의 영을 받지 아니하고 하나님으로부터 난 영을 받았으니 이것은 우리가 하나님께서 우리에게 값없이 주신 것들을 알게 하려 함이라.", "web": "But we received, not the spirit of the world, but the Spirit which is from God, that we might know the things that were freely given to us by God."}}, {"id": 40, "coll": "60구절 주제별 성경 암송", "sub": ["하나님을 의뢰함", "능력"], "book": "이사야", "chap": 41, "verse": "10", "ref": "이사야 41:10", "texts": {"krv": "두려워 말라 내가 너와 함께 함이니라 놀라지 말라 나는 네 하나님이 됨이니라 내가 너를 굳세게 하리라 참으로 너를 도와 주리라 참으로 나의 의로운 오른손으로 너를 붙들리라", "kkjv": "¶너는 두려워하지 말라. 내가 너와 함께하느니라. 놀라지 말라. 나는 네 하나님이니라. 내가 너를 강하게 하리라. 참으로 내가 너를 도와주리라. 참으로 내가 내 의의 오른손으로 너를 떠받쳐 주리라.", "web": "Don’t you be afraid, for I am with you. Don’t be dismayed, for I am your God. I will strengthen you. Yes, I will help you. Yes, I will uphold you with the right hand of my righteousness."}}, {"id": 41, "coll": "60구절 주제별 성경 암송", "sub": ["하나님을 의뢰함", "능력"], "book": "빌립보서", "chap": 4, "verse": "13", "ref": "빌립보서 4:13", "texts": {"krv": "내게 능력 주시는 자 안에서 내가 모든 것을 할 수 있느니라", "kkjv": "나를 강하게 하시는 그리스도를 통해 내가 모든 것을 할 수 있느니라.", "web": "I can do all things through Christ, who strengthens me."}}, {"id": 42, "coll": "60구절 주제별 성경 암송", "sub": ["하나님을 의뢰함", "성실"], "book": "예레미야애가", "chap": 3, "verse": "22-23", "ref": "예레미야애가 3:22-23", "texts": {"krv": "여호와의 자비와 긍휼이 무궁하시므로 우리가 진멸되지 아니함이니이다 이것이 아침마다 새로우니 주의 성실이 크도소이다", "kkjv": "¶주의 긍휼로 말미암아 우리가 소멸되지 아니하였으니 그분의 불쌍히 여기심은 끝이 없도다. 그것들이 아침마다 새로우니 주의 신실하심은 크시나이다.", "web": "It is because of Yahweh’s loving kindnesses that we are not consumed, because his compassion doesn’t fail. They are new every morning; great is your faithfulness."}}, {"id": 43, "coll": "60구절 주제별 성경 암송", "sub": ["하나님을 의뢰함", "성실"], "book": "민수기", "chap": 23, "verse": "19", "ref": "민수기 23:19", "texts": {"krv": "하나님은 인생이 아니시니 식언치 않으시고 인자가 아니시니 후회가 없으시도다 어찌 그 말씀하신 바를 행치 않으시며 하신 말씀을 실행치 않으시랴", "kkjv": "하나님은 사람이 아니시니 거짓말하지 아니하시고 사람의 아들이 아니시니 뜻을 돌이키지 아니하시는도다. 그분께서 말씀하셨은즉 그것을 행하지 아니하시리요? 그분께서 이르셨은즉 그것을 실행하지 아니하시리요?", "web": "God is not a man, that he should lie, nor the son of man, that he should repent. Has he said, and will he not do it? Or has he spoken, and will he not make it good?"}}, {"id": 44, "coll": "60구절 주제별 성경 암송", "sub": ["하나님을 의뢰함", "평안"], "book": "이사야", "chap": 26, "verse": "3", "ref": "이사야 26:3", "texts": {"krv": "주께서 심지가 견고한 자를 평강에 평강으로 지키시리니 이는 그가 주를 의뢰함이니이다", "kkjv": "주께서는 생각을 주께 고정시킨 자를 완전한 평강으로 지키시리니 이는 그가 주를 신뢰하기 때문이니이다.", "web": "You will keep whoever’s mind is steadfast in perfect peace, because he trusts in you."}}, {"id": 45, "coll": "60구절 주제별 성경 암송", "sub": ["하나님을 의뢰함", "평안"], "book": "베드로전서", "chap": 5, "verse": "7", "ref": "베드로전서 5:7", "texts": {"krv": "너희 염려를 다 주께 맡겨 버리라 이는 저가 너희를 권고하심이니라", "kkjv": "너희의 모든 염려를 그분께 맡기라. 그분께서 너희를 돌보시느니라.", "web": "casting all your worries on him, because he cares for you."}}, {"id": 46, "coll": "60구절 주제별 성경 암송", "sub": ["하나님을 의뢰함", "공급"], "book": "로마서", "chap": 8, "verse": "32", "ref": "로마서 8:32", "texts": {"krv": "자기 아들을 아끼지 아니하시고 우리 모든 사람을 위하여 내어주신 이가 어찌 그 아들과 함께 모든 것을 우리에게 은사로 주지 아니하시겠느뇨", "kkjv": "자신의 아들을 아끼지 아니하시고 우리 모두를 위해 그분을 내주신 분께서 어찌 그 아들과 함께 또한 모든 것을 우리에게 값없이 주지 아니하시겠느냐?", "web": "He who didn’t spare his own Son, but delivered him up for us all, how would he not also with him freely give us all things?"}}, {"id": 47, "coll": "60구절 주제별 성경 암송", "sub": ["하나님을 의뢰함", "공급"], "book": "빌립보서", "chap": 4, "verse": "19", "ref": "빌립보서 4:19", "texts": {"krv": "나의 하나님이 그리스도 예수 안에서 영광 가운데 그 풍성한 대로 너희 모든 쓸 것을 채우시리라", "kkjv": "오직 내 하나님께서 그리스도 예수님을 통해 영광 가운데서 자신의 부요하심에 따라 너희의 모든 필요를 공급하시리라.", "web": "My God will supply every need of yours according to his riches in glory in Christ Jesus."}}, {"id": 48, "coll": "60구절 주제별 성경 암송", "sub": ["하나님을 의뢰함", "유혹에서 도우심"], "book": "히브리서", "chap": 2, "verse": "18", "ref": "히브리서 2:18", "texts": {"krv": "자기가 시험을 받아 고난을 당하셨은즉 시험받는 자들을 능히 도우시느니라", "kkjv": "그분께서 친히 시험을 받아 고난을 당하셨은즉 시험받는 자들을 능히 구조하실 수 있느니라.", "web": "For in that he himself has suffered being tempted, he is able to help those who are tempted."}}, {"id": 49, "coll": "60구절 주제별 성경 암송", "sub": ["하나님을 의뢰함", "유혹에서 도우심"], "book": "시편", "chap": 119, "verse": "9,11", "ref": "시편 119:9,11", "texts": {"krv": "청년이 무엇으로 그 행실을 깨끗케 하리이까 주의 말씀을 따라 삼갈 것이니이다 내가 주께 범죄치 아니하려 하여 주의 말씀을 내 마음에 두었나이다", "kkjv": "청년이 무엇으로 자기 길을 깨끗하게 하리이까? 주의 말씀에 따라 자기 길을 조심함으로 하리이다. 내가 주께 죄를 짓지 아니하려고 주의 말씀을 내 마음속에 숨겼나이다.", "web": "How can a young man keep his way pure? By living according to your word. I have hidden your word in my heart, that I might not sin against you."}}, {"id": 50, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도 제자의 자격", "그리스도를 첫자리에 모심"], "book": "마태복음", "chap": 6, "verse": "33", "ref": "마태복음 6:33", "texts": {"krv": "너희는 먼저 그의 나라와 그의 의를 구하라 그리하면 이 모든 것을 너희에게 더하시리라", "kkjv": "오직 너희는 첫째로 하나님의 왕국과 그분의 의를 구하라. 그리하면 이 모든 것을 너희에게 더하시리라.", "web": "But seek first God’s Kingdom, and his righteousness; and all these things will be given to you as well."}}, {"id": 51, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도 제자의 자격", "그리스도를 첫자리에 모심"], "book": "누가복음", "chap": 9, "verse": "23", "ref": "누가복음 9:23", "texts": {"krv": "또 무리에게 이르시되 아무든지 나를 따라 오려거든 자기를 부인하고 날마다 제 십자가를 지고 나를 좇을 것이니라", "kkjv": "¶또 그분께서 그들 모두에게 이르시되, 어떤 사람이 나를 따라오려거든 자기를 부인하고 날마다 자기 십자가를 지고 나를 따를지니라.", "web": "He said to all, “If anyone desires to come after me, let him deny himself, take up his cross,and follow me."}}, {"id": 52, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도 제자의 자격", "죄에서 떠남"], "book": "요한일서", "chap": 2, "verse": "15-16", "ref": "요한일서 2:15-16", "texts": {"krv": "이 세상이나 세상에 있는 것들을 사랑치 말라 누구든지 세상을 사랑하면 아버지의 사랑이 그 속에 있지 아니하니 이는 세상에 있는 모든 것이 육신의 정욕과 안목의 정욕과 이생의 자랑이니 다 아버지께로 좇아 온 것이 아니요 세상으로 좇아 온 것이라", "kkjv": "세상이나 세상에 있는 것들을 사랑하지 말라. 어떤 사람이 세상을 사랑하면 아버지의 사랑이 그 속에 있지 아니하니 세상에 있는 모든 것 즉 육신의 정욕과 안목의 정욕과 인생의 자랑은 아버지에게서 나지 아니하고 세상에서 나느니라.", "web": "Don’t love the world, neither the things that are in the world. If anyone loves the world, the Father’s love isn’t in him. For all that is in the world, the lust of the flesh, the lust of the eyes, and the pride of life, isn’t the Father’s, but is the world’s."}}, {"id": 53, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도 제자의 자격", "죄에서 떠남"], "book": "로마서", "chap": 12, "verse": "2", "ref": "로마서 12:2", "texts": {"krv": "너희는 이 세대를 본받지 말고 오직 마음을 새롭게 함으로 변화를 받아 하나님의 선하시고 기뻐하시고 온전하신 뜻이 무엇인지 분별하도록 하라", "kkjv": "너희는 이 세상에 동화되지 말고 오직 너희 생각을 새롭게 함으로 변화를 받아 하나님의 그 선하시고 받으실 만하며 완전하신 뜻이 무엇인지 입증하도록 하라.", "web": "Don’t be conformed to this world, but be transformed by the renewing of your mind, so that you may prove what is the good, well-pleasing, and perfect will of God."}}, {"id": 54, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도 제자의 자격", "견고함"], "book": "고린도전서", "chap": 15, "verse": "58", "ref": "고린도전서 15:58", "texts": {"krv": "그러므로 내 사랑하는 형제들아 견고하며 흔들리지 말며 항상 주의 일에 더욱 힘쓰는 자들이 되라 이는 너희 수고가 주 안에서 헛되지 않은 줄을 앎이니라", "kkjv": "그러므로 내 사랑하는 형제들아, 너희는 굳게 서서 흔들리지 말고 항상 주의 일을 넘치게 하라. 너희 수고가 주 안에서 헛되지 않은 줄 너희가 아느니라.", "web": "Therefore, my beloved brothers, be steadfast, immovable, always abounding in the Lord’s work, because you know that your labor is not in vain in the Lord."}}, {"id": 55, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도 제자의 자격", "견고함"], "book": "히브리서", "chap": 12, "verse": "3", "ref": "히브리서 12:3", "texts": {"krv": "너희가 피곤하여 낙심치 않기 위하여 죄인들의 이같이 자기에게 거역한 일을 참으신 자를 생각하라", "kkjv": "죄인들이 자기를 대적하여 이처럼 거역한 것을 견디어 내신 분을 깊이 생각할지니 이것은 너희가 너희 생각 속에서 지치고 기진하지 아니하게 하려 함이라.", "web": "For consider him who has endured such contradiction of sinners against himself, that you don’t grow weary, fainting in your souls."}}, {"id": 56, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도 제자의 자격", "다른 사람을 섬김"], "book": "마가복음", "chap": 10, "verse": "45", "ref": "마가복음 10:45", "texts": {"krv": "인자의 온 것은 섬김을 받으려 함이 아니라 도리어 섬기려 하고 자기 목숨을 많은 사람의 대속물로 주려 함이니라", "kkjv": "사람의 아들은 섬김을 받으러 오지 아니하고 도리어 섬기며 자기 생명을 많은 사람의 대속물로 주려고 왔느니라, 하시니라.", "web": "For the Son of Man also came not to be served, but to serve, and to give his life as a ransom for many.”"}}, {"id": 57, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도 제자의 자격", "다른 사람을 섬김"], "book": "고린도후서", "chap": 4, "verse": "5", "ref": "고린도후서 4:5", "texts": {"krv": "우리가 우리를 전파하는 것이 아니라 오직 그리스도 예수의 주 되신 것과 또 예수를 위하여 우리가 너희의 종 된 것을 전파함이라", "kkjv": "우리는 우리 자신을 선포하지 아니하며 오직 주 되신 그리스도 예수님과 또 예수님으로 인하여 너희의 종 된 우리 자신을 선포하노니", "web": "For we don’t preach ourselves, but Christ Jesus as Lord, and ourselves as your servants for Jesus’ sake;"}}, {"id": 58, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도 제자의 자격", "후히 드릴 것"], "book": "잠언", "chap": 3, "verse": "9-10", "ref": "잠언 3:9-10", "texts": {"krv": "네 재물과 네 소산물의 처음 익은 열매로 여호와를 공경하라 그리하면 네 창고가 가득히 차고 네 즙틀에 새 포도즙이 넘치리라", "kkjv": "네 재물과 네 모든 소출의 첫 열매로 주를 공경하라. 그리하면 네 창고가 가득히 차고 네 포도즙 틀이 새 포도즙으로 터져 넘치리라.", "web": "Honor Yahweh with your substance, with the first fruits of all your increase: so your barns will be filled with plenty, and your vats will overflow with new wine."}}, {"id": 59, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도 제자의 자격", "후히 드릴 것"], "book": "고린도후서", "chap": 9, "verse": "6-7", "ref": "고린도후서 9:6-7", "texts": {"krv": "이것이 곧 적게 심는 자는 적게 거두고 많이 심는 자는 많이 거둔다 하는 말이로다 각각 그 마음에 정한 대로 할 것이요 인색함으로나 억지로 하지 말지니 하나님은 즐겨 내는 자를 사랑하시느니라", "kkjv": "다만 내가 말하려는 바는 이것이니 곧 인색하게 뿌리는 자는 또한 인색하게 거둘 것이요, 풍성하게 뿌리는 자는 또한 풍성하게 거두리라는 것이라. 저마다 자기 마음속에 정한 대로 낼 것이요, 마지못해 하거나 억지로 하지 말지니 하나님은 즐거이 내는 자를 사랑하시느니라.", "web": "Remember this: he who sows sparingly will also reap sparingly. He who sows bountifully will also reap bountifully. Let each man give according as he has determined in his heart; not grudgingly, or under compulsion; for God loves a cheerful giver."}}, {"id": 60, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도 제자의 자격", "세계 비전"], "book": "사도행전", "chap": 1, "verse": "8", "ref": "사도행전 1:8", "texts": {"krv": "오직 성령이 너희에게 임하시면 너희가 권능을 받고 예루살렘과 온 유대와 사마리아와 땅 끝까지 이르러 내 증인이 되리라 하시니라", "kkjv": "오직 성령님께서 너희에게 임하신 뒤에 너희가 권능을 받고 예루살렘과 온 유대와 사마리아에서 그리고 땅의 맨 끝 지역까지 이르러 나를 위한 증인이 되리라, 하시니라.", "web": "But you will receive power when the Holy Spirit has come upon you. You will be witnesses to me in Jerusalem, in all Judea and Samaria, and to the uttermost parts of the earth.”"}}, {"id": 61, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도 제자의 자격", "세계 비전"], "book": "마태복음", "chap": 28, "verse": "19-20", "ref": "마태복음 28:19-20", "texts": {"krv": "그러므로 너희는 가서 모든 족속으로 제자를 삼아 아버지와 아들과 성령의 이름으로 세례를 주고 내가 너희에게 분부한 모든 것을 가르쳐 지키게 하라 볼지어다 내가 세상 끝날까지 너희와 항상 함께 있으리라 하시니라", "kkjv": "¶그러므로 너희는 가서 모든 민족들을 가르치고 아버지와 아들과 성령의 이름으로 그들에게 침례를 주며 무엇이든지 내가 너희에게 명령한 모든 것을 그들에게 가르쳐 지키게 하라. 보라, 내가 세상의 끝까지 항상 너희와 함께 있느니라, 하시니라. 아멘.", "web": "Go,and make disciples of all nations, baptizing them in the name of the Father and of the Son and of the Holy Spirit, teaching them to observe all things that I commanded you. Behold, I am with you always, even to the end of the age.” Amen."}}, {"id": 62, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 닮아감", "사랑"], "book": "요한복음", "chap": 13, "verse": "34-35", "ref": "요한복음 13:34-35", "texts": {"krv": "새 계명을 너희에게 주노니 서로 사랑하라 내가 너희를 사랑한것 같이 너희도 서로 사랑하라 너희가 서로 사랑하면 이로써 모든 사람이 너희가 내 제자인 줄 알리라", "kkjv": "내가 새 명령을 너희에게 주노니 너희는 서로 사랑하라. 내가 너희를 사랑한 것 같이 너희도 서로 사랑하라. 너희가 서로 사랑하면 이로써 모든 사람이 너희가 내 제자인 줄 알리라, 하시니라.", "web": "A new commandment I give to you, that you love one another, just like I have loved you; that you also love one another. By this everyone will know that you are my disciples, if you have love for one another.”"}}, {"id": 63, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 닮아감", "사랑"], "book": "요한일서", "chap": 3, "verse": "18", "ref": "요한일서 3:18", "texts": {"krv": "자녀들아 우리가 말과 혀로만 사랑하지 말고 오직 행함과 진실함으로 하자", "kkjv": "나의 어린 자녀들아, 우리가 말과 혀로만 사랑하지 말고 오직 행함과 진실함으로 하자.", "web": "My little children, let’s not love in word only, neither with the tongue only, but in deed and truth."}}, {"id": 64, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 닮아감", "겸손"], "book": "빌립보서", "chap": 2, "verse": "3-4", "ref": "빌립보서 2:3-4", "texts": {"krv": "아무 일에든지 다툼이나 허영으로 하지 말고 오직 겸손한 마음으로 각각 자기보다 남을 낫게 여기고 각각 자기 일을 돌아볼 뿐더러 또한 각각 다른 사람들의 일을 돌아보아 나의 기쁨을 충만케 하라", "kkjv": "어떤 일도 다툼이나 헛된 영광으로 하지 말고 오직 겸손한 생각으로 각각 자기보다 남을 더 낫게 여기며 각 사람이 자기 일들만 돌아보지 말고 각 사람이 남의 일들도 돌아보라.", "web": "doing nothing through rivalry or through conceit, but in humility, each counting others better than himself; each of you not just looking to his own things, but each of you also to the things of others."}}, {"id": 65, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 닮아감", "겸손"], "book": "베드로전서", "chap": 5, "verse": "5-6", "ref": "베드로전서 5:5-6", "texts": {"krv": "젊은 자들아 이와 같이 장로들에게 순복하고 다 서로 겸손으로 허리를 동이라 하나님이 교만한 자를 대적하시되 겸손한 자들에게는 은혜를 주시느니라 그러므로 하나님의 능하신 손 아래서 겸손하라 때가 되면 너희를 높이시리라", "kkjv": "너희 젊은 사람들아, 이와 같이 장로에게 복종하고 참으로 너희가 다 서로에게 복종하며 겸손으로 옷 입으라. 하나님께서 교만한 자는 물리치시고 겸손한 자에게는 은혜를 주시느니라. 그러므로 하나님의 강한 손 밑에서 스스로 겸손하라. 그리하면 정하신 때에 그분께서 너희를 높이시리라.", "web": "Likewise, you younger ones, be subject to the elder. Yes, all of you clothe yourselves with humility, to subject yourselves to one another; for “God resists the proud, but gives grace to the humble.” Humble yourselves therefore under the mighty hand of God, that he may exalt you in due time;"}}, {"id": 66, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 닮아감", "순결"], "book": "에베소서", "chap": 5, "verse": "3", "ref": "에베소서 5:3", "texts": {"krv": "음행과 온갖 더러운 것과 탐욕은 너희 중에서 그 이름이라도 부르지 말라 이는 성도의 마땅한 바니라", "kkjv": "오직 음행과 모든 부정한 것과 혹은 탐욕은 너희 가운데서 한 번이라도 그 이름조차 부르지 말라. 그것이 성도에게 합당하니라.", "web": "But sexual immorality, and all uncleanness, or covetousness, let it not even be mentioned among you, as becomes saints;"}}, {"id": 67, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 닮아감", "순결"], "book": "베드로전서", "chap": 2, "verse": "11", "ref": "베드로전서 2:11", "texts": {"krv": "사랑하는 자들아 나그네와 행인 같은 너희를 권하노니 영혼을 거스려 싸우는 육체의 정욕을 제어하라", "kkjv": "극진히 사랑하는 자들아, 나그네와 순례자인 너희에게 내가 간청하노니 혼을 대적하여 싸우는 육체의 정욕들을 삼가라.", "web": "Beloved, I beg you as foreigners and pilgrims, to abstain from fleshly lusts, which war against the soul;"}}, {"id": 68, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 닮아감", "정직"], "book": "레위기", "chap": 19, "verse": "11", "ref": "레위기 19:11", "texts": {"krv": "너희는 도적질하지 말며 속이지 말며 서로 거짓말하지 말며", "kkjv": "¶너희는 도둑질하지 말고 거짓으로 행하지 말며 서로 거짓말하지 말라.", "web": "“‘You shall not steal.   “‘You shall not lie.   “‘You shall not deceive one another."}}, {"id": 69, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 닮아감", "정직"], "book": "사도행전", "chap": 24, "verse": "16", "ref": "사도행전 24:16", "texts": {"krv": "이것을 인하여 나도 하나님과 사람을 대하여 항상 양심에 거리낌이 없기를 힘쓰노라", "kkjv": "이 소망 속에서 나는 하나님과 사람들을 향하여 항상 양심에 실족하게 하는 일이 없도록 스스로 힘쓰나이다.", "web": "Herein I also practice always having a conscience void of offense toward God and men."}}, {"id": 70, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 닮아감", "믿음"], "book": "히브리서", "chap": 11, "verse": "6", "ref": "히브리서 11:6", "texts": {"krv": "믿음이 없이는 기쁘시게 못하나니 하나님께 나아가는 자는 반드시 그가 계신 것과 또한 그가 자기를 찾는 자들에게 상 주시는 이심을 믿어야 할지니라", "kkjv": "그러나 믿음이 없이는 하나님을 기쁘게 하지 못하나니 그분께 가는 자는 반드시 그분께서 계시는 것과 또 그분께서 부지런히 자신을 찾는 자들에게 보상해 주시는 분이심을 믿어야 하느니라.", "web": "Without faith it is impossible to be well pleasing to him, for he who comes to God must believe that he exists, and that he is a rewarder of those who seek him."}}, {"id": 71, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 닮아감", "믿음"], "book": "로마서", "chap": 4, "verse": "20-21", "ref": "로마서 4:20-21", "texts": {"krv": "믿음이 없어 하나님의 약속을 의심치 않고 믿음에 견고하여져서 하나님께 영광을 돌리며 약속하신 그것을 또한 능히 이루실 줄을 확신하였으니", "kkjv": "믿지 아니함으로써 하나님의 약속에 관하여 흔들리지 아니하고 오히려 믿음이 강해져서 하나님께 영광을 돌리며 그분께서 약속하신 것을 그분께서 또한 능히 이행하실 줄로 온전히 확신하였으니", "web": "Yet, looking to the promise of God, he didn’t waver through unbelief, but grew strong through faith, giving glory to God, and being fully assured that what he had promised, he was also able to perform."}}, {"id": 72, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 닮아감", "선행"], "book": "갈라디아서", "chap": 6, "verse": "9-10", "ref": "갈라디아서 6:9-10", "texts": {"krv": "우리가 선을 행하되 낙심하지 말지니 피곤하지 아니하면 때가 이르매 거두리라 그러므로 우리는 기회 있는 대로 모든 이에게 착한 일을 하되 더욱 믿음의 가정들에게 할지니라", "kkjv": "우리가 잘 행하는 가운데 지치지 말지니 우리가 기진하지 아니하면 정하신 때에 거두리라. 그러므로 우리는 기회 있는 대로 모든 사람에게 선을 행하되 특히 믿음의 집안에 속한 자들에게 할지니라.", "web": "Let us not be weary in doing good, for we will reap in due season, if we don’t give up. So then, as we have opportunity, let’s do what is good toward all men, and especially toward those who are of the household of the faith."}}, {"id": 73, "coll": "60구절 주제별 성경 암송", "sub": ["그리스도를 닮아감", "선행"], "book": "마태복음", "chap": 5, "verse": "16", "ref": "마태복음 5:16", "texts": {"krv": "이같이 너희 빛을 사람 앞에 비취게 하여 저희로 너희 착한 행실을 보고 하늘에 계신 너희 아버지께 영광을 돌리게 하라", "kkjv": "이와 같이 너희 빛을 사람들 앞에 비추어 그들이 너희의 선한 행위를 보고 하늘에 계신 너희 아버지께 영광을 돌리게 하라.", "web": "Even so, let your light shine before men; that they may see your good works, and glorify your Father who is in heaven."}}, {"id": 74, "coll": "확립 100구절", "sub": ["세움을 입음"], "book": "골로새서", "chap": 2, "verse": "6-7", "ref": "골로새서 2:6-7", "texts": {"krv": "그러므로 너희가 그리스도 예수를 주로 받았으니 그 안에서 행하되 그 안에 뿌리를 박으며 세움을 입어 교훈을 받은 대로 믿음에 굳게 서서 감사함을 넘치게 하라", "kkjv": "그러므로 너희가 주 곧 그리스도 예수님을 받아들였듯이 그렇게 그분 안에서 걷되 그분 안에서 뿌리를 내리고 세워지며 가르침을 받은 대로 믿음 안에 굳게 서서 그 안에서 넘치도록 감사를 드리라.", "web": "As therefore you received Christ Jesus, the Lord, walk in him, rooted and built up in him, and established in the faith, even as you were taught, abounding in it in thanksgiving."}}, {"id": 75, "coll": "확립 100구절", "sub": ["장성한 자"], "book": "히브리서", "chap": 5, "verse": "13-14", "ref": "히브리서 5:13-14", "texts": {"krv": "대저 젖을 먹는 자마다 어린아이니 의의 말씀을 경험하지 못한 자요 단단한 식물은 장성한 자의 것이니 저희는 지각을 사용하므로 연단을 받아 선악을 분변하는 자들이니라", "kkjv": "젖을 사용하는 자마다 갓난아이이므로 의의 말씀에 능숙하지 못하니라. 그러나 단단한 음식은 장성한 자들에게 속하나니 그들은 그것을 사용하여 자기 감각들을 단련시킴으로 선악을 분별하느니라.", "web": "For everyone who lives on milk is not experienced in the word of righteousness, for he is a baby. But solid food is for those who are full grown, who by reason of use have their senses exercised to discern good and evil."}}, {"id": 76, "coll": "확립 100구절", "sub": ["은혜 안의 성장"], "book": "베드로후서", "chap": 3, "verse": "18", "ref": "베드로후서 3:18", "texts": {"krv": "오직 우리 주 곧 구주 예수 그리스도의 은혜와 저를 아는 지식에서 자라가라 영광이 이제와 영원한 날까지 저에게 있을지어다", "kkjv": "오직 은혜 안에서 자라고 우리 주 곧 구원자 예수 그리스도를 아는 것에서 자라라. 그분께 영광이 이제와 영원토록 있기를 원하노라. 아멘.", "web": "But grow in the grace and knowledge of our Lord and Savior Jesus Christ. To him be the glory both now and forever. Amen."}}, {"id": 77, "coll": "확립 100구절", "sub": ["믿음 위의 건축"], "book": "유다서", "chap": 1, "verse": "20-21", "ref": "유다서 1:20-21", "texts": {"krv": "사랑하는 자들아 너희는 너희의 지극히 거룩한 믿음 위에 자기를 건축하며 성령으로 기도하며 하나님의 사랑 안에서 자기를 지키며 영생에 이르도록 우리 주 예수 그리스도의 긍휼을 기다리라", "kkjv": "그러나 사랑하는 자들아, 너희는 너희의 지극히 거룩한 믿음 위에 너희 자신을 세우며 성령님 안에서 기도하고 하나님의 사랑 안에서 너희 자신을 지키며 영원한 생명에 이르도록 우리 주 예수 그리스도의 긍휼을 기다리라.", "web": "But you, beloved, keep building up yourselves on your most holy faith, praying in the Holy Spirit. Keep yourselves in the love of God, looking for the mercy of our Lord Jesus Christ to eternal life."}}, {"id": 78, "coll": "확립 100구절", "sub": ["구원의 확신", "죄사함"], "book": "이사야", "chap": 1, "verse": "18", "ref": "이사야 1:18", "texts": {"krv": "여호와께서 말씀하시되 오라 우리가 서로 변론하자 너희 죄가 주홍 같을지라도 눈과 같이 희어질 것이요 진홍 같이 붉을지라도 양털 같이 되리라", "kkjv": "주가 말하노라. 이제 오라. 우리가 함께 변론하자. 너희 죄들이 주홍 같을지라도 눈같이 희게 될 것이요, 진홍같이 붉을지라도 양털같이 되리라.", "web": "“Come now, and let us reason together,” says Yahweh: “Though your sins be as scarlet, they shall be as white as snow. Though they be red like crimson, they shall be as wool."}}, {"id": 79, "coll": "확립 100구절", "sub": ["구원의 확신", "허물을 도말함"], "book": "이사야", "chap": 43, "verse": "25", "ref": "이사야 43:25", "texts": {"krv": "나 곧 나는 나를 위하여 네 허물을 도말하는 자니 네 죄를 기억지 아니하리라", "kkjv": "나 곧 나는 내 자신을 위하여 네 범법들을 지워 버리는 자니 내가 네 죄들을 기억하지 아니하리라.", "web": "I, even I, am he who blots out your transgressions for my own sake; and I will not remember your sins."}}, {"id": 80, "coll": "확립 100구절", "sub": ["구원의 확신", "십자가 구속"], "book": "이사야", "chap": 53, "verse": "5", "ref": "이사야 53:5", "texts": {"krv": "그가 찔림은 우리의 허물을 인함이요 그가 상함은 우리의 죄악을 인함이라 그가 징계를 받음으로 우리가 평화를 누리고 그가 채찍에 맞음으로 우리가 나음을 입었도다", "kkjv": "그러나 그는 우리의 범법들로 인해 부상을 당하고 우리의 불법들로 인해 상하였노라. 그가 징벌을 받음으로 우리가 화평을 누리고 그가 채찍에 맞음으로 우리가 고침을 받았도다.", "web": "But he was pierced for our transgressions. He was crushed for our iniquities. The punishment that brought our peace was on him; and by his wounds we are healed."}}, {"id": 81, "coll": "확립 100구절", "sub": ["구원의 확신", "신앙 고백"], "book": "마태복음", "chap": 16, "verse": "16-17", "ref": "마태복음 16:16-17", "texts": {"krv": "시몬 베드로가 대답하여 가로되 주는 그리스도시요 살아 계신 하나님의 아들이시니이다 예수께서 대답하여 가라사대 바요나 시몬아 네가 복이 있도다 이를 네게 알게 한 이는 혈육이 아니요 하늘에 계신 내 아버지시니라", "kkjv": "시몬 베드로가 대답하여 이르되, 주는 그리스도시요 살아 계신 하나님의 아들이시니이다, 하매 예수님께서 그에게 응답하여 이르시되, 바요나 시몬아, 네가 복이 있도다. 그것을 네게 계시한 이는 살과 피가 아니요 하늘에 계신 내 아버지시니라.", "web": "Simon Peter answered, “You are the Christ, the Son of the living God.” Jesus answered him, “Blessed are you, Simon Bar Jonah, for flesh and blood has not revealed this to you, but my Father who is in heaven."}}, {"id": 82, "coll": "확립 100구절", "sub": ["구원의 확신", "하나님의 사랑"], "book": "요한복음", "chap": 3, "verse": "16", "ref": "요한복음 3:16", "texts": {"krv": "하나님이 세상을 이처럼 사랑하사 독생자를 주셨으니 이는 저를 믿는 자마다 멸망치 않고 영생을 얻게 하려 하심이니라", "kkjv": "¶하나님께서 세상을 이처럼 사랑하사 자신의 독생자를 주셨으니 이것은 누구든지 그를 믿는 자는 멸망하지 않고 영존하는 생명을 얻게 하려 하심이라.", "web": "For God so loved the world, that he gave his one and only Son, that whoever believes in him should not perish, but have eternal life."}}, {"id": 83, "coll": "확립 100구절", "sub": ["구원의 확신", "하나님의 뜻"], "book": "요한복음", "chap": 6, "verse": "40", "ref": "요한복음 6:40", "texts": {"krv": "내 아버지의 뜻은 아들을 보고 믿는 자마다 영생을 얻는 이것이니 마지막 날에 내가 이를 다시 살리리라 하시니라", "kkjv": "나를 보내신 분의 뜻은 이것이니 곧 아들을 보고 그를 믿는 모든 자가 영존하는 생명을 얻는 것이니라. 마지막 날에 내가 그를 일으키리라, 하시니라.", "web": "This is the will of the one who sent me, that everyone who sees the Son, and believes in him, should have eternal life; and I will raise him up at the last day.”"}}, {"id": 84, "coll": "확립 100구절", "sub": ["구원의 확신", "길 진리 생명"], "book": "요한복음", "chap": 14, "verse": "6", "ref": "요한복음 14:6", "texts": {"krv": "예수께서 가라사대 내가 곧 길이요 진리요 생명이니 나로 말미암지 않고는 아버지께로 올 자가 없느니라", "kkjv": "예수님께서 그에게 이르시되, 내가 곧 길이요 진리요 생명이니 나를 통하지 않고는 아무도 아버지께 오지 못하느니라.", "web": "Jesus said to him, “I am the way, the truth, and the life. No one comes to the Father, except through me."}}, {"id": 85, "coll": "확립 100구절", "sub": ["구원의 확신", "구원의 조건"], "book": "사도행전", "chap": 2, "verse": "21", "ref": "사도행전 2:21", "texts": {"krv": "누구든지 주의 이름을 부르는 자는 구원을 얻으리라 하였느니라", "kkjv": "누구든지 주의 이름을 부르는 자는 구원을 받으리라, 하였느니라.", "web": "It will be, that whoever will call on the name of the Lord will be saved.’"}}, {"id": 86, "coll": "확립 100구절", "sub": ["구원의 확신", "오직 예수"], "book": "사도행전", "chap": 4, "verse": "12", "ref": "사도행전 4:12", "texts": {"krv": "다른 이로서는 구원을 얻을 수 없나니 천하 인간에 구원을 얻을 만한 다른 이름을 우리에게 주신 일이 없음이니라 하였더라", "kkjv": "다른 사람 안에는 구원이 없나니 하늘 아래에서 우리를 구원할 다른 이름을 사람들 가운데 주지 아니하셨느니라, 하였더라.", "web": "There is salvation in none other, for neither is there any other name under heaven, that is given among men, by which we must be saved!”"}}, {"id": 87, "coll": "확립 100구절", "sub": ["구원의 확신", "성령의 법"], "book": "로마서", "chap": 8, "verse": "1-2", "ref": "로마서 8:1-2", "texts": {"krv": "그러므로 이제 그리스도 예수 안에 있는 자에게는 결코 정죄함이 없나니 이는 그리스도 예수 안에 있는 생명의 성령의 법이 죄와 사망의 법에서 너를 해방하였음이라", "kkjv": "그러므로 이제 그리스도 예수님 안에 있는 자들에게는 정죄함이 없나니 그들은 육신을 따라 걷지 아니하고 성령을 따라 걷느니라. 이는 그리스도 예수님 안에 있는 생명의 성령의 법이 죄와 사망의 법에서 나를 해방시켰기 때문이라.", "web": "There is therefore now no condemnation to those who are in Christ Jesus, who don’t walk according to the flesh, but according to the Spirit. For the law of the Spirit of life in Christ Jesus made me free from the law of sin and of death."}}, {"id": 88, "coll": "확립 100구절", "sub": ["구원의 확신", "구원의 확증"], "book": "고린도후서", "chap": 13, "verse": "5", "ref": "고린도후서 13:5", "texts": {"krv": "너희가 믿음에 있는가 너희 자신을 시험하고 너희 자신을 확증하라 예수 그리스도께서 너희 안에 계신 줄을 너희가 스스로 알지 못하느냐 그렇지 않으면 너희가 버리운 자니라", "kkjv": "너희가 믿음 안에 있는지 너희 자신을 살펴보고 너희 자신을 입증하라. 예수 그리스도께서 너희 안에 계시는 줄을 너희가 스스로 알지 못하느냐? 그렇지 않으면 너희는 버림받은 자니라.", "web": "Test your own selves, whether you are in the faith. Test your own selves. Or don’t you know as to your own selves, that Jesus Christ is in you?—unless indeed you are disqualified."}}, {"id": 89, "coll": "확립 100구절", "sub": ["구원의 확신", "말씀으로 거듭남"], "book": "베드로전서", "chap": 1, "verse": "23", "ref": "베드로전서 1:23", "texts": {"krv": "너희가 거듭난 것이 썩어질 씨로 된 것이 아니요 썩지 아니할 씨로 된 것이니 하나님의 살아 있고 항상 있는 말씀으로 되었느니라", "kkjv": "너희가 다시 태어난 것은 썩을 씨에서 난 것이 아니요 썩지 아니할 씨에서 난 것이니 살아 있고 영원히 거하는 하나님의 말씀으로 된 것이니라.", "web": "having been born again, not of corruptible seed, but of incorruptible, through the word of God, which lives and remains forever."}}, {"id": 90, "coll": "확립 100구절", "sub": ["경건의 시간", "아침 기도"], "book": "시편", "chap": 5, "verse": "3", "ref": "시편 5:3", "texts": {"krv": "여호와여 아침에 주께서 나의 소리를 들으시리니 아침에 내가 주께 기도하고 바라리이다", "kkjv": "오 주여, 아침에 주께서 내 목소리를 들으시리니 아침에 내가 내 기도를 주께로 향하게 하고 위를 바라보리이다.", "web": "Yahweh, in the morning you shall hear my voice. In the morning I will lay my requests before you, and will watch expectantly."}}, {"id": 91, "coll": "확립 100구절", "sub": ["경건의 시간", "요동치 않음"], "book": "시편", "chap": 16, "verse": "8", "ref": "시편 16:8", "texts": {"krv": "내가 여호와를 항상 내 앞에 모심이여 그가 내 우편에 계시므로 내가 요동치 아니하리로다", "kkjv": "내가 주를 항상 내 앞에 모셨나니 그분께서 내 오른편에 계시므로 내가 흔들리지 아니하리로다.", "web": "I have set Yahweh always before me. Because he is at my right hand, I shall not be moved."}}, {"id": 92, "coll": "확립 100구절", "sub": ["경건의 시간", "다윗의 소망"], "book": "시편", "chap": 27, "verse": "4", "ref": "시편 27:4", "texts": {"krv": "내가 여호와께 청하였던 한 가지 일 곧 그것을 구하리니 곧 나로 내 생전에 여호와의 집에 거하여 여호와의 아름다움을 앙망하며 그 전에서 사모하게 하실 것이라", "kkjv": "내가 주께 바라던 한 가지 일 바로 그것을 구하리니 그것은 곧 내가 평생토록 주의 집에 거하여 주의 아름다움을 바라보며 그분의 성전에서 여쭙는 것이라.", "web": "One thing I have asked of Yahweh, that I will seek after, that I may dwell in Yahweh’s house all the days of my life, to see Yahweh’s beauty, and to inquire in his temple."}}, {"id": 93, "coll": "확립 100구절", "sub": ["경건의 시간", "새벽을 깨움"], "book": "시편", "chap": 57, "verse": "7-8", "ref": "시편 57:7-8", "texts": {"krv": "하나님이여 내 마음이 확정되었고 내 마음이 확정되었사오니 내가 노래하고 내가 찬송하리이다 내 영광아 깰지어다 비파야 수금아 깰지어다 내가 새벽을 깨우리로다", "kkjv": "오 하나님이여, 내 마음이 확정되고 내 마음이 확정되었사오니 내가 노래하고 찬양을 드리리이다. 내 영광아, 깰지어다. 비파야, 하프야, 깰지어다. 나 자신도 일찍 깨리로다.", "web": "My heart is steadfast, God, my heart is steadfast. I will sing, yes, I will sing praises. Wake up, my glory! Wake up, psaltery and harp! I will wake up the dawn."}}, {"id": 94, "coll": "확립 100구절", "sub": ["경건의 시간", "하나님만 바람"], "book": "시편", "chap": 62, "verse": "1", "ref": "시편 62:1", "texts": {"krv": "나의 영혼이 잠잠히 하나님만 바람이여 나의 구원이 그에게서 나는도다", "kkjv": "진실로 내 혼이 하나님을 바라나니 나의 구원이 그분에게서 나오는도다.", "web": "My soul rests in God alone. My salvation is from him."}}, {"id": 95, "coll": "확립 100구절", "sub": ["경건의 시간", "참 기쁨"], "book": "시편", "chap": 90, "verse": "14", "ref": "시편 90:14", "texts": {"krv": "아침에 주의 인자로 우리를 만족케 하사 우리 평생에 즐겁고 기쁘게 하소서", "kkjv": "오 일찍 주의 긍휼로 우리를 만족하게 하사 우리가 평생토록 기뻐하고 즐거워하게 하소서.", "web": "Satisfy us in the morning with your loving kindness, that we may rejoice and be glad all our days."}}, {"id": 96, "coll": "확립 100구절", "sub": ["경건의 시간", "영적 시야"], "book": "시편", "chap": 119, "verse": "18", "ref": "시편 119:18", "texts": {"krv": "내 눈을 열어서 주의 법의 기이한 것을 보게 하소서", "kkjv": "주께서 내 눈을 여사 주의 법에서 나오는 놀라운 것들을 내가 보게 하소서.", "web": "Open my eyes, that I may see wondrous things out of your law."}}, {"id": 97, "coll": "확립 100구절", "sub": ["경건의 시간", "깨달음과 순종"], "book": "시편", "chap": 119, "verse": "34", "ref": "시편 119:34", "texts": {"krv": "나로 깨닫게 하소서 내가 주의 법을 준행하며 전심으로 지키리이다", "kkjv": "내게 명철을 주소서. 내가 주의 법을 지키리니 참으로 내 온 마음으로 그것을 준수하리이다.", "web": "Give me understanding, and I will keep your law. Yes, I will obey it with my whole heart."}}, {"id": 98, "coll": "확립 100구절", "sub": ["경건의 시간", "묵상의 열정"], "book": "시편", "chap": 119, "verse": "147-148", "ref": "시편 119:147-148", "texts": {"krv": "내가 새벽 전에 부르짖으며 주의 말씀을 바랐사오며 주의 말씀을 묵상하려고 내 눈이 야경이 깊기 전에 깨었나이다", "kkjv": "내가 아침이 밝기 전에 일어나 부르짖었고 주의 말씀에 소망을 두었사오며 주의 말씀을 묵상하려고 내 눈이 밤의 경점들보다 앞서 가나이다.", "web": "I rise before dawn and cry for help. I put my hope in your words. My eyes stay open through the night watches, that I might meditate on your word."}}, {"id": 99, "coll": "확립 100구절", "sub": ["경건의 시간", "간절한 기다림"], "book": "시편", "chap": 130, "verse": "6", "ref": "시편 130:6", "texts": {"krv": "파숫군이 아침을 기다림보다 내 영혼이 주를 더 기다리나니 참으로 파숫군의 아침을 기다림보다 더하도다", "kkjv": "내 혼이 주를 기다림이 파수 보는 자들이 아침을 기다림보다 더하나니 내가 말하거니와 파수 보는 자들이 아침을 기다림보다 더하도다.", "web": "My soul longs for the Lord more than watchmen long for the morning; more than watchmen for the morning."}}, {"id": 100, "coll": "확립 100구절", "sub": ["경건의 시간", "인도하심"], "book": "시편", "chap": 143, "verse": "8", "ref": "시편 143:8", "texts": {"krv": "아침에 나로 주의 인자한 말씀을 듣게 하소서 내가 주를 의뢰함이니이다 나의 다닐 길을 알게 하소서 내가 내 영혼을 주께 받듦이니이다", "kkjv": "내가 주를 신뢰하오니 아침에 나로 하여금 주의 인자하심에 대하여 듣게 하소서. 내가 주를 향해 내 혼을 들어 올리오니 나로 하여금 내가 마땅히 가야 할 길을 알게 하소서.", "web": "Cause me to hear your loving kindness in the morning, for I trust in you. Cause me to know the way in which I should walk, for I lift up my soul to you."}}, {"id": 101, "coll": "확립 100구절", "sub": ["경건의 시간", "성실하신 주님"], "book": "호세아", "chap": 6, "verse": "3", "ref": "호세아 6:3", "texts": {"krv": "그러므로 우리가 여호와를 알자 힘써 여호와를 알자 그의 나오심은 새벽 빛 같이 일정하니 비와 같이 땅을 적시는 늦은 비와 같이 우리에게 임하시리라 하리라", "kkjv": "우리가 계속해서 주를 알고자 하면 그때에 우리가 알리라. 그분의 나아오심은 아침같이 예비되어 있으며 그분께서는 비같이 곧 땅에 내리는 늦은 비와 이른 비같이 우리에게 임하시리라.", "web": "Let us acknowledge Yahweh. Let us press on to know Yahweh. As surely as the sun rises, Yahweh will appear. He will come to us like the rain, like the spring rain that waters the earth.”"}}, {"id": 102, "coll": "확립 100구절", "sub": ["그리스도의 주재권", "인생의 연약함"], "book": "시편", "chap": 39, "verse": "4-5", "ref": "시편 39:4-5", "texts": {"krv": "여호와여 나의 종말과 연한의 어떠함을 알게 하사 나로 나의 연약함을 알게 하소서 주께서 나의 날을 손 넓이만큼 되게 하시매 나의 일생이 주의 앞에는 없는 것 같사오니 사람마다 그 든든히 선 때도 진실로 허사뿐이니이다", "kkjv": "주여, 나로 하여금 내 종말과 내 날들의 한계가 어떠한 것인지 알게 하사 내가 얼마나 연약한 존재인지 알게 하소서. 보소서, 주께서 내 날들을 한 뼘만큼 되게 하셨사오니 내 시대가 주 앞에는 없는 것 같사오며 참으로 모든 사람은 최선의 상태에서도 전적으로 헛될 뿐이니이다. 셀라.", "web": "“Yahweh, show me my end, what is the measure of my days. Let me know how frail I am. Behold, you have made my days hand breadths. My lifetime is as nothing before you. Surely every man stands as a breath.” Selah."}}, {"id": 103, "coll": "확립 100구절", "sub": ["그리스도의 주재권", "하나님의 주권"], "book": "시편", "chap": 127, "verse": "1", "ref": "시편 127:1", "texts": {"krv": "여호와께서 집을 세우지 아니하시면 세우는 자의 수고가 헛되며 여호와께서 성을 지키지 아니하시면 파숫군의 경성함이 허사로다", "kkjv": "주께서 집을 세우지 아니하시면 그것을 세우는 자들의 수고가 헛되며 주께서 도시를 지키지 아니하시면 파수꾼의 깨어 있음이 헛되도다.", "web": "Unless Yahweh builds the house, they labor in vain who build it. Unless Yahweh watches over the city, the watchman guards it in vain."}}, {"id": 104, "coll": "확립 100구절", "sub": ["그리스도의 주재권", "야망을 포기함"], "book": "예레미야", "chap": 45, "verse": "5", "ref": "예레미야 45:5", "texts": {"krv": "네가 너를 위하여 대사를 경영하느냐 그것을 경영하지 말라 보라 내가 모든 육체에게 재앙을 내리리라 그러나 너의 가는 모든 곳에서는 내가 너로 생명 얻기를 노략물을 얻는 것 같게 하리라 여호와의 말이니라 하셨느니라", "kkjv": "네가 너를 위하여 큰일들을 구하느냐? 그것들을 구하지 말라. 보라, 내가 모든 육체에게 재앙을 내리리라. 그러나 네가 가는 모든 곳에서 내가 네 생명을 네게 탈취물로 주리라. 주가 말하노라.", "web": "Do you seek great things for yourself? Don’t seek them; for, behold, I will bring evil on all flesh, says Yahweh; but your life will I give to you for a prey in all places where you go."}}, {"id": 105, "coll": "확립 100구절", "sub": ["그리스도의 주재권", "우상"], "book": "마태복음", "chap": 6, "verse": "24", "ref": "마태복음 6:24", "texts": {"krv": "한 사람이 두 주인을 섬기지 못할 것이니 혹 이를 미워하며 저를 사랑하거나 혹 이를 중히 여기며 저를 경히 여김이라 너희가 하나님과 재물을 겸하여 섬기지 못하느니라", "kkjv": "¶아무도 두 주인을 섬길 수 없나니 이는 그가 한 주인을 미워하고 다른 주인을 사랑하거나 혹은 한 주인을 떠받들고 다른 주인을 업신여길 것이기 때문이라. 너희가 하나님과 맘몬을 겸하여 섬길 수 없느니라.", "web": "“No one can serve two masters, for either he will hate the one and love the other; or else he will be devoted to one and despise the other. You can’t serve both God and Mammon."}}, {"id": 106, "coll": "확립 100구절", "sub": ["그리스도의 주재권", "온 인류의 주"], "book": "로마서", "chap": 14, "verse": "8-9", "ref": "로마서 14:8-9", "texts": {"krv": "우리가 살아도 주를 위하여 살고 죽어도 주를 위하여 죽나니 그러므로 사나 죽으나 우리가 주의 것이로라 이를 위하여 그리스도께서 죽었다가 다시 살으셨으니 곧 죽은 자와 산 자의 주가 되려 하심이니라", "kkjv": "우리가 살아도 주를 위해 살고 죽어도 주를 위해 죽나니 그러므로 살든지 죽든지 우리가 주의 것이로다. 이 목적을 위해 그리스도께서 죽으시고 일어나사 다시 살아나셨으니 이것은 그분께서 죽은 자와 산 자의 주가 되려 하심이라.", "web": "For if we live, we live to the Lord. Or if we die, we die to the Lord. If therefore we live or die, we are the Lord’s. For to this end Christ died, rose, and lived again, that he might be Lord of both the dead and the living."}}, {"id": 107, "coll": "확립 100구절", "sub": ["그리스도의 주재권", "우리의 만족"], "book": "고린도후서", "chap": 3, "verse": "5", "ref": "고린도후서 3:5", "texts": {"krv": "우리가 무슨 일이든지 우리에게서 난것 같이 생각하여 스스로 만족할 것이 아니니 우리의 만족은 오직 하나님께로서 났느니라", "kkjv": "우리는 어떤 일이 우리 자신에게서 난 것으로 생각할 만큼 능력이 있지 아니하며 오직 우리의 능력은 하나님에게서 나느니라.", "web": "not that we are sufficient of ourselves, to account anything as from ourselves; but our sufficiency is from God;"}}, {"id": 108, "coll": "확립 100구절", "sub": ["그리스도의 주재권", "질그릇과 보배"], "book": "고린도후서", "chap": 4, "verse": "7", "ref": "고린도후서 4:7", "texts": {"krv": "우리가 이 보배를 질그릇에 가졌으니 이는 능력의 심히 큰 것이 하나님께 있고 우리에게 있지 아니함을 알게 하려 함이라", "kkjv": "그러나 우리가 이 보배를 질그릇 안에 가지고 있나니 이것은 뛰어난 권능이 하나님에게서 나며 우리에게서 나지 아니하게 하려 함이라.", "web": "But we have this treasure in clay vessels, that the exceeding greatness of the power may be of God, and not from ourselves."}}, {"id": 109, "coll": "확립 100구절", "sub": ["그리스도의 주재권", "주를 위한 삶"], "book": "고린도후서", "chap": 5, "verse": "15", "ref": "고린도후서 5:15", "texts": {"krv": "저가 모든 사람을 대신하여 죽으심은 산 자들로 하여금 다시는 저희 자신을 위하여 살지 않고 오직 저희를 대신하여 죽었다가 다시 사신 자를 위하여 살게 하려 함이니라", "kkjv": "그분께서 모든 사람을 위하여 죽으신 것은 살아 있는 자들이 이제부터는 자기들을 위하여 살지 아니하고 오직 자기들을 위하여 죽었다가 다시 일어나신 분을 위하여 살게 하려 함이니라.", "web": "He died for all, that those who live should no longer live to themselves, but to him who for their sakes died and rose again."}}, {"id": 110, "coll": "확립 100구절", "sub": ["그리스도의 주재권", "그리스도의 종"], "book": "갈라디아서", "chap": 1, "verse": "10", "ref": "갈라디아서 1:10", "texts": {"krv": "이제 내가 사람들에게 좋게 하랴 하나님께 좋게 하랴 사람들에게 기쁨을 구하랴 내가 지금까지 사람의 기쁨을 구하는 것이었더면 그리스도의 종이 아니니라", "kkjv": "내가 지금 사람들을 설득하느냐, 하나님을 설득하느냐? 혹은 사람들을 기쁘게 하려고 애쓰느냐? 내가 아직도 사람들을 기쁘게 한다면 결코 그리스도의 종이 아니리라.", "web": "For am I now seeking the favor of men, or of God? Or am I striving to please men? For if I were still pleasing men, I wouldn’t be a servant of Christ."}}, {"id": 111, "coll": "확립 100구절", "sub": ["그리스도의 주재권", "제자의 자랑"], "book": "갈라디아서", "chap": 6, "verse": "14", "ref": "갈라디아서 6:14", "texts": {"krv": "그러나 내게는 우리 주 예수 그리스도의 십자가 외에 결코 자랑할 것이 없으니 그리스도로 말미암아 세상이 나를 대하여 십자가에 못박히고 내가 또한 세상을 대하여 그러하니라", "kkjv": "그러나 나는 우리 주 예수 그리스도의 십자가 외에 결코 어떤 것도 자랑할 수 없나니 그분으로 말미암아 세상이 나에 대하여 십자가에 못 박혀 있고 나 또한 세상에 대하여 그러하니라.", "web": "But far be it from me to boast, except in the cross of our Lord Jesus Christ, through which the world has been crucified to me, and I to the world."}}, {"id": 112, "coll": "확립 100구절", "sub": ["그리스도의 주재권", "생의 목표"], "book": "빌립보서", "chap": 1, "verse": "20", "ref": "빌립보서 1:20", "texts": {"krv": "나의 간절한 기대와 소망을 따라 아무 일에든지 부끄럽지 아니하고 오직 전과 같이 이제도 온전히 담대하여 살든지 죽든지 내 몸에서 그리스도가 존귀히 되게 하려 하나니", "kkjv": "나의 간절한 기대와 소망에 따라 내가 아무 일에든지 부끄러워하지 아니하고 항상 그러하였듯이 지금도 온전히 담대하여 살든지 죽든지 내 몸에서 그리스도를 높이고자 하나니", "web": "according to my earnest expectation and hope, that I will in no way be disappointed, but with all boldness, as always, now also Christ will be magnified in my body, whether by life, or by death."}}, {"id": 113, "coll": "확립 100구절", "sub": ["그리스도의 주재권", "만주의 주"], "book": "디모데전서", "chap": 6, "verse": "15", "ref": "디모데전서 6:15", "texts": {"krv": "기약이 이르면 하나님이 그의 나타나심을 보이시리니 하나님은 복되시고 홀로 한 분이신 능하신 자이며 만왕의 왕이시며 만주의 주시요", "kkjv": "그분께서 자신의 때에 그 나타나심을 보이시리니 그분은 찬송 받으실 유일한 권능자이시요 왕들의 왕이시며 주들의 주시니라.", "web": "which in its own times he will show, who is the blessed and only Ruler, the King of kings, and Lord of lords;"}}, {"id": 114, "coll": "확립 100구절", "sub": ["말씀의 중요성", "가까이 있는 말씀"], "book": "신명기", "chap": 30, "verse": "14", "ref": "신명기 30:14", "texts": {"krv": "오직 그 말씀이 네게 심히 가까와서 네 입에 있으며 네 마음에 있은즉 네가 이를 행할 수 있느니라", "kkjv": "오직 말씀이 네게 심히 가까이 있어 네 입에 있으며 네 마음에 있나니 그러므로 네가 그것을 행할 수 있느니라.", "web": "But the word is very near to you, in your mouth and in your heart, that you may do it."}}, {"id": 115, "coll": "확립 100구절", "sub": ["말씀의 중요성", "즐거이 순종"], "book": "시편", "chap": 40, "verse": "8", "ref": "시편 40:8", "texts": {"krv": "나의 하나님이여 내가 주의 뜻 행하기를 즐기오니 주의 법이 나의 심중에 있나이다 하였나이다", "kkjv": "오 나의 하나님이여, 내가 주의 뜻 행하기를 기뻐하오니 참으로 주의 법이 내 마음속에 있나이다, 하였나이다.", "web": "I delight to do your will, my God. Yes, your law is within my heart.”"}}, {"id": 116, "coll": "확립 100구절", "sub": ["말씀의 중요성", "즉각적인 순종"], "book": "시편", "chap": 119, "verse": "59-60", "ref": "시편 119:59-60", "texts": {"krv": "내가 내 행위를 생각하고 주의 증거로 내 발을 돌이켰사오며 주의 계명을 지키기에 신속히 하고 지체치 아니하였나이다", "kkjv": "내가 나의 길들을 생각하고 주의 증언들을 향해 내 발을 돌렸사오며 신속히 움직여 주의 명령들을 지키려고 지체하지 아니하였나이다.", "web": "I considered my ways, and turned my steps to your statutes. I will hurry, and not delay, to obey your commandments."}}, {"id": 117, "coll": "확립 100구절", "sub": ["말씀의 중요성", "말씀에 대한 태도"], "book": "시편", "chap": 119, "verse": "97", "ref": "시편 119:97", "texts": {"krv": "내가 주의 법을 어찌 그리 사랑하는지요 내가 그것을 종일 묵상하나이다", "kkjv": "오 내가 주의 법을 얼마나 사랑하는지요! 그 법이 종일토록 나의 묵상이 되나이다.", "web": "How I love your law! It is my meditation all day."}}, {"id": 118, "coll": "확립 100구절", "sub": ["말씀의 중요성", "묵상의 축복"], "book": "시편", "chap": 119, "verse": "99-100", "ref": "시편 119:99-100", "texts": {"krv": "내가 주의 증거를 묵상하므로 나의 명철함이 나의 모든 스승보다 승하며 주의 법도를 지키므로 나의 명철함이 노인보다 승하니이다", "kkjv": "주의 증언들이 나의 묵상이 되므로 나의 모든 스승보다 내게 더 많은 명철이 있으며 내가 주의 훈계들을 지키므로 노인들보다 더 잘 깨닫나이다.", "web": "I have more understanding than all my teachers, for your testimonies are my meditation. I understand more than the aged, because I have kept your precepts."}}, {"id": 119, "coll": "확립 100구절", "sub": ["말씀의 중요성", "말씀의 인도"], "book": "시편", "chap": 119, "verse": "105", "ref": "시편 119:105", "texts": {"krv": "주의 말씀은 내 발에 등이요 내 길에 빛이니이다", "kkjv": "주의 말씀은 내 발에 등불이요, 내 길에 빛이니이다.", "web": "Your word is a lamp to my feet, and a light for my path."}}, {"id": 120, "coll": "확립 100구절", "sub": ["말씀의 중요성", "영원한 축복"], "book": "시편", "chap": 119, "verse": "111", "ref": "시편 119:111", "texts": {"krv": "주의 증거로 내가 영원히 기업을 삼았사오니 이는 내 마음의 즐거움이 됨이니이다", "kkjv": "내가 주의 증언들을 영원히 유산으로 삼았사오니 그것들은 내 마음의 기쁨이니이다.", "web": "I have taken your testimonies as a heritage forever, for they are the joy of my heart."}}, {"id": 121, "coll": "확립 100구절", "sub": ["말씀의 중요성", "암송의 유익"], "book": "잠언", "chap": 6, "verse": "21-22", "ref": "잠언 6:21-22", "texts": {"krv": "그것을 항상 네 마음에 새기며 네 목에 매라 그것이 너의 다닐 때에 너를 인도하며 너의 잘 때에 너를 보호하며 너의 깰 때에 너로 더불어 말하리니", "kkjv": "그것들을 계속해서 네 마음에 묶어 두고 네 목에 매어 두라. 그것이 네가 다닐 때에 너를 인도하고 네가 잘 때에 너를 보호하며 네가 깰 때에 너와 말하리니", "web": "Bind them continually on your heart. Tie them around your neck. When you walk, it will lead you. When you sleep, it will watch over you. When you awake, it will talk with you."}}, {"id": 122, "coll": "확립 100구절", "sub": ["말씀의 중요성", "능력의 말씀"], "book": "누가복음", "chap": 1, "verse": "37", "ref": "누가복음 1:37", "texts": {"krv": "대저 하나님의 모든 말씀은 능치 못하심이 없느니라", "kkjv": "하나님께는 불가능한 일이 없느니라, 하니라.", "web": "For everything spoken by God is possible.”"}}, {"id": 123, "coll": "확립 100구절", "sub": ["말씀의 중요성", "일꾼의 자질"], "book": "디모데후서", "chap": 2, "verse": "15", "ref": "디모데후서 2:15", "texts": {"krv": "네가 진리의 말씀을 옳게 분변하며 부끄러울 것이 없는 일꾼으로 인정된 자로 자신을 하나님 앞에 드리기를 힘쓰라", "kkjv": "너는 진리의 말씀을 바르게 나누어 네 자신을 하나님께 인정받은 자로, 부끄러울 것이 없는 일꾼으로 나타내도록 연구하라.", "web": "Give diligence to present yourself approved by God, a workman who doesn’t need to be ashamed, properly handling the Word of Truth."}}, {"id": 124, "coll": "확립 100구절", "sub": ["말씀의 중요성", "말씀의 유익"], "book": "디모데후서", "chap": 3, "verse": "17", "ref": "디모데후서 3:17", "texts": {"krv": "이는 하나님의 사람으로 온전케 하며 모든 선한 일을 행하기에 온전케 하려 함이니라", "kkjv": "이것은 하나님의 사람이 완전하게 되어 모든 선한 일에 철저히 갖추어지게 하려 함이라.", "web": "that the man of God may be complete, thoroughly equipped for every good work."}}, {"id": 125, "coll": "확립 100구절", "sub": ["말씀의 중요성", "복있는 사람"], "book": "요한계시록", "chap": 1, "verse": "3", "ref": "요한계시록 1:3", "texts": {"krv": "이 예언의 말씀을 읽는 자와 듣는 자들과 그 가운데 기록한 것을 지키는 자들이 복이 있나니 때가 가까움이라", "kkjv": "이 대언의 말씀들을 읽는 자와 듣고 그 안에 기록된 그것들을 지키는 자들은 복이 있나니 이는 때가 가깝기 때문이라.", "web": "Blessed is he who reads and those who hear the words of the prophecy, and keep the things that are written in it, for the time is at hand."}}, {"id": 126, "coll": "확립 100구절", "sub": ["기도의 중요성", "자백 기도"], "book": "시편", "chap": 32, "verse": "5", "ref": "시편 32:5", "texts": {"krv": "내가 이르기를 내 허물을 여호와께 자복하리라 하고 주께 내 죄를 아뢰고 내 죄악을 숨기지 아니하였더니 곧 주께서 내 죄의 악을 사하셨나이다", "kkjv": "내가 주께 내 죄를 시인하고 내 불법을 숨기지 아니하며 또 이르기를, 내 범법들을 주께 자백하리라, 하였더니 주께서 내 죄의 불법을 용서하셨나이다. 셀라.", "web": "I acknowledged my sin to you. I didn’t hide my iniquity. I said, I will confess my transgressions to Yahweh, and you forgave the iniquity of my sin. Selah."}}, {"id": 127, "coll": "확립 100구절", "sub": ["기도의 중요성", "기도의 축복"], "book": "시편", "chap": 34, "verse": "10", "ref": "시편 34:10", "texts": {"krv": "젊은 사자는 궁핍하여 주릴지라도 여호와를 찾는 자는 모든 좋은 것에 부족함이 없으리로다", "kkjv": "젊은 사자들은 부족하여 굶주릴지라도 주를 찾는 자들에게는 모든 좋은 것이 부족하지 아니하리로다.", "web": "The young lions do lack, and suffer hunger, but those who seek Yahweh shall not lack any good thing."}}, {"id": 128, "coll": "확립 100구절", "sub": ["기도의 중요성", "감사 기도"], "book": "시편", "chap": 50, "verse": "23", "ref": "시편 50:23", "texts": {"krv": "감사로 제사를 드리는 자가 나를 영화롭게 하나니 그 행위를 옳게 하는 자에게 내가 하나님의 구원을 보이리라", "kkjv": "찬양을 드리는 자는 다 나를 영화롭게 하나니 자기 행실을 바르게 하는 자에게 내가 하나님의 구원을 보이리로다.", "web": "Whoever offers the sacrifice of thanksgiving glorifies me, and prepares his way so that I will show God’s salvation to him.”"}}, {"id": 129, "coll": "확립 100구절", "sub": ["기도의 중요성", "기도의 적"], "book": "시편", "chap": 66, "verse": "18", "ref": "시편 66:18", "texts": {"krv": "내가 내 마음에 죄악을 품으면 주께서 듣지 아니하시리라", "kkjv": "내가 마음속으로 불법에 관심을 두면 주께서 내 말을 듣지 아니하시리라.", "web": "If I cherished sin in my heart, the Lord wouldn’t have listened."}}, {"id": 130, "coll": "확립 100구절", "sub": ["기도의 중요성", "불순종"], "book": "잠언", "chap": 28, "verse": "9", "ref": "잠언 28:9", "texts": {"krv": "사람이 귀를 돌이키고 율법을 듣지 아니하면 그의 기도도 가증하니라", "kkjv": "사람이 자기 귀를 돌려 율법을 듣지 아니하면 그의 기도조차 가증한 것이 되리로다.", "web": "He who turns away his ear from hearing the law, even his prayer is an abomination."}}, {"id": 131, "coll": "확립 100구절", "sub": ["기도의 중요성", "합심 기도"], "book": "마태복음", "chap": 18, "verse": "19", "ref": "마태복음 18:19", "texts": {"krv": "진실로 다시 너희에게 이르노니 너희 중에 두 사람이 땅에서 합심하여 무엇이든지 구하면 하늘에 계신 내 아버지께서 저희를 위하여 이루게 하시리라", "kkjv": "내가 다시 너희에게 이르노니, 너희 중의 두 사람이 자기들이 구할 어떤 것에 대하여 땅에서 한마음이 되면 하늘에 계신 내 아버지께서 그들을 위해 그것을 행하시리라.", "web": "Again, assuredly I tell you, that if two of you will agree on earth concerning anything that they will ask, it will be done for them by my Father who is in heaven."}}, {"id": 132, "coll": "확립 100구절", "sub": ["기도의 중요성", "방어 기도"], "book": "마태복음", "chap": 26, "verse": "41", "ref": "마태복음 26:41", "texts": {"krv": "시험에 들지 않게 깨어 있어 기도하라 마음에는 원이로되 육신이 약하도다 하시고", "kkjv": "너희가 시험에 빠지지 않게 깨어 기도하라. 참으로 영은 원하되 육이 약하도다, 하시니라.", "web": "Watch and pray, that you don’t enter into temptation. The spirit indeed is willing, but the flesh is weak.”"}}, {"id": 133, "coll": "확립 100구절", "sub": ["기도의 중요성", "믿음의 기도"], "book": "마가복음", "chap": 11, "verse": "24", "ref": "마가복음 11:24", "texts": {"krv": "그러므로 내가 너희에게 말하노니 무엇이든지 기도하고 구하는 것은 받은 줄로 믿으라 그리하면 너희에게 그대로 되리라", "kkjv": "그러므로 내가 너희에게 이르노니, 너희가 기도할 때에 무엇을 원하든지 너희가 그것들을 받는 줄로 믿으라. 그리하면 너희가 그것들을 받으리라.", "web": "Therefore I tell you, all things whatever you pray and ask for, believe that you have received them, and you shall have them."}}, {"id": 134, "coll": "확립 100구절", "sub": ["기도의 중요성", "순종의 기도"], "book": "마가복음", "chap": 14, "verse": "36", "ref": "마가복음 14:36", "texts": {"krv": "가라사대 아바 아버지여 아버지께는 모든 것이 가능하오니 이 잔을 내게서 옮기시옵소서 그러나 나의 원대로 마옵시고 아버지의 원대로 하옵소서 하시고", "kkjv": "이르시되, 아바, 아버지여, 아버지께는 모든 것이 가능하오니 이 잔을 내게서 옮기시옵소서. 그러나 내 뜻대로 하지 마옵시고 아버지의 뜻대로 하옵소서, 하시고는", "web": "He said, “Abba, Father, all things are possible to you. Please remove this cup from me. However, not what I desire, but what you desire.”"}}, {"id": 135, "coll": "확립 100구절", "sub": ["기도의 중요성", "간절한 기도"], "book": "누가복음", "chap": 11, "verse": "8", "ref": "누가복음 11:8", "texts": {"krv": "내가 너희에게 말하노니 비록 벗됨을 인하여서는 일어나 주지 아니할지라도 그 강청함을 인하여 일어나 그 소용대로 주리라", "kkjv": "내가 너희에게 이르노니, 그가 자기 친구이므로 그가 일어나 그에게 주지는 아니할지라도 그가 귀찮게 졸라대므로 일어나 그의 필요대로 다 그에게 주리라.", "web": "I tell you, although he will not rise and give it to him because he is his friend, yet because of his persistence, he will get up and give him as many as he needs."}}, {"id": 136, "coll": "확립 100구절", "sub": ["기도의 중요성", "주님의 이름으로"], "book": "요한복음", "chap": 14, "verse": "13-14", "ref": "요한복음 14:13-14", "texts": {"krv": "너희가 내 이름으로 무엇을 구하든지 내가 시행하리니 이는 아버지로 하여금 아들을 인하여 영광을 얻으시게 하려 함이라 내 이름으로 무엇이든지 내게 구하면 내가 시행하리라", "kkjv": "너희가 내 이름으로 무엇을 구하든지 내가 그것을 행하리니 이것은 아버지께서 아들 안에서 영광을 받게 하려 함이라. 너희가 내 이름으로 무엇이든지 구하면 내가 그것을 행하리라.", "web": "Whatever you will ask in my name, that will I do, that the Father may be glorified in the Son. If you will ask anything in my name, I will do it."}}, {"id": 137, "coll": "확립 100구절", "sub": ["기도의 중요성", "은혜의 보좌"], "book": "히브리서", "chap": 4, "verse": "16", "ref": "히브리서 4:16", "texts": {"krv": "그러므로 우리가 긍휼하심을 받고 때를 따라 돕는 은혜를 얻기 위하여 은혜의 보좌 앞에 담대히 나아갈 것이니라", "kkjv": "그러므로 우리가 긍휼을 얻고 필요한 때에 도우시는 은혜를 얻기 위해 은혜의 왕좌로 담대히 갈 것이니라.", "web": "Let us therefore draw near with boldness to the throne of grace, that we may receive mercy, and may find grace for help in time of need."}}, {"id": 138, "coll": "확립 100구절", "sub": ["교제의 중요성", "즐거움"], "book": "시편", "chap": 16, "verse": "3", "ref": "시편 16:3", "texts": {"krv": "땅에 있는 성도는 존귀한 자니 나의 모든 즐거움이 저희에게 있도다", "kkjv": "땅에 있는 성도들과 뛰어난 자들에게는 미치오니 나의 모든 기쁨이 그들에게 있나이다, 하였도다.", "web": "As for the saints who are in the earth, they are the excellent ones in whom is all my delight."}}, {"id": 139, "coll": "확립 100구절", "sub": ["교제의 중요성", "연합함"], "book": "시편", "chap": 133, "verse": "1", "ref": "시편 133:1", "texts": {"krv": "형제가 연합하여 동거함이 어찌 그리 선하고 아름다운고", "kkjv": "보라, 형제들이 하나가 되어 동거함이 어찌 그리 좋으며 어찌 그리 기쁜가!", "web": "See how good and how pleasant it is for brothers to live together in unity!"}}, {"id": 140, "coll": "확립 100구절", "sub": ["교제의 중요성", "지혜로운 자"], "book": "잠언", "chap": 13, "verse": "20", "ref": "잠언 13:20", "texts": {"krv": "지혜로운 자와 동행하면 지혜를 얻고 미련한 자와 사귀면 해를 받느니라", "kkjv": "지혜로운 자들과 함께 걷는 자는 지혜로우려니와 어리석은 자들의 벗이 되는 자는 멸망을 당하리라.", "web": "One who walks with wise men grows wise, but a companion of fools suffers harm."}}, {"id": 141, "coll": "확립 100구절", "sub": ["교제의 중요성", "형제의 유익"], "book": "잠언", "chap": 27, "verse": "17", "ref": "잠언 27:17", "texts": {"krv": "철이 철을 날카롭게 하는것 같이 사람이 그 친구의 얼굴을 빛나게 하느니라", "kkjv": "쇠가 쇠를 예리하게 하는 것 같이 사람이 자기 친구의 얼굴을 예리하게 하느니라.", "web": "Iron sharpens iron; so a man sharpens his friend’s countenance."}}, {"id": 142, "coll": "확립 100구절", "sub": ["교제의 중요성", "견고함"], "book": "전도서", "chap": 4, "verse": "12", "ref": "전도서 4:12", "texts": {"krv": "한 사람이면 패하겠거니와 두 사람이면 능히 당하나니 삼겹줄은 쉽게 끊어지지 아니하느니라", "kkjv": "누가 그를 쳐서 이기면 두 사람이 그와 맞서리니 세 겹 줄은 빨리 끊어지지 아니하느니라.", "web": "If a man prevails against one who is alone, two shall withstand him; and a threefold cord is not quickly broken."}}, {"id": 143, "coll": "확립 100구절", "sub": ["교제의 중요성", "교제를 힘씀"], "book": "사도행전", "chap": 2, "verse": "46", "ref": "사도행전 2:46", "texts": {"krv": "날마다 마음을 같이하여 성전에 모이기를 힘쓰고 집에서 떡을 떼며 기쁨과 순전한 마음으로 음식을 먹고", "kkjv": "또 날마다 한마음이 되어 성전에 거하고 집에서 집으로 돌아가며 빵을 떼면서 단일한 마음으로 즐겁게 자기들의 음식을 먹고", "web": "Day by day, continuing steadfastly with one accord in the temple, and breaking bread at home, they took their food with gladness and singleness of heart,"}}, {"id": 144, "coll": "확립 100구절", "sub": ["교제의 중요성", "한 몸"], "book": "로마서", "chap": 12, "verse": "5", "ref": "로마서 12:5", "texts": {"krv": "이와 같이 우리 많은 사람이 그리스도 안에서 한 몸이 되어 서로 지체가 되었느니라", "kkjv": "이와 같이 우리도 여럿이지만 그리스도 안에서 한 몸이요 각 사람이 서로 지체이니라.", "web": "so we, who are many, are one body in Christ, and individually members one of another."}}, {"id": 145, "coll": "확립 100구절", "sub": ["교제의 중요성", "하나됨"], "book": "에베소서", "chap": 4, "verse": "13", "ref": "에베소서 4:13", "texts": {"krv": "우리가 다 하나님의 아들을 믿는 것과 아는 일에 하나가 되어 온전한 사람을 이루어 그리스도의 장성한 분량이 충만한데까지 이르리니", "kkjv": "마침내 우리가 다 믿음과 하나님의 아들을 아는 것에서 하나가 되어 완전한 사람에 이르고 그리스도의 충만하심의 장성한 분량에까지 이르리니", "web": "until we all attain to the unity of the faith, and of the knowledge of the Son of God, to a full grown man, to the measure of the stature of the fullness of Christ;"}}, {"id": 146, "coll": "확립 100구절", "sub": ["교제의 중요성", "복음 중심"], "book": "빌립보서", "chap": 1, "verse": "27", "ref": "빌립보서 1:27", "texts": {"krv": "오직 너희는 그리스도 복음에 합당하게 생활하라 이는 내가 너희를 가 보나 떠나 있으나 너희가 일심으로 서서 한 뜻으로 복음의 신앙을 위하여 협력하는 것과", "kkjv": "오직 너희 행실을 그리스도의 복음에 합당하게 하라. 그리하면 너희에 대한 일들 곧 내가 가서 너희를 보든지 떠나 있든지 너희가 한 영 안에 굳게 서서 복음의 믿음을 위하여 한마음으로 함께 싸우며", "web": "Only let your way of life be worthy of the Good News of Christ, that, whether I come and see you or am absent, I may hear of your state, that you stand firm in one spirit, with one soul striving for the faith of the Good News;"}}, {"id": 147, "coll": "확립 100구절", "sub": ["교제의 중요성", "한 마음"], "book": "빌립보서", "chap": 2, "verse": "2", "ref": "빌립보서 2:2", "texts": {"krv": "마음을 같이하여 같은 사랑을 가지고 뜻을 합하며 한 마음을 품어", "kkjv": "너희는 같은 생각을 품고 같은 사랑을 가지며 한 마음과 한 생각이 되어 내 기쁨을 성취하라.", "web": "make my joy full, by being like-minded, having the same love, being of one accord, of one mind;"}}, {"id": 148, "coll": "확립 100구절", "sub": ["교제의 중요성", "경건함"], "book": "디모데후서", "chap": 2, "verse": "22", "ref": "디모데후서 2:22", "texts": {"krv": "또한 네가 청년의 정욕을 피하고 주를 깨끗한 마음으로 부르는 자들과 함께 의와 믿음과 사랑과 화평을 좇으라", "kkjv": "또한 청년의 정욕을 피하고 오직 순수한 마음으로 주를 부르는 자들과 함께 의와 믿음과 사랑과 화평을 따르라.", "web": "Flee from youthful lusts; but pursue righteousness, faith, love, and peace with those who call on the Lord out of a pure heart."}}, {"id": 149, "coll": "확립 100구절", "sub": ["교제의 중요성", "매일 교제함"], "book": "히브리서", "chap": 3, "verse": "13", "ref": "히브리서 3:13", "texts": {"krv": "오직 오늘이라 일컫는 동안에 매일 피차 권면하여 너희 중에 누구든지 죄의 유혹으로 강퍅케 됨을 면하라", "kkjv": "오직 오늘이라 불리는 때에 서로 날마다 권면하여 너희 중의 아무도 죄의 속임수를 통해 강퍅하게 되지 아니하도록 하라.", "web": "but exhort one another day by day, so long as it is called “today”; lest any one of you be hardened by the deceitfulness of sin."}}, {"id": 150, "coll": "확립 100구절", "sub": ["증거", "동행하시는 주님"], "book": "출애굽기", "chap": 4, "verse": "12", "ref": "출애굽기 4:12", "texts": {"krv": "이제 가라 내가 네 입과 함께 있어서 할 말을 가르치리라", "kkjv": "그런즉 이제 가라. 내가 네 입과 함께하여 네가 할 말을 네게 가르치리라.", "web": "Now therefore go, and I will be with your mouth, and teach you what you shall speak.”"}}, {"id": 151, "coll": "확립 100구절", "sub": ["증거", "확실한 열매"], "book": "시편", "chap": 126, "verse": "5-6", "ref": "시편 126:5-6", "texts": {"krv": "눈물을 흘리며 씨를 뿌리는 자는 기쁨으로 거두리로다 울며 씨를 뿌리러 나가는 자는 정녕 기쁨으로 그 단을 가지고 돌아오리로다", "kkjv": "눈물을 흘리며 씨를 뿌리는 자들은 기쁨으로 거두리로다. 귀중한 씨를 가지고 나아가 우는 자는 반드시 기뻐하며 자기의 곡식 단들을 가지고 돌아오리로다.", "web": "Those who sow in tears will reap in joy. He who goes out weeping, carrying seed for sowing, will certainly come again with joy, carrying his sheaves."}}, {"id": 152, "coll": "확립 100구절", "sub": ["증거", "전도의 열정"], "book": "예레미야", "chap": 20, "verse": "9", "ref": "예레미야 20:9", "texts": {"krv": "내가 다시는 여호와를 선포하지 아니하며 그 이름으로 말하지 아니하리라 하면 나의 중심이 불붙는 것 같아서 골수에 사무치니 답답하여 견딜 수 없나이다", "kkjv": "그때에 내가 말하기를, 내가 다시는 그분에 대하여 언급하지 아니하며 그분의 이름으로 말하지 아니하리라, 하였으나 그분의 말씀이 내 마음속에 타오르는 불 같아서 내 뼈 속에 사무치니 내가 참기에 지치고 가만히 있을 수 없었도다.", "web": "If I say, I will not make mention of him, nor speak any more in his name, then there is in my heart as it were a burning fire shut up in my bones, and I am weary with forbearing, and I can’t."}}, {"id": 153, "coll": "확립 100구절", "sub": ["증거", "영원한 상급"], "book": "다니엘", "chap": 12, "verse": "3", "ref": "다니엘 12:3", "texts": {"krv": "지혜 있는 자는 궁창의 빛과 같이 빛날 것이요 많은 사람을 옳은 데로 돌아오게 한 자는 별과 같이 영원토록 비취리라", "kkjv": "지혜로운 자들은 궁창의 광채같이 빛나고 많은 사람을 의로 돌아서게 하는 자들은 별들과 같이 영원무궁토록 빛나리라.", "web": "Those who are wise shall shine as the brightness of the expanse; and those who turn many to righteousness as the stars forever and ever."}}, {"id": 154, "coll": "확립 100구절", "sub": ["증거", "하늘의 기쁨"], "book": "누가복음", "chap": 15, "verse": "7", "ref": "누가복음 15:7", "texts": {"krv": "내가 너희에게 이르노니 이와 같이 죄인 하나가 회개하면 하늘에서는 회개할 것 없는 의인 아흔 아홉을 인하여 기뻐하는 것보다 더하리라", "kkjv": "내가 너희에게 이르노니, 이와 같이 하늘에서는 회개할 필요가 없는 의로운 아흔아홉 사람보다 회개하는 한 죄인으로 인하여 더 기쁨이 있으리라.", "web": "I tell you that even so there will be more joy in heaven over one sinner who repents, than over ninety-nine righteous people who need no repentance."}}, {"id": 155, "coll": "확립 100구절", "sub": ["증거", "쉬지 않는 전도"], "book": "사도행전", "chap": 5, "verse": "42", "ref": "사도행전 5:42", "texts": {"krv": "저희가 날마다 성전에 있든지 집에 있든지 예수는 그리스도라 가르치기와 전도하기를 쉬지 아니하니라", "kkjv": "그들이 날마다 성전에서와 모든 집에서 예수 그리스도를 가르치고 선포하는 것을 그치지 아니하니라.", "web": "Every day, in the temple and at home, they never stopped teaching and preaching Jesus, the Christ."}}, {"id": 156, "coll": "확립 100구절", "sub": ["증거", "전하는 일꾼"], "book": "로마서", "chap": 10, "verse": "14", "ref": "로마서 10:14", "texts": {"krv": "그런즉 저희가 믿지 아니하는 이를 어찌 부르리요 듣지도 못한 이를 어찌 믿으리요 전파하는 자가 없이 어찌 들으리요", "kkjv": "그런즉 그들이 자기들이 믿지 아니한 분을 어찌 부르리요? 자기들이 듣지 못한 분을 어찌 믿으리요? 선포자가 없이 어찌 들으리요?", "web": "How then will they call on him in whom they have not believed? How will they believe in him whom they have not heard? How will they hear without a preacher?"}}, {"id": 157, "coll": "확립 100구절", "sub": ["증거", "복음의 제사장"], "book": "로마서", "chap": 15, "verse": "16", "ref": "로마서 15:16", "texts": {"krv": "이 은혜는 곧 나로 이방인을 위하여 그리스도 예수의 일꾼이 되어 하나님의 복음의 제사장 직무를 하게 하사 이방인을 제물로 드리는 그것이 성령 안에서 거룩하게 되어 받으심직하게 하려 하심이라", "kkjv": "이것은 내가 이방인들을 향한 예수 그리스도의 사역자가 되어 하나님의 복음을 제공함으로써 이방인들을 바치는 일이 성령님을 통해 거룩히 구별되어 주께서 받으실 만하게 하려 함이라.", "web": "that I should be a servant of Christ Jesus to the Gentiles, serving as a priest the Good News of God, that the offering up of the Gentiles might be made acceptable, sanctified by the Holy Spirit."}}, {"id": 158, "coll": "확립 100구절", "sub": ["증거", "하나님의 지혜"], "book": "고린도전서", "chap": 1, "verse": "21", "ref": "고린도전서 1:21", "texts": {"krv": "하나님의 지혜에 있어서는 이 세상이 자기 지혜로 하나님을 알지 못하는 고로 하나님께서 전도의 미련한 것으로 믿는 자들을 구원하시기를 기뻐하셨도다", "kkjv": "하나님의 지혜에 있어서는 세상이 지혜로 하나님을 알지 못하였으므로 하나님께서 복음 선포의 어리석은 것으로 믿는 자들 구원하시는 것을 기뻐하셨도다.", "web": "For seeing that in the wisdom of God, the world through its wisdom didn’t know God, it was God’s good pleasure through the foolishness of the preaching to save those who believe."}}, {"id": 159, "coll": "확립 100구절", "sub": ["증거", "복음의 능력"], "book": "에베소서", "chap": 3, "verse": "6", "ref": "에베소서 3:6", "texts": {"krv": "이는 이방인들이 복음으로 말미암아 그리스도 예수 안에서 함께 후사가 되고 함께 지체가 되고 함께 약속에 참예하는 자가 됨이라", "kkjv": "이 신비는 곧 복음으로 말미암아 이방인들이 그리스도 안에서 동료 상속자가 되고 같은 몸에 속하게 되며 그분의 약속에 참여하는 자가 된다는 것이라.", "web": "that the Gentiles are fellow heirs, and fellow members of the body, and fellow partakers of his promise in Christ Jesus through the Good News,"}}, {"id": 160, "coll": "확립 100구절", "sub": ["증거", "그리스도의 풍성함"], "book": "에베소서", "chap": 3, "verse": "8", "ref": "에베소서 3:8", "texts": {"krv": "모든 성도 중에 지극히 작은 자보다 더 작은 나에게 이 은혜를 주신 것은 측량할 수 없는 그리스도의 풍성을 이방인에게 전하게 하시고", "kkjv": "그분께서 모든 성도들 중에서 가장 작은 자보다 더 작은 나에게 이 은혜를 주신 것은 헤아릴 수 없는 그리스도의 부요함을 내가 이방인들 가운데 선포하게 하고", "web": "To me, the very least of all saints, was this grace given, to preach to the Gentiles the unsearchable riches of Christ,"}}, {"id": 161, "coll": "확립 100구절", "sub": ["증거", "마지막 명령"], "book": "디모데후서", "chap": 4, "verse": "1-2", "ref": "디모데후서 4:1-2", "texts": {"krv": "하나님 앞과 산 자와 죽은 자를 심판하실 그리스도 예수 앞에서 그의 나타나실 것과 그의 나라를 두고 엄히 명하노니 너는 말씀을 전파하라 때를 얻든지 못 얻든지 항상 힘쓰라 범사에 오래 참음과 가르침으로 경책하며 경계하며 권하라", "kkjv": "그러므로 내가 하나님 앞과 주 예수 그리스도 앞에서 곧 친히 나타나실 때에 자신의 왕국에서 산 자와 죽은 자를 심판하실 분 앞에서 네게 명하노니 말씀을 선포하라. 때에 맞든지 맞지 아니하든지 긴급히 하라. 모든 오래 참음과 교리로 책망하고 꾸짖고 권면하라.", "web": "I command you therefore before God and the Lord Jesus Christ, who will judge the living and the dead at his appearing and his Kingdom: preach the word; be urgent in season and out of season; reprove, rebuke, and exhort, with all patience and teaching."}}, {"id": 162, "coll": "확립 100구절", "sub": ["세계 비전", "별과 같은 영적 자손들"], "book": "창세기", "chap": 22, "verse": "17-18", "ref": "창세기 22:17-18", "texts": {"krv": "내가 네게 큰 복을 주고 네 씨로 크게 성하여 하늘의 별과 같고 바닷가의 모래와 같게 하리니 네 씨가 그 대적의 문을 얻으리라 또 네 씨로 말미암아 천하 만민이 복을 얻으리니 이는 네가 나의 말을 준행하였음이니라 하셨다 하니라", "kkjv": "내가 네게 복을 주고 복을 주며 또 네 씨를 하늘의 별들같이 바닷가의 모래같이 번성하게 하고 번성하게 하리니 네 씨가 자기 원수들의 문을 소유하리라. 또 네 씨 안에서 땅의 모든 민족들이 복을 받으리니 이는 네가 내 음성에 순종하였기 때문이니라, 하니라.", "web": "that I will bless you greatly, and I will multiply your seed greatly like the stars of the heavens, and like the sand which is on the seashore. Your seed will possess the gate of his enemies. All the nations of the earth will be blessed by your seed, because you have obeyed my voice.”"}}, {"id": 163, "coll": "확립 100구절", "sub": ["세계 비전", "열방의 주재"], "book": "시편", "chap": 22, "verse": "27-28", "ref": "시편 22:27-28", "texts": {"krv": "땅의 모든 끝이 여호와를 기억하고 돌아오며 열방의 모든 족속이 주의 앞에 경배하리니 나라는 여호와의 것이요 여호와는 열방의 주재심이로다", "kkjv": "세상의 모든 끝이 기억하고 주께로 돌아오며 민족들의 모든 족속이 주 앞에 경배하리니 왕국은 주의 것이요, 그분은 민족들 가운데서 다스리는 이시로다.", "web": "All the ends of the earth shall remember and turn to Yahweh. All the relatives of the nations shall worship before you. For the kingdom is Yahweh’s. He is the ruler over the nations."}}, {"id": 164, "coll": "확립 100구절", "sub": ["세계 비전", "온 세계 위의 영광"], "book": "시편", "chap": 57, "verse": "11", "ref": "시편 57:11", "texts": {"krv": "하나님이여 주는 하늘 위에 높이 들리시며 주의 영광은 온 세계 위에 높아지기를 원하나이다", "kkjv": "오 하나님이여, 주께서 하늘들 위로 높여지시며 주의 영광이 온 땅 위로 높여지기 원하나이다.", "web": "Be exalted, God, above the heavens. Let your glory be over all the earth."}}, {"id": 165, "coll": "확립 100구절", "sub": ["세계 비전", "여호와를 아는 지식"], "book": "이사야", "chap": 11, "verse": "9", "ref": "이사야 11:9", "texts": {"krv": "나의 거룩한 산 모든 곳에서 해됨도 없고 상함도 없을 것이니 이는 물이 바다를 덮음 같이 여호와를 아는 지식이 세상에 충만할 것임이니라", "kkjv": "그것들이 내 거룩한 산 모든 곳에서 상하게 하거나 멸하지 아니하리니 이는 물들이 바다를 덮는 것 같이 주를 아는 지식이 땅에 충만할 것이기 때문이니라.", "web": "They will not hurt nor destroy in all my holy mountain; for the earth will be full of the knowledge of Yahweh, as the waters cover the sea."}}, {"id": 166, "coll": "확립 100구절", "sub": ["세계 비전", "이방의 빛"], "book": "이사야", "chap": 49, "verse": "6", "ref": "이사야 49:6", "texts": {"krv": "그가 가라사대 네가 나의 종이 되어 야곱의 지파들을 일으키며 이스라엘 중에 보전된 자를 돌아오게 할 것은 오히려 경한 일이라 내가 또 너로 이방의 빛을 삼아 나의 구원을 베풀어서 땅 끝까지 이르게 하리라", "kkjv": "그분께서 또 이르시되, 네가 나의 종이 되어 야곱의 지파들을 일으켜 세우며 이스라엘에서 보존된 자들을 회복시키는 것은 쉬운 일이라. 내가 또한 너를 이방인들의 빛으로 주리니 이것은 네가 땅 끝까지 이르러 나의 구원이 되게 하려 함이라, 하셨느니라.", "web": "yes, he says, “It is too light a thing that you should be my servant to raise up the tribes of Jacob, and to restore the preserved of Israel: I will also give you for a light to the nations, that you may be my salvation to the end of the earth.”"}}, {"id": 167, "coll": "확립 100구절", "sub": ["세계 비전", "나라를 일으키심"], "book": "이사야", "chap": 55, "verse": "5", "ref": "이사야 55:5", "texts": {"krv": "네가 알지 못하는 나라를 부를 것이며 너를 알지 못하는 나라가 네게 달려올 것은 나 여호와 네 하나님 곧 이스라엘의 거룩한 자를 인함이니라 내가 너를 영화롭게 하였느니라", "kkjv": "보라, 네가 알지 못하는 한 민족을 네가 부를 것이요, 주 네 하나님 곧 이스라엘의 거룩하신 이로 인하여 너를 알지 못하던 민족들이 네게로 달려오리니 그분께서 너를 영화롭게 하셨느니라.", "web": "Behold, you shall call a nation that you don’t know; and a nation that didn’t know you shall run to you, because of Yahweh your God, and for the Holy One of Israel; for he has glorified you.”"}}, {"id": 168, "coll": "확립 100구절", "sub": ["세계 비전", "믿음의 시야"], "book": "이사야", "chap": 60, "verse": "4", "ref": "이사야 60:4", "texts": {"krv": "네 눈을 들어 사면을 보라 무리가 다 모여 네게로 오느니라 네 아들들은 원방에서 오겠고 네 딸들은 안기워 올 것이라", "kkjv": "네 눈을 들어 사방을 보라. 그들이 다 함께 모여 네게로 오느니라. 네 아들들은 멀리서 오며 네 딸들은 네 곁에서 양육을 받으리라.", "web": "“Lift up your eyes all around, and see: they all gather themselves together, they come to you; your sons shall come from far, and your daughters shall be carried in the arms."}}, {"id": 169, "coll": "확립 100구절", "sub": ["세계 비전", "여호와의 영광"], "book": "하박국", "chap": 2, "verse": "14", "ref": "하박국 2:14", "texts": {"krv": "대저 물이 바다를 덮음 같이 여호와의 영광을 인정하는 것이 세상에 가득하리라", "kkjv": "물들이 바다를 덮는 것 같이 주의 영광을 아는 지식이 땅에 가득하리로다.", "web": "For the earth will be filled with the knowledge of Yahweh’s glory, as the waters cover the sea."}}, {"id": 170, "coll": "확립 100구절", "sub": ["세계 비전", "하나님의 크신 이름"], "book": "말라기", "chap": 1, "verse": "11", "ref": "말라기 1:11", "texts": {"krv": "만군의 여호와가 이르노라 해 뜨는 곳에서부터 해 지는 곳까지의 이방 민족 중에서 내 이름이 크게 될 것이라 각처에서 내 이름을 위하여 분향하며 깨끗한 제물을 드리리니 이는 내 이름이 이방 민족 중에서 크게 될 것임이니라", "kkjv": "해 뜨는 곳에서부터 해 지는 곳까지의 이방인들 가운데서 내 이름이 크게 되며 모든 곳에서 내 이름을 위해 향을 드리고 정결한 헌물을 드리리니 내 이름이 이교도들 가운데서 크게 되리라. 만군의 주가 말하노라.", "web": "For from the rising of the sun even to the going down of the same, my name is great among the nations, and in every place incense will be offered to my name, and a pure offering: for my name is great among the nations,” says Yahweh of Armies."}}, {"id": 171, "coll": "확립 100구절", "sub": ["세계 비전", "만민에게 전함"], "book": "마가복음", "chap": 16, "verse": "15", "ref": "마가복음 16:15", "texts": {"krv": "또 가라사대 너희는 온 천하에 다니며 만민에게 복음을 전파하라", "kkjv": "그분께서 그들에게 이르시되, 너희는 온 세상에 가서 모든 창조물에게 복음을 선포하라.", "web": "He said to them, “Go into all the world, and preach the Good News to the whole creation."}}, {"id": 172, "coll": "확립 100구절", "sub": ["세계 비전", "믿음의 조상"], "book": "로마서", "chap": 4, "verse": "18", "ref": "로마서 4:18", "texts": {"krv": "아브라함이 바랄 수 없는 중에 바라고 믿었으니 이는 네 후손이 이같으리라 하신 말씀대로 많은 민족의 조상이 되게 하려 하심을 인함이라", "kkjv": "그가 바랄 수 없는 가운데 바라면서 믿었으니 이것은, 네 씨가 이와 같으리라, 하신 것대로 그가 많은 민족들의 조상이 되려 함이라.", "web": "Who in hope believed against hope, to the end that he might become a father of many nations, according to that which had been spoken, “So will your seed be.”"}}, {"id": 173, "coll": "확립 100구절", "sub": ["세계 비전", "하나님의 소망"], "book": "디모데전서", "chap": 2, "verse": "4", "ref": "디모데전서 2:4", "texts": {"krv": "하나님은 모든 사람이 구원을 받으며 진리를 아는 데 이르기를 원하시느니라", "kkjv": "그분은 모든 사람이 구원을 받고 진리를 아는 데 이르기를 원하시느니라.", "web": "who desires all people to be saved and come to full knowledge of the truth."}}, {"id": 174, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "예수 그리스도", "예수님의 신성"], "book": "요한복음", "chap": 1, "verse": "1,14", "ref": "요한복음 1:1,14", "texts": {"krv": "태초에 말씀이 계시니라 이 말씀이 하나님과 함께 계셨으니 이 말씀은 곧 하나님이시니라 말씀이 육신이 되어 우리 가운데 거하시매 우리가 그 영광을 보니 아버지의 독생자의 영광이요 은혜와 진리가 충만하더라", "kkjv": "처음에 말씀이 계셨고 말씀이 하나님과 함께 계셨으며 말씀이 하나님이셨더라. 말씀이 육신이 되어 우리 가운데 거하시매 (우리가 그분의 영광을 보니 아버지의 독생하신 분의 영광이요) 은혜와 진리가 충만하더라.", "web": "In the beginning was the Word, and the Word was with God, and the Word was God. The Word became flesh, and lived among us. We saw his glory, such glory as of the one and only Son of the Father, full of grace and truth."}}, {"id": 175, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "예수 그리스도", "예수님의 신성"], "book": "히브리서", "chap": 1, "verse": "8", "ref": "히브리서 1:8", "texts": {"krv": "아들에 관하여는 하나님이여 주의 보좌가 영영하며 주의 나라의 홀은 공평한 홀이니이다", "kkjv": "아들에게는 이르시기를, 오 하나님이여, 주의 왕좌는 영원무궁하오며 주의 왕국의 홀(笏)은 의의 홀이니이다.", "web": "But of the Son he says,  “Your throne, O God, is forever and ever. The scepter of uprightness is the scepter of your Kingdom."}}, {"id": 176, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "예수 그리스도", "예수님의 인성"], "book": "히브리서", "chap": 4, "verse": "15", "ref": "히브리서 4:15", "texts": {"krv": "우리에게 있는 대제사장은 우리 연약함을 체휼하지 아니하는 자가 아니요 모든 일에 우리와 한결 같이 시험을 받은 자로되 죄는 없으시니라", "kkjv": "우리에게 계신 대제사장은 우리의 연약함의 감정을 몸소 느끼지 못하시는 분이 아니요 모든 점에서 우리와 똑같이 시험을 받으셨으되 죄는 없으신 분이시니라.", "web": "For we don’t have a high priest who can’t be touched with the feeling of our infirmities, but one who has been in all points tempted like we are, yet without sin."}}, {"id": 177, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "예수 그리스도", "예수님의 인성"], "book": "누가복음", "chap": 2, "verse": "52", "ref": "누가복음 2:52", "texts": {"krv": "예수는 그 지혜와 그 키가 자라가며 하나님과 사람에게 더 사랑스러워 가시더라", "kkjv": "예수님께서는 지혜와 키가 자라며 하나님과 사람에게 더욱 호의를 입으시더라.", "web": "And Jesus increased in wisdom and stature, and in favor with God and men."}}, {"id": 178, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "예수 그리스도", "예수님의 부활"], "book": "고린도전서", "chap": 15, "verse": "3-4", "ref": "고린도전서 15:3-4", "texts": {"krv": "내가 받은 것을 먼저 너희에게 전하였노니 이는 성경대로 그리스도께서 우리 죄를 위하여 죽으시고 장사지낸바 되었다가 성경대로 사흘만에 다시 살아나사", "kkjv": "내가 또한 받은 것을 무엇보다 먼저 너희에게 전하였노니 그것은 곧 성경 기록대로 그리스도께서 우리의 죄들로 인하여 죽으시고 묻히셨다가 성경 기록대로 셋째 날에 다시 살아나시고", "web": "For I delivered to you first of all that which I also received: that Christ died for our sins according to the Scriptures, that he was buried, that he was raised on the third day according to the Scriptures,"}}, {"id": 179, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "예수 그리스도", "예수님의 부활"], "book": "고린도전서", "chap": 15, "verse": "20", "ref": "고린도전서 15:20", "texts": {"krv": "그러나 이제 그리스도께서 죽은 자 가운데서 다시 살아 잠자는 자들의 첫 열매가 되셨도다", "kkjv": "그러나 이제 그리스도께서 죽은 자들로부터 일어나사 잠든 자들의 첫 열매가 되셨도다.", "web": "But now Christ has been raised from the dead. He became the first fruits of those who are asleep."}}, {"id": 180, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "예수 그리스도", "예수님은 하나님을 나타내심"], "book": "요한복음", "chap": 1, "verse": "18", "ref": "요한복음 1:18", "texts": {"krv": "본래 하나님을 본 사람이 없으되 아버지 품 속에 있는 독생하신 하나님이 나타내셨느니라", "kkjv": "아무도 어느 때나 하나님을 보지 못하였으되 아버지 품속에 계신 독생자께서 그분을 밝히 드러내셨느니라.", "web": "No one has seen God at any time. The one and only Son, who is in the bosom of the Father, he has declared him."}}, {"id": 181, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "예수 그리스도", "예수님은 하나님을 나타내심"], "book": "히브리서", "chap": 1, "verse": "3", "ref": "히브리서 1:3", "texts": {"krv": "이는 하나님의 영광의 광채시요 그 본체의 형상이시라 그의 능력의 말씀으로 만물을 붙드시며 죄를 정결케 하는 일을 하시고 높은 곳에 계신 위엄의 우편에 앉으셨느니라", "kkjv": "하나님의 영광의 광채시요 그분 자체의 정확한 형상이시며 자신의 권능의 말씀으로 모든 것을 떠받치시는 이 아들께서는 친히 우리의 죄들을 정결하게 하신 뒤에 높은 곳에 계신 존엄하신 분의 오른편에 앉으셨느니라.", "web": "His Son is the radiance of his glory, the very image of his substance, and upholding all things by the word of his power, when he had by himself purified us of our sins, sat down on the right hand of the Majesty on high;"}}, {"id": 182, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "예수 그리스도", "구속자이신 예수님"], "book": "누가복음", "chap": 19, "verse": "10", "ref": "누가복음 19:10", "texts": {"krv": "인자의 온 것은 잃어버린 자를 찾아 구원하려 함이니라", "kkjv": "사람의 아들은 잃어버린 것을 찾아 구원하러 왔느니라, 하시니라.", "web": "For the Son of Man came to seek and to save that which was lost.”"}}, {"id": 183, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "예수 그리스도", "구속자이신 예수님"], "book": "베드로전서", "chap": 1, "verse": "18-19", "ref": "베드로전서 1:18-19", "texts": {"krv": "너희가 알거니와 너희 조상의 유전한 망령된 행실에서 구속된 것은 은이나 금 같이 없어질 것으로 한 것이 아니요 오직 흠 없고 점 없는 어린 양 같은 그리스도의 보배로운 피로 한 것이니라", "kkjv": "너희가 알거니와 너희 조상들로부터 전통으로 물려받은 너희의 헛된 행실에서 너희가 구속받은 것은 은이나 금같이 썩을 것들로 된 것이 아니요, 오직 흠도 없고 점도 없는 어린양의 피 같은 그리스도의 보배로운 피로 된 것이니라.", "web": "knowing that you were redeemed, not with corruptible things, with silver or gold, from the useless way of life handed down from your fathers, but with precious blood, as of a faultless and pure lamb, the blood of Christ;"}}, {"id": 184, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "예수 그리스도", "예수님의 재림"], "book": "데살로니가전서", "chap": 4, "verse": "16-17", "ref": "데살로니가전서 4:16-17", "texts": {"krv": "주께서 호령과 천사장의 소리와 하나님의 나팔로 친히 하늘로 좇아 강림하시리니 그리스도 안에서 죽은 자들이 먼저 일어나고 그 후에 우리 살아 남은 자도 저희와 함께 구름 속으로 끌어 올려 공중에서 주를 영접하게 하시리니 그리하여 우리가 항상 주와 함께 있으리라", "kkjv": "주께서 호령과 천사장의 음성과 하나님의 나팔 소리와 함께 친히 하늘로부터 내려오시리니 그리스도 안에서 죽은 자들이 먼저 일어나고 그 뒤에 살아서 남아 있는 우리가 그들과 함께 구름들 속으로 채여 올라가 공중에서 주를 만나리라. 그리하여 우리가 항상 주와 함께 있으리라.", "web": "For the Lord himself will descend from heaven with a shout, with the voice of the archangel, and with God’s trumpet. The dead in Christ will rise first, then we who are alive, who are left, will be caught up together with them in the clouds, to meet the Lord in the air. So we will be with the Lord forever."}}, {"id": 185, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "예수 그리스도", "예수님의 재림"], "book": "요한일서", "chap": 3, "verse": "2-3", "ref": "요한일서 3:2-3", "texts": {"krv": "사랑하는 자들아 우리가 지금은 하나님의 자녀라 장래에 어떻게 될 것은 아직 나타나지 아니하였으나 그가 나타내심이 되면 우리가 그와 같을 줄을 아는 것은 그의 계신 그대로 볼 것을 인함이니 주를 항하여 이 소망을 가진 자마다 그의 깨끗하심과 같이 자기를 깨끗하게 하느니라", "kkjv": "사랑하는 자들아, 이제 우리는 하나님의 아들들이니라. 우리가 앞으로 어떻게 될지는 아직 나타나지 아니하였으되 그분께서 나타나시면 우리가 그분과 같게 될 줄 아노니 이는 우리가 그분을 그분께서 계신 그대로 볼 것이기 때문이라. 그분 안에서 이 소망을 가진 자마다 그분께서 순결하신 것 같이 자기를 순결하게 하느니라.", "web": "Beloved, now we are children of God, and it is not yet revealed what we will be. But we know that, when he is revealed, we will be like him; for we will see him just as he is. Everyone who has this hope set on him purifies himself, even as he is pure."}}, {"id": 186, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "성령", "증거하시는 성령"], "book": "요한복음", "chap": 16, "verse": "13-14", "ref": "요한복음 16:13-14", "texts": {"krv": "그러하나 진리의 성령이 오시면 그가 너희를 모든 진리 가운데로 인도하시리니 그가 자의로 말하지 않고 오직 듣는 것을 말하시며 장래 일을 너희에게 알리시리라 그가 내 영광을 나타내리니 내 것을 가지고 너희에게 알리겠음이니라", "kkjv": "그러나 그분 곧 진리의 영께서 오시면 너희를 모든 진리 가운데로 인도하시리니 그분은 스스로 말씀하지 아니하시고 무엇이든지 자기가 들을 것만을 말씀하시며 앞으로 일어날 일들을 너희에게 보이시리라. 그분께서 나를 영화롭게 하시리니 이는 그분께서 내게서 받아 그것을 너희에게 보이실 것이기 때문이라.", "web": "However when he, the Spirit of truth, has come, he will guide you into all truth, for he will not speak from himself; but whatever he hears, he will speak. He will declare to you things that are coming. He will glorify me, for he will take from what is mine, and will declare it to you."}}, {"id": 187, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "성령", "증거하시는 성령"], "book": "고린도전서", "chap": 12, "verse": "3", "ref": "고린도전서 12:3", "texts": {"krv": "그러므로 내가 너희에게 알게 하노니 하나님의 영으로 말하는 자는 누구든지 예수를 저주할 자라 하지 않고 또 성령으로 아니하고는 누구든지 예수를 주시라 할 수 없느니라", "kkjv": "그러므로 내가 너희에게 깨닫게 하노니 하나님의 영으로 말미암아 말하는 자는 아무도 예수님을 저주받은 자라 하지 아니하고 또 성령님으로 말미암지 않고서는 아무도 예수님을 주라고 말할 수 없느니라.", "web": "Therefore I make known to you that no man speaking by God’s Spirit says, “Jesus is accursed.” No one can say, “Jesus is Lord,” but by the Holy Spirit."}}, {"id": 188, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "성령", "내주하시는 성령"], "book": "로마서", "chap": 8, "verse": "9", "ref": "로마서 8:9", "texts": {"krv": "만일 너희 속에 하나님의 영이 거하시면 너희가 육신에 있지 아니하고 영에 있나니 누구든지 그리스도의 영이 없으면 그리스도의 사람이 아니라", "kkjv": "그러나 너희 안에 하나님의 영께서 거하시면 너희가 육신 안에 있지 아니하고 성령 안에 있나니 이제 어떤 사람에게 그리스도의 영이 없으면 그는 그분의 사람이 아니니라.", "web": "But you are not in the flesh but in the Spirit, if it is so that the Spirit of God dwells in you. But if any man doesn’t have the Spirit of Christ, he is not his."}}, {"id": 189, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "성령", "내주하시는 성령"], "book": "갈라디아서", "chap": 4, "verse": "6", "ref": "갈라디아서 4:6", "texts": {"krv": "너희가 아들인 고로 하나님이 그 아들의 영을 우리 마음 가운데 보내사 아바 아버지라 부르게 하셨느니라", "kkjv": "너희가 아들이므로 하나님께서 자신의 아들의 영을 너희 마음속에 보내사, 아바, 아버지, 하고 부르짖게 하셨느니라.", "web": "And because you are children, God sent out the Spirit of his Son into your hearts, crying, “Abba, Father!”"}}, {"id": 190, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "성령", "통치하시는 성령"], "book": "에베소서", "chap": 5, "verse": "18", "ref": "에베소서 5:18", "texts": {"krv": "술 취하지 말라 이는 방탕한 것이니 오직 성령의 충만을 받으라", "kkjv": "술 취하지 말라. 거기에는 과도함이 있나니 오직 성령으로 충만하라.", "web": "Don’t be drunken with wine, in which is dissipation, but be filled with the Spirit,"}}, {"id": 191, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "성령", "통치하시는 성령"], "book": "갈라디아서", "chap": 5, "verse": "16", "ref": "갈라디아서 5:16", "texts": {"krv": "내가 이르노니 너희는 성령을 좇아 행하라 그리하면 육체의 욕심을 이루지 아니하리라", "kkjv": "그런즉 내가 이것을 말하노니 곧 성령 안에서 걸으라. 그리하면 너희가 육신의 욕심을 이루지 아니하리라.", "web": "But I say, walk by the Spirit, and you won’t fulfill the lust of the flesh."}}, {"id": 192, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "성령", "계시하시는 성령"], "book": "고린도전서", "chap": 2, "verse": "9-10", "ref": "고린도전서 2:9-10", "texts": {"krv": "기록된바 하나님이 자기를 사랑하는 자들을 위하여 예비하신 모든 것은 눈으로 보지 못하고 귀로도 듣지 못하고 사람의 마음으로도 생각지 못하였다 함과 같으니라 오직 하나님이 성령으로 이것을 우리에게 보이셨으니 성령은 모든 것 곧 하나님의 깊은 것이라도 통달하시느니라", "kkjv": "그러나 이것은 기록된바, 하나님께서 자신을 사랑하는 자들을 위하여 예비하신 것들은 눈이 보지 못하였고 귀가 듣지 못하였으며 사람의 마음속에 들어가지도 못하였도다, 함과 같으니라. 그러나 하나님께서 자신의 영으로 우리에게 그것들을 계시하셨으니 성령께서는 참으로 모든 것 즉 하나님의 깊은 것들을 살피시느니라.", "web": "But as it is written,  “Things which an eye didn’t see, and an ear didn’t hear, which didn’t enter into the heart of man, these God has prepared for those who love him.” But to us, God revealed them through the Spirit. For the Spirit searches all things, yes, the deep things of God."}}, {"id": 193, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "성령", "계시하시는 성령"], "book": "요한복음", "chap": 14, "verse": "26", "ref": "요한복음 14:26", "texts": {"krv": "보혜사 곧 아버지께서 내 이름으로 보내실 성령 그가 너희에게 모든 것을 가르치시고 내가 너희에게 말한 모든 것을 생각나게 하시리라", "kkjv": "위로자 곧 아버지께서 내 이름으로 보내실 성령님 그분께서 너희에게 모든 것을 가르치시고 내가 너희에게 무엇을 말하였든지 너희가 모든 것을 기억하게 하시리라.", "web": "But the Counselor, the Holy Spirit, whom the Father will send in my name, he will teach you all things, and will remind you of all that I said to you."}}, {"id": 194, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "성령", "능력을 주시는 성령"], "book": "고린도전서", "chap": 2, "verse": "4-5", "ref": "고린도전서 2:4-5", "texts": {"krv": "내 말과 내 전도함이 지혜의 권하는 말로 하지 아니하고 다만 성령의 나타남과 능력으로 하여 너희 믿음이 사람의 지혜에 있지 아니하고 다만 하나님의 능력에 있게 하려 하였노라", "kkjv": "또 나의 말과 나의 복음 선포를 사람의 지혜의 유혹하는 말들로 하지 아니하고 성령과 권능을 실증함으로 하였으니 이것은 너희의 믿음이 사람들의 지혜 안에 서지 아니하고 오직 하나님의 권능 안에 서게 하려 함이라.", "web": "My speech and my preaching were not in persuasive words of human wisdom, but in demonstration of the Spirit and of power, that your faith wouldn’t stand in the wisdom of men, but in the power of God."}}, {"id": 195, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "성령", "능력을 주시는 성령"], "book": "데살로니가전서", "chap": 1, "verse": "5", "ref": "데살로니가전서 1:5", "texts": {"krv": "이는 우리 복음이 말로만 너희에게 이른 것이 아니라 오직 능력과 성령과 큰 확신으로 된 것이니 우리가 너희 가운데서 너희를 위하여 어떠한 사람이 된 것은 너희 아는 바와 같으니라", "kkjv": "이는 우리의 복음이 말로만 너희에게 이르지 아니하고 권능과 성령님과 큰 확신으로 이르렀기 때문이니라. 우리가 너희를 위해 너희 가운데서 어떤 사람이 되었는지는 너희가 아는 바와 같으니라.", "web": "and that our Good News came to you not in word only, but also in power, and in the Holy Spirit, and with much assurance. You know what kind of men we showed ourselves to be among you for your sake."}}, {"id": 196, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "성령", "은사를 주시는 성령"], "book": "고린도전서", "chap": 12, "verse": "11", "ref": "고린도전서 12:11", "texts": {"krv": "이 모든 일은 같은 한 성령이 행하사 그 뜻대로 각 사람에게 나눠 주시느니라", "kkjv": "이 모든 것은 같은 그 한 성령께서 행하사 자신의 뜻대로 각 사람에게 개별적으로 나누어 주시는 것이니라.", "web": "But the one and the same Spirit works all of these, distributing to each one separately as he desires."}}, {"id": 197, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "성령", "은사를 주시는 성령"], "book": "고린도전서", "chap": 12, "verse": "4-6", "ref": "고린도전서 12:4-6", "texts": {"krv": "은사는 여러 가지나 성령은 같고 직임은 여러 가지나 주는 같으며 또 역사는 여러 가지나 모든 것을 모든 사람 가운데서 역사하시는 하나님은 같으니", "kkjv": "이제 선물은 여러 가지나 같은 성령이시고 직무는 다르나 같은 주시며 활동은 여러 가지나 모든 것 안에서 모든 것을 행하시는 같은 하나님이 계시되", "web": "Now there are various kinds of gifts, but the same Spirit. There are various kinds of service, and the same Lord. There are various kinds of workings, but the same God, who works all things in all."}}, {"id": 198, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "하나님", "하나님의 능력"], "book": "예레미야", "chap": 32, "verse": "17", "ref": "예레미야 32:17", "texts": {"krv": "슬프도소이다 주 여호와여 주께서 큰 능과 드신 팔로 천지를 지으셨사오니 주에게는 능치 못한 일이 없으시니이다", "kkjv": "아, 주 하나님이여! 보시옵소서. 주께서 주의 크신 권능과 뻗은 팔로 하늘과 땅을 만드셨사오니 주께는 너무 어려운 일이 없나이다.", "web": "Ah Lord Yahweh! Behold, you have made the heavens and the earth by your great power and by your outstretched arm; there is nothing too hard for you,"}}, {"id": 199, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "하나님", "하나님의 지혜"], "book": "로마서", "chap": 11, "verse": "33", "ref": "로마서 11:33", "texts": {"krv": "깊도다 하나님의 지혜와 지식의 부요함이여 그의 판단은 측량치 못할 것이며 그의 길은 찾지 못할 것이로다", "kkjv": "오 깊도다, 하나님의 지혜와 지식의 부요함이여! 그분의 판단들은 헤아릴 수 없으며 그분의 길들은 찾지 못할 것이로다!", "web": "Oh the depth of the riches both of the wisdom and the knowledge of God! How unsearchable are his judgments, and his ways past tracing out!"}}, {"id": 200, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "하나님", "하나님의 임재"], "book": "예레미야", "chap": 23, "verse": "24", "ref": "예레미야 23:24", "texts": {"krv": "나 여호와가 말하노라 사람이 내게 보이지 아니하려고 누가 자기를 은밀한 곳에 숨길 수 있겠느냐 나 여호와가 말하노라 나는 천지에 충만하지 아니하냐", "kkjv": "주가 말하노라. 어느 누가 내가 보지 못하도록 자신을 은밀한 곳에 숨길 수 있느냐? 주가 말하노라. 내가 하늘과 땅을 가득 채우지 아니하느냐?", "web": "Can any hide himself in secret places so that I shall not see him? says Yahweh. Don’t I fill heaven and earth? says Yahweh."}}, {"id": 201, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "하나님", "하나님의 은혜"], "book": "고린도후서", "chap": 9, "verse": "8", "ref": "고린도후서 9:8", "texts": {"krv": "하나님이 능히 모든 은혜를 너희에게 넘치게 하시나니 이는 너희로 모든 일에 항상 모든 것이 넉넉하여 모든 착한 일을 넘치게 하게 하려 하심이라", "kkjv": "하나님께서 능히 모든 은혜를 너희에게 넘치게 하시나니 이것은 너희가 항상 모든 일에서 모든 것이 넉넉하여 모든 선한 일을 풍성히 하게 하려 하심이라.", "web": "And God is able to make all grace abound to you, that you, always having all sufficiency in everything, may abound to every good work."}}, {"id": 202, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "하나님", "하나님의 영광"], "book": "역대상", "chap": 29, "verse": "11-13", "ref": "역대상 29:11-13", "texts": {"krv": "여호와여 광대하심과 권능과 영광과 이김과 위엄이 다 주께 속하였사오니 천지에 있는 것이 다 주의 것이로소이다 여호와여 주권도 주께 속하였사오니 주는 높으사 만유의 머리심이니이다 부와 귀가 주께로 말미암고 또 주는 만유의 주재가 되사 손에 권세와 능력이 있사오니 모든 자를 크게 하심과 강하게 하심이 주의 손에 있나이다 우리 하나님이여 이제 우리가 주께 감사하오며 주의 영화로운 이름을 찬양하나이다", "kkjv": "오 주여, 광대하심과 권능과 영광과 승리와 위엄이 주의 것이오니 하늘과 땅에 있는 모든 것이 주의 것이니이다. 오 주여, 왕국도 주의 것이오니 주께서는 모든 것 위에 머리로서 높여지셨나이다. 재물과 명예가 다 주에게서 나오며 또 주께서는 모든 것을 통치하시나이다. 주의 손에 권능과 능력이 있사오니 사람을 크게 하심과 모든 사람에게 기력을 주심이 주의 손에 있나이다. 그러므로 우리 하나님이여, 이제 우리가 주께 감사하오며 주의 영화로운 이름을 찬양하나이다.", "web": "Yours, Yahweh, is the greatness, the power, the glory, the victory, and the majesty! For all that is in the heavens and in the earth is yours. Yours is the kingdom, Yahweh, and you are exalted as head above all. Both riches and honor come from you, and you rule over all; and in your hand is power and might; and it is in your hand to make great, and to give strength to all. Now therefore, our God, we thank you, and praise your glorious name."}}, {"id": 203, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "하나님", "하나님의 성실"], "book": "데살로니가후서", "chap": 3, "verse": "3", "ref": "데살로니가후서 3:3", "texts": {"krv": "주는 미쁘사 너희를 굳게 하시고 악한 자에게서 지키시리라", "kkjv": "그러나 주께서는 신실하사 너희를 굳게 세우시며 악으로부터 너희를 지키시리라.", "web": "But the Lord is faithful, who will establish you, and guard you from the evil one."}}, {"id": 204, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "하나님", "하나님은 영이심"], "book": "요한복음", "chap": 4, "verse": "24", "ref": "요한복음 4:24", "texts": {"krv": "하나님은 영이시니 예배하는 자가 신령과 진정으로 예배할지니라", "kkjv": "하나님은 영이시니 그분께 경배하는 자들이 반드시 영과 진리로 그분께 경배할지니라, 하시니라.", "web": "God is spirit, and those who worship him must worship in spirit and truth.”"}}, {"id": 205, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "하나님", "하나님의 거룩하심"], "book": "베드로전서", "chap": 1, "verse": "15-16", "ref": "베드로전서 1:15-16", "texts": {"krv": "오직 너희를 부르신 거룩한 자처럼 너희도 모든 행실에 거룩한 자가 되라 기록하였으되 내가 거룩하니 너희도 거룩할지어다 하셨느니라", "kkjv": "오직 너희를 부르신 분께서 거룩하신 것 같이 너희도 온갖 종류의 행실에서 거룩할지니라. 기록된바, 내가 거룩하니 너희도 거룩하라, 하셨느니라.", "web": "but just as he who called you is holy, you yourselves also be holy in all of your behavior; because it is written, “You shall be holy; for I am holy.”"}}, {"id": 206, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "하나님", "하나님의 광대하심"], "book": "시편", "chap": 145, "verse": "3", "ref": "시편 145:3", "texts": {"krv": "여호와는 광대하시니 크게 찬양할 것이라 그의 광대하심을 측량치 못하리로다", "kkjv": "주께서는 위대하시니 크게 찬양할지어다. 그분의 위대하심은 헤아릴 수 없도다.", "web": "Great is Yahweh, and greatly to be praised! His greatness is unsearchable."}}, {"id": 207, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "하나님", "하나님의 사랑"], "book": "요한일서", "chap": 4, "verse": "10", "ref": "요한일서 4:10", "texts": {"krv": "사랑은 여기 있으니 우리가 하나님을 사랑한 것이 아니요 오직 하나님이 우리를 사랑하사 우리 죄를 위하여 화목제로 그 아들을 보내셨음이니라", "kkjv": "우리가 하나님을 사랑하지 아니하였으나 그분께서 우리를 사랑하시고 자신의 아들을 보내사 우리의 죄들로 인한 화해 헌물로 삼으셨나니 여기에 사랑이 있느니라.", "web": "In this is love, not that we loved God, but that he loved us, and sent his Son as the atoning sacrifice for our sins."}}, {"id": 208, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "하나님", "하나님의 긍휼"], "book": "시편", "chap": 86, "verse": "15", "ref": "시편 86:15", "texts": {"krv": "그러나 주여 주는 긍휼히 여기시며 은혜를 베푸시며 노하기를 더디 하시며 인자와 진실이 풍성하신 하나님이시오니", "kkjv": "그러나, 오 주여, 주는 동정심이 많으시며 은혜로우시며 오래 참으시며 긍휼과 진리가 풍성하신 하나님이시오니", "web": "But you, Lord, are a merciful and gracious God, slow to anger, and abundant in loving kindness and truth."}}, {"id": 209, "coll": "180구절 주제별 성경 암송", "sub": ["1. 하나님을 알아감", "하나님", "하나님의 절대 주권"], "book": "로마서", "chap": 8, "verse": "28", "ref": "로마서 8:28", "texts": {"krv": "우리가 알거니와 하나님을 사랑하는 자 곧 그 뜻대로 부르심을 입은 자들에게는 모든 것이 합력하여 선을 이루느니라", "kkjv": "우리가 알거니와 하나님을 사랑하는 자들 곧 그분의 목적에 따라 부르심을 받은 자들에게는 모든 것이 합력하여 선을 이루느니라.", "web": "We know that all things work together for good for those who love God, to those who are called according to his purpose."}}, {"id": 210, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 말함", "진실을 말함"], "book": "에베소서", "chap": 4, "verse": "15", "ref": "에베소서 4:15", "texts": {"krv": "오직 사랑 안에서 참된 것을 하여 범사에 그에게까지 자랄지라 그는 머리니 곧 그리스도라", "kkjv": "오직 사랑 안에서 진리를 말하며 모든 일에서 그분 안에 이르도록 성장하게 하려 함이라. 그분은 머리시니 곧 그리스도시니라.", "web": "but speaking truth in love, we may grow up in all things into him, who is the head, Christ;"}}, {"id": 211, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 말함", "진실을 말함"], "book": "골로새서", "chap": 3, "verse": "9", "ref": "골로새서 3:9", "texts": {"krv": "너희가 서로 거짓말을 말라 옛 사람과 그 행위를 벗어 버리고", "kkjv": "서로 거짓말하지 말라. 너희는 옛 사람과 그의 행위를 벗어 버리고", "web": "Don’t lie to one another, seeing that you have put off the old man with his doings,"}}, {"id": 212, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 말함", "험담을 피함"], "book": "잠언", "chap": 17, "verse": "9", "ref": "잠언 17:9", "texts": {"krv": "허물을 덮어 주는 자는 사랑을 구하는 자요 그것을 거듭 말하는 자는 친한 벗을 이간하는 자니라", "kkjv": "범법을 덮어 주는 자는 사랑을 구하거니와 문제를 거듭 말하는 자는 친한 친구들을 갈라놓느니라.", "web": "He who covers an offense promotes love; but he who repeats a matter separates best friends."}}, {"id": 213, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 말함", "험담을 피함"], "book": "잠언", "chap": 11, "verse": "13", "ref": "잠언 11:13", "texts": {"krv": "두루 다니며 한담하는 자는 남의 비밀을 누설하나 마음이 신실한 자는 그런 것을 숨기느니라", "kkjv": "소문을 퍼뜨리는 자는 은밀한 일들을 드러내나 신실한 영을 지닌 자는 문제를 숨기느니라.", "web": "One who brings gossip betrays a confidence, but one who is of a trustworthy spirit is one who keeps a secret."}}, {"id": 214, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 말함", "은혜스럽게 말함"], "book": "골로새서", "chap": 4, "verse": "4-6", "ref": "골로새서 4:4-6", "texts": {"krv": "그리하면 내가 마땅히 할 말로써 이 비밀을 나타내리라 외인을 향하여서는 지혜로 행하여 세월을 아끼라 너희 말을 항상 은혜 가운데서 소금으로 고루게 함같이 하라 그리하면 각 사람에게 마땅히 대답할 것을 알리라", "kkjv": "이것은 내가 마땅히 할 말을 하여 그것을 드러내고자 함이라. 밖에 있는 자들을 향해서는 시간을 되찾으며 지혜롭게 걸으라. 너희 말을 소금으로 간 맞추어 항상 은혜롭게 하라. 그리하면 너희가 각 사람에게 어떻게 마땅히 대답해야 할지 알게 되리라.", "web": "that I may reveal it as I ought to speak. Walk in wisdom toward those who are outside, redeeming the time. Let your speech always be with grace, seasoned with salt, that you may know how you ought to answer each one."}}, {"id": 215, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 말함", "은혜스럽게 말함"], "book": "잠언", "chap": 15, "verse": "1", "ref": "잠언 15:1", "texts": {"krv": "유순한 대답은 분노를 쉬게 하여도 과격한 말은 노를 격동하느니라", "kkjv": "부드러운 대답은 진노를 돌이키거니와 가혹한 말들은 분노를 일으키느니라.", "web": "A gentle answer turns away wrath, but a harsh word stirs up anger."}}, {"id": 216, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 말함", "죄를 시인함"], "book": "야고보서", "chap": 5, "verse": "16", "ref": "야고보서 5:16", "texts": {"krv": "이러므로 너희 죄를 서로 고하며 병 낫기를 위하여 서로 기도하라 의인의 간구는 역사하는 힘이 많으니라", "kkjv": "너희 잘못들을 서로 고백하고 너희가 병 고침을 받도록 서로를 위해 기도하라. 의로운 자의 효력 있고 뜨거운 기도는 많은 유익이 있느니라.", "web": "Confess your offenses to one another, and pray for one another, that you may be healed. The insistent prayer of a righteous person is powerfully effective."}}, {"id": 217, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 말함", "죄를 시인함"], "book": "마태복음", "chap": 5, "verse": "23-24", "ref": "마태복음 5:23-24", "texts": {"krv": "그러므로 예물을 제단에 드리다가 거기서 네 형제에게 원망 들을 만한 일이 있는 줄 생각나거든 예물을 제단 앞에 두고 먼저 가서 형제와 화목하고 그 후에 와서 예물을 드리라", "kkjv": "그러므로 네가 네 예물을 제단으로 가져오다가 너를 대적할 어떤 일이 네 형제에게 있음을 거기서 기억하거든 네 예물을 거기에, 제단 앞에 두고 네 길로 가서 맨 먼저 네 형제와 화해하고 그 뒤에 와서 네 예물을 드리라.", "web": "“If therefore you are offering your gift at the altar, and there remember that your brother has anything against you, leave your gift there before the altar, and go your way. First be reconciled to your brother, and then come and offer your gift."}}, {"id": 218, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 말함", "경청함"], "book": "야고보서", "chap": 1, "verse": "19", "ref": "야고보서 1:19", "texts": {"krv": "내 사랑하는 형제들아 너희가 알거니와 사람마다 듣기는 속히 하고 말하기는 더디 하며 성내기도 더디 하라", "kkjv": "그러므로 내 사랑하는 형제들아, 사람마다 듣기는 빨리 하고 말하기는 더디 하며 진노하는 것도 더디 하라.", "web": "So, then, my beloved brothers, let every man be swift to hear, slow to speak, and slow to anger;"}}, {"id": 219, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 말함", "경청함"], "book": "잠언", "chap": 18, "verse": "13", "ref": "잠언 18:13", "texts": {"krv": "사연을 듣기 전에 대답하는 자는 미련하여 욕을 당하느니라", "kkjv": "문제를 듣기도 전에 대답하는 자에게는 그것이 어리석음이요, 수치니라.", "web": "He who gives answer before he hears, that is folly and shame to him."}}, {"id": 220, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 말함", "책망을 받아들임"], "book": "잠언", "chap": 9, "verse": "8-9", "ref": "잠언 9:8-9", "texts": {"krv": "거만한 자를 책망하지 말라 그가 너를 미워할까 두려우니라 지혜 있는 자를 책망하라 그가 너를 사랑하리라 지혜 있는 자에게 교훈을 더하라 그가 더욱 지혜로와질 것이요 의로운 사람을 가르치라 그의 학식이 더하리라", "kkjv": "비웃는 자를 책망하지 말라. 그가 너를 미워할까 염려하노라. 지혜로운 자를 꾸짖으라. 그가 너를 사랑하리라. 지혜로운 자에게 훈계를 주라. 그러면 그가 더욱 지혜롭게 되리라. 의로운 자를 가르치라. 그러면 그의 학식이 늘어나리라.", "web": "Don’t reprove a scoffer, lest he hate you. Reprove a wise man, and he will love you. Instruct a wise man, and he will be still wiser. Teach a righteous man, and he will increase in learning."}}, {"id": 221, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 말함", "책망을 받아들임"], "book": "마태복음", "chap": 18, "verse": "15", "ref": "마태복음 18:15", "texts": {"krv": "네 형제가 죄를 범하거든 가서 너와 그 사람과만 상대하여 권고하라 만일 들으면 네가 네 형제를 얻은 것이요", "kkjv": "¶또한 만일 네 형제가 네게 범법하거든 가서 너와 그만 따로 있을 때에 그의 허물을 그에게 일러 주라. 만일 그가 네 말을 들으면 네가 네 형제를 얻었느니라.", "web": "“If your brother sins against you, go, show him his fault between you and him alone. If he listens to you, you have gained back your brother."}}, {"id": 222, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 대함", "다른 사람을 용서함"], "book": "에베소서", "chap": 4, "verse": "32", "ref": "에베소서 4:32", "texts": {"krv": "서로 인자하게 하며 불쌍히 여기며 서로 용서하기를 하나님이 그리스도 안에서 너희를 용서하심과 같이 하라", "kkjv": "서로 친절히 대하며 상냥한 마음을 품고 서로 용서하기를 하나님께서 그리스도로 인하여 너희를 용서하신 것 같이 하라.", "web": "And be kind to one another, tender hearted, forgiving each other, just as God also in Christ forgave you."}}, {"id": 223, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 대함", "다른 사람을 용서함"], "book": "골로새서", "chap": 3, "verse": "13", "ref": "골로새서 3:13", "texts": {"krv": "누가 뉘게 혐의가 있거든 서로 용납하여 피차 용서하되 주께서 너희를 용서하신 것과 같이 너희도 그리하고", "kkjv": "누가 누구와 다툴 일이 있거든 서로 참고 서로 용서하되 그리스도께서 너희를 용서하신 것 같이 너희도 그리하며", "web": "bearing with one another, and forgiving each other, if any man has a complaint against any; even as Christ forgave you, so you also do."}}, {"id": 224, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 대함", "오래 참음"], "book": "에베소서", "chap": 4, "verse": "2", "ref": "에베소서 4:2", "texts": {"krv": "모든 겸손과 온유로 하고 오래 참음으로 사랑 가운데서 서로 용납하고", "kkjv": "모든 겸손과 온유와 오래 참음으로 사랑 안에서 서로 참아 주며", "web": "with all lowliness and humility, with patience, bearing with one another in love;"}}, {"id": 225, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 대함", "오래 참음"], "book": "디모데후서", "chap": 2, "verse": "24-25", "ref": "디모데후서 2:24-25", "texts": {"krv": "마땅히 주의 종은 다투지 아니하고 모든 사람을 대하여 온유하며 가르치기를 잘하며 참으며 거역하는 자를 온유함으로 징계할지니 혹 하나님이 저희에게 회개함을 주사 진리를 알게 하실까 하며", "kkjv": "주의 종은 결코 다투지 말아야 하며 모든 사람에게 부드러우며 가르치기를 잘하며 인내하며 스스로 반대하는 자들을 온유함으로 일깨워 주어야 하리라. 혹시 하나님께서 그들에게 회개를 허락하사 진리를 인정하게 하시리니", "web": "The Lord’s servant must not quarrel, but be gentle towards all, able to teach, patient, in gentleness correcting those who oppose him: perhaps God may give them repentance leading to a full knowledge of the truth,"}}, {"id": 226, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 대함", "분노를 다스림"], "book": "에베소서", "chap": 4, "verse": "26", "ref": "에베소서 4:26", "texts": {"krv": "분을 내어도 죄를 짓지 말며 해가 지도록 분을 품지 말고", "kkjv": "너희는 화를 내도 죄는 짓지 말며 해가 지도록 진노하지 말고", "web": "“Be angry, and don’t sin.” Don’t let the sun go down on your wrath,"}}, {"id": 227, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 대함", "분노를 다스림"], "book": "골로새서", "chap": 3, "verse": "8", "ref": "골로새서 3:8", "texts": {"krv": "이제는 너희가 이 모든 것을 벗어 버리라 곧 분과 악의와 훼방과 너희 입의 부끄러운 말이라", "kkjv": "이제는 너희도 이 모든 것을 내버리라. 곧 분노와 진노와 악의와 신성모독과 너희 입에서 나오는 더러운 대화라.", "web": "but now you also put them all away: anger, wrath, malice, slander, and shameful speaking out of your mouth."}}, {"id": 228, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 대함", "악의를 버림"], "book": "히브리서", "chap": 12, "verse": "15", "ref": "히브리서 12:15", "texts": {"krv": "너희는 돌아보아 하나님 은혜에 이르지 못하는 자가 있는가 두려워하고 또 쓴 뿌리가 나서 괴롭게 하고 많은 사람이 이로 말미암아 더러움을 입을까 두려워하고", "kkjv": "부지런히 살펴 하나님의 은혜에 이르지 못하는 자가 없게 하고 쓴 뿌리가 돋아나 너희를 괴롭게 하거나 그것으로 말미암아 많은 사람이 더럽게 되지 않도록 할지니", "web": "looking carefully lest there be any man who falls short of the grace of God; lest any root of bitterness springing up trouble you, and many be defiled by it;"}}, {"id": 229, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 대함", "악의를 버림"], "book": "에베소서", "chap": 4, "verse": "31", "ref": "에베소서 4:31", "texts": {"krv": "너희는 모든 악독과 노함과 분냄과 떠드는 것과 훼방하는 것을 모든 악의와 함께 버리고", "kkjv": "너희는 모든 쓴 것과 진노와 분노와 소리 지르는 것과 비방하는 것을 모든 악의와 함께 버리고", "web": "Let all bitterness, wrath, anger, outcry, and slander, be put away from you, with all malice."}}, {"id": 230, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 대함", "억울한 일을 참음"], "book": "베드로전서", "chap": 2, "verse": "20-21", "ref": "베드로전서 2:20-21", "texts": {"krv": "죄가 있어 매를 맞고 참으면 무슨 칭찬이 있으리요 오직 선을 행함으로 고난을 받고 참으면 이는 하나님 앞에 아름다우니라 이를 위하여 너희가 부르심을 입었으니 그리스도도 너희를 위하여 고난을 받으사 너희에게 본을 끼쳐 그 자취를 따라 오게 하려 하셨느니라", "kkjv": "너희가 너희 잘못으로 인하여 매를 맞고 참으면 그것이 무슨 영광이냐? 그러나 너희가 잘 행하고도 그것으로 인해 고난을 당하고 끈기 있게 그것을 견디면 이것은 하나님께서 받으실 만한 것이니라. 참으로 너희가 심지어 그 일을 위해 부르심을 받았나니 그리스도께서도 우리를 위해 고난을 당하심으로 우리에게 본을 남기사 너희가 자신의 발자취를 따라오게 하셨느니라.", "web": "For what glory is it if, when you sin, you patiently endure beating? But if, when you do well, you patiently endure suffering, this is commendable with God. For to this you were called, because Christ also suffered for us, leaving you an example, that you should follow his steps,"}}, {"id": 231, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 대함", "억울한 일을 참음"], "book": "로마서", "chap": 12, "verse": "19", "ref": "로마서 12:19", "texts": {"krv": "내 사랑하는 자들아 너희가 친히 원수를 갚지 말고 진노하심에 맡기라 기록되었으되 원수 갚는 것이 내게 있으니 내가 갚으리라고 주께서 말씀하시니라", "kkjv": "극진히 사랑하는 자들아, 너희 스스로 원수를 갚지 말고 도리어 진노하심에 맡기라. 기록된바, 원수 갚는 일은 내 것이니 내가 갚으리라. 주가 말하노라, 하였느니라.", "web": "Don’t seek revenge yourselves, beloved, but give place to God’s wrath. For it is written, “Vengeance belongs to me; I will repay, says the Lord.”"}}, {"id": 232, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 대함", "시기심을 버림"], "book": "잠언", "chap": 27, "verse": "4", "ref": "잠언 27:4", "texts": {"krv": "분은 잔인하고 노는 창수 같거니와 투기 앞에야 누가 서리요", "kkjv": "진노는 잔인하고 분노는 포악하거니와 시기 앞에야 누가 능히 서리요?", "web": "Wrath is cruel, and anger is overwhelming; but who is able to stand before jealousy?"}}, {"id": 233, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 대함", "시기심을 버림"], "book": "야고보서", "chap": 3, "verse": "16", "ref": "야고보서 3:16", "texts": {"krv": "시기와 다툼이 있는 곳에는 요란과 모든 악한 일이 있음이니라", "kkjv": "시기와 다툼이 있는 곳에는, 거기에는 혼란과 모든 악한 일이 있느니라.", "web": "For where jealousy and selfish ambition are, there is confusion and every evil deed."}}, {"id": 234, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 행함", "화목한 생활"], "book": "로마서", "chap": 15, "verse": "5-6", "ref": "로마서 15:5-6", "texts": {"krv": "이제 인내와 안위의 하나님이 너희로 그리스도 예수를 본받아 서로 뜻이 같게 하여 주사 한 마음과 한 입으로 하나님 곧 우리 주 예수 그리스도의 아버지께 영광을 돌리게 하려 하노라", "kkjv": "이제 인내와 안위의 하나님께서 너희에게 그리스도 예수님을 따라 서로를 향해 같은 마음을 갖게 하사 너희가 한 마음과 한 입으로 하나님 곧 우리 주 예수 그리스도의 아버지께 영광을 돌리게 하시기를 원하노라.", "web": "Now the God of patience and of encouragement grant you to be of the same mind one with another according to Christ Jesus, that with one accord you may with one mouth glorify the God and Father of our Lord Jesus Christ."}}, {"id": 235, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 행함", "화목한 생활"], "book": "고린도전서", "chap": 1, "verse": "10", "ref": "고린도전서 1:10", "texts": {"krv": "형제들아 내가 우리 주 예수 그리스도의 이름으로 너희를 권하노니 다 같은 말을 하고 너희 가운데 분쟁이 없이 같은 마음과 같은 뜻으로 온전히 합하라", "kkjv": "형제들아, 이제 내가 우리 주 예수 그리스도의 이름으로 너희에게 간청하노니 너희는 다 같은 것을 말하고 너희 가운데 분쟁이 없이 같은 생각과 같은 판단 안에서 완전히 함께 결합하라.", "web": "Now I beg you, brothers, through the name of our Lord, Jesus Christ, that you all speak the same thing and that there be no divisions among you, but that you be perfected together in the same mind and in the same judgment."}}, {"id": 236, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 행함", "다른 사람을 섬김"], "book": "마태복음", "chap": 20, "verse": "26-27", "ref": "마태복음 20:26-27", "texts": {"krv": "너희 중에는 그렇지 아니하니 너희 중에 누구든지 크고자 하는 자는 너희를 섬기는 자가 되고 너희 중에 누구든지 으뜸이 되고자 하는 자는 너희 종이 되어야 하리라", "kkjv": "너희끼리는 그리하지 말지니 너희 가운데 누구든지 크게 되고자 하는 자는 너희를 섬기는 자가 되고 너희 가운데 누구든지 으뜸이 되고자 하는 자는 너희 종이 될지니라.", "web": "It shall not be so among you, but whoever desires to become great among you shall beyour servant. Whoever desires to be first among you shall be your bondservant,"}}, {"id": 237, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 행함", "다른 사람을 섬김"], "book": "갈라디아서", "chap": 5, "verse": "13", "ref": "갈라디아서 5:13", "texts": {"krv": "형제들아 너희가 자유를 위하여 부르심을 입었으나 그러나 그 자유로 육체의 기회를 삼지 말고 오직 사랑으로 서로 종 노릇 하라", "kkjv": "형제들아, 너희가 부르심을 받아 자유에 이르렀으나 오직 자유를 육신을 위한 기회로 쓰지 말고 사랑으로 서로를 섬기라.", "web": "For you, brothers, were called for freedom. Only don’t use your freedom for gain to the flesh, but through love be servants to one another."}}, {"id": 238, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 행함", "남을 먼저 생각함"], "book": "로마서", "chap": 15, "verse": "2", "ref": "로마서 15:2", "texts": {"krv": "우리 각 사람이 이웃을 기쁘게 하되 선을 이루고 덕을 세우도록 할지니라", "kkjv": "우리 각 사람은 자기 이웃을 기쁘게 하여 그의 유익을 구하고 그를 세워 주어야 할지니라.", "web": "Let each one of us please his neighbor for that which is good, to be building him up."}}, {"id": 239, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 행함", "남을 먼저 생각함"], "book": "빌립보서", "chap": 2, "verse": "3-4", "ref": "빌립보서 2:3-4", "texts": {"krv": "아무 일에든지 다툼이나 허영으로 하지 말고 오직 겸손한 마음으로 각각 자기보다 남을 낫게 여기고 각각 자기 일을 돌아볼 뿐더러 또한 각각 다른 사람들의 일을 돌아보아 나의 기쁨을 충만케 하라", "kkjv": "어떤 일도 다툼이나 헛된 영광으로 하지 말고 오직 겸손한 생각으로 각각 자기보다 남을 더 낫게 여기며 각 사람이 자기 일들만 돌아보지 말고 각 사람이 남의 일들도 돌아보라.", "web": "doing nothing through rivalry or through conceit, but in humility, each counting others better than himself; each of you not just looking to his own things, but each of you also to the things of others."}}, {"id": 240, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 행함", "서로 격려함"], "book": "데살로니가전서", "chap": 5, "verse": "11", "ref": "데살로니가전서 5:11", "texts": {"krv": "그러므로 피차 권면하고 피차 덕을 세우기를 너희가 하는것 같이 하라", "kkjv": "그러므로 너희가 지금 하고 있는 것 같이 너희끼리 함께 위로하고 서로를 세우라.", "web": "Therefore exhort one another, and build each other up, even as you also do."}}, {"id": 241, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 행함", "서로 격려함"], "book": "전도서", "chap": 4, "verse": "9-10", "ref": "전도서 4:9-10", "texts": {"krv": "두 사람이 한 사람보다 나음은 저희가 수고함으로 좋은 상을 얻을 것임이라 혹시 저희가 넘어지면 하나가 그 동무를 붙들어 일으키려니와 홀로 있어 넘어지고 붙들어 일으킬 자가 없는 자에게는 화가 있으리라", "kkjv": "¶두 사람이 한 사람보다 나음은 그들이 자기들의 수고로 인하여 좋은 보상을 받기 때문이라. 혹시 그들이 넘어지면 한 사람이 자기 동료를 일으켜 세우려니와 홀로 있는 자는 넘어질 때에 화가 있으리니 그를 도와서 일으킬 다른 자가 그에게 없도다.", "web": "Two are better than one, because they have a good reward for their labor. For if they fall, the one will lift up his fellow; but woe to him who is alone when he falls, and doesn’t have another to lift him up."}}, {"id": 242, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 행함", "불쌍히 여김"], "book": "마태복음", "chap": 9, "verse": "36", "ref": "마태복음 9:36", "texts": {"krv": "무리를 보시고 민망히 여기시니 이는 저희가 목자 없는 양과 같이 고생하며 유리함이라", "kkjv": "¶그러나 그분께서 무리들을 보시고 그들을 불쌍히 여기는 마음을 가지셨으니 이는 그들이 목자 없는 양같이 지치고 널리 흩어졌기 때문이라.", "web": "But when he saw the multitudes, he was moved with compassion for them, because they were harassed and scattered, like sheep without a shepherd."}}, {"id": 243, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 행함", "불쌍히 여김"], "book": "로마서", "chap": 12, "verse": "15", "ref": "로마서 12:15", "texts": {"krv": "즐거워하는 자들로 함께 즐거워하고 우는 자들로 함께 울라", "kkjv": "기뻐하는 자들과 함께 기뻐하고 슬피 우는 자들과 함께 슬피 울라.", "web": "Rejoice with those who rejoice. Weep with those who weep."}}, {"id": 244, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 행함", "온유하게 대함"], "book": "야고보서", "chap": 3, "verse": "17", "ref": "야고보서 3:17", "texts": {"krv": "오직 위로부터 난 지혜는 첫째 성결하고 다음에 화평하고 관용하고 양순하며 긍휼과 선한 열매가 가득하고 편벽과 거짓이 없나니", "kkjv": "그러나 위로부터 난 지혜는 첫째 순수하고 다음으로 화평하며 부드럽고 간청을 잘 들어주며 긍휼과 선한 열매로 가득하고 차별이 없고 위선이 없나니", "web": "But the wisdom that is from above is first pure, then peaceful, gentle, reasonable, full of mercy and good fruits, without partiality, and without hypocrisy."}}, {"id": 245, "coll": "180구절 주제별 성경 암송", "sub": ["2. 사랑 안에서 자라감", "사랑으로 행함", "온유하게 대함"], "book": "갈라디아서", "chap": 6, "verse": "1", "ref": "갈라디아서 6:1", "texts": {"krv": "형제들아 사람이 만일 무슨 범죄한 일이 드러나거든 신령한 너희는 온유한 심령으로 그러한 자를 바로잡고 네 자신을 돌아보아 너도 시험을 받을까 두려워하라", "kkjv": "형제들아, 만일 어떤 사람이 잘못에 빠지거든 영적인 너희는 온유의 영으로 그러한 자를 회복시키고 네 자신을 살펴보아 너도 시험에 들지 않게 하라.", "web": "Brothers, even if a man is caught in some fault, you who are spiritual must restore such a one in a spirit of gentleness; looking to yourself so that you also aren’t tempted."}}, {"id": 246, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "약속", "약속의 중요성"], "book": "베드로후서", "chap": 1, "verse": "3-4", "ref": "베드로후서 1:3-4", "texts": {"krv": "그의 신기한 능력으로 생명과 경건에 속한 모든 것을 우리에게 주셨으니 이는 자기의 영광과 덕으로써 우리를 부르신 자를 앎으로 말미암음이라 이로써 그 보배롭고 지극히 큰 약속을 우리에게 주사 이 약속으로 말미암아 너희로 정욕을 인하여 세상에서 썩어질 것을 피하여 신의 성품에 참예하는 자가 되게 하려 하셨으니", "kkjv": "우리를 부르사 영광과 덕에 이르게 하신 분을 아는 것을 통해 그분의 신성한 권능이 생명과 하나님의 성품에 속한 모든 것을 우리에게 주셨도다. 그것들로 말미암아 지극히 크고 보배로운 약속들이 우리에게 주어졌나니 이것은 너희가 이 약속들을 힘입어 정욕으로 인해 세상에 있게 된 썩을 것을 피하여 하나님의 본성에 참여하는 자가 되게 하려 함이니라.", "web": "seeing that his divine power has granted to us all things that pertain to life and godliness, through the knowledge of him who called us by his own glory and virtue; by which he has granted to us his precious and exceedingly great promises; that through these you may become partakers of the divine nature, having escaped from the corruption that is in the world by lust."}}, {"id": 247, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "약속", "약속의 중요성"], "book": "고린도후서", "chap": 1, "verse": "20", "ref": "고린도후서 1:20", "texts": {"krv": "하나님의 약속은 얼마든지 그리스도 안에서 예가 되니 그런즉 그로 말미암아 우리가 아멘하여 하나님께 영광을 돌리게 되느니라", "kkjv": "하나님의 모든 약속은 그분 안에서 예가 되고 그분 안에서 아멘이 되어 우리를 통해 하나님의 영광이 되느니라.", "web": "For however many are the promises of God, in him is the “Yes.” Therefore also through him is the “Amen”, to the glory of God through us."}}, {"id": 248, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "약속", "선교를 위한 약속들"], "book": "고린도후서", "chap": 1, "verse": "3-4", "ref": "고린도후서 1:3-4", "texts": {"krv": "찬송하리로다 그는 우리 주 예수 그리스도의 하나님이시요 자비의 아버지시요 모든 위로의 하나님이시며 우리의 모든 환난 중에서 우리를 위로하사 우리로 하여금 하나님께 받는 위로로써 모든 환난 중에 있는 자들을 능히 위로하게 하시는 이시로다", "kkjv": "하나님을 찬송하리로다. 그분은 곧 우리 주 예수 그리스도의 아버지시요 긍휼의 아버지시며 모든 위로의 하나님이시니라. 그분께서 우리의 모든 환난 중에서 우리를 위로하심은 우리 자신이 하나님께 위로 받을 때 얻는 위로를 힘입어 우리가 어떤 고난 중에 있는 자들도 능히 위로하게 하려 하심이라.", "web": "Blessed be the God and Father of our Lord Jesus Christ, the Father of mercies and God of all comfort; who comforts us in all our affliction, that we may be able to comfort those who are in any affliction, through the comfort with which we ourselves are comforted by God."}}, {"id": 249, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "약속", "선교를 위한 약속들"], "book": "고린도전서", "chap": 3, "verse": "7-8", "ref": "고린도전서 3:7-8", "texts": {"krv": "그런즉 심는 이나 물 주는 이는 아무것도 아니로되 오직 자라나게 하시는 하나님뿐이니라 심는 이와 물 주는 이가 일반이나 각각 자기의 일하는 대로 자기의 상을 받으리라", "kkjv": "그런즉 이와 같이 심는 자나 물 주는 자는 아무것도 아니며 자라나게 하시는 이는 오직 하나님이시니라. 이제 심는 자와 물 주는 자는 하나이며 저마다 자기의 수고에 따라 자기의 보상을 받으리라.", "web": "So then neither he who plants is anything, nor he who waters, but God who gives the increase. Now he who plants and he who waters are the same, but each will receive his own reward according to his own labor."}}, {"id": 250, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "약속", "열매 맺는 삶을 위한 약속들"], "book": "시편", "chap": 1, "verse": "2-3", "ref": "시편 1:2-3", "texts": {"krv": "오직 여호와의 율법을 즐거워하여 그 율법을 주야로 묵상하는 자로다 저는 시냇가에 심은 나무가 시절을 좇아 과실을 맺으며 그 잎사귀가 마르지 아니함 같으니 그 행사가 다 형통하리로다", "kkjv": "그는 주의 율법을 기뻐하며 그분의 율법을 밤낮으로 묵상하는도다. 그는 물 있는 강가에 심은 나무 곧 제 철에 열매를 맺는 나무 같으며 그의 잎사귀 또한 시들지 아니하리로다. 그가 하는 것은 무엇이든지 형통하리로다.", "web": "but his delight is in Yahweh’s law. On his law he meditates day and night. He will be like a tree planted by the streams of water, that produces its fruit in its season, whose leaf also does not wither. Whatever he does shall prosper."}}, {"id": 251, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "약속", "열매 맺는 삶을 위한 약속들"], "book": "베드로후서", "chap": 1, "verse": "8", "ref": "베드로후서 1:8", "texts": {"krv": "이런 것이 너희에게 있어 흡족한즉 너희로 우리 주 예수 그리스도를 알기에 게으르지 않고 열매 없는 자가 되지 않게 하려니와", "kkjv": "이것들이 너희 안에 있어 풍성하면 그것들이 너희가 우리 주 예수 그리스도를 아는 것에서 빈약하거나 열매를 맺지 못하는 자가 되지 아니하게 하려니와", "web": "For if these things are yours and abound, they make you to be not idle nor unfruitful to the knowledge of our Lord Jesus Christ."}}, {"id": 252, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "약속", "고난 중 도우심을 위한 약속들"], "book": "베드로전서", "chap": 5, "verse": "10", "ref": "베드로전서 5:10", "texts": {"krv": "모든 은혜의 하나님 곧 그리스도 안에서 너희를 부르사 자기의 영원한 영광에 들어가게 하신 이가 잠깐 고난을 받은 너희를 친히 온전케 하시며 굳게 하시며 강하게 하시며 터를 견고케 하시리라", "kkjv": "그러나 모든 은혜의 하나님 곧 그리스도 예수님을 통해 우리를 부르사 자신의 영원한 영광에 이르게 하신 분께서 너희가 잠시 고난을 받은 뒤에 너희를 완전하게 하시고 굳건하게 하시며 강하게 하시고 정착시키시리니", "web": "But may the God of all grace, who called you to his eternal glory by Christ Jesus, after you have suffered a little while, perfect, establish, strengthen, and settle you."}}, {"id": 253, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "약속", "고난 중 도우심을 위한 약속들"], "book": "고린도후서", "chap": 12, "verse": "9", "ref": "고린도후서 12:9", "texts": {"krv": "내게 이르시기를 내 은혜가 네게 족하도다 이는 내 능력이 약한 데서 온전하여짐이라 하신지라 이러므로 도리어 크게 기뻐함으로 나의 여러 약한 것들에 대하여 자랑하리니 이는 그리스도의 능력으로 내게 머물게 하려 함이라", "kkjv": "그분께서 내게 이르시되, 내 은혜가 네게 족하도다. 나의 강한 능력은 약한 데서 완전해지느니라, 하셨느니라. 그러므로 내가 오히려 크게 기뻐하며 나의 연약한 것들을 자랑하리니 이것은 그리스도의 권능이 내 위에 머무르게 하려 함이라.", "web": "He has said to me, “My grace is sufficient for you, for my power is made perfect in weakness.” Most gladly therefore I will rather glory in my weaknesses, that the power of Christ may rest on me."}}, {"id": 254, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "약속", "공급을 위한 약속들"], "book": "에베소서", "chap": 1, "verse": "3", "ref": "에베소서 1:3", "texts": {"krv": "찬송하리로다 하나님 곧 우리 주 예수 그리스도의 아버지께서 그리스도 안에서 하늘에 속한 모든 신령한 복으로 우리에게 복 주시되", "kkjv": "하나님 곧 우리 주 예수 그리스도의 아버지를 찬송하리로다. 그분께서 그리스도 안에서 하늘의 처소들에 있는 모든 영적인 복으로 우리에게 복을 주셨으니", "web": "Blessed be the God and Father of our Lord Jesus Christ, who has blessed us with every spiritual blessing in the heavenly places in Christ;"}}, {"id": 255, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "약속", "공급을 위한 약속들"], "book": "시편", "chap": 37, "verse": "4-5", "ref": "시편 37:4-5", "texts": {"krv": "또 여호와를 기뻐하라 저가 네 마음의 소원을 이루어 주시리로다 너의 길을 여호와께 맡기라 저를 의지하면 저가 이루시고", "kkjv": "너는 또 주를 기뻐하라. 그분께서 네 마음에서 소원한 것들을 네게 주시리라. 네 길을 주께 맡기고 또 그분을 신뢰하라. 그분께서 그것을 이루시고", "web": "Also delight yourself in Yahweh, and he will give you the desires of your heart. Commit your way to Yahweh. Trust also in him, and he will do this:"}}, {"id": 256, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "약속", "용서에 대한 약속들"], "book": "요한일서", "chap": 2, "verse": "1-2", "ref": "요한일서 2:1-2", "texts": {"krv": "나의 자녀들아 내가 이것을 너희에게 씀은 너희로 죄를 범치 않게 하려 함이라 만일 누가 죄를 범하면 아버지 앞에서 우리에게 대언자가 있으니 곧 의로우신 예수 그리스도시라 저는 우리 죄를 위한 화목 제물이니 우리만 위할 뿐 아니요 온 세상의 죄를 위하심이라", "kkjv": "나의 어린 자녀들아, 내가 이것들을 너희에게 쓰는 것은 너희가 죄를 짓지 아니하게 하려 함이라. 만일 누가 죄를 지어도 우리에게 아버지와 함께 계신 변호자가 계시니 곧 의로우신 분 예수 그리스도시라. 그분은 우리의 죄들로 인한 화해 헌물이시니 우리의 죄들뿐 아니요 온 세상의 죄들로 인한 화해 헌물이시니라.", "web": "My little children, I write these things to you so that you may not sin. If anyone sins, we have a Counselor with the Father, Jesus Christ, the righteous. And he is the atoning sacrifice for our sins, and not for ours only, but also for the whole world."}}, {"id": 257, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "약속", "용서에 대한 약속들"], "book": "시편", "chap": 103, "verse": "12", "ref": "시편 103:12", "texts": {"krv": "동이 서에서 먼것 같이 우리 죄과를 우리에게서 멀리 옮기셨으며", "kkjv": "동이 서에서 먼 것 같이 그분께서 우리의 범법들을 우리에게서 멀리 옮기셨으며", "web": "As far as the east is from the west, so far has he removed our transgressions from us."}}, {"id": 258, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "말씀", "능력"], "book": "히브리서", "chap": 4, "verse": "12", "ref": "히브리서 4:12", "texts": {"krv": "하나님의 말씀은 살았고 운동력이 있어 좌우에 날선 어떤 검보다도 예리하여 혼과 영과 및 관절과 골수를 찔러 쪼개기까지 하며 또 마음의 생각과 뜻을 감찰하나니", "kkjv": "하나님의 말씀은 살아 있고 권능이 있으며 양날 달린 어떤 검보다도 예리하여 혼과 영과 및 관절과 골수를 찔러 둘로 나누기까지 하고 또 마음의 생각과 의도를 분별하는 분이시니", "web": "For the word of God is living, and active, and sharper than any two-edged sword, and piercing even to the dividing of soul and spirit, of both joints and marrow, and is able to discern the thoughts and intentions of the heart."}}, {"id": 259, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "말씀", "능력"], "book": "이사야", "chap": 55, "verse": "10-11", "ref": "이사야 55:10-11", "texts": {"krv": "비와 눈이 하늘에서 내려서는 다시 그리로 가지 않고 토지를 적시어서 싹이 나게 하며 열매가 맺게 하여 파종하는 자에게 종자를 주며 먹는 자에게 양식을 줌과 같이 내 입에서 나가는 말도 헛되이 내게로 돌아오지 아니하고 나의 뜻을 이루며 나의 명하여 보낸 일에 형통하리라", "kkjv": "비와 눈이 하늘에서 내려와 거기로 되돌아가지 아니하고 땅을 적셔서 땅이 열매를 맺게 하고 싹을 내게 하여 씨 뿌리는 자에게 씨를 주고 먹는 자에게 빵을 주게 하는 것 같이 내 입에서 나아가는 내 말도 그러하여 그것이 헛되이 내게로 되돌아오지 아니하고 내가 기뻐하는 것을 이루며 내가 그 말을 보내어 이루게 하려는 일에서 형통하리니", "web": "For as the rain comes down and the snow from the sky, and doesn’t return there, but waters the earth, and makes it grow and bud, and gives seed to the sower and bread to the eater; so shall my word be that goes out of my mouth: it shall not return to me void, but it shall accomplish that which I please, and it shall prosper in the thing I sent it to do."}}, {"id": 260, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "말씀", "영감"], "book": "베드로후서", "chap": 1, "verse": "20-21", "ref": "베드로후서 1:20-21", "texts": {"krv": "먼저 알 것은 경의 모든 예언은 사사로이 풀 것이 아니니 예언은 언제든지 사람의 뜻으로 낸 것이 아니요 오직 성령의 감동하심을 입은 사람들이 하나님께 받아 말한 것임이니라", "kkjv": "먼저 이것을 알라. 성경 기록의 대언은 결코 어떤 사적인 해석에서 나지 아니하였나니 대언은 옛적에 사람의 뜻으로 말미암아 나오지 아니하였고 오직 하나님의 거룩한 사람들은 성령님께서 자기들을 움직이시는 대로 말하였느니라.", "web": "knowing this first, that no prophecy of Scripture is of private interpretation. For no prophecy ever came by the will of man: but holy men of God spoke, being moved by the Holy Spirit."}}, {"id": 261, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "말씀", "영감"], "book": "데살로니가전서", "chap": 2, "verse": "13", "ref": "데살로니가전서 2:13", "texts": {"krv": "이러므로 우리가 하나님께 쉬지 않고 감사함은 너희가 우리에게 들은바 하나님의 말씀을 받을 때에 사람의 말로 아니하고 하나님의 말씀으로 받음이니 진실로 그러하다 이 말씀이 또한 너희 믿는 자 속에서 역사하느니라", "kkjv": "이런 까닭에 우리가 또한 하나님께 끊임없이 감사를 드림은 너희가 우리에게서 들은 하나님의 말씀을 받을 때에 그것을 사람들의 말로 받지 아니하고 하나님의 말씀으로 받았기 때문이니 진실로 그러하도다. 그 말씀이 또한 믿는 너희 안에서 효력 있게 일하느니라.", "web": "For this cause we also thank God without ceasing, that, when you received from us the word of the message of God, you accepted it not as the word of men, but, as it is in truth, the word of God, which also works in you who believe."}}, {"id": 262, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "말씀", "영양"], "book": "예레미야", "chap": 15, "verse": "16", "ref": "예레미야 15:16", "texts": {"krv": "만군의 하나님 여호와시여 나는 주의 이름으로 일컬음을 받는 자라 내가 주의 말씀을 얻어 먹었사오니 주의 말씀은 내게 기쁨과 내 마음의 즐거움이오나", "kkjv": "내가 주의 말씀들을 발견하고 그것들을 먹으매 주의 말씀이 내게 기쁨과 마음의 즐거움이 되었사오니, 오 주 만군의 하나님이여, 나는 주의 이름으로 불리나이다.", "web": "Your words were found, and I ate them; and your words were to me a joy and the rejoicing of my heart: for I am called by your name, Yahweh, God of Armies."}}, {"id": 263, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "말씀", "영양"], "book": "욥기", "chap": 23, "verse": "12", "ref": "욥기 23:12", "texts": {"krv": "내가 그의 입술의 명령을 어기지 아니하고 일정한 음식보다 그 입의 말씀을 귀히 여겼구나", "kkjv": "내가 그분의 입술의 명령에서 돌이키지 아니하고 내게 필요한 음식보다 그분의 입의 말씀들을 더 귀히 여겼도다.", "web": "I haven’t gone back from the commandment of his lips. I have treasured up the words of his mouth more than my necessary food."}}, {"id": 264, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "말씀", "알아야 함"], "book": "사도행전", "chap": 17, "verse": "11", "ref": "사도행전 17:11", "texts": {"krv": "베뢰아 사람은 데살로니가에 있는 사람보다 더 신사적이어서 간절한 마음으로 말씀을 받고 이것이 그러한가 하여 날마다 성경을 상고하므로", "kkjv": "이들은 데살로니가에 있던 자들보다 더 고귀하여 온전히 준비된 마음으로 말씀을 받아들이고 그것들이 그러한가 하여 날마다 성경 기록들을 탐구하므로", "web": "Now these were more noble than those in Thessalonica, in that they received the word with all readiness of the mind, examining the Scriptures daily to see whether these things were so."}}, {"id": 265, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "말씀", "알아야 함"], "book": "요한복음", "chap": 5, "verse": "39-40", "ref": "요한복음 5:39-40", "texts": {"krv": "너희가 성경에서 영생을 얻는 줄 생각하고 성경을 상고하거니와 이 성경이 곧 내게 대하여 증거하는 것이로다 그러나 너희가 영생을 얻기 위하여 내게 오기를 원하지 아니하는도다", "kkjv": "¶성경 기록들을 탐구하라. 너희가 그것들 안에서 영원한 생명을 얻는 줄로 생각하거니와 그것들은 곧 나에 대하여 증언하는 것들이니라. 그러나 너희는 생명을 얻기 위해 내게 오기를 원치 아니하는도다.", "web": "“You search the Scriptures, because you think that in them you have eternal life; and these are they which testify about me. Yet you will not come to me, that you may have life."}}, {"id": 266, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "말씀", "순종해야 함"], "book": "요한복음", "chap": 8, "verse": "31-32", "ref": "요한복음 8:31-32", "texts": {"krv": "그러므로 예수께서 자기를 믿은 유대인들에게 이르시되 너희가 내 말에 거하면 참 내 제자가 되고 진리를 알지니 진리가 너희를 자유케 하리라", "kkjv": "이에 예수님께서 자기를 믿은 그 유대인들에게 이르시되, 너희가 내 말에 거하면 참으로 내 제자가 되고 또 너희가 진리를 알리니 진리가 너희를 자유롭게 하리라, 하시니라.", "web": "Jesus therefore said to those Jews who had believed him, “If you remain in my word, then you are truly my disciples. You will know the truth, and the truth will make you free.”"}}, {"id": 267, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "말씀", "순종해야 함"], "book": "마태복음", "chap": 4, "verse": "4", "ref": "마태복음 4:4", "texts": {"krv": "예수께서 대답하여 가라사대 기록되었으되 사람이 떡으로만 살 것이 아니요 하나님의 입으로 나오는 모든 말씀으로 살 것이라 하였느니라 하시니", "kkjv": "그분께서 응답하여 이르시되, 기록된바, 사람이 빵으로만 살 것이 아니요, 하나님의 입에서 나오는 모든 말씀으로 살 것이라, 하였느니라, 하시더라.", "web": "But he answered, “It is written, ‘Man shall not live by bread alone, but by every word that proceeds out of the mouth of God.’”"}}, {"id": 268, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "말씀", "확실성"], "book": "마태복음", "chap": 24, "verse": "35", "ref": "마태복음 24:35", "texts": {"krv": "천지는 없어지겠으나 내 말은 없어지지 아니하리라", "kkjv": "하늘과 땅은 없어지겠으나 내 말들은 없어지지 아니하리라.", "web": "Heaven and earth will pass away, but my words will not pass away."}}, {"id": 269, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "말씀", "확실성"], "book": "요한복음", "chap": 17, "verse": "17", "ref": "요한복음 17:17", "texts": {"krv": "저희를 진리로 거룩하게 하옵소서 아버지의 말씀은 진리니이다", "kkjv": "아버지의 진리로 그들을 거룩히 구별하옵소서. 아버지의 말씀은 진리이니이다.", "web": "Sanctify them in your truth. Your word is truth."}}, {"id": 270, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "믿음", "믿음의 시련"], "book": "베드로전서", "chap": 1, "verse": "6-7", "ref": "베드로전서 1:6-7", "texts": {"krv": "그러므로 너희가 이제 여러 가지 시험을 인하여 잠깐 근심하게 되지 않을 수 없었으나 오히려 크게 기뻐하도다 너희 믿음의 시련이 불로 연단하여도 없어질 금보다 더 귀하여 예수 그리스도의 나타나실 때에 칭찬과 영광과 존귀를 얻게 하려 함이라", "kkjv": "비록 지금은 필요가 있어 너희가 여러 가지 시험으로 인해 잠시 근심하고 있지만 그 구원을 크게 기뻐하나니 이것은 너희 믿음의 단련이 불로 단련해도 없어지는 금을 단련하는 것보다 훨씬 더 귀하여 예수 그리스도께서 나타나실 때에 칭찬과 존귀와 영광으로 드러나게 하려 함이니라.", "web": "Wherein you greatly rejoice, though now for a little while, if need be, you have been put to grief in various trials, that the proof of your faith, which is more precious than gold that perishes even though it is tested by fire, may be found to result in praise, glory, and honor at the revelation of Jesus Christ—"}}, {"id": 271, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "믿음", "믿음의 시련"], "book": "야고보서", "chap": 1, "verse": "2-4", "ref": "야고보서 1:2-4", "texts": {"krv": "내 형제들아 너희가 여러 가지 시험을 만나거든 온전히 기쁘게 여기라 이는 너희 믿음의 시련이 인내를 만들어 내는 줄 너희가 앎이라 인내를 온전히 이루라 이는 너희로 온전하고 구비하여 조금도 부족함이 없게 하려 함이라", "kkjv": "내 형제들아, 너희가 여러 가지 시험에 빠질 때에 그것을 다 기쁨으로 여기라. 너희 믿음의 단련이 인내를 이루는 줄 너희가 아느니라. 오직 인내를 완전히 이루라. 이것은 너희가 완전하고 완벽하여 아무것도 부족함이 없게 하려 함이라.", "web": "Count it all joy, my brothers, when you fall into various temptations, knowing that the testing of your faith produces endurance. Let endurance have its perfect work, that you may be perfect and complete, lacking in nothing."}}, {"id": 272, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "믿음", "불신의 결과"], "book": "히브리서", "chap": 4, "verse": "2", "ref": "히브리서 4:2", "texts": {"krv": "저희와 같이 우리도 복음 전함을 받은 자이나 그러나 그 들은 바 말씀이 저희에게 유익되지 못한 것은 듣는 자가 믿음을 화합지 아니함이라", "kkjv": "우리뿐만 아니라 그들에게도 복음이 선포되었으나 선포된 그 말씀이 그것을 들은 자들 속에서 믿음과 섞이지 아니하였으므로 그들에게 유익을 끼치지 못하였느니라.", "web": "For indeed we have had good news preached to us, even as they also did, but the word they heard didn’t profit them, because it wasn’t mixed with faith by those who heard."}}, {"id": 273, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "믿음", "불신의 결과"], "book": "히브리서", "chap": 10, "verse": "38", "ref": "히브리서 10:38", "texts": {"krv": "오직 나의 의인은 믿음으로 말미암아 살리라 또한 뒤로 물러가면 내 마음이 저를 기뻐하지 아니하리라 하셨느니라", "kkjv": "이제 의인은 믿음으로 살리라. 그러나 어떤 사람이 뒤로 물러가면 내 혼이 그를 기뻐하지 아니하리라.", "web": "But the righteous will live by faith. If he shrinks back, my soul has no pleasure in him.”"}}, {"id": 274, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "믿음", "믿음의 투쟁"], "book": "에베소서", "chap": 6, "verse": "16", "ref": "에베소서 6:16", "texts": {"krv": "모든 것 위에 믿음의 방패를 가지고 이로써 능히 악한 자의 모든 화전을 소멸하고", "kkjv": "모든 것 위에 믿음의 방패를 취하여 그것으로 너희가 능히 그 사악한 자의 모든 불화살을 끄며", "web": "above all, taking up the shield of faith, with which you will be able to quench all the fiery darts of the evil one."}}, {"id": 275, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "믿음", "믿음의 투쟁"], "book": "디모데전서", "chap": 6, "verse": "11-12", "ref": "디모데전서 6:11-12", "texts": {"krv": "오직 너 하나님의 사람아 이것들을 피하고 의와 경건과 믿음과 사랑과 인내와 온유를 좇으며 믿음의 선한 싸움을 싸우라 영생을 취하라 이를 위하여 네가 부르심을 입었고 많은 증인 앞에서 선한 증거를 증거하였도다", "kkjv": "그러나, 오 하나님의 사람아, 너는 이것들을 피하고 의와 하나님의 성품과 믿음과 사랑과 인내와 온유를 추구하라. 믿음의 선한 싸움을 싸우며 영원한 생명을 붙들라. 그것을 위하여 너 역시 부르심을 받았고 많은 증인들 앞에서 선한 고백을 고백하였도다.", "web": "But you, man of God, flee these things, and follow after righteousness, godliness, faith, love, patience, and gentleness. Fight the good fight of faith. Lay hold of the eternal life to which you were called, and you confessed the good confession in the sight of many witnesses."}}, {"id": 276, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "믿음", "믿음의 근원"], "book": "히브리서", "chap": 11, "verse": "1", "ref": "히브리서 11:1", "texts": {"krv": "믿음은 바라는 것들의 실상이요 보지 못하는 것들의 증거니", "kkjv": "이제 믿음은 바라는 것들의 실체요 보이지 않는 것들의 증거니", "web": "Now faith is assurance of things hoped for, proof of things not seen."}}, {"id": 277, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "믿음", "믿음의 근원"], "book": "로마서", "chap": 10, "verse": "17", "ref": "로마서 10:17", "texts": {"krv": "그러므로 믿음은 들음에서 나며 들음은 그리스도의 말씀으로 말미암았느니라", "kkjv": "그런즉 이와 같이 믿음은 들음에 의해 오며 들음은 하나님의 말씀에 의해 오느니라.", "web": "So faith comes by hearing, and hearing by the word of God."}}, {"id": 278, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "믿음", "행하는 믿음"], "book": "히브리서", "chap": 6, "verse": "12", "ref": "히브리서 6:12", "texts": {"krv": "게으르지 아니하고 믿음과 오래 참음으로 말미암아 약속들을 기업으로 받는 자들을 본받는 자 되게 하려는 것이니라", "kkjv": "이것은 너희가 게으르지 아니하고 믿음과 인내를 통해 약속들을 상속받는 자들을 따르는 자들이 되게 하려 함이라.", "web": "that you won’t be sluggish, but imitators of those who through faith and patience inherited the promises."}}, {"id": 279, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "믿음", "행하는 믿음"], "book": "야고보서", "chap": 2, "verse": "17", "ref": "야고보서 2:17", "texts": {"krv": "이와 같이 행함이 없는 믿음은 그 자체가 죽은 것이라", "kkjv": "이와 같이 믿음도 행위가 없으면 그것만으로는 죽은 것이니라.", "web": "Even so faith, if it has no works, is dead in itself."}}, {"id": 280, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "믿음", "믿음으로 의롭게 됨"], "book": "갈라디아서", "chap": 2, "verse": "16", "ref": "갈라디아서 2:16", "texts": {"krv": "사람이 의롭게 되는 것은 율법의 행위에서 난 것이 아니요 오직 예수 그리스도를 믿음으로 말미암는 줄 아는 고로 우리도 그리스도 예수를 믿나니 이는 우리가 율법의 행위에서 아니고 그리스도를 믿음으로써 의롭다 함을 얻으려 함이라 율법의 행위로써는 의롭다 함을 얻을 육체가 없느니라", "kkjv": "사람이 율법의 행위로 의롭게 되지 아니하고 오직 예수 그리스도의 믿음으로 되는 줄 알므로 우리도 예수 그리스도를 믿었나니 이것은 우리가 율법의 행위가 아니라 그리스도의 믿음으로 의롭게 되고자 함이라. 율법의 행위로는 어떤 육체도 의롭게 될 수 없느니라.", "web": "yet knowing that a man is not justified by the works of the law but through faith in Jesus Christ, even we believed in Christ Jesus, that we might be justified by faith in Christ, and not by the works of the law, because no flesh will be justified by the works of the law."}}, {"id": 281, "coll": "180구절 주제별 성경 암송", "sub": ["3. 믿음 안에서 자라감", "믿음", "믿음으로 의롭게 됨"], "book": "로마서", "chap": 5, "verse": "1", "ref": "로마서 5:1", "texts": {"krv": "그러므로 우리가 믿음으로 의롭다 하심을 얻었은즉 우리 주 예수 그리스도로 말미암아 하나님으로 더불어 화평을 누리자", "kkjv": "그러므로 우리가 믿음으로 의롭게 되어 우리 주 예수 그리스도를 통해 하나님과의 화평을 누리는도다.", "web": "Being therefore justified by faith, we have peace with God through our Lord Jesus Christ;"}}, {"id": 282, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "승리", "그리스도 안에 있는 승리"], "book": "고린도전서", "chap": 15, "verse": "57", "ref": "고린도전서 15:57", "texts": {"krv": "우리 주 예수 그리스도로 말미암아 우리에게 이김을 주시는 하나님께 감사하노니", "kkjv": "그러나 우리 주 예수 그리스도를 통하여 우리에게 승리를 주시는 하나님께 감사하노라.", "web": "But thanks be to God, who gives us the victory through our Lord Jesus Christ."}}, {"id": 283, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "승리", "그리스도 안에 있는 승리"], "book": "고린도후서", "chap": 2, "verse": "14", "ref": "고린도후서 2:14", "texts": {"krv": "항상 우리를 그리스도 안에서 이기게 하시고 우리로 말미암아 각처에서 그리스도를 아는 냄새를 나타내시는 하나님께 감사하노라", "kkjv": "항상 우리를 그리스도 안에서 승리하게 하시고 우리를 통해 모든 곳에서 그분을 아는 냄새를 풍기게 하시는 하나님께 이제 감사하노라.", "web": "Now thanks be to God, who always leads us in triumph in Christ, and reveals through us the sweet aroma of his knowledge in every place."}}, {"id": 284, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "승리", "승리의 무기"], "book": "고린도후서", "chap": 10, "verse": "4-5", "ref": "고린도후서 10:4-5", "texts": {"krv": "우리의 싸우는 병기는 육체에 속한 것이 아니요 오직 하나님 앞에서 견고한 진을 파하는 강력이라 모든 이론을 파하며 하나님 아는 것을 대적하여 높아진 것을 다 파하고 모든 생각을 사로잡아 그리스도에게 복종케 하니", "kkjv": "(우리의 전쟁 무기는 육신에 속하지 아니하고 하나님을 통해 강력하여 강한 요새들도 무너뜨리느니라.) 우리는 상상하는 것과 또 하나님을 아는 것을 대적하여 스스로를 높이는 모든 높은 것을 무너뜨리고 모든 생각을 사로잡아 그리스도께 순종하게 하며", "web": "for the weapons of our warfare are not of the flesh, but mighty before God to the throwing down of strongholds, throwing down imaginations and every high thing that is exalted against the knowledge of God, and bringing every thought into captivity to the obedience of Christ;"}}, {"id": 285, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "승리", "승리의 무기"], "book": "에베소서", "chap": 6, "verse": "10-11", "ref": "에베소서 6:10-11", "texts": {"krv": "종말로 너희가 주 안에서와 그 힘의 능력으로 강건하여지고 마귀의 궤계를 능히 대적하기 위하여 하나님의 전신갑주를 입으라", "kkjv": "끝으로 내 형제들아, 주 안에서와 그분의 강력한 권능 안에서 강건한 자가 되라. 너희가 마귀의 간계들을 능히 대적하며 서기 위해 하나님의 전신갑주를 입으라.", "web": "Finally, be strong in the Lord, and in the strength of his might. Put on the whole armor of God, that you may be able to stand against the wiles of the devil."}}, {"id": 286, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "승리", "마귀를 이김"], "book": "요한계시록", "chap": 12, "verse": "11", "ref": "요한계시록 12:11", "texts": {"krv": "또 여러 형제가 어린 양의 피와 자기의 증거하는 말을 인하여 저를 이기었으니 그들은 죽기까지 자기 생명을 아끼지 아니하였도다", "kkjv": "그들이 어린양의 피와 자기들의 증언의 말로 그를 이기었으며 그들은 죽기까지 자기 생명을 사랑하지 아니하였도다.", "web": "They overcame him because of the Lamb’s blood, and because of the word of their testimony. They didn’t love their life, even to death."}}, {"id": 287, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "승리", "마귀를 이김"], "book": "야고보서", "chap": 4, "verse": "7-8", "ref": "야고보서 4:7-8", "texts": {"krv": "그런즉 너희는 하나님께 순복할지어다 마귀를 대적하라 그리하면 너희를 피하리라 하나님을 가까이 하라 그리하면 너희를 가까이 하시리라 죄인들아 손을 깨끗이 하라 두 마음을 품은 자들아 마음을 성결케 하라", "kkjv": "그러므로 하나님께 복종하라. 마귀를 대적하라. 그리하면 그가 너희에게서 도망하리라. 하나님께 가까이 나아가라. 그리하면 그분께서 너희에게 가까이 오시리라. 너희 죄인들아, 너희 손을 정결하게 하라. 두 마음을 품은 자들아, 너희 마음을 순결하게 하라.", "web": "Be subject therefore to God. But resist the devil, and he will flee from you. Draw near to God, and he will draw near to you. Cleanse your hands, you sinners; and purify your hearts, you double-minded."}}, {"id": 288, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "승리", "육신을 이김"], "book": "로마서", "chap": 8, "verse": "5-6", "ref": "로마서 8:5-6", "texts": {"krv": "육신을 좇는 자는 육신의 일을 영을 좇는 자는 영의 일을 생각하나니 육신의 생각은 사망이요 영의 생각은 생명과 평안이니라", "kkjv": "육신을 따르는 자들은 육신의 일들을 생각하거니와 성령을 따르는 자들은 성령의 일들을 생각하나니 육신적으로 생각하는 것은 사망이요 영적으로 생각하는 것은 생명과 평안이니라.", "web": "For those who live according to the flesh set their minds on the things of the flesh, but those who live according to the Spirit, the things of the Spirit. For the mind of the flesh is death, but the mind of the Spirit is life and peace;"}}, {"id": 289, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "승리", "육신을 이김"], "book": "로마서", "chap": 13, "verse": "14", "ref": "로마서 13:14", "texts": {"krv": "오직 주 예수 그리스도로 옷 입고 정욕을 위하여 육신의 일을 도모하지 말라", "kkjv": "오직 너희는 주 예수 그리스도로 옷 입고 육신의 정욕을 채우기 위해 육신에게 기회를 주지 말라.", "web": "But put on the Lord Jesus Christ, and make no provision for the flesh, for its lusts."}}, {"id": 290, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "승리", "세상을 이김"], "book": "요한일서", "chap": 4, "verse": "4", "ref": "요한일서 4:4", "texts": {"krv": "자녀들아 너희는 하나님께 속하였고 또 저희를 이기었나니 이는 너희 안에 계신 이가 세상에 있는 이보다 크심이라", "kkjv": "어린 자녀들아, 너희는 하나님께 속하였고 또 그들을 이기었나니 이는 너희 안에 계신 분이 세상에 있는 그보다 더 크시기 때문이라.", "web": "You are of God, little children, and have overcome them; because greater is he who is in you than he who is in the world."}}, {"id": 291, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "승리", "세상을 이김"], "book": "요한일서", "chap": 5, "verse": "4-5", "ref": "요한일서 5:4-5", "texts": {"krv": "대저 하나님께로서 난 자마다 세상을 이기느니라 세상을 이긴 이김은 이것이니 우리의 믿음이니라 예수께서 하나님의 아들이심을 믿는 자가 아니면 세상을 이기는 자가 누구뇨", "kkjv": "무엇이든 하나님에게서 난 것은 세상을 이기느니라. 세상을 이기는 승리는 이것이니 곧 우리의 믿음이니라. 예수님께서 하나님의 아들이심을 믿는 자가 아니면 누가 세상을 이기는 자냐?", "web": "For whatever is born of God overcomes the world. This is the victory that has overcome the world: your faith. Who is he who overcomes the world, but he who believes that Jesus is the Son of God?"}}, {"id": 292, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "승리", "죄를 이김"], "book": "시편", "chap": 37, "verse": "31", "ref": "시편 37:31", "texts": {"krv": "그 마음에는 하나님의 법이 있으니 그 걸음에 실족함이 없으리로다", "kkjv": "그의 마음속에는 그의 하나님의 법이 있으니 그의 발걸음은 하나도 미끄러지지 아니하리로다.", "web": "The law of his God is in his heart. None of his steps shall slide."}}, {"id": 293, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "승리", "죄를 이김"], "book": "로마서", "chap": 6, "verse": "12-13", "ref": "로마서 6:12-13", "texts": {"krv": "그러므로 너희는 죄로 너희 죽을 몸에 왕 노릇 하지 못하게 하여 몸의 사욕을 순종치 말고 또한 너희 지체를 불의의 병기로 죄에게 드리지 말고 오직 너희 자신을 죽은 자 가운데서 다시 산 자 같이 하나님께 드리며 너희 지체를 의의 병기로 하나님께 드리라", "kkjv": "그러므로 너희는 죄가 너희의 죽을 몸 안에서 군림하지 못하게 하여 몸의 정욕 안에서 죄에게 순종하지 말고 또한 너희 지체를 불의의 도구로 죄에게 내주지 말며 오직 너희 자신을 죽은 자들로부터 살아난 자로서 하나님께 드리고 너희 지체를 의의 도구로 하나님께 드리라.", "web": "Therefore don’t let sin reign in your mortal body, that you should obey it in its lusts. Neither present your members to sin as instruments of unrighteousness, but present yourselves to God, as alive from the dead, and your members as instruments of righteousness to God."}}, {"id": 294, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "순결", "생각"], "book": "빌립보서", "chap": 4, "verse": "8", "ref": "빌립보서 4:8", "texts": {"krv": "종말로 형제들아 무엇에든지 참되며 무엇에든지 경건하며 무엇에든지 옳으며 무엇에든지 정결하며 무엇에든지 사랑할 만하며 무엇에든지 칭찬할 만하며 무슨 덕이 있든지 무슨 기림이 있든지 이것들을 생각하라", "kkjv": "끝으로 형제들아, 무엇이든지 진실한 것과 무엇이든지 정직한 것과 무엇이든지 의로운 것과 무엇이든지 순수한 것과 무엇이든지 사랑스러운 것과 무엇이든지 좋은 평판이 있는 것과 덕이 되는 것과 칭찬이 되는 것이 있거든 이런 것들을 곰곰이 생각하라.", "web": "Finally, brothers, whatever things are true, whatever things are honorable, whatever things are just, whatever things are pure, whatever things are lovely, whatever things are of good report; if there is any virtue, and if there is any praise, think about these things."}}, {"id": 295, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "순결", "생각"], "book": "디도서", "chap": 1, "verse": "15", "ref": "디도서 1:15", "texts": {"krv": "깨끗한 자들에게는 모든 것이 깨끗하나 더럽고 믿지 아니하는 자들에게는 아무것도 깨끗한 것이 없고 오직 저희 마음과 양심이 더러운지라", "kkjv": "순수한 자들에게는 모든 것이 순수하나 더럽혀지고 믿지 않는 자들에게는 아무것도 순수하지 아니하고 오히려 그들의 생각과 양심마저도 더럽혀져 있느니라.", "web": "To the pure, all things are pure; but to those who are defiled and unbelieving, nothing is pure; but both their mind and their conscience are defiled."}}, {"id": 296, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "순결", "마음"], "book": "누가복음", "chap": 6, "verse": "45", "ref": "누가복음 6:45", "texts": {"krv": "선한 사람은 마음의 쌓은 선에서 선을 내고 악한 자는 그 쌓은 악에서 악을 내나니 이는 마음의 가득한 것을 입으로 말함이니라", "kkjv": "선한 사람은 자기 마음의 선한 보고에서 선한 것을 내고 악한 사람은 자기 마음의 악한 보고에서 악한 것을 내나니 그의 입은 마음에 가득한 것을 말하느니라.", "web": "The good man out of the good treasure of his heart brings out that which is good, and the evil man out of the evil treasure of his heart brings out that which is evil, for out of the abundance of the heart, his mouth speaks."}}, {"id": 297, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "순결", "마음"], "book": "잠언", "chap": 4, "verse": "23", "ref": "잠언 4:23", "texts": {"krv": "무릇 지킬 만한 것보다 더욱 네 마음을 지키라 생명의 근원이 이에서 남이니라", "kkjv": "¶열심을 다하여 네 마음을 지키라. 생명의 근원이 거기에서 나오느니라.", "web": "Keep your heart with all diligence, for out of it is the wellspring of life."}}, {"id": 298, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "순결", "눈"], "book": "마태복음", "chap": 6, "verse": "22", "ref": "마태복음 6:22", "texts": {"krv": "눈은 몸의 등불이니 그러므로 네 눈이 성하면 온 몸이 밝을 것이요", "kkjv": "몸의 등불은 눈이니 그러므로 네 눈이 단일하면 네 온 몸이 빛으로 가득하되", "web": "“The lamp of the body is the eye. If therefore your eye is sound, your whole body will be full of light."}}, {"id": 299, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "순결", "눈"], "book": "마태복음", "chap": 5, "verse": "28", "ref": "마태복음 5:28", "texts": {"krv": "나는 너희에게 이르노니 여자를 보고 음욕을 품는 자마다 마음에 이미 간음하였느니라", "kkjv": "나는 너희에게 이르노니, 누구든지 여자를 보고 그녀에게 음욕을 품는 자는 이미 마음속으로 그녀와 간음하였느니라.", "web": "but I tell you that everyone who gazes at a woman to lust after her has committed adultery with her already in his heart."}}, {"id": 300, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "순결", "몸"], "book": "데살로니가전서", "chap": 4, "verse": "3", "ref": "데살로니가전서 4:3", "texts": {"krv": "하나님의 뜻은 이것이니 너희의 거룩함이라 곧 음란을 버리고", "kkjv": "하나님의 뜻은 이것이니 곧 너희가 거룩히 구별되는 것이라. 너희는 음행을 삼가고", "web": "For this is the will of God: your sanctification, that you abstain from sexual immorality,"}}, {"id": 301, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "순결", "몸"], "book": "고린도전서", "chap": 6, "verse": "13", "ref": "고린도전서 6:13", "texts": {"krv": "식물은 배를 위하고 배는 식물을 위하나 하나님이 이것 저것 다 폐하시리라 몸은 음란을 위하지 않고 오직 주를 위하며 주는 몸을 위하시느니라", "kkjv": "음식들은 배를 위해 있고 배는 음식들을 위해 있거니와 하나님께서는 그것과 그것들을 다 멸하시리라. 이제 몸은 음행을 위해 있지 아니하고 주를 위해 있으며 주께서는 몸을 위해 계시느니라.", "web": "“Foods for the belly, and the belly for foods,” but God will bring to nothing both it and them. But the body is not for sexual immorality, but for the Lord; and the Lord for the body."}}, {"id": 302, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "순결", "말"], "book": "에베소서", "chap": 4, "verse": "29", "ref": "에베소서 4:29", "texts": {"krv": "무릇 더러운 말은 너희 입 밖에도 내지 말고 오직 덕을 세우는 데 소용되는 대로 선한 말을 하여 듣는 자들에게 은혜를 끼치게 하라", "kkjv": "부패한 대화는 결코 너희 입 밖으로 내지 말고 오직 세워 주는 일에 쓸 좋은 것만을 말하여 그것이 듣는 자들에게 은혜를 끼치게 하라.", "web": "Let no corrupt speech proceed out of your mouth, but such as is good for building up as the need may be, that it may give grace to those who hear."}}, {"id": 303, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "순결", "말"], "book": "마태복음", "chap": 12, "verse": "36-37", "ref": "마태복음 12:36-37", "texts": {"krv": "내가 너희에게 이르노니 사람이 무슨 무익한 말을 하든지 심판 날에 이에 대하여 심문을 받으리니 네 말로 의롭다 함을 받고 네 말로 정죄함을 받으리라", "kkjv": "오직 내가 너희에게 이르노니, 사람들이 무슨 쓸데없는 말을 하든지 심판 날에 그것에 대하여 회계 보고를 하리라. 네 말들로 네가 의롭게 되며 네 말들로 네가 정죄 받으리라, 하시니라.", "web": "I tell you that every idle word that men speak, they will give account of it in the day of judgment. For by your words you will be justified, and by your words you will be condemned.”"}}, {"id": 304, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "순결", "행동"], "book": "데살로니가전서", "chap": 5, "verse": "22", "ref": "데살로니가전서 5:22", "texts": {"krv": "악은 모든 모양이라도 버리라", "kkjv": "악의 모든 모양을 삼가라.", "web": "Abstain from every form of evil."}}, {"id": 305, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "순결", "행동"], "book": "디모데전서", "chap": 5, "verse": "1-2", "ref": "디모데전서 5:1-2", "texts": {"krv": "늙은이를 꾸짖지 말고 권하되 아비에게 하듯 하며 젊은이를 형제에게 하듯 하고 늙은 여자를 어미에게 하듯 하며 젊은 여자를 일절 깨끗함으로 자매에게 하듯 하라", "kkjv": "연로한 남자를 꾸짖지 말고 그를 아버지처럼 대하며 젊은 남자들은 형제처럼 대하고 연로한 여자들은 어머니처럼, 젊은 여자들은 온전히 순결하게 자매처럼 대하라.", "web": "Don’t rebuke an older man, but exhort him as a father; the younger men as brothers; the elder women as mothers; the younger as sisters, in all purity."}}, {"id": 306, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "기도", "구하고 행하라"], "book": "마태복음", "chap": 21, "verse": "22", "ref": "마태복음 21:22", "texts": {"krv": "너희가 기도할 때에 무엇이든지 믿고 구하는 것은 다 받으리라 하시니라", "kkjv": "너희가 믿고 기도할 때에 무엇을 구하든지 모든 것을 받으리라, 하시니라.", "web": "All things, whatever you ask in prayer, believing, you will receive.”"}}, {"id": 307, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "기도", "구하고 행하라"], "book": "마태복음", "chap": 7, "verse": "7-8", "ref": "마태복음 7:7-8", "texts": {"krv": "구하라 그러면 너희에게 주실 것이요 찾으라 그러면 찾을 것이요 문을 두드리라 그러면 너희에게 열릴 것이니 구하는 이마다 얻을 것이요 찾는 이가 찾을 것이요 두드리는 이에게 열릴 것이니라", "kkjv": "¶구하라. 그러면 너희에게 주실 것이요, 찾으라. 그러면 너희가 찾을 것이요, 두드리라. 그러면 너희에게 열릴 것이니 구하는 자마다 받고 찾는 자는 찾으며 두드리는 자에게 열릴 것이니라.", "web": "“Ask, and it will be given you. Seek, and you will find. Knock, and it will be opened for you. For everyone who asks receives. He who seeks finds. To him who knocks it will be opened."}}, {"id": 308, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "기도", "은밀한 기도"], "book": "마태복음", "chap": 6, "verse": "6", "ref": "마태복음 6:6", "texts": {"krv": "너는 기도할 때에 네 골방에 들어가 문을 닫고 은밀한 중에 계신 네 아버지께 기도하라 은밀한 중에 보시는 네 아버지께서 갚으시리라", "kkjv": "오직 너는 기도할 때에 네 골방으로 들어가 네 문을 닫고 은밀한 가운데 계시는 네 아버지께 기도하라. 그리하면 은밀한 가운데 보시는 네 아버지께서 네게 드러나게 갚아 주시리라.", "web": "But you, when you pray, enter into your inner room, and having shut your door, pray to your Father who is in secret, and your Father who sees in secret will reward you openly."}}, {"id": 309, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "기도", "은밀한 기도"], "book": "마가복음", "chap": 1, "verse": "35", "ref": "마가복음 1:35", "texts": {"krv": "새벽 오히려 미명에 예수께서 일어나 나가 한적한 곳으로 가사 거기서 기도하시더니", "kkjv": "새벽에 아직 날이 밝기 훨씬 전에 그분께서 일어나 나가서 외진 곳으로 떠나 거기서 기도하시더라.", "web": "Early in the morning, while it was still dark, he rose up and went out, and departed into a deserted place, and prayed there."}}, {"id": 310, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "기도", "하나님의 응답"], "book": "예레미야", "chap": 33, "verse": "3", "ref": "예레미야 33:3", "texts": {"krv": "너는 내게 부르짖으라 내가 네게 응답하겠고 네가 알지 못하는 크고 비밀한 일을 네게 보이리라", "kkjv": "나를 부르라. 그리하면 내가 네게 응답하고 네가 알지 못하는 크고 능력 있는 일들을 네게 보이리라.", "web": "Call to me, and I will answer you, and will show you great things, and difficult, which you don’t know."}}, {"id": 311, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "기도", "하나님의 응답"], "book": "에베소서", "chap": 3, "verse": "20", "ref": "에베소서 3:20", "texts": {"krv": "우리 가운데서 역사하시는 능력대로 우리의 온갖 구하는 것이나 생각하는 것에 더 넘치도록 능히 하실 이에게", "kkjv": "이제 우리 안에서 일하는 권능에 따라 우리가 구하거나 생각하는 모든 것 이상으로 심히 넘치도록 능히 행하실 분에게", "web": "Now to him who is able to do exceedingly abundantly above all that we ask or think, according to the power that works in us,"}}, {"id": 312, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "기도", "그의 뜻대로 기도함"], "book": "요한일서", "chap": 5, "verse": "14-15", "ref": "요한일서 5:14-15", "texts": {"krv": "그를 향하여 우리의 가진바 담대한 것이 이것이니 그의 뜻대로 무엇을 구하면 들으심이라 우리가 무엇이든지 구하는 바를 들으시는 줄을 안즉 우리가 그에게 구한 그것을 얻은 줄을 또한 아느니라", "kkjv": "그분 안에서 우리가 가진 확신은 이것이니 곧 우리가 그분의 뜻대로 무엇이든 구하면 그분께서 우리 말을 들으신다는 것이라. 우리가 무엇을 구하든지 그분께서 우리 말을 들으시는 줄 우리가 알진대 우리가 그분께 구하여 청원한 것들을 얻는 줄 우리가 아느니라.", "web": "This is the boldness which we have toward him, that, if we ask anything according to his will, he listens to us. And if we know that he listens to us, whatever we ask, we know that we have the petitions which we have asked of him."}}, {"id": 313, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "기도", "그의 뜻대로 기도함"], "book": "데살로니가전서", "chap": 5, "verse": "17-18", "ref": "데살로니가전서 5:17-18", "texts": {"krv": "쉬지 말고 기도하라 범사에 감사하라 이는 그리스도 예수 안에서 너희를 향하신 하나님의 뜻이니라", "kkjv": "쉬지 말고 기도하라. 모든 일에서 감사하라. 이것이 그리스도 예수님 안에서 너희에 대한 하나님의 뜻이니라.", "web": "Pray without ceasing. In everything give thanks, for this is the will of God in Christ Jesus toward you."}}, {"id": 314, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "기도", "중보의 기도"], "book": "사무엘상", "chap": 12, "verse": "23", "ref": "사무엘상 12:23", "texts": {"krv": "나는 너희를 위하여 기도하기를 쉬는 죄를 여호와 앞에 결단코 범치 아니하고 선하고 의로운 도로 너희를 가르칠 것인즉", "kkjv": "또한 나로 말하건대 너희를 위하여 기도하기를 쉼으로 내가 결단코 주께 죄를 짓지 아니하고 선하고 바른 길을 너희에게 가르칠 터인즉", "web": "Moreover as for me, far be it from me that I should sin against Yahweh in ceasing to pray for you: but I will instruct you in the good and the right way."}}, {"id": 315, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "기도", "중보의 기도"], "book": "마태복음", "chap": 9, "verse": "37-38", "ref": "마태복음 9:37-38", "texts": {"krv": "이에 제자들에게 이르시되 추수할 것은 많되 일군은 적으니 그러므로 추수하는 주인에게 청하여 추수할 일군들을 보내어 주소서 하라 하시니라", "kkjv": "이에 그분께서 자기 제자들에게 이르시되, 진실로 수확할 것은 많되 일꾼들이 적으니 그러므로 너희는 수확하시는 주께 기도하여 그분께서 그분의 수확 밭에 일꾼들을 보내실 것을 청하라, 하시니라.", "web": "Then he said to his disciples, “The harvest indeed is plentiful, but the laborers are few. Pray therefore that the Lord of the harvest will send out laborers into his harvest.”"}}, {"id": 316, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "기도", "찬양"], "book": "히브리서", "chap": 13, "verse": "15", "ref": "히브리서 13:15", "texts": {"krv": "이러므로 우리가 예수로 말미암아 항상 찬미의 제사를 하나님께 드리자 이는 그 이름을 증거하는 입술의 열매니라", "kkjv": "그러므로 우리가 그분으로 말미암아 계속해서 찬양의 희생을 하나님께 드리자. 그것은 곧 그분의 이름에 감사를 드리는 우리 입술의 열매니라.", "web": "Through him, then, let us offer up a sacrifice of praise to God  continually, that is, the fruit of lips which proclaim allegiance to his name."}}, {"id": 317, "coll": "180구절 주제별 성경 암송", "sub": ["4. 승리 안에서 행함", "기도", "찬양"], "book": "시편", "chap": 146, "verse": "1-2", "ref": "시편 146:1-2", "texts": {"krv": "할렐루야 내 영혼아 여호와를 찬양하라 나의 생전에 여호와를 찬양하며 나의 평생에 내 하나님을 찬송하리로다", "kkjv": "너희는 주를 찬양하라. 오 내 혼아, 주를 찬양하라. 내가 사는 동안에 주를 찬양하며 내가 생존하는 동안에 노래로 내 하나님을 찬양하리로다.", "web": "Praise Yah! Praise Yahweh, my soul. While I live, I will praise Yahweh. I will sing praises to my God as long as I exist."}}, {"id": 318, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "전도", "모든 사람에게 전파함"], "book": "골로새서", "chap": 1, "verse": "27-28", "ref": "골로새서 1:27-28", "texts": {"krv": "하나님이 그들로 하여금 이 비밀의 영광이 이방인 가운데 어떻게 풍성한 것을 알게 하려 하심이라 이 비밀은 너희 안에 계신 그리스도시니 곧 영광의 소망이니라 우리가 그를 전파하여 각 사람을 권하고 모든 지혜로 각 사람을 가르침은 각 사람을 그리스도 안에서 완전한 자로 세우려 함이니", "kkjv": "하나님께서는 이방인들 가운데서 이 신비의 영광의 풍성함이 무엇인지 자신의 성도들에게 알리려 하시는데 이 신비는 너희 안에 계신 그리스도 곧 영광의 소망이시니라. 우리가 그분을 선포하며 각 사람에게 경고하고 모든 지혜로 각 사람을 가르침은 우리가 각 사람을 그리스도 예수님 안에서 완전한 자로 드리고자 함이니라.", "web": "to whom God was pleased to make known what are the riches of the glory of this mystery among the Gentiles, which is Christ in you, the hope of glory; whom we proclaim, admonishing every man and teaching every man in all wisdom, that we may present every man perfect in Christ Jesus;"}}, {"id": 319, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "전도", "하나님의 사신이 됨"], "book": "고린도후서", "chap": 5, "verse": "19-20", "ref": "고린도후서 5:19-20", "texts": {"krv": "이는 하나님께서 그리스도 안에 계시사 세상을 자기와 화목하게 하시며 저희의 죄를 저희에게 돌리지 아니하시고 화목하게 하는 말씀을 우리에게 부탁하셨느니라 이러므로 우리가 그리스도를 대신하여 사신이 되어 하나님이 우리로 너희를 권면하시는것 같이 그리스도를 대신하여 간구하노니 너희는 하나님과 화목하라", "kkjv": "곧 하나님께서 그리스도 안에 계시사 세상을 자신과 화해하게 하시며 그들의 범법을 그들에게 돌리지 아니하시고 화해하게 하는 말씀을 우리에게 맡기셨느니라. 그런즉 하나님께서 우리를 통해 너희에게 간청하시는 것 같이 이제 우리가 그리스도를 위한 대사가 되어 그리스도를 대신하여 너희에게 간구하노니 너희는 하나님과 화해하라.", "web": "namely, that God was in Christ reconciling the world to himself, not reckoning to them their trespasses, and having committed to us the word of reconciliation. We are therefore ambassadors on behalf of Christ, as though God were entreating by us: we beg you on behalf of Christ, be reconciled to God."}}, {"id": 320, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "전도", "하나님을 기쁘시게 함"], "book": "데살로니가전서", "chap": 2, "verse": "4", "ref": "데살로니가전서 2:4", "texts": {"krv": "오직 하나님의 옳게 여기심을 입어 복음 전할 부탁을 받았으니 우리가 이와 같이 말함은 사람을 기쁘게 하려 함이 아니요 오직 우리 마음을 감찰하시는 하나님을 기쁘시게 하려 함이라", "kkjv": "다만 우리는 하나님의 허락을 받아 복음을 위탁받은 대로 말하노니 이것은 사람들을 기쁘게 하려 함이 아니요 오직 우리의 마음을 시험하시는 하나님을 기쁘게 하려 함이라.", "web": "But even as we have been approved by God to be entrusted with the Good News, so we speak; not as pleasing men, but God, who tests our hearts."}}, {"id": 321, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "전도", "모든 사람을 섬김"], "book": "고린도전서", "chap": 9, "verse": "19", "ref": "고린도전서 9:19", "texts": {"krv": "내가 모든 사람에게 자유하였으나 스스로 모든 사람에게 종이 된 것은 더 많은 사람을 얻고자 함이라", "kkjv": "내가 모든 사람으로부터 자유로우나 스스로 모든 사람에게 종이 된 것은 더 많은 사람을 얻고자 함이라.", "web": "For though I was free from all, I brought myself under bondage to all, that I might gain the more."}}, {"id": 322, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "전도", "시기를 분별함"], "book": "요한복음", "chap": 4, "verse": "35", "ref": "요한복음 4:35", "texts": {"krv": "너희가 넉 달이 지나야 추수할 때가 이르겠다 하지 아니하느냐 내가 너희에게 이르노니 눈을 들어 밭을 보라 희어져 추수하게 되었도다", "kkjv": "너희가 말하기를, 아직 넉 달이 남아 있고 그 뒤에 수확할 때가 이른다, 하지 아니하느냐? 보라, 내가 너희에게 이르노니, 너희 눈을 들어 밭들을 보라. 그것들이 이미 희게 되어 수확하게 되었도다.", "web": "Don’t you say, ‘There are yet four months until the harvest?’ Behold, I tell you, lift up your eyes, and look at the fields, that they are white for harvest already."}}, {"id": 323, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "전도", "생명을 나눔"], "book": "데살로니가전서", "chap": 2, "verse": "8", "ref": "데살로니가전서 2:8", "texts": {"krv": "우리가 이같이 너희를 사모하여 하나님의 복음으로만 아니라 우리 목숨까지 너희에게 주기를 즐겨함은 너희가 우리의 사랑하는 자 됨이니라", "kkjv": "우리가 이같이 너희를 다정하게 사모하여 하나님의 복음뿐 아니라 우리 자신의 혼까지도 너희에게 기꺼이 나누어 주고자 함은 너희가 우리에게 소중하였기 때문이라.", "web": "Even so, affectionately longing for you, we were well pleased to impart to you, not the Good News of God only, but also our own souls, because you had become very dear to us."}}, {"id": 324, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "전도", "죄의 실재"], "book": "로마서", "chap": 3, "verse": "10-12", "ref": "로마서 3:10-12", "texts": {"krv": "기록한바 의인은 없나니 하나도 없으며 깨닫는 자도 없고 하나님을 찾는 자도 없고 다 치우쳐 한가지로 무익하게 되고 선을 행하는 자는 없나니 하나도 없도다", "kkjv": "이것은 기록된바, 의로운 자는 없나니 단 한 사람도 없으며 깨닫는 자도 없고 하나님을 찾는 자도 없으며 그들이 다 길에서 벗어나 함께 무익하게 되고 선을 행하는 자가 없나니 단 한 사람도 없도다.", "web": "As it is written,  “There is no one righteous; no, not one. There is no one who understands. There is no one who seeks after God. They have all turned aside. They have together become unprofitable. There is no one who does good, no, not so much as one.”"}}, {"id": 325, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "전도", "죄의 결말"], "book": "데살로니가후서", "chap": 1, "verse": "8-9", "ref": "데살로니가후서 1:8-9", "texts": {"krv": "하나님을 모르는 자들과 우리 주 예수의 복음을 복종치 않는 자들에게 형벌을 주시리니 이런 자들이 주의 얼굴과 그의 힘의 영광을 떠나 영원한 멸망의 형벌을 받으리로다", "kkjv": "하나님을 알지 못하는 자들과 우리 주 예수 그리스도의 복음에 순종하지 아니하는 자들에게 타오르는 불로 징벌하실 때에 그리하시리라. 그들은 주의 앞과 그분의 권능의 영광에서 떠나 영존하는 파멸로 형벌을 받으리로다.", "web": "giving vengeance to those who don’t know God, and to those who don’t obey the Good News of our Lord Jesus, who will pay the penalty: eternal destruction from the face of the Lord and from the glory of his might,"}}, {"id": 326, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "전도", "그리스도께서 값을 치르심"], "book": "베드로전서", "chap": 2, "verse": "24", "ref": "베드로전서 2:24", "texts": {"krv": "친히 나무에 달려 그 몸으로 우리 죄를 담당하셨으니 이는 우리로 죄에 대하여 죽고 의에 대하여 살게 하려 하심이라 저가 채찍에 맞음으로 너희는 나음을 얻었나니", "kkjv": "친히 나무에 달려 자신의 몸으로 우리의 죄들을 지셨으니 이것은 죄들에 대하여 죽은 우리가 살아서 의에 이르게 하려 하심이라. 그분께서 채찍에 맞음으로 너희가 고침을 받았나니", "web": "who his own self bore our sins in his body on the tree, that we, having died to sins, might live to righteousness; by whose stripes you were healed."}}, {"id": 327, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "전도", "선물로 주신 구원"], "book": "디모데후서", "chap": 1, "verse": "9", "ref": "디모데후서 1:9", "texts": {"krv": "하나님이 우리를 구원하사 거룩하신 부르심으로 부르심은 우리의 행위대로 하심이 아니요 오직 자기 뜻과 영원한 때 전부터 그리스도 예수 안에서 우리에게 주신 은혜대로 하심이라", "kkjv": "그분께서 우리를 구원하시고 거룩한 부르심으로 부르신 것은 우리의 행위에 따른 것이 아니요 자신의 목적과 은혜에 따른 것이니라. 그 은혜는 세상이 시작되기 전에 그리스도 예수님 안에서 우리에게 주어졌으나", "web": "who saved us and called us with a holy calling, not according to our works, but according to his own purpose and grace, which was given to us in Christ Jesus before times eternal,"}}, {"id": 328, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "전도", "믿고 영접함"], "book": "로마서", "chap": 10, "verse": "9-10", "ref": "로마서 10:9-10", "texts": {"krv": "네가 만일 네 입으로 예수를 주로 시인하며 또 하나님께서 그를 죽은 자 가운데서 살리신 것을 네 마음에 믿으면 구원을 얻으리니 사람이 마음으로 믿어 의에 이르고 입으로 시인하여 구원에 이르느니라", "kkjv": "네가 만일 네 입으로 주 예수님을 시인하고 하나님께서 그분을 죽은 자들로부터 살리신 것을 네 마음속으로 믿으면 구원을 받으리니 사람이 마음으로 믿어 의에 이르고 입으로 시인하여 구원에 이르느니라.", "web": "that if you will confess with your mouth that Jesus is Lord, and believe in your heart that God raised him from the dead, you will be saved. For with the heart, one believes unto righteousness; and with the mouth confession is made unto salvation."}}, {"id": 329, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "전도", "구원의 확신"], "book": "요한복음", "chap": 10, "verse": "28-29", "ref": "요한복음 10:28-29", "texts": {"krv": "내가 저희에게 영생을 주노니 영원히 멸망치 아니할 터이요 또 저희를 내 손에서 빼앗을 자가 없느니라 저희를 주신 내 아버지는 만유보다 크시매 아무도 아버지 손에서 빼앗을 수 없느니라", "kkjv": "내가 그들에게 영원한 생명을 주노니 그들이 결코 멸망하지 않을 것이요 또 아무도 내 손에서 그들을 빼앗지 못하리라. 그들을 내게 주신 내 아버지는 모든 것보다 크시매 아무도 내 아버지 손에서 능히 그들을 빼앗지 못하느니라.", "web": "I give eternal life to them. They will never perish, and no one will snatch them out of my hand. My Father, who has given them to me, is greater than all. No one is able to snatch them out of my Father’s hand."}}, {"id": 330, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "변명", "나는 그렇게 나쁜 사람이 아니다"], "book": "잠언", "chap": 21, "verse": "2", "ref": "잠언 21:2", "texts": {"krv": "사람의 행위가 자기 보기에는 모두 정직하여도 여호와는 심령을 감찰하시느니라", "kkjv": "사람의 모든 길이 그의 눈에는 옳게 보여도 주께서는 마음을 살피시느니라.", "web": "Every way of a man is right in his own eyes, but Yahweh weighs the hearts."}}, {"id": 331, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "변명", "포기할 게 너무 많다"], "book": "마가복음", "chap": 8, "verse": "36", "ref": "마가복음 8:36", "texts": {"krv": "사람이 만일 온 천하를 얻고도 제 목숨을 잃으면 무엇이 유익하리요", "kkjv": "사람이 만일 온 세상을 얻고도 자기 혼을 잃으면 그에게 무슨 유익이 있겠느냐?", "web": "For what does it profit a man, to gain the whole world, and forfeit his life?"}}, {"id": 332, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "변명", "이해할 수 없다"], "book": "요한복음", "chap": 7, "verse": "17", "ref": "요한복음 7:17", "texts": {"krv": "사람이 하나님의 뜻을 행하려 하면 이 교훈이 하나님께로서 왔는지 내가 스스로 말함인지 알리라", "kkjv": "어떤 사람이 그분의 뜻을 행하려 하면 그 교리가 하나님에게서 왔는지 혹은 내가 스스로 말하는지 알리라.", "web": "If anyone desires to do his will, he will know about the teaching, whether it is from God, or if I am speaking from myself."}}, {"id": 333, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "변명", "나는 아직 그렇게 선하지는 못하다"], "book": "누가복음", "chap": 5, "verse": "31-32", "ref": "누가복음 5:31-32", "texts": {"krv": "예수께서 대답하여 가라사대 건강한 자에게는 의원이 쓸데 없고 병든 자에게라야 쓸데 있나니 내가 의인을 부르러 온 것이 아니요 죄인을 불러 회개시키러 왔노라", "kkjv": "예수님께서 응답하여 그들에게 이르시되, 온전한 자들에게는 의사가 필요 없으나 병든 자들에게는 필요하니 나는 의로운 자들을 부르러 오지 아니하고 죄인들을 불러 회개하게 하려고 왔노라, 하시니라.", "web": "Jesus answered them, “Those who are healthy have no need for a physician, but those who are sick do. I have not come to call the righteous, but sinners to repentance.”"}}, {"id": 334, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "변명", "사람들이 어떻게 생각할까"], "book": "요한복음", "chap": 5, "verse": "44", "ref": "요한복음 5:44", "texts": {"krv": "너희가 서로 영광을 취하고 유일하신 하나님께로부터 오는 영광은 구하지 아니하니 어찌 나를 믿을 수 있느냐", "kkjv": "너희가 서로 존귀를 받고 오직 하나님으로부터만 나오는 존귀는 구하지 아니하니 어찌 믿을 수 있겠느냐?", "web": "How can you believe, who receive glory from one another, and you don’t seek the glory that comes from the only God?"}}, {"id": 335, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "변명", "나는 지속하지 못할 것이다"], "book": "히브리서", "chap": 7, "verse": "25", "ref": "히브리서 7:25", "texts": {"krv": "그러므로 자기를 힘입어 하나님께 나아가는 자들을 온전히 구원하실 수 있으니 이는 그가 항상 살아서 저희를 위하여 간구하심이니라", "kkjv": "그러므로 그분께서 항상 살아 계셔서 그들을 위해 중보하심을 보건대 그분은 또한 자기를 통하여 하나님께 나아오는 자들을 끝까지 구원하실 수 있느니라.", "web": "Therefore he is also able to save to the uttermost those who draw near to God through him, seeing that he lives forever to make intercession for them."}}, {"id": 336, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "변명", "좀더 기다려 보겠다"], "book": "잠언", "chap": 27, "verse": "1", "ref": "잠언 27:1", "texts": {"krv": "너는 내일 일을 자랑하지 말라 하루 동안에 무슨 일이 날는지 네가 알 수 없음이니라", "kkjv": "너는 내일을 자랑하지 말라. 하루 동안에 무슨 일이 일어날지 네가 알지 못하느니라.", "web": "Don’t boast about tomorrow; for you don’t know what a day may bring."}}, {"id": 337, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "변명", "위선자가 너무 많다"], "book": "로마서", "chap": 14, "verse": "12", "ref": "로마서 14:12", "texts": {"krv": "이러므로 우리 각인이 자기 일을 하나님께 직고하리라", "kkjv": "그러므로 이와 같이 우리 각 사람이 자신에 관하여 하나님께 회계 보고를 하리라.", "web": "So then each one of us will give account of himself to God."}}, {"id": 338, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "변명", "그리스도를 믿을 수 없다"], "book": "요한복음", "chap": 5, "verse": "39", "ref": "요한복음 5:39", "texts": {"krv": "너희가 성경에서 영생을 얻는 줄 생각하고 성경을 상고하거니와 이 성경이 곧 내게 대하여 증거하는 것이로다", "kkjv": "¶성경 기록들을 탐구하라. 너희가 그것들 안에서 영원한 생명을 얻는 줄로 생각하거니와 그것들은 곧 나에 대하여 증언하는 것들이니라.", "web": "“You search the Scriptures, because you think that in them you have eternal life; and these are they which testify about me."}}, {"id": 339, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "변명", "다른 종교는 어떠한가"], "book": "잠언", "chap": 14, "verse": "12", "ref": "잠언 14:12", "texts": {"krv": "어떤 길은 사람의 보기에 바르나 필경은 사망의 길이니라", "kkjv": "어떤 길은 사람이 보기에 옳으나 그것의 끝은 사망의 길들이니라.", "web": "There is a way which seems right to a man, but in the end it leads to death."}}, {"id": 340, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "변명", "하나님은 아무도 지옥에 보내시지 않을 것이다"], "book": "마태복음", "chap": 25, "verse": "41", "ref": "마태복음 25:41", "texts": {"krv": "또 왼편에 있는 자들에게 이르시되 저주를 받은 자들아 나를 떠나 마귀와 그 사자들을 위하여 예비된 영영한 불에 들어가라", "kkjv": "그때에 그가 왼편에 있는 자들에게도 이르되, 저주를 받은 자들아, 너희는 내게서 떠나 마귀와 그의 천사들을 위하여 예비된 영존하는 불에 들어가라.", "web": "Then he will say also to those on the left hand, ‘Depart from me, you cursed, into the eternal fire which is prepared for the devil and his angels;"}}, {"id": 341, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "변명", "이교도들은 어떻게 되나"], "book": "로마서", "chap": 1, "verse": "20", "ref": "로마서 1:20", "texts": {"krv": "창세로부터 그의 보이지 아니하는 것들 곧 그의 영원하신 능력과 신성이 그 만드신 만물에 분명히 보여 알게 되나니 그러므로 저희가 핑계치 못할지니라", "kkjv": "그분의 보이지 아니하는 것들 곧 그분의 영원하신 권능과 신격은 세상의 창조 이후로 분명히 보이며 만들어진 것들을 통해 깨달아 알 수 있나니 그러므로 그들이 변명할 수 없느니라.", "web": "For the invisible things of him since the creation of the world are clearly seen, being perceived through the things that are made, even his everlasting power and divinity; that they may be without excuse."}}, {"id": 342, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "그리스도 안에 있는 신자의 위치", "구속받음"], "book": "베드로전서", "chap": 1, "verse": "18-19", "ref": "베드로전서 1:18-19", "texts": {"krv": "너희가 알거니와 너희 조상의 유전한 망령된 행실에서 구속된 것은 은이나 금 같이 없어질 것으로 한 것이 아니요 오직 흠 없고 점 없는 어린 양 같은 그리스도의 보배로운 피로 한 것이니라", "kkjv": "너희가 알거니와 너희 조상들로부터 전통으로 물려받은 너희의 헛된 행실에서 너희가 구속받은 것은 은이나 금같이 썩을 것들로 된 것이 아니요, 오직 흠도 없고 점도 없는 어린양의 피 같은 그리스도의 보배로운 피로 된 것이니라.", "web": "knowing that you were redeemed, not with corruptible things, with silver or gold, from the useless way of life handed down from your fathers, but with precious blood, as of a faultless and pure lamb, the blood of Christ;"}}, {"id": 343, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "그리스도 안에 있는 신자의 위치", "화목하게 됨"], "book": "고린도후서", "chap": 5, "verse": "18", "ref": "고린도후서 5:18", "texts": {"krv": "모든 것이 하나님께로 났나니 저가 그리스도로 말미암아 우리를 자기와 화목하게 하시고 또 우리에게 화목하게 하는 직책을 주셨으니", "kkjv": "또 모든 것이 하나님에게서 났으며 그분께서 예수 그리스도를 통하여 우리를 자신과 화해하게 하시고 또 화해하게 하는 사역을 우리에게 주셨으니", "web": "But all things are of God, who reconciled us to himself through Jesus Christ, and gave to us the ministry of reconciliation;"}}, {"id": 344, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "그리스도 안에 있는 신자의 위치", "사함받음"], "book": "에베소서", "chap": 1, "verse": "7", "ref": "에베소서 1:7", "texts": {"krv": "우리가 그리스도 안에서 그의 은혜의 풍성함을 따라 그의 피로 말미암아 구속 곧 죄 사함을 받았으니", "kkjv": "그 사랑하시는 자 안에서 우리가 그분의 풍성한 은혜에 따라 그분의 피를 통해 구속 곧 죄들의 용서를 받았도다.", "web": "in whom we have our redemption through his blood, the forgiveness of our trespasses, according to the riches of his grace,"}}, {"id": 345, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "그리스도 안에 있는 신자의 위치", "율법에서 해방됨"], "book": "로마서", "chap": 6, "verse": "14-15", "ref": "로마서 6:14-15", "texts": {"krv": "죄가 너희를 주관치 못하리니 이는 너희가 법 아래 있지 아니하고 은혜 아래 있음이니라 그런즉 어찌하리요 우리가 법 아래 있지 아니하고 은혜 아래 있으니 죄를 지으리요 그럴 수 없느니라", "kkjv": "너희가 율법 아래 있지 아니하고 은혜 아래 있으므로 죄가 너희를 지배하지 못하리라. 그런즉 어찌하리요? 우리가 율법 아래 있지 아니하고 은혜 아래 있으므로 죄를 지으리요? 결코 그럴 수 없느니라.", "web": "For sin will not have dominion over you. For you are not under law, but under grace. What then? Shall we sin, because we are not under law, but under grace? May it never be!"}}, {"id": 346, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "그리스도 안에 있는 신자의 위치", "하나님께로 남"], "book": "갈라디아서", "chap": 3, "verse": "26", "ref": "갈라디아서 3:26", "texts": {"krv": "너희가 다 믿음으로 말미암아 그리스도 예수 안에서 하나님의 아들이 되었으니", "kkjv": "너희가 다 그리스도 예수님을 믿는 믿음으로 말미암아 하나님의 아이들이 되었나니", "web": "For you are all children of God, through faith in Christ Jesus."}}, {"id": 347, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "그리스도 안에 있는 신자의 위치", "제사장이 됨"], "book": "베드로전서", "chap": 2, "verse": "9", "ref": "베드로전서 2:9", "texts": {"krv": "오직 너희는 택하신 족속이요 왕 같은 제사장들이요 거룩한 나라요 그의 소유된 백성이니 이는 너희를 어두운 데서 불러내어 그의 기이한 빛에 들어가게 하신 자의 아름다운 덕을 선전하게 하려 하심이라", "kkjv": "그러나 너희는 선정된 세대요 왕가의 제사장이요 거룩한 민족이요 특별한 백성이니 이것은 너희를 어둠에서 불러내어 자신의 놀라운 빛으로 들어가게 하신 분께 대한 찬양을 너희가 전하게 하려 하심이라.", "web": "But you are a chosen race, a royal priesthood, a holy nation, a people for God’s own possession, that you may proclaim the excellence of him who called you out of darkness into his marvelous light:"}}, {"id": 348, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "그리스도 안에 있는 신자의 위치", "의롭게 됨"], "book": "고린도후서", "chap": 5, "verse": "21", "ref": "고린도후서 5:21", "texts": {"krv": "하나님이 죄를 알지도 못하신 자로 우리를 대신하여 죄를 삼으신 것은 우리로 하여금 저의 안에서 하나님의 의가 되게 하려 하심이니라", "kkjv": "하나님께서 죄를 알지 못한 그분을 우리를 위하여 죄가 되게 하신 것은 우리가 그분 안에서 하나님의 의가 되게 하려 하심이라.", "web": "For him who knew no sin he made to be sin on our behalf; so that in him we might become the righteousness of God."}}, {"id": 349, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "그리스도 안에 있는 신자의 위치", "거룩하게 됨"], "book": "고린도전서", "chap": 1, "verse": "30", "ref": "고린도전서 1:30", "texts": {"krv": "너희는 하나님께로부터 나서 그리스도 예수 안에 있고 예수는 하나님께로서 나와서 우리에게 지혜와 의로움과 거룩함과 구속함이 되셨으니", "kkjv": "그러나 너희는 하나님에게서 나서 그리스도 예수님 안에 있고 예수님은 하나님에게서 나사 우리에게 지혜와 의와 성별과 구속이 되셨으니", "web": "But of him, you are in Christ Jesus, who was made to us wisdom from God, and righteousness and sanctification, and redemption:"}}, {"id": 350, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "그리스도 안에 있는 신자의 위치", "완전하게 됨"], "book": "히브리서", "chap": 10, "verse": "14", "ref": "히브리서 10:14", "texts": {"krv": "저가 한 제물로 거룩하게 된 자들을 영원히 온전케 하셨느니라", "kkjv": "그분께서는 거룩히 구별된 자들을 단 한 번 헌물을 드림으로 영원토록 완전하게 하셨느니라.", "web": "For by one offering he has perfected forever those who are being sanctified."}}, {"id": 351, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "그리스도 안에 있는 신자의 위치", "의롭다 하심"], "book": "로마서", "chap": 3, "verse": "24", "ref": "로마서 3:24", "texts": {"krv": "그리스도 예수 안에 있는 구속으로 말미암아 하나님의 은혜로 값없이 의롭다 하심을 얻은 자 되었느니라", "kkjv": "그리스도 예수님 안에 있는 구속(救贖)을 통해 하나님의 은혜로 값없이 의롭게 되었느니라.", "web": "being justified freely by his grace through the redemption that is in Christ Jesus;"}}, {"id": 352, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "그리스도 안에 있는 신자의 위치", "천국 시민이 됨"], "book": "빌립보서", "chap": 3, "verse": "20", "ref": "빌립보서 3:20", "texts": {"krv": "오직 우리의 시민권은 하늘에 있는지라 거기로서 구원하는 자 곧 주 예수 그리스도를 기다리노니", "kkjv": "우리의 생활 방식은 하늘에 있으며 거기로부터 또한 우리가 구원자 주 예수 그리스도를 기다리노니", "web": "For our citizenship is in heaven, from where we also wait for a Savior, the Lord Jesus Christ;"}}, {"id": 353, "coll": "180구절 주제별 성경 암송", "sub": ["5. 그리스도를 증거함", "그리스도 안에 있는 신자의 위치", "온전하게 됨"], "book": "골로새서", "chap": 2, "verse": "9-10", "ref": "골로새서 2:9-10", "texts": {"krv": "그 안에는 신성의 모든 충만이 육체로 거하시고 너희도 그 안에서 충만하여졌으니 그는 모든 정사와 권세의 머리시라", "kkjv": "그분 안에는 하나님의 신격의 모든 충만이 몸으로 거하고 또 너희는 모든 정사와 권능의 머리이신 그분 안에서 완벽하며", "web": "For in him all the fullness of the Godhead dwells bodily, and in him you are made full, who is the head of all principality and power;"}}, {"id": 354, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "Vision"], "book": "창세기", "chap": 28, "verse": "14", "ref": "창세기 28:14", "texts": {"krv": "네 자손이 땅의 티끌 같이 되어서 동서남북에 편만할지며 땅의 모든 족속이 너와 네 자손을 인하여 복을 얻으리라", "kkjv": "네 씨가 땅의 티끌같이 되어 네가 서쪽과 동쪽과 북쪽과 남쪽으로 널리 퍼지며 너와 네 씨 안에서 땅의 모든 가족들이 복을 받으리라.", "web": "Your seed will be as the dust of the earth, and you will spread abroad to the west, and to the east, and to the north, and to the south. In you and in your seed will all the families of the earth be blessed."}}, {"id": 355, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "Vision"], "book": "창세기", "chap": 35, "verse": "11", "ref": "창세기 35:11", "texts": {"krv": "그에게 이르시되 나는 전능한 하나님이니라 생육하며 번성하라 국민과 많은 국민이 네게서 나고 왕들이 네 허리에서 나오리라", "kkjv": "하나님께서 그에게 이르시되, 나는 하나님 곧 전능자니라. 다산하고 번성하라. 민족과 민족들의 무리가 네게서 나고 왕들이 네 허리에서 나오리라.", "web": "God said to him, “I am God Almighty. Be fruitful and multiply. A nation and a company of nations will be from you, and kings will come out of your body."}}, {"id": 356, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "Vision"], "book": "이사야", "chap": 54, "verse": "2-3", "ref": "이사야 54:2-3", "texts": {"krv": "네 장막터를 넓히며 네 처소의 휘장을 아끼지 말고 널리 펴되 너의 줄을 길게 하며 너의 말뚝을 견고히 할지어다 이는 네가 좌우로 퍼지며 네 자손은 열방을 얻으며 황폐한 성읍들로 사람 살 곳이 되게 할 것임이니라", "kkjv": "네 장막 터를 넓히며 그들이 네 처소의 휘장들을 널리 펼치게 하라. 아끼지 말고 네 줄을 길게 하며 네 말뚝을 강하게 하라. 네가 오른쪽과 왼쪽으로 터져 나가고 네 씨가 이방인들을 상속하며 황폐한 도시들을 사람이 거주하는 곳이 되게 하리라.", "web": "“Enlarge the place of your tent, and let them stretch out the curtains of your habitations; don’t spare: lengthen your cords, and strengthen your stakes. For you shall spread out on the right hand and on the left; and your seed shall possess the nations, and make the desolate cities to be inhabited."}}, {"id": 357, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "Vision"], "book": "이사야", "chap": 58, "verse": "11-12", "ref": "이사야 58:11-12", "texts": {"krv": "나 여호와가 너를 항상 인도하여 마른 곳에서도 네 영혼을 만족케 하며 네 뼈를 견고케 하리니 너는 물댄 동산 같겠고 물이 끊어지지 아니하는 샘 같을 것이라 네게서 날 자들이 오래 황폐된 곳들을 다시 세울 것이며 너는 역대의 파괴된 기초를 쌓으리니 너를 일컬어 무너진 데를 수보하는 자라 할 것이며 길을 수축하여 거할 곳이 되게 하는 자라 하리라", "kkjv": "또 주가 너를 항상 인도하여 가뭄 속에서도 네 혼을 만족시키며 네 뼈를 기름지게 하리니 너는 물 댄 동산 같겠고 물이 끊어지지 아니하는 물 샘 같으리라. 또 네게서 나올 자들이 오래되고 폐허가 된 곳들을 건축하며 너는 많은 세대들의 기초들을 일으켜 세우리니 사람들이 너를 일컬어, 무너진 곳을 보수하는 자, 라 하며, 거할 수 있도록 행로들을 복구하는 자, 라 하리라.", "web": "and Yahweh will guide you continually, and satisfy your soul in dry places, and make strong your bones; and you shall be like a watered garden, and like a spring of water, whose waters don’t fail. Those who shall be of you shall build the old waste places; you shall raise up the foundations of many generations; and you shall be called The repairer of the breach, The restorer of paths to dwell in."}}, {"id": 358, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "Vision"], "book": "이사야", "chap": 60, "verse": "22", "ref": "이사야 60:22", "texts": {"krv": "그 작은 자가 천을 이루겠고 그 약한 자가 강국을 이룰 것이라 때가 되면 나 여호와가 속히 이루리라", "kkjv": "어린 자 하나가 천 명이 되고 작은 자가 강한 민족이 되리라. 나 주가 자신의 때에 그 일을 속히 이루리라.", "web": "The little one shall become a thousand, and the small one a strong nation; I, Yahweh, will hasten it in its time.”"}}, {"id": 359, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "Vision"], "book": "이사야", "chap": 66, "verse": "22", "ref": "이사야 66:22", "texts": {"krv": "나 여호와가 말하노라 나의 지을 새 하늘과 새 땅이 내 앞에 항상 있을것 같이 너희 자손과 너희 이름이 항상 있으리라", "kkjv": "내가 만들 새 하늘들과 새 땅이 내 앞에 남아 있을 것 같이 너희 씨와 너희 이름도 남아 있으리라. 주가 말하노라.", "web": "“For as the new heavens and the new earth, which I will make, shall remain before me,” says Yahweh, “so your seed and your name shall remain."}}, {"id": 360, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "헌신"], "book": "욥기", "chap": 22, "verse": "24-25", "ref": "욥기 22:24-25", "texts": {"krv": "네 보배를 진토에 버리고 오빌의 금을 강가의 돌에 버리라 그리하면 전능자가 네 보배가 되시며 네게 귀한 은이 되시리니", "kkjv": "그때에 네가 금을 흙처럼, 오빌의 금을 시내의 돌처럼 쌓으며 참으로 전능자께서 네 방벽이 되시고 네가 많은 은을 소유하리니", "web": "Lay your treasure in the dust, the gold of Ophir among the stones of the brooks. The Almighty will be your treasure, and precious silver to you."}}, {"id": 361, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "헌신"], "book": "시편", "chap": 110, "verse": "3", "ref": "시편 110:3", "texts": {"krv": "주의 권능의 날에 주의 백성이 거룩한 옷을 입고 즐거이 헌신하니 새벽 이슬 같은 주의 청년들이 주께 나오는도다", "kkjv": "주의 권능의 날에 주의 백성이 아침의 태에서 나와 거룩함의 아름다움들 속에서 자원하리니 주께는 주의 젊음의 이슬이 있나이다.", "web": "Your people offer themselves willingly in the day of your power, in holy array. Out of the womb of the morning, you have the dew of your youth."}}, {"id": 362, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "헌신"], "book": "마태복음", "chap": 13, "verse": "44", "ref": "마태복음 13:44", "texts": {"krv": "천국은 마치 밭에 감추인 보화와 같으니 사람이 이를 발견한 후 숨겨 두고 기뻐하여 돌아가서 자기의 소유를 다 팔아 그 밭을 샀느니라", "kkjv": "¶또 하늘의 왕국은 마치 밭에 숨겨진 보물과 같으니라. 사람이 그것을 발견하면 숨겨 두고 그것의 기쁨으로 인해 가서 자기의 모든 소유를 팔아 그 밭을 사느니라.", "web": "“Again, the Kingdom of Heaven is like a treasure hidden in the field, which a man found, and hid. In his joy, he goes and sells all that he has, and buys that field."}}, {"id": 363, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "헌신"], "book": "마태복음", "chap": 19, "verse": "27-28", "ref": "마태복음 19:27-28", "texts": {"krv": "이에 베드로가 대답하여 가로되 보소서 우리가 모든 것을 버리고 주를 좇았사오니 그런즉 우리가 무엇을 얻으리이까 예수께서 가라사대 내가 진실로 너희에게 이르노니 세상이 새롭게 되어 인자가 자기 영광의 보좌에 앉을 때에 나를 좇는 너희도 열 두 보좌에 앉아 이스라엘 열 두 지파를 심판하리라", "kkjv": "¶그때에 베드로가 그분께 응답하여 이르되, 보소서, 우리가 모든 것을 버리고 주를 따랐사오니 그런즉 우리가 무엇을 얻으리이까? 하매 예수님께서 그들에게 이르시되, 진실로 내가 너희에게 이르노니, 다시 나게 하는 때 곧 사람의 아들이 자기의 영광의 왕좌에 앉을 때에 나를 따른 너희도 열두 왕좌에 앉아 이스라엘의 열두 지파를 재판하리라.", "web": "Then Peter answered, “Behold, we have left everything, and followed you. What then will we have?” Jesus said to them, “Most certainly I tell you that you who have followed me, in the regeneration when the Son of Man will sit on the throne of his glory, you also will sit on twelve thrones, judging the twelve tribes of Israel."}}, {"id": 364, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "헌신"], "book": "요한복음", "chap": 12, "verse": "24", "ref": "요한복음 12:24", "texts": {"krv": "내가 진실로 진실로 너희에게 이르노니 한 알의 밀이 땅에 떨어져 죽지 아니하면 한 알 그대로 있고 죽으면 많은 열매를 맺느니라", "kkjv": "진실로 진실로 내가 너희에게 이르노니, 한 알의 밀이 땅에 떨어져 죽지 아니하면 홀로 남거니와 죽으면 많은 열매를 맺느니라.", "web": "Most certainly I tell you, unless a grain of wheat falls into the earth and dies, it remains by itself alone. But if it dies, it bears much fruit."}}, {"id": 365, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "헌신"], "book": "히브리서", "chap": 11, "verse": "24-26", "ref": "히브리서 11:24-26", "texts": {"krv": "믿음으로 모세는 장성하여 바로의 공주의 아들이라 칭함을 거절하고 도리어 하나님의 백성과 함께 고난받기를 잠시 죄악의 낙을 누리는 것보다 더 좋아하고 그리스도를 위하여 받는 능욕을 애굽의 모든 보화보다 더 큰 재물로 여겼으니 이는 상 주심을 바라봄이라", "kkjv": "믿음으로 모세는 나이가 들었을 때에 파라오의 딸의 아들이라 불리는 것을 거절하고 잠시 죄의 쾌락들을 즐기는 것보다 오히려 하나님의 백성과 함께 고난 받는 것을 택하였으며 또 그리스도의 치욕을 이집트의 보화보다 더 큰 재물로 여겼으니 이는 그가 주께서 보상으로 보답해 주시는 일에 관심을 두었기 때문이니라.", "web": "By faith, Moses, when he had grown up, refused to be called the son of Pharaoh’s daughter, choosing rather to share ill treatment with God’s people, than to enjoy the pleasures of sin for a time; accounting the reproach of Christ greater riches than the treasures of Egypt; for he looked to the reward."}}, {"id": 366, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "훈련"], "book": "전도서", "chap": 10, "verse": "10", "ref": "전도서 10:10", "texts": {"krv": "무딘 철 연장 날을 갈지 아니하면 힘이 더 드느니라 오직 지혜는 성공하기에 유익하니라", "kkjv": "쇠가 무디어졌는데도 사람이 날을 갈지 아니하면 그가 반드시 더 많은 힘을 들여야 하거니와 지혜는 지도하는 일에 유익하니라.", "web": "If the ax is blunt, and one doesn’t sharpen the edge, then he must use more strength; but skill brings success."}}, {"id": 367, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "훈련"], "book": "예레미야", "chap": 12, "verse": "5", "ref": "예레미야 12:5", "texts": {"krv": "네가 보행자와 함께 달려도 피곤하면 어찌 능히 말과 경주하겠느냐 네가 평안한 땅에서는 무사하려니와 요단의 창일한 중에서는 어찌하겠느냐", "kkjv": "¶네가 보병들과 달릴 때에 그들이 너를 지치게 하였거늘 어찌 네가 능히 말들과 겨루겠느냐? 또 네가 신뢰하던 화평의 땅에서도 그들이 너를 지치게 하였거늘 요르단이 넘치는 속에서 네가 어찌하겠느냐?", "web": "If you have run with the footmen, and they have wearied you, then how can you contend with horses? and though in a land of peace you are secure, yet how will you do in the pride of the Jordan?"}}, {"id": 368, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "훈련"], "book": "예레미야애가", "chap": 3, "verse": "27-28", "ref": "예레미야애가 3:27-28", "texts": {"krv": "사람이 젊었을 때에 멍에를 메는 것이 좋으니 혼자 앉아서 잠잠할 것은 주께서 그것을 메우셨음이라", "kkjv": "사람이 젊었을 때에 멍에를 메는 것이 그에게 좋으니 그가 홀로 앉아서 잠잠함은 그분께서 그것을 그에게 지게 하셨기 때문이라.", "web": "It is good for a man that he bear the yoke in his youth. Let him sit alone and keep silence, because he has laid it on him."}}, {"id": 369, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "훈련"], "book": "고린도전서", "chap": 9, "verse": "27", "ref": "고린도전서 9:27", "texts": {"krv": "내가 내 몸을 쳐 복종하게 함은 내가 남에게 전파한 후에 자기가 도리어 버림이 될까 두려워 함이로라", "kkjv": "오직 내가 내 몸을 억제하여 복종시킴은 내가 다른 사람들에게 복음을 선포한 뒤에 어떤 방법으로든 내 자신이 버림받은 자가 되지 않게 하려 함이라.", "web": "but I beat my body and bring it into submission, lest by any means, after I have preached to others, I myself should be rejected."}}, {"id": 370, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "훈련"], "book": "디모데전서", "chap": 4, "verse": "7-8", "ref": "디모데전서 4:7-8", "texts": {"krv": "망령되고 허탄한 신화를 버리고 오직 경건에 이르기를 연습하라 육체의 연습은 약간의 유익이 있으나 경건은 범사에 유익하니 금생과 내생에 약속이 있느니라", "kkjv": "그러나 속되고 늙은 부녀들의 꾸며 낸 이야기들을 거부하고 도리어 하나님의 성품에 이르도록 스스로 훈련하라. 육체의 훈련은 유익이 적으나 하나님의 성품은 모든 일에 유익하며 현재의 생명과 다가올 생명의 약속을 지니고 있느니라.", "web": "But refuse profane and old wives’ fables. Exercise yourself toward godliness. For bodily exercise has some value, but godliness has value in all things, having the promise of the life which is now, and of that which is to come."}}, {"id": 371, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "훈련"], "book": "히브리서", "chap": 12, "verse": "11", "ref": "히브리서 12:11", "texts": {"krv": "무릇 징계가 당시에는 즐거워 보이지 않고 슬퍼 보이나 후에 그로 말미암아 연달한 자에게는 의의 평강한 열매를 맺나니", "kkjv": "이제 어떤 징계도 그 당시에는 기쁘게 보이지 아니하고 슬프게 보이나 그럼에도 불구하고 나중에는 그것으로 말미암아 단련된 자들에게 그것이 의의 화평의 열매를 맺느니라.", "web": "All chastening seems for the present to be not joyous but grievous; yet afterward it yields the peaceful fruit of righteousness to those who have been exercised thereby."}}, {"id": 372, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "단순성"], "book": "마태복음", "chap": 4, "verse": "20", "ref": "마태복음 4:20", "texts": {"krv": "저희가 곧 그물을 버려두고 예수를 좇으니라", "kkjv": "그들이 즉시 자기들의 그물들을 버려두고 그분을 따르니라.", "web": "They immediately left their nets and followed him."}}, {"id": 373, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "단순성"], "book": "누가복음", "chap": 9, "verse": "62", "ref": "누가복음 9:62", "texts": {"krv": "예수께서 이르시되 손에 쟁기를 잡고 뒤를 돌아보는 자는 하나님의 나라에 합당치 아니하니라 하시니라", "kkjv": "예수님께서 그에게 이르시되, 손에 쟁기를 잡고 뒤를 돌아보는 자는 하나님의 왕국에 합당하지 아니하니라, 하시니라.", "web": "But Jesus said to him, “No one, having put his hand to the plow, and looking back, is fit for the Kingdom of God.”"}}, {"id": 374, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "단순성"], "book": "요한복음", "chap": 21, "verse": "22", "ref": "요한복음 21:22", "texts": {"krv": "예수께서 가라사대 내가 올 때까지 그를 머물게 하고자 할지라도 네게 무슨 상관이냐 너는 나를 따르라 하시더라", "kkjv": "예수님께서 그에게 이르시되, 내가 올 때까지 그가 머물 것을 내가 원할지라도 그것이 너와 무슨 상관이 있느냐? 너는 나를 따르라, 하시더라.", "web": "Jesus said to him, “If I desire that he stay until I come, what is that to you? You follow me.”"}}, {"id": 375, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "단순성"], "book": "사도행전", "chap": 6, "verse": "4", "ref": "사도행전 6:4", "texts": {"krv": "우리는 기도하는 것과 말씀 전하는 것을 전무하리라 하니", "kkjv": "오직 우리는 계속해서 기도와 말씀 사역에 전념하리라, 하니라.", "web": "But we will continue steadfastly in prayer and in the ministry of the word.”"}}, {"id": 376, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "단순성"], "book": "빌립보서", "chap": 3, "verse": "8", "ref": "빌립보서 3:8", "texts": {"krv": "또한 모든 것을 해로 여김은 내 주 그리스도 예수를 아는 지식이 가장 고상함을 인함이라 내가 그를 위하여 모든 것을 잃어버리고 배설물로 여김은 그리스도를 얻고", "kkjv": "참으로 확실히 모든 것을 손실로 여김은 그리스도 예수 내 주를 아는 지식이 뛰어나기 때문이라. 내가 그분을 위하여 모든 것의 손실을 입고 그것들을 단지 배설물로 여김은 내가 그리스도를 얻고", "web": "Yes most certainly, and I count all things to be loss for the excellency of the knowledge of Christ Jesus, my Lord, for whom I suffered the loss of all things, and count them nothing but refuse, that I may gain Christ"}}, {"id": 377, "coll": "무장 900구절", "sub": ["Navigator 4대 강조사항", "단순성"], "book": "히브리서", "chap": 12, "verse": "1", "ref": "히브리서 12:1", "texts": {"krv": "이러므로 우리에게 구름 같이 둘러싼 허다한 증인들이 있으니 모든 무거운 것과 얽매이기 쉬운 죄를 벗어 버리고 인내로써 우리 앞에 당한 경주를 경주하며", "kkjv": "그러므로 증인들이 이렇게 큰 구름을 이루며 또한 우리를 둘러싸고 있으니 모든 무거운 것과 너무 쉽게 우리를 얽어매는 죄를 우리가 떨쳐 버리고 인내로 우리 앞에 놓인 경주를 달리며", "web": "Therefore let us also, seeing we are surrounded by so great a cloud of witnesses, lay aside every weight and the sin which so easily entangles us, and let us run with patience the race that is set before us,"}}, {"id": 378, "coll": "무장 900구절", "sub": ["제자의 조건", "Faithful"], "book": "민수기", "chap": 12, "verse": "7", "ref": "민수기 12:7", "texts": {"krv": "내 종 모세와는 그렇지 아니하니 그는 나의 온 집에 충성됨이라", "kkjv": "내 종 모세와는 그리하지 아니하나니 그는 나의 온 집에서 신실한 자니라.", "web": "My servant Moses is not so. He is faithful in all my house."}}, {"id": 379, "coll": "무장 900구절", "sub": ["제자의 조건", "Faithful"], "book": "시편", "chap": 101, "verse": "6", "ref": "시편 101:6", "texts": {"krv": "내 눈이 이 땅의 충성된 자를 살펴 나와 함께 거하게 하리니 완전한 길에 행하는 자가 나를 수종하리로다", "kkjv": "내 눈이 땅의 신실한 자들 위에 있어 그들이 나와 함께 거하게 하리니 완전한 길 안에서 걷는 자 곧 그가 나를 섬기리이다.", "web": "My eyes will be on the faithful of the land, that they may dwell with me. He who walks in a perfect way, he will serve me."}}, {"id": 380, "coll": "무장 900구절", "sub": ["제자의 조건", "Faithful"], "book": "잠언", "chap": 20, "verse": "6", "ref": "잠언 20:6", "texts": {"krv": "많은 사람은 각기 자기의 인자함을 자랑하나니 충성된 자를 누가 만날 수 있으랴", "kkjv": "대부분의 사람들이 저마다 자기의 선함을 외치려니와 누가 신실한 사람을 찾을 수 있으리요?", "web": "Many men claim to be men of unfailing love, but who can find a faithful man?"}}, {"id": 381, "coll": "무장 900구절", "sub": ["제자의 조건", "Faithful"], "book": "마태복음", "chap": 25, "verse": "21", "ref": "마태복음 25:21", "texts": {"krv": "그 주인이 이르되 잘 하였도다 착하고 충성된 종아 네가 작은 일에 충성하였으매 내가 많은 것으로 네게 맡기리니 네 주인의 즐거움에 참예할지어다 하고", "kkjv": "그의 주인이 그에게 이르되, 잘하였도다. 선하고 신실한 종아, 네가 적은 것에 신실하였은즉 내가 너를 많은 것을 다스릴 치리자로 삼으리니 너는 네 주인의 기쁨에 참여하라, 하니라.", "web": "“His lord said to him, ‘Well done, good and faithful servant. You have been faithful over a few things, I will set you over many things. Enter into the joy of your lord.’"}}, {"id": 382, "coll": "무장 900구절", "sub": ["제자의 조건", "Faithful"], "book": "디모데전서", "chap": 1, "verse": "12", "ref": "디모데전서 1:12", "texts": {"krv": "나를 능하게 하신 그리스도 예수 우리 주께 내가 감사함은 나를 충성되이 여겨 내게 직분을 맡기심이니", "kkjv": "나를 능하게 하신 그리스도 예수 우리 주께 내가 감사를 드림은 그분께서 나를 신실한 자로 여기사 내게 사역을 맡기셨기 때문이라.", "web": "And I thank him who enabled me, Christ Jesus our Lord, because he counted me faithful, appointing me to service;"}}, {"id": 383, "coll": "무장 900구절", "sub": ["제자의 조건", "Faithful"], "book": "히브리서", "chap": 3, "verse": "2", "ref": "히브리서 3:2", "texts": {"krv": "저가 자기를 세우신 이에게 충성하시기를 모세가 하나님의 온 집에서 한 것과 같으니", "kkjv": "그분께서는 모세가 하나님의 온 집에서 신실했던 것 같이 자기를 세우신 분에게 신실하셨느니라.", "web": "who was faithful to him who appointed him, as also was Moses in all his house."}}, {"id": 384, "coll": "무장 900구절", "sub": ["제자의 조건", "Available"], "book": "마태복음", "chap": 10, "verse": "37-38", "ref": "마태복음 10:37-38", "texts": {"krv": "아비나 어미를 나보다 더 사랑하는 자는 내게 합당치 아니하고 아들이나 딸을 나보다 더 사랑하는 자도 내게 합당치 아니하고 또 자기 십자가를 지고 나를 좇지 않는 자도 내게 합당치 아니하니라", "kkjv": "아버지나 어머니를 나보다 더 사랑하는 자는 내게 합당하지 아니하고 아들이나 딸을 나보다 더 사랑하는 자도 내게 합당하지 아니하며 또 자기 십자가를 지고 내 뒤를 따르지 아니하는 자도 내게 합당하지 아니하니라.", "web": "He who loves father or mother more than me is not worthy of me; and he who loves son or daughter more than me isn’t worthy of me. He who doesn’t take his cross and follow after me, isn’t worthy of me."}}, {"id": 385, "coll": "무장 900구절", "sub": ["제자의 조건", "Available"], "book": "갈라디아서", "chap": 5, "verse": "1", "ref": "갈라디아서 5:1", "texts": {"krv": "그리스도께서 우리로 자유케 하려고 자유를 주셨으니 그러므로 굳세게 서서 다시는 종의 멍에를 메지 말라", "kkjv": "그리스도께서 자유로 우리를 자유롭게 하셨으니 그러므로 그 자유 안에 굳게 서고 다시 속박의 멍에를 메지 말라.", "web": "Stand firm therefore in the liberty by which Christ has made us free, and don’t be entangled again with a yoke of bondage."}}, {"id": 386, "coll": "무장 900구절", "sub": ["제자의 조건", "Available"], "book": "갈라디아서", "chap": 5, "verse": "24", "ref": "갈라디아서 5:24", "texts": {"krv": "그리스도 예수의 사람들은 육체와 함께 그 정과 욕심을 십자가에 못 박았느니라", "kkjv": "그리스도께 속한 사람들은 애착들과 정욕들과 함께 육신을 십자가에 못 박았느니라.", "web": "Those who belong to Christ have crucified the flesh with its passions and lusts."}}, {"id": 387, "coll": "무장 900구절", "sub": ["제자의 조건", "Available"], "book": "디모데후서", "chap": 2, "verse": "3-4", "ref": "디모데후서 2:3-4", "texts": {"krv": "네가 그리스도 예수의 좋은 군사로 나와 함께 고난을 받을지니 군사로 다니는 자는 자기 생활에 얽매이는 자가 하나도 없나니 이는 군사로 모집한 자를 기쁘게 하려 함이라", "kkjv": "그러므로 너는 예수 그리스도의 좋은 군사로서 고난을 견디어 내라. 전쟁을 하는 어떤 사람도 이 세상 삶의 일에 얽매이지 아니하나니 이것은 그가 자기를 군사로 택한 자를 기쁘게 하려 함이라.", "web": "You therefore must endure hardship, as a good soldier of Christ Jesus. No soldier on duty entangles himself in the affairs of life, that he may please him who enrolled him as a soldier."}}, {"id": 388, "coll": "무장 900구절", "sub": ["제자의 조건", "Available"], "book": "히브리서", "chap": 11, "verse": "9", "ref": "히브리서 11:9", "texts": {"krv": "믿음으로 저가 외방에 있는것 같이 약속하신 땅에 우거하여 동일한 약속을 유업으로 함께 받은 이삭과 야곱으로 더불어 장막에 거하였으니", "kkjv": "믿음으로 그는 낯선 나라에 머무는 것 같이 약속의 땅에 머물렀고 자기와 함께 동일한 약속의 상속자가 된 이삭과 야곱과 함께 장막들에 거하였으니", "web": "By faith, he lived as an alien in the land of promise, as in a land not his own, dwelling in tents, with Isaac and Jacob, the heirs with him of the same promise."}}, {"id": 389, "coll": "무장 900구절", "sub": ["제자의 조건", "Available"], "book": "야고보서", "chap": 4, "verse": "15", "ref": "야고보서 4:15", "texts": {"krv": "너희가 도리어 말하기를 주의 뜻이면 우리가 살기도 하고 이것 저것을 하리라 할 것이거늘", "kkjv": "그런 까닭에 너희가 마땅히 말하기를, 주께서 원하시면 우리가 살며 이것이나 저것을 하리라, 하여야 하나", "web": "For you ought to say, “If the Lord wills, we will both live, and do this or that.”"}}, {"id": 390, "coll": "무장 900구절", "sub": ["제자의 조건", "Teachable"], "book": "시편", "chap": 86, "verse": "11", "ref": "시편 86:11", "texts": {"krv": "여호와여 주의 도로 내게 가르치소서 내가 주의 진리에 행하오리니 일심으로 주의 이름을 경외하게 하소서", "kkjv": "오 주여, 내게 주의 길을 가르치소서. 내가 주의 진리 안에서 걸으리니 내 마음이 하나가 되게 하사 주의 이름을 두려워하게 하소서.", "web": "Teach me your way, Yahweh. I will walk in your truth. Make my heart undivided to fear your name."}}, {"id": 391, "coll": "무장 900구절", "sub": ["제자의 조건", "Teachable"], "book": "시편", "chap": 141, "verse": "5", "ref": "시편 141:5", "texts": {"krv": "의인이 나를 칠지라도 은혜로 여기며 책망할지라도 머리의 기름 같이 여겨서 내 머리가 이를 거절치 아니할지라 저희의 재난 중에라도 내가 항상 기도하리로다", "kkjv": "의로운 자가 나를 치게 하소서. 그것이 친절이 되리이다. 그가 나를 책망하게 하소서. 그것이 심히 좋은 기름이 되며 내 머리를 부수지 아니하리니 그들이 재난을 당할 때에도 내가 여전히 기도하리이다.", "web": "Let the righteous strike me, it is kindness; let him reprove me, it is like oil on the head; don’t let my head refuse it; Yet my prayer is always against evil deeds."}}, {"id": 392, "coll": "무장 900구절", "sub": ["제자의 조건", "Teachable"], "book": "잠언", "chap": 3, "verse": "11-12", "ref": "잠언 3:11-12", "texts": {"krv": "내 아들아 여호와의 징계를 경히 여기지 말라 그 꾸지람을 싫어하지 말라 대저 여호와께서 그 사랑하시는 자를 징계하시기를 마치 아비가 그 기뻐하는 아들을 징계함 같이 하시느니라", "kkjv": "¶내 아들아, 주의 징계를 멸시하지 말며 그분께서 바로잡아 주시는 것에 싫증을 내지 말라. 아버지가 자기가 기뻐하는 아들을 바로잡아 주는 것 같이 주께서 자신이 사랑하는 자를 바로잡아 주시느니라.", "web": "My son, don’t despise Yahweh’s discipline, neither be weary of his reproof: for whom Yahweh loves, he reproves; even as a father reproves the son in whom he delights."}}, {"id": 393, "coll": "무장 900구절", "sub": ["제자의 조건", "Teachable"], "book": "잠언", "chap": 12, "verse": "1", "ref": "잠언 12:1", "texts": {"krv": "훈계를 좋아하는 자는 지식을 좋아하나니 징계를 싫어하는 자는 짐승과 같으니라", "kkjv": "누구든지 훈계를 사랑하는 자는 지식을 사랑하거니와 책망을 싫어하는 자는 짐승과 같으니라.", "web": "Whoever loves correction loves knowledge, but he who hates reproof is stupid."}}, {"id": 394, "coll": "무장 900구절", "sub": ["제자의 조건", "Teachable"], "book": "잠언", "chap": 12, "verse": "15", "ref": "잠언 12:15", "texts": {"krv": "미련한 자는 자기 행위를 바른 줄로 여기나 지혜로운 자는 권고를 듣느니라", "kkjv": "어리석은 자의 길은 그의 눈에 옳으나 권고에 귀를 기울이는 자는 지혜로우니라.", "web": "The way of a fool is right in his own eyes, but he who is wise listens to counsel."}}, {"id": 395, "coll": "무장 900구절", "sub": ["제자의 조건", "Teachable"], "book": "잠언", "chap": 13, "verse": "1", "ref": "잠언 13:1", "texts": {"krv": "지혜로운 아들은 아비의 훈계를 들으나 거만한 자는 꾸지람을 즐겨 듣지 아니하느니라", "kkjv": "지혜로운 아들은 자기 아버지의 훈계를 들으나 비웃는 자는 책망을 귀담아 듣지 아니하느니라.", "web": "A wise son listens to his father’s instruction, but a scoffer doesn’t listen to rebuke."}}, {"id": 396, "coll": "무장 900구절", "sub": ["제자의 조건", "Teachable"], "book": "잠언", "chap": 15, "verse": "32", "ref": "잠언 15:32", "texts": {"krv": "훈계 받기를 싫어하는 자는 자기의 영혼을 경히 여김이라 견책을 달게 받는 자는 지식을 얻느니라", "kkjv": "훈계를 거절하는 자는 자기 혼을 멸시하나 책망을 귀담아 듣는 자는 명철을 얻느니라.", "web": "He who refuses correction despises his own soul, but he who listens to reproof gets understanding."}}, {"id": 397, "coll": "무장 900구절", "sub": ["제자의 조건", "Teachable"], "book": "잠언", "chap": 24, "verse": "32", "ref": "잠언 24:32", "texts": {"krv": "내가 보고 생각이 깊었고 내가 보고 훈계를 받았었노라", "kkjv": "그때에 내가 보고 그것을 매우 깊이 생각해 보았으며 그것을 바라보고 훈계를 받았느니라.", "web": "Then I saw, and considered well. I saw, and received instruction:"}}, {"id": 398, "coll": "무장 900구절", "sub": ["제자의 조건", "Teachable"], "book": "마태복음", "chap": 11, "verse": "29-30", "ref": "마태복음 11:29-30", "texts": {"krv": "나는 마음이 온유하고 겸손하니 나의 멍에를 메고 내게 배우라 그러면 너희 마음이 쉼을 얻으리니 이는 내 멍에는 쉽고 내 짐은 가벼움이라 하시니라", "kkjv": "나는 마음이 온유하고 겸손하니 너희 위에 내 멍에를 메고 내게 배우라. 그리하면 너희가 너희 혼을 위한 안식을 찾으리니 내 멍에는 쉽고 내 짐은 가벼우니라, 하시니라.", "web": "Take my yoke upon you, and learn from me, for I am gentle and lowly in heart; and you will find rest for your souls. For my yoke is easy, and my burden is light.”"}}, {"id": 399, "coll": "무장 900구절", "sub": ["제자의 조건", "Teachable"], "book": "디모데후서", "chap": 2, "verse": "7", "ref": "디모데후서 2:7", "texts": {"krv": "내 말하는 것을 생각하라 주께서 범사에 네게 총명을 주시리라", "kkjv": "내가 말하는 것을 깊이 생각하라. 주께서 모든 일에서 네게 깨달음을 주시기 원하노라.", "web": "Consider what I say, and may the Lord give you understanding in all things."}}, {"id": 400, "coll": "무장 900구절", "sub": ["제자의 조건", "Teachable"], "book": "히브리서", "chap": 13, "verse": "7", "ref": "히브리서 13:7", "texts": {"krv": "하나님의 말씀을 너희에게 이르고 너희를 인도하던 자들을 생각하며 저희 행실의 종말을 주의하여 보고 저희 믿음을 본받으라", "kkjv": "하나님의 말씀을 너희에게 일러 주고 너희를 다스리는 자들을 기억하며 그들의 행실의 결말을 깊이 살펴보고 그들의 믿음을 따르라.", "web": "Remember your leaders, men who spoke to you the word of God, and considering the results of their conduct, imitate their faith."}}, {"id": 401, "coll": "무장 900구절", "sub": ["제자의 조건", "Teachable"], "book": "히브리서", "chap": 13, "verse": "17", "ref": "히브리서 13:17", "texts": {"krv": "너희를 인도하는 자들에게 순종하고 복종하라 저희는 너희 영혼을 위하여 경성하기를 자기가 회계할 자인것 같이 하느니라 저희로 하여금 즐거움으로 이것을 하게 하고 근심으로 하게 말라 그렇지 않으면 너희에게 유익이 없느니라", "kkjv": "너희를 다스리는 자들에게 순종하고 복종하라. 그들은 마치 자기가 회계 보고할 자인 것 같이 너희 혼을 위해 깨어 있나니 그들이 기쁨으로 그것을 하게 하고 근심으로 하게 하지 말라. 그것은 너희에게 유익을 주지 못하느니라.", "web": "Obey your leaders and submit to them, for they watch on behalf of your souls, as those who will give account, that they may do this with joy, and not with groaning, for that would be unprofitable for you."}}, {"id": 402, "coll": "무장 900구절", "sub": ["제자도", "예수님의 본"], "book": "마가복음", "chap": 1, "verse": "38", "ref": "마가복음 1:38", "texts": {"krv": "이르시되 우리가 다른 가까운 마을들로 가자 거기서도 전도하리니 내가 이를 위하여 왔노라 하시고", "kkjv": "그분께서 그들에게 이르시되, 우리가 다음 고을들로 들어가자. 내가 거기서도 선포하리니 이런 까닭으로 내가 왔노라, 하시고", "web": "He said to them, “Let’s go elsewhere into the next towns, that I may preach there also, because I came out for this reason.”"}}, {"id": 403, "coll": "무장 900구절", "sub": ["제자도", "예수님의 본"], "book": "누가복음", "chap": 22, "verse": "44", "ref": "누가복음 22:44", "texts": {"krv": "예수께서 힘쓰고 애써 더욱 간절히 기도하시니 땀이 땅에 떨어지는 핏방울 같이 되더라", "kkjv": "그분께서 고뇌에 차서 더욱 간절히 기도하시니 그분의 땀이 큰 핏방울같이 되어 땅에 떨어지더라.", "web": "Being in agony he prayed more earnestly. His sweat became like great drops of blood falling down on the ground."}}, {"id": 404, "coll": "무장 900구절", "sub": ["제자도", "예수님의 본"], "book": "요한복음", "chap": 4, "verse": "34", "ref": "요한복음 4:34", "texts": {"krv": "예수께서 이르시되 나의 양식은 나를 보내신 이의 뜻을 행하며 그의 일을 온전히 이루는 이것이니라", "kkjv": "예수님께서 그들에게 이르시되, 내 양식은 나를 보내신 분의 뜻을 행하고 그분의 일을 끝마치는 것이니라.", "web": "Jesus said to them, “My food is to do the will of him who sent me, and to accomplish his work."}}, {"id": 405, "coll": "무장 900구절", "sub": ["제자도", "예수님의 본"], "book": "요한복음", "chap": 6, "verse": "38-39", "ref": "요한복음 6:38-39", "texts": {"krv": "내가 하늘로서 내려온 것은 내 뜻을 행하려 함이 아니요 나를 보내신 이의 뜻을 행하려 함이니라 나를 보내신 이의 뜻은 내게 주신자 중에 내가 하나도 잃어버리지 아니하고 마지막 날에 다시 살리는 이것이니라", "kkjv": "나는 내 뜻을 행하려고 하늘로부터 내려오지 아니하고 나를 보내신 분의 뜻을 행하려고 내려왔느니라. 나를 보내신 아버지의 뜻은 이것이니 곧 그분께서 내게 주신 모든 것 중에서 내가 하나도 잃지 아니하고 마지막 날에 그것을 다시 일으키는 것이니라.", "web": "For I have come down from heaven, not to do my own will, but the will of him who sent me. This is the will of my Father who sent me, that of all he has given to me I should lose nothing, but should raise him up at the last day."}}, {"id": 406, "coll": "무장 900구절", "sub": ["제자도", "예수님의 본"], "book": "요한복음", "chap": 8, "verse": "29", "ref": "요한복음 8:29", "texts": {"krv": "나를 보내신 이가 나와 함께 하시도다 내가 항상 그의 기뻐하시는 일을 행하므로 나를 혼자 두지 아니하셨느니라", "kkjv": "나를 보내신 분께서 나와 함께 계시는도다. 내가 항상 아버지를 기쁘게 하는 그것들을 행하므로 그분께서 나를 혼자 버려두지 아니하셨느니라, 하시니라.", "web": "He who sent me is with me. The Father hasn’t left me alone, for I always do the things that are pleasing to him.”"}}, {"id": 407, "coll": "무장 900구절", "sub": ["제자도", "예수님의 본"], "book": "요한복음", "chap": 10, "verse": "14-15", "ref": "요한복음 10:14-15", "texts": {"krv": "나는 선한 목자라 내가 내 양을 알고 양도 나를 아는 것이 아버지께서 나를 아시고 내가 아버지를 아는 것 같으니 나는 양을 위하여 목숨을 버리노라", "kkjv": "나는 선한 목자라 내 양들을 알고 내 양들도 나를 아노라. 아버지께서 나를 알 듯이 나도 아버지를 아노니 나는 양들을 위해 내 생명을 내놓느니라.", "web": "I am the good shepherd. I know my own, and I’m known by my own; even as the Father knows me, and I know the Father. I lay down my life for the sheep."}}, {"id": 408, "coll": "무장 900구절", "sub": ["제자도", "예수님의 본"], "book": "요한복음", "chap": 13, "verse": "1", "ref": "요한복음 13:1", "texts": {"krv": "유월절 전에 예수께서 자기가 세상을 떠나 아버지께로 돌아가실 때가 이른 줄 아시고 세상에 있는 자기 사람들을 사랑하시되 끝까지 사랑하시니라", "kkjv": "이제 유월절 전에 예수님께서 자기 때가 이르러 자기가 이 세상을 떠나 아버지께로 가야 할 줄 아시고 세상에 있던 자기 사람들을 사랑하시되 끝까지 사랑하시니라.", "web": "Now before the feast of the Passover, Jesus, knowing that his time had come that he would depart from this world to the Father, having loved his own who were in the world, he loved them to the end."}}, {"id": 409, "coll": "무장 900구절", "sub": ["제자도", "예수님의 본"], "book": "요한복음", "chap": 17, "verse": "4", "ref": "요한복음 17:4", "texts": {"krv": "아버지께서 내게 하라고 주신 일을 내가 이루어 아버지를 이 세상에서 영화롭게 하였사오니", "kkjv": "내가 아버지를 땅에서 영화롭게 하였사오니 곧 내가 아버지께서 내게 하라고 주신 일을 끝마쳤나이다.", "web": "I glorified you on the earth. I have accomplished the work which you have given me to do."}}, {"id": 410, "coll": "무장 900구절", "sub": ["제자도", "예수님의 본"], "book": "요한복음", "chap": 19, "verse": "30", "ref": "요한복음 19:30", "texts": {"krv": "예수께서 신 포도주를 받으신 후 가라사대 다 이루었다 하시고 머리를 숙이시고 영혼이 돌아가시니라", "kkjv": "그러므로 예수님께서 식초를 받으신 뒤에 이르시되, 다 이루었다, 하시고 머리를 숙이신 뒤 숨을 거두시니라.", "web": "When Jesus therefore had received the vinegar, he said, “It is finished.” He bowed his head, and gave up his spirit."}}, {"id": 411, "coll": "무장 900구절", "sub": ["제자도", "예수님의 본"], "book": "고린도후서", "chap": 8, "verse": "9", "ref": "고린도후서 8:9", "texts": {"krv": "우리 주 예수 그리스도의 은혜를 너희가 알거니와 부요하신 자로서 너희를 위하여 가난하게 되심은 그의 가난함을 인하여 너희로 부요케 하려 하심이니라", "kkjv": "우리 주 예수 그리스도의 은혜를 너희가 알거니와 그분께서 부요하셨으나 너희를 위하여 가난하게 되심은 자신의 가난으로 말미암아 너희를 부요하게 하려 하심이라.", "web": "For you know the grace of our Lord Jesus Christ, that, though he was rich, yet for your sakes he became poor, that you through his poverty might become rich."}}, {"id": 412, "coll": "무장 900구절", "sub": ["제자도", "예수님의 본"], "book": "히브리서", "chap": 3, "verse": "1", "ref": "히브리서 3:1", "texts": {"krv": "그러므로 함께 하늘의 부르심을 입은 거룩한 형제들아 우리의 믿는 도리의 사도시며 대제사장이신 예수를 깊이 생각하라", "kkjv": "그러므로 거룩한 형제들 곧 하늘의 부르심에 참여한 자들아, 우리의 신앙 고백의 사도시며 대제사장이신 그리스도 예수님을 깊이 생각하라.", "web": "Therefore, holy brothers, partakers of a heavenly calling, consider the Apostle and High Priest of our confession, Jesus;"}}, {"id": 413, "coll": "무장 900구절", "sub": ["제자도", "예수님의 본"], "book": "히브리서", "chap": 12, "verse": "2", "ref": "히브리서 12:2", "texts": {"krv": "믿음의 주요 또 온전케 하시는 이인 예수를 바라보자 저는 그 앞에 있는 즐거움을 위하여 십자가를 참으사 부끄러움을 개의치 아니하시더니 하나님 보좌 우편에 앉으셨느니라", "kkjv": "우리의 믿음의 창시자요 또 완성자이신 예수님을 바라보자. 그분께서는 자기 앞에 놓인 기쁨으로 인해 십자가를 견디사 그 수치를 멸시하시더니 이제 하나님의 왕좌 오른편에 앉으셨느니라.", "web": "looking to Jesus, the author and perfecter of faith, who for the joy that was set before him endured the cross, despising its shame, and has sat down at the right hand of the throne of God."}}, {"id": 414, "coll": "무장 900구절", "sub": ["제자도", "Discipleship"], "book": "마태복음", "chap": 7, "verse": "13-14", "ref": "마태복음 7:13-14", "texts": {"krv": "좁은 문으로 들어가라 멸망으로 인도하는 문은 크고 그 길이 넓어 그리로 들어가는 자가 많고 생명으로 인도하는 문은 좁고 길이 협착하여 찾는 이가 적음이니라", "kkjv": "¶너희는 좁은 문으로 들어가라. 멸망으로 인도하는 그 문은 넓고 그 길이 넓어 거기로 들어가는 자가 많고 생명으로 인도하는 그 문은 좁고 그 길이 좁아 그것을 찾는 자가 적으니라.", "web": "“Enter in by the narrow gate; for wide is the gate and broad is the way that leads to destruction, and many are those who enter in by it. Hownarrow is the gate, and restricted is the way that leads to life! Few are those who find it."}}, {"id": 415, "coll": "무장 900구절", "sub": ["제자도", "Discipleship"], "book": "마태복음", "chap": 10, "verse": "42", "ref": "마태복음 10:42", "texts": {"krv": "또 누구든지 제자의 이름으로 이 소자 중 하나에게 냉수 한 그릇이라도 주는 자는 내가 진실로 너희에게 이르노니 그 사람이 결단코 상을 잃지 아니하리라 하시니라", "kkjv": "또 누구든지 제자의 이름으로 이 작은 자들 중 하나에게 찬 물 한 잔이라도 주어 마시게 하면 진실로 내가 너희에게 이르노니, 그가 결코 자기 보상을 잃지 아니하리라, 하시니라.", "web": "Whoever gives one of these little ones just a cup of cold water to drink in the name of a disciple, most certainly I tell you he will in no way lose his reward.”"}}, {"id": 416, "coll": "무장 900구절", "sub": ["제자도", "Discipleship"], "book": "마태복음", "chap": 12, "verse": "50", "ref": "마태복음 12:50", "texts": {"krv": "누구든지 하늘에 계신 내 아버지의 뜻대로 하는 자가 내 형제요 자매요 모친이니라 하시더라", "kkjv": "누구든지 하늘에 계신 내 아버지의 뜻을 행하는 자 곧 그가 내 형제요 자매요 어머니이니라, 하시니라.", "web": "For whoever does the will of my Father who is in heaven, he is my brother, and sister, and mother.”"}}, {"id": 417, "coll": "무장 900구절", "sub": ["제자도", "Discipleship"], "book": "마태복음", "chap": 19, "verse": "21", "ref": "마태복음 19:21", "texts": {"krv": "예수께서 가라사대 네가 온전하고자 할진대 가서 네 소유를 팔아 가난한 자들을 주라 그리하면 하늘에서 보화가 네게 있으리라 그리고 와서 나를 좇으라 하시니", "kkjv": "예수님께서 그에게 이르시되, 네가 완전하게 되려거든 가서 네 소유를 팔아 가난한 사람들에게 주라. 그리하면 하늘에서 네게 보화가 있으리라. 그리고 와서 나를 따르라, 하시매", "web": "Jesus said to him, “If you want to be perfect, go, sell what you have, and give to the poor, and you will have treasure in heaven; and come, follow me.”"}}, {"id": 418, "coll": "무장 900구절", "sub": ["제자도", "Discipleship"], "book": "마가복음", "chap": 10, "verse": "29-30", "ref": "마가복음 10:29-30", "texts": {"krv": "예수께서 가라사대 내가 진실로 너희에게 이르노니 나와 및 복음을 위하여 집이나 형제나 자매나 어미나 아비나 자식이나 전토를 버린 자는 금세에 있어 집과 형제와 자매와 모친과 자식과 전토를 백배나 받되 핍박을 겸하여 받고 내세에 영생을 받지 못할 자가 없느니라", "kkjv": "예수님께서 응답하여 이르시되, 진실로 내가 너희에게 이르노니, 나와 복음을 위하여 집이나 형제나 자매나 아버지나 어머니나 아내나 자녀나 토지를 버린 자는 지금 이 시대에서 집과 형제와 자매와 어머니와 자녀와 토지를 백 배나 받되 핍박과 함께 받고 오는 세상에서는 영원한 생명을 받으리라.", "web": "Jesus said, “Most certainly I tell you, there is no one who has left house, or brothers, or sisters, or father, or mother, or wife, or children, or land, for my sake, and for the sake of the Good News, but he will receive one hundred times more now in this time, houses, brothers, sisters, mothers, children, and land, with persecutions; and in the age to come eternal life."}}, {"id": 419, "coll": "무장 900구절", "sub": ["제자도", "Discipleship"], "book": "누가복음", "chap": 9, "verse": "60", "ref": "누가복음 9:60", "texts": {"krv": "가라사대 죽은 자들로 자기의 죽은 자들을 장사하게 하고 너는 가서 하나님의 나라를 전파하라 하시고", "kkjv": "예수님께서 그에게 이르시되, 죽은 자들이 자기들의 죽은 자들을 장사지내게 하고 너는 가서 하나님의 왕국을 선포하라, 하시니라.", "web": "But Jesus said to him, “Leave the dead to bury their own dead, but you go and announce the Kingdom of God.”"}}, {"id": 420, "coll": "무장 900구절", "sub": ["제자도", "Discipleship"], "book": "누가복음", "chap": 12, "verse": "22", "ref": "누가복음 12:22", "texts": {"krv": "또 제자들에게 이르시되 그러므로 내가 너희에게 이르노니 너희 목숨을 위하여 무엇을 먹을까 몸을 위하여 무엇을 입을까 염려하지 말라", "kkjv": "¶또 그분께서 자기 제자들에게 이르시되, 그러므로 내가 너희에게 이르노니, 너희 생명을 위해 무엇을 먹을까, 몸을 위해 무엇을 입을까 염려하지 말라.", "web": "He said to his disciples, “Therefore I tell you, don’t be anxious for your life, what you will eat, nor yet for your body, what you will wear."}}, {"id": 421, "coll": "무장 900구절", "sub": ["제자도", "Discipleship"], "book": "누가복음", "chap": 14, "verse": "26-27", "ref": "누가복음 14:26-27", "texts": {"krv": "무릇 내게 오는 자가 자기 부모와 처자와 형제와 자매와 및 자기 목숨까지 미워하지 아니하면 능히 나의 제자가 되지 못하고 누구든지 자기 십자가를 지고 나를 좇지 않는 자도 능히 나의 제자가 되지 못하리라", "kkjv": "어떤 사람이 내게 오면서 자기 아버지나 어머니나 아내나 자녀나 형제나 자매나 참으로 자기 생명도 미워하지 아니하면 능히 내 제자가 되지 못하고 누구든지 자기 십자가를 지고 나를 따라오지 아니하는 자도 능히 내 제자가 되지 못하리라.", "web": "“If anyone comes to me, and doesn’t disregardhis own father, mother, wife, children, brothers, and sisters, yes, and his own life also, he can’t be my disciple. Whoever doesn’t bear his own cross, and come after me, can’t be my disciple."}}, {"id": 422, "coll": "무장 900구절", "sub": ["제자도", "Discipleship"], "book": "누가복음", "chap": 14, "verse": "33", "ref": "누가복음 14:33", "texts": {"krv": "이와 같이 너희 중에 누구든지 자기의 모든 소유를 버리지 아니하면 능히 내 제자가 되지 못하리라", "kkjv": "이와 같이 너희 중에 누구든지 자기의 모든 소유를 버리지 아니하는 자는 능히 내 제자가 되지 못하리라.", "web": "So therefore whoever of you who doesn’t renounce all that he has, he can’t be my disciple."}}, {"id": 423, "coll": "무장 900구절", "sub": ["제자도", "Discipleship"], "book": "요한복음", "chap": 6, "verse": "67-68", "ref": "요한복음 6:67-68", "texts": {"krv": "예수께서 열 두 제자에게 이르시되 너희도 가려느냐 시몬 베드로가 대답하되 주여 영생의 말씀이 계시매 우리가 뉘게로 가오리이까", "kkjv": "이에 예수님께서 열둘에게 이르시되, 너희도 가려느냐? 하시니 그때에 시몬 베드로가 그분께 대답하되, 주여, 영원한 생명의 말씀들이 주께 있사온대 우리가 누구에게로 가리이까?", "web": "Jesus said therefore to the twelve, “You don’t also want to go away, do you?” Simon Peter answered him, “Lord, to whom would we go? You have the words of eternal life."}}, {"id": 424, "coll": "무장 900구절", "sub": ["제자도", "Discipleship"], "book": "요한복음", "chap": 12, "verse": "25", "ref": "요한복음 12:25", "texts": {"krv": "자기 생명을 사랑하는 자는 잃어버릴 것이요 이 세상에서 자기 생명을 미워하는 자는 영생하도록 보존하리라", "kkjv": "자기 생명을 사랑하는 자는 그것을 잃을 것이요, 이 세상에서 자기 생명을 미워하는 자는 영생에 이르도록 그것을 간직하리라.", "web": "He who loves his life will lose it. He who hates his life in this world will keep it to eternal life."}}, {"id": 425, "coll": "무장 900구절", "sub": ["제자도", "Discipleship"], "book": "요한복음", "chap": 15, "verse": "8", "ref": "요한복음 15:8", "texts": {"krv": "너희가 과실을 많이 맺으면 내 아버지께서 영광을 받으실 것이요 너희가 내 제자가 되리라", "kkjv": "너희가 열매를 많이 맺는 것, 이것으로 내 아버지께서 영광을 받으시나니 이로써 너희가 내 제자가 되리라.", "web": "“In this is my Father glorified, that you bear much fruit; and so you will be my disciples."}}, {"id": 426, "coll": "무장 900구절", "sub": ["제자도", "신분 의식"], "book": "이사야", "chap": 43, "verse": "1", "ref": "이사야 43:1", "texts": {"krv": "야곱아 너를 창조하신 여호와께서 이제 말씀하시느니라 이스라엘아 너를 조성하신 자가 이제 말씀하시느니라 너는 두려워 말라 내가 너를 구속하였고 내가 너를 지명하여 불렀나니 너는 내 것이라", "kkjv": "그러나, 오 야곱아, 너를 창조한 주가 이제 이같이 말하노라. 오 이스라엘아, 너를 지은 이가 말하노라. 두려워하지 말라. 내가 너를 구속하고 내가 너를 네 이름으로 불렀나니 너는 내 것이니라.", "web": "But now thus says Yahweh who created you, Jacob, and he who formed you, Israel: “Don’t be afraid, for I have redeemed you. I have called you by your name. You are mine."}}, {"id": 427, "coll": "무장 900구절", "sub": ["제자도", "신분 의식"], "book": "이사야", "chap": 49, "verse": "5", "ref": "이사야 49:5", "texts": {"krv": "나는 여호와의 보시기에 존귀한 자라 나의 하나님이 나의 힘이 되셨도다 다시 야곱을 자기에게로 돌아오게 하시며 이스라엘을 자기에게로 모이게 하시려고 나를 태에서 나옴으로부터 자기 종을 삼으신 여호와께서 말씀하시니라", "kkjv": "¶나를 자기 종으로 삼으시려고, 야곱을 자기에게로 다시 데려오시려고 태에서부터 나를 지으신 주께서 말씀하시되, 지금 비록 이스라엘이 모여 있지 아니하여도 내가 주의 눈에 영화롭게 되고 나의 하나님이 나의 힘이 되시리로다, 하시는도다.", "web": "Now says Yahweh who formed me from the womb to be his servant, to bring Jacob again to him, and that Israel be gathered to him (for I am honorable in the eyes of Yahweh, and my God has become my strength);"}}, {"id": 428, "coll": "무장 900구절", "sub": ["제자도", "신분 의식"], "book": "스바냐", "chap": 3, "verse": "17", "ref": "스바냐 3:17", "texts": {"krv": "너의 하나님 여호와가 너의 가운데 계시니 그는 구원을 베푸실 전능자시라 그가 너로 인하여 기쁨을 이기지 못하여 하시며 너를 잠잠히 사랑하시며 너로 인하여 즐거이 부르며 기뻐하시리라 하리라", "kkjv": "네 한가운데 계시는 주 네 하나님은 능하신 이시니 그분께서 구원하시고 너로 인해 기뻐하며 즐거워하시고 친히 사랑하시는 가운데 안식하시며 너로 인해 노래를 부르고 기뻐하시리라, 하리라.", "web": "Yahweh, your God, is in your midst, a mighty one who will save. He will rejoice over you with joy. He will calm you in his love. He will rejoice over you with singing."}}, {"id": 429, "coll": "무장 900구절", "sub": ["제자도", "신분 의식"], "book": "마태복음", "chap": 5, "verse": "13", "ref": "마태복음 5:13", "texts": {"krv": "너희는 세상의 소금이니 소금이 만일 그 맛을 잃으면 무엇으로 짜게 하리요 후에는 아무 쓸데없어 다만 밖에 버리워 사람에게 밟힐 뿐이니라", "kkjv": "¶너희는 땅의 소금이로되 만일 소금이 제 맛을 잃으면 무엇으로 그것을 짜게 하리요? 그 뒤에는 그것이 아무 쓸모없으므로 버려져서 사람들의 발밑에 밟힐 뿐이니라.", "web": "“You are the salt of the earth, but if the salt has lost its flavor, with what will it be salted? It is then good for nothing, but to be cast out and trodden under the feet of men."}}, {"id": 430, "coll": "무장 900구절", "sub": ["제자도", "신분 의식"], "book": "마태복음", "chap": 10, "verse": "30-31", "ref": "마태복음 10:30-31", "texts": {"krv": "너희에게는 머리털까지 다 세신 바 되었나니 두려워하지 말라 너희는 많은 참새보다 귀하니라", "kkjv": "오직 아버지께서 너희 머리털까지도 다 세셨나니 그러므로 너희는 두려워하지 말라. 너희는 많은 참새보다 더 귀중하니라.", "web": "but the very hairs of your head are all numbered. Therefore don’t be afraid. You are of more value than many sparrows."}}, {"id": 431, "coll": "무장 900구절", "sub": ["제자도", "신분 의식"], "book": "마태복음", "chap": 11, "verse": "11", "ref": "마태복음 11:11", "texts": {"krv": "내가 진실로 너희에게 말하노니 여자가 낳은 자 중에 세례 요한보다 큰 이가 일어남이 없도다 그러나 천국에서는 극히 작은 자라도 저보다 크니라", "kkjv": "진실로 내가 너희에게 이르노니, 여자에게서 태어난 자들 가운데 침례자 요한보다 더 큰 자가 일어나지 아니하였도다. 그럼에도 불구하고 하늘의 왕국에서 가장 작은 자가 그보다 더 크니라.", "web": "Most certainly I tell you, among those who are born of women there has not arisen anyone greater than John the Baptizer; yet he who is least in the Kingdom of Heaven is greater than he."}}, {"id": 432, "coll": "무장 900구절", "sub": ["제자도", "신분 의식"], "book": "요한복음", "chap": 15, "verse": "13-14", "ref": "요한복음 15:13-14", "texts": {"krv": "사람이 친구를 위하여 자기 목숨을 버리면 이에서 더 큰 사랑이 없나니 너희가 나의 명하는 대로 행하면 곧 나의 친구라", "kkjv": "아무에게도 자기 친구들을 위해 자기 생명을 내놓는 것, 이것보다 더 큰 사랑은 없나니 무엇이든지 내가 너희에게 명령하는 것을 너희가 행하면 너희가 나의 친구니라.", "web": "Greater love has no one than this, that someone lay down his life for his friends. You are my friends, if you do whatever I command you."}}, {"id": 433, "coll": "무장 900구절", "sub": ["제자도", "신분 의식"], "book": "요한복음", "chap": 17, "verse": "16", "ref": "요한복음 17:16", "texts": {"krv": "내가 세상에 속하지 아니함 같이 저희도 세상에 속하지 아니하였삽나이다", "kkjv": "내가 세상에 속하지 아니한 것 같이 그들도 세상에 속하지 아니하나이다.", "web": "They are not of the world even as I am not of the world."}}, {"id": 434, "coll": "무장 900구절", "sub": ["제자도", "신분 의식"], "book": "고린도후서", "chap": 3, "verse": "8-9", "ref": "고린도후서 3:8-9", "texts": {"krv": "하물며 영의 직분이 더욱 영광이 있지 아니하겠느냐 정죄의 직분도 영광이 있은즉 의의 직분은 영광이 더욱 넘치리라", "kkjv": "하물며 영의 직무에는 더욱 영광이 있지 아니하겠느냐? 정죄의 직무도 영광이 될진대 의의 직무는 영광이 더욱 뛰어나니라.", "web": "won’t service of the Spirit be with much more glory? For if the service of condemnation has glory, the service of righteousness exceeds much more in glory."}}, {"id": 435, "coll": "무장 900구절", "sub": ["제자도", "신분 의식"], "book": "고린도후서", "chap": 6, "verse": "10", "ref": "고린도후서 6:10", "texts": {"krv": "근심하는 자 같으나 항상 기뻐하고 가난한 자 같으나 많은 사람을 부요하게 하고 아무것도 없는 자 같으나 모든 것을 가진 자로다", "kkjv": "근심하는 자 같으나 항상 기뻐하고 가난한 자 같으나 많은 사람을 부요하게 하며 아무것도 없는 자 같으나 모든 것을 소유한 자로다.", "web": "as sorrowful, yet always rejoicing; as poor, yet making many rich; as having nothing, and yet possessing all things."}}, {"id": 436, "coll": "무장 900구절", "sub": ["제자도", "신분 의식"], "book": "에베소서", "chap": 5, "verse": "8", "ref": "에베소서 5:8", "texts": {"krv": "너희가 전에는 어두움이더니 이제는 주 안에서 빛이라 빛의 자녀들처럼 행하라", "kkjv": "너희가 한때는 어둠이었으나 이제는 주 안에서 빛이니 빛의 자녀들로서 걸으라.", "web": "For you were once darkness, but are now light in the Lord. Walk as children of light,"}}, {"id": 437, "coll": "무장 900구절", "sub": ["제자도", "신분 의식"], "book": "히브리서", "chap": 2, "verse": "11", "ref": "히브리서 2:11", "texts": {"krv": "거룩하게 하시는 자와 거룩하게 함을 입은 자들이 다 하나에서 난지라 그러므로 형제라 부르시기를 부끄러워 아니하시고", "kkjv": "거룩히 구별하시는 분과 거룩히 구별된 자들이 다 하나에서 났으니 이러한 까닭에 그분께서 그들을 형제라 부르기를 부끄러워하지 아니하시고", "web": "For both he who sanctifies and those who are sanctified are all from one, for which cause he is not ashamed to call them brothers,"}}, {"id": 438, "coll": "무장 900구절", "sub": ["일꾼 배가", "Promise"], "book": "창세기", "chap": 12, "verse": "1-3", "ref": "창세기 12:1-3", "texts": {"krv": "여호와께서 아브람에게 이르시되 너는 너의 본토 친척 아비 집을 떠나 내가 네게 지시할 땅으로 가라 내가 너로 큰 민족을 이루고 네게 복을 주어 네 이름을 창대케 하리니 너는 복의 근원이 될지라 너를 축복하는 자에게는 내가 복을 내리고 너를 저주하는 자에게는 내가 저주하리니 땅의 모든 족속이 너를 인하여 복을 얻을 것이니라 하신지라", "kkjv": "그런데 전에 주께서 아브람에게 이르시되, 너는 네 고향과 친족과 아버지 집에서 나와 내가 네게 보여 줄 땅으로 가라. 내가 너로부터 큰 민족을 만들고 네게 복을 주어 네 이름을 크게 하리니 네가 복이 되리라. 너를 축복하는 자들에게는 내가 복을 주고 너를 저주하는 자에게는 저주를 내리리니 네 안에서 땅의 모든 가족들이 복을 받으리라, 하셨더라.", "web": "Now Yahweh said to Abram, “Get out of your country, and from your relatives, and from your father’s house, to the land that I will show you. I will make of you a great nation. I will bless you and make your name great. You will be a blessing. I will bless those who bless you, and I will curse him who curses you. All of the families of the earth will be blessed in you.”"}}, {"id": 439, "coll": "무장 900구절", "sub": ["일꾼 배가", "Promise"], "book": "이사야", "chap": 42, "verse": "6", "ref": "이사야 42:6", "texts": {"krv": "나 여호와가 의로 너를 불렀은즉 내가 네 손을 잡아 너를 보호하며 너를 세워 백성의 언약과 이방의 빛이 되게 하리니", "kkjv": "나 주가 의 안에서 너를 불렀은즉 내가 네 손을 붙잡고 너를 지키며 너를 백성의 언약으로, 이방인들의 빛으로 주리니", "web": "“I, Yahweh, have called you in righteousness, and will hold your hand, and will keep you, and make you a covenant for the people, as a light for the nations;"}}, {"id": 440, "coll": "무장 900구절", "sub": ["일꾼 배가", "Promise"], "book": "이사야", "chap": 43, "verse": "4", "ref": "이사야 43:4", "texts": {"krv": "내가 너를 보배롭고 존귀하게 여기고 너를 사랑하였은즉 내가 사람들을 주어 너를 바꾸며 백성들로 네 생명을 대신하리니", "kkjv": "너는 내 눈앞에서 귀중하므로 존귀한 자였으며 내가 너를 사랑하였은즉 내가 네 대신 사람들을 내주며 백성들을 내주어 네 생명을 대신하게 하리니", "web": "Since you have been precious and honored in my sight, and I have loved you; therefore I will give people in your place, and nations instead of your life."}}, {"id": 441, "coll": "무장 900구절", "sub": ["일꾼 배가", "Promise"], "book": "이사야", "chap": 43, "verse": "19", "ref": "이사야 43:19", "texts": {"krv": "보라 내가 새 일을 행하리니 이제 나타낼 것이라 너희가 그것을 알지 못하겠느냐 정녕히 내가 광야에 길과 사막에 강을 내리니", "kkjv": "보라, 내가 새 일을 행하리니 이제 그것이 솟아오르리라. 너희가 그것을 알지 못하겠느냐? 심지어 내가 광야에 길을 내며 사막에 강들을 내리니", "web": "Behold, I will do a new thing. It springs out now. Don’t you know it? I will even make a way in the wilderness, and rivers in the desert."}}, {"id": 442, "coll": "무장 900구절", "sub": ["일꾼 배가", "Promise"], "book": "이사야", "chap": 49, "verse": "25", "ref": "이사야 49:25", "texts": {"krv": "나 여호와가 이같이 말하노라 용사의 포로도 빼앗을 것이요 강포자의 빼앗은 것도 건져낼 것이니 이는 내가 너를 대적하는 자를 대적하고 네 자녀를 구원할 것임이라", "kkjv": "그러나 주가 이같이 말하노라. 용사가 끌고 간 포로들도 빼앗아 오고 무서운 자들의 탈취물도 건져 내리니 내가 너와 싸우는 자와 싸우고 네 자녀들을 구원하리라.", "web": "But thus says Yahweh, “Even the captives of the mighty shall be taken away, and the plunder of the terrible shall be delivered; for I will contend with him who contends with you, and I will save your children."}}, {"id": 443, "coll": "무장 900구절", "sub": ["일꾼 배가", "Promise"], "book": "이사야", "chap": 51, "verse": "2", "ref": "이사야 51:2", "texts": {"krv": "너희 조상 아브라함과 너희를 생산한 사라를 생각하여 보라 아브라함이 혈혈 단신으로 있을 때에 내가 부르고 그에게 복을 주어 창성케 하였느니라", "kkjv": "너희 조상 아브라함과 너희를 낳은 사라를 보라. 내가 그를 홀로 불러 그에게 복을 주고 그를 증대시켰느니라.", "web": "Look to Abraham your father, and to Sarah who bore you; for when he was but one I called him, and I blessed him, and made him many."}}, {"id": 444, "coll": "무장 900구절", "sub": ["일꾼 배가", "Promise"], "book": "이사야", "chap": 60, "verse": "1", "ref": "이사야 60:1", "texts": {"krv": "일어나라 빛을 발하라 이는 네 빛이 이르렀고 여호와의 영광이 네 위에 임하였음이니라", "kkjv": "일어나라. 빛을 발하라. 네 빛이 이르렀고 주의 영광이 일어나 네 위에 임하였느니라.", "web": "“Arise, shine; for your light has come, and Yahweh’s glory is risen on you."}}, {"id": 445, "coll": "무장 900구절", "sub": ["일꾼 배가", "Promise"], "book": "이사야", "chap": 60, "verse": "15", "ref": "이사야 60:15", "texts": {"krv": "전에는 네가 버림을 입으며 미움을 당하였으므로 네게로 지나는 자가 없었으나 이제는 내가 너로 영영한 아름다움과 대대의 기쁨이 되게 하리니", "kkjv": "전에는 네가 버림을 받고 미움을 받았으므로 너를 통해 지나가는 자가 없었으나 내가 너를 영원히 뛰어난 자가 되게 하며 많은 세대들의 기쁨이 되게 하리니", "web": "“Whereas you have been forsaken and hated, so that no man passed through you, I will make you an eternal excellency, a joy of many generations."}}, {"id": 446, "coll": "무장 900구절", "sub": ["일꾼 배가", "Promise"], "book": "갈라디아서", "chap": 4, "verse": "28", "ref": "갈라디아서 4:28", "texts": {"krv": "형제들아 너희는 이삭과 같이 약속의 자녀라", "kkjv": "형제들아, 이제 우리는 이삭과 같이 약속의 아이들이니라.", "web": "Now we, brothers, as Isaac was, are children of promise."}}, {"id": 447, "coll": "무장 900구절", "sub": ["일꾼 배가", "Promise"], "book": "히브리서", "chap": 6, "verse": "14-15", "ref": "히브리서 6:14-15", "texts": {"krv": "가라사대 내가 반드시 너를 복 주고 복 주며 너를 번성케 하고 번성케 하리라 하셨더니 저가 이같이 오래 참아 약속을 받았느니라", "kkjv": "이르시되, 내가 반드시 네게 복을 주고 복을 주며 너를 번성하게 하고 번성하게 하리라, 하셨더니 그가 이같이 끈기 있게 견딘 뒤에 그 약속하신 것을 얻었느니라.", "web": "saying, “Surely blessing I will bless you, and multiplying I will multiply you.” Thus, having patiently endured, he obtained the promise."}}, {"id": 448, "coll": "무장 900구절", "sub": ["일꾼 배가", "Promise"], "book": "히브리서", "chap": 6, "verse": "17", "ref": "히브리서 6:17", "texts": {"krv": "하나님은 약속을 기업으로 받는 자들에게 그 뜻이 변치 아니함을 충분히 나타내시려고 그 일에 맹세로 보증하셨나니", "kkjv": "이러므로 하나님께서도 약속의 상속자들에게 자신의 계획이 불변함을 더욱 풍성히 보여 주시려고 그 일을 맹세로써 확증하셨나니", "web": "In this way God, being determined to show more abundantly to the heirs of the promise the immutability of his counsel, interposed with an oath;"}}, {"id": 449, "coll": "무장 900구절", "sub": ["일꾼 배가", "Promise"], "book": "히브리서", "chap": 11, "verse": "12", "ref": "히브리서 11:12", "texts": {"krv": "이러므로 죽은 자와 방불한 한 사람으로 말미암아 하늘에 허다한 별과 또 해변의 무수한 모래와 같이 많이 생육하였느니라", "kkjv": "그러므로 심지어 죽은 자와 다름없던 한 사람에게서 하늘의 허다한 별과 바닷가의 무수한 모래와 같이 많은 사람이 나왔느니라.", "web": "Therefore as many as the stars of the sky in multitude, and as innumerable as the sand which is by the sea shore, were fathered by one man, and him as good as dead."}}, {"id": 450, "coll": "무장 900구절", "sub": ["일꾼 배가", "기업"], "book": "창세기", "chap": 13, "verse": "14-15", "ref": "창세기 13:14-15", "texts": {"krv": "롯이 아브람을 떠난 후에 여호와께서 아브람에게 이르시되 너는 눈을 들어 너 있는 곳에서 동서남북을 바라보라 보이는 땅을 내가 너와 네 자손에게 주리니 영원히 이르리라", "kkjv": "¶롯이 아브람을 떠나 갈라선 뒤에 주께서 아브람에게 이르시되, 이제 네 눈을 들어 네가 있는 곳에서부터 북쪽과 남쪽과 동쪽과 서쪽을 바라보라. 네가 보는 온 땅을 내가 너와 네 씨에게 영원히 주리라.", "web": "Yahweh said to Abram, after Lot was separated from him, “Now, lift up your eyes, and look from the place where you are, northward and southward and eastward and westward, for all the land which you see, I will give to you, and to your offspring forever."}}, {"id": 451, "coll": "무장 900구절", "sub": ["일꾼 배가", "기업"], "book": "창세기", "chap": 32, "verse": "10", "ref": "창세기 32:10", "texts": {"krv": "나는 주께서 주의 종에게 베푸신 모든 은총과 모든 진리를 조금이라도 감당할 수 없사오나 내가 내 지팡이만 가지고 이 요단을 건넜더니 지금은 두 떼나 이루었나이다", "kkjv": "나는 주께서 주의 종에게 보여 주신 모든 긍휼과 모든 진리 중 가장 작은 것도 감당할 수 없사오니 내가 내 지팡이만 가지고 이 요르단을 건넜으나 지금은 두 떼나 이루었나이다.", "web": "I am not worthy of the least of all the loving kindnesses, and of all the truth, which you have shown to your servant; for with just my staff I passed over this Jordan; and now I have become two companies."}}, {"id": 452, "coll": "무장 900구절", "sub": ["일꾼 배가", "기업"], "book": "시편", "chap": 2, "verse": "8", "ref": "시편 2:8", "texts": {"krv": "내게 구하라 내가 열방을 유업으로 주리니 네 소유가 땅 끝까지 이르리로다", "kkjv": "내게 구하라. 그리하면 내가 이교도들을 네게 상속물로 주고 땅의 맨 끝 지역들을 네게 소유물로 주리라.", "web": "Ask of me, and I will give the nations for your inheritance, the uttermost parts of the earth for your possession."}}, {"id": 453, "coll": "무장 900구절", "sub": ["일꾼 배가", "기업"], "book": "시편", "chap": 16, "verse": "6", "ref": "시편 16:6", "texts": {"krv": "내게 줄로 재어 준 구역은 아름다운 곳에 있음이여 나의 기업이 실로 아름답도다", "kkjv": "줄들이 나를 위해 아름다운 곳들에 떨어졌나니 참으로 내게 좋은 유산이 있도다.", "web": "The lines have fallen to me in pleasant places. Yes, I have a good inheritance."}}, {"id": 454, "coll": "무장 900구절", "sub": ["일꾼 배가", "기업"], "book": "시편", "chap": 119, "verse": "57", "ref": "시편 119:57", "texts": {"krv": "여호와는 나의 분깃이시니 나는 주의 말씀을 지키리라 하였나이다", "kkjv": "오 주여, 주는 나의 몫이오니 내가 주의 말씀들을 지키리라 말하였나이다.", "web": "Yahweh is my portion. I promised to obey your words."}}, {"id": 455, "coll": "무장 900구절", "sub": ["일꾼 배가", "기업"], "book": "시편", "chap": 127, "verse": "3", "ref": "시편 127:3", "texts": {"krv": "자식은 여호와의 주신 기업이요 태의 열매는 그의 상급이로다", "kkjv": "보라, 자식들은 주의 유산이요, 태의 열매는 그분의 보상이로다.", "web": "Behold, children are a heritage of Yahweh. The fruit of the womb is his reward."}}, {"id": 456, "coll": "무장 900구절", "sub": ["일꾼 배가", "기업"], "book": "누가복음", "chap": 12, "verse": "32", "ref": "누가복음 12:32", "texts": {"krv": "적은 무리여 무서워 말라 너희 아버지께서 그 나라를 너희에게 주시기를 기뻐하시느니라", "kkjv": "적은 양 무리여, 두려워하지 말라. 너희 아버지께서 그 왕국을 너희에게 주시는 것을 참으로 기뻐하시느니라.", "web": "Don’t be afraid, little flock, for it is your Father’s good pleasure to give you the Kingdom."}}, {"id": 457, "coll": "무장 900구절", "sub": ["일꾼 배가", "기업"], "book": "로마서", "chap": 8, "verse": "17", "ref": "로마서 8:17", "texts": {"krv": "자녀이면 또한 후사 곧 하나님의 후사요 그리스도와 함께 한 후사니 우리가 그와 함께 영광을 받기 위하여 고난도 함께 받아야 될 것이니라", "kkjv": "자녀이면 상속자 곧 하나님의 상속자요, 그리스도와 함께하는 공동 상속자니라. 우리가 그분과 함께 고난당하면 이것은 우리가 함께 영광도 받으려 함이니라.", "web": "and if children, then heirs; heirs of God, and joint heirs with Christ; if indeed we suffer with him, that we may also be glorified with him."}}, {"id": 458, "coll": "무장 900구절", "sub": ["일꾼 배가", "기업"], "book": "갈라디아서", "chap": 3, "verse": "29", "ref": "갈라디아서 3:29", "texts": {"krv": "너희가 그리스도께 속한 자면 곧 아브라함의 자손이요 약속대로 유업을 이을 자니라", "kkjv": "너희가 그리스도께 속한 자면 곧 아브라함의 씨요 약속에 따른 상속자니라.", "web": "If you are Christ’s, then you are Abraham’s seed and heirs according to promise."}}, {"id": 459, "coll": "무장 900구절", "sub": ["일꾼 배가", "기업"], "book": "에베소서", "chap": 1, "verse": "18", "ref": "에베소서 1:18", "texts": {"krv": "너희 마음 눈을 밝히사 그의 부르심의 소망이 무엇이며 성도 안에서 그 기업의 영광의 풍성이 무엇이며", "kkjv": "너희의 지각의 눈을 밝히사 그분의 부르심의 소망이 무엇이며 성도들 안에 있는 그분의 상속 유업의 영광이 얼마나 풍성하며", "web": "having the eyes of your hearts enlightened, that you may know what is the hope of his calling, and what are the riches of the glory of his inheritance in the saints,"}}, {"id": 460, "coll": "무장 900구절", "sub": ["일꾼 배가", "기업"], "book": "히브리서", "chap": 11, "verse": "16", "ref": "히브리서 11:16", "texts": {"krv": "저희가 이제는 더 나은 본향을 사모하니 곧 하늘에 있는 것이라 그러므로 하나님이 저희 하나님이라 일컬음 받으심을 부끄러워 아니하시고 저희를 위하여 한 성을 예비하셨느니라", "kkjv": "이제는 그들이 더 좋은 본향을 사모하니 곧 하늘의 본향이라. 그러므로 하나님께서도 그들의 하나님이라 불리는 것을 부끄러워하지 아니하시나니 그분께서 그들을 위하여 한 도시를 예비하셨느니라.", "web": "But now they desire a better country, that is, a heavenly one. Therefore God is not ashamed of them, to be called their God, for he has prepared a city for them."}}, {"id": 461, "coll": "무장 900구절", "sub": ["일꾼 배가", "기업"], "book": "요한계시록", "chap": 22, "verse": "12", "ref": "요한계시록 22:12", "texts": {"krv": "보라 내가 속히 오리니 내가 줄 상이 내게 있어 각 사람에게 그의 일한 대로 갚아 주리라", "kkjv": "보라, 내가 속히 오리니 내가 줄 보상이 내게 있어 각 사람에게 그의 행위에 따라 주리라.", "web": "“Behold, I come quickly. My reward is with me, to repay to each man according to his work."}}, {"id": 462, "coll": "무장 900구절", "sub": ["일꾼 배가", "일꾼"], "book": "민수기", "chap": 1, "verse": "3", "ref": "민수기 1:3", "texts": {"krv": "이스라엘 중 이십세 이상으로 싸움에 나갈 만한 모든 자를 너와 아론은 그 군대대로 계수하되", "kkjv": "이스라엘 안에서 스무 살이 넘어 싸움에 나갈 수 있는 모든 자를 너와 아론은 그들의 군대대로 계수하고", "web": "from twenty years old and upward, all who are able to go out to war in Israel. You and Aaron shall number them by their divisions."}}, {"id": 463, "coll": "무장 900구절", "sub": ["일꾼 배가", "일꾼"], "book": "이사야", "chap": 46, "verse": "11", "ref": "이사야 46:11", "texts": {"krv": "내가 동방에서 독수리를 부르며 먼 나라에서 나의 모략을 이룰 사람을 부를 것이라 내가 말하였은즉 정녕 이룰 것이요 경영하였은즉 정녕 행하리라", "kkjv": "내가 동쪽에서 굶주린 새를 부르되 곧 먼 나라에서 나의 계획을 집행할 사람을 부르리라. 참으로 내가 그것을 말하였은즉 또한 그것을 이룰 것이요, 내가 그것을 작정하였은즉 또한 그것을 행하리라.", "web": "calling a ravenous bird from the east, the man of my counsel from a far country; yes, I have spoken, I will also bring it to pass; I have purposed, I will also do it."}}, {"id": 464, "coll": "무장 900구절", "sub": ["일꾼 배가", "일꾼"], "book": "에스겔", "chap": 3, "verse": "17", "ref": "에스겔 3:17", "texts": {"krv": "인자야 내가 너를 이스라엘 족속의 파숫군으로 세웠으니 너는 내 입의 말을 듣고 나를 대신하여 그들을 깨우치라", "kkjv": "사람의 아들아, 내가 너를 이스라엘의 집에게 파수꾼으로 세웠으니 그러므로 내 입에서 나오는 말을 듣고 내게서 나오는 경고를 그들에게 줄지니라.", "web": "Son of man, I have made you a watchman to the house of Israel: therefore hear the word from my mouth, and give them warning from me."}}, {"id": 465, "coll": "무장 900구절", "sub": ["일꾼 배가", "일꾼"], "book": "에스겔", "chap": 22, "verse": "30", "ref": "에스겔 22:30", "texts": {"krv": "이 땅을 위하여 성을 쌓으며 성 무너진 데를 막아서서 나로 멸하지 못하게 할 사람을 내가 그 가운데서 찾다가 얻지 못한 고로", "kkjv": "그 땅을 위해 내 앞에서 울타리를 세우며 무너진 곳에 서서 나로 하여금 그것을 멸하지 못하게 할 한 사람을 내가 그들 가운데서 찾았으나 아무도 찾지 못하였노라.", "web": "I sought for a man among them, who should build up the wall, and stand in the gap before me for the land, that I should not destroy it; but I found no one."}}, {"id": 466, "coll": "무장 900구절", "sub": ["일꾼 배가", "일꾼"], "book": "에베소서", "chap": 4, "verse": "12", "ref": "에베소서 4:12", "texts": {"krv": "이는 성도를 온전케 하며 봉사의 일을 하게 하며 그리스도의 몸을 세우려 하심이라", "kkjv": "이것은 성도들을 완전하게 하고 섬기는 일을 하게 하며 그리스도의 몸을 세우게 하려 하심이라.", "web": "for the perfecting of the saints, to the work of serving, to the building up of the body of Christ;"}}, {"id": 467, "coll": "무장 900구절", "sub": ["일꾼 배가", "일꾼"], "book": "빌립보서", "chap": 3, "verse": "3", "ref": "빌립보서 3:3", "texts": {"krv": "하나님의 성령으로 봉사하며 그리스도 예수로 자랑하고 육체를 신뢰하지 아니하는 우리가 곧 할례당이라", "kkjv": "영으로 하나님께 경배하고 그리스도 예수님을 기뻐하며 육체를 신뢰하지 아니하는 우리가 곧 할례자니라.", "web": "For we are the circumcision, who worship God in the Spirit, and rejoice in Christ Jesus, and have no confidence in the flesh;"}}, {"id": 468, "coll": "무장 900구절", "sub": ["일꾼 배가", "전도"], "book": "시편", "chap": 71, "verse": "15", "ref": "시편 71:15", "texts": {"krv": "내가 측량할 수 없는 주의 의와 구원을 내 입으로 종일 전하리이다", "kkjv": "내 입이 주의 의와 구원을 종일토록 전하리니 이는 내가 그것들의 수를 알지 못하기 때문이니이다.", "web": "My mouth will tell about your righteousness, and of your salvation all day, though I don’t know its full measure."}}, {"id": 469, "coll": "무장 900구절", "sub": ["일꾼 배가", "전도"], "book": "이사야", "chap": 52, "verse": "7", "ref": "이사야 52:7", "texts": {"krv": "좋은 소식을 가져오며 평화를 공포하며 복된 좋은 소식을 가져오며 구원을 공포하며 시온을 향하여 이르기를 네 하나님이 통치하신다 하는 자의 산을 넘는 발이 어찌 그리 아름다운고", "kkjv": "¶좋은 소식을 가져오고 화평을 선포하며 복된 좋은 소식을 가져오고 구원을 선포하며 시온에게 이르기를, 네 하나님께서 통치하신다, 하는 자의 산을 넘는 발이 어찌 그리 아름다운가!", "web": "How beautiful on the mountains are the feet of him who brings good news, who publishes peace, who brings good news of good, who publishes salvation, who says to Zion, “Your God reigns!”"}}, {"id": 470, "coll": "무장 900구절", "sub": ["일꾼 배가", "전도"], "book": "누가복음", "chap": 24, "verse": "46-48", "ref": "누가복음 24:46-48", "texts": {"krv": "또 이르시되 이같이 그리스도가 고난을 받고 제삼 일에 죽은 자 가운데서 살아날 것과 또 그의 이름으로 죄사함을 얻게 하는 회개가 예루살렘으로부터 시작하여 모든 족속에게 전파될 것이 기록되었으니 너희는 이 모든 일의 증인이라", "kkjv": "또 그들에게 이르시되, 이같이 기록되었은즉 이같이 그리스도가 고난을 받고 셋째 날 죽은 자들로부터 일어나는 것이 마땅하며 또 회개와 죄들의 사면이 그의 이름으로 예루살렘에서 시작하여 모든 민족들 가운데 선포되어야 하리니 너희는 이 일들의 증인이라.", "web": "He said to them, “Thus it is written, and thus it was necessary for the Christ to suffer and to rise from the dead the third day, and that repentance and remission of sins should be preached in his name to all the nations, beginning at Jerusalem. You are witnesses of these things."}}, {"id": 471, "coll": "무장 900구절", "sub": ["일꾼 배가", "전도"], "book": "요한복음", "chap": 4, "verse": "36", "ref": "요한복음 4:36", "texts": {"krv": "거두는 자가 이미 삯도 받고 영생에 이르는 열매를 모으나니 이는 뿌리는 자와 거두는 자가 함께 즐거워하게 하려 함이니라", "kkjv": "거두는 자가 삯을 받고 영원한 생명에 이르는 열매를 모으나니 이것은 뿌리는 자와 거두는 자가 다 함께 기뻐하려 함이라.", "web": "He who reaps receives wages, and gathers fruit to eternal life; that both he who sows and he who reaps may rejoice together."}}, {"id": 472, "coll": "무장 900구절", "sub": ["일꾼 배가", "전도"], "book": "사도행전", "chap": 4, "verse": "20", "ref": "사도행전 4:20", "texts": {"krv": "우리는 보고 들은 것을 말하지 아니할 수 없다 하니", "kkjv": "우리는 우리가 보고 들은 것들을 말할 수밖에 없노라, 하니라.", "web": "for we can’t help telling the things which we saw and heard.”"}}, {"id": 473, "coll": "무장 900구절", "sub": ["일꾼 배가", "전도"], "book": "사도행전", "chap": 5, "verse": "41", "ref": "사도행전 5:41", "texts": {"krv": "사도들은 그 이름을 위하여 능욕 받는 일에 합당한 자로 여기심을 기뻐하면서 공회 앞을 떠나니라", "kkjv": "¶그들은 자기들이 그분의 이름으로 인해 수치당하는 일에 합당한 자로 여겨진 것을 기뻐하며 공회 앞을 떠나니라.", "web": "They therefore departed from the presence of the council, rejoicing that they were counted worthy to suffer dishonor for Jesus’ name."}}, {"id": 474, "coll": "무장 900구절", "sub": ["일꾼 배가", "전도"], "book": "사도행전", "chap": 20, "verse": "24", "ref": "사도행전 20:24", "texts": {"krv": "나의 달려갈 길과 주 예수께 받은 사명 곧 하나님의 은혜의 복음 증거하는 일을 마치려 함에는 나의 생명을 조금도 귀한 것으로 여기지 아니하노라", "kkjv": "이 일들 중 어떤 것도 결코 나를 움직이지 못하며 또한 내가 나의 생명도 내게 귀한 것으로 여기지 아니하노니 이것은 내가 나의 달려갈 길과 주 예수님께 받은 사역 곧 하나님의 은혜의 복음을 증언하는 일을 기쁨으로 끝마치고자 함이라.", "web": "But these things don’t count; nor do I hold my life dear to myself, so that I may finish my race with joy, and the ministry which I received from the Lord Jesus, to fully testify to the Good News of the grace of God."}}, {"id": 475, "coll": "무장 900구절", "sub": ["일꾼 배가", "전도"], "book": "고린도전서", "chap": 1, "verse": "23-24", "ref": "고린도전서 1:23-24", "texts": {"krv": "우리는 십자가에 못 박힌 그리스도를 전하니 유대인에게는 거리끼는 것이요 이방인에게는 미련한 것이로되 오직 부르심을 입은 자들에게는 유대인이나 헬라인이나 그리스도는 하나님의 능력이요 하나님의 지혜니라", "kkjv": "우리는 십자가에 못 박히신 그리스도를 선포하노니 그분은 유대인들에게는 걸려 넘어지게 하는 것이요 그리스인들에게는 어리석은 것이로되 부르심을 받은 자들에게는 유대인들에게나 그리스인들에게나 그리스도는 하나님의 권능이시요 하나님의 지혜이시니라.", "web": "but we preach Christ crucified; a stumbling block to Jews, and foolishness to Greeks, but to those who are called, both Jews and Greeks, Christ is the power of God and the wisdom of God."}}, {"id": 476, "coll": "무장 900구절", "sub": ["일꾼 배가", "전도"], "book": "고린도전서", "chap": 9, "verse": "14", "ref": "고린도전서 9:14", "texts": {"krv": "이와 같이 주께서도 복음 전하는 자들이 복음으로 말미암아 살리라 명하셨느니라", "kkjv": "이와 같이 주께서도 복음을 선포하는 자들이 복음으로 살 것을 정하셨느니라.", "web": "Even so the Lord ordained that those who proclaim the Good News should live from the Good News."}}, {"id": 477, "coll": "무장 900구절", "sub": ["일꾼 배가", "전도"], "book": "고린도전서", "chap": 9, "verse": "16", "ref": "고린도전서 9:16", "texts": {"krv": "내가 복음을 전할지라도 자랑할 것이 없음은 내가 부득불 할 일임이라 만일 복음을 전하지 아니하면 내게 화가 있을 것임이로라", "kkjv": "내가 복음을 선포할지라도 자랑할 것이 없나니 이는 필연적으로 내가 해야 하기 때문이라. 만일 내가 복음을 선포하지 아니하면 참으로 내게 화가 있으리로다!", "web": "For if I preach the Good News, I have nothing to boast about; for necessity is laid on me; but woe is to me, if I don’t preach the Good News."}}, {"id": 478, "coll": "무장 900구절", "sub": ["일꾼 배가", "전도"], "book": "디모데후서", "chap": 4, "verse": "5", "ref": "디모데후서 4:5", "texts": {"krv": "그러나 너는 모든 일에 근신하여 고난을 받으며 전도인의 일을 하며 네 직무를 다하라", "kkjv": "그러나 너는 모든 일에서 깨어 있고 고난을 견디며 복음 전도자의 일을 행하고 네 사역을 온전히 입증하라.", "web": "But you be sober in all things, suffer hardship, do the work of an evangelist, and fulfill your ministry."}}, {"id": 479, "coll": "무장 900구절", "sub": ["일꾼 배가", "전도"], "book": "디모데후서", "chap": 4, "verse": "17", "ref": "디모데후서 4:17", "texts": {"krv": "주께서 내 곁에 서서 나를 강건케 하심은 나로 말미암아 전도의 말씀이 온전히 전파되어 이방인으로 듣게 하려 하심이니 내가 사자의 입에서 건지웠느니라", "kkjv": "그럼에도 불구하고 주께서 나와 함께 서서 나를 강건하게 하셨으니 이것은 나로 말미암아 그 선포한 말씀이 온전히 알려져서 모든 이방인들이 듣게 하려 하심이라. 내가 사자의 입에서 구출되었느니라.", "web": "But the Lord stood by me, and strengthened me, that through me the message might be fully proclaimed, and that all the Gentiles might hear; and I was delivered out of the mouth of the lion."}}, {"id": 480, "coll": "무장 900구절", "sub": ["일꾼 배가", "양육"], "book": "출애굽기", "chap": 18, "verse": "20", "ref": "출애굽기 18:20", "texts": {"krv": "그들에게 율례와 법도를 가르쳐서 마땅히 갈 길과 할 일을 그들에게 보이고", "kkjv": "그들에게 규례와 법들을 가르쳐서 그들이 마땅히 걸어야 할 길과 마땅히 행해야 할 일을 그들에게 보여 주며", "web": "You shall teach them the statutes and the laws, and shall show them the way in which they must walk, and the work that they must do."}}, {"id": 481, "coll": "무장 900구절", "sub": ["일꾼 배가", "양육"], "book": "신명기", "chap": 6, "verse": "7", "ref": "신명기 6:7", "texts": {"krv": "네 자녀에게 부지런히 가르치며 집에 앉았을 때에든지 길에 행할 때에든지 누웠을 때에든지 일어날 때에든지 이 말씀을 강론할 것이며", "kkjv": "너는 그것들을 네 자녀들에게 부지런히 가르치며 네가 네 집에 앉을 때에든지, 길을 걸을 때에든지, 누울 때에든지, 일어날 때에든지 그것들을 말할 것이며", "web": "and you shall teach them diligently to your children, and shall talk of them when you sit in your house, and when you walk by the way, and when you lie down, and when you rise up."}}, {"id": 482, "coll": "무장 900구절", "sub": ["일꾼 배가", "양육"], "book": "느헤미야", "chap": 8, "verse": "8", "ref": "느헤미야 8:8", "texts": {"krv": "하나님의 율법책을 낭독하고 그 뜻을 해석하여 백성으로 그 낭독하는 것을 다 깨닫게 하매", "kkjv": "이와 같이 그들이 하나님의 율법에서 책에서 명료하게 낭독하고 의미를 알려 주어 그들로 하여금 그 낭독하는 것을 깨닫게 하니라.", "web": "They read in the book, in the law of God, distinctly; and they gave the sense, so that they understood the reading."}}, {"id": 483, "coll": "무장 900구절", "sub": ["일꾼 배가", "양육"], "book": "잠언", "chap": 22, "verse": "6", "ref": "잠언 22:6", "texts": {"krv": "마땅히 행할 길을 아이에게 가르치라 그리하면 늙어도 그것을 떠나지 아니하리라", "kkjv": "아이가 마땅히 가야 할 길로 아이를 훈련시키라. 그리하면 그가 늙어서도 그 길을 떠나지 아니하리라.", "web": "Train up a child in the way he should go, and when he is old he will not depart from it."}}, {"id": 484, "coll": "무장 900구절", "sub": ["일꾼 배가", "양육"], "book": "요한복음", "chap": 21, "verse": "16", "ref": "요한복음 21:16", "texts": {"krv": "또 두번째 가라사대 요한의 아들 시몬아 네가 나를 사랑하느냐 하시니 가로되 주여 그러하외다 내가 주를 사랑하는 줄 주께서 아시나이다 가라사대 내 양을 치라 하시고", "kkjv": "다시 두 번째 그에게 이르시되, 요나의 아들 시몬아, 네가 나를 사랑하느냐? 하시니 그가 그분께 이르되, 주여, 그러하나이다. 내가 주를 사랑하는 줄 주께서 아시나이다, 하매 그분께서 그에게 이르시되, 내 양들을 먹이라, 하시고", "web": "He said to him again a second time, “Simon, son of Jonah, do you love me?”   He said to him, “Yes, Lord; you know that I have affection for you.”   He said to him, “Tend my sheep.”"}}, {"id": 485, "coll": "무장 900구절", "sub": ["일꾼 배가", "양육"], "book": "사도행전", "chap": 20, "verse": "31", "ref": "사도행전 20:31", "texts": {"krv": "그러므로 너희가 일깨어 내가 삼년이나 밤낮 쉬지 않고 눈물로 각 사람을 훈계하던 것을 기억하라", "kkjv": "그러므로 깨어서 내가 삼 년 동안 밤낮 쉬지 않고 눈물로 각 사람을 훈계하던 것을 기억하라.", "web": "Therefore watch, remembering that for a period of three years I didn’t cease to admonish everyone night and day with tears."}}, {"id": 486, "coll": "무장 900구절", "sub": ["일꾼 배가", "양육"], "book": "고린도전서", "chap": 4, "verse": "15", "ref": "고린도전서 4:15", "texts": {"krv": "그리스도 안에서 일만 스승이 있으되 아비는 많지 아니하니 그리스도 예수 안에서 복음으로써 내가 너희를 낳았음이라", "kkjv": "그리스도 안에서 너희에게 만 명의 스승이 있다 해도 아버지는 많지 아니하니 그리스도 예수님 안에서 복음을 통하여 내가 너희를 낳았느니라.", "web": "For though you have ten thousand tutors in Christ, yet not many fathers. For in Christ Jesus, I became your father through the Good News."}}, {"id": 487, "coll": "무장 900구절", "sub": ["일꾼 배가", "양육"], "book": "빌립보서", "chap": 1, "verse": "8", "ref": "빌립보서 1:8", "texts": {"krv": "내가 예수 그리스도의 심장으로 너희 무리를 어떻게 사모하는지 하나님이 내 증인이시니라", "kkjv": "내가 예수 그리스도의 심정으로 너희 모두를 얼마나 많이 그리워하는지 하나님께서 내 증인이시니라.", "web": "For God is my witness, how I long after all of you in the tender mercies of Christ Jesus."}}, {"id": 488, "coll": "무장 900구절", "sub": ["일꾼 배가", "양육"], "book": "빌립보서", "chap": 2, "verse": "17", "ref": "빌립보서 2:17", "texts": {"krv": "만일 너희 믿음의 제물과 봉사 위에 내가 나를 관제로 드릴지라도 나는 기뻐하고 너희 무리와 함께 기뻐하리니", "kkjv": "참으로 그러하며 또 너희의 믿음의 희생과 섬김 위에 내가 헌물로 드려질지라도 나는 기뻐하고 너희 모두와 함께 기뻐하리니", "web": "Yes, and if I am poured out on the sacrifice and service of your faith, I rejoice, and rejoice with you all."}}, {"id": 489, "coll": "무장 900구절", "sub": ["일꾼 배가", "양육"], "book": "데살로니가전서", "chap": 2, "verse": "11-12", "ref": "데살로니가전서 2:11-12", "texts": {"krv": "너희도 아는 바와 같이 우리가 너희 각 사람에게 아비가 자기 자녀에게 하듯 권면하고 위로하고 경계하노니 이는 너희를 부르사 자기 나라와 영광에 이르게 하시는 하나님께 합당히 행하게 하려 함이니라", "kkjv": "너희가 아는 바와 같이 우리가 너희 각 사람에게 아버지가 자기 자녀들에게 하듯 권면하고 위로하고 명하였노니 이것은 너희를 부르사 자신의 왕국과 영광에 이르게 하신 하나님께 너희가 합당히 걷게 하려 함이라.", "web": "As you know, we exhorted, comforted, and implored every one of you, as a father does his own children, to the end that you should walk worthily of God, who calls you into his own Kingdom and glory."}}, {"id": 490, "coll": "무장 900구절", "sub": ["일꾼 배가", "양육"], "book": "디모데전서", "chap": 4, "verse": "13", "ref": "디모데전서 4:13", "texts": {"krv": "내가 이를 때까지 읽는 것과 권하는 것과 가르치는 것에 착념하라", "kkjv": "내가 갈 때까지 읽는 것과 권면하는 것과 교리에 주의를 기울이라.", "web": "Until I come, pay attention to reading, to exhortation, and to teaching."}}, {"id": 491, "coll": "무장 900구절", "sub": ["일꾼 배가", "양육"], "book": "요한삼서", "chap": 1, "verse": "4", "ref": "요한삼서 1:4", "texts": {"krv": "내가 내 자녀들이 진리 안에서 행한다 함을 듣는 것보다 더 즐거움이 없도다", "kkjv": "내게는 내 자녀들이 진리 안에서 걷는다는 것을 듣는 것보다 더 큰 기쁨이 없도다.", "web": "I have no greater joy than this, to hear about my children walking in truth."}}, {"id": 492, "coll": "무장 900구절", "sub": ["일꾼 배가", "재생산"], "book": "레위기", "chap": 26, "verse": "8", "ref": "레위기 26:8", "texts": {"krv": "너희 다섯이 백을 쫓고 너희 백이 만을 쫓으리니 너희 대적들이 너희 앞에서 칼에 엎드러질 것이며", "kkjv": "너희 중 다섯 명이 백 명을 쫓고 너희 중 백 명이 만 명을 도망가게 하리니 너희 원수들이 너희 앞에서 칼에 쓰러지리라.", "web": "Five of you shall chase a hundred, and a hundred of you shall chase ten thousand; and your enemies shall fall before you by the sword."}}, {"id": 493, "coll": "무장 900구절", "sub": ["일꾼 배가", "재생산"], "book": "여호수아", "chap": 11, "verse": "15", "ref": "여호수아 11:15", "texts": {"krv": "여호와께서 그 종 모세에게 명하신 것을 모세는 여호수아에게 명하였고 여호수아는 그대로 행하여 여호와께서 무릇 모세에게 명하신 것을 하나도 행치 아니한 것이 없었더라", "kkjv": "¶주께서 자신의 종 모세에게 명령하신 대로 모세는 여호수아에게 명령하였고 여호수아는 그대로 행하여 주께서 모세에게 명령하신 모든 것 중에서 그가 행하지 않은 채 남겨 둔 것이 하나도 없었더라.", "web": "As Yahweh commanded Moses his servant, so Moses commanded Joshua. Joshua did so. He left nothing undone of all that Yahweh commanded Moses."}}, {"id": 494, "coll": "무장 900구절", "sub": ["일꾼 배가", "재생산"], "book": "시편", "chap": 115, "verse": "14", "ref": "시편 115:14", "texts": {"krv": "여호와께서 너희 곧 너희와 또 너희 자손을 더욱 번창케 하시기를 원하노라", "kkjv": "주께서 너희 곧 너희와 너희 자손들을 더욱 번창하게 하시리로다.", "web": "May Yahweh increase you more and more, you and your children."}}, {"id": 495, "coll": "무장 900구절", "sub": ["일꾼 배가", "재생산"], "book": "시편", "chap": 128, "verse": "6", "ref": "시편 128:6", "texts": {"krv": "네 자식의 자식을 볼지어다 이스라엘에게 평강이 있을지로다", "kkjv": "참으로 네 자식들의 자식들을 볼 것이요, 이스라엘 위에는 화평이 있으리로다.", "web": "Yes, may you see your children’s children. Peace be upon Israel."}}, {"id": 496, "coll": "무장 900구절", "sub": ["일꾼 배가", "재생산"], "book": "이사야", "chap": 59, "verse": "21", "ref": "이사야 59:21", "texts": {"krv": "여호와께서 또 가라사대 내가 그들과 세운 나의 언약이 이러하니 곧 네 위에 있는 나의 신과 네 입에 둔 나의 말이 이제부터 영영토록 네 입에서와 네 후손의 입에서와 네 후손의 후손의 입에서 떠나지 아니하리라 하시니라 여호와의 말씀이니라", "kkjv": "나로 말하건대 이것이 그들과 맺은 내 언약이니라. 주가 말하노라. 곧 네 위에 있는 내 영과 내가 네 입에 둔 내 말들이 이제부터 영원토록 네 입과 네 씨의 입과 네 씨의 씨의 입에서 떠나지 아니하리라. 주가 말하노라.", "web": "“As for me, this is my covenant with them,” says Yahweh. “My Spirit who is on you, and my words which I have put in your mouth, shall not depart out of your mouth, nor out of the mouth of your seed, nor out of the mouth of your seed’s seed,” says Yahweh, “from henceforth and forever.”"}}, {"id": 497, "coll": "무장 900구절", "sub": ["일꾼 배가", "재생산"], "book": "디모데후서", "chap": 2, "verse": "1-2", "ref": "디모데후서 2:1-2", "texts": {"krv": "내 아들아 그러므로 네가 그리스도 예수 안에 있는 은혜 속에서 강하고 또 네가 많은 증인 앞에서 내게 들은 바를 충성된 사람들에게 부탁하라 저희가 또 다른 사람들을 가르칠 수 있으리라", "kkjv": "그러므로 내 아들아, 너는 그리스도 예수님 안에 있는 은혜 안에서 강건한 자가 되고 또 네가 많은 증인들 가운데서 내게 들은 것들 바로 그것들을 신실한 사람들에게 맡기라. 그들이 또한 다른 사람들을 가르칠 수 있으리라.", "web": "You therefore, my child, be strengthened in the grace that is in Christ Jesus. The things which you have heard from me among many witnesses, commit the same to faithful men, who will be able to teach others also."}}, {"id": 498, "coll": "무장 900구절", "sub": ["일꾼 배가", "중보 기도"], "book": "창세기", "chap": 32, "verse": "26", "ref": "창세기 32:26", "texts": {"krv": "그 사람이 가로되 날이 새려하니 나로 가게 하라 야곱이 가로되 당신이 내게 축복하지 아니하면 가게 하지 아니하겠나이다", "kkjv": "그가 이르되, 날이 새려 하니 나를 가게 하라, 하매 야곱이 이르되, 당신이 나를 축복하지 아니하면 내가 당신을 가게 하지 아니하겠나이다, 하니", "web": "The man said, “Let me go, for the day breaks.”   Jacob said, “I won’t let you go, unless you bless me.”"}}, {"id": 499, "coll": "무장 900구절", "sub": ["일꾼 배가", "중보 기도"], "book": "출애굽기", "chap": 17, "verse": "11", "ref": "출애굽기 17:11", "texts": {"krv": "모세가 손을 들면 이스라엘이 이기고 손을 내리면 아말렉이 이기더니", "kkjv": "모세가 손을 들면 이스라엘이 이기고 그가 손을 내리면 아말렉이 이기더라.", "web": "When Moses held up his hand, Israel prevailed. When he let down his hand, Amalek prevailed."}}, {"id": 500, "coll": "무장 900구절", "sub": ["일꾼 배가", "중보 기도"], "book": "열왕기하", "chap": 6, "verse": "17", "ref": "열왕기하 6:17", "texts": {"krv": "기도하여 가로되 여호와여 원컨대 저의 눈을 열어서 보게 하옵소서 하니 여호와께서 그 사환의 눈을 여시매 저가 보니 불말과 불병거가 산에 가득하여 엘리사를 둘렀더라", "kkjv": "엘리사가 기도하여 이르되, 주여, 원하건대 그의 눈을 여시사 그가 보게 하옵소서, 하니 주께서 그 청년의 눈을 여시매 그가 보니, 보라, 불 말과 불 병거가 산에 가득하여 엘리사를 둘렀더라.", "web": "Elisha prayed, and said, “Yahweh, please open his eyes, that he may see.” Yahweh opened the eyes of the young man; and he saw: and behold, the mountain was full of horses and chariots of fire around Elisha."}}, {"id": 501, "coll": "무장 900구절", "sub": ["일꾼 배가", "중보 기도"], "book": "로마서", "chap": 1, "verse": "9", "ref": "로마서 1:9", "texts": {"krv": "내가 그의 아들의 복음 안에서 내 심령으로 섬기는 하나님이 나의 증인이 되시거니와 항상 내 기도에 쉬지 않고 너희를 말하며", "kkjv": "내가 그분의 아들의 복음 안에서 내 영으로 섬기는 하나님께서 내 증인이 되시거니와 내가 기도할 때에 언제나 너희에 관하여 끊임없이 말하며", "web": "For God is my witness, whom I serve in my spirit in the Good News of his Son, how unceasingly I make mention of you always in my prayers,"}}, {"id": 502, "coll": "무장 900구절", "sub": ["일꾼 배가", "중보 기도"], "book": "고린도후서", "chap": 13, "verse": "9", "ref": "고린도후서 13:9", "texts": {"krv": "우리가 약할 때에 너희의 강한 것을 기뻐하고 또 이것을 위하여 구하니 곧 너희의 온전하게 되는 것이라", "kkjv": "우리가 약할 때에 너희가 강한 것을 우리는 기뻐하노라. 또한 우리는 이것 즉 너희의 완전함을 바라노라.", "web": "For we rejoice when we are weak and you are strong. And this we also pray for, even your perfecting."}}, {"id": 503, "coll": "무장 900구절", "sub": ["일꾼 배가", "중보 기도"], "book": "에베소서", "chap": 6, "verse": "18-19", "ref": "에베소서 6:18-19", "texts": {"krv": "모든 기도와 간구로 하되 무시로 성령 안에서 기도하고 이를 위하여 깨어 구하기를 항상 힘쓰며 여러 성도를 위하여 구하고 또 나를 위하여 구할 것은 내게 말씀을 주사 나로 입을 벌려 복음의 비밀을 담대히 알리게 하옵소서 할 것이니", "kkjv": "모든 기도와 간구로 성령 안에서 항상 기도하되 모든 성도를 위해 모든 인내와 간구로 그 일에 깨어 있고 또 나를 위하여는 내게 말하는 것을 허락하사 내가 담대히 입을 열어 복음의 신비를 알리도록 구하라.", "web": "with all prayer and requests, praying at all times in the Spirit, and being watchful to this end in all perseverance and requests for all the saints: on my behalf, that utterance may be given to me in opening my mouth, to make known with boldness the mystery of the Good News,"}}, {"id": 504, "coll": "무장 900구절", "sub": ["일꾼 배가", "중보 기도"], "book": "빌립보서", "chap": 1, "verse": "10-11", "ref": "빌립보서 1:10-11", "texts": {"krv": "너희로 지극히 선한 것을 분별하며 또 진실하여 허물없이 그리스도의 날까지 이르고 예수 그리스도로 말미암아 의의 열매가 가득하여 하나님의 영광과 찬송이 되게 하시기를 구하노라", "kkjv": "너희가 뛰어난 것들을 입증하며 그리스도의 날까지 성실하고 실족거리가 없는 사람이 되며 예수 그리스도로 말미암은 의의 열매들로 가득하여 하나님의 영광과 찬양이 되기를 구하노라.", "web": "so that you may approve the things that are excellent; that you may be sincere and without offense to the day of Christ; being filled with the fruits of righteousness, which are through Jesus Christ, to the glory and praise of God."}}, {"id": 505, "coll": "무장 900구절", "sub": ["일꾼 배가", "중보 기도"], "book": "골로새서", "chap": 4, "verse": "3", "ref": "골로새서 4:3", "texts": {"krv": "또한 우리를 위하여 기도하되 하나님이 전도할 문을 우리에게 열어 주사 그리스도의 비밀을 말하게 하시기를 구하라 내가 이것을 인하여 매임을 당하였노라", "kkjv": "아울러 또한 우리를 위해 기도하되 하나님께서 말할 수 있는 문을 우리에게 열어 주사 그리스도의 신비를 말하게 하실 것을 구하라. 내가 또한 그것을 위해 결박당하였나니", "web": "praying together for us also, that God may open to us a door for the word, to speak the mystery of Christ, for which I am also in bonds;"}}, {"id": 506, "coll": "무장 900구절", "sub": ["일꾼 배가", "중보 기도"], "book": "골로새서", "chap": 4, "verse": "12", "ref": "골로새서 4:12", "texts": {"krv": "그리스도 예수의 종인 너희에게서 온 에바브라가 너희에게 문안하니 저가 항상 너희를 위하여 애써 기도하여 너희로 하나님의 모든 뜻 가운데서 완전하고 확신있게 서기를 구하나니", "kkjv": "너희에게 속한 사람으로 그리스도의 종인 에바브라가 너희에게 문안하느니라. 그가 너희를 위해 항상 기도로 뜨겁게 수고하나니 이것은 너희가 하나님의 모든 뜻 안에서 완전하고 완벽하게 서게 하려 함이라.", "web": "Epaphras, who is one of you, a servant of Christ, salutes you, always striving for you in his prayers, that you may stand perfect and complete in all the will of God."}}, {"id": 507, "coll": "무장 900구절", "sub": ["일꾼 배가", "중보 기도"], "book": "데살로니가전서", "chap": 3, "verse": "10", "ref": "데살로니가전서 3:10", "texts": {"krv": "주야로 심히 간구함은 너희 얼굴을 보고 너희 믿음의 부족함을 온전케 하려 함이라", "kkjv": "우리가 밤낮으로 넘치도록 기도함은 너희 얼굴을 보고 너희의 믿음에서 부족한 것을 완전하게 하려 함이라.", "web": "night and day praying exceedingly that we may see your face, and may perfect that which is lacking in your faith?"}}, {"id": 508, "coll": "무장 900구절", "sub": ["일꾼 배가", "중보 기도"], "book": "디모데후서", "chap": 1, "verse": "3", "ref": "디모데후서 1:3", "texts": {"krv": "나의 밤낮 간구하는 가운데 쉬지 않고 너를 생각하여 청결한 양심으로 조상 적부터 섬겨 오는 하나님께 감사하고", "kkjv": "내가 밤낮으로 기도하는 가운데 끊임없이 너를 기억하므로 내 선조들 때부터 내가 순수한 양심으로 섬기는 하나님께 감사를 드리고", "web": "I thank God, whom I serve as my forefathers did, with a pure conscience. How unceasing is my memory of you in my petitions, night and day"}}, {"id": 509, "coll": "무장 900구절", "sub": ["일꾼 배가", "중보 기도"], "book": "요한삼서", "chap": 1, "verse": "2", "ref": "요한삼서 1:2", "texts": {"krv": "사랑하는 자여 네 영혼이 잘 됨같이 네가 범사에 잘 되고 강건하기를 내가 간구하노라", "kkjv": "사랑하는 자여, 무엇보다도 네 혼이 형통하는 것같이 네가 형통하고 건강하기를 내가 바라노라.", "web": "Beloved, I pray that you may prosper in all things and be healthy, even as your soul prospers."}}, {"id": 510, "coll": "무장 900구절", "sub": ["일꾼 배가", "열매 맺는 삶"], "book": "잠언", "chap": 11, "verse": "30", "ref": "잠언 11:30", "texts": {"krv": "의인의 열매는 생명나무라 지혜로운 자는 사람을 얻느니라", "kkjv": "의로운 자의 열매는 생명나무니 혼들을 얻는 자는 지혜로우니라.", "web": "The fruit of the righteous is a tree of life. He who is wise wins souls."}}, {"id": 511, "coll": "무장 900구절", "sub": ["일꾼 배가", "열매 맺는 삶"], "book": "예레미야", "chap": 17, "verse": "7-8", "ref": "예레미야 17:7-8", "texts": {"krv": "그러나 무릇 여호와를 의지하며 여호와를 의뢰하는 그 사람은 복을 받을 것이라 그는 물가에 심기운 나무가 그 뿌리를 강변에 뻗치고 더위가 올지라도 두려워 아니하며 그 잎이 청청하며 가무는 해에도 걱정이 없고 결실이 그치지 아니함 같으리라", "kkjv": "주를 신뢰하며 주를 소망으로 삼는 사람은 복이 있나니 그는 물가에 심은 나무 곧 뿌리를 강가로 뻗은 나무 같아서 더위가 오는 때를 보지 아니하며 잎이 푸르고 가무는 해에도 걱정이 없으며 열매 맺는 일을 그치지 아니하리라.", "web": "Blessed is the man who trusts in Yahweh, and whose trust Yahweh is. For he shall be as a tree planted by the waters, who spreads out its roots by the river, and shall not fear when heat comes, but its leaf shall be green; and shall not be careful in the year of drought, neither shall cease from yielding fruit."}}, {"id": 512, "coll": "무장 900구절", "sub": ["일꾼 배가", "열매 맺는 삶"], "book": "마태복음", "chap": 7, "verse": "17-18", "ref": "마태복음 7:17-18", "texts": {"krv": "이와 같이 좋은 나무마다 아름다운 열매를 맺고 못된 나무가 나쁜 열매를 맺나니 좋은 나무가 나쁜 열매를 맺을 수 없고 못된 나무가 아름다운 열매를 맺을 수 없느니라", "kkjv": "이와 같이 좋은 나무마다 좋은 열매를 맺고 변질된 나무는 나쁜 열매를 맺나니 좋은 나무가 나쁜 열매를 맺지 못하고 또 변질된 나무가 좋은 열매를 맺지 못하느니라.", "web": "Even so, every good tree produces good fruit; but the corrupt tree produces evil fruit. A good tree can’t produce evil fruit, neither can a corrupt tree produce good fruit."}}, {"id": 513, "coll": "무장 900구절", "sub": ["일꾼 배가", "열매 맺는 삶"], "book": "요한복음", "chap": 15, "verse": "1-2", "ref": "요한복음 15:1-2", "texts": {"krv": "내가 참 포도나무요 내 아버지는 그 농부라 무릇 내게 있어 과실을 맺지 아니하는 가지는 아버지께서 이를 제해 버리시고 무릇 과실을 맺는 가지는 더 과실을 맺게 하려 하여 이를 깨끗케 하시느니라", "kkjv": "나는 참 포도나무요 내 아버지는 농부시니 내 안에서 열매를 맺지 아니하는 모든 가지는 그분께서 제거하시고 열매를 맺는 모든 가지는 깨끗하게 하사 그것이 더 많은 열매를 맺게 하시느니라.", "web": "“I am the true vine, and my Father is the farmer. Every branch in me that doesn’t bear fruit, he takes away. Every branch that bears fruit, he prunes, that it may bear more fruit."}}, {"id": 514, "coll": "무장 900구절", "sub": ["일꾼 배가", "열매 맺는 삶"], "book": "요한복음", "chap": 15, "verse": "16", "ref": "요한복음 15:16", "texts": {"krv": "너희가 나를 택한 것이 아니요 내가 너희를 택하여 세웠나니 이는 너희로 가서 과실을 맺게 하고 또 너희 과실이 항상 있게 하여 내 이름으로 아버지께 무엇을 구하든지 다 받게 하려 함이니라", "kkjv": "너희가 나를 택하지 아니하고 내가 너희를 택하여 세웠나니 이것은 너희가 가서 열매를 맺게 하고 또 너희 열매가 남아 있게 하려 함이요, 또 너희가 내 이름으로 아버지께 무엇을 구하든지 그분께서 그것을 너희에게 주게 하려 함이라.", "web": "You didn’t choose me, but I chose you, and appointed you, that you should go and bear fruit, and that your fruit should remain; that whatever you will ask of the Father in my name, he may give it to you."}}, {"id": 515, "coll": "무장 900구절", "sub": ["일꾼 배가", "열매 맺는 삶"], "book": "데살로니가전서", "chap": 3, "verse": "5", "ref": "데살로니가전서 3:5", "texts": {"krv": "이러므로 나도 참다 못하여 너희 믿음을 알기 위하여 보내었노니 이는 혹 시험하는 자가 너희를 시험하여 우리 수고를 헛되게 할까 함일러니", "kkjv": "이런 까닭에 내가 더 이상 참지 못하여 너희의 믿음을 알아보려고 사람을 보내었노니 이것은 그 시험하는 자가 어떤 식으로든 너희를 시험하여 우리의 수고를 헛되게 하지 못하게 하려 함이었노라.", "web": "For this cause I also, when I couldn’t stand it any longer, sent that I might know your faith, for fear that by any means the tempter had tempted you, and our labor would have been in vain."}}, {"id": 516, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "개인 계발"], "book": "시편", "chap": 12, "verse": "1", "ref": "시편 12:1", "texts": {"krv": "여호와여 도우소서 경건한 자가 끊어지며 충실한 자가 인생 중에 없어지도소이다", "kkjv": "주여, 도우소서. 하나님을 따르는 사람이 끊어지고 신실한 자들이 사람들의 자녀들 가운데서 없어지나이다.", "web": "Help, Yahweh; for the godly man ceases. For the faithful fail from among the children of men."}}, {"id": 517, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "개인 계발"], "book": "갈라디아서", "chap": 5, "verse": "22-23", "ref": "갈라디아서 5:22-23", "texts": {"krv": "오직 성령의 열매는 사랑과 희락과 화평과 오래 참음과 자비와 양선과 충성과 온유와 절제니 이 같은 것을 금지할 법이 없느니라", "kkjv": "그러나 성령의 열매는 사랑과 기쁨과 화평과 오래 참음과 부드러움과 선함과 믿음과 온유와 절제니 이 같은 것을 대적할 법이 없느니라.", "web": "But the fruit of the Spirit is love, joy, peace, patience, kindness, goodness, faith, gentleness, and self-control. Against such things there is no law."}}, {"id": 518, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "개인 계발"], "book": "에베소서", "chap": 4, "verse": "22-24", "ref": "에베소서 4:22-24", "texts": {"krv": "너희는 유혹의 욕심을 따라 썩어져 가는 구습을 좇는 옛 사람을 벗어 버리고 오직 심령으로 새롭게 되어 하나님을 따라 의와 진리의 거룩함으로 지으심을 받은 새 사람을 입으라", "kkjv": "이전 행실에 관하여는 너희가 속이는 것으로 가득한 욕심들에 따라 부패한 옛 사람을 벗어 버릴 것을 가르침을 받았으니 너희의 생각의 영 속에서 새롭게 되라. 또 너희가 하나님을 따라 의와 참된 거룩함으로 창조된 새 사람을 입을 것을 가르침을 받았으니", "web": "that you put away, as concerning your former way of life, the old man, that grows corrupt after the lusts of deceit; and that you be renewed in the spirit of your mind, and put on the new man, who in the likeness of God has been created in righteousness and holiness of truth."}}, {"id": 519, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "개인 계발"], "book": "에베소서", "chap": 5, "verse": "1", "ref": "에베소서 5:1", "texts": {"krv": "그러므로 사랑을 입은 자녀 같이 너희는 하나님을 본받는 자가 되고", "kkjv": "그러므로 너희는 사랑스러운 자녀로서 하나님을 따르는 자가 되고", "web": "Be therefore imitators of God, as beloved children."}}, {"id": 520, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "개인 계발"], "book": "디모데전서", "chap": 4, "verse": "12", "ref": "디모데전서 4:12", "texts": {"krv": "누구든지 네 연소함을 업신여기지 못하게 하고 오직 말과 행실과 사랑과 믿음과 정절에 대하여 믿는 자에게 본이 되어", "kkjv": "아무도 네 연소함을 업신여기지 못하게 하고 오직 너는 말과 행실과 사랑과 영과 믿음과 순결에서 믿는 자들의 본이 되라.", "web": "Let no man despise your youth; but be an example to those who believe, in word, in your way of life, in love, in spirit, in faith, and in purity."}}, {"id": 521, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "개인 계발"], "book": "디모데전서", "chap": 4, "verse": "15", "ref": "디모데전서 4:15", "texts": {"krv": "이 모든 일에 전심전력하여 너의 진보를 모든 사람에게 나타나게 하라", "kkjv": "이것들을 묵상하고 전적으로 그것들에 몰두하여 네가 유익을 얻은 것이 모든 사람에게 나타나게 하라.", "web": "Be diligent in these things. Give yourself wholly to them, that your progress may be revealed to all."}}, {"id": 522, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "겸손"], "book": "사무엘상", "chap": 15, "verse": "17", "ref": "사무엘상 15:17", "texts": {"krv": "사무엘이 가로되 왕이 스스로 작게 여길 그 때에 이스라엘 지파의 머리가 되지 아니하셨나이까 여호와께서 왕에게 기름을 부어 이스라엘 왕을 삼으시고", "kkjv": "사무엘이 이르되, 왕이 스스로 보기에 작았을 때에 이스라엘 지파들의 머리가 되셨고 주께서 왕에게 기름을 부어 이스라엘을 다스릴 왕으로 삼지 아니하셨나이까?", "web": "Samuel said, “Though you were little in your own sight, weren’t you made the head of the tribes of Israel? Yahweh anointed you king over Israel;"}}, {"id": 523, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "겸손"], "book": "욥기", "chap": 22, "verse": "29", "ref": "욥기 22:29", "texts": {"krv": "네가 낮춤을 받거든 높아지리라고 말하라 하나님은 겸손한 자를 구원하시느니라", "kkjv": "사람들이 쓰러지거든 그때에 너는 이르기를, 그분께서 높여 주시리라, 하라. 그리하면 그분께서 겸손한 자를 구원하시리라.", "web": "When they cast down, you shall say, ‘be lifted up.’ He will save the humble person."}}, {"id": 524, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "겸손"], "book": "잠언", "chap": 18, "verse": "12", "ref": "잠언 18:12", "texts": {"krv": "사람의 마음의 교만은 멸망의 선봉이요 겸손은 존귀의 앞잡이니라", "kkjv": "멸망에 앞서 사람의 마음의 거만이 있고 명예에 앞서 겸손이 있느니라.", "web": "Before destruction the heart of man is proud, but before honor is humility."}}, {"id": 525, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "겸손"], "book": "이사야", "chap": 57, "verse": "15", "ref": "이사야 57:15", "texts": {"krv": "지존 무상하며 영원히 거하며 거룩하다 이름하는 자가 이같이 말씀하시되 내가 높고 거룩한 곳에 거하며 또한 통회하고 마음이 겸손한 자와 함께 거하나니 이는 겸손한 자의 영을 소성케 하며 통회하는 자의 마음을 소성케 하려 함이라", "kkjv": "높고 높으며 영원에 거주하고 이름이 거룩함인 이가 이같이 말하노라. 나는 높고 거룩한 곳에 거하며 또한 통회하고 겸손한 영을 지닌 자와 함께 거하나니 이것은 겸손한 자의 영을 소생시키며 통회하는 자들의 마음을 소생시키려 함이라.", "web": "For thus says the high and lofty One who inhabits eternity, whose name is Holy: “I dwell in the high and holy place, with him also who is of a contrite and humble spirit, to revive the spirit of the humble, and to revive the heart of the contrite."}}, {"id": 526, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "겸손"], "book": "마태복음", "chap": 18, "verse": "4", "ref": "마태복음 18:4", "texts": {"krv": "그러므로 누구든지 이 어린아이와 같이 자기를 낮추는 그이가 천국에서 큰 자니라", "kkjv": "그러므로 누구든지 이 어린아이처럼 자기를 낮추는 자 곧 그가 하늘의 왕국에서 가장 큰 자니라.", "web": "Whoever therefore humbles himself as this little child, the same is the greatest in the Kingdom of Heaven."}}, {"id": 527, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "겸손"], "book": "마태복음", "chap": 23, "verse": "12", "ref": "마태복음 23:12", "texts": {"krv": "누구든지 자기를 높이는 자는 낮아지고 누구든지 자기를 낮추는 자는 높아지리라", "kkjv": "누구든지 자기를 높이는 자는 낮아지고 자기를 낮추는 자는 높아지리라.", "web": "Whoever exalts himself will be humbled, and whoever humbles himself will be exalted."}}, {"id": 528, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "겸손"], "book": "누가복음", "chap": 14, "verse": "10", "ref": "누가복음 14:10", "texts": {"krv": "청함을 받았을 때에 차라리 가서 말석에 앉으라 그러면 너를 청한 자가 와서 너더러 벗이여 올라 앉으라 하리니 그 때에야 함께 앉은 모든 사람 앞에 영광이 있으리라", "kkjv": "오직 네가 초대를 받거든 가서 가장 낮은 자리에 앉으라. 그러면 너를 초대한 자가 와서 네게 이르기를, 친구여, 더 높은 데로 올라가라, 하리니 그때에 네가 너와 함께 음식 앞에 앉은 자들 앞에서 영예를 얻으리라.", "web": "But when you are invited, go and sit in the lowest place, so that when he who invited you comes, he may tell you, ‘Friend, move up higher.’ Then you will be honored in the presence of all who sit at the table with you."}}, {"id": 529, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "겸손"], "book": "요한복음", "chap": 3, "verse": "30", "ref": "요한복음 3:30", "texts": {"krv": "그는 흥하여야 하겠고 나는 쇠하여야 하리라 하니라", "kkjv": "그분은 반드시 흥하여야 하되 나는 반드시 쇠하여야 하리라, 하니라.", "web": "He must increase, but I must decrease."}}, {"id": 530, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "겸손"], "book": "로마서", "chap": 12, "verse": "16", "ref": "로마서 12:16", "texts": {"krv": "서로 마음을 같이 하며 높은 데 마음을 두지 말고 도리어 낮은 데 처하며 스스로 지혜 있는 체 말라", "kkjv": "서로를 향해 같은 생각을 가지며 높은 것들에 생각을 두지 말고 도리어 낮은 처지의 사람들에게 겸손히 행하며 스스로 지혜 있는 것으로 여기지 말라.", "web": "Be of the same mind one toward another. Don’t set your mind on high things, but associate with the humble. Don’t be wise in your own conceits."}}, {"id": 531, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "겸손"], "book": "고린도전서", "chap": 15, "verse": "10", "ref": "고린도전서 15:10", "texts": {"krv": "그러나 나의 나 된 것은 하나님의 은혜로 된 것이니 내게 주신 그의 은혜가 헛되지 아니하여 내가 모든 사도보다 더 많이 수고하였으나 내가 아니요 오직 나와 함께 하신 하나님의 은혜로라", "kkjv": "하나님의 은혜로 내가 지금의 내가 되었으니 내게 베푸신 그분의 은혜가 헛되지 아니하여 내가 그들 모두보다 더 많이 수고하였으나 내가 아니요, 오직 나와 함께하신 하나님의 은혜로다.", "web": "But by the grace of God I am what I am. His grace which was bestowed on me was not futile, but I worked more than all of them; yet not I, but the grace of God which was with me."}}, {"id": 532, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "겸손"], "book": "빌립보서", "chap": 2, "verse": "5-8", "ref": "빌립보서 2:5-8", "texts": {"krv": "너희 안에 이 마음을 품으라 곧 그리스도 예수의 마음이니 그는 근본 하나님의 본체시나 하나님과 동등됨을 취할 것으로 여기지 아니하시고 오히려 자기를 비어 종의 형체를 가져 사람들과 같이 되었고 사람의 모양으로 나타나셨으매 자기를 낮추시고 죽기까지 복종하셨으니 곧 십자가에 죽으심이라", "kkjv": "너희 안에 이 생각을 품을지니 그것은 그리스도 예수님 안에도 있던 생각이라. 그분은 하나님의 형체로 계시므로 하나님과 동등함을 강탈로 여기지 아니하셨으나 스스로 무명한 자가 되사 자기 위에 종의 형체를 취하시고 사람들의 모습이 되셨으며 사람의 모양으로 나타나사 자기를 낮추시고 죽기까지 순종하셨으니 곧 십자가의 죽음이라.", "web": "Have this in your mind, which was also in Christ Jesus, who, existing in the form of God, didn’t consider equality with God a thing to be grasped, but emptied himself, taking the form of a servant, being made in the likeness of men. And being found in human form, he humbled himself, becoming obedient to death, yes, the death of the cross."}}, {"id": 533, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "겸손"], "book": "야고보서", "chap": 4, "verse": "10", "ref": "야고보서 4:10", "texts": {"krv": "주 앞에서 낮추라 그리하면 주께서 너희를 높이시리라", "kkjv": "주의 눈앞에서 스스로 겸손하라. 그리하면 그분께서 너희를 높이시리라.", "web": "Humble yourselves in the sight of the Lord, and he will exalt you."}}, {"id": 534, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "믿음"], "book": "마태복음", "chap": 8, "verse": "8", "ref": "마태복음 8:8", "texts": {"krv": "백부장이 대답하여 가로되 주여 내 집에 들어오심을 나는 감당치 못하겠사오니 다만 말씀으로만 하옵소서 그러면 내 하인이 낫겠삽나이다", "kkjv": "백부장이 응답하여 이르되, 주여, 주께서 내 지붕 아래로 오심을 내가 감당할 자격이 없사온즉 오직 말씀만 하옵소서. 그러면 내 종이 낫겠나이다.", "web": "The centurion answered, “Lord, I’m not worthy for you to come under my roof. Just say the word, and my servant will be healed."}}, {"id": 535, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "믿음"], "book": "마태복음", "chap": 9, "verse": "29", "ref": "마태복음 9:29", "texts": {"krv": "이에 예수께서 저희 눈을 만지시며 가라사대 너희 믿음대로 되라 하신대", "kkjv": "이에 그분께서 그들의 눈에 손을 대시며 이르시되, 너희 믿음대로 그 일이 너희에게 이루어질지어다, 하시니", "web": "Then he touched their eyes, saying, “According to your faith be it done to you.”"}}, {"id": 536, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "믿음"], "book": "마가복음", "chap": 9, "verse": "23", "ref": "마가복음 9:23", "texts": {"krv": "예수께서 이르시되 할 수 있거든이 무슨 말이냐 믿는 자에게는 능치 못할 일이 없느니라 하시니", "kkjv": "예수님께서 그에게 이르시되, 네가 만일 믿을 수 있거든 믿는 자에게는 모든 것이 가능하니라, 하시니", "web": "Jesus said to him, “If you can believe, all things are possible to him who believes.”"}}, {"id": 537, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "믿음"], "book": "마가복음", "chap": 11, "verse": "23", "ref": "마가복음 11:23", "texts": {"krv": "내가 진실로 너희에게 이르노니 누구든지 이 산더러 들리어 바다에 던지우라 하며 그 말하는 것이 이룰 줄 믿고 마음에 의심치 아니하면 그대로 되리라", "kkjv": "진실로 내가 너희에게 이르노니, 누구든지 이 산에게 이르기를, 옮겨져서 바다에 빠지라, 하며 마음속으로 의심하지 아니하고 자기가 말하는 그것들이 이루어질 줄 믿으면 그가 무엇을 말하든지 다 받으리라.", "web": "For most certainly I tell you, whoever may tell this mountain, ‘Be taken up and cast into the sea,’ and doesn’t doubt in his heart, but believes that what he says is happening; he shall have whatever he says."}}, {"id": 538, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "믿음"], "book": "누가복음", "chap": 17, "verse": "6", "ref": "누가복음 17:6", "texts": {"krv": "주께서 가라사대 너희에게 겨자씨 한 알만한 믿음이 있었더면 이 뽕나무더러 뿌리가 뽑혀 바다에 심기우라 하였을 것이요 그것이 너희에게 순종하였으리라", "kkjv": "주께서 이르시되, 너희에게 만일 겨자씨 한 알만 한 믿음이 있었더라면 너희가 이 뽕나무에게 이르기를, 뿌리째 뽑혀 바다에 심겨라, 하였을 것이요, 그것이 너희에게 순종하였으리라.", "web": "The Lord said, “If you had faith like a grain of mustard seed, you would tell this sycamore tree, ‘Be uprooted, and be planted in the sea,’ and it would obey you."}}, {"id": 539, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "믿음"], "book": "요한복음", "chap": 11, "verse": "25-26", "ref": "요한복음 11:25-26", "texts": {"krv": "예수께서 가라사대 나는 부활이요 생명이니 나를 믿는 자는 죽어도 살겠고 무릇 살아서 나를 믿는 자는 영원히 죽지 아니하리니 이것을 네가 믿느냐", "kkjv": "예수님께서 그녀에게 이르시되, 나는 부활이요 생명이니 나를 믿는 자는 죽어도 살겠고 누구든지 살아서 나를 믿는 자는 결코 죽지 아니하리라. 이것을 네가 믿느냐? 하시니", "web": "Jesus said to her, “I am the resurrection and the life. He who believes in me will still live, even if he dies. Whoever lives and believes in me will never die. Do you believe this?”"}}, {"id": 540, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "믿음"], "book": "요한복음", "chap": 11, "verse": "40", "ref": "요한복음 11:40", "texts": {"krv": "예수께서 가라사대 내 말이 네가 믿으면 하나님의 영광을 보리라 하지 아니하였느냐 하신대", "kkjv": "예수님께서 그녀에게 이르시되, 내가 네게 말하기를, 네가 믿고자 하면 하나님의 영광을 보리라, 하지 아니하였느냐? 하시니라.", "web": "Jesus said to her, “Didn’t I tell you that if you believed, you would see God’s glory?”"}}, {"id": 541, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "믿음"], "book": "요한복음", "chap": 14, "verse": "12", "ref": "요한복음 14:12", "texts": {"krv": "내가 진실로 진실로 너희에게 이르노니 나를 믿는 자는 나의 하는 일을 저도 할 것이요 또한 이보다 큰 것도 하리니 이는 내가 아버지께로 감이니라", "kkjv": "진실로 진실로 내가 너희에게 이르노니, 나를 믿는 자는 또한 내가 하는 그 일들을 할 것이요, 또 이것들보다 더 큰일들도 하리니 이는 내가 내 아버지께로 가기 때문이라.", "web": "Most certainly I tell you, he who believes in me, the works that I do, he will do also; and he will do greater works than these, because I am going to my Father."}}, {"id": 542, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "믿음"], "book": "요한복음", "chap": 20, "verse": "29", "ref": "요한복음 20:29", "texts": {"krv": "예수께서 가라사대 너는 나를 본 고로 믿느냐 보지 못하고 믿는 자들은 복되도다 하시니라", "kkjv": "예수님께서 그에게 이르시되, 도마야, 너는 나를 보았으므로 믿었으나 보지 않고도 믿은 자들은 복이 있도다, 하시니라.", "web": "Jesus said to him, “Because you have seen me,you have believed. Blessed are those who have not seen, and have believed.”"}}, {"id": 543, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "믿음"], "book": "사도행전", "chap": 27, "verse": "25", "ref": "사도행전 27:25", "texts": {"krv": "그러므로 여러분이여 안심하라 나는 내게 말씀하신 그대로 되리라고 하나님을 믿노라", "kkjv": "그러므로 선생들아, 기운을 내라. 내가 하나님을 믿노니 내게 말씀하신 그대로 되리라.", "web": "Therefore, sirs, cheer up! For I believe God, that it will be just as it has been spoken to me."}}, {"id": 544, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "믿음"], "book": "디모데전서", "chap": 1, "verse": "19", "ref": "디모데전서 1:19", "texts": {"krv": "믿음과 착한 양심을 가지라 어떤 이들이 이 양심을 버렸고 그 믿음에 관하여는 파선하였느니라", "kkjv": "믿음과 선한 양심을 붙들라. 어떤 자들이 그것을 버리고 믿음에 관하여는 파선하였느니라.", "web": "holding faith and a good conscience; which some having thrust away made a shipwreck concerning the faith;"}}, {"id": 545, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "믿음"], "book": "히브리서", "chap": 11, "verse": "8", "ref": "히브리서 11:8", "texts": {"krv": "믿음으로 아브라함은 부르심을 받았을 때에 순종하여 장래 기업으로 받을 땅에 나갈새 갈 바를 알지 못하고 나갔으며", "kkjv": "믿음으로 아브라함은 부르심을 받아 훗날 상속 재산으로 받게 될 곳으로 나가면서 순종하였고 자기가 어디로 가는지 알지 못한 채 나갔으며", "web": "By faith, Abraham, when he was called, obeyed to go out to the place which he was to receive for an inheritance. He went out, not knowing where he went."}}, {"id": 546, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "사랑"], "book": "로마서", "chap": 12, "verse": "9", "ref": "로마서 12:9", "texts": {"krv": "사랑엔 거짓이 없나니 악을 미워하고 선에 속하라", "kkjv": "사랑에 꾸밈이 없게 하라. 악한 것을 몹시 싫어하고 선한 것을 굳게 붙들라.", "web": "Let love be without hypocrisy. Abhor that which is evil. Cling to that which is good."}}, {"id": 547, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "사랑"], "book": "로마서", "chap": 12, "verse": "10", "ref": "로마서 12:10", "texts": {"krv": "형제를 사랑하여 서로 우애하고 존경하기를 서로 먼저 하며", "kkjv": "형제의 사랑으로 서로 친절하게 애정을 가지고 서로 먼저 존중하며", "web": "In love of the brothers be tenderly affectionate one to another; in honor preferring one another;"}}, {"id": 548, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "사랑"], "book": "로마서", "chap": 13, "verse": "10", "ref": "로마서 13:10", "texts": {"krv": "사랑은 이웃에게 악을 행치 아니하나니 그러므로 사랑은 율법의 완성이니라", "kkjv": "사랑은 자기 이웃에게 해를 끼치지 아니하나니 그러므로 사랑은 율법의 완성이니라.", "web": "Love doesn’t harm a neighbor. Love therefore is the fulfillment of the law."}}, {"id": 549, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "사랑"], "book": "고린도전서", "chap": 8, "verse": "1", "ref": "고린도전서 8:1", "texts": {"krv": "우상의 제물에 대하여는 우리가 다 지식이 있는 줄을 아나 지식은 교만하게 하며 사랑은 덕을 세우나니", "kkjv": "이제 우상들에게 바친 것들에 관하여는 우리가 다 지식이 있는 줄로 아나니 지식은 우쭐대게 하나 사랑은 세워 주느니라.", "web": "Now concerning things sacrificed to idols: We know that we all have knowledge. Knowledge puffs up, but love builds up."}}, {"id": 550, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "사랑"], "book": "고린도전서", "chap": 13, "verse": "4-7", "ref": "고린도전서 13:4-7", "texts": {"krv": "사랑은 오래 참고 사랑은 온유하며 투기하는 자가 되지 아니하며 사랑은 자랑하지 아니하며 교만하지 아니하며 무례히 행치 아니하며 자기의 유익을 구치 아니하며 성내지 아니하며 악한 것을 생각지 아니하며 불의를 기뻐하지 아니하며 진리와 함께 기뻐하고 모든 것을 참으며 모든 것을 믿으며 모든 것을 바라며 모든 것을 견디느니라", "kkjv": "사랑은 오래 참고 친절하며 사랑은 시기하지 아니하며 사랑은 자기를 자랑하지 아니하며 우쭐대지 아니하며 무례히 행동하지 아니하며 자기 것을 추구하지 아니하며 쉽게 성내지 아니하며 악을 생각하지 아니하며 불법을 기뻐하지 아니하고 진리를 기뻐하며 모든 것을 참으며 모든 것을 믿으며 모든 것을 바라며 모든 것을 견디느니라.", "web": "Love is patient and is kind; love doesn’t envy. Love doesn’t brag, is not proud, doesn’t behave itself inappropriately, doesn’t seek its own way, is not provoked, takes no account of evil; doesn’t rejoice in unrighteousness, but rejoices with the truth; bears all things, believes all things, hopes all things, endures all things."}}, {"id": 551, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "사랑"], "book": "고린도전서", "chap": 16, "verse": "14", "ref": "고린도전서 16:14", "texts": {"krv": "너희 모든 일을 사랑으로 행하라", "kkjv": "너희의 모든 일을 사랑으로 할지니라.", "web": "Let all that you do be done in love."}}, {"id": 552, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "사랑"], "book": "갈라디아서", "chap": 6, "verse": "2", "ref": "갈라디아서 6:2", "texts": {"krv": "너희가 짐을 서로 지라 그리하여 그리스도의 법을 성취하라", "kkjv": "너희는 서로 남의 짐들을 지라. 그리하여 그리스도의 법을 성취하라.", "web": "Bear one another’s burdens, and so fulfill the law of Christ."}}, {"id": 553, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "사랑"], "book": "베드로전서", "chap": 4, "verse": "8", "ref": "베드로전서 4:8", "texts": {"krv": "무엇보다도 열심으로 서로 사랑할지니 사랑은 허다한 죄를 덮느니라", "kkjv": "무엇보다도 너희끼리 뜨거운 사랑을 품으라. 사랑은 허다한 죄를 덮으리라.", "web": "And above all things be earnest in your love among yourselves, for love covers a multitude of sins."}}, {"id": 554, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "사랑"], "book": "요한일서", "chap": 3, "verse": "16", "ref": "요한일서 3:16", "texts": {"krv": "그가 우리를 위하여 목숨을 버리셨으니 우리가 이로써 사랑을 알고 우리도 형제들을 위하여 목숨을 버리는 것이 마땅하니라", "kkjv": "하나님께서 우리를 위해 자신의 생명을 내놓으셨으므로 이로써 우리가 그분의 사랑을 깨닫나니 우리가 형제들을 위해 우리의 생명을 내놓는 것이 마땅하니라.", "web": "By this we know love, because he laid down his life for us. And we ought to lay down our lives for the brothers."}}, {"id": 555, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "사랑"], "book": "요한일서", "chap": 4, "verse": "7-8", "ref": "요한일서 4:7-8", "texts": {"krv": "사랑하는 자들아 우리가 서로 사랑하자 사랑은 하나님께 속한 것이니 사랑하는 자마다 하나님께로 나서 하나님을 알고 사랑하지 아니하는 자는 하나님을 알지 못하나니 이는 하나님은 사랑이심이라", "kkjv": "사랑하는 자들아, 우리가 서로 사랑하자. 사랑은 하나님께 속한 것인즉 사랑하는 자마다 하나님에게서 나서 하나님을 알고 사랑하지 아니하는 자는 하나님을 알지 못하나니 이는 하나님이 사랑이시기 때문이라.", "web": "Beloved, let us love one another, for love is of God; and everyone who loves has been born of God, and knows God. He who doesn’t love doesn’t know God, for God is love."}}, {"id": 556, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "사랑"], "book": "요한일서", "chap": 4, "verse": "18", "ref": "요한일서 4:18", "texts": {"krv": "사랑 안에 두려움이 없고 온전한 사랑이 두려움을 내어쫓나니 두려움에는 형벌이 있음이라 두려워하는 자는 사랑 안에서 온전히 이루지 못하였느니라", "kkjv": "사랑에는 결코 두려움이 없고 완전한 사랑은 두려움을 내쫓나니 이는 두려움에 고통이 있기 때문이라. 두려워하는 자는 사랑 안에서 완전하게 되지 못하였느니라.", "web": "There is no fear in love; but perfect love casts out fear, because fear has punishment. He who fears is not made perfect in love."}}, {"id": 557, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "사랑"], "book": "요한일서", "chap": 4, "verse": "20", "ref": "요한일서 4:20", "texts": {"krv": "누구든지 하나님을 사랑하노라 하고 그 형제를 미워하면 이는 거짓말하는 자니 보는 바 그 형제를 사랑치 아니하는 자가 보지 못하는 바 하나님을 사랑할 수가 없느니라", "kkjv": "어떤 사람이, 나는 하나님을 사랑하노라, 하고 자기 형제를 미워하면 그는 거짓말하는 자니 자기가 본 자기 형제를 사랑하지 아니하는 자가 어찌 자기가 보지 못한 하나님을 사랑할 수 있으리요?", "web": "If a man says, “I love God,” and hates his brother, he is a liar; for he who doesn’t love his brother whom he has seen, how can he love God whom he has not seen?"}}, {"id": 558, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "소망"], "book": "시편", "chap": 84, "verse": "10", "ref": "시편 84:10", "texts": {"krv": "주의 궁정에서 한 날이 다른 곳에서 천 날보다 나은즉 악인의 장막에 거함보다 내 하나님 문지기로 있는 것이 좋사오니", "kkjv": "주의 뜰에서의 한 날이 천 날보다 나으니이다. 내가 사악함의 장막들에 거하는 것보다 차라리 내 하나님의 집 문지기가 되겠사오니", "web": "For a day in your courts is better than a thousand. I would rather be a doorkeeper in the house of my God, than to dwell in the tents of wickedness."}}, {"id": 559, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "소망"], "book": "시편", "chap": 119, "verse": "49", "ref": "시편 119:49", "texts": {"krv": "주의 종에게 하신 말씀을 기억하소서 주께서 나로 소망이 있게 하셨나이다", "kkjv": "주의 종에게 하신 말씀을 기억하소서. 주께서 나로 하여금 그 위에 소망을 두게 하셨나이다.", "web": "Remember your word to your servant, because you gave me hope."}}, {"id": 560, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "소망"], "book": "잠언", "chap": 14, "verse": "32", "ref": "잠언 14:32", "texts": {"krv": "악인은 그 환난에 엎드러져도 의인은 그 죽음에도 소망이 있느니라", "kkjv": "사악한 자는 자기의 사악함 가운데서 쫓겨나거니와 의로운 자는 자기의 죽음 가운데서도 소망을 갖느니라.", "web": "The wicked is brought down in his calamity, but in death, the righteous has a refuge."}}, {"id": 561, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "소망"], "book": "요한복음", "chap": 14, "verse": "1-2", "ref": "요한복음 14:1-2", "texts": {"krv": "너희는 마음에 근심하지 말라 하나님을 믿으니 또 나를 믿으라 내 아버지 집에 거할 곳이 많도다 그렇지 않으면 너희에게 일렀으리라 내가 너희를 위하여 처소를 예비하러 가노니", "kkjv": "너희는 마음에 근심하지 말라. 하나님을 믿고 또한 나를 믿으라. 내 아버지 집에 거할 곳이 많도다. 그렇지 않으면 내가 너희에게 말해 주었으리라. 내가 너희를 위해 처소를 예비하러 가노니", "web": "“Don’t let your heart be troubled. Believe in God. Believe also in me. In my Father’s house are many homes. If it weren’t so, I would have told you. I am going to prepare a place for you."}}, {"id": 562, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "소망"], "book": "로마서", "chap": 13, "verse": "12", "ref": "로마서 13:12", "texts": {"krv": "밤이 깊고 낮이 가까왔으니 그러므로 우리가 어두움의 일을 벗고 빛의 갑옷을 입자", "kkjv": "밤이 많이 지나고 낮이 가까이 왔으니 그러므로 우리가 어둠의 행위를 벗어 버리고 빛의 갑옷을 입자.", "web": "The night is far gone, and the day is near. Let’s therefore throw off the works of darkness, and let’s put on the armor of light."}}, {"id": 563, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "소망"], "book": "빌립보서", "chap": 3, "verse": "21", "ref": "빌립보서 3:21", "texts": {"krv": "그가 만물을 자기에게 복종케 하실 수 있는 자의 역사로 우리의 낮은 몸을 자기 영광의 몸의 형체와 같이 변케 하시리라", "kkjv": "그분께서는 모든 것을 자기에게 복종시킬 때 사용하는 능력을 발휘하사 우리의 천한 몸을 변화시켜 자신의 영광스러운 몸과 같게 만드시리라.", "web": "who will change the body of our humiliation to be conformed to the body of his glory, according to the working by which he is able even to subject all things to himself."}}, {"id": 564, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "소망"], "book": "골로새서", "chap": 3, "verse": "2-3", "ref": "골로새서 3:2-3", "texts": {"krv": "위엣 것을 생각하고 땅엣 것을 생각지 말라 이는 너희가 죽었고 너희 생명이 그리스도와 함께 하나님 안에 감취었음이니라", "kkjv": "위에 있는 것들에 너희의 애착을 두고 땅에 있는 것들에 두지 말라. 너희는 죽었고 너희 생명은 그리스도와 함께 하나님 안에 감추어져 있느니라.", "web": "Set your mind on the things that are above, not on the things that are on the earth. For you died, and your life is hidden with Christ in God."}}, {"id": 565, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "소망"], "book": "베드로전서", "chap": 1, "verse": "13", "ref": "베드로전서 1:13", "texts": {"krv": "그러므로 너희 마음의 허리를 동이고 근신하여 예수 그리스도의 나타나실 때에 너희에게 가져올 은혜를 온전히 바랄지어다", "kkjv": "그러므로 너희 마음의 허리를 동이고 정신을 차려 예수 그리스도께서 나타나실 때에 너희에게 가져오실 그 은혜로 인해 끝까지 소망을 가질지어다.", "web": "Therefore prepare your minds for action, be sober and set your hope fully on the grace that will be brought to you at the revelation of Jesus Christ—"}}, {"id": 566, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "소망"], "book": "베드로전서", "chap": 4, "verse": "7", "ref": "베드로전서 4:7", "texts": {"krv": "만물의 마지막이 가까왔으니 그러므로 너희는 정신을 차리고 근신하여 기도하라", "kkjv": "오직 모든 것의 끝이 가까이 왔으니 그러므로 너희는 정신을 차리고 깨어 기도하라.", "web": "But the end of all things is near. Therefore be of sound mind, self-controlled, and sober in prayer."}}, {"id": 567, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "소망"], "book": "베드로후서", "chap": 3, "verse": "11-13", "ref": "베드로후서 3:11-13", "texts": {"krv": "이 모든 것이 이렇게 풀어지리니 너희가 어떠한 사람이 되어야 마땅하뇨 거룩한 행실과 경건함으로 하나님의 날이 임하기를 바라보고 간절히 사모하라 그 날에 하늘이 불에 타서 풀어지고 체질이 뜨거운 불에 녹아지려니와 우리는 그의 약속대로 의의 거하는 바 새 하늘과 새 땅을 바라보도다", "kkjv": "그런즉 이 모든 것이 해체될진대 너희가 어떤 사람이 되어야 마땅하겠느냐? 모든 거룩한 행실 속에서 하나님을 따르는 가운데 하나님의 날이 오는 것을 기다리고 서두르라. 그 날에 하늘들이 불이 붙어 해체되고 원소들도 뜨거운 열로 녹으려니와 그럼에도 불구하고 우리는 그분의 약속에 따라 의가 거하는 새 하늘들과 새 땅을 기다리는도다.", "web": "Therefore since all these things will be destroyed like this, what kind of people ought you to be in holy living and godliness, looking for and earnestly desiring the coming of the day of God, which will cause the burning heavens to be dissolved, and the elements will melt with fervent heat? But, according to his promise, we look for new heavens and a new earth, in which righteousness dwells."}}, {"id": 568, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "소망"], "book": "요한계시록", "chap": 21, "verse": "4", "ref": "요한계시록 21:4", "texts": {"krv": "모든 눈물을 그 눈에서 씻기시매 다시 사망이 없고 애통하는 것이나 곡하는 것이나 아픈 것이 다시 있지 아니하리니 처음 것들이 다 지나갔음이러라", "kkjv": "또 하나님께서 그들의 눈에서 모든 눈물을 씻어 주시리라. 다시는 사망이 없고 슬픔도 울부짖음도 없으며 또 아픔도 다시는 없으리니 이는 이전 것들이 지나갔기 때문이라, 하더라.", "web": "He will wipe away from them every tear from their eyes. Death will be no more; neither will there be mourning, nor crying, nor pain, any more. The first things have passed away.”"}}, {"id": 569, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "소망"], "book": "요한계시록", "chap": 22, "verse": "20", "ref": "요한계시록 22:20", "texts": {"krv": "이것들을 증거하신 이가 가라사대 내가 진실로 속히 오리라 하시거늘 아멘 주 예수여 오시옵소서", "kkjv": "이것들을 증언하시는 분께서 이르시되, 내가 반드시 속히 오리라, 하시는도다. 아멘. 주 예수님이여, 과연 그와 같이 오시옵소서.", "web": "He who testifies these things says, “Yes, I come quickly.”    Amen! Yes, come, Lord Jesus."}}, {"id": 570, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순종"], "book": "신명기", "chap": 17, "verse": "19", "ref": "신명기 17:19", "texts": {"krv": "평생에 자기 옆에 두고 읽어서 그 하나님 여호와 경외하기를 배우며 이 율법의 모든 말과 이 규례를 지켜 행할 것이라", "kkjv": "평생토록 자기 곁에 두고 그 안의 것을 읽어서 주 자기 하나님 두려워하기를 배우며 이 율법의 모든 말과 이 법규를 지키고 행할 것이니라.", "web": "It shall be with him, and he shall read from it all the days of his life; that he may learn to fear Yahweh his God, to keep all the words of this law and these statutes, to do them;"}}, {"id": 571, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순종"], "book": "신명기", "chap": 26, "verse": "16", "ref": "신명기 26:16", "texts": {"krv": "오늘날 네 하나님 여호와께서 이 규례와 법도를 행하라고 네게 명하시나니 그런즉 너는 마음을 다하고 성품을 다하여 지켜 행하라", "kkjv": "¶이 날 주 네 하나님께서 네게 명령하사 이 법규와 판단의 법도를 행하게 하셨나니 그런즉 너는 네 마음을 다하고 혼을 다하여 그것들을 지키고 행하라.", "web": "This day Yahweh your God commands you to do these statutes and ordinances. You shall therefore keep and do them with all your heart and with all your soul."}}, {"id": 572, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순종"], "book": "사무엘상", "chap": 15, "verse": "22", "ref": "사무엘상 15:22", "texts": {"krv": "사무엘이 가로되 여호와께서 번제와 다른 제사를 그 목소리 순종하는 것을 좋아하심 같이 좋아하시겠나이까 순종이 제사보다 낫고 듣는 것이 수양의 기름보다 나으니", "kkjv": "사무엘이 이르되, 주께서 주의 음성에 순종하는 것만큼 번제 헌물과 희생물을 크게 기뻐하시나이까? 보소서, 순종이 희생 헌물보다 낫고 귀를 기울이는 것이 숫양의 기름보다 나으니", "web": "Samuel said, “Has Yahweh as great delight in burnt offerings and sacrifices, as in obeying the voice of Yahweh? Behold, to obey is better than sacrifice, and to listen than the fat of rams."}}, {"id": 573, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순종"], "book": "시편", "chap": 119, "verse": "56", "ref": "시편 119:56", "texts": {"krv": "내 소유는 이것이니 곧 주의 법도를 지킨 것이니이다", "kkjv": "내가 주의 훈계들을 지켰으므로 이것을 소유하였나이다.", "web": "This is my way, that I keep your precepts."}}, {"id": 574, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순종"], "book": "마태복음", "chap": 7, "verse": "24", "ref": "마태복음 7:24", "texts": {"krv": "그러므로 누구든지 나의 이 말을 듣고 행하는 자는 그 집을 반석 위에 지은 지혜로운 사람 같으리니", "kkjv": "¶그러므로 누구든지 나의 이 말들을 듣고 그것들을 행하는 자를 나는 자기 집을 반석 위에 지은 지혜로운 사람과 같다 하리라.", "web": "“Everyone therefore who hears these words of mine, and does them, I will liken him to a wise man, who built his house on a rock."}}, {"id": 575, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순종"], "book": "누가복음", "chap": 5, "verse": "5", "ref": "누가복음 5:5", "texts": {"krv": "시몬이 대답하여 가로되 선생이여 우리들이 밤이 맟도록 수고를 하였으되 얻은 것이 없지마는 말씀에 의지하여 내가 그물을 내리리이다 하고", "kkjv": "시몬이 응답하여 그분께 이르되, 선생님이여, 우리가 밤새도록 수고하였어도 아무것도 잡지 못하였으나 그럼에도 불구하고 선생님의 말씀에 따라 내가 그물을 내리리이다, 하고", "web": "Simon answered him, “Master, we worked all night, and took nothing; but at your word I will let down the net.”"}}, {"id": 576, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순종"], "book": "누가복음", "chap": 11, "verse": "28", "ref": "누가복음 11:28", "texts": {"krv": "예수께서 가라사대 오히려 하나님의 말씀을 듣고 지키는 자가 복이 있느니라 하시니라", "kkjv": "그분께서 이르시되, 그러하다. 그러나 하나님의 말씀을 듣고 그것을 지키는 자들이 복이 있느니라, 하시니라.", "web": "But he said, “On the contrary, blessed are those who hear the word of God, and keep it.”"}}, {"id": 577, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순종"], "book": "로마서", "chap": 5, "verse": "19", "ref": "로마서 5:19", "texts": {"krv": "한 사람의 순종치 아니함으로 많은 사람이 죄인 된것 같이 한 사람의 순종하심으로 많은 사람이 의인이 되리라", "kkjv": "한 사람의 불순종으로 말미암아 많은 사람이 죄인이 된 것 같이 한 사람의 순종으로 말미암아 많은 사람이 의로운 자가 되리라.", "web": "For as through the one man’s disobedience many were made sinners, even so through the obedience of the one, many will be made righteous."}}, {"id": 578, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순종"], "book": "히브리서", "chap": 5, "verse": "8-9", "ref": "히브리서 5:8-9", "texts": {"krv": "그가 아들이시라도 받으신 고난으로 순종함을 배워서 온전하게 되었은즉 자기를 순종하는 모든 자에게 영원한 구원의 근원이 되시고", "kkjv": "그분께서 아들이실지라도 친히 고난 받으신 일들로 말미암아 순종하기를 배우사 완전하게 되셨으므로 자기에게 순종하는 모든 사람들에게 영원한 구원의 창시자가 되시고", "web": "though he was a Son, yet learned obedience by the things which he suffered. Having been made perfect, he became to all of those who obey him the author of eternal salvation,"}}, {"id": 579, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순종"], "book": "야고보서", "chap": 1, "verse": "22", "ref": "야고보서 1:22", "texts": {"krv": "너희는 도를 행하는 자가 되고 듣기만 하여 자신을 속이는 자가 되지 말라", "kkjv": "오직 너희는 말씀을 행하는 자가 되고 듣기만 하여 너희 자신을 속이는 자가 되지 말라.", "web": "But be doers of the word, and not only hearers, deluding your own selves."}}, {"id": 580, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순종"], "book": "야고보서", "chap": 1, "verse": "25", "ref": "야고보서 1:25", "texts": {"krv": "자유하게 하는 온전한 율법을 들여다보고 있는 자는 듣고 잊어버리는 자가 아니요 실행하는 자니 이 사람이 그 행하는 일에 복을 받으리라", "kkjv": "누구든지 자유롭게 하는 완전한 법을 들여다보며 그 안에 거하는 자는 듣고 잊어버리는 자가 아니요, 그 일을 행하는 자니 이 사람은 자기가 행하는 일에서 복을 받으리라.", "web": "But he who looks into the perfect law of freedom, and continues, not being a hearer who forgets, but a doer of the work, this man will be blessed in what he does."}}, {"id": 581, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순종"], "book": "야고보서", "chap": 2, "verse": "22", "ref": "야고보서 2:22", "texts": {"krv": "네가 보거니와 믿음이 그의 행함과 함께 일하고 행함으로 믿음이 온전케 되었느니라", "kkjv": "네가 보거니와 믿음이 그의 행위와 함께 일하고 행위로 믿음이 완전하게 되지 아니하였느냐?", "web": "You see that faith worked with his works, and by works faith was perfected;"}}, {"id": 582, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온유"], "book": "민수기", "chap": 12, "verse": "3", "ref": "민수기 12:3", "texts": {"krv": "이 사람 모세는 온유함이 지면의 모든 사람보다 승하더라", "kkjv": "(이제 그 사람 모세는 매우 온유하여 지면의 모든 사람보다 온유하였더라.)", "web": "Now the man Moses was very humble, above all the men who were on the surface of the earth."}}, {"id": 583, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온유"], "book": "시편", "chap": 25, "verse": "9", "ref": "시편 25:9", "texts": {"krv": "온유한 자를 공의로 지도하심이여 온유한 자에게 그 도를 가르치시리로다", "kkjv": "그분께서 온유한 자를 판단의 공의로 지도하시리니 곧 온유한 자에게 자신의 길을 가르치시리로다.", "web": "He will guide the humble in justice. He will teach the humble his way."}}, {"id": 584, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온유"], "book": "시편", "chap": 37, "verse": "11", "ref": "시편 37:11", "texts": {"krv": "오직 온유한 자는 땅을 차지하며 풍부한 화평으로 즐기리로다", "kkjv": "그러나 온유한 자들은 땅을 상속하며 넘치는 화평 속에서 즐거워하리로다.", "web": "But the humble shall inherit the land, and shall delight themselves in the abundance of peace."}}, {"id": 585, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온유"], "book": "마태복음", "chap": 5, "verse": "5", "ref": "마태복음 5:5", "texts": {"krv": "온유한 자는 복이 있나니 저희가 땅을 기업으로 받을 것임이요", "kkjv": "온유한 자들은 복이 있나니 그들이 땅을 상속받을 것이기 때문이요,", "web": "Blessed are the gentle, for they shall inherit the earth."}}, {"id": 586, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온유"], "book": "빌립보서", "chap": 4, "verse": "5", "ref": "빌립보서 4:5", "texts": {"krv": "너희 관용을 모든 사람에게 알게 하라 주께서 가까우시니라", "kkjv": "너희의 절제를 모든 사람이 알게 하라. 주께서 가까이 계시느니라.", "web": "Let your gentleness be known to all men. The Lord is at hand."}}, {"id": 587, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온유"], "book": "디도서", "chap": 3, "verse": "2", "ref": "디도서 3:2", "texts": {"krv": "아무도 훼방하지 말며 다투지 말며 관용하며 범사에 온유함을 모든 사람에게 나타낼 것을 기억하게 하라", "kkjv": "아무도 비방하지 말며 말다툼하는 자가 되지 말며 오직 부드러우며 모든 사람에게 온전히 온유함을 보이게 하라.", "web": "to speak evil of no one, not to be contentious, to be gentle, showing all humility toward all men."}}, {"id": 588, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "인내"], "book": "잠언", "chap": 12, "verse": "16", "ref": "잠언 12:16", "texts": {"krv": "미련한 자는 분노를 당장에 나타내거니와 슬기로운 자는 수욕을 참느니라", "kkjv": "어리석은 자의 진노는 즉시 알려지거니와 분별 있는 자는 수치를 덮느니라.", "web": "A fool shows his annoyance the same day, but one who overlooks an insult is prudent."}}, {"id": 589, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "인내"], "book": "전도서", "chap": 7, "verse": "8", "ref": "전도서 7:8", "texts": {"krv": "일의 끝이 시작보다 낫고 참는 마음이 교만한 마음보다 나으니", "kkjv": "일의 끝이 일의 시작보다 낫고 영 안에서 참는 자가 영 안에서 교만한 자보다 나으니", "web": "Better is the end of a thing than its beginning.   The patient in spirit is better than the proud in spirit."}}, {"id": 590, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "인내"], "book": "누가복음", "chap": 8, "verse": "15", "ref": "누가복음 8:15", "texts": {"krv": "좋은 땅에 있다는 것은 착하고 좋은 마음으로 말씀을 듣고 지키어 인내로 결실하는 자니라", "kkjv": "그러나 좋은 땅에 있는 것은 말씀을 듣고 정직하고 선한 마음속에 그것을 간직하여 인내로 열매를 내는 자들이니라.", "web": "That in the good ground, these are such as in an honest and good heart, having heard the word, hold it tightly, and produces fruit with patience."}}, {"id": 591, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "인내"], "book": "히브리서", "chap": 10, "verse": "36", "ref": "히브리서 10:36", "texts": {"krv": "너희에게 인내가 필요함은 너희가 하나님의 뜻을 행한 후에 약속을 받기 위함이라", "kkjv": "너희가 하나님의 뜻을 행한 뒤에 그 약속하신 것을 받기 위해 너희에게 인내가 필요하니라.", "web": "For you need endurance so that, having done the will of God, you may receive the promise."}}, {"id": 592, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "인내"], "book": "야고보서", "chap": 5, "verse": "7-8", "ref": "야고보서 5:7-8", "texts": {"krv": "그러므로 형제들아 주의 강림하시기까지 길이 참으라 보라 농부가 땅에서 나는 귀한 열매를 바라고 길이 참아 이른 비와 늦은 비를 기다리나니 너희도 길이 참고 마음을 굳게 하라 주의 강림이 가까우니라", "kkjv": "그러므로 형제들아, 주께서 오실 때까지 인내하라. 보라, 농부가 땅에서 나는 귀한 열매를 바라고 이른 비와 늦은 비를 받을 때까지 오랫동안 그것을 위해 인내하느니라. 너희도 인내하고 너희 마음을 굳건히 하라. 주의 오심이 가까이 다가오고 있느니라.", "web": "Be patient therefore, brothers, until the coming of the Lord. Behold, the farmer waits for the precious fruit of the earth, being patient over it, until it receives the early and late rain. You also be patient. Establish your hearts, for the coming of the Lord is at hand."}}, {"id": 593, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "인내"], "book": "야고보서", "chap": 5, "verse": "11", "ref": "야고보서 5:11", "texts": {"krv": "보라 인내하는 자를 우리가 복되다 하나니 너희가 욥의 인내를 들었고 주께서 주신 결말을 보았거니와 주는 가장 자비하시고 긍휼히 여기는 자시니라", "kkjv": "보라, 참는 자들을 우리가 행복한 자로 여기나니 너희가 욥의 인내를 들었고 주께서 주신 결말을 보았거니와 주께서는 지극히 동정심이 많으시며 친절한 긍휼을 베푸는 분이시니라.", "web": "Behold, we call them blessed who endured. You have heard of the patience of Job, and have seen the Lord in the outcome, and how the Lord is full of compassion and mercy."}}, {"id": 594, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "정직"], "book": "욥기", "chap": 8, "verse": "6-7", "ref": "욥기 8:6-7", "texts": {"krv": "또 청결하고 정직하면 정녕 너를 돌아보시고 네 의로운 집으로 형통하게 하실 것이라 네 시작은 미약하였으나 네 나중은 심히 창대하리라", "kkjv": "또 네가 순수하고 곧바르면 이제 그분께서 반드시 너를 위해 깨어나사 네 의가 거하는 처소를 형통하게 하시리니 비록 네 시작은 작을지라도 네 마지막 끝은 심히 크게 되리라.", "web": "If you were pure and upright, surely now he would awaken for you, and make the habitation of your righteousness prosperous. Though your beginning was small, yet your latter end would greatly increase."}}, {"id": 595, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "정직"], "book": "시편", "chap": 7, "verse": "10", "ref": "시편 7:10", "texts": {"krv": "나의 방패는 마음이 정직한 자를 구원하시는 하나님께 있도다", "kkjv": "나의 방벽은 마음이 올바른 자를 구원하시는 하나님에게서 나는도다.", "web": "My shield is with God, who saves the upright in heart."}}, {"id": 596, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "정직"], "book": "시편", "chap": 11, "verse": "7", "ref": "시편 11:7", "texts": {"krv": "여호와는 의로우사 의로운 일을 좋아하시나니 정직한 자는 그 얼굴을 뵈오리로다", "kkjv": "의로우신 주께서 의를 사랑하시나니 그분의 얼굴은 곧바른 자를 보시느니라.", "web": "For Yahweh is righteous. He loves righteousness. The upright shall see his face."}}, {"id": 597, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "정직"], "book": "시편", "chap": 15, "verse": "1-2", "ref": "시편 15:1-2", "texts": {"krv": "여호와여 주의 장막에 유할 자 누구오며 주의 성산에 거할 자 누구오니이까 정직하게 행하며 공의를 일삼으며 그 마음에 진실을 말하며", "kkjv": "주여, 누가 주의 장막에 머무르리이까? 누가 주의 거룩한 산에 거하리이까? 곧바르게 걷고 의를 행하며 마음속으로 진리를 말하는 자,", "web": "Yahweh, who shall dwell in your sanctuary? Who shall live on your holy hill? He who walks blamelessly does what is right, and speaks truth in his heart;"}}, {"id": 598, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "정직"], "book": "시편", "chap": 51, "verse": "10", "ref": "시편 51:10", "texts": {"krv": "하나님이여 내 속에 정한 마음을 창조하시고 내 안에 정직한 영을 새롭게 하소서", "kkjv": "오 하나님이여, 내 안에 깨끗한 마음을 창조하시고 내 속에 올바른 영을 새롭게 하소서.", "web": "Create in me a clean heart, O God. Renew a right spirit within me."}}, {"id": 599, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "정직"], "book": "시편", "chap": 64, "verse": "10", "ref": "시편 64:10", "texts": {"krv": "의인은 여호와를 인하여 즐거워하며 그에게 피하리니 마음이 정직한 자는 다 자랑하리로다", "kkjv": "의로운 자는 주를 즐거워하며 그분을 신뢰하리니 마음이 올바른 모든 자들은 자랑하리로다.", "web": "The righteous shall be glad in Yahweh, and shall take refuge in him. All the upright in heart shall praise him!"}}, {"id": 600, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "정직"], "book": "시편", "chap": 97, "verse": "11", "ref": "시편 97:11", "texts": {"krv": "의인을 위하여 빛을 뿌리고 마음이 정직한 자를 위하여 기쁨을 뿌렸도다", "kkjv": "그분께서 의로운 자를 위하여 빛을 뿌리시고 마음이 올바른 자를 위하여 즐거움을 뿌리셨나니", "web": "Light is sown for the righteous, and gladness for the upright in heart."}}, {"id": 601, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "정직"], "book": "잠언", "chap": 2, "verse": "7", "ref": "잠언 2:7", "texts": {"krv": "그는 정직한 자를 위하여 완전한 지혜를 예비하시며 행실이 온전한 자에게 방패가 되시나니", "kkjv": "그분께서는 의로운 자들을 위하여 건전한 지혜를 모아 두시며 곧바르게 걷는 자들에게 방패가 되시고", "web": "He lays up sound wisdom for the upright. He is a shield to those who walk in integrity;"}}, {"id": 602, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "정직"], "book": "잠언", "chap": 14, "verse": "11", "ref": "잠언 14:11", "texts": {"krv": "악한 자의 집은 망하겠고 정직한 자의 장막은 흥하리라", "kkjv": "사악한 자의 집은 뒤엎어지려니와 곧바른 자의 장막은 흥왕하리라.", "web": "The house of the wicked will be overthrown, but the tent of the upright will flourish."}}, {"id": 603, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "정직"], "book": "잠언", "chap": 15, "verse": "8", "ref": "잠언 15:8", "texts": {"krv": "악인의 제사는 여호와께서 미워하셔도 정직한 자의 기도는 그가 기뻐하시느니라", "kkjv": "사악한 자의 희생물은 주께 가증한 것이나 곧바른 자의 기도는 그분께서 기뻐하시는 것이니라.", "web": "The sacrifice made by the wicked is an abomination to Yahweh, but the prayer of the upright is his delight."}}, {"id": 604, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "정직"], "book": "전도서", "chap": 7, "verse": "29", "ref": "전도서 7:29", "texts": {"krv": "나의 깨달은 것이 이것이라 곧 하나님이 사람을 정직하게 지으셨으나 사람은 많은 꾀를 낸 것이니라", "kkjv": "보라, 내가 발견한 것은 오직 이것이니 곧 하나님은 사람을 곧바르게 만드셨으나 그들이 많은 창안물을 찾아냈다는 것이라.", "web": "Behold, this only have I found: that God made man upright; but they search for many schemes.”"}}, {"id": 605, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "정직"], "book": "이사야", "chap": 26, "verse": "7", "ref": "이사야 26:7", "texts": {"krv": "의인의 길은 정직함이여 정직하신 주께서 의인의 첩경을 평탄케 하시도다", "kkjv": "곧바름이 의인의 길인즉 지극히 곧바른 주께서 의인의 행로를 다시나이다.", "web": "The way of the just is uprightness. You who are upright make the path of the righteous level."}}, {"id": 606, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "평강"], "book": "시편", "chap": 37, "verse": "37", "ref": "시편 37:37", "texts": {"krv": "완전한 사람을 살피고 정직한 자를 볼지어다 화평한 자의 결국은 평안이로다", "kkjv": "완전한 사람을 주목하고 곧바른 자를 눈여겨볼지어다. 그 사람의 마지막은 화평이니라.", "web": "Mark the perfect man, and see the upright, for there is a future for the man of peace."}}, {"id": 607, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "평강"], "book": "시편", "chap": 119, "verse": "165", "ref": "시편 119:165", "texts": {"krv": "주의 법을 사랑하는 자에게는 큰 평안이 있으니 저희에게 장애물이 없으리이다", "kkjv": "주의 법을 사랑하는 자들에게는 큰 평안이 있나니 아무것도 그들을 실족하게 하지 못하리이다.", "web": "Those who love your law have great peace. Nothing causes them to stumble."}}, {"id": 608, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "평강"], "book": "이사야", "chap": 57, "verse": "2", "ref": "이사야 57:2", "texts": {"krv": "그는 평안에 들어갔나니 무릇 정로로 행하는 자는 자기들의 침상에서 편히 쉬느니라", "kkjv": "그는 화평 속으로 들어갈 것이요, 자기의 곧바름 속에서 걷는 자들은 다 자기 침상에서 안식하리로다.", "web": "He enters into peace; they rest in their beds, each one who walks in his uprightness."}}, {"id": 609, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "평강"], "book": "예레미야", "chap": 29, "verse": "11", "ref": "예레미야 29:11", "texts": {"krv": "나 여호와가 말하노라 너희를 향한 나의 생각은 내가 아나니 재앙이 아니라 곧 평안이요 너희 장래에 소망을 주려 하는 생각이라", "kkjv": "너희를 향해 내가 생각하는 생각을 내가 아노라. 그것은 평안을 주려는 생각이요, 재앙을 주려는 생각이 아니니 곧 기대하던 결말을 너희에게 주려는 것이라. 주가 말하노라.", "web": "For I know the thoughts that I think toward you, says Yahweh, thoughts of peace, and not of evil, to give you hope and a future."}}, {"id": 610, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "평강"], "book": "요한복음", "chap": 14, "verse": "27", "ref": "요한복음 14:27", "texts": {"krv": "평안을 너희에게 끼치노니 곧 나의 평안을 너희에게 주노라 내가 너희에게 주는 것은 세상이 주는 것 같지 아니하니라 너희는 마음에 근심도 말고 두려워하지도 말라", "kkjv": "내가 너희에게 평안을 남기노니 곧 나의 평안을 너희에게 주노라. 세상이 주는 것과 달리 내가 너희에게 주노니 너희는 마음에 근심하지도 말고 두려워하지도 말라.", "web": "Peace I leave with you. My peace I give to you; not as the world gives, give I to you. Don’t let your heart be troubled, neither let it be fearful."}}, {"id": 611, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "평강"], "book": "요한복음", "chap": 15, "verse": "11", "ref": "요한복음 15:11", "texts": {"krv": "내가 이것을 너희에게 이름은 내 기쁨이 너희 안에 있어 너희 기쁨을 충만하게 하려 함이니라", "kkjv": "내가 너희에게 이 일들을 말한 것은 내 기쁨이 너희 안에 머물러 있어 너희 기쁨이 충만하게 하려 함이니라.", "web": "I have spoken these things to you, that my joy may remain in you, and that your joy may be made full."}}, {"id": 612, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "평강"], "book": "요한복음", "chap": 16, "verse": "33", "ref": "요한복음 16:33", "texts": {"krv": "이것을 너희에게 이름은 너희로 내 안에서 평안을 누리게 하려 함이라 세상에서는 너희가 환난을 당하나 담대하라 내가 세상을 이기었노라 하시니라", "kkjv": "너희에게 이 일들을 말한 것은 너희가 내 안에서 평안을 누리게 하려 함이니라. 세상에서는 너희가 환난을 당할 터이나 기운을 내라. 내가 세상을 이기었노라, 하시니라.", "web": "I have told you these things, that in me you may have peace. In the world you have oppression; but cheer up! I have overcome the world.”"}}, {"id": 613, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "평강"], "book": "로마서", "chap": 14, "verse": "17", "ref": "로마서 14:17", "texts": {"krv": "하나님의 나라는 먹는 것과 마시는 것이 아니요 오직 성령 안에서 의와 평강과 희락이라", "kkjv": "하나님의 왕국은 먹는 것과 마시는 것이 아니요, 오직 성령님 안에서 의와 화평과 기쁨이니라.", "web": "for the Kingdom of God is not eating and drinking, but righteousness, peace, and joy in the Holy Spirit."}}, {"id": 614, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "평강"], "book": "에베소서", "chap": 4, "verse": "3", "ref": "에베소서 4:3", "texts": {"krv": "평안의 매는 줄로 성령의 하나 되게 하신 것을 힘써 지키라", "kkjv": "화평의 매는 띠로 성령이 하나 되게 하신 것을 힘써 지키라.", "web": "being eager to keep the unity of the Spirit in the bond of peace."}}, {"id": 615, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "평강"], "book": "빌립보서", "chap": 4, "verse": "4", "ref": "빌립보서 4:4", "texts": {"krv": "주 안에서 항상 기뻐하라 내가 다시 말하노니 기뻐하라", "kkjv": "항상 주를 기뻐하라. 내가 다시 말하노니 기뻐하라.", "web": "Rejoice in the Lord always! Again I will say, “Rejoice!”"}}, {"id": 616, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "평강"], "book": "골로새서", "chap": 3, "verse": "15", "ref": "골로새서 3:15", "texts": {"krv": "그리스도의 평강이 너희 마음을 주장하게 하라 평강을 위하여 너희가 한 몸으로 부르심을 받았나니 또한 너희는 감사하는 자가 되라", "kkjv": "하나님의 화평이 너희 마음속에서 다스리게 하라. 너희도 그 화평에 이르도록 한 몸 안에서 부르심을 받았으니 감사하는 자가 되라.", "web": "And let the peace of God rule in your hearts, to which also you were called in one body; and be thankful."}}, {"id": 617, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "평강"], "book": "데살로니가후서", "chap": 3, "verse": "16", "ref": "데살로니가후서 3:16", "texts": {"krv": "평강의 주께서 친히 때마다 일마다 너희에게 평강을 주시기를 원하노라 주는 너희 모든 사람과 함께 하실지어다", "kkjv": "이제 평강의 주께서 친히 모든 방법으로 항상 너희에게 평강을 주시기를 원하노라. 주께서 너희 모두와 함께하시기를 원하노라.", "web": "Now may the Lord of peace himself give you peace at all times in all ways. The Lord be with you all."}}, {"id": 618, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "감사함"], "book": "시편", "chap": 9, "verse": "1", "ref": "시편 9:1", "texts": {"krv": "내가 전심으로 여호와께 감사하오며 주의 모든 기사를 전하리이다", "kkjv": "오 주여, 내가 온 마음으로 주를 찬양하오며 주의 모든 놀라운 일들을 전하리이다.", "web": "I will give thanks to Yahweh with my whole heart. I will tell of all your marvelous works."}}, {"id": 619, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "감사함"], "book": "시편", "chap": 50, "verse": "14", "ref": "시편 50:14", "texts": {"krv": "감사로 하나님께 제사를 드리며 지극히 높으신 자에게 네 서원을 갚으며", "kkjv": "감사를 하나님에게 드리고 지극히 높으신 이에게 네 서원을 갚으며", "web": "Offer to God the sacrifice of thanksgiving. Pay your vows to the Most High."}}, {"id": 620, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "감사함"], "book": "시편", "chap": 100, "verse": "4", "ref": "시편 100:4", "texts": {"krv": "감사함으로 그 문에 들어가며 찬송함으로 그 궁정에 들어가서 그에게 감사하며 그 이름을 송축할지어다", "kkjv": "감사와 더불어 그분의 문들에 들어가며 찬양과 더불어 그분의 뜰에 들어가서 그분께 감사하고 그분의 이름을 찬송하라.", "web": "Enter into his gates with thanksgiving, into his courts with praise. Give thanks to him, and bless his name."}}, {"id": 621, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "감사함"], "book": "시편", "chap": 119, "verse": "7", "ref": "시편 119:7", "texts": {"krv": "내가 주의 의로운 판단을 배울 때에는 정직한 마음으로 주께 감사하리이다", "kkjv": "내가 주의 의로운 판단들을 배울 때에 올바른 마음으로 주를 찬양하리이다.", "web": "I will give thanks to you with uprightness of heart, when I learn your righteous judgments."}}, {"id": 622, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "감사함"], "book": "에베소서", "chap": 5, "verse": "20", "ref": "에베소서 5:20", "texts": {"krv": "범사에 우리 주 예수 그리스도의 이름으로 항상 아버지 하나님께 감사하며", "kkjv": "모든 일로 인해 우리 주 예수 그리스도의 이름으로 항상 하나님 곧 아버지께 감사하고", "web": "giving thanks always concerning all things in the name of our Lord Jesus Christ, to God, even the Father;"}}, {"id": 623, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "감사함"], "book": "골로새서", "chap": 4, "verse": "2", "ref": "골로새서 4:2", "texts": {"krv": "기도를 항상 힘쓰고 기도에 감사함으로 깨어 있으라", "kkjv": "항상 기도하고 기도 중에 감사를 드리며 깨어 있으라.", "web": "Continue steadfastly in prayer, watching therein with thanksgiving;"}}, {"id": 624, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "강건함"], "book": "여호수아", "chap": 1, "verse": "7", "ref": "여호수아 1:7", "texts": {"krv": "오직 너는 마음을 강하게 하고 극히 담대히 하여 나의 종 모세가 네게 명한 율법을 다 지켜 행하고 좌로나 우로나 치우치지 말라 그리하면 어디로 가든지 형통하리니", "kkjv": "오직 너는 마음을 강하게 하고 심히 용감한 자가 되어 내 종 모세가 네게 명령한 모든 율법대로 지켜 행하고 그것을 떠나 오른쪽으로나 왼쪽으로나 치우치지 말라. 그리하면 네가 어디로 가든지 형통하리라.", "web": "Only be strong and very courageous, to observe to do according to all the law, which Moses my servant commanded you. Don’t turn from it to the right hand or to the left, that you may have good success wherever you go."}}, {"id": 625, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "강건함"], "book": "이사야", "chap": 41, "verse": "15", "ref": "이사야 41:15", "texts": {"krv": "보라 내가 너로 이가 날카로운 새 타작 기계를 삼으리니 네가 산들을 쳐서 부스러기를 만들 것이며 작은 산들로 겨 같게 할 것이라", "kkjv": "보라, 내가 너를 이가 달린 날카로운 새 타작 기구로 삼으리니 네가 산들을 쳐서 작게 부수며 작은 산들을 겨같이 만들리라.", "web": "Behold, I have made you into a new sharp threshing instrument with teeth. You will thresh the mountains, and beat them small, and will make the hills like chaff."}}, {"id": 626, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "강건함"], "book": "다니엘", "chap": 10, "verse": "19", "ref": "다니엘 10:19", "texts": {"krv": "가로되 은총을 크게 받은 사람이여 두려워하지 말라 평안하라 강건하라 강건하라 그가 이같이 내게 말하매 내가 곧 힘이 나서 가로되 내 주께서 나로 힘이 나게 하셨사오니 말씀하옵소서", "kkjv": "이르되, 오 크게 사랑받는 사람아, 두려워하지 말라. 네게 평강이 있을지어다. 마음을 강하게 하라. 참으로 마음을 강하게 하라, 하니라. 그가 내게 말하매 내가 강하게 되어 이르되, 주께서 나를 강하게 하셨사오니 내 주는 말씀하소서, 하매", "web": "He said, “Greatly beloved man, don’t be afraid: peace be to you, be strong, yes, be strong.”   When he spoke to me, I was strengthened, and said, “Let my lord speak; for you have strengthened me.”"}}, {"id": 627, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "강건함"], "book": "고린도전서", "chap": 16, "verse": "13", "ref": "고린도전서 16:13", "texts": {"krv": "깨어 믿음에 굳게 서서 남자답게 강건하여라", "kkjv": "너희는 깨어 믿음에 굳게 서서 남자답게 행동하며 강건한 자가 되라.", "web": "Watch! Stand firm in the faith! Be courageous! Be strong!"}}, {"id": 628, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "강건함"], "book": "에베소서", "chap": 3, "verse": "16", "ref": "에베소서 3:16", "texts": {"krv": "그 영광의 풍성을 따라 그의 성령으로 말미암아 너희 속 사람을 능력으로 강건하게 하옵시며", "kkjv": "그분께서 자신의 영광의 풍성함에 따라 자신의 영을 통해 속사람이 능력으로 강건하게 됨을 너희에게 허락하시며", "web": "that he would grant you, according to the riches of his glory, that you may be strengthened with power through his Spirit in the inward man;"}}, {"id": 629, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "강건함"], "book": "에베소서", "chap": 6, "verse": "13", "ref": "에베소서 6:13", "texts": {"krv": "그러므로 하나님의 전신갑주를 취하라 이는 악한 날에 너희가 능히 대적하고 모든 일을 행한 후에 서기 위함이라", "kkjv": "그러므로 너희가 악한 날에 능히 버티어 내고 모든 일을 행한 뒤에 서기 위해 하나님의 전신갑주를 취하라.", "web": "Therefore put on the whole armor of God, that you may be able to withstand in the evil day, and, having done all, to stand."}}, {"id": 630, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "견고함"], "book": "시편", "chap": 17, "verse": "5", "ref": "시편 17:5", "texts": {"krv": "나의 걸음이 주의 길을 굳게 지키고 실족지 아니하였나이다", "kkjv": "주의 행로들 안에서 내가 가는 것을 떠받쳐 주사 내 발걸음이 미끄러지지 아니하게 하소서.", "web": "My steps have held fast to your paths. My feet have not slipped."}}, {"id": 631, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "견고함"], "book": "시편", "chap": 62, "verse": "2", "ref": "시편 62:2", "texts": {"krv": "오직 저만 나의 반석이시요 나의 구원이시요 나의 산성이시니 내가 크게 요동치 아니하리로다", "kkjv": "오직 그분만이 나의 반석이시요, 나의 구원이시요, 나의 방벽이시니 내가 크게 흔들리지 아니하리로다.", "web": "He alone is my rock and my salvation, my fortress— I will never be greatly shaken."}}, {"id": 632, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "견고함"], "book": "시편", "chap": 119, "verse": "133", "ref": "시편 119:133", "texts": {"krv": "나의 행보를 주의 말씀에 굳게 세우시고 아무 죄악이 나를 주장치 못하게 하소서", "kkjv": "주의 말씀 안에서 내 발걸음을 명하시고 어떤 불법도 나를 지배하지 못하게 하소서.", "web": "Establish my footsteps in your word. Don’t let any iniquity have dominion over me."}}, {"id": 633, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "견고함"], "book": "히브리서", "chap": 13, "verse": "9", "ref": "히브리서 13:9", "texts": {"krv": "여러 가지 다른 교훈에 끌리지 말라 마음은 은혜로써 굳게 함이 아름답고 식물로써 할 것이 아니니 식물로 말미암아 행한 자는 유익을 얻지 못하였느니라", "kkjv": "여러 가지 이상한 교리에 끌려 다니지 말라. 은혜로 마음을 굳게 함이 선한 일이요, 음식으로 할 것이 아니니 음식에 전념하는 자들에게 음식이 유익을 끼치지 못하였느니라.", "web": "Don’t be carried away by various and strange teachings, for it is good that the heart be established by grace, not by food, through which those who were so occupied were not benefited."}}, {"id": 634, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "견고함"], "book": "베드로후서", "chap": 1, "verse": "10", "ref": "베드로후서 1:10", "texts": {"krv": "그러므로 형제들아 더욱 힘써 너희 부르심과 택하심을 굳게 하라 너희가 이것을 행한즉 언제든지 실족지 아니하리라", "kkjv": "그러므로 형제들아, 더욱 열심을 내어 너희를 부르신 것과 선택하신 것을 확고히 하라. 너희가 이것들을 행하면 결코 넘어지지 아니하리니", "web": "Therefore, brothers, be more diligent to make your calling and election sure. For if you do these things, you will never stumble."}}, {"id": 635, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "견고함"], "book": "요한계시록", "chap": 2, "verse": "25", "ref": "요한계시록 2:25", "texts": {"krv": "다만 너희에게 있는 것을 내가 올 때까지 굳게 잡으라", "kkjv": "다만 너희가 이미 가지고 있는 것을 내가 올 때까지 굳게 붙잡으라.", "web": "Nevertheless, hold that which you have firmly until I come."}}, {"id": 636, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "담대함"], "book": "여호수아", "chap": 1, "verse": "9", "ref": "여호수아 1:9", "texts": {"krv": "내가 네게 명한 것이 아니냐 마음을 강하게 하고 담대히 하라 두려워 말며 놀라지 말라 네가 어디로 가든지 네 하나님 여호와가 너와 함께 하느니라 하시니라", "kkjv": "내가 네게 명령하지 아니하였느냐? 마음을 강하게 하고 크게 용기를 내라. 두려워하지 말며 너는 놀라지 말라. 네가 어디로 가든지 주 네 하나님이 너와 함께하느니라, 하시니라.", "web": "Haven’t I commanded you? Be strong and courageous. Don’t be afraid, neither be dismayed: for Yahweh your God is with you wherever you go.”"}}, {"id": 637, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "담대함"], "book": "사무엘하", "chap": 22, "verse": "30", "ref": "사무엘하 22:30", "texts": {"krv": "내가 주를 의뢰하고 적군에 달리며 내 하나님을 의지하고 성벽을 뛰어 넘나이다", "kkjv": "내가 주를 힘입어 군대 사이를 달려가며 내 하나님을 힘입어 담을 뛰어넘었나이다.", "web": "For by you, I run against a troop. By my God, I leap over a wall."}}, {"id": 638, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "담대함"], "book": "시편", "chap": 31, "verse": "24", "ref": "시편 31:24", "texts": {"krv": "강하고 담대하라 여호와를 바라는 너희들아", "kkjv": "주께 소망을 둔 모든 자들아, 너희는 크게 용기를 내라. 그분께서 너희 마음을 강하게 하시리로다.", "web": "Be strong, and let your heart take courage, all you who hope in Yahweh."}}, {"id": 639, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "담대함"], "book": "잠언", "chap": 28, "verse": "1", "ref": "잠언 28:1", "texts": {"krv": "악인은 쫓아오는 자가 없어도 도망하나 의인은 사자 같이 담대하니라", "kkjv": "사악한 자들은 쫓아오는 자가 없어도 도망하나 의로운 자들은 사자같이 담대하니라.", "web": "The wicked flee when no one pursues; but the righteous are as bold as a lion."}}, {"id": 640, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "담대함"], "book": "이사야", "chap": 50, "verse": "7", "ref": "이사야 50:7", "texts": {"krv": "주 여호와께서 나를 도우시므로 내가 부끄러워 아니하고 내 얼굴을 부싯돌 같이 굳게 하였은즉 내가 수치를 당치 아니할 줄 아노라", "kkjv": "¶주 하나님께서 나를 도우실 터인즉 내가 당황하지 아니하리라. 그러므로 내가 내 얼굴을 부싯돌같이 세웠나니 내가 부끄러움을 당하지 아니할 줄 아노라.", "web": "For the Lord Yahweh will help me; therefore I have not been confounded: therefore have I set my face like a flint, and I know that I shall not be disappointed."}}, {"id": 641, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "담대함"], "book": "사도행전", "chap": 4, "verse": "29", "ref": "사도행전 4:29", "texts": {"krv": "주여 이제도 저희의 위협함을 하감하옵시고 또 종들로 하여금 담대히 하나님의 말씀을 전하게 하여 주옵시며", "kkjv": "주여, 이제 그들의 위협을 보시고 또 주의 종들이 전적으로 담대히 주의 말씀을 말하게 하시며", "web": "Now, Lord, look at their threats, and grant to your servants to speak your word with all boldness,"}}, {"id": 642, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "담대함"], "book": "사도행전", "chap": 4, "verse": "31", "ref": "사도행전 4:31", "texts": {"krv": "빌기를 다하매 모인 곳이 진동하더니 무리가 다 성령이 충만하여 담대히 하나님의 말씀을 전하니라", "kkjv": "¶그들이 기도하기를 마치매 그들이 함께 모인 곳이 흔들리더니 그들이 다 성령님으로 충만하여 담대히 하나님의 말씀을 말하니라.", "web": "When they had prayed, the place was shaken where they were gathered together. They were all filled with the Holy Spirit, and they spoke the word of God with boldness."}}, {"id": 643, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "담대함"], "book": "에베소서", "chap": 3, "verse": "12", "ref": "에베소서 3:12", "texts": {"krv": "우리가 그 안에서 그를 믿음으로 말미암아 담대함과 하나님께 당당히 나아감을 얻느니라", "kkjv": "그리스도 안에서 우리가 그분의 믿음을 통해 담대함을 가지며 또 확신 있게 나아감을 얻느니라.", "web": "in whom we have boldness and access in confidence through our faith in him."}}, {"id": 644, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "담대함"], "book": "디모데후서", "chap": 1, "verse": "7", "ref": "디모데후서 1:7", "texts": {"krv": "하나님이 우리에게 주신 것은 두려워하는 마음이 아니요 오직 능력과 사랑과 근신하는 마음이니", "kkjv": "하나님께서는 우리에게 두려움의 영을 주지 아니하시고 권능과 사랑과 건전한 생각의 영을 주셨느니라.", "web": "For God didn’t give us a spirit of fear, but of power, love, and self-control."}}, {"id": 645, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "담대함"], "book": "히브리서", "chap": 10, "verse": "35", "ref": "히브리서 10:35", "texts": {"krv": "그러므로 너희 담대함을 버리지 말라 이것이 큰 상을 얻느니라", "kkjv": "그러므로 너희의 확신을 버리지 말라. 그것이 큰 보상의 보응을 얻게 하느니라.", "web": "Therefore don’t throw away your boldness, which has a great reward."}}, {"id": 646, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "담대함"], "book": "요한일서", "chap": 3, "verse": "21", "ref": "요한일서 3:21", "texts": {"krv": "사랑하는 자들아 만일 우리 마음이 우리를 책망할 것이 없으면 하나님 앞에서 담대함을 얻고", "kkjv": "사랑하는 자들아, 만일 우리 마음이 우리를 정죄하지 아니한다면 우리가 하나님을 향해 확신을 갖고", "web": "Beloved, if our hearts don’t condemn us, we have boldness toward God;"}}, {"id": 647, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "담대함"], "book": "요한일서", "chap": 4, "verse": "17", "ref": "요한일서 4:17", "texts": {"krv": "이로써 사랑이 우리에게 온전히 이룬 것은 우리로 심판 날에 담대함을 가지게 하려 함이니 주의 어떠하심과 같이 우리도 세상에서 그러하니라", "kkjv": "이 점에서 우리의 사랑이 완전하게 되었나니 이것은 우리가 심판 날에 담대함을 가지게 하려 함이라. 이는 그분께서 어떠하신 것 같이 우리도 이 세상에서 그러하기 때문이니라.", "web": "In this love has been made perfect among us, that we may have boldness in the day of judgment, because as he is, even so are we in this world."}}, {"id": 648, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "의로움"], "book": "이사야", "chap": 45, "verse": "8", "ref": "이사야 45:8", "texts": {"krv": "너 하늘이여 위에서부터 의로움을 비 같이 듣게 할지어다 궁창이여 의를 부어 내릴지어다 땅이여 열려서 구원을 내고 의도 함께 움돋게 할지어다 나 여호와가 이 일을 창조하였느니라", "kkjv": "하늘들아, 너희는 위에서부터 의를 내리며 창공은 의를 내려 부을지니라. 땅은 열리고 그들은 구원을 가져오며 의는 함께 솟아날지어다. 나 주가 그 일을 창조하였느니라.", "web": "Distil, you heavens, from above, and let the skies pour down righteousness. Let the earth open, that it may produce salvation, and let it cause righteousness to spring up with it. I, Yahweh, have created it."}}, {"id": 649, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "의로움"], "book": "로마서", "chap": 8, "verse": "33", "ref": "로마서 8:33", "texts": {"krv": "누가 능히 하나님의 택하신 자들을 송사하리요 의롭다 하신 이는 하나님이시니", "kkjv": "누가 하나님께서 선택하신 자들을 무슨 일로 고소하리요? 의롭다 하시는 분은 하나님이시니", "web": "Who could bring a charge against God’s chosen ones? It is God who justifies."}}, {"id": 650, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "의로움"], "book": "고린도전서", "chap": 6, "verse": "11", "ref": "고린도전서 6:11", "texts": {"krv": "너희 중에 이와 같은 자들이 있더니 주 예수 그리스도의 이름과 우리 하나님의 성령 안에서 씻음과 거룩함과 의롭다 하심을 얻었느니라", "kkjv": "너희 중에 이 같은 자들이 더러 있었으나 너희가 우리 하나님의 영을 통해 주 예수님의 이름으로 씻기고 거룩히 구별되어 의롭게 되었느니라.", "web": "Such were some of you, but you were washed. But you were sanctified. But you were justified in the name of the Lord Jesus, and in the Spirit of our God."}}, {"id": 651, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "의로움"], "book": "갈라디아서", "chap": 5, "verse": "4", "ref": "갈라디아서 5:4", "texts": {"krv": "율법 안에서 의롭다 함을 얻으려 하는 너희는 그리스도에게서 끊어지고 은혜에서 떨어진 자로다", "kkjv": "너희 중에 누구든지 율법으로 의롭게 된 자에게는 그리스도께서 아무런 효력이 없으며 너희는 은혜에서 떨어져 나갔느니라.", "web": "You are alienated from Christ, you who desire to be justified by the law. You have fallen away from grace."}}, {"id": 652, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "의로움"], "book": "디모데후서", "chap": 2, "verse": "5", "ref": "디모데후서 2:5", "texts": {"krv": "경기하는 자가 법대로 경기하지 아니하면 면류관을 얻지 못할 것이며", "kkjv": "또한 사람이 우승하려고 애써도 적법하게 애쓰지 아니하면 관을 얻지 못하며", "web": "Also, if anyone competes in athletics, he isn’t crowned unless he has competed by the rules."}}, {"id": 653, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "의로움"], "book": "디도서", "chap": 3, "verse": "7", "ref": "디도서 3:7", "texts": {"krv": "우리로 저의 은혜를 힘입어 의롭다 하심을 얻어 영생의 소망을 따라 후사가 되게 하려 하심이라", "kkjv": "이것은 우리가 그분의 은혜로 의롭게 되어 영원한 생명의 소망에 따라 상속자가 되게 하려 하심이라.", "web": "that, being justified by his grace, we might be made heirs according to the hope of eternal life."}}, {"id": 654, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자원함"], "book": "출애굽기", "chap": 25, "verse": "2", "ref": "출애굽기 25:2", "texts": {"krv": "이스라엘 자손에게 명하여 내게 예물을 가져오라 하고 무릇 즐거운 마음으로 내는 자에게서 내게 드리는 것을 너희는 받을지니라", "kkjv": "이스라엘 자손에게 말하여 그들이 내게 헌물을 가져오게 하라. 또 너희는 마음에서 즐거이 그것을 내는 모든 자로부터 나의 헌물을 취할지니라.", "web": "“Speak to the children of Israel, that they take an offering for me. From everyone whose heart makes him willing you shall take my offering."}}, {"id": 655, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자원함"], "book": "역대상", "chap": 29, "verse": "14", "ref": "역대상 29:14", "texts": {"krv": "나와 나의 백성이 무엇이관대 이처럼 즐거운 마음으로 드릴 힘이 있었나이까 모든 것이 주께로 말미암았사오니 우리가 주의 손에서 받은 것으로 주께 드렸을 뿐이니이다", "kkjv": "그러나 나는 누구며 내 백성은 무엇이기에 우리가 이런 식으로 이렇게 자원하여 드릴 힘이 있겠나이까? 모든 것이 주에게서 나오니 우리가 주의 것에서 주께 드렸을 뿐이니이다.", "web": "But who am I, and what is my people, that we should be able to offer so willingly as this? For all things come from you, and of your own have we given you."}}, {"id": 656, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자원함"], "book": "시편", "chap": 51, "verse": "12", "ref": "시편 51:12", "texts": {"krv": "주의 구원의 즐거움을 내게 회복시키시고 자원하는 심령을 주사 나를 붙드소서", "kkjv": "주의 구원의 기쁨을 내게 회복시켜 주시고 주의 자유로운 영으로 나를 떠받쳐 주소서.", "web": "Restore to me the joy of your salvation. Uphold me with a willing spirit."}}, {"id": 657, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자원함"], "book": "이사야", "chap": 6, "verse": "8", "ref": "이사야 6:8", "texts": {"krv": "내가 또 주의 목소리를 들은즉 이르시되 내가 누구를 보내며 누가 우리를 위하여 갈꼬 그 때에 내가 가로되 내가 여기 있나이다 나를 보내소서", "kkjv": "또한 내가 주의 음성을 들었는데 이르시기를, 내가 누구를 보내며 누가 우리를 위하여 갈까? 하시더라. 그때에 내가 이르되, 내가 여기 있나이다. 나를 보내소서, 하였더라.", "web": "I heard the Lord’s voice, saying, “Whom shall I send, and who will go for us?”   Then I said, “Here I am. Send me!”"}}, {"id": 658, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자원함"], "book": "고린도후서", "chap": 8, "verse": "3", "ref": "고린도후서 8:3", "texts": {"krv": "내가 증거하노니 저희가 힘대로 할 뿐 아니라 힘에 지나도록 자원하여", "kkjv": "내가 증언하노니 그들이 힘닿는 데까지 하였을 뿐 아니라 참으로 힘에 넘치도록 자원하여 하였고", "web": "For according to their power, I testify, yes and beyond their power, they gave of their own accord,"}}, {"id": 659, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자원함"], "book": "고린도후서", "chap": 8, "verse": "17", "ref": "고린도후서 8:17", "texts": {"krv": "저가 권함을 받고 더욱 간절함으로 자원하여 너희에게 나아갔고", "kkjv": "참으로 그가 권면의 말을 받아들였을 뿐 아니라 더욱 열심을 내어 자원함으로 너희에게 갔느니라.", "web": "For he indeed accepted our exhortation, but being himself very earnest, he went out to you of his own accord."}}, {"id": 660, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자족함"], "book": "시편", "chap": 17, "verse": "15", "ref": "시편 17:15", "texts": {"krv": "나는 의로운 중에 주의 얼굴을 보리니 깰 때에 주의 형상으로 만족하리이다", "kkjv": "나로 말하건대 나는 의 가운데서 주의 얼굴을 바라보리니 내가 깰 때에 주의 모습으로 만족하리이다.", "web": "As for me, I shall see your face in righteousness. I shall be satisfied, when I awake, with seeing your form."}}, {"id": 661, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자족함"], "book": "시편", "chap": 65, "verse": "4", "ref": "시편 65:4", "texts": {"krv": "주께서 택하시고 가까이 오게 하사 주의 뜰에 거하게 하신 사람은 복이 있나이다 우리가 주의 집 곧 주의 성전의 아름다움으로 만족하리이다", "kkjv": "주께서 택하시고 주께 가까이 오게 하사 주의 뜰에 거하게 하는 사람은 복이 있나이다. 우리가 주의 집 곧 주의 거룩한 전의 좋은 것으로 만족하리이다.", "web": "Blessed is one whom you choose, and cause to come near, that he may live in your courts. We will be filled with the goodness of your house, your holy temple."}}, {"id": 662, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자족함"], "book": "전도서", "chap": 5, "verse": "10", "ref": "전도서 5:10", "texts": {"krv": "은을 사랑하는 자는 은으로 만족함이 없고 풍부를 사랑하는 자는 소득으로 만족함이 없나니 이것도 헛되도다", "kkjv": "은을 사랑하는 자는 은으로 만족하지 못하며 풍요를 사랑하는 자도 소득의 증대로 만족하지 못하리니 이것도 헛되도다.", "web": "He who loves silver shall not be satisfied with silver; nor he who loves abundance, with increase: this also is vanity."}}, {"id": 663, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자족함"], "book": "빌립보서", "chap": 4, "verse": "11-12", "ref": "빌립보서 4:11-12", "texts": {"krv": "내가 궁핍하므로 말하는 것이 아니라 어떠한 형편에든지 내가 자족하기를 배웠노니 내가 비천에 처할 줄도 알고 풍부에 처할 줄도 알아 모든 일에 배부르며 배고픔과 풍부와 궁핍에도 일체의 비결을 배웠노라", "kkjv": "내가 궁핍하므로 말하지 아니하노라. 내가 어떤 처지에 있든지 거기에 만족하는 것을 내가 배웠노니 내가 비천하게 되는 것도 알고 풍부하게 되는 것도 알아 어디에서나 모든 일에서 배부른 것과 배고픈 것, 풍부한 것과 궁핍당하는 것을 다 배웠노라.", "web": "Not that I speak in respect to lack, for I have learned in whatever state I am, to be content in it. I know how to be humbled, and I know also how to abound. In everything and in all things I have learned the secret both to be filled and to be hungry, both to abound and to be in need."}}, {"id": 664, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자족함"], "book": "디모데전서", "chap": 6, "verse": "7-8", "ref": "디모데전서 6:7-8", "texts": {"krv": "우리가 세상에 아무것도 가지고 온 것이 없으매 또한 아무것도 가지고 가지 못하리니 우리가 먹을 것과 입을 것이 있은즉 족한 줄로 알 것이니라", "kkjv": "우리가 이 세상에 아무것도 가지고 오지 아니하였은즉 아무것도 가지고 가지 못할 것이 확실하니 먹을 것과 입을 것이 있은즉 우리가 그것으로 만족할 것이니라.", "web": "For we brought nothing into the world, and we certainly can’t carry anything out. But having food and clothing, we will be content with that."}}, {"id": 665, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자족함"], "book": "히브리서", "chap": 13, "verse": "5", "ref": "히브리서 13:5", "texts": {"krv": "돈을 사랑치 말고 있는 바를 족한 줄로 알라 그가 친히 말씀하시기를 내가 과연 너희를 버리지 아니하고 과연 너희를 떠나지 아니하리라 하셨느니라", "kkjv": "너희의 행실을 탐욕이 없게 하고 너희가 가진 것들로 만족하라. 그분께서 이르시되, 내가 결코 너를 떠나지 아니하고 너를 버리지 아니하리라, 하셨느니라.", "web": "Be free from the love of money, content with such things as you have, for he has said, “I will in no way leave you, neither will I in any way forsake you.”"}}, {"id": 666, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "진실함"], "book": "시편", "chap": 51, "verse": "6", "ref": "시편 51:6", "texts": {"krv": "중심에 진실함을 주께서 원하시오니 내 속에 지혜를 알게 하시리이다", "kkjv": "보소서, 주께서는 속 부분에 있는 진실함을 원하시오니 나로 하여금 은밀한 부분에 있는 지혜를 알게 하시리이다.", "web": "Behold, you desire truth in the inward parts. You teach me wisdom in the inmost place."}}, {"id": 667, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "진실함"], "book": "시편", "chap": 139, "verse": "23-24", "ref": "시편 139:23-24", "texts": {"krv": "하나님이여 나를 살피사 내 마음을 아시며 나를 시험하사 내 뜻을 아옵소서 내게 무슨 악한 행위가 있나 보시고 나를 영원한 길로 인도하소서", "kkjv": "오 하나님이여, 나를 살피사 내 마음을 아시고 나를 시험하사 내 생각들을 아시옵소서. 또 내 안에 어떤 사악한 길이 있는지 보시고 나를 영존하는 길로 인도하소서.", "web": "Search me, God, and know my heart. Try me, and know my thoughts. See if there is any wicked way in me, and lead me in the everlasting way."}}, {"id": 668, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "진실함"], "book": "잠언", "chap": 12, "verse": "19", "ref": "잠언 12:19", "texts": {"krv": "진실한 입술은 영원히 보존되거니와 거짓 혀는 눈 깜짝일 동안만 있을 뿐이니라", "kkjv": "진리의 입술은 영원토록 굳게 세워지려니와 거짓말하는 혀는 잠시 있을 뿐이니라.", "web": "Truth’s lips will be established forever, but a lying tongue is only momentary."}}, {"id": 669, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "진실함"], "book": "잠언", "chap": 12, "verse": "22", "ref": "잠언 12:22", "texts": {"krv": "거짓 입술은 여호와께 미움을 받아도 진실히 행하는 자는 그의 기뻐하심을 받느니라", "kkjv": "거짓말하는 입술은 주께 가증한 것이나 진실하게 행하는 자들은 그분께서 기뻐하시는 자들이니라.", "web": "Lying lips are an abomination to Yahweh, but those who do the truth are his delight."}}, {"id": 670, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "진실함"], "book": "에베소서", "chap": 5, "verse": "9", "ref": "에베소서 5:9", "texts": {"krv": "빛의 열매는 모든 착함과 의로움과 진실함에 있느니라", "kkjv": "(성령의 열매는 모든 선함과 의와 진리 안에 있느니라.)", "web": "for the fruit of the Spirit is in all goodness and righteousness and truth,"}}, {"id": 671, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "진실함"], "book": "요한일서", "chap": 1, "verse": "8", "ref": "요한일서 1:8", "texts": {"krv": "만일 우리가 죄 없다 하면 스스로 속이고 또 진리가 우리 속에 있지 아니할 것이요", "kkjv": "만일 우리에게 죄가 없다고 우리가 말하면 우리가 우리 자신을 속이며 또 진리가 우리 속에 있지 아니하니라.", "web": "If we say that we have no sin, we deceive ourselves, and the truth is not in us."}}, {"id": 672, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "목표 중심"], "book": "잠언", "chap": 13, "verse": "19", "ref": "잠언 13:19", "texts": {"krv": "소원을 성취하면 마음에 달아도 미련한 자는 악에서 떠나기를 싫어하느니라", "kkjv": "혼에게는 성취된 소원이 달거니와 어리석은 자들에게는 악에서 떠나는 것이 가증한 것이니라.", "web": "Longing fulfilled is sweet to the soul, but fools detest turning from evil."}}, {"id": 673, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "목표 중심"], "book": "이사야", "chap": 43, "verse": "18", "ref": "이사야 43:18", "texts": {"krv": "너희는 이전 일을 기억하지 말며 옛적 일을 생각하지 말라", "kkjv": "¶너희는 이전 일들을 기억하지 말며 옛날 일들을 깊이 생각하지 말라.", "web": "“Don’t remember the former things, and don’t consider the things of old."}}, {"id": 674, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "목표 중심"], "book": "이사야", "chap": 62, "verse": "1", "ref": "이사야 62:1", "texts": {"krv": "나는 시온의 공의가 빛 같이 예루살렘의 구원이 횃불 같이 나타나도록 시온을 위하여 잠잠하지 아니하며 예루살렘을 위하여 쉬지 아니할 것인즉", "kkjv": "시온의 의가 광채같이, 예루살렘의 구원이 타는 등불같이 나아갈 때까지 내가 시온을 위해 잠잠하지 아니하며 예루살렘을 위해 안식하지 아니하리니", "web": "For Zion’s sake will I not hold my peace, and for Jerusalem’s sake I will not rest, until her righteousness go out as brightness, and her salvation as a lamp that burns."}}, {"id": 675, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "목표 중심"], "book": "고린도전서", "chap": 9, "verse": "26", "ref": "고린도전서 9:26", "texts": {"krv": "그러므로 내가 달음질하기를 향방 없는것 같이 아니하고 싸우기를 허공을 치는것 같이 아니하여", "kkjv": "그러므로 내가 이와 같이 달리되 정해진 것이 없는 것처럼 하지 아니하고 또 이와 같이 싸우되 허공을 치는 자같이 하지 아니하며", "web": "I therefore run like that, as not uncertainly. I fight like that, as not beating the air,"}}, {"id": 676, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "목표 중심"], "book": "빌립보서", "chap": 3, "verse": "12", "ref": "빌립보서 3:12", "texts": {"krv": "내가 이미 얻었다 함도 아니요 온전히 이루었다 함도 아니라 오직 내가 그리스도 예수께 잡힌 바 된 그것을 잡으려고 좇아가노라", "kkjv": "나는 내가 이미 도달한 것처럼 말하지 아니하며 이미 완전한 것처럼 말하지도 아니하고 다만 그리스도 예수님께서 나를 붙잡아 이루시고자 하신 그것을 붙잡으려고 뒤따라가노라.", "web": "Not that I have already obtained, or am already made perfect; but I press on, if it is so that I may take hold of that for which also I was taken hold of by Christ Jesus."}}, {"id": 677, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "목표 중심"], "book": "빌립보서", "chap": 3, "verse": "14", "ref": "빌립보서 3:14", "texts": {"krv": "푯대를 향하여 그리스도 예수 안에서 하나님이 위에서 부르신 부름의 상을 위하여 좇아가노라", "kkjv": "그리스도 예수님 안에서 하나님의 높은 부르심의 상을 받으려고 푯대를 향해 밀고 나아가노라.", "web": "I press on toward the goal for the prize of the high calling of God in Christ Jesus."}}, {"id": 678, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "지혜로움"], "book": "열왕기상", "chap": 3, "verse": "9", "ref": "열왕기상 3:9", "texts": {"krv": "누가 주의 이 많은 백성을 재판할 수 있사오리이까 지혜로운 마음을 종에게 주사 주의 백성을 재판하여 선악을 분별하게 하옵소서", "kkjv": "그러므로 주의 백성을 재판하도록 주의 종에게 깨닫는 마음을 주사 내가 좋은 것과 나쁜 것을 분별하게 하옵소서. 이같이 큰 주의 백성을 누가 능히 재판하리이까? 하니라.", "web": "Give your servant therefore an understanding heart to judge your people, that I may discern between good and evil; for who is able to judge this your great people?”"}}, {"id": 679, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "지혜로움"], "book": "시편", "chap": 49, "verse": "3", "ref": "시편 49:3", "texts": {"krv": "내 입은 지혜를 말하겠고 내 마음은 명철을 묵상하리로다", "kkjv": "내 입이 지혜를 말하리니 내 마음의 묵상은 깨달음에서 나리로다.", "web": "My mouth will speak words of wisdom. My heart shall utter understanding."}}, {"id": 680, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "지혜로움"], "book": "시편", "chap": 90, "verse": "12", "ref": "시편 90:12", "texts": {"krv": "우리에게 우리 날 계수함을 가르치사 지혜의 마음을 얻게 하소서", "kkjv": "그런즉 우리에게 우리의 날수 세는 것을 가르치사 우리가 지혜에 이르도록 우리의 마음을 쓰게 하소서.", "web": "So teach us to number our days, that we may gain a heart of wisdom."}}, {"id": 681, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "지혜로움"], "book": "잠언", "chap": 3, "verse": "15", "ref": "잠언 3:15", "texts": {"krv": "지혜는 진주보다 귀하니 너의 사모하는 모든 것으로 이에 비교할 수 없도다", "kkjv": "지혜는 루비보다 귀하니 네가 바랄 수 있는 모든 것이 그것과 비교될 수 없도다.", "web": "She is more precious than rubies. None of the things you can desire are to be compared to her."}}, {"id": 682, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "지혜로움"], "book": "잠언", "chap": 3, "verse": "18-19", "ref": "잠언 3:18-19", "texts": {"krv": "지혜는 그 얻은 자에게 생명 나무라 지혜를 가진 자는 복되도다 여호와께서는 지혜로 땅을 세우셨으며 명철로 하늘을 굳게 펴셨고", "kkjv": "지혜는 그것을 붙잡는 자들에게 생명나무니 그것을 간직하는 자는 다 행복하도다. 주께서는 지혜로 땅의 기초를 놓으셨으며 명철로 하늘들을 굳게 세우셨도다.", "web": "She is a tree of life to those who lay hold of her. Happy is everyone who retains her. By wisdom Yahweh founded the earth. By understanding, he established the heavens."}}, {"id": 683, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "지혜로움"], "book": "잠언", "chap": 4, "verse": "6-7", "ref": "잠언 4:6-7", "texts": {"krv": "지혜를 버리지 말라 그가 너를 보호하리라 그를 사랑하라 그가 너를 지키리라 지혜가 제일이니 지혜를 얻으라 무릇 너의 얻은 것을 가져 명철을 얻을지니라", "kkjv": "지혜를 버리지 말라. 그리하면 그것이 너를 보존하리라. 그것을 사랑하라. 그리하면 그것이 너를 보호하리라. 지혜는 으뜸가는 것이니 그러므로 지혜를 얻으라. 네가 얻은 모든 것으로 명철을 얻을지니라.", "web": "Don’t forsake her, and she will preserve you. Love her, and she will keep you. Wisdom is supreme. Get wisdom. Yes, though it costs all your possessions, get understanding."}}, {"id": 684, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "지혜로움"], "book": "잠언", "chap": 9, "verse": "10", "ref": "잠언 9:10", "texts": {"krv": "여호와를 경외하는 것이 지혜의 근본이요 거룩하신 자를 아는 것이 명철이니라", "kkjv": "주를 두려워하는 것이 지혜의 시작이요, 거룩한 것들을 아는 것이 명철이니", "web": "The fear of Yahweh is the beginning of wisdom. The knowledge of the Holy One is understanding."}}, {"id": 685, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "지혜로움"], "book": "잠언", "chap": 10, "verse": "23", "ref": "잠언 10:23", "texts": {"krv": "미련한 자는 행악으로 낙을 삼는것 같이 명철한 자는 지혜로 낙을 삼느니라", "kkjv": "해악을 행하는 것이 어리석은 자에게는 오락과 같으나 명철한 자에게는 지혜가 있느니라.", "web": "It is a fool’s pleasure to do wickedness, but wisdom is a man of understanding’s pleasure."}}, {"id": 686, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "지혜로움"], "book": "전도서", "chap": 7, "verse": "14", "ref": "전도서 7:14", "texts": {"krv": "형통한 날에는 기뻐하고 곤고한 날에는 생각하라 하나님이 이 두 가지를 병행하게 하사 사람으로 그 장래 일을 능히 헤아려 알지 못하게 하셨느니라", "kkjv": "형통하는 날에는 기뻐하되 역경을 당하는 날에는 깊이 생각하라. 하나님께서 또한 이것과 저것을 마주보게 두신 것은 사람이 자기 뒤에 일어날 일을 찾지 못하게 하려 하심이로다.", "web": "In the day of prosperity be joyful, and in the day of adversity consider; yes, God has made the one side by side with the other, to the end that man should not find out anything after him."}}, {"id": 687, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "지혜로움"], "book": "고린도전서", "chap": 3, "verse": "18", "ref": "고린도전서 3:18", "texts": {"krv": "아무도 자기를 속이지 말라 너희 중에 누구든지 이 세상에서 지혜 있는 줄로 생각하거든 미련한 자가 되어라 그리하여야 지혜로운 자가 되리라", "kkjv": "아무도 자신을 속이지 말라. 너희 가운데서 누구든지 이 세상에서 지혜로운 것처럼 보이려거든 어리석은 자가 되라. 그리하여야 그가 지혜로운 자가 되리라.", "web": "Let no one deceive himself. If anyone thinks that he is wise among you in this world, let him become a fool, that he may become wise."}}, {"id": 688, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "지혜로움"], "book": "고린도전서", "chap": 14, "verse": "20", "ref": "고린도전서 14:20", "texts": {"krv": "형제들아 지혜에는 아이가 되지 말고 악에는 어린 아이가 되라 지혜에 장성한 사람이 되라", "kkjv": "형제들아, 이해하는 일에는 아이가 되지 말라. 너희가 오직 악한 일에는 아이가 될지라도 이해하는 일에는 어른이 될지니라.", "web": "Brothers, don’t be children in thoughts, yet in malice be babies, but in thoughts be mature."}}, {"id": 689, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "지혜로움"], "book": "에베소서", "chap": 5, "verse": "15-16", "ref": "에베소서 5:15-16", "texts": {"krv": "그런즉 너희가 어떻게 행할 것을 자세히 주의하여 지혜 없는 자 같이 말고 오직 지혜 있는 자 같이 하여 세월을 아끼라 때가 악하니라", "kkjv": "그런즉 너희는 주의하여 어리석은 자가 아니라 지혜로운 자로서 조심스럽게 걸어 시간을 되찾으라. 날들이 악하니라.", "web": "Therefore watch carefully how you walk, not as unwise, but as wise; redeeming the time, because the days are evil."}}, {"id": 690, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "바로 잡아 줌"], "book": "잠언", "chap": 6, "verse": "23", "ref": "잠언 6:23", "texts": {"krv": "대저 명령은 등불이요 법은 빛이요 훈계의 책망은 곧 생명의 길이라", "kkjv": "그 명령은 등불이요, 그 법은 빛이며 훈계하는 책망들은 생명의 길이니라.", "web": "For the commandment is a lamp, and the law is light. Reproofs of instruction are the way of life,"}}, {"id": 691, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "바로 잡아 줌"], "book": "잠언", "chap": 13, "verse": "24", "ref": "잠언 13:24", "texts": {"krv": "초달을 차마 못하는 자는 그 자식을 미워함이라 자식을 사랑하는 자는 근실히 징계하느니라", "kkjv": "회초리를 아끼는 자는 자기 아들을 미워하거니와 그를 사랑하는 자는 어릴 때에 그를 징계하느니라.", "web": "One who spares the rod hates his son, but one who loves him is careful to discipline him."}}, {"id": 692, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "바로 잡아 줌"], "book": "잠언", "chap": 17, "verse": "10", "ref": "잠언 17:10", "texts": {"krv": "한 마디로 총명한 자를 경계하는 것이 매 백개로 미련한 자를 때리는 것보다 더욱 깊이 박이느니라", "kkjv": "지혜로운 자를 한 번 책망하는 것이 어리석은 자를 백 번 채찍질하는 것보다 더 깊이 박히느니라.", "web": "A rebuke enters deeper into one who has understanding than a hundred lashes into a fool."}}, {"id": 693, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "바로 잡아 줌"], "book": "잠언", "chap": 23, "verse": "13", "ref": "잠언 23:13", "texts": {"krv": "아이를 훈계하지 아니치 말라 채찍으로 그를 때릴지라도 죽지 아니하리라", "kkjv": "바로잡는 것을 아이에게 금하지 말라. 네가 그를 회초리로 때릴지라도 그가 죽지 아니하리라.", "web": "Don’t withhold correction from a child. If you punish him with the rod, he will not die."}}, {"id": 694, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "바로 잡아 줌"], "book": "잠언", "chap": 27, "verse": "5-6", "ref": "잠언 27:5-6", "texts": {"krv": "면책은 숨은 사랑보다 나으니라 친구의 통책은 충성에서 말미암은 것이나 원수의 자주 입맞춤은 거짓에서 난 것이니라", "kkjv": "드러내어 꾸짖는 것이 은밀하게 사랑하는 것보다 나으니라. 친구가 주는 상처는 믿음직하나 원수의 입맞춤은 속임수가 가득하니라.", "web": "Better is open rebuke than hidden love. Faithful are the wounds of a friend; although the kisses of an enemy are profuse."}}, {"id": 695, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "바로 잡아 줌"], "book": "잠언", "chap": 28, "verse": "23", "ref": "잠언 28:23", "texts": {"krv": "사람을 경책하는 자는 혀로 아첨하는 자보다 나중에 더욱 사랑을 받느니라", "kkjv": "사람을 꾸짖는 자는 혀로 아첨하는 자보다 나중에 더 많은 호의를 얻으리라.", "web": "One who rebukes a man will afterward find more favor than one who flatters with the tongue."}}, {"id": 696, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "바로 잡아 줌"], "book": "잠언", "chap": 29, "verse": "1", "ref": "잠언 29:1", "texts": {"krv": "자주 책망을 받으면서도 목이 곧은 사람은 갑자기 패망을 당하고 피하지 못하리라", "kkjv": "자주 책망을 받으면서도 목을 굳게 하는 자는 갑자기 멸망을 당하며 또 구할 길이 없으리라.", "web": "He who is often rebuked and stiffens his neck will be destroyed suddenly, with no remedy."}}, {"id": 697, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "바로 잡아 줌"], "book": "잠언", "chap": 29, "verse": "15", "ref": "잠언 29:15", "texts": {"krv": "채찍과 꾸지람이 지혜를 주거늘 임의로 하게 버려두면 그 자식은 어미를 욕되게 하느니라", "kkjv": "회초리와 꾸짖음은 지혜를 주거니와 제멋대로 버려둔 자식은 자기 어머니에게 수치를 가져오느니라.", "web": "The rod of correction gives wisdom, but a child left to himself causes shame to his mother."}}, {"id": 698, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "바로 잡아 줌"], "book": "잠언", "chap": 29, "verse": "17", "ref": "잠언 29:17", "texts": {"krv": "네 자식을 징계하라 그리하면 그가 너를 평안하게 하겠고 또 네 마음에 기쁨을 주리라", "kkjv": "네 아들을 바로잡으라. 그리하면 그가 네게 안식을 주고 참으로 네 혼에게 기쁨을 주리라.", "web": "Correct your son, and he will give you peace; yes, he will bring delight to your soul."}}, {"id": 699, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "바로 잡아 줌"], "book": "에베소서", "chap": 5, "verse": "11", "ref": "에베소서 5:11", "texts": {"krv": "너희는 열매 없는 어두움의 일에 참예하지 말고 도리어 책망하라", "kkjv": "열매 없는 어둠의 일들에 참여하지 말고 도리어 그것들을 책망하라.", "web": "Have no fellowship with the unfruitful works of darkness, but rather even reprove them."}}, {"id": 700, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "바로 잡아 줌"], "book": "에베소서", "chap": 5, "verse": "13", "ref": "에베소서 5:13", "texts": {"krv": "그러나 책망을 받는 모든 것이 빛으로 나타나나니 나타나지는 것마다 빛이니라", "kkjv": "그러나 책망을 받는 모든 것은 빛으로 말미암아 밝히 드러나게 되나니 무엇이든지 밝히 드러나게 하는 것은 다 빛이니라.", "web": "But all things, when they are reproved, are revealed by the light, for everything that reveals is light."}}, {"id": 701, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "바로 잡아 줌"], "book": "요한계시록", "chap": 3, "verse": "19", "ref": "요한계시록 3:19", "texts": {"krv": "무릇 내가 사랑하는 자를 책망하여 징계하노니 그러므로 네가 열심을 내라 회개하라", "kkjv": "내가 사랑하는 자들을 다 책망하고 징계하노니 그런즉 열심을 내고 회개하라.", "web": "As many as I love, I reprove and chasten. Be zealous therefore, and repent."}}, {"id": 702, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자기를 부인함"], "book": "마가복음", "chap": 8, "verse": "35", "ref": "마가복음 8:35", "texts": {"krv": "누구든지 제 목숨을 구원코자 하면 잃을 것이요 누구든지 나와 복음을 위하여 제 목숨을 잃으면 구원하리라", "kkjv": "누구든지 자기 생명을 구원하려 하는 자는 그것을 잃되 누구든지 나와 복음으로 인해 자기 생명을 잃을 자는 바로 그것을 구원하리라.", "web": "For whoever wants to save his life will lose it; and whoever will lose his life for my sake and the sake of the Good News will save it."}}, {"id": 703, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자기를 부인함"], "book": "로마서", "chap": 6, "verse": "8", "ref": "로마서 6:8", "texts": {"krv": "만일 우리가 그리스도와 함께 죽었으면 또한 그와 함께 살 줄을 믿노니", "kkjv": "만일 이제 우리가 그리스도와 함께 죽었으면 또한 그분과 함께 살 줄을 믿노니", "web": "But if we died with Christ, we believe that we will also live with him;"}}, {"id": 704, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자기를 부인함"], "book": "로마서", "chap": 6, "verse": "11", "ref": "로마서 6:11", "texts": {"krv": "이와 같이 너희도 너희 자신을 죄에 대하여는 죽은 자요 그리스도 예수 안에서 하나님을 대하여는 산자로 여길지어다", "kkjv": "이와 같이 너희도 너희 자신을 죄에 대하여는 참으로 죽은 자요, 하나님께 대하여는 예수 그리스도 우리 주를 통해 산 자로 여길지어다.", "web": "Thus consider yourselves also to be dead to sin, but alive to God in Christ Jesus our Lord."}}, {"id": 705, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자기를 부인함"], "book": "고린도전서", "chap": 15, "verse": "31", "ref": "고린도전서 15:31", "texts": {"krv": "형제들아 내가 그리스도 예수 우리 주 안에서 가진 바 너희에게 대한 나의 자랑을 두고 단언하노니 나는 날마다 죽노라", "kkjv": "내가 그리스도 예수 우리 주 안에서 가진바 너희로 인한 기쁨을 두고 단언하노니 나는 날마다 죽노라.", "web": "I affirm, by the boasting in you which I have in Christ Jesus our Lord, I die daily."}}, {"id": 706, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자기를 부인함"], "book": "고린도후서", "chap": 5, "verse": "14", "ref": "고린도후서 5:14", "texts": {"krv": "그리스도의 사랑이 우리를 강권하시는도다 우리가 생각건대 한 사람이 모든 사람을 대신하여 죽었은즉 모든 사람이 죽은 것이라", "kkjv": "이는 그리스도의 사랑이 우리를 강권하기 때문이라. 우리가 이같이 판단하노니 곧 한 사람이 모든 사람을 위하여 죽었으면 모든 사람이 죽었느니라.", "web": "For the love of Christ constrains us; because we judge thus, that one died for all, therefore all died."}}, {"id": 707, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "자기를 부인함"], "book": "골로새서", "chap": 2, "verse": "20", "ref": "골로새서 2:20", "texts": {"krv": "너희가 세상의 초등 학문에서 그리스도와 함께 죽었거든 어찌하여 세상에 사는 것과 같이 의문에 순종하느냐", "kkjv": "그러므로 너희가 세상의 유치한 원리들로부터 떠나 그리스도와 함께 죽었거늘 어찌하여 세상에 살고 있는 것 같이 규례들에 복종하느냐?", "web": "If you died with Christ from the elements of the world, why, as though living in the world, do you subject yourselves to ordinances,"}}, {"id": 708, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "전심으로 행함"], "book": "열왕기상", "chap": 8, "verse": "23", "ref": "열왕기상 8:23", "texts": {"krv": "가로되 이스라엘 하나님 여호와여 상천하지에 주와 같은 신이 없나이다 주께서는 온 마음으로 주의 앞에서 행하는 종들에게 언약을 지키시고 은혜를 베푸시나이다", "kkjv": "이르되, 주 이스라엘의 하나님이여, 위로 하늘에나 아래로 땅에 주와 같은 하나님이 없나이다. 주께서는 마음을 다해 주 앞에서 걷는 주의 종들에게 언약을 지키시고 긍휼을 베푸시나이다.", "web": "and he said, “Yahweh, the God of Israel, there is no God like you, in heaven above, or on earth beneath; who keep covenant and loving kindness with your servants, who walk before you with all their heart;"}}, {"id": 709, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "전심으로 행함"], "book": "역대하", "chap": 16, "verse": "9", "ref": "역대하 16:9", "texts": {"krv": "여호와의 눈은 온 땅을 두루 감찰하사 전심으로 자기에게 향하는 자를 위하여 능력을 베푸시나니 이 일은 왕이 망령되이 행하였은즉 이 후부터는 왕에게 전쟁이 있으리이다 하매", "kkjv": "주의 눈은 온 땅을 두루 이리저리 달리며 완전한 마음으로 그분을 향하는 자들을 위하여 그분의 강하심을 보이시나니 이 일로 왕이 어리석게 행하였은즉 이제부터는 왕에게 전쟁이 있으리이다, 하매", "web": "For the eyes of Yahweh run back and forth throughout the whole earth, to show himself strong in the behalf of them whose heart is perfect toward him. Herein you have done foolishly; for from henceforth you shall have wars.”"}}, {"id": 710, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "전심으로 행함"], "book": "역대하", "chap": 17, "verse": "6", "ref": "역대하 17:6", "texts": {"krv": "저가 전심으로 여호와의 도를 행하여 산당과 아세라 목상들도 유다에서 제하였더라", "kkjv": "주의 길들 안에서 그의 마음이 고무되매 그가 또한 유다에서 산당들과 작은 숲들을 제거하였더라.", "web": "His heart was lifted up in the ways of Yahweh: and furthermore he took away the high places and the Asherah poles out of Judah."}}, {"id": 711, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "전심으로 행함"], "book": "시편", "chap": 119, "verse": "2", "ref": "시편 119:2", "texts": {"krv": "여호와의 증거를 지키고 전심으로 여호와를 구하는 자가 복이 있도다", "kkjv": "그분의 증언들을 지키고 온 마음으로 그분을 찾는 자들은 복이 있나니", "web": "Blessed are those who keep his statutes, who seek him with their whole heart."}}, {"id": 712, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "전심으로 행함"], "book": "시편", "chap": 119, "verse": "10", "ref": "시편 119:10", "texts": {"krv": "내가 전심으로 주를 찾았사오니 주의 계명에서 떠나지 말게 하소서", "kkjv": "내가 온 마음으로 주를 찾았사오니 오 내가 주의 명령들에서 떠나 방황하지 않게 하소서.", "web": "With my whole heart, I have sought you. Don’t let me wander from your commandments."}}, {"id": 713, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "전심으로 행함"], "book": "시편", "chap": 119, "verse": "69", "ref": "시편 119:69", "texts": {"krv": "교만한 자가 거짓을 지어 나를 치려하였사오나 나는 전심으로 주의 법도를 지키리이다", "kkjv": "교만한 자들이 거짓말을 꾸며 나를 치려 하였사오나 나는 내 온 마음으로 주의 훈계들을 지키리이다.", "web": "The proud have smeared a lie upon me. With my whole heart, I will keep your precepts."}}, {"id": 714, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "전심으로 행함"], "book": "예레미야", "chap": 24, "verse": "7", "ref": "예레미야 24:7", "texts": {"krv": "내가 여호와인줄 아는 마음을 그들에게 주어서 그들로 전심으로 내게 돌아오게 하리니 그들은 내 백성이 되겠고 나는 그들의 하나님이 되리라", "kkjv": "또 내가 그들에게 나를 아는 마음과 내가 주인 줄 아는 마음을 주리니 그들은 내 백성이 되고 나는 그들의 하나님이 되리라. 그들이 자기들의 온 마음으로 내게 돌아오리라.", "web": "I will give them a heart to know me, that I am Yahweh: and they shall be my people, and I will be their God; for they shall return to me with their whole heart."}}, {"id": 715, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "전심으로 행함"], "book": "고린도전서", "chap": 9, "verse": "24", "ref": "고린도전서 9:24", "texts": {"krv": "운동장에서 달음질하는 자들이 다 달아날지라도 오직 상 얻는 자는 하나인 줄을 너희가 알지 못하느냐 너희도 얻도록 이와 같이 달음질하라", "kkjv": "경주할 때에 달리는 자들이 다 달릴지라도 한 사람이 상을 받는 줄을 너희가 알지 못하느냐? 너희도 상을 받도록 이와 같이 달리라.", "web": "Don’t you know that those who run in a race all run, but one receives the prize? Run like that, that you may win."}}, {"id": 716, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "전심으로 행함"], "book": "빌립보서", "chap": 2, "verse": "16", "ref": "빌립보서 2:16", "texts": {"krv": "생명의 말씀을 밝혀 나의 달음질도 헛되지 아니하고 수고도 헛되지 아니함으로 그리스도의 날에 나로 자랑할 것이 있게 하려 함이라", "kkjv": "생명의 말씀을 제시하나니 이로써 나는 내가 헛되이 달음질하지 아니하고 헛되이 수고하지 아니한 것에 대해 그리스도의 날에 기뻐하리라.", "web": "holding up the word of life; that I may have something to boast in the day of Christ, that I didn’t run in vain nor labor in vain."}}, {"id": 717, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "전심으로 행함"], "book": "골로새서", "chap": 1, "verse": "29", "ref": "골로새서 1:29", "texts": {"krv": "이를 위하여 나도 내 속에서 능력으로 역사하시는 이의 역사를 따라 힘을 다하여 수고하노라", "kkjv": "이 일을 위해 나도 내 속에서 강력하게 일하시는 그분의 활동에 따라 싸우며 수고하노라.", "web": "for which I also labor, striving according to his working, which works in me mightily."}}, {"id": 718, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "전심으로 행함"], "book": "골로새서", "chap": 3, "verse": "17", "ref": "골로새서 3:17", "texts": {"krv": "또 무엇을 하든지 말에나 일에나 다 주 예수의 이름으로 하고 그를 힘입어 하나님 아버지께 감사하라", "kkjv": "또 너희가 말이나 행위로 무엇을 하든지 모든 것을 주 예수님의 이름으로 하며 그분을 힘입어 하나님 곧 아버지께 감사를 드리라.", "web": "Whatever you do, in word or in deed, do all in the name of the Lord Jesus, giving thanks to God the Father, through him."}}, {"id": 719, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "전심으로 행함"], "book": "골로새서", "chap": 3, "verse": "23-24", "ref": "골로새서 3:23-24", "texts": {"krv": "무슨 일을 하든지 마음을 다하여 주께 하듯 하고 사람에게 하듯 하지 말라 이는 유업의 상을 주께 받을 줄 앎이니 너희는 주 그리스도를 섬기느니라", "kkjv": "또 너희가 무슨 일을 하든지 마음을 다해 주께 하듯 하고 사람들에게 하듯 하지 말라. 너희가 상속 유업의 보상을 주에게서 받을 줄 아나니 너희는 주 그리스도를 섬기느니라.", "web": "And whatever you do, work heartily, as for the Lord, and not for men, knowing that from the Lord you will receive the reward of the inheritance; for you serve the Lord Christ."}}, {"id": 720, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "포기하지 않음"], "book": "시편", "chap": 37, "verse": "23-24", "ref": "시편 37:23-24", "texts": {"krv": "여호와께서 사람의 걸음을 정하시고 그 길을 기뻐하시나니 저는 넘어지나 아주 엎드러지지 아니함은 여호와께서 손으로 붙드심이로다", "kkjv": "주께서 선한 사람의 걸음을 정하시고 그의 길을 기뻐하시는도다. 그가 넘어질지라도 완전히 쓰러지지 아니하리니 주께서 자신의 손으로 그를 떠받치시는도다.", "web": "A man’s goings are established by Yahweh. He delights in his way. Though he stumble, he shall not fall, for Yahweh holds him up with his hand."}}, {"id": 721, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "포기하지 않음"], "book": "시편", "chap": 44, "verse": "17", "ref": "시편 44:17", "texts": {"krv": "이 모든 일이 우리에게 임하였으나 우리가 주를 잊지 아니하며 주의 언약을 어기지 아니하였나이다", "kkjv": "이 모든 일이 우리에게 임하였으나 우리가 주를 잊지 아니하였으며 주의 언약 가운데서 거짓으로 행하지 아니하였나이다.", "web": "All this has come on us, yet have we not forgotten you, Neither have we been false to your covenant."}}, {"id": 722, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "포기하지 않음"], "book": "시편", "chap": 119, "verse": "33", "ref": "시편 119:33", "texts": {"krv": "여호와여 주의 율례의 도를 내게 가르치소서 내가 끝까지 지키리이다", "kkjv": "오 주여, 주의 법규들의 길을 내게 가르치소서. 내가 끝까지 그 길을 지키리이다.", "web": "Teach me, Yahweh, the way of your statutes. I will keep them to the end."}}, {"id": 723, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "포기하지 않음"], "book": "잠언", "chap": 24, "verse": "16", "ref": "잠언 24:16", "texts": {"krv": "대저 의인은 일곱 번 넘어질지라도 다시 일어나려니와 악인은 재앙으로 인하여 엎드러지느니라", "kkjv": "의인은 일곱 번 넘어질지라도 다시 일어나려니와 사악한 자는 넘어져서 해악에 빠지리라.", "web": "for a righteous man falls seven times, and rises up again; but the wicked are overthrown by calamity."}}, {"id": 724, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "포기하지 않음"], "book": "고린도전서", "chap": 1, "verse": "8", "ref": "고린도전서 1:8", "texts": {"krv": "주께서 너희를 우리 주 예수 그리스도의 날에 책망할 것이 없는 자로 끝까지 견고케 하시리라", "kkjv": "그분께서 또한 너희를 끝까지 견고하게 하사 우리 주 예수 그리스도의 날에 너희가 책망 받을 것이 없게 하시리라.", "web": "who will also confirm you until the end, blameless in the day of our Lord Jesus Christ."}}, {"id": 725, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "포기하지 않음"], "book": "히브리서", "chap": 3, "verse": "14", "ref": "히브리서 3:14", "texts": {"krv": "우리가 시작할 때에 확실한 것을 끝까지 견고히 잡으면 그리스도와 함께 참여한 자가 되리라", "kkjv": "우리가 우리의 확신의 시작을 끝까지 확고히 붙들진대 우리는 그리스도께 참여한 자들이 되었느니라.", "web": "For we have become partakers of Christ, if we hold fast the beginning of our confidence firm to the end:"}}, {"id": 726, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "두려워 하지 않음"], "book": "시편", "chap": 27, "verse": "1", "ref": "시편 27:1", "texts": {"krv": "여호와는 나의 빛이요 나의 구원이시니 내가 누구를 두려워하리요 여호와는 내 생명의 능력이시니 내가 누구를 무서워하리요", "kkjv": "주는 나의 빛이요, 나의 구원이시니 내가 누구를 두려워하리요? 주는 내 생명의 힘이시니 내가 누구를 무서워하리요?", "web": "Yahweh is my light and my salvation. Whom shall I fear? Yahweh is the strength of my life. Of whom shall I be afraid?"}}, {"id": 727, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "두려워 하지 않음"], "book": "시편", "chap": 118, "verse": "6", "ref": "시편 118:6", "texts": {"krv": "여호와는 내 편이시라 내게 두려움이 없나니 사람이 내게 어찌할꼬", "kkjv": "주께서 내 편이시니 내가 두려워하지 아니하리라. 사람이 내게 무엇을 할 수 있으리요?", "web": "Yahweh is on my side. I will not be afraid. What can man do to me?"}}, {"id": 728, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "두려워 하지 않음"], "book": "잠언", "chap": 1, "verse": "33", "ref": "잠언 1:33", "texts": {"krv": "오직 나를 듣는 자는 안연히 살며 재앙의 두려움이 없이 평안하리라", "kkjv": "그러나 누구든지 내 말에 귀를 기울이는 자는 안전히 거하며 재난의 두려움에서 벗어나 평안하리로다.", "web": "But whoever listens to me will dwell securely, and will be at ease, without fear of harm.”"}}, {"id": 729, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "두려워 하지 않음"], "book": "잠언", "chap": 29, "verse": "25", "ref": "잠언 29:25", "texts": {"krv": "사람을 두려워하면 올무에 걸리게 되거니와 여호와를 의지하는 자는 안전하리라", "kkjv": "사람을 두려워하면 올무에 걸리려니와 누구든지 주를 신뢰하는 자는 안전하리라.", "web": "The fear of man proves to be a snare, but whoever puts his trust in Yahweh is kept safe."}}, {"id": 730, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "두려워 하지 않음"], "book": "이사야", "chap": 41, "verse": "14", "ref": "이사야 41:14", "texts": {"krv": "지렁이 같은 너 야곱아 너희 이스라엘 사람들아 두려워 말라 나 여호와가 말하노니 내가 너를 도울 것이라 네 구속자는 이스라엘의 거룩한 자니라", "kkjv": "너 벌레 야곱아, 너희 이스라엘 사람들아, 두려워하지 말라. 내가 너를 도우리라. 주 곧 네 구속자, 이스라엘의 거룩한 이가 말하노라.", "web": "Don’t be afraid, you worm Jacob, and you men of Israel. I will help you,” says Yahweh, “and your Redeemer is the Holy One of Israel."}}, {"id": 731, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "두려워 하지 않음"], "book": "마태복음", "chap": 10, "verse": "28", "ref": "마태복음 10:28", "texts": {"krv": "몸은 죽여도 영혼은 능히 죽이지 못하는 자들을 두려워하지 말고 오직 몸과 영혼을 능히 지옥에 멸하시는 자를 두려워하라", "kkjv": "몸은 죽여도 혼은 능히 죽이지 못하는 자들을 두려워하지 말고 오직 혼과 몸을 다 능히 지옥에서 멸하시는 분을 두려워하라.", "web": "Don’t be afraid of those who kill the body, but are not able to kill the soul. Rather, fear him who is able to destroy both soul and body in Gehenna."}}, {"id": 732, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Loyalty"], "book": "잠언", "chap": 25, "verse": "13", "ref": "잠언 25:13", "texts": {"krv": "충성된 사자는 그를 보낸 이에게 마치 추수하는 날에 얼음 냉수 같아서 능히 그 주인의 마음을 시원케 하느니라", "kkjv": "신실한 사자(使者)는 그를 보낸 자들에게 마치 수확 때에 내린 차가운 눈 같으니 그는 자기 주인들의 혼을 시원하게 하느니라.", "web": "As the cold of snow in the time of harvest, so is a faithful messenger to those who send him; for he refreshes the soul of his masters."}}, {"id": 733, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Loyalty"], "book": "로마서", "chap": 16, "verse": "4", "ref": "로마서 16:4", "texts": {"krv": "저희는 내 목숨을 위하여 자기의 목이라도 내어 놓았나니 나뿐 아니라 이방인의 모든 교회도 저희에게 감사하느니라", "kkjv": "그들은 내 생명을 위하여 자기 목까지도 내놓았나니 나뿐만 아니라 이방인들의 모든 교회들도 그들에게 감사하느니라.", "web": "who for my life, laid down their own necks; to whom not only I give thanks, but also all the assemblies of the Gentiles."}}, {"id": 734, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Loyalty"], "book": "갈라디아서", "chap": 6, "verse": "6", "ref": "갈라디아서 6:6", "texts": {"krv": "가르침을 받는 자는 말씀을 가르치는 자와 모든 좋은 것을 함께 하라", "kkjv": "말씀 안에서 가르침을 받는 자는 가르치는 자와 함께 모든 좋은 것을 나눌지니라.", "web": "But let him who is taught in the word share all good things with him who teaches."}}, {"id": 735, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Loyalty"], "book": "빌립보서", "chap": 2, "verse": "30", "ref": "빌립보서 2:30", "texts": {"krv": "저가 그리스도의 일을 위하여 죽기에 이르러도 자기 목숨을 돌아보지 아니한 것은 나를 섬기는 너희의 일에 부족함을 채우려 함이니라", "kkjv": "나를 섬기는 일에서 너희의 부족한 것을 공급하기 위해 그가 자기 생명을 돌보지 아니하고 그리스도의 일을 위하여 거의 죽기에 이르렀느니라.", "web": "because for the work of Christ he came near to death, risking his life to supply that which was lacking in your service toward me."}}, {"id": 736, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Loyalty"], "book": "데살로니가전서", "chap": 5, "verse": "12-13", "ref": "데살로니가전서 5:12-13", "texts": {"krv": "형제들아 우리가 너희에게 구하노니 너희 가운데서 수고하고 주 안에서 너희를 다스리며 권하는 자들을 너희가 알고 저의 역사로 말미암아 사랑 안에서 가장 귀히 여기며 너희끼리 화목하라", "kkjv": "형제들아, 우리가 너희에게 간청하노니 너희 가운데서 수고하고 주 안에서 너희를 감독하며 너희에게 훈계하는 자들을 알고 그들의 일로 인하여 사랑 안에서 그들을 매우 귀중히 여기라. 또 너희끼리 화목하게 지내라.", "web": "But we beg you, brothers, to know those who labor among you, and are over you in the Lord, and admonish you, and to respect and honor them in love for their work’s sake.   Be at peace among yourselves."}}, {"id": 737, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Loyalty"], "book": "디모데후서", "chap": 1, "verse": "16-17", "ref": "디모데후서 1:16-17", "texts": {"krv": "원컨대 주께서 오네시보로의 집에 긍휼을 베푸시옵소서 저가 나를 자주 유쾌케 하고 나의 사슬에 매인 것을 부끄러워 아니하여 로마에 있을 때에 나를 부지런히 찾아 만났느니라", "kkjv": "주께서 오네시보로의 집에 긍휼을 베푸시기 원하노니 그가 자주 나를 유쾌하게 하고 나의 사슬을 부끄러워하지 아니하였으며 오히려 그가 로마에 있었을 때에는 매우 부지런히 나를 찾아내어 만났느니라.", "web": "May the Lord grant mercy to the house of Onesiphorus, for he often refreshed me, and was not ashamed of my chain, but when he was in Rome, he sought me diligently, and found me"}}, {"id": 738, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "One Heart"], "book": "사무엘상", "chap": 14, "verse": "7", "ref": "사무엘상 14:7", "texts": {"krv": "병기 든 자가 그에게 이르되 당신의 마음에 있는 대로 다 행하여 앞서 가소서 내가 당신과 마음을 같이 하여 따르리이다", "kkjv": "그의 병기 드는 자가 그에게 이르되, 당신의 마음속에 있는 모든 것을 행하시오며 몸을 돌이키소서. 보소서, 당신의 마음에 따라 내가 당신과 함께하나이다, 하니라.", "web": "His armor bearer said to him, “Do all that is in your heart. Turn and, behold, I am with you according to your heart.”"}}, {"id": 739, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "One Heart"], "book": "아모스", "chap": 3, "verse": "3", "ref": "아모스 3:3", "texts": {"krv": "두 사람이 의합지 못하고야 어찌 동행하겠으며", "kkjv": "두 사람이 합의하지 아니하고서야 함께 걸을 수 있겠느냐?", "web": "Do two walk together, unless they have agreed?"}}, {"id": 740, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "One Heart"], "book": "요한복음", "chap": 17, "verse": "21-22", "ref": "요한복음 17:21-22", "texts": {"krv": "아버지께서 내 안에 내가 아버지 안에 있는것 같이 저희도 다 하나가 되어 우리 안에 있게 하사 세상으로 아버지께서 나를 보내신 것을 믿게 하옵소서 내게 주신 영광을 내가 저희에게 주었사오니 이는 우리가 하나가 된것 같이 저희도 하나가 되게 하려 함이니이다", "kkjv": "이것은 그들이 다 하나가 되게 하려 함이니이다. 아버지여, 아버지께서 내 안에, 내가 아버지 안에 있는 것 같이 그들도 우리 안에서 하나가 되게 하사 아버지께서 나를 보내신 것을 세상이 믿게 하옵소서. 아버지께서 내게 주신 영광을 내가 그들에게 주었사오니 이것은 우리가 하나인 것 같이 그들도 하나가 되게 하려 함이니이다.", "web": "that they may all be one; even as you, Father, are in me, and I in you, that they also may be one in us; that the world may believe that you sent me. The glory which you have given me, I have given to them; that they may be one, even as we are one;"}}, {"id": 741, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "One Heart"], "book": "사도행전", "chap": 13, "verse": "22", "ref": "사도행전 13:22", "texts": {"krv": "폐하시고 다윗을 왕으로 세우시고 증거하여 가라사대 내가 이새의 아들 다윗을 만나니 내 마음에 합한 사람이라 내 뜻을 다 이루게 하리라 하시더니", "kkjv": "그를 폐하시고 그들을 위해 다윗을 일으키사 그들의 왕이 되게 하시며 또 그에 대해 증언하여 이르시되, 내가 이새의 아들 다윗을 찾아내었는데 그는 내 마음에 맞는 사람이라. 그가 내 모든 뜻을 성취하리라, 하시고", "web": "When he had removed him, he raised up David to be their king, to whom he also testified, ‘I have found David the son of Jesse, a man after my heart, who will do all my will.’"}}, {"id": 742, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "One Heart"], "book": "고린도후서", "chap": 12, "verse": "18", "ref": "고린도후서 12:18", "texts": {"krv": "내가 디도를 권하고 함께 한 형제를 보내었으니 디도가 너희의 이를 취하더냐 우리가 동일한 성령으로 행하지 아니하더냐 동일한 보조로 하지 아니하더냐", "kkjv": "내가 디도에게 청하였고 그와 더불어 한 형제를 보내었는데 디도가 너희에게서 이득을 취하더냐? 우리가 같은 영 안에서 걷지 아니하더냐? 우리가 같은 보조로 걷지 아니하더냐?", "web": "I exhorted Titus, and I sent the brother with him. Did Titus take any advantage of you? Didn’t we walk in the same spirit? Didn’t we walk in the same steps?"}}, {"id": 743, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "One Heart"], "book": "빌립보서", "chap": 2, "verse": "21-22", "ref": "빌립보서 2:21-22", "texts": {"krv": "저희가 다 자기 일을 구하고 그리스도 예수의 일을 구하지 아니하되 디모데의 연단을 너희가 아나니 자식이 아비에게 함같이 나와 함께 복음을 위하여 수고하였느니라", "kkjv": "모든 사람이 자기의 일을 추구하고 예수 그리스도의 일들을 추구하지 아니하되 오직 그의 증거를 너희가 아나니 아들이 아버지에게 하듯 그가 나와 함께 복음 안에서 섬겨 왔느니라.", "web": "For they all seek their own, not the things of Jesus Christ. But you know the proof of him, that, as a child serves a father, so he served with me in furtherance of the Good News."}}, {"id": 744, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Other First"], "book": "잠언", "chap": 3, "verse": "27", "ref": "잠언 3:27", "texts": {"krv": "네 손이 선을 베풀 힘이 있거든 마땅히 받을 자에게 배풀기를 아끼지 말며", "kkjv": "¶네 손 안에 선을 베풀 힘이 있거든 마땅히 그것을 받을 자들에게 선 베풀기를 금하지 말며", "web": "Don’t withhold good from those to whom it is due, when it is in the power of your hand to do it."}}, {"id": 745, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Other First"], "book": "잠언", "chap": 11, "verse": "24-25", "ref": "잠언 11:24-25", "texts": {"krv": "흩어 구제하여도 더욱 부하게 되는 일이 있나니 과도히 아껴도 가난하게 될 뿐이니라 구제를 좋아하는 자는 풍족하여질 것이요 남을 윤택하게 하는 자는 윤택하여지리라", "kkjv": "흩을지라도 여전히 불어나는 일이 있고 지나치게 아낄지라도 가난에 이르는 일이 있느니라. 후하게 주는 혼은 기름지게 되며 물을 대는 자는 자기도 물을 받으리라.", "web": "There is one who scatters, and increases yet more. There is one who withholds more than is appropriate, but gains poverty. The liberal soul shall be made fat. He who waters shall be watered also himself."}}, {"id": 746, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Other First"], "book": "마태복음", "chap": 7, "verse": "12", "ref": "마태복음 7:12", "texts": {"krv": "그러므로 무엇이든지 남에게 대접을 받고자 하는 대로 너희도 남을 대접하라 이것이 율법이요 선지자니라", "kkjv": "그러므로 무엇이든지 사람들이 너희에게 해 주기를 바라는 모든 것을 너희도 그들에게 그대로 하라. 이것이 율법이요, 대언자들이니라.", "web": "Therefore whatever you desire for men to do to you, you shall also do to them; for this is the law and the prophets."}}, {"id": 747, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Other First"], "book": "누가복음", "chap": 6, "verse": "38", "ref": "누가복음 6:38", "texts": {"krv": "주라 그리하면 너희에게 줄 것이니 곧 후히 되어 누르고 흔들어 넘치도록 하여 너희에게 안겨주리라 너희의 헤아리는 그 헤아림으로 너희도 헤아림을 도로 받을 것이니라", "kkjv": "주라. 그리하면 너희에게 줄 것이니 곧 후히 되어 누르고 함께 흔들고 넘치게 하여 사람들이 너희 품에 안겨 주리라. 너희가 잴 때 쓰는 바로 그 척도로 너희가 다시 평가를 받으리라, 하시니라.", "web": "“Give, and it will be given to you: good measure, pressed down, shaken together, and running over, will be given to you. For with the same measure you measure it will be measured back to you.”"}}, {"id": 748, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Other First"], "book": "고린도전서", "chap": 10, "verse": "24", "ref": "고린도전서 10:24", "texts": {"krv": "누구든지 자기의 유익을 구치 말고 남의 유익을 구하라", "kkjv": "아무도 자기 것을 구하지 말고 각각 다른 사람이 잘되기를 구하라.", "web": "Let no one seek his own, but each one his neighbor’s good."}}, {"id": 749, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Other First"], "book": "고린도전서", "chap": 10, "verse": "33", "ref": "고린도전서 10:33", "texts": {"krv": "나와 같이 모든 일에 모든 사람을 기쁘게 하여 나의 유익을 구치 아니하고 많은 사람의 유익을 구하여 저희로 구원을 얻게 하라", "kkjv": "곧 많은 사람이 구원을 받도록 내가 내 자신의 유익을 구하지 아니하고 그들의 유익을 구하면서 모든 일에서 모든 사람을 기쁘게 하는 것 같이 하라.", "web": "even as I also please all men in all things, not seeking my own profit, but the profit of the many, that they may be saved."}}, {"id": 750, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Communication"], "book": "잠언", "chap": 15, "verse": "22", "ref": "잠언 15:22", "texts": {"krv": "의논이 없으면 경영이 파하고 모사가 많으면 경영이 성립하느니라", "kkjv": "조언이 없으면 계획들이 실패하되 조언자가 많으면 그것들이 굳게 서느니라.", "web": "Where there is no counsel, plans fail; but in a multitude of counselors they are established."}}, {"id": 751, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Communication"], "book": "잠언", "chap": 20, "verse": "18", "ref": "잠언 20:18", "texts": {"krv": "무릇 경영은 의논함으로 성취하나니 모략을 베풀고 전쟁할지니라", "kkjv": "모든 목적한 바가 의논함으로 굳게 세워지나니 좋은 충고를 가지고 전쟁할지니라.", "web": "Plans are established by advice; by wise guidance you wage war!"}}, {"id": 752, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Communication"], "book": "잠언", "chap": 24, "verse": "6", "ref": "잠언 24:6", "texts": {"krv": "너는 모략으로 싸우라 승리는 모사가 많음에 있느니라", "kkjv": "너는 지혜로운 조언으로 전쟁을 할지니라. 조언자가 많으면 안전하니라.", "web": "for by wise guidance you wage your war; and victory is in many advisors."}}, {"id": 753, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Communication"], "book": "잠언", "chap": 25, "verse": "25", "ref": "잠언 25:25", "texts": {"krv": "먼 땅에서 오는 좋은 기별은 목마른 사람에게 냉수 같으니라", "kkjv": "먼 나라에서 오는 좋은 소식은 목마른 혼에게 냉수 같으니라.", "web": "Like cold water to a thirsty soul, so is good news from a far country."}}, {"id": 754, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Communication"], "book": "마가복음", "chap": 6, "verse": "30", "ref": "마가복음 6:30", "texts": {"krv": "사도들이 예수께 모여 자기들의 행한 것과 가르친 것을 낱낱이 고하니", "kkjv": "사도들이 같이 예수님께 모여 모든 것 즉 자기들이 행한 것과 가르친 것을 다 그분께 고하매", "web": "The apostles gathered themselves together to Jesus, and they told him all things, whatever they had done, and whatever they had taught."}}, {"id": 755, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Communication"], "book": "고린도전서", "chap": 14, "verse": "8", "ref": "고린도전서 14:8", "texts": {"krv": "만일 나팔이 분명치 못한 소리를 내면 누가 전쟁을 예비하리요", "kkjv": "만일 나팔이 분명하지 못한 소리를 내면 누가 전쟁을 준비하리요?", "web": "For if the trumpet gave an uncertain sound, who would prepare himself for war?"}}, {"id": 756, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Fighting Spirit"], "book": "민수기", "chap": 14, "verse": "9", "ref": "민수기 14:9", "texts": {"krv": "오직 여호와를 거역하지 말라 또 그 땅 백성을 두려워하지 말라 그들은 우리 밥이라 그들의 보호자는 그들에게서 떠났고 여호와는 우리와 함께 하시느니라 그들을 두려워 말라 하나", "kkjv": "오직 너희는 주를 대적하여 반역하지 말며 또 그 땅의 백성을 두려워하지 말라. 그들은 우리의 양식이니라. 그들의 방어자는 그들에게서 떠났고 주께서는 우리와 함께 계시느니라. 그들을 두려워하지 말라, 하였으나", "web": "Only don’t rebel against Yahweh, neither fear the people of the land; for they are bread for us. Their defense is removed from over them, and Yahweh is with us. Don’t fear them.”"}}, {"id": 757, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Fighting Spirit"], "book": "신명기", "chap": 1, "verse": "21", "ref": "신명기 1:21", "texts": {"krv": "너희 하나님 여호와께서 이 땅을 너희 앞에 두셨은즉 너희 열조의 하나님 여호와께서 너희에게 이르신 대로 올라가서 얻으라 두려워 말라 주저하지 말라 한즉", "kkjv": "보라, 주 네 하나님께서 이 땅을 네 앞에 두셨은즉 주 네 조상들의 하나님께서 네게 말씀하신 대로 올라가 그것을 소유하라. 두려워하지 말라. 낙담하지 말라, 하였느니라.", "web": "Behold, Yahweh your God has set the land before you. Go up, take possession, as Yahweh, the God of your fathers, has spoken to you. Don’t be afraid, neither be dismayed.”"}}, {"id": 758, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Fighting Spirit"], "book": "신명기", "chap": 20, "verse": "8", "ref": "신명기 20:8", "texts": {"krv": "유사들은 오히려 또 백성에게 고하여 이르기를 두려워서 마음에 겁내는 자가 있느냐 그는 집으로 돌아갈지니 그 형제들의 마음도 그의 마음과 같이 떨어질까 하노라 하여", "kkjv": "또 직무 수행자들은 백성에게 더 말하여 이르기를, 두려워하며 낙심하는 자가 있느냐? 그는 가서 자기 집으로 돌아갈지니 그의 형제들의 마음도 그의 마음과 같이 약해질까 염려하노라, 하라.", "web": "The officers shall speak further to the people, and they shall say, “What man is there who is fearful and faint-hearted? Let him go and return to his house, lest his brother’s heart melt as his heart.”"}}, {"id": 759, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Fighting Spirit"], "book": "여호수아", "chap": 17, "verse": "18", "ref": "여호수아 17:18", "texts": {"krv": "그 산지도 네 것이 되리니 비록 삼림이라도 네가 개척하라 그 끝까지 네 것이 되리라 가나안 사람이 비록 철병거를 가졌고 강할지라도 네가 능히 그를 쫓아내리라", "kkjv": "그 산도 네 것이 되리라. 그것이 삼림인즉 네가 베어 내야 하리라. 그러면 그 산에서 나간 곳이 네 것이 되리니 비록 가나안 족속이 철 병거를 가졌고 강할지라도 네가 그들을 쫓아낼지니라, 하니라.", "web": "but the hill country shall be yours. Although it is a forest, you shall cut it down, and it’s farthest extent shall be yours; for you shall drive out the Canaanites, though they have chariots of iron, and though they are strong.”"}}, {"id": 760, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Fighting Spirit"], "book": "사무엘상", "chap": 17, "verse": "47", "ref": "사무엘상 17:47", "texts": {"krv": "또 여호와의 구원하심이 칼과 창에 있지 아니함을 이 무리로 알게 하리라 전쟁은 여호와께 속한 것인즉 그가 너희를 우리 손에 붙이시리라", "kkjv": "또 주께서 칼이나 창으로 구원하지 아니하심을 이 모인 온 무리가 알게 하리라. 전쟁은 주께 속한 것인즉 그분께서 너희를 우리 손에 넘겨주시리라, 하니라.", "web": "and that all this assembly may know that Yahweh doesn’t save with sword and spear: for the battle is Yahweh’s, and he will give you into our hand.”"}}, {"id": 761, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Fighting Spirit"], "book": "시편", "chap": 3, "verse": "6", "ref": "시편 3:6", "texts": {"krv": "천만 인이 나를 둘러치려 하여도 나는 두려워 아니하리이다", "kkjv": "수만의 백성이 나를 에워싸고 대적한다 하여도 내가 그들을 무서워하지 아니하리로다.", "web": "I will not be afraid of tens of thousands of people who have set themselves against me on every side."}}, {"id": 762, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Fighting Spirit"], "book": "잠언", "chap": 18, "verse": "14", "ref": "잠언 18:14", "texts": {"krv": "사람의 심령은 그 병을 능히 이기려니와 심령이 상하면 그것을 누가 일으키겠느냐", "kkjv": "사람의 영이 그의 병약함을 지탱하려니와 상처 입은 영은 누가 감당하리요?", "web": "A man’s spirit will sustain him in sickness, but a crushed spirit, who can bear?"}}, {"id": 763, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Fighting Spirit"], "book": "이사야", "chap": 50, "verse": "8", "ref": "이사야 50:8", "texts": {"krv": "나를 의롭다 하시는 이가 가까이 계시니 나와 다툴 자가 누구뇨 나와 함게 설지어다 나의 대적이 누구뇨 내게 가까이 나올지어다", "kkjv": "나를 의롭다 하시는 이가 가까이 계시니 누가 나와 다투겠느냐? 우리가 함께 일어서자. 내 대적이 누구냐? 그는 내게로 가까이 나아올지어다.", "web": "He is near who justifies me; who will bring charges against me? Let us stand up together: who is my adversary? Let him come near to me."}}, {"id": 764, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Fighting Spirit"], "book": "마태복음", "chap": 11, "verse": "12", "ref": "마태복음 11:12", "texts": {"krv": "세례 요한의 때부터 지금까지 천국은 침노를 당하나니 침노하는 자는 빼앗느니라", "kkjv": "침례자 요한의 시대로부터 지금까지 하늘의 왕국은 폭력을 당하며 폭력배들이 강제로 그것을 빼앗느니라.", "web": "From the days of John the Baptizer until now, the Kingdom of Heaven suffers violence, and the violent take it by force."}}, {"id": 765, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Fighting Spirit"], "book": "사도행전", "chap": 21, "verse": "13", "ref": "사도행전 21:13", "texts": {"krv": "바울이 대답하되 너희가 어찌하여 울어 내 마음을 상하게 하느냐 나는 주 예수의 이름을 위하여 결박받을 뿐 아니라 예루살렘에서 죽을 것도 각오하였노라 하니", "kkjv": "이에 바울이 응답하되, 너희가 무슨 뜻으로 슬피 울어 내 마음을 상하게 하느냐? 나는 주 예수님의 이름을 위해 예루살렘에서 결박당하는 것뿐 아니라 죽는 것도 각오하고 있노라, 하니", "web": "Then Paul answered, “What are you doing, weeping and breaking my heart? For I am ready not only to be bound, but also to die at Jerusalem for the name of the Lord Jesus.”"}}, {"id": 766, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Fighting Spirit"], "book": "로마서", "chap": 12, "verse": "21", "ref": "로마서 12:21", "texts": {"krv": "악에게 지지 말고 선으로 악을 이기라", "kkjv": "악에게 지지 말고 도리어 선으로 악을 이기라.", "web": "Don’t be overcome by evil, but overcome evil with good."}}, {"id": 767, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "Fighting Spirit"], "book": "디모데후서", "chap": 4, "verse": "7-8", "ref": "디모데후서 4:7-8", "texts": {"krv": "내가 선한 싸움을 싸우고 나의 달려갈 길을 마치고 믿음을 지켰으니 이제 후로는 나를 위하여 의의 면류관이 예비되었으므로 주 곧 의로우신 재판장이 그 날에 내게 주실 것이니 내게만 아니라 주의 나타나심을 사모하는 모든 자에게니라", "kkjv": "내가 선한 싸움을 싸우고 나의 달려갈 길을 마치고 믿음을 지켰은즉 이후로는 나를 위하여 의의 관(冠)이 예비되어 있나니 주 곧 의로우신 심판자께서 그 날에 그것을 내게 주실 것이요, 내게만 아니라 그분의 나타나심을 사랑하는 모든 자들에게도 주시리라.", "web": "I have fought the good fight. I have finished the course. I have kept the faith. From now on, there is stored up for me the crown of righteousness, which the Lord, the righteous judge, will give to me on that day; and not to me only, but also to all those who have loved his appearing."}}, {"id": 768, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말"], "book": "시편", "chap": 35, "verse": "28", "ref": "시편 35:28", "texts": {"krv": "나의 혀가 주의 의를 말하며 종일토록 주를 찬송하리이다", "kkjv": "그리하시면 내 혀가 주의 의를 말하며 종일토록 주를 찬양하는 말을 하리이다.", "web": "My tongue shall talk about your righteousness and about your praise all day long."}}, {"id": 769, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말"], "book": "시편", "chap": 141, "verse": "3", "ref": "시편 141:3", "texts": {"krv": "여호와여 내 입 앞에 파숫군을 세우시고 내 입술의 문을 지키소서", "kkjv": "오 주여, 내 입 앞에 파수꾼을 세우시고 내 입술의 문을 지키소서.", "web": "Set a watch, Yahweh, before my mouth. Keep the door of my lips."}}, {"id": 770, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말"], "book": "잠언", "chap": 12, "verse": "18", "ref": "잠언 12:18", "texts": {"krv": "혹은 칼로 찌름 같이 함부로 말하거니와 지혜로운 자의 혀는 양약 같으니라", "kkjv": "칼로 찌르듯이 말하는 자가 있거니와 지혜로운 자의 혀는 건강하게 하느니라.", "web": "There is one who speaks rashly like the piercing of a sword, but the tongue of the wise heals."}}, {"id": 771, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말"], "book": "잠언", "chap": 15, "verse": "23", "ref": "잠언 15:23", "texts": {"krv": "사람은 그 입의 대답으로 말미암아 기쁨을 얻나니 때에 맞은 말이 얼마나 아름다운고", "kkjv": "사람은 자기 입의 대답으로 기쁨을 누리나니 때에 맞게 한 말이 얼마나 좋은가!", "web": "Joy comes to a man with the reply of his mouth. How good is a word at the right time!"}}, {"id": 772, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말"], "book": "잠언", "chap": 15, "verse": "28", "ref": "잠언 15:28", "texts": {"krv": "의인의 마음은 대답할 말을 깊이 생각하여도 악인의 입은 악을 쏟느니라", "kkjv": "의로운 자의 마음은 대답을 하려고 연구하거니와 사악한 자의 입은 악한 것들을 쏟아 내느니라.", "web": "The heart of the righteous weighs answers, but the mouth of the wicked gushes out evil."}}, {"id": 773, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말"], "book": "잠언", "chap": 18, "verse": "2", "ref": "잠언 18:2", "texts": {"krv": "미련한 자는 명철을 기뻐하지 아니하고 자기의 의사를 드러내기만 기뻐하느니라", "kkjv": "어리석은 자는 명철을 기뻐하지 아니하며 자기 마음을 드러내기를 기뻐하느니라.", "web": "A fool has no delight in understanding, but only in revealing his own opinion."}}, {"id": 774, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말"], "book": "잠언", "chap": 18, "verse": "4", "ref": "잠언 18:4", "texts": {"krv": "명철한 사람의 입의 말은 깊은 물과 같고 지혜의 샘은 솟쳐 흐르는 내와 같으니라", "kkjv": "사람의 입의 말들은 깊은 물과 같고 지혜의 원천은 흐르는 시내와 같으니라.", "web": "The words of a man’s mouth are like deep waters. The fountain of wisdom is like a flowing brook."}}, {"id": 775, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말"], "book": "잠언", "chap": 25, "verse": "11", "ref": "잠언 25:11", "texts": {"krv": "경우에 합당한 말은 아로새긴 은쟁반에 금사과니라", "kkjv": "적절히 말한 말은 은 그림들에 있는 금 사과들 같으니라.", "web": "A word fitly spoken is like apples of gold in settings of silver."}}, {"id": 776, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말"], "book": "전도서", "chap": 12, "verse": "11", "ref": "전도서 12:11", "texts": {"krv": "지혜자의 말씀은 찌르는 채찍 같고 회중의 스승의 말씀은 잘 박힌 못 같으니 다 한 목자의 주신 바니라", "kkjv": "지혜로운 자들의 말씀들은 가시 채들 같고 집회의 스승들이 굳게 박은 못들 같나니 이것들은 한 목자께서 주신 것이니라.", "web": "The words of the wise are like goads; and like nails well fastened are words from the masters of assemblies, which are given from one shepherd."}}, {"id": 777, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말"], "book": "이사야", "chap": 50, "verse": "4", "ref": "이사야 50:4", "texts": {"krv": "주 여호와께서 학자의 혀를 내게 주사 나로 곤핍한 자를 말로 어떻게 도와줄 줄을 알게 하시고 아침마다 깨우치시되 나의 귀를 깨우치사 학자 같이 알아듣게 하시도다", "kkjv": "주 하나님께서 학식 있는 자의 혀를 내게 주사 내가 피곤한 자에게 때에 맞는 말을 할 줄 알게 하시나니 그분께서 아침마다 일깨우시되 나의 귀를 일깨우사 학식 있는 자같이 듣게 하시는도다.", "web": "The Lord Yahweh has given me the tongue of those who are taught, that I may know how to sustain with words him who is weary: he wakens morning by morning, he wakens my ear to hear as those who are taught."}}, {"id": 778, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말"], "book": "에베소서", "chap": 5, "verse": "4", "ref": "에베소서 5:4", "texts": {"krv": "누추함과 어리석은 말이나 희롱의 말이 마땅치 아니하니 돌이켜 감사하는 말을 하라", "kkjv": "또한 추잡한 것이나 어리석은 이야기나 희롱하는 말도 적합하지 아니하니 하지 말고 오히려 감사하는 말을 하라.", "web": "nor filthiness, nor foolish talking, nor jesting, which are not appropriate; but rather giving of thanks."}}, {"id": 779, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말"], "book": "야고보서", "chap": 3, "verse": "2", "ref": "야고보서 3:2", "texts": {"krv": "우리가 다 실수가 많으니 만일 말에 실수가 없는 자면 곧 온전한 사람이라 능히 온 몸도 굴레 씌우리라", "kkjv": "우리가 다 많은 것에서 실족하나니 만일 어떤 사람이 말에서 실족하지 아니하면 바로 그 사람은 완전한 사람이요 능히 온 몸도 제어하는 사람이라.", "web": "For in many things we all stumble. If anyone doesn’t stumble in word, the same is a perfect man, able to bridle the whole body also."}}, {"id": 780, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "고난"], "book": "시편", "chap": 34, "verse": "19", "ref": "시편 34:19", "texts": {"krv": "의인은 고난이 많으나 여호와께서 그 모든 고난에서 건지시는도다", "kkjv": "의로운 자의 고난이 많으나 주께서 그 모든 고난에서 그를 건지시는도다.", "web": "Many are the afflictions of the righteous, but Yahweh delivers him out of them all."}}, {"id": 781, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "고난"], "book": "시편", "chap": 66, "verse": "12", "ref": "시편 66:12", "texts": {"krv": "사람들로 우리 머리 위로 타고 가게 하셨나이다 우리가 불과 물을 통행하였더니 주께서 우리를 끌어내사 풍부한 곳에 들이셨나이다", "kkjv": "사람들로 하여금 우리의 머리 위를 타고 가게 하셨나이다. 우리가 불과 물을 통과하였사오나 주께서 우리를 꺼내사 풍요로운 곳으로 데려가셨나이다.", "web": "You allowed men to ride over our heads. We went through fire and through water, but you brought us to the place of abundance."}}, {"id": 782, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "고난"], "book": "시편", "chap": 119, "verse": "71", "ref": "시편 119:71", "texts": {"krv": "고난 당한 것이 내게 유익이라 이로 인하여 내가 주의 율례를 배우게 되었나이다", "kkjv": "고난당한 것이 내게 유익하오니 이로써 내가 주의 법규들을 배우게 되었나이다.", "web": "It is good for me that I have been afflicted, that I may learn your statutes."}}, {"id": 783, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "고난"], "book": "마태복음", "chap": 5, "verse": "11-12", "ref": "마태복음 5:11-12", "texts": {"krv": "나를 인하여 너희를 욕하고 핍박하고 거짓으로 너희를 거스려 모든 악한 말을 할 때에는 너희에게 복이 있나니 기뻐하고 즐거워하라 하늘에서 너희의 상이 큼이라 너희 전에 있던 선지자들을 이같이 핍박하였느니라", "kkjv": "나로 인해 사람들이 너희를 욕하고 핍박하며 너희를 대적하여 거짓으로 온갖 종류의 악한 것을 말할 때에 너희에게 복이 있나니 기뻐하고 크게 즐거워하라. 하늘에서 너희 보상이 크니라. 그들이 너희 전에 있던 대언자들을 이같이 핍박하였느니라.", "web": "“Blessed are you when people reproach you, persecute you, and say all kinds of evil against you falsely, for my sake. Rejoice, and be exceedingly glad, for great is your reward in heaven. For that is how they persecuted the prophets who were before you."}}, {"id": 784, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "고난"], "book": "로마서", "chap": 8, "verse": "18", "ref": "로마서 8:18", "texts": {"krv": "생각건대 현재의 고난은 장차 우리에게 나타날 영광과 족히 비교할 수 없도다", "kkjv": "내가 생각하건대 이 현 시대의 고난들은 앞으로 우리 안에 나타날 영광과 족히 비교될 수 없도다.", "web": "For I consider that the sufferings of this present time are not worthy to be compared with the glory which will be revealed toward us."}}, {"id": 785, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "고난"], "book": "고린도후서", "chap": 1, "verse": "5", "ref": "고린도후서 1:5", "texts": {"krv": "그리스도의 고난이 우리에게 넘친것 같이 우리의 위로도 그리스도로 말미암아 넘치는도다", "kkjv": "그리스도의 고난이 우리 안에 넘치는 것 같이 우리의 안위도 그리스도로 말미암아 넘치는도다.", "web": "For as the sufferings of Christ abound to us, even so our comfort also abounds through Christ."}}, {"id": 786, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "고난"], "book": "고린도후서", "chap": 4, "verse": "17", "ref": "고린도후서 4:17", "texts": {"krv": "우리의 잠시 받는 환난의 경한 것이 지극히 크고 영원한 영광의 중한 것을 우리에게 이루게 함이니", "kkjv": "우리가 잠시 받는 가벼운 고난이 우리를 위해 훨씬 더 뛰어나고 영원한 영광의 무거운 것을 이루느니라.", "web": "For our light affliction, which is for the moment, works for us more and more exceedingly an eternal weight of glory;"}}, {"id": 787, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "고난"], "book": "빌립보서", "chap": 1, "verse": "29", "ref": "빌립보서 1:29", "texts": {"krv": "그리스도를 위하여 너희에게 은혜를 주신 것은 다만 그를 믿을 뿐 아니라 또한 그를 위하여 고난도 받게 하심이라", "kkjv": "그리스도를 믿는 것뿐 아니라 그분으로 인해 고난당하는 것도 주께서 그분을 대신해서 너희에게 주셨나니", "web": "Because it has been granted to you on behalf of Christ, not only to believe in him, but also to suffer on his behalf,"}}, {"id": 788, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "고난"], "book": "골로새서", "chap": 1, "verse": "24", "ref": "골로새서 1:24", "texts": {"krv": "내가 이제 너희를 위하여 받는 괴로움을 기뻐하고 그리스도의 남은 고난을 그의 몸된 교회를 위하여 내 육체에 채우노라", "kkjv": "나는 이제 너희를 위해 내가 고난당하는 것을 기뻐하고 그리스도의 고난들 뒤에 있는 것을 그분의 몸 곧 교회를 위해 내 육체 안에 채우노라.", "web": "Now I rejoice in my sufferings for your sake, and fill up on my part that which is lacking of the afflictions of Christ in my flesh for his body’s sake, which is the assembly;"}}, {"id": 789, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "고난"], "book": "디모데후서", "chap": 1, "verse": "8", "ref": "디모데후서 1:8", "texts": {"krv": "그러므로 네가 우리 주의 증거와 또는 주를 위하여 갇힌 자 된 나를 부끄러워 말고 오직 하나님의 능력을 좇아 복음과 함께 고난을 받으라", "kkjv": "그러므로 너는 우리 주의 증언과 그분의 갇힌 자 된 나를 부끄러워하지 말고 오직 하나님의 권능에 따라 복음의 고난에 참여하는 자가 되라.", "web": "Therefore don’t be ashamed of the testimony of our Lord, nor of me his prisoner; but endure hardship for the Good News according to the power of God,"}}, {"id": 790, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "고난"], "book": "디모데후서", "chap": 3, "verse": "12", "ref": "디모데후서 3:12", "texts": {"krv": "무릇 그리스도 예수 안에서 경건하게 살고자 하는 자는 핍박을 받으리라", "kkjv": "참으로 그리스도 예수님 안에서 하나님의 뜻대로 살고자 하는 모든 자는 핍박을 받을 터이나", "web": "Yes, and all who desire to live godly in Christ Jesus will suffer persecution."}}, {"id": 791, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "고난"], "book": "베드로전서", "chap": 4, "verse": "13-14", "ref": "베드로전서 4:13-14", "texts": {"krv": "오직 너희가 그리스도의 고난에 참예하는 것으로 즐거워하라 이는 그의 영광을 나타내실 때에 너희로 즐거워하고 기뻐하게 하려 함이라 너희가 그리스도의 이름으로 욕을 받으면 복 있는 자로다 영광의 영 곧 하나님의 영이 너희 위에 계심이라", "kkjv": "오히려 너희가 그리스도의 고난에 참여하는 자가 되었으므로 기뻐하라. 이것은 그분의 영광이 드러날 때에 너희가 넘치는 기쁨으로 또한 즐거워하게 하려 함이니라. 너희가 그리스도의 이름으로 인해 비방을 받으면 행복한 자로다. 영광의 영 곧 하나님의 영께서 너희 위에 머물러 계시느니라. 그분께서 그들 편에서는 비방을 받으시나 너희 편에서는 영광을 받으시느니라.", "web": "But because you are partakers of Christ’s sufferings, rejoice; that at the revelation of his glory you also may rejoice with exceeding joy. If you are insulted for the name of Christ, you are blessed; because the Spirit of glory and of God rests on you. On their part he is blasphemed, but on your part he is glorified."}}, {"id": 792, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "섬김"], "book": "누가복음", "chap": 17, "verse": "10", "ref": "누가복음 17:10", "texts": {"krv": "이와 같이 너희도 명령 받은 것을 다 행한 후에 이르기를 우리는 무익한 종이라 우리의 하여야 할 일을 한 것뿐이라 할지니라", "kkjv": "이와 같이 너희도 명령받은 그 모든 일들을 행한 뒤에 이르기를, 우리는 무익한 종이니이다. 우리는 해야 할 우리의 의무를 하였나이다, 하라, 하시니라.", "web": "Even so you also, when you have done all the things that are commanded you, say, ‘We are unworthy servants. We have done our duty.’”"}}, {"id": 793, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "섬김"], "book": "요한복음", "chap": 12, "verse": "26", "ref": "요한복음 12:26", "texts": {"krv": "사람이 나를 섬기려면 나를 따르라 나 있는 곳에 나를 섬기는 자도 거기 있으리니 사람이 나를 섬기면 내 아버지께서 저를 귀히 여기시리라", "kkjv": "어떤 사람이 나를 섬기면 그는 나를 따를지니라. 내가 있는 곳에, 거기에 내 종도 있으리니 어떤 사람이 나를 섬기면 내 아버지께서 그를 존귀히 여기시리라.", "web": "If anyone serves me, let him follow me. Where I am, there will my servant also be. If anyone serves me, the Father will honor him."}}, {"id": 794, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "섬김"], "book": "로마서", "chap": 12, "verse": "13", "ref": "로마서 12:13", "texts": {"krv": "성도들의 쓸 것을 공급하며 손 대접하기를 힘쓰라", "kkjv": "성도들의 필요에 따라 나누어 주며 손님 대접하기를 힘쓰라.", "web": "contributing to the needs of the saints; given to hospitality."}}, {"id": 795, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "섬김"], "book": "로마서", "chap": 14, "verse": "18", "ref": "로마서 14:18", "texts": {"krv": "이로써 그리스도를 섬기는 자는 하나님께 기뻐하심을 받으며 사람에게도 칭찬을 받느니라", "kkjv": "이것들 안에서 그리스도를 섬기는 자는 하나님께서 받아 주시며 사람들에게 인정을 받느니라.", "web": "For he who serves Christ in these things is acceptable to God and approved by men."}}, {"id": 796, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "섬김"], "book": "에베소서", "chap": 6, "verse": "6-7", "ref": "에베소서 6:6-7", "texts": {"krv": "눈가림만 하여 사람을 기쁘게 하는 자처럼 하지 말고 그리스도의 종들처럼 마음으로 하나님의 뜻을 행하여 단 마음으로 섬기기를 주께 하듯 하고 사람들에게 하듯 하지 말라", "kkjv": "사람들을 기쁘게 하는 자들같이 눈으로 섬기지 말고 그리스도의 종들로서 마음으로부터 하나님의 뜻을 행하여 선한 뜻으로 섬기기를 주께 하듯 하고 사람들에게 하듯 하지 말라.", "web": "not in the way of service only when eyes are on you, as men pleasers; but as servants of Christ, doing the will of God from the heart; with good will doing service, as to the Lord, and not to men;"}}, {"id": 797, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "섬김"], "book": "히브리서", "chap": 6, "verse": "10", "ref": "히브리서 6:10", "texts": {"krv": "하나님이 불의치 아니하사 너희 행위와 그의 이름을 위하여 나타낸 사랑으로 이미 성도를 섬긴 것과 이제도 섬기는 것을 잊어버리지 아니하시느니라", "kkjv": "하나님은 불의하지 아니하사 자신의 이름을 위해 너희가 보여 준 너희의 행위와 사랑의 수고 곧 너희가 성도들을 섬겨 온 것과 또 섬기고 있는 것을 잊지 아니하시느니라.", "web": "For God is not unrighteous, so as to forget your work and the labor of love which you showed toward his name, in that you served the saints, and still do serve them."}}, {"id": 798, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순결"], "book": "욥기", "chap": 31, "verse": "1-2", "ref": "욥기 31:1-2", "texts": {"krv": "내가 내 눈과 언약을 세웠나니 어찌 처녀에게 주목하랴 그리하면 위에 계신 하나님의 내리시는 분깃이 무엇이겠으며 높은 곳에서 전능자의 주시는 산업이 무엇이겠느냐", "kkjv": "내가 내 눈과 언약을 맺었거늘 어찌하여 처녀를 생각하랴? 위에서 내려오는 하나님의 몫이 무엇이겠느냐? 높은 곳에서 내려오는 전능자의 상속 재산이 무엇이겠느냐?", "web": "“I made a covenant with my eyes, how then should I look lustfully at a young woman? For what is the portion from God above, and the heritage from the Almighty on high?"}}, {"id": 799, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순결"], "book": "시편", "chap": 24, "verse": "3-4", "ref": "시편 24:3-4", "texts": {"krv": "여호와의 산에 오를 자 누구며 그 거룩한 곳에 설 자가 누군고 곧 손이 깨끗하며 마음이 청결하며 뜻을 허탄한 데 두지 아니하며 거짓 맹세치 아니하는 자로다", "kkjv": "누가 주의 산에 오르리요? 누가 그분의 거룩한 곳에 서리요? 깨끗한 손과 순수한 마음을 가진 자 곧 헛된 것을 향해 자기 혼을 들지 아니하고 속임수로 맹세하지 아니한 자로다.", "web": "Who may ascend to Yahweh’s hill? Who may stand in his holy place? He who has clean hands and a pure heart; who has not lifted up his soul to falsehood, and has not sworn deceitfully."}}, {"id": 800, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순결"], "book": "시편", "chap": 101, "verse": "3", "ref": "시편 101:3", "texts": {"krv": "나는 비루한 것을 내 눈 앞에서 두지 아니할 것이요 배도자들의 행위를 미워하니 이것이 내게 붙접지 아니하리이다", "kkjv": "내가 사악한 것을 내 눈앞에 두지 아니하리이다. 내가 곁길로 가는 자들이 행하는 일을 미워하오니 그것이 내게 달라붙지 못하리이다.", "web": "I will set no vile thing before my eyes. I hate the deeds of faithless men. They will not cling to me."}}, {"id": 801, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순결"], "book": "시편", "chap": 119, "verse": "37", "ref": "시편 119:37", "texts": {"krv": "내 눈을 돌이켜 허탄한 것을 보지 말게 하시고 주의 도에 나를 소성케 하소서", "kkjv": "내 눈을 돌리사 허탄한 것을 보지 말게 하시며 주께서 주의 길에서 나를 살리소서.", "web": "Turn my eyes away from looking at worthless things. Revive me in your ways."}}, {"id": 802, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순결"], "book": "잠언", "chap": 22, "verse": "11", "ref": "잠언 22:11", "texts": {"krv": "마음의 정결을 사모하는 자의 입술에는 덕이 있으므로 임금이 그의 친구가 되느니라", "kkjv": "마음의 순수함을 사랑하는 자는 그의 입술의 은혜로 인하여 왕이 그의 친구가 되리로다.", "web": "He who loves purity of heart and speaks gracefully is the king’s friend."}}, {"id": 803, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순결"], "book": "잠언", "chap": 25, "verse": "4", "ref": "잠언 25:4", "texts": {"krv": "은에서 찌끼를 제하라 그리하면 장색의 쓸만한 그릇이 나올 것이요", "kkjv": "은에서 찌꺼기를 제거하라. 그리하면 정련공을 위한 그릇이 나오리라.", "web": "Take away the dross from the silver, and material comes out for the refiner;"}}, {"id": 804, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순결"], "book": "이사야", "chap": 52, "verse": "11", "ref": "이사야 52:11", "texts": {"krv": "너희는 떠날지어다 떠날지어다 거기서 나오고 부정한 것을 만지지 말지어다 그 가운데서 나올지어다 여호와의 기구를 메는 자여 스스로 정결케 할지어다", "kkjv": "¶너희는 떠날지어다. 너희는 떠날지어다. 너희는 거기서 나오고 부정한 것을 만지지 말지어다. 너희는 그녀의 한가운데서 나올지어다. 주의 기구들을 나르는 자들아, 너희는 정결할지어다.", "web": "Depart, depart, go out from there, touch no unclean thing! Go out of the midst of her! Cleanse yourselves, you who bear the vessels of Yahweh."}}, {"id": 805, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순결"], "book": "마태복음", "chap": 5, "verse": "8", "ref": "마태복음 5:8", "texts": {"krv": "마음이 청결한 자는 복이 있나니 저희가 하나님을 볼 것임이요", "kkjv": "마음이 순수한 자들은 복이 있나니 그들이 하나님을 볼 것이기 때문이요,", "web": "Blessed are the pure in heart, for they shall see God."}}, {"id": 806, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순결"], "book": "마태복음", "chap": 10, "verse": "16", "ref": "마태복음 10:16", "texts": {"krv": "보라 내가 너희를 보냄이 양을 이리 가운데 보냄과 같도다 그러므로 너희는 뱀 같이 지혜롭고 비둘기 같이 순결하라", "kkjv": "¶보라, 내가 너희를 보내는 것이 양을 이리들 가운데로 보내는 것과 같도다. 그러므로 너희는 뱀같이 지혜롭고 비둘기같이 무해하라.", "web": "“Behold, I send you out as sheep in the midst of wolves. Therefore be wise as serpents, and harmless as doves."}}, {"id": 807, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순결"], "book": "고린도후서", "chap": 11, "verse": "3", "ref": "고린도후서 11:3", "texts": {"krv": "뱀이 그 간계로 이와를 미혹케 한것 같이 너희 마음이 그리스도를 향하는 진실함과 깨끗함에서 떠나 부패할까 두려워하노라", "kkjv": "그러나 뱀이 자기의 간교함으로 이브를 속인 것 같이 어떤 방법으로든 너희 마음이 그리스도 안에 있는 단순함에서 떠나 부패될까 내가 두려워하노라.", "web": "But I am afraid that somehow, as the serpent deceived Eve in his craftiness, so your minds might be corrupted from the simplicity that is in Christ."}}, {"id": 808, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순결"], "book": "디모데후서", "chap": 2, "verse": "21", "ref": "디모데후서 2:21", "texts": {"krv": "그러므로 누구든지 이런 것에서 자기를 깨끗하게 하면 귀히 쓰는 그릇이 되어 거룩하고 주인의 쓰심에 합당하며 모든 선한 일에 예비함이 되리라", "kkjv": "그러므로 사람이 이런 것들로부터 자기를 깨끗하게 하면 존귀에 이르는 그릇 곧 거룩히 구별되어 주인이 쓰기에 합당하며 모든 선한 일에 예비된 그릇이 되리라.", "web": "If anyone therefore purges himself from these, he will be a vessel for honor, sanctified, and suitable for the master’s use, prepared for every good work."}}, {"id": 809, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "순결"], "book": "베드로전서", "chap": 1, "verse": "22", "ref": "베드로전서 1:22", "texts": {"krv": "너희가 진리를 순종함으로 너희 영혼을 깨끗하게 하여 거짓이 없이 형제를 사랑하기에 이르렀으니 마음으로 뜨겁게 피차 사랑하라", "kkjv": "너희가 성령을 통해 진리에 순종함으로 너희 혼을 깨끗하게 하여 거짓 없이 형제들을 사랑하기에 이르렀으니 순수한 마음으로 뜨겁게 서로 사랑하라.", "web": "Seeing you have purified your souls in your obedience to the truth through the Spirit in sincere brotherly affection, love one another from the heart fervently:"}}, {"id": 810, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "연단"], "book": "신명기", "chap": 8, "verse": "16", "ref": "신명기 8:16", "texts": {"krv": "네 열조도 알지 못하던 만나를 광야에서 네게 먹이셨나니 이는 다 너를 낮추시며 너를 시험하사 마침내 네게 복을 주려 하심이었느니라", "kkjv": "네 조상들이 알지 못하던 만나로 광야에서 너를 먹이셨나니 이것은 그분께서 너를 낮추시며 너를 시험하사 너의 마지막 끝에 네게 선을 행하려 하심이었느니라.", "web": "who fed you in the wilderness with manna, which your fathers didn’t know; that he might humble you, and that he might prove you, to do you good at your latter end:"}}, {"id": 811, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "연단"], "book": "욥기", "chap": 23, "verse": "10", "ref": "욥기 23:10", "texts": {"krv": "나의 가는 길을 오직 그가 아시나니 그가 나를 단련하신 후에는 내가 정금 같이 나오리라", "kkjv": "그러나 내가 가는 길을 그분께서 아시나니 그분께서 나를 단련하신 뒤에는 내가 금같이 나오리라.", "web": "But he knows the way that I take. When he has tried me, I shall come out like gold."}}, {"id": 812, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "연단"], "book": "시편", "chap": 26, "verse": "2", "ref": "시편 26:2", "texts": {"krv": "여호와여 나를 살피시고 시험하사 내 뜻과 내 마음을 단련하소서", "kkjv": "오 주여, 나를 살피시고 시험하시며 내 속 중심과 마음을 단련하소서.", "web": "Examine me, Yahweh, and prove me. Try my heart and my mind."}}, {"id": 813, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "연단"], "book": "시편", "chap": 66, "verse": "10", "ref": "시편 66:10", "texts": {"krv": "하나님이여 주께서 우리를 시험하시되 우리를 단련하시기를 은을 단련함 같이 하셨으며", "kkjv": "오 하나님이여, 주께서 우리를 시험하시되 은을 제련하는 것 같이 우리를 단련하셨나이다.", "web": "For you, God, have tested us. You have refined us, as silver is refined."}}, {"id": 814, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "연단"], "book": "잠언", "chap": 17, "verse": "3", "ref": "잠언 17:3", "texts": {"krv": "도가니는 은을 풀무는 금을 연단하거니와 여호와는 마음을 연단하시느니라", "kkjv": "도가니는 은을, 용광로는 금을 제련하거니와 주께서는 마음을 단련하시느니라.", "web": "The refining pot is for silver, and the furnace for gold, but Yahweh tests the hearts."}}, {"id": 815, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "연단"], "book": "이사야", "chap": 48, "verse": "10", "ref": "이사야 48:10", "texts": {"krv": "보라 내가 너를 연단하였으나 은처럼 하지 아니하고 너를 고난의 풀무에서 택하였노라", "kkjv": "보라, 내가 너를 단련하되 은과 함께 단련하지 아니하고 너를 고난의 용광로 속에서 택하였노라.", "web": "Behold, I have refined you, but not as silver; I have chosen you in the furnace of affliction."}}, {"id": 816, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "절제"], "book": "잠언", "chap": 10, "verse": "19", "ref": "잠언 10:19", "texts": {"krv": "말이 많으면 허물을 면키 어려우나 그 입술을 제어하는 자는 지혜가 있느니라", "kkjv": "말이 많은 곳에는 죄가 부족하지 아니하거니와 자기 입술을 금하는 자는 지혜로우니라.", "web": "In the multitude of words there is no lack of disobedience, but he who restrains his lips does wisely."}}, {"id": 817, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "절제"], "book": "잠언", "chap": 16, "verse": "32", "ref": "잠언 16:32", "texts": {"krv": "노하기를 더디하는 자는 용사보다 낫고 자기의 마음을 다스리는 자는 성을 빼앗는 자보다 나으니라", "kkjv": "분노하기를 더디 하는 자는 용사보다 낫고 자기 영을 다스리는 자는 도시를 취하는 자보다 나으니라.", "web": "One who is slow to anger is better than the mighty; one who rules his spirit, than he who takes a city."}}, {"id": 818, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "절제"], "book": "잠언", "chap": 25, "verse": "28", "ref": "잠언 25:28", "texts": {"krv": "자기의 마음을 제어하지 아니하는 자는 성읍이 무너지고 성벽이 없는 것 같으니라", "kkjv": "자기 영을 다스리지 못하는 자는 무너져 내려 성벽이 없는 도시와 같으니라.", "web": "Like a city that is broken down and without walls is a man whose spirit is without restraint."}}, {"id": 819, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "절제"], "book": "고린도전서", "chap": 9, "verse": "25", "ref": "고린도전서 9:25", "texts": {"krv": "이기기를 다투는 자마다 모든 일에 절제하나니 저희는 썩을 면류관을 얻고자 하되 우리는 썩지 아니할 것을 얻고자 하노라", "kkjv": "이기려고 애쓰는 자마다 모든 일에서 절제하나니 이제 그들은 썩을 관을 얻고자 그 일을 하되 우리는 썩지 아니할 관을 얻고자 하느니라.", "web": "Every man who strives in the games exercises self-control in all things. Now they do it to receive a corruptible crown, but we an incorruptible."}}, {"id": 820, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "절제"], "book": "디도서", "chap": 2, "verse": "12", "ref": "디도서 2:12", "texts": {"krv": "우리를 양육하시되 경건치 않은 것과 이 세상 정욕을 다 버리고 근신함과 의로움과 경건함으로 이 세상에 살고", "kkjv": "우리를 가르치시되 경건치 아니한 것과 세상에 속한 정욕들을 우리가 거부하고 이 현 세상에서 맑은 정신을 가지고 의롭게 하나님의 뜻대로 살며", "web": "instructing us to the intent that, denying ungodliness and worldly lusts, we would live soberly, righteously, and godly in this present world;"}}, {"id": 821, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "절제"], "book": "베드로전서", "chap": 5, "verse": "8", "ref": "베드로전서 5:8", "texts": {"krv": "근신하라 깨어라 너희 대적 마귀가 우는 사자 같이 두루 다니며 삼킬 자를 찾나니", "kkjv": "정신을 차리라. 깨어 있으라. 너희 대적 마귀가 울부짖는 사자같이 두루 다니며 삼킬 자를 찾나니", "web": "Be sober and self-controlled. Be watchful. Your adversary, the devil, walks around like a roaring lion, seeking whom he may devour."}}, {"id": 822, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "거룩함"], "book": "레위기", "chap": 20, "verse": "26", "ref": "레위기 20:26", "texts": {"krv": "너희는 내게 거룩할지어다 이는 나 여호와가 거룩하고 내가 또 너희로 나의 소유를 삼으려고 너희를 만민 중에서 구별하였음이니라", "kkjv": "나 주는 거룩하며 또 내가 너희를 내 소유로 삼으려고 다른 백성으로부터 구별하였으니 너희는 내게 거룩할지니라.", "web": "You shall be holy to me; for I, Yahweh, am holy, and have set you apart from the peoples, that you should be mine."}}, {"id": 823, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "거룩함"], "book": "시편", "chap": 32, "verse": "6", "ref": "시편 32:6", "texts": {"krv": "이로 인하여 무릇 경건한 자는 주를 만날 기회를 타서 주께 기도할지라 진실로 홍수가 범람할지라도 저에게 미치지 못하리이다", "kkjv": "이것을 위해 하나님을 따르는 모든 자는 주를 만날 수 있을 때에 주께 기도하리니 참으로 큰물들의 홍수 속에서도 물들이 그에게 닥치지 못하리이다.", "web": "For this, let everyone who is godly pray to you in a time when you may be found. Surely when the great waters overflow, they shall not reach to him."}}, {"id": 824, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "거룩함"], "book": "요한복음", "chap": 17, "verse": "19", "ref": "요한복음 17:19", "texts": {"krv": "또 저희를 위하여 내가 나를 거룩하게 하오니 이는 저희도 진리로 거룩함을 얻게 하려 함이니이다", "kkjv": "또 내가 그들을 위하여 내 자신을 거룩히 구별하오니 이것은 그들도 진리를 통해 거룩히 구별되게 하려 함이니이다.", "web": "For their sakes I sanctify myself, that they themselves also may be sanctified in truth."}}, {"id": 825, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "거룩함"], "book": "로마서", "chap": 6, "verse": "19", "ref": "로마서 6:19", "texts": {"krv": "너희 육신이 연약하므로 내가 사람의 예대로 말하노니 전에 너희가 너희 지체를 부정과 불법에 드려 불법에 이른것 같이 이제는 너희 지체를 의에게 종으로 드려 거룩함에 이르라", "kkjv": "너희의 육신이 연약하므로 내가 사람들의 관례대로 말하노니 전에 너희가 너희 지체를 부정함과 불법에게 종으로 내주어 불법에 이른 것 같이 이제는 너희 지체를 의에게 종으로 내주어 거룩함에 이르라.", "web": "I speak in human terms because of the weakness of your flesh, for as you presented your members as servants to uncleanness and to wickedness upon wickedness, even so now present your members as servants to righteousness for sanctification."}}, {"id": 826, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "거룩함"], "book": "로마서", "chap": 6, "verse": "22", "ref": "로마서 6:22", "texts": {"krv": "그러나 이제는 너희가 죄에게서 해방되고 하나님께 종이 되어 거룩함에 이르는 열매를 얻었으니 이 마지막은 영생이라", "kkjv": "그러나 이제는 너희가 죄로부터 해방되고 하나님께 종이 되어 거룩함에 이르는 너희의 열매를 얻었으니 그 끝은 영존하는 생명이니라.", "web": "But now, being made free from sin, and having become servants of God, you have your fruit of sanctification, and the result of eternal life."}}, {"id": 827, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "거룩함"], "book": "고린도전서", "chap": 3, "verse": "17", "ref": "고린도전서 3:17", "texts": {"krv": "누구든지 하나님의 성전을 더럽히면 하나님이 그 사람을 멸하시리라 하나님의 성전은 거룩하니 너희도 그러하니라", "kkjv": "누구든지 하나님의 성전을 더럽히면 하나님께서 그를 멸하시리니 하나님의 성전은 거룩하며 너희가 곧 그 성전이니라.", "web": "If anyone destroys the temple of God, God will destroy him; for God’s temple is holy, which you are."}}, {"id": 828, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "거룩함"], "book": "고린도후서", "chap": 7, "verse": "1", "ref": "고린도후서 7:1", "texts": {"krv": "그런즉 사랑하는 자들아 이 약속을 가진 우리가 하나님을 두려워하는 가운데서 거룩함을 온전히 이루어 육과 영의 온갖 더러운 것에서 자신을 깨끗케 하자", "kkjv": "그러므로 극진히 사랑하는 자들아, 우리가 이 약속들을 가졌은즉 하나님을 두려워하는 가운데 거룩함을 완전히 이루어 육과 영의 모든 더러움에서 우리 자신을 깨끗하게 하자.", "web": "Having therefore these promises, beloved, let us cleanse ourselves from all defilement of flesh and spirit, perfecting holiness in the fear of God."}}, {"id": 829, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "거룩함"], "book": "데살로니가전서", "chap": 4, "verse": "7-8", "ref": "데살로니가전서 4:7-8", "texts": {"krv": "하나님이 우리를 부르심은 부정케 하심이 아니요 거룩케 하심이니 그러므로 저버리는 자는 사람을 저버림이 아니요 너희에게 그의 성령을 주신 하나님을 저버림이니라", "kkjv": "하나님께서는 우리를 부정함에 이르도록 부르지 아니하시고 거룩함에 이르도록 부르셨나니 그러므로 멸시하는 자는 사람을 멸시하지 아니하고 우리에게 또한 자신의 거룩한 영을 주신 하나님을 멸시하느니라.", "web": "For God called us not for uncleanness, but in sanctification. Therefore he who rejects this doesn’t reject man, but God, who has also given his Holy Spirit to you."}}, {"id": 830, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "거룩함"], "book": "디모데후서", "chap": 3, "verse": "5", "ref": "디모데후서 3:5", "texts": {"krv": "경건의 모양은 있으나 경건의 능력은 부인하는 자니 이같은 자들에게서 네가 돌아서라", "kkjv": "하나님의 성품의 모양은 있으나 그것의 능력은 부인하리니 이런 자들에게서 돌아서라.", "web": "holding a form of godliness, but having denied its power. Turn away from these, also."}}, {"id": 831, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "거룩함"], "book": "히브리서", "chap": 12, "verse": "10", "ref": "히브리서 12:10", "texts": {"krv": "저희는 잠시 자기의 뜻대로 우리를 징계하였거니와 오직 하나님은 우리의 유익을 위하여 그의 거룩하심에 참예케 하시느니라", "kkjv": "진실로 그들은 며칠 동안 자기들이 기뻐하는 대로 우리를 징계하였거니와 그분께서는 우리의 유익을 위해 하시나니 이것은 우리가 자신의 거룩함에 참여하는 자가 되게 하려 하심이라.", "web": "For they indeed, for a few days, punished us as seemed good to them; but he for our profit, that we may be partakers of his holiness."}}, {"id": 832, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "거룩함"], "book": "히브리서", "chap": 12, "verse": "14", "ref": "히브리서 12:14", "texts": {"krv": "모든 사람으로 더불어 화평함과 거룩함을 좇으라 이것이 없이는 아무도 주를 보지 못하리라", "kkjv": "모든 사람과 더불어 화평과 거룩함을 따르라. 그것들이 없이는 아무도 주를 보지 못하리라.", "web": "Follow after peace with all men, and the sanctification without which no man will see the Lord,"}}, {"id": 833, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "거룩함"], "book": "베드로전서", "chap": 2, "verse": "5", "ref": "베드로전서 2:5", "texts": {"krv": "너희도 산 돌 같이 신령한 집으로 세워지고 예수 그리스도로 말미암아 하나님이 기쁘게 받으실 신령한 제사를 드릴 거룩한 제사장이 될찌니라", "kkjv": "너희도 살아 있는 돌들로서 영적 집으로 건축되고 예수 그리스도를 통해 하나님께서 받으실 만한 영적 희생물을 드리는 거룩한 제사장이 되었도다.", "web": "You also, as living stones, are built up as a spiritual house, to be a holy priesthood, to offer up spiritual sacrifices, acceptable to God through Jesus Christ."}}, {"id": 834, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온전함"], "book": "민수기", "chap": 14, "verse": "24", "ref": "민수기 14:24", "texts": {"krv": "오직 내 종 갈렙은 그 마음이 그들과 달라서 나를 온전히 좇았은즉 그의 갔던 땅으로 내가 그를 인도하여 들이리니 그 자손이 그 땅을 차지하리라", "kkjv": "오직 내 종 갈렙은 다른 영을 지녀 나를 온전히 따랐은즉 그가 갔던 땅으로 내가 그를 데려가리니 그의 씨가 그 땅을 소유하리라.", "web": "But my servant Caleb, because he had another spirit with him, and has followed me fully, him I will bring into the land into which he went. His seed shall possess it."}}, {"id": 835, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온전함"], "book": "역대하", "chap": 25, "verse": "2", "ref": "역대하 25:2", "texts": {"krv": "아마샤가 여호와 보시기에 정직히 행하기는 하였으나 온전한 마음으로 행치 아니하였더라", "kkjv": "그가 주의 눈앞에서 올바른 것을 행하였으나 완전한 마음으로 하지는 아니하였더라.", "web": "He did that which was right in the eyes of Yahweh, but not with a perfect heart."}}, {"id": 836, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온전함"], "book": "시편", "chap": 101, "verse": "2", "ref": "시편 101:2", "texts": {"krv": "내가 완전한 길에 주의 하오리니 주께서 언제나 내게 임하시겠나이까 내가 완전한 마음으로 내 집안에서 행하리이다", "kkjv": "내가 완전한 길 안에서 지혜롭게 행동하오리니 오 주께서 어느 때에 내게 오려 하시나이까? 내가 완전한 마음으로 내 집 안에서 걸으리이다.", "web": "I will be careful to live a blameless life. When will you come to me? I will walk within my house with a blameless heart."}}, {"id": 837, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온전함"], "book": "잠언", "chap": 11, "verse": "20", "ref": "잠언 11:20", "texts": {"krv": "마음이 패려한 자는 여호와의 미움을 받아도 행위가 온전한 자는 그의 기뻐하심을 받느니라", "kkjv": "비뚤어진 마음을 가진 자들은 주께 가증한 자들이나 자기 길에서 곧바른 자들은 그분께서 기뻐하시는 자들이니라.", "web": "Those who are perverse in heart are an abomination to Yahweh, but those whose ways are blameless are his delight."}}, {"id": 838, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온전함"], "book": "마태복음", "chap": 5, "verse": "48", "ref": "마태복음 5:48", "texts": {"krv": "그러므로 하늘에 계신 너희 아버지의 온전하심과 같이 너희도 온전하라", "kkjv": "그러므로 하늘에 계신 너희 아버지께서 완전하신 것 같이 너희도 완전하라.", "web": "Therefore you shall be perfect, just as your Father in heaven is perfect."}}, {"id": 839, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온전함"], "book": "누가복음", "chap": 6, "verse": "40", "ref": "누가복음 6:40", "texts": {"krv": "제자가 그 선생보다 높지 못하나 무릇 온전케 된 자는 그 선생과 같으리라", "kkjv": "제자가 자기 스승보다 높지 못하나 완전한 자마다 자기 스승과 같게 되리라.", "web": "A disciple is not above his teacher, but everyone when he is fully trained will be like his teacher."}}, {"id": 840, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온전함"], "book": "누가복음", "chap": 11, "verse": "36", "ref": "누가복음 11:36", "texts": {"krv": "네 온 몸이 밝아 조금도 어두운 데가 없으면 등불의 광선이 너를 비출 때와 같이 온전히 밝으리라 하시니라", "kkjv": "그러므로 네 온 몸이 빛으로 가득하고 어두운 데가 없으면 등잔불이 밝게 빛나 네게 빛을 주는 때와 같이 전체가 빛으로 가득하리라, 하시니라.", "web": "If therefore your whole body is full of light, having no part dark, it will be wholly full of light, as when the lamp with its bright shining gives you light.”"}}, {"id": 841, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온전함"], "book": "디모데전서", "chap": 6, "verse": "14", "ref": "디모데전서 6:14", "texts": {"krv": "우리 주 예수 그리스도 나타나실 때까지 점도 없고 책망받을 것도 없이 이 명령을 지키라", "kkjv": "너는 우리 주 예수 그리스도의 나타나심이 있을 때까지 점도 없고 책망 받을 것도 없이 이 명령을 지키라.", "web": "that you keep the commandment without spot, blameless, until the appearing of our Lord Jesus Christ;"}}, {"id": 842, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온전함"], "book": "데살로니가전서", "chap": 5, "verse": "23", "ref": "데살로니가전서 5:23", "texts": {"krv": "평강의 하나님이 친히 너희로 온전히 거룩하게 하시고 또 너희 온 영과 혼과 몸이 우리 주 예수 그리스도 강림하실 때에 흠없게 보전되기를 원하노라", "kkjv": "평강의 바로 그 하나님께서 너희를 온전하게 거룩히 구별하시기를 원하노라. 내가 하나님께 기도하여 너희의 온 영과 혼과 몸을 우리 주 예수 그리스도께서 오실 때까지 흠 없이 보존해 주시기를 구하노라.", "web": "May the God of peace himself sanctify you completely. May your whole spirit, soul, and body be preserved blameless at the coming of our Lord Jesus Christ."}}, {"id": 843, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온전함"], "book": "디도서", "chap": 1, "verse": "13", "ref": "디도서 1:13", "texts": {"krv": "이 증거가 참되도다 그러므로 네가 저희를 엄히 꾸짖으라 이는 저희로 하여금 믿음을 온전케 하고", "kkjv": "이 증언이 참되도다. 그러므로 그들을 엄히 꾸짖으라. 이것은 그들이 믿음 안에서 건전한 자가 되어", "web": "This testimony is true. For this cause, reprove them sharply, that they may be sound in the faith,"}}, {"id": 844, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온전함"], "book": "히브리서", "chap": 10, "verse": "22", "ref": "히브리서 10:22", "texts": {"krv": "우리가 마음에 뿌림을 받아 양심의 악을 깨닫고 몸을 맑은 물로 씻었으니 참 마음과 온전한 믿음으로 하나님께 나아가자", "kkjv": "우리 마음이 뿌림을 받아 악한 양심으로부터 벗어났고 우리 몸은 순수한 물로 씻겼으니 우리가 믿음의 충만한 확신 속에서 진실한 마음으로 가까이 다가가자.", "web": "let’s draw near with a true heart in fullness of faith, having our hearts sprinkled from an evil conscience, and having our body washed with pure water,"}}, {"id": 845, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "온전함"], "book": "베드로후서", "chap": 3, "verse": "14", "ref": "베드로후서 3:14", "texts": {"krv": "그러므로 사랑하는 자들아 너희가 이것을 바라보나니 주 앞에서 점도 없고 흠도 없이 평강 가운데서 나타나기를 힘쓰라", "kkjv": "그러므로 사랑하는 자들아, 너희가 그러한 것들을 기다리나니 너희가 점도 없고 흠도 없이 화평 중에 그분께 발견되기를 힘쓰라.", "web": "Therefore, beloved, seeing that you look for these things, be diligent to be found in peace, without defect and blameless in his sight."}}, {"id": 846, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "예비함"], "book": "잠언", "chap": 6, "verse": "8", "ref": "잠언 6:8", "texts": {"krv": "먹을 것을 여름 동안에 예비하며 추수 때에 양식을 모으느니라", "kkjv": "여름에 자기의 먹을 것을 예비하며 수확 때에 자기 양식을 모으느니라.", "web": "provides her bread in the summer, and gathers her food in the harvest."}}, {"id": 847, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "예비함"], "book": "이사야", "chap": 40, "verse": "3", "ref": "이사야 40:3", "texts": {"krv": "외치는 자의 소리여 가로되 너희는 광야에서 여호와의 길을 예비하라 사막에서 우리 하나님의 대로를 평탄케 하라", "kkjv": "¶광야에서 외치는 자의 소리가 있어 이르기를, 너희는 주의 길을 예비하라. 사막에서 우리 하나님을 위해 큰길을 곧게 만들라.", "web": "The voice of one who calls out,  “Prepare the way of Yahweh in the wilderness! Make a level highway in the desert for our God."}}, {"id": 848, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "예비함"], "book": "예레미야", "chap": 46, "verse": "3", "ref": "예레미야 46:3", "texts": {"krv": "너희는 큰 방패 작은 방패를 예비하고 나가서 싸우라", "kkjv": "너희는 작은 방패와 큰 방패를 정비하고 싸움터로 가까이 나아가라.", "web": "Prepare the buckler and shield, and draw near to battle!"}}, {"id": 849, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "예비함"], "book": "마태복음", "chap": 24, "verse": "44", "ref": "마태복음 24:44", "texts": {"krv": "이러므로 너희도 예비하고 있으라 생각지 않은 때에 인자가 오리라", "kkjv": "그러므로 너희도 준비하고 있으라. 너희가 생각하지 않는 시각에 사람의 아들이 오느니라.", "web": "Therefore also be ready, for in an hour that you don’t expect, the Son of Man will come."}}, {"id": 850, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "예비함"], "book": "마태복음", "chap": 25, "verse": "10", "ref": "마태복음 25:10", "texts": {"krv": "저희가 사러 간 동안에 신랑이 오므로 예비하였던 자들은 함께 혼인 잔치에 들어가고 문은 닫힌지라", "kkjv": "그들이 사러 간 사이에 신랑이 오므로 준비된 자들은 그와 함께 혼인 잔치에 들어가고 문이 닫히니라.", "web": "While they went away to buy, the bridegroom came, and those who were ready went in with him to the marriage feast, and the door was shut."}}, {"id": 851, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "예비함"], "book": "누가복음", "chap": 12, "verse": "36", "ref": "누가복음 12:36", "texts": {"krv": "너희는 마치 그 주인이 혼인 집에서 돌아와 문을 두드리면 곧 열어 주려고 기다리는 사람과 같이 되라", "kkjv": "너희 자신은 마치 자기 주인이 결혼식에서 돌아올 때에 그를 기다리는 사람들과 같이 되라. 그가 와서 두드리면 그들이 즉시 그에게 열어 주리라.", "web": "Be like men watching for their lord, when he returns from the marriage feast; that, when he comes and knocks, they may immediately open to him."}}, {"id": 852, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "탁월함"], "book": "창세기", "chap": 1, "verse": "31", "ref": "창세기 1:31", "texts": {"krv": "하나님이 그 지으신 모든 것을 보시니 보시기에 심히 좋았더라 저녁이 되며 아침이 되니 이는 여섯째 날이니라", "kkjv": "하나님께서 자신이 만든 모든 것을 보시니, 보라, 매우 좋았더라. 그 저녁과 아침이 여섯째 날이더라.", "web": "God saw everything that he had made, and, behold, it was very good. There was evening and there was morning, a sixth day."}}, {"id": 853, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "탁월함"], "book": "창세기", "chap": 39, "verse": "23", "ref": "창세기 39:23", "texts": {"krv": "전옥은 그의 손에 맡긴 것을 무엇이든지 돌아보지 아니하였으니 이는 여호와께서 요셉과 함께 하심이라 여호와께서 그의 범사에 형통케 하셨더라", "kkjv": "감옥의 간수는 그의 손 밑에 둔 것은 무엇이든 돌아보지 아니하였으니 이는 주께서 그와 함께 계셨기 때문이라. 주께서 그가 행한 일을 형통하게 하셨더라.", "web": "The keeper of the prison didn’t look after anything that was under his hand, because Yahweh was with him; and that which he did, Yahweh made it prosper."}}, {"id": 854, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "탁월함"], "book": "역대하", "chap": 31, "verse": "21", "ref": "역대하 31:21", "texts": {"krv": "무릇 그 행하는 모든 일 곧 하나님의 전에 수종드는 일에나 율법에나 계명에나 그 하나님을 구하고 일심으로 행하여 형통하였더라", "kkjv": "그가 자기가 시작한 모든 일 곧 하나님의 집에서 섬기는 일에서나 율법에서나 명령에서 자기 하나님을 구하고 마음을 다해 그것을 행하였고 형통하였더라.", "web": "In every work that he began in the service of God’s house, and in the law, and in the commandments, to seek his God, he did it with all his heart, and prospered."}}, {"id": 855, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "탁월함"], "book": "전도서", "chap": 10, "verse": "1", "ref": "전도서 10:1", "texts": {"krv": "죽은 파리가 향기름으로 악취가 나게 하는것 같이 적은 우매가 지혜와 존귀로 패하게 하느니라", "kkjv": "죽은 파리들이 약제사의 향유에서 지독한 냄새가 나게 만드는 것 같이 작은 어리석음도 지혜와 명예로 명성을 얻은 자를 그렇게 만드느니라.", "web": "Dead flies cause the oil of the perfumer to produce an evil odor; so does a little folly outweigh wisdom and honor."}}, {"id": 856, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "탁월함"], "book": "다니엘", "chap": 6, "verse": "4", "ref": "다니엘 6:4", "texts": {"krv": "이에 총리들과 방백들이 국사에 대하여 다니엘을 고소할 틈을 얻고자 하였으나 능히 아무 틈 아무 허물을 얻지 못하였으니 이는 그가 충성되어 아무 그릇함도 없고 아무 허물도 없음이었더라", "kkjv": "¶그때에 총리들과 통치자들이 왕국에 관하여 다니엘을 고소할 기회를 찾고자 하되 어떤 기회나 허물도 찾지 못하였더라. 그는 신실하였으므로 그에게서 어떤 실수나 허물도 찾아볼 수 없었더라.", "web": "Then the presidents and the satraps sought to find occasion against Daniel as touching the kingdom; but they could find no occasion nor fault, because he was faithful, neither was there any error or fault found in him."}}, {"id": 857, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "탁월함"], "book": "마가복음", "chap": 7, "verse": "37", "ref": "마가복음 7:37", "texts": {"krv": "사람들이 심히 놀라 가로되 그가 다 잘하였도다 귀머거리도 듣게 하고 벙어리도 말하게 한다 하니라", "kkjv": "또 한량없이 놀라 이르되, 그분께서 모든 것을 잘하셨도다. 그분께서 귀먹은 자도 듣게 하시고 말 못하는 자도 말하게 하신다, 하니라.", "web": "They were astonished beyond measure, saying, “He has done all things well. He makes even the deaf hear, and the mute speak!”"}}, {"id": 858, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "본이 됨"], "book": "고린도전서", "chap": 11, "verse": "1", "ref": "고린도전서 11:1", "texts": {"krv": "내가 그리스도를 본 받는 자 된것 같이 너희는 나를 본 받는 자 되라", "kkjv": "내가 그리스도를 따르는 자가 된 것 같이 너희도 나를 따르는 자가 되라.", "web": "Be imitators of me, even as I also am of Christ."}}, {"id": 859, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "본이 됨"], "book": "빌립보서", "chap": 4, "verse": "9", "ref": "빌립보서 4:9", "texts": {"krv": "너희는 내게 배우고 받고 듣고 본 바를 행하라 그리하면 평강의 하나님이 너희와 함께 계시리라", "kkjv": "너희가 내 안에서 배우고 받고 듣고 본 그것들을 행하라. 그리하면 평강의 하나님께서 너희와 함께 하시리라.", "web": "The things which you learned, received, heard, and saw in me: do these things, and the God of peace will be with you."}}, {"id": 860, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "본이 됨"], "book": "데살로니가전서", "chap": 1, "verse": "7", "ref": "데살로니가전서 1:7", "texts": {"krv": "그러므로 너희가 마게도냐와 아가야 모든 믿는 자의 본이 되었는지라", "kkjv": "그러므로 너희는 마케도니아와 아가야에서 믿는 모든 자들에게 본이 되었느니라.", "web": "so that you became an example to all who believe in Macedonia and in Achaia."}}, {"id": 861, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "본이 됨"], "book": "디모데전서", "chap": 1, "verse": "16", "ref": "디모데전서 1:16", "texts": {"krv": "그러나 내가 긍휼을 입은 까닭은 예수 그리스도께서 내게 먼저 일체 오래 참으심을 보이사 후에 주를 믿어 영생 얻는 자들에게 본이 되게 하려 하심이니라", "kkjv": "그러나 예수 그리스도께서 먼저 내 안에서 모든 오래 참으심을 보이사 이후에 자신을 믿어 영존하는 생명에 이르게 될 자들에게 본이 되게 하셨으니 이런 까닭으로 내가 긍휼을 얻었느니라.", "web": "However, for this cause I obtained mercy, that in me first, Jesus Christ might display all his patience, for an example of those who were going to believe in him for eternal life."}}, {"id": 862, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "본이 됨"], "book": "디모데후서", "chap": 3, "verse": "11", "ref": "디모데후서 3:11", "texts": {"krv": "핍박과 고난과 또한 안디옥과 이고니온과 루스드라에서 당한 일과 어떠한 핍박받은 것을 네가 과연 보고 알았거니와 주께서 이 모든 것 가운데서 나를 건지셨느니라", "kkjv": "안디옥과 이고니움과 루스드라에서 내게 닥친 핍박과 고난을 잘 알았으며 내가 어떠한 핍박을 견디어 냈는지 잘 알았느니라. 그러나 주께서 그 모든 것 가운데서 나를 건져 내셨느니라.", "web": "persecutions, and sufferings: those things that happened to me at Antioch, Iconium, and Lystra. I endured those persecutions. The Lord delivered me out of them all."}}, {"id": 863, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "본이 됨"], "book": "디도서", "chap": 2, "verse": "7-8", "ref": "디도서 2:7-8", "texts": {"krv": "범사에 네 자신으로 선한 일의 본을 보여 교훈의 부패치 아니함과 경건함과 책망할 것이 없는 바른 말을 하게 하라 이는 대적하는 자로 하여금 부끄러워 우리를 악하다 할 것이 없게 하려 함이라", "kkjv": "모든 일에서 네 자신을 선한 행위의 본으로 보이며 교리에서 부패하지 아니함과 신중함과 성실함을 보이고 비난 받을 수 없는 건전한 말을 하라. 이것은 반대편에 속한 자가 너희에 대하여 나쁘게 말할 것이 없으므로 부끄러움을 당하게 하려 함이라.", "web": "in all things showing yourself an example of good works; in your teaching showing integrity, seriousness, incorruptibility, and soundness of speech that can’t be condemned; that he who opposes you may be ashamed, having no evil thing to say about us."}}, {"id": 864, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "부지런함"], "book": "창세기", "chap": 31, "verse": "40", "ref": "창세기 31:40", "texts": {"krv": "내가 이와 같이 낮에는 더위를 무릅쓰고 밤에는 추위를 당하며 눈붙일 겨를도 없이 지내었나이다", "kkjv": "내가 이와 같았으니 곧 낮에는 갈증이 밤에는 서리가 나를 쇠약하게 하고 내 눈에서 잠이 떠났나이다.", "web": "This was my situation: in the day the drought consumed me, and the frost by night; and my sleep fled from my eyes."}}, {"id": 865, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "부지런함"], "book": "잠언", "chap": 10, "verse": "4-5", "ref": "잠언 10:4-5", "texts": {"krv": "손을 게으르게 놀리는 자는 가난하게 되고 손이 부지런한 자는 부하게 되느니라 여름에 거두는 자는 지혜로운 아들이나 추수 때에 자는 자는 부끄러움을 끼치는 아들이니라", "kkjv": "손을 느리게 놀리는 자는 가난하게 되나 부지런한 자의 손은 부하게 만드느니라. 여름에 거두는 자는 지혜로운 아들이나 수확 때에 잠자는 자는 수치를 끼치는 아들이니라.", "web": "He becomes poor who works with a lazy hand, but the hand of the diligent brings wealth. He who gathers in summer is a wise son, but he who sleeps during the harvest is a son who causes shame."}}, {"id": 866, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "부지런함"], "book": "잠언", "chap": 12, "verse": "24", "ref": "잠언 12:24", "texts": {"krv": "부지런한 자의 손은 사람을 다스리게 되어도 게으른 자는 부림을 받느니라", "kkjv": "부지런한 자의 손은 다스릴 것이나 게으른 자는 공세를 바치리라.", "web": "The hands of the diligent ones shall rule, but laziness ends in slave labor."}}, {"id": 867, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "부지런함"], "book": "잠언", "chap": 12, "verse": "27", "ref": "잠언 12:27", "texts": {"krv": "게으른 자는 그 잡을 것도 사냥하지 아니하나니 사람의 부귀는 부지런한 것이니라", "kkjv": "게으른 사람은 자기가 사냥해서 잡은 것도 굽지 아니하거니와 부지런한 사람의 재산은 귀중하니라.", "web": "The slothful man doesn’t roast his game, but the possessions of diligent men are prized."}}, {"id": 868, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "부지런함"], "book": "잠언", "chap": 13, "verse": "4", "ref": "잠언 13:4", "texts": {"krv": "게으른 자는 마음으로 원하여도 얻지 못하나 부지런한 자의 마음은 풍족함을 얻느니라", "kkjv": "게으른 자의 혼은 원하여도 아무것도 소유하지 못하나 부지런한 자의 혼은 기름지게 되리로다.", "web": "The soul of the sluggard desires, and has nothing, but the desire of the diligent shall be fully satisfied."}}, {"id": 869, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "부지런함"], "book": "잠언", "chap": 20, "verse": "13", "ref": "잠언 20:13", "texts": {"krv": "너는 잠자기를 좋아하지 말라 네가 빈궁하게 될까 두려우니라 네 눈을 뜨라 그리하면 양식에 족하리라", "kkjv": "잠을 사랑하지 말라. 네가 가난하게 될까 염려하노라. 네 눈을 뜨라. 그리하면 네가 빵으로 만족하리라.", "web": "Don’t love sleep, lest you come to poverty. Open your eyes, and you shall be satisfied with bread."}}, {"id": 870, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "부지런함"], "book": "잠언", "chap": 22, "verse": "29", "ref": "잠언 22:29", "texts": {"krv": "네가 자기 사업에 근실한 사람을 보았느냐 이러한 사람은 왕 앞에 설 것이요 천한 자 앞에 서지 아니하리라", "kkjv": "자기 업무에 부지런한 사람을 네가 보느냐? 그는 왕들 앞에 설 것이요, 천한 자들 앞에 서지 아니하리라.", "web": "Do you see a man skilled in his work? He will serve kings. He won’t serve obscure men."}}, {"id": 871, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "부지런함"], "book": "전도서", "chap": 11, "verse": "6", "ref": "전도서 11:6", "texts": {"krv": "너는 아침에 씨를 뿌리고 저녁에도 손을 거두지 말라 이것이 잘 될는지 저것이 잘 될는지 혹 둘이 다 잘 될는지 알지 못함이니라", "kkjv": "아침에 네 씨를 뿌리고 저녁에 네 손을 금하지 말라. 이것이 잘 될지 저것이 잘 될지 혹은 그것들 둘 다 똑같이 좋을지 네가 알지 못하느니라.", "web": "In the morning sow your seed, and in the evening don’t withhold your hand; for you don’t know which will prosper, whether this or that, or whether they both will be equally good."}}, {"id": 872, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "부지런함"], "book": "로마서", "chap": 12, "verse": "11", "ref": "로마서 12:11", "texts": {"krv": "부지런하여 게으르지 말고 열심을 품고 주를 섬기라", "kkjv": "일을 게을리 하지 말고 영이 뜨거운 가운데 주를 섬기며", "web": "not lagging in diligence; fervent in spirit; serving the Lord;"}}, {"id": 873, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "부지런함"], "book": "데살로니가전서", "chap": 4, "verse": "11", "ref": "데살로니가전서 4:11", "texts": {"krv": "또 너희에게 명한것 같이 종용하여 자기 일을 하고 너희 손으로 일하기를 힘쓰라", "kkjv": "또 우리가 너희에게 명령한 것 같이 너희는 조용히 지내며 너희 일을 하고 너희 손으로 일하기를 힘쓰라.", "web": "and that you make it your ambition to lead a quiet life, and to do your own business, and to work with your own hands, even as we instructed you;"}}, {"id": 874, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "부지런함"], "book": "디모데후서", "chap": 2, "verse": "6", "ref": "디모데후서 2:6", "texts": {"krv": "수고하는 농부가 곡식을 먼저 받는 것이 마땅하니라", "kkjv": "수고하는 농부가 열매에 맨 먼저 참여하는 자가 되어야 마땅하니라.", "web": "The farmers who labor must be the first to get a share of the crops."}}, {"id": 875, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "부지런함"], "book": "히브리서", "chap": 6, "verse": "11", "ref": "히브리서 6:11", "texts": {"krv": "우리가 간절히 원하는 것은 너희 각 사람이 동일한 부지런을 나타내어 끝까지 소망의 풍성함에 이르러", "kkjv": "우리는 너희 각 사람이 동일한 열심을 나타내어 끝까지 소망의 충만한 확신에 이르기를 바라노니", "web": "We desire that each one of you may show the same diligence to the fullness of hope even to the end,"}}, {"id": 876, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "영원한 것을 구함"], "book": "시편", "chap": 73, "verse": "26", "ref": "시편 73:26", "texts": {"krv": "내 육체와 마음은 쇠잔하나 하나님은 내 마음의 반석이시요 영원한 분깃이시라", "kkjv": "내 육체와 내 마음이 쇠약하오나 하나님은 내 마음의 힘이시요, 영원토록 내 몫이니이다.", "web": "My flesh and my heart fails, but God is the strength of my heart and my portion forever."}}, {"id": 877, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "영원한 것을 구함"], "book": "시편", "chap": 145, "verse": "13", "ref": "시편 145:13", "texts": {"krv": "주의 나라는 영원한 나라이니 주의 통치는 대대에 이르리이다", "kkjv": "주의 왕국은 영존하는 왕국이오니 주의 통치는 모든 세대에 두루 지속되리이다.", "web": "Your kingdom is an everlasting kingdom. Your dominion endures throughout all generations. Yahweh is faithful in all his words, and loving in all his deeds."}}, {"id": 878, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "영원한 것을 구함"], "book": "이사야", "chap": 26, "verse": "4", "ref": "이사야 26:4", "texts": {"krv": "너희는 여호와를 영원히 의뢰하라 주 여호와는 영원한 반석이심이로다", "kkjv": "너희는 영원토록 주를 신뢰하라. 주 여호와 안에 영존하는 능력이 있도다.", "web": "Trust in Yahweh forever; for in Yah, Yahweh, is an everlasting Rock."}}, {"id": 879, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "영원한 것을 구함"], "book": "이사야", "chap": 32, "verse": "17", "ref": "이사야 32:17", "texts": {"krv": "의의 공효는 화평이요 의의 결과는 영원한 평안과 안전이라", "kkjv": "의의 일은 화평이 되며 의의 결과는 영원토록 평온함과 확신이 되리로다.", "web": "The work of righteousness will be peace; and the effect of righteousness, quietness and confidence forever."}}, {"id": 880, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "영원한 것을 구함"], "book": "마태복음", "chap": 6, "verse": "20", "ref": "마태복음 6:20", "texts": {"krv": "오직 너희를 위하여 보물을 하늘에 쌓아두라 거기는 좀이나 동록이 해하지 못하며 도적이 구멍을 뚫지도 못하고 도적질도 못하느니라", "kkjv": "오직 너희 자신을 위해 보물을 하늘에 쌓아 두라. 거기서는 좀과 녹이 부패시키지 아니하며 거기서는 도둑들이 뚫지도 훔치지도 못하느니라.", "web": "but lay up for yourselves treasures in heaven, where neither moth nor rust consume, and where thieves don’t break through and steal;"}}, {"id": 881, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "영원한 것을 구함"], "book": "누가복음", "chap": 16, "verse": "9", "ref": "누가복음 16:9", "texts": {"krv": "내가 너희에게 말하노니 불의의 재물로 친구를 사귀라 그리하면 없어질 때에 저희가 영원한 처소로 너희를 영접하리라", "kkjv": "내가 너희에게 이르노니, 불의의 맘몬으로 너희를 위해 친구들을 사귀라. 그리하면 너희가 숨이 멎을 때에 그들이 너희를 영존하는 처소로 받아들이리라.", "web": "I tell you, make for yourselves friends by means of unrighteous mammon, so that when you fail, they may receive you into the eternal tents."}}, {"id": 882, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "영원한 것을 구함"], "book": "요한복음", "chap": 6, "verse": "27", "ref": "요한복음 6:27", "texts": {"krv": "썩은 양식을 위하여 일하지 말고 영생하도록 있는 양식을 위하여 하라 이 양식은 인자가 너희에게 주리니 인자는 아버지 하나님의 인치신 자니라", "kkjv": "썩어 없어지는 양식을 위해 수고하지 말고 영존하는 생명에 이르도록 항상 있는 그 양식을 위해 수고하라. 그것은 사람의 아들이 너희에게 주리니 그를 하나님 아버지께서 봉인하셨느니라, 하시니라.", "web": "Don’t work for the food which perishes, but for the food which remains to eternal life, which the Son of Man will give to you. For God the Father has sealed him.”"}}, {"id": 883, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "영원한 것을 구함"], "book": "고린도전서", "chap": 7, "verse": "31", "ref": "고린도전서 7:31", "texts": {"krv": "세상 물건을 쓰는 자들은 다 쓰지 못하는 자 같이 하라 이 세상의 형적은 지니감이니라", "kkjv": "이 세상을 이용하는 자들은 남용하지 않는 자처럼 되라. 이 세상의 외형은 사라지느니라.", "web": "and those who use the world, as not using it to the fullest. For the mode of this world passes away."}}, {"id": 884, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "영원한 것을 구함"], "book": "고린도후서", "chap": 4, "verse": "18", "ref": "고린도후서 4:18", "texts": {"krv": "우리의 돌아보는 것은 보이는 것이 아니요 보이지 않는 것이니 보이는 것은 잠간이요 보이지 않는 것은 영원함이니라", "kkjv": "우리는 보이는 것들을 바라보지 아니하고 보이지 아니하는 것들을 바라보나니 보이는 것들은 잠깐 있을 뿐이나 보이지 아니하는 것들은 영원하니라.", "web": "while we don’t look at the things which are seen, but at the things which are not seen. For the things which are seen are temporal, but the things which are not seen are eternal."}}, {"id": 885, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "영원한 것을 구함"], "book": "갈라디아서", "chap": 6, "verse": "8", "ref": "갈라디아서 6:8", "texts": {"krv": "자기의 육체를 위하여 심는 자는 육체로부터 썩어진 것을 거두고 성령을 위하여 심는 자는 성령으로부터 영생을 거두리라", "kkjv": "자기 육신에게 심는 자는 육신으로부터 썩는 것을 거두되 성령에게 심는 자는 성령으로부터 영존하는 생명을 거두리라.", "web": "For he who sows to his own flesh will from the flesh reap corruption. But he who sows to the Spirit will from the Spirit reap eternal life."}}, {"id": 886, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "영원한 것을 구함"], "book": "히브리서", "chap": 10, "verse": "34", "ref": "히브리서 10:34", "texts": {"krv": "너희가 갇힌 자를 동정하고 너희 산업을 빼앗기는 것도 기쁘게 당한 것은 더 낫고 영구한 산업이 있는 줄 앎이라", "kkjv": "너희에게 하늘에 더 낫고 영구한 실체가 있는 줄 너희 자신이 알므로 결박 중에 있는 나를 너희가 불쌍히 여겼고 너희 재산을 노략당하는 것도 기쁘게 여겼느니라.", "web": "For you both had compassion on me in my chains, and joyfully accepted the plundering of your possessions, knowing that you have for yourselves a better possession and an enduring one in the heavens."}}, {"id": 887, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "영원한 것을 구함"], "book": "요한일서", "chap": 2, "verse": "17", "ref": "요한일서 2:17", "texts": {"krv": "이 세상도 그 정욕도 지나가되 오직 하나님의 뜻을 행하는 이는 영원히 거하느니라", "kkjv": "세상도 그것의 정욕도 사라지되 오직 하나님의 뜻을 행하는 자는 영원토록 거하느니라.", "web": "The world is passing away with its lusts, but he who does God’s will remains forever."}}, {"id": 888, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말씀에 헌신함"], "book": "신명기", "chap": 6, "verse": "6", "ref": "신명기 6:6", "texts": {"krv": "오늘날 내가 네게 명하는 이 말씀을 너는 마음에 새기고", "kkjv": "이 날 내가 네게 명령하는 이 말씀들을 네 마음속에 두고", "web": "These words, which I command you this day, shall be on your heart;"}}, {"id": 889, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말씀에 헌신함"], "book": "시편", "chap": 19, "verse": "7-8", "ref": "시편 19:7-8", "texts": {"krv": "여호와의 율법은 완전하여 영혼을 소성케 하고 여호와의 증거는 확실하여 우둔한 자로 지혜롭게 하며 여호와의 교훈은 정직하여 마음을 기쁘게 하고 여호와의 계명은 순결하여 눈을 밝게 하도다", "kkjv": "주의 율법은 완전하여 혼을 회심시키고 주의 증언은 확실하여 단순한 자를 지혜롭게 하며 주의 법규들은 올발라서 마음을 기쁘게 하고 주의 명령은 순수하여 눈을 밝게 하는도다.", "web": "Yahweh’s law is perfect, restoring the soul. Yahweh’s testimony is sure, making wise the simple. Yahweh’s precepts are right, rejoicing the heart. Yahweh’s commandment is pure, enlightening the eyes."}}, {"id": 890, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말씀에 헌신함"], "book": "시편", "chap": 119, "verse": "6", "ref": "시편 119:6", "texts": {"krv": "내가 주의 모든 계명에 주의할 때에는 부끄럽지 아니하리이다", "kkjv": "그러면 내가 주의 모든 명령에 관심을 기울일 때에 부끄럼을 당하지 아니하리이다.", "web": "Then I wouldn’t be disappointed, when I consider all of your commandments."}}, {"id": 891, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말씀에 헌신함"], "book": "시편", "chap": 119, "verse": "50", "ref": "시편 119:50", "texts": {"krv": "이 말씀은 나의 곤란 중에 위로라 주의 말씀이 나를 살리셨음이니이다", "kkjv": "나의 고난 중에 이것이 내 위로가 되었사오니 주의 말씀이 나를 살리셨나이다.", "web": "This is my comfort in my affliction, for your word has revived me."}}, {"id": 892, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말씀에 헌신함"], "book": "시편", "chap": 119, "verse": "92-93", "ref": "시편 119:92-93", "texts": {"krv": "주의 법이 나의 즐거움이 되지 아니하였더면 내가 내 고난 중에 멸망하였으리이다 내가 주의 법도를 영원히 잊지 아니하오니 주께서 이것들로 나를 살게 하심이니이다", "kkjv": "주의 법이 나의 기쁨이 되지 아니하였더라면 내가 나의 고난 중에 멸망하였으리이다. 내가 결코 주의 훈계들을 잊지 아니하리니 주께서 그것들로 나를 살리셨나이다.", "web": "Unless your law had been my delight, I would have perished in my affliction. I will never forget your precepts, for with them, you have revived me."}}, {"id": 893, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말씀에 헌신함"], "book": "잠언", "chap": 2, "verse": "4-5", "ref": "잠언 2:4-5", "texts": {"krv": "은을 구하는것 같이 그것을 구하며 감추인 보배를 찾는것 같이 그것을 찾으면 여호와 경외하기를 깨달으며 하나님을 알게 되리니", "kkjv": "은을 구하는 것 같이 그것을 구하고 감추어진 보화들을 찾는 것 같이 그것을 찾으면 그때에 주 두려워하는 것을 깨닫고 하나님 아는 것을 발견하리니", "web": "If you seek her as silver, and search for her as for hidden treasures: then you will understand the fear of Yahweh, and find the knowledge of God."}}, {"id": 894, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말씀에 헌신함"], "book": "잠언", "chap": 13, "verse": "13", "ref": "잠언 13:13", "texts": {"krv": "말씀을 멸시하는 자는 패망을 이루고 계명을 두려워하는 자는 상을 얻느니라", "kkjv": "누구든지 말씀을 멸시하는 자는 멸망하려니와 명령을 두려워하는 자는 보상을 받으리라.", "web": "Whoever despises instruction will pay for it, but he who respects a command will be rewarded."}}, {"id": 895, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말씀에 헌신함"], "book": "이사야", "chap": 40, "verse": "8", "ref": "이사야 40:8", "texts": {"krv": "풀은 마르고 꽃은 시드나 우리 하나님의 말씀은 영영히 서리라 하라", "kkjv": "풀은 마르고 꽃은 시드나 우리 하나님의 말씀은 영원토록 서리라, 하라.", "web": "The grass withers, the flower fades; but the word of our God stands forever.”"}}, {"id": 896, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말씀에 헌신함"], "book": "이사야", "chap": 66, "verse": "2", "ref": "이사야 66:2", "texts": {"krv": "나 여호와가 말하노라 나의 손이 이 모든 것을 지어서 다 이루었느니라 무릇 마음이 가난하고 심령에 통회하며 나의 말을 인하여 떠는 자 그 사람은 내가 권고하려니와", "kkjv": "그 모든 것들을 내 손이 만들었으므로 그 모든 것들이 존재해 왔느니라. 주가 말하노라. 오직 나는 이런 사람 곧 가난하고 통회하는 영을 가진 자, 내 말에 떠는 자를 보살피리라.", "web": "For all these things has my hand made, and so all these things came to be,” says Yahweh:  “but to this man will I look, even to him who is poor and of a contrite spirit, and who trembles at my word."}}, {"id": 897, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말씀에 헌신함"], "book": "아모스", "chap": 8, "verse": "11", "ref": "아모스 8:11", "texts": {"krv": "주 여호와께서 가라사대 보라 날이 이를지라 내가 기근을 땅에 보내리니 양식이 없어 주림이 아니며 물이 없어 갈함이 아니요 여호와의 말씀을 듣지 못한 기갈이라", "kkjv": "¶주 하나님이 말하노라. 보라, 날들이 이르리니 내가 그 땅에 기근을 보내리라. 그것은 빵으로 인한 기근도 아니요 물로 인한 갈증도 아니며 오직 주의 말씀들을 듣는 것에 대한 기갈이니라.", "web": "Behold, the days come,” says the Lord Yahweh, “that I will send a famine in the land, not a famine of bread, nor a thirst for water, but of hearing Yahweh’s words."}}, {"id": 898, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말씀에 헌신함"], "book": "골로새서", "chap": 3, "verse": "16", "ref": "골로새서 3:16", "texts": {"krv": "그리스도의 말씀이 너희 속에 풍성히 거하여 모든 지혜로 피차 가르치며 권면하고 시와 찬미와 신령한 노래를 부르며 마음에 감사함으로 하나님을 찬양하고", "kkjv": "그리스도의 말씀이 너희 속에 모든 지혜로 풍부히 거하게 하여 시와 찬송가와 영적 노래로 서로 가르치고 훈계하며 너희 마음속에서 은혜로 주께 노래하고", "web": "Let the word of Christ dwell in you richly; in all wisdom teaching and admonishing one another with psalms, hymns, and spiritual songs, singing with grace in your heart to the Lord."}}, {"id": 899, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "말씀에 헌신함"], "book": "디모데후서", "chap": 2, "verse": "9", "ref": "디모데후서 2:9", "texts": {"krv": "복음을 인하여 내가 죄인과 같이 매이는 데까지 고난을 받았으나 하나님의 말씀은 매이지 아니하니라", "kkjv": "이 복음으로 인하여 내가 악을 행하는 자처럼 매이는 데까지 고난을 당하나 하나님의 말씀은 매이지 아니하느니라.", "web": "in which I suffer hardship to the point of chains as a criminal. But God’s word isn’t chained."}}, {"id": 900, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "승리"], "book": "사무엘상", "chap": 17, "verse": "45", "ref": "사무엘상 17:45", "texts": {"krv": "다윗이 블레셋 사람에게 이르되 너는 칼과 창과 단창으로 내게 오거니와 나는 만군의 여호와의 이름 곧 네가 모욕하는 이스라엘 군대의 하나님의 이름으로 네게 가노라", "kkjv": "이에 다윗이 그 블레셋 사람에게 이르되, 너는 칼과 창과 방패를 가지고 내게 오거니와 나는 네가 도전한 이스라엘 군대의 하나님 곧 만군의 주의 이름으로 네게 가노라.", "web": "Then David said to the Philistine, “You come to me with a sword, and with a spear, and with a javelin: but I come to you in the name of Yahweh of Armies, the God of the armies of Israel, whom you have defied."}}, {"id": 901, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "승리"], "book": "잠언", "chap": 21, "verse": "31", "ref": "잠언 21:31", "texts": {"krv": "싸울 날을 위하여 마병을 예비하거니와 이김은 여호와께 있느니라", "kkjv": "싸울 날에 대비하여 말을 예비해도 안전은 주에게서 오느니라.", "web": "The horse is prepared for the day of battle; but victory is with Yahweh."}}, {"id": 902, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "승리"], "book": "로마서", "chap": 8, "verse": "37", "ref": "로마서 8:37", "texts": {"krv": "그러나 이 모든 일에 우리를 사랑하시는 이로 말미암아 우리가 넉넉히 이기느니라", "kkjv": "아니라. 이 모든 것 가운데서 우리는 우리를 사랑하신 그분을 통해 정복자들보다 더 나은 자들이니라.", "web": "No, in all these things, we are more than conquerors through him who loved us."}}, {"id": 903, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "승리"], "book": "요한계시록", "chap": 2, "verse": "26", "ref": "요한계시록 2:26", "texts": {"krv": "이기는 자와 끝까지 내 일을 지키는 그에게 만국을 다스리는 권세를 주리니", "kkjv": "이기고 나의 행위를 끝까지 지키는 자에게는 내가 민족들을 다스릴 권능을 주리니", "web": "He who overcomes, and he who keeps my works to the end, to him I will give authority over the nations."}}, {"id": 904, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "승리"], "book": "요한계시록", "chap": 3, "verse": "12", "ref": "요한계시록 3:12", "texts": {"krv": "이기는 자는 내 하나님 성전에 기둥이 되게 하리니 그가 결코 다시 나가지 아니하리라 내가 하나님의 이름과 하나님의 성 곧 하늘에서 내 하나님께로부터 내려오는 새 예루살렘의 이름과 나의 새 이름을 그이 위에 기록하리라", "kkjv": "이기는 자는 내가 내 하나님의 성전에서 기둥이 되게 하리니 그가 다시는 나가지 아니하리라. 또 내가 내 하나님의 이름과 내 하나님의 도시 곧 하늘에서 내 하나님으로부터 내려오는 새 예루살렘의 이름을 그 위에 기록하고 나의 새 이름을 그 위에 기록하리라.", "web": "He who overcomes, I will make him a pillar in the temple of my God, and he will go out from there no more. I will write on him the name of my God, and the name of the city of my God, the new Jerusalem, which comes down out of heaven from my God, and my own new name."}}, {"id": 905, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "승리"], "book": "요한계시록", "chap": 3, "verse": "21", "ref": "요한계시록 3:21", "texts": {"krv": "이기는 그에게는 내가 내 보좌에 함께 앉게 하여 주기를 내가 이기고 아버지 보좌에 함께 앉은 것과 같이 하리라", "kkjv": "이기는 자에게는 나 역시 이긴 뒤에 내 아버지와 함께 그분의 왕좌에 앉게 된 것 같이 나와 함께 내 왕좌에 앉는 것을 내가 허락하리라.", "web": "He who overcomes, I will give to him to sit down with me on my throne, as I also overcame, and sat down with my Father on his throne."}}, {"id": 906, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "상급"], "book": "역대하", "chap": 15, "verse": "7", "ref": "역대하 15:7", "texts": {"krv": "그런즉 너희는 강하게 하라 손이 약하지 않게 하라 너희 행위에는 상급이 있음이니라", "kkjv": "그런즉 너희는 강한 자가 되며 너희 손이 약해지지 않게 하라. 너희 일에 보상이 있으리라, 하니라.", "web": "But you be strong, and don’t let your hands be slack; for your work shall be rewarded.”"}}, {"id": 907, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "상급"], "book": "이사야", "chap": 40, "verse": "10", "ref": "이사야 40:10", "texts": {"krv": "보라 주 여호와께서 장차 강한 자로 임하실 것이요 친히 그 팔로 다스리실 것이라 보라 상급이 그에게 있고 보응이 그 앞에 있으며", "kkjv": "보라, 주 하나님께서 강한 손과 더불어 임하실 것이요, 그분의 팔이 그분을 위하여 다스리리라. 보라, 그분의 보상이 그분께 있고 그분의 일이 그분 앞에 있도다.", "web": "Behold, the Lord Yahweh will come as a mighty one, and his arm will rule for him. Behold, his reward is with him, and his recompense before him."}}, {"id": 908, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "상급"], "book": "고린도전서", "chap": 3, "verse": "13-14", "ref": "고린도전서 3:13-14", "texts": {"krv": "각각 공력이 나타날 터인데 그 날이 공력을 밝히리니 이는 불로 나타내고 그 불이 각 사람의 공력이 어떠한 것을 시험할 것임이니라 만일 누구든지 그 위에 세운 공력이 그대로 있으면 상을 받고", "kkjv": "각 사람의 일이 드러나리라. 그 날이 그것을 밝히 드러내리니 이는 그것이 불에 의해 드러나고 그 불이 각 사람의 일이 어떤 종류인지 그것을 시험할 것이기 때문이라. 어떤 사람이 그 기초 위에 세운 일이 남아 있으면 그는 보상을 받고", "web": "each man’s work will be revealed. For the Day will declare it, because it is revealed in fire; and the fire itself will test what sort of work each man’s work is. If any man’s work remains which he built on it, he will receive a reward."}}, {"id": 909, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "상급"], "book": "빌립보서", "chap": 4, "verse": "1", "ref": "빌립보서 4:1", "texts": {"krv": "그러므로 나의 사랑하고 사모하는 형제들 나의 기쁨이요 면류관인 사랑하는 자들아 이와 같이 주 안에 서라", "kkjv": "그러므로 극진히 사랑하고 사모하는 나의 형제들 곧 나의 기쁨이요 왕관인 나의 극진히 사랑하는 자들아, 이와 같이 주 안에서 굳게 서라.", "web": "Therefore, my brothers, beloved and longed for, my joy and crown, so stand firm in the Lord, my beloved."}}, {"id": 910, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "상급"], "book": "데살로니가전서", "chap": 2, "verse": "19-20", "ref": "데살로니가전서 2:19-20", "texts": {"krv": "우리의 소망이나 기쁨이나 자랑의 면류관이 무엇이냐 그의 강림하실 때 우리 주 예수 앞에 너희가 아니냐 너희는 우리의 영광이요 기쁨이니라", "kkjv": "우리의 소망이나 기쁨이나 환희의 관(冠)이 무엇이냐? 우리 주 예수 그리스도께서 오실 때에 그분 앞에 있을 바로 너희가 아니냐? 너희는 우리의 영광이요 기쁨이니라.", "web": "For what is our hope, or joy, or crown of rejoicing? Isn’t it even you, before our Lord Jesus at his coming? For you are our glory and our joy."}}, {"id": 911, "coll": "무장 900구절", "sub": ["Character Building and Life Training", "상급"], "book": "야고보서", "chap": 1, "verse": "12", "ref": "야고보서 1:12", "texts": {"krv": "시험을 참는 자는 복이 있도다 이것에 옳다 인정하심을 받은 후에 주께서 자기를 사랑하는 자들에게 약속하신 생명의 면류관을 얻을 것임이니라", "kkjv": "시험을 견디는 자는 복이 있나니 그가 단련을 받은 뒤에 주께서 자신을 사랑하는 자들에게 약속하신 생명의 관(冠)을 받으리라.", "web": "Blessed is the man who endures temptation, for when he has been approved, he will receive the crown of life, which the Lord promised to those who love him."}}, {"id": 912, "coll": "무장 900구절", "sub": ["경계", "교만"], "book": "잠언", "chap": 13, "verse": "10", "ref": "잠언 13:10", "texts": {"krv": "교만에서는 다툼만 일어날 뿐이라 권면을 듣는 자는 지혜가 있느니라", "kkjv": "오직 교만에 의해서 다툼이 생기나 좋은 충고를 받은 자에게는 지혜가 있느니라.", "web": "Pride only breeds quarrels, but with ones who take advice is wisdom."}}, {"id": 913, "coll": "무장 900구절", "sub": ["경계", "교만"], "book": "잠언", "chap": 15, "verse": "12", "ref": "잠언 15:12", "texts": {"krv": "거만한 자는 견책 받기를 좋아하지 아니하며 지혜 있는 자에게로 가지도 아니하느니라", "kkjv": "비웃는 자는 자기를 책망하는 자를 사랑하지 아니하며 지혜로운 자에게 가려 하지도 아니하리로다.", "web": "A scoffer doesn’t love to be reproved; he will not go to the wise."}}, {"id": 914, "coll": "무장 900구절", "sub": ["경계", "교만"], "book": "잠언", "chap": 16, "verse": "18", "ref": "잠언 16:18", "texts": {"krv": "교만은 패망의 선봉이요 거만한 마음은 넘어짐의 앞잡이니라", "kkjv": "멸망에 앞서 교만이 나가며 넘어짐에 앞서 거만한 영이 있느니라.", "web": "Pride goes before destruction, and a haughty spirit before a fall."}}, {"id": 915, "coll": "무장 900구절", "sub": ["경계", "교만"], "book": "잠언", "chap": 27, "verse": "2", "ref": "잠언 27:2", "texts": {"krv": "타인으로 너를 칭찬하게 하고 네 입으로는 말며 외인으로 너를 칭찬하게 하고 네 입술로는 말지니라", "kkjv": "다른 사람이 너를 칭찬하게 하고 네 입으로는 하지 말며 낯선 자가 너를 칭찬하게 하고 네 입술로는 하지 말지니라.", "web": "Let another man praise you, and not your own mouth; a stranger, and not your own lips."}}, {"id": 916, "coll": "무장 900구절", "sub": ["경계", "교만"], "book": "로마서", "chap": 12, "verse": "3", "ref": "로마서 12:3", "texts": {"krv": "내게 주신 은혜로 말미암아 너희 중 각 사람에게 말하노니 마땅히 생각할 그 이상의 생각을 품지 말고 오직 하나님께서 각 사람에게 나눠 주신 믿음의 분량대로 지혜롭게 생각하라", "kkjv": "내게 주신 은혜를 힘입어 너희 가운데 있는 각 사람에게 내가 말하노니 각 사람은 자기가 마땅히 생각할 것보다 더 높이 자기에 대하여 생각하지 말고 하나님께서 각 사람에게 믿음의 분량을 나누어 주신대로 맑은 정신으로 생각하라.", "web": "For I say, through the grace that was given me, to every man who is among you, not to think of himself more highly than he ought to think; but to think reasonably, as God has apportioned to each person a measure of faith."}}, {"id": 917, "coll": "무장 900구절", "sub": ["경계", "교만"], "book": "고린도전서", "chap": 10, "verse": "12", "ref": "고린도전서 10:12", "texts": {"krv": "그런즉 선 줄로 생각하는 자는 넘어질까 조심하라", "kkjv": "그런즉 스스로 서 있는 줄로 생각하는 자는 넘어지지 않도록 주의할지니라.", "web": "Therefore let him who thinks he stands be careful that he doesn’t fall."}}, {"id": 918, "coll": "무장 900구절", "sub": ["경계", "탐욕"], "book": "잠언", "chap": 18, "verse": "1", "ref": "잠언 18:1", "texts": {"krv": "무리에게서 스스로 나뉘는 자는 자기 소욕을 따르는 자라 온갖 참 지혜를 배척하느니라", "kkjv": "어떤 사람은 소원으로 말미암아 자신을 분리하고 모든 지혜를 구하며 그것과 상관하느니라.", "web": "An unfriendly man pursues selfishness, and defies all sound judgment."}}, {"id": 919, "coll": "무장 900구절", "sub": ["경계", "탐욕"], "book": "마태복음", "chap": 13, "verse": "22", "ref": "마태복음 13:22", "texts": {"krv": "가시떨기에 뿌리웠다는 것은 말씀을 들으나 세상의 염려와 재리의 유혹에 말씀이 막혀 결실치 못하는 자요", "kkjv": "가시나무들 사이에 씨를 받은 자 또한 말씀을 듣되 이 세상의 염려와 재물의 속임수가 말씀을 숨 막히게 하므로 열매 맺지 못하는 자니라.", "web": "What was sown among the thorns, this is he who hears the word, but the cares of this age and the deceitfulness of riches choke the word, and he becomes unfruitful."}}, {"id": 920, "coll": "무장 900구절", "sub": ["경계", "탐욕"], "book": "누가복음", "chap": 12, "verse": "15", "ref": "누가복음 12:15", "texts": {"krv": "저희에게 이르시되 삼가 모든 탐심을 물리치라 사람의 생명이 그 소유의 넉넉한 데 있지 아니하니라 하시고", "kkjv": "그들에게 이르시되, 탐욕을 주의하고 조심하라. 사람의 생명이 그의 풍부한 소유물에 있지 아니하니라, 하시니라.", "web": "He said to them, “Beware! Keep yourselves from covetousness, for a man’s life doesn’t consist of the abundance of the things which he possesses.”"}}, {"id": 921, "coll": "무장 900구절", "sub": ["경계", "탐욕"], "book": "골로새서", "chap": 3, "verse": "5", "ref": "골로새서 3:5", "texts": {"krv": "그러므로 땅에 있는 지체를 죽이라 곧 음란과 부정과 사욕과 악한 정욕과 탐심이니 탐심은 우상 숭배니라", "kkjv": "그러므로 땅에 있는 너희 지체들을 죽이라. 그것들은 음행과 부정함과 무절제한 애정과 악한 욕정과 탐욕이니 탐욕은 우상 숭배니라.", "web": "Put to death therefore your members which are on the earth: sexual immorality, uncleanness, depraved passion, evil desire, and covetousness, which is idolatry;"}}, {"id": 922, "coll": "무장 900구절", "sub": ["경계", "탐욕"], "book": "디모데전서", "chap": 6, "verse": "9-10", "ref": "디모데전서 6:9-10", "texts": {"krv": "부하려 하는 자들은 시험과 올무와 여러 가지 어리석고 해로운 정욕에 떨어지나니 곧 사람으로 침륜과 멸망에 빠지게 하는 것이라 돈을 사랑함이 일만 악의 뿌리가 되나니 이것을 사모하는 자들이 미혹을 받아 믿음에서 떠나 많은 근심으로써 자기를 찔렀도다", "kkjv": "그러나 부유하게 되고자 하는 자들은 사람들을 파멸과 멸망에 빠지게 하는 시험과 올무와 여러 가지 어리석고 해로운 욕심에 떨어지느니라. 돈을 사랑함이 모든 악의 뿌리이니 어떤 자들이 돈을 탐내다가 믿음에서 떠나 잘못하고 많은 고통으로 자기를 찔러 꿰뚫었도다.", "web": "But those who are determined to be rich fall into a temptation and a snare and many foolish and harmful lusts, such as drown men in ruin and destruction. For the love of money is a root of all kinds of evil. Some have been led astray from the faith in their greed, and have pierced themselves through with many sorrows."}}, {"id": 923, "coll": "무장 900구절", "sub": ["경계", "탐욕"], "book": "야고보서", "chap": 1, "verse": "14-15", "ref": "야고보서 1:14-15", "texts": {"krv": "오직 각 사람이 시험을 받는 것은 자기 욕심에 끌려 미혹됨이니 욕심이 잉태한즉 죄를 낳고 죄가 장성한즉 사망을 낳느니라", "kkjv": "오직 모든 사람이 자기 자신의 욕심에 이끌려 유혹을 받을 때에 시험을 받나니 그런즉 욕심이 잉태하면 죄를 낳고 죄가 완료되면 사망을 낳느니라.", "web": "But each one is tempted, when he is drawn away by his own lust, and enticed. Then the lust, when it has conceived, bears sin; and the sin, when it is full grown, produces death."}}, {"id": 924, "coll": "무장 900구절", "sub": ["경계", "게으름"], "book": "잠언", "chap": 1, "verse": "32", "ref": "잠언 1:32", "texts": {"krv": "어리석은 자의 퇴보는 자기를 죽이며 미련한 자의 안일은 자기를 멸망시키려니와", "kkjv": "단순한 자들의 돌이켜 떠나감이 그들을 죽이며 어리석은 자들의 형통함이 그들을 파멸시키리라.", "web": "For the backsliding of the simple will kill them. The careless ease of fools will destroy them."}}, {"id": 925, "coll": "무장 900구절", "sub": ["경계", "게으름"], "book": "잠언", "chap": 6, "verse": "6", "ref": "잠언 6:6", "texts": {"krv": "게으른 자여 개미에게로 가서 그 하는 것을 보고 지혜를 얻으라", "kkjv": "¶너 게으른 자여, 개미에게 가서 개미의 길들을 깊이 살펴보고 지혜로운 자가 되라.", "web": "Go to the ant, you sluggard. Consider her ways, and be wise;"}}, {"id": 926, "coll": "무장 900구절", "sub": ["경계", "게으름"], "book": "잠언", "chap": 6, "verse": "10-11", "ref": "잠언 6:10-11", "texts": {"krv": "좀더 자자 좀더 졸자 손을 모으고 좀더 눕자 하면 네 빈궁이 강도 같이 오며 네 곤핍이 군사 같이 이르리라", "kkjv": "좀 더 자자. 좀 더 졸자. 손을 모으고 좀 더 자자, 하면 네 빈궁이 여행자같이, 네 궁핍이 군사같이 이르리로다.", "web": "A little sleep, a little slumber, a little folding of the hands to sleep: so your poverty will come as a robber, and your scarcity as an armed man."}}, {"id": 927, "coll": "무장 900구절", "sub": ["경계", "게으름"], "book": "잠언", "chap": 18, "verse": "9", "ref": "잠언 18:9", "texts": {"krv": "자기의 일을 게을리 하는 자는 패가하는 자의 형제니라", "kkjv": "자기 일을 게을리 하는 자는 또한 크게 탕진하는 자와 형제니라.", "web": "One who is slack in his work is brother to him who is a master of destruction."}}, {"id": 928, "coll": "무장 900구절", "sub": ["경계", "게으름"], "book": "잠언", "chap": 21, "verse": "25", "ref": "잠언 21:25", "texts": {"krv": "게으른 자의 정욕이 그를 죽이나니 이는 그 손으로 일하기를 싫어함이니라", "kkjv": "게으른 자의 손은 수고하기를 거부하므로 그의 욕망이 그를 죽이느니라.", "web": "The desire of the sluggard kills him, for his hands refuse to labor."}}, {"id": 929, "coll": "무장 900구절", "sub": ["경계", "게으름"], "book": "잠언", "chap": 26, "verse": "15", "ref": "잠언 26:15", "texts": {"krv": "게으른 자는 그 손을 그릇에 넣고도 입으로 올리기를 괴로워하느니라", "kkjv": "게으른 자는 자기 손을 품에 감추고 그것을 다시 자기 입으로 가져가는 것을 괴로워하느니라.", "web": "The sluggard buries his hand in the dish. He is too lazy to bring it back to his mouth."}}, {"id": 930, "coll": "무장 900구절", "sub": ["경계", "낙심함"], "book": "시편", "chap": 42, "verse": "11", "ref": "시편 42:11", "texts": {"krv": "내 영혼아 네가 어찌하여 낙망하며 어찌하여 내 속에서 불안하여 하는고 너는 하나님을 바라라 나는 내 얼굴을 도우시는 내 하나님을 오히려 찬송하리로다", "kkjv": "오 내 혼아, 어찌하여 네가 낙심하느냐? 어찌하여 네가 내 속에서 불안해하느냐? 너는 하나님께 소망을 두라. 내 얼굴의 건강이시요, 내 하나님이신 그분을 내가 여전히 찬양하리로다.", "web": "Why are you in despair, my soul? Why are you disturbed within me? Hope in God! For I shall still praise him, the saving help of my countenance, and my God."}}, {"id": 931, "coll": "무장 900구절", "sub": ["경계", "낙심함"], "book": "잠언", "chap": 24, "verse": "10", "ref": "잠언 24:10", "texts": {"krv": "네가 만일 환난 날에 낙담하면 네 힘의 미약함을 보임이니라", "kkjv": "역경을 당하는 날에 네가 기진하면 네 힘이 적은 것이니라.", "web": "If you falter in the time of trouble, your strength is small."}}, {"id": 932, "coll": "무장 900구절", "sub": ["경계", "낙심함"], "book": "고린도후서", "chap": 4, "verse": "1", "ref": "고린도후서 4:1", "texts": {"krv": "이러하므로 우리가 이 직분을 받아 긍휼하심을 입은 대로 낙심하지 아니하고", "kkjv": "그러므로 우리가 긍휼을 받아 이 사역을 맡았은즉 낙심하지 아니하며", "web": "Therefore seeing we have this ministry, even as we obtained mercy, we don’t faint."}}, {"id": 933, "coll": "무장 900구절", "sub": ["경계", "낙심함"], "book": "고린도후서", "chap": 4, "verse": "8", "ref": "고린도후서 4:8", "texts": {"krv": "우리가 사방으로 우겨쌈을 당하여도 싸이지 아니하며 답답한 일을 당하여도 낙심하지 아니하며", "kkjv": "우리가 사방에서 고난을 당하나 괴로워하지 아니하며 난처한 일을 당하나 절망하지 아니하고", "web": "We are pressed on every side, yet not crushed; perplexed, yet not to despair;"}}, {"id": 934, "coll": "무장 900구절", "sub": ["경계", "낙심함"], "book": "고린도후서", "chap": 4, "verse": "16", "ref": "고린도후서 4:16", "texts": {"krv": "그러므로 우리가 낙심하지 아니하노니 겉사람은 후패하나 우리의 속은 날로 새롭도다", "kkjv": "이런 까닭에 우리가 낙심하지 아니하노니 우리의 겉 사람은 썩어 없어져도 속사람은 날마다 새로워지는도다.", "web": "Therefore we don’t faint, but though our outward man is decaying, yet our inward man is renewed day by day."}}, {"id": 935, "coll": "무장 900구절", "sub": ["경계", "낙심함"], "book": "데살로니가후서", "chap": 3, "verse": "13", "ref": "데살로니가후서 3:13", "texts": {"krv": "형제들아 너희는 선을 행하다가 낙심치 말라", "kkjv": "그러나 형제들아, 너희는 잘 행하는 가운데 지치지 말라.", "web": "But you, brothers, don’t be weary in doing well."}}, {"id": 936, "coll": "무장 900구절", "sub": ["경계", "둔해짐"], "book": "잠언", "chap": 26, "verse": "11", "ref": "잠언 26:11", "texts": {"krv": "개가 그 토한 것을 도로 먹는것 같이 미련한 자는 그 미련한 것을 거듭 행하느니라", "kkjv": "개가 자기의 토한 것으로 돌아가는 것 같이 어리석은 자도 자기의 어리석은 짓으로 돌아가느니라.", "web": "As a dog that returns to his vomit, so is a fool who repeats his folly."}}, {"id": 937, "coll": "무장 900구절", "sub": ["경계", "둔해짐"], "book": "누가복음", "chap": 21, "verse": "34", "ref": "누가복음 21:34", "texts": {"krv": "너희는 스스로 조심하라 그렇지 않으면 방탕함과 술 취함과 생활의 염려로 마음이 둔하여지고 뜻밖에 그 날이 덫과 같이 너희에게 임하리라", "kkjv": "¶너희는 스스로 주의하라. 그렇지 않으면 언제라도 너희 마음이 과식과 술 취함과 이 세상 삶의 염려로 무겁게 되어 그 날이 알지 못하게 너희에게 임할까 염려하노니", "web": "“So be careful, or your hearts will be loaded down with carousing, drunkenness, and cares of this life, and that day will come on you suddenly."}}, {"id": 938, "coll": "무장 900구절", "sub": ["경계", "둔해짐"], "book": "에베소서", "chap": 4, "verse": "19-20", "ref": "에베소서 4:19-20", "texts": {"krv": "저희가 감각 없는 자 되어 자신을 방탕에 방임하여 모든 더러운 것을 욕심으로 행하되 오직 너희는 그리스도를 이같이 배우지 아니하였느니라", "kkjv": "그들이 감각을 지나쳐 자기를 색욕에 내주고 탐욕을 내어 모든 부정한 것을 행하였으되 너희는 그리스도를 그렇게 배우지 아니하였느니라.", "web": "who having become callous gave themselves up to lust, to work all uncleanness with greediness. But you did not learn Christ that way;"}}, {"id": 939, "coll": "무장 900구절", "sub": ["경계", "둔해짐"], "book": "히브리서", "chap": 2, "verse": "1", "ref": "히브리서 2:1", "texts": {"krv": "그러므로 모든 들은 것을 우리가 더욱 간절히 삼갈지니 혹 흘러 떠내려 갈까 염려하노라", "kkjv": "그러므로 우리는 마땅히 우리가 지금까지 들은 것들에 더 열심히 주의를 기울여야 하리니 이것은 언제라도 그것들이 우리에게서 빠져나가지 못하게 하려 함이라.", "web": "Therefore we ought to pay greater attention to the things that were heard, lest perhaps we drift away."}}, {"id": 940, "coll": "무장 900구절", "sub": ["경계", "둔해짐"], "book": "요한계시록", "chap": 2, "verse": "4-5", "ref": "요한계시록 2:4-5", "texts": {"krv": "그러나 너를 책망할 것이 있나니 너의 처음 사랑을 버렸느니라 그러므로 어디서 떨어진 것을 생각하고 회개하여 처음 행위를 가지라 만일 그리하지 아니하고 회개치 아니하면 내가 네게 임하여 네 촛대를 그 자리에서 옮기리라", "kkjv": "그럼에도 불구하고 내가 너를 책망할 것이 조금 있나니 이는 네가 너의 처음 사랑을 버렸기 때문이라. 그러므로 네가 어디로부터 떨어졌는지 기억하고 회개하며 처음 행위를 하라. 만일 그리하지 아니하고 네가 회개하지 아니하면 내가 속히 네게 가서 네 등잔대를 그것의 자리에서 옮기리라.", "web": "But I have this against you, that you left your first love. Remember therefore from where you have fallen, and repent and do the first works; or else I am coming to you swiftly, and will move your lamp stand out of its place, unless you repent."}}, {"id": 941, "coll": "무장 900구절", "sub": ["경계", "둔해짐"], "book": "요한계시록", "chap": 3, "verse": "16", "ref": "요한계시록 3:16", "texts": {"krv": "네가 이같이 미지근하여 더웁지도 아니하고 차지도 아니하니 내 입에서 너를 토하여 내치리라", "kkjv": "그런즉 네가 이같이 미지근하여 차지도 아니하고 뜨겁지도 아니하므로 내가 내 입에서 너를 토하여 내리니", "web": "So, because you are lukewarm, and neither hot nor cold, I will vomit you out of my mouth."}}, {"id": 942, "coll": "무장 900구절", "sub": ["경계", "불순종"], "book": "신명기", "chap": 28, "verse": "62", "ref": "신명기 28:62", "texts": {"krv": "너희가 하늘의 별 같이 많았을지라도 네 하나님 여호와의 말씀을 순종치 아니하므로 남는 자가 얼마 되지 못할 것이라", "kkjv": "너희가 하늘의 별들같이 많았을지라도 네가 주 네 하나님의 음성에 순종하려 하지 아니하므로 남는 자의 수가 적으리라.", "web": "You will be left few in number, even though you were as the stars of the sky for multitude; because you didn’t listen to Yahweh your God’s voice."}}, {"id": 943, "coll": "무장 900구절", "sub": ["경계", "불순종"], "book": "이사야", "chap": 48, "verse": "18-19", "ref": "이사야 48:18-19", "texts": {"krv": "슬프다 네가 나의 명령을 듣지 아니하였도다 만일 들었더면 네 평강이 강과 같았겠고 네 의가 바다 물결 같았을 것이며 네 자손이 모래 같았겠고 네 몸의 소생이 모래 알갱이 같아서 그 이름이 내 앞에서 끊어지지 아니하였겠고 없어지지 아니하였으리라 하셨느니라", "kkjv": "네가 내 명령들에 귀를 기울였더라면 얼마나 좋았을까! 그리하였더라면 네 화평이 강 같았겠고 네 의가 바다 물결 같았으리라. 또 네 씨가 모래 같고 네 배 속에서 나오는 후손이 그것의 자갈 같아서 그의 이름이 내 앞에서 끊어지거나 멸절되지 아니하였으리라.", "web": "Oh that you had listened to my commandments! then your peace would have been like a river, and your righteousness like the waves of the sea: your seed also had been as the sand, and the offspring of your body like its grains: his name would not be cut off nor destroyed from before me."}}, {"id": 944, "coll": "무장 900구절", "sub": ["경계", "불순종"], "book": "누가복음", "chap": 12, "verse": "47", "ref": "누가복음 12:47", "texts": {"krv": "주인의 뜻을 알고도 예비치 아니하고 그 뜻대로 행치 아니한 종은 많이 맞을 것이요", "kkjv": "자기 주인의 뜻을 알고도 자기를 예비하지 아니하고 주인의 뜻대로 행하지 아니한 그 종은 채찍을 많이 맞되", "web": "That servant, who knew his lord’s will, and didn’t prepare, nor do what he wanted, will be beaten with many stripes,"}}, {"id": 945, "coll": "무장 900구절", "sub": ["경계", "불순종"], "book": "디도서", "chap": 1, "verse": "16", "ref": "디도서 1:16", "texts": {"krv": "저희가 하나님을 시인하나 행위로는 부인하니 가증한 자요 복종치 아니하는 자요 모든 선한 일을 버리는 자니라", "kkjv": "그들이 하나님을 안다고 고백하나 행위로는 그분을 부인하니 그들은 가증하고 불순종하는 자들이요 모든 선한 일에 대해 버림받은 자들이니라.", "web": "They profess that they know God, but by their works they deny him, being abominable, disobedient, and unfit for any good work."}}, {"id": 946, "coll": "무장 900구절", "sub": ["경계", "불순종"], "book": "히브리서", "chap": 3, "verse": "18", "ref": "히브리서 3:18", "texts": {"krv": "또 하나님이 누구에게 맹세하사 그의 안식에 들어오지 못하리라 하셨느뇨 곧 순종치 아니하던 자에게가 아니냐", "kkjv": "또 그분께서 누구에게 맹세하사 그들이 자신의 안식에 들어오지 못하리라고 하셨느냐, 오직 믿지 아니한 자들이 아니냐?", "web": "To whom did he swear that they wouldn’t enter into his rest, but to those who were disobedient?"}}, {"id": 947, "coll": "무장 900구절", "sub": ["경계", "불순종"], "book": "히브리서", "chap": 12, "verse": "25", "ref": "히브리서 12:25", "texts": {"krv": "너희는 삼가 말하신 자를 거역하지 말라 땅에서 경고하신 자를 거역한 저희가 피하지 못하였거든 하물며 하늘로 좇아 경고하신 자를 배반하는 우리일까보냐", "kkjv": "너희는 조심하여 말씀하시는 분을 거역하지 말라. 땅에서 말한 자를 거역한 그들이 피하지 못하였거든 우리가 하늘로부터 말씀하시는 분에게서 돌아선다면 더더욱 피하지 못하리로다.", "web": "See that you don’t refuse him who speaks. For if they didn’t escape when they refused him who warned on the earth, how much more will we not escape who turn away from him who warns from heaven,"}}, {"id": 948, "coll": "무장 900구절", "sub": ["경계", "음란함"], "book": "잠언", "chap": 4, "verse": "15", "ref": "잠언 4:15", "texts": {"krv": "그 길을 피하고 지나가지 말며 돌이켜 떠나갈지어다", "kkjv": "그것을 피하고 그 곁으로 지나가지 말며 거기서 돌이켜 떠나갈지어다.", "web": "Avoid it, and don’t pass by it. Turn from it, and pass on."}}, {"id": 949, "coll": "무장 900구절", "sub": ["경계", "음란함"], "book": "잠언", "chap": 5, "verse": "9-10", "ref": "잠언 5:9-10", "texts": {"krv": "두렵건대 네 존영이 남에게 잃어버리게 되며 네 수한이 잔포자에게 빼앗기게 될까 하노라 두렵건대 타인이 네 재물로 충족하게 되며 네 수고한 것이 외인의 집에 있게될까 하노라", "kkjv": "네가 네 존귀를 남들에게 주며 네 삶의 햇수를 잔인한 자들에게 줄까 염려하노라. 낯선 자들이 네 재물로 충만하게 되며 네가 수고한 것들이 낯선 자의 집에 있게 될까 염려하노라.", "web": "lest you give your honor to others, and your years to the cruel one; lest strangers feast on your wealth, and your labors enrich another man’s house."}}, {"id": 950, "coll": "무장 900구절", "sub": ["경계", "음란함"], "book": "잠언", "chap": 6, "verse": "27-28", "ref": "잠언 6:27-28", "texts": {"krv": "사람이 불을 품에 품고야 어찌 그 옷이 타지 아니하겠으며 사람이 숯불을 밟고야 어찌 그 발이 데지 아니하겠느냐", "kkjv": "사람이 자기 품에 불을 품고 자기 옷이 타지 않게 할 수 있겠느냐? 사람이 뜨거운 숯을 밟고 자기 발이 타지 않게 할 수 있겠느냐?", "web": "Can a man scoop fire into his lap, and his clothes not be burned? Or can one walk on hot coals, and his feet not be scorched?"}}, {"id": 951, "coll": "무장 900구절", "sub": ["경계", "음란함"], "book": "고린도전서", "chap": 6, "verse": "18", "ref": "고린도전서 6:18", "texts": {"krv": "음행을 피하라 사람이 범하는 죄마다 몸 밖에 있거니와 음행하는 자는 자기 몸에게 죄를 범하느니라", "kkjv": "음행을 피하라. 사람이 행하는 모든 죄는 몸 밖에 있거니와 음행하는 자는 자기 몸에 죄를 짓느니라.", "web": "Flee sexual immorality! “Every sin that a man does is outside the body,” but he who commits sexual immorality sins against his own body."}}, {"id": 952, "coll": "무장 900구절", "sub": ["경계", "음란함"], "book": "에베소서", "chap": 5, "verse": "5", "ref": "에베소서 5:5", "texts": {"krv": "너희도 이것을 정녕히 알거니와 음행하는 자나 더러운 자나 탐하는 자 곧 우상 숭배자는 다 그리스도와 하나님 나라에서 기업을 얻지 못하리니", "kkjv": "너희가 이것을 알거니와 음행을 일삼는 자나 부정한 자나 탐욕을 부리는 자 곧 우상 숭배자는 결코 그리스도와 하나님의 왕국에서 아무 상속 유업도 받지 못하느니라.", "web": "Know this for sure, that no sexually immoral person, nor unclean person, nor covetous man, who is an idolater, has any inheritance in the Kingdom of Christ and God."}}, {"id": 953, "coll": "무장 900구절", "sub": ["경계", "음란함"], "book": "히브리서", "chap": 12, "verse": "16", "ref": "히브리서 12:16", "texts": {"krv": "음행하는 자와 혹 한 그릇 식물을 위하여 장자의 명분을 판 에서와 같이 망령된 자가 있을까 두려워하라", "kkjv": "이것은 음행하는 자나 혹은 먹을 것 한 조각을 위해 자기의 장자권을 판 에서와 같이 속된 자가 있지 아니하게 하려 함이라.", "web": "lest there be any sexually immoral person, or profane person, like Esau, who sold his birthright for one meal."}}, {"id": 954, "coll": "무장 900구절", "sub": ["경계", "조급함"], "book": "잠언", "chap": 14, "verse": "29", "ref": "잠언 14:29", "texts": {"krv": "노하기를 더디하는 자는 크게 명철하여도 마음이 조급한 자는 어리석음을 나타내느니라", "kkjv": "진노하기를 더디 하는 자는 큰 명철이 있으나 영이 조급한 자는 어리석음을 높이느니라.", "web": "He who is slow to anger has great understanding, but he who has a quick temper displays folly."}}, {"id": 955, "coll": "무장 900구절", "sub": ["경계", "조급함"], "book": "잠언", "chap": 19, "verse": "2", "ref": "잠언 19:2", "texts": {"krv": "지식 없는 소원은 선치 못하고 발이 급한 사람은 그릇하느니라", "kkjv": "또한 혼에게 지식이 없으면 그것은 선하지 아니하며 발이 급한 사람은 죄를 짓느니라.", "web": "It isn’t good to have zeal without knowledge; nor being hasty with one’s feet and missing the way."}}, {"id": 956, "coll": "무장 900구절", "sub": ["경계", "조급함"], "book": "잠언", "chap": 20, "verse": "21", "ref": "잠언 20:21", "texts": {"krv": "처음에 속히 잡은 산업은 마침내 복이 되지 아니하느니라", "kkjv": "처음에 서둘러서 상속 재산을 받을 수 있으나 그것의 끝은 복되지 아니하리로다.", "web": "An inheritance quickly gained at the beginning, won’t be blessed in the end."}}, {"id": 957, "coll": "무장 900구절", "sub": ["경계", "조급함"], "book": "잠언", "chap": 21, "verse": "5", "ref": "잠언 21:5", "texts": {"krv": "부지런한 자의 경영은 풍부함에 이를 것이나 조급한 자는 궁핍함에 이를 따름이니라", "kkjv": "부지런한 자들의 생각들은 오직 풍족함으로 이끌거니와 조급한 모든 자의 생각들은 궁핍함으로 이끌 뿐이니라.", "web": "The plans of the diligent surely lead to profit; and everyone who is hasty surely rushes to poverty."}}, {"id": 958, "coll": "무장 900구절", "sub": ["경계", "조급함"], "book": "잠언", "chap": 28, "verse": "20", "ref": "잠언 28:20", "texts": {"krv": "충성된 자는 복이 많아도 속히 부하고자 하는 자는 형벌을 면치 못하리라", "kkjv": "신실한 자는 복이 넘치려니와 속히 부자가 되려 하는 자는 무죄하지 아니하리라.", "web": "A faithful man is rich with blessings; but one who is eager to be rich will not go unpunished."}}, {"id": 959, "coll": "무장 900구절", "sub": ["경계", "조급함"], "book": "잠언", "chap": 29, "verse": "20", "ref": "잠언 29:20", "texts": {"krv": "네가 언어에 조급한 사람을 보느냐 그보다 미련한 자에게 오히려 바랄 것이 있느니라", "kkjv": "네가 말이 조급한 사람을 보느냐? 그보다는 어리석은 자에게 더 소망이 있느니라.", "web": "Do you see a man who is hasty in his words? There is more hope for a fool than for him."}}, {"id": 960, "coll": "무장 900구절", "sub": ["경계", "죄를 사랑함"], "book": "이사야", "chap": 59, "verse": "1-2", "ref": "이사야 59:1-2", "texts": {"krv": "여호와의 손이 짧아 구원치 못하심도 아니요 귀가 둔하여 듣지 못하심도 아니라 오직 너희 죄악이 너희와 너희 하나님 사이를 내었고 너희 죄가 그 얼굴을 가리워서 너희를 듣지 않으시게 함이니", "kkjv": "보라, 주의 손이 짧아져서 구원하지 못하는 것도 아니요, 그분의 귀가 둔하여서 듣지 못하는 것도 아니라. 오직 너희 불법들이 너희와 너희 하나님 사이를 갈라놓았고 너희 죄들이 그분의 얼굴을 너희에게 숨겼으므로 그분께서 듣지 아니하시리라.", "web": "Behold, Yahweh’s hand is not shortened, that it can’t save; neither his ear heavy, that it can’t hear: but your iniquities have separated between you and your God, and your sins have hidden his face from you, so that he will not hear."}}, {"id": 961, "coll": "무장 900구절", "sub": ["경계", "죄를 사랑함"], "book": "로마서", "chap": 6, "verse": "16", "ref": "로마서 6:16", "texts": {"krv": "너희 자신을 종으로 드려 누구에게 순종하든지 그 순종함을 받는 자의 종이 되는 줄을 너희가 알지 못하느냐 혹은 죄의 종으로 사망에 이르고 혹은 순종의 종으로 의에 이르느니라", "kkjv": "너희 자신을 누구에게 종으로 내주어 순종하게 하면 너희가 순종하는 그 사람의 종이 되는 줄을 너희가 알지 못하느냐? 혹은 죄의 종으로 사망에 이르고 혹은 순종의 종으로 의에 이르느니라.", "web": "Don’t you know that to whom you present yourselves as servants to obedience, his servants you are whom you obey; whether of sin to death, or of obedience to righteousness?"}}, {"id": 962, "coll": "무장 900구절", "sub": ["경계", "죄를 사랑함"], "book": "로마서", "chap": 8, "verse": "8", "ref": "로마서 8:8", "texts": {"krv": "육신에 있는 자들은 하나님을 기쁘시게 할 수 없느니라", "kkjv": "그런즉 이와 같이 육신 안에 있는 자들은 하나님을 기쁘게 할 수 없느니라.", "web": "Those who are in the flesh can’t please God."}}, {"id": 963, "coll": "무장 900구절", "sub": ["경계", "죄를 사랑함"], "book": "에베소서", "chap": 4, "verse": "30", "ref": "에베소서 4:30", "texts": {"krv": "하나님의 성령을 근심하게 하지 말라 그 안에서 너희가 구속의 날까지 인치심을 받았느니라", "kkjv": "하나님의 거룩한 영을 슬프게 하지 말라. 그분으로 말미암아 너희가 구속의 날까지 봉인되었느니라.", "web": "Don’t grieve the Holy Spirit of God, in whom you were sealed for the day of redemption."}}, {"id": 964, "coll": "무장 900구절", "sub": ["경계", "죄를 사랑함"], "book": "디모데후서", "chap": 3, "verse": "4", "ref": "디모데후서 3:4", "texts": {"krv": "배반하여 팔며 조급하며 자고하며 쾌락을 사랑하기를 하나님 사랑하는 것보다 더하며", "kkjv": "배신하며 고집이 세며 높은 마음을 품으며 하나님을 사랑하기보다는 쾌락들을 더 사랑하며", "web": "traitors, headstrong, conceited, lovers of pleasure rather than lovers of God;"}}, {"id": 965, "coll": "무장 900구절", "sub": ["경계", "죄를 사랑함"], "book": "히브리서", "chap": 12, "verse": "4", "ref": "히브리서 12:4", "texts": {"krv": "너희가 죄와 싸우되 아직 피 흘리기까지는 대항치 아니하고", "kkjv": "너희가 죄와 싸우되 아직 피 흘리기까지 대항하지는 아니하였노라.", "web": "You have not yet resisted to blood, striving against sin;"}}, {"id": 966, "coll": "무장 900구절", "sub": ["경계", "세상을 사랑함"], "book": "이사야", "chap": 40, "verse": "6", "ref": "이사야 40:6", "texts": {"krv": "말하는 자의 소리여 가로되 외치라 대답하되 내가 무엇이라 외치리이이까 가로되 모든 육체는 풀이요 그 모든 아름다움은 들의 꽃 같으니", "kkjv": "그 소리가 이르되, 외치라, 하니 그가 이르기를, 내가 무엇이라 외치리이까? 하매, 모든 육체는 풀이요, 육체의 모든 아름다움은 들의 꽃과 같으니라.", "web": "The voice of one saying, “Cry!”  One said, “What shall I cry?” “All flesh is like grass, and all its glory is like the flower of the field."}}, {"id": 967, "coll": "무장 900구절", "sub": ["경계", "세상을 사랑함"], "book": "요한복음", "chap": 17, "verse": "15", "ref": "요한복음 17:15", "texts": {"krv": "내가 비옵는 것은 저희를 세상에서 데려가시기를 위함이 아니요 오직 악에 빠지지 않게 보전하시기를 위함이니이다", "kkjv": "나는 아버지께서 그들을 세상에서 데려가시라고 기도하지 아니하오며 다만 그들을 악에서 지켜 주시라고 기도하나이다.", "web": "I pray not that you would take them from the world, but that you would keep them from the evil one."}}, {"id": 968, "coll": "무장 900구절", "sub": ["경계", "세상을 사랑함"], "book": "고린도후서", "chap": 6, "verse": "14", "ref": "고린도후서 6:14", "texts": {"krv": "너희는 믿지 않는 자와 멍에를 같이 하지 말라 의와 불법이 어찌 함께 하며 빛과 어두움이 어찌 사귀며", "kkjv": "너희는 믿지 않는 자들과 더불어 공평하지 않게 멍에를 같이 메지 말라. 의가 불의와 무슨 사귐을 갖겠느냐? 빛이 어둠과 무슨 친교를 나누겠느냐?", "web": "Don’t be unequally yoked with unbelievers, for what fellowship have righteousness and iniquity? Or what fellowship has light with darkness?"}}, {"id": 969, "coll": "무장 900구절", "sub": ["경계", "세상을 사랑함"], "book": "디모데후서", "chap": 4, "verse": "10", "ref": "디모데후서 4:10", "texts": {"krv": "데마는 이 세상을 사랑하여 나를 버리고 데살로니가로 갔고 그레스게는 갈라디아로 디도는 달마디아로 갔고", "kkjv": "데마는 현재의 이 세상을 사랑하여 나를 버리고 데살로니가로 떠났고 그레스겐은 갈라디아로, 디도는 달마디아로 갔으며", "web": "for Demas left me, having loved this present world, and went to Thessalonica; Crescens to Galatia, and Titus to Dalmatia."}}, {"id": 970, "coll": "무장 900구절", "sub": ["경계", "세상을 사랑함"], "book": "야고보서", "chap": 4, "verse": "4", "ref": "야고보서 4:4", "texts": {"krv": "간음하는 여자들이여 세상과 벗된 것이 하나님의 원수임을 알지 못하느뇨 그런즉 누구든지 세상과 벗이 되고자 하는 자는 스스로 하나님과 원수 되게 하는 것이니라", "kkjv": "너희 간음하는 남자들과 간음하는 여자들아, 세상과 친구가 되는 것이 하나님과 원수 되는 것인 줄 너희가 알지 못하느냐? 그러므로 누구든지 세상의 친구가 되고자 하는 자는 하나님의 원수가 되느니라.", "web": "You adulterers and adulteresses, don’t you know that friendship with the world is hostility toward God? Whoever therefore wants to be a friend of the world makes himself an enemy of God."}}, {"id": 971, "coll": "무장 900구절", "sub": ["경계", "세상을 사랑함"], "book": "야고보서", "chap": 4, "verse": "14", "ref": "야고보서 4:14", "texts": {"krv": "내일 일을 너희가 알지 못하는도다 너희 생명이 무엇이뇨 너희는 잠깐 보이다가 없어지는 안개니라", "kkjv": "내일 있을 일을 너희가 알지 못하는도다. 너희 생명이 무엇이냐? 그것은 곧 잠시 나타났다가 그 뒤에 사라져 버리는 수증기니라.", "web": "Whereas you don’t know what your life will be like tomorrow. For what is your life? For you are a vapor, that appears for a little time, and then vanishes away."}}, {"id": 972, "coll": "무장 900구절", "sub": ["경계", "하나님을 떠남"], "book": "민수기", "chap": 14, "verse": "23", "ref": "민수기 14:23", "texts": {"krv": "내가 그 조상들에게 맹세한 땅을 결단코 보지 못할 것이요 또 나를 멸시하는 사람은 하나라도 그것을 보지 못하리라", "kkjv": "그들은 내가 그들의 조상들에게 맹세한 땅을 결코 보지 못할 것이요, 또 나를 격노하게 한 사람들 중 아무도 그 땅을 보지 못하리라.", "web": "surely they shall not see the land which I swore to their fathers, neither shall any of those who despised me see it."}}, {"id": 973, "coll": "무장 900구절", "sub": ["경계", "하나님을 떠남"], "book": "신명기", "chap": 8, "verse": "14", "ref": "신명기 8:14", "texts": {"krv": "두렵건대 네 마음이 교만하여 네 하나님 여호와를 잊어버릴까 하노라 여호와는 너를 애굽 땅 종 되었던 집에서 이끌어 내시고", "kkjv": "네 마음이 교만하여 네가 주 네 하나님을 잊어버릴까 염려하노라. 그분께서는 너를 이집트 땅 속박의 집에서 데리고 나오시며", "web": "then your heart might be lifted up, and you forget Yahweh your God, who brought you out of the land of Egypt, out of the house of bondage;"}}, {"id": 974, "coll": "무장 900구절", "sub": ["경계", "하나님을 떠남"], "book": "예레미야", "chap": 2, "verse": "13", "ref": "예레미야 2:13", "texts": {"krv": "내 백성이 두 가지 악을 행하였나니 곧 생수의 근원되는 나를 버린 것과 스스로 웅덩이를 판 것인데 그것은 물을 저축지 못할 터진 웅덩이니라", "kkjv": "내 백성이 두 가지 악을 행하였으니 곧 그들이 생수의 샘인 나를 버렸고 또 자기들을 위해 물 저장고들 즉 물을 가두지 못할 터진 저장고들을 팠느니라.", "web": "“For my people have committed two evils: they have forsaken me, the spring of living waters, and cut them out cisterns, broken cisterns, that can hold no water."}}, {"id": 975, "coll": "무장 900구절", "sub": ["경계", "하나님을 떠남"], "book": "예레미야", "chap": 2, "verse": "19", "ref": "예레미야 2:19", "texts": {"krv": "네 악이 너를 징계하겠고 네 패역이 너를 책할 것이라 그런즉 네 하나님 여호와를 버림과 네 속에 나를 경외함이 없는 것이 악이요 고통인 줄 알라 주 만군의 여호와의 말이니라", "kkjv": "네 자신의 사악함이 너를 바로잡고 네 타락함이 너를 꾸짖으리라. 그런즉 네가 주 네 하나님을 버린 것과 네 속에 나를 두려워함이 없는 것이 악한 일이요, 쓰라린 일인 줄 알고 주의하라. 주 만군의 하나님이 말하노라.", "web": "“Your own wickedness shall correct you, and your backsliding shall reprove you. Know therefore and see that it is an evil thing and a bitter, that you have forsaken Yahweh your God, and that my fear is not in you,” says the Lord, Yahweh of Armies."}}, {"id": 976, "coll": "무장 900구절", "sub": ["경계", "하나님을 떠남"], "book": "스바냐", "chap": 1, "verse": "6", "ref": "스바냐 1:6", "texts": {"krv": "여호와를 배반하고 좇지 아니한 자와 여호와를 찾지도 아니하며 구하지도 아니한 자를 멸절하리라", "kkjv": "뒤로 물러나 주를 떠나는 자들과 주를 찾지도 아니하며 그를 위하여 묻지도 아니한 자들을 끊으리라.", "web": "those who have turned back from following Yahweh, and those who haven’t sought Yahweh nor inquired after him."}}, {"id": 977, "coll": "무장 900구절", "sub": ["경계", "하나님을 떠남"], "book": "히브리서", "chap": 3, "verse": "12", "ref": "히브리서 3:12", "texts": {"krv": "형제들아 너희가 삼가 혹 너희 중에 누가 믿지 아니하는 악심을 품고 살아 계신 하나님에게서 떨어질까 염려할 것이요", "kkjv": "형제들아, 너희 중의 어떤 사람에게 믿지 아니하는 악한 마음이 있어 살아 계신 하나님을 떠나는 일이 생기지 아니하도록 조심하라.", "web": "Beware, brothers, lest perhaps there be in any one of you an evil heart of unbelief, in falling away from the living God;"}}, {"id": 978, "coll": "무장 900구절", "sub": ["경계", "헛된 것을 의지함"], "book": "사무엘상", "chap": 12, "verse": "21", "ref": "사무엘상 12:21", "texts": {"krv": "돌이켜 유익하게도 못하며 구원하지도 못하는 헛된 것을 좇지 말라 그들은 헛되니라", "kkjv": "또한 너희는 돌이키지 말라. 그리하면 너희가 유익하게도 못하며 건져 내지도 못하는 헛된 것들을 따르리니 그것들은 헛된 것이니라.", "web": "Don’t turn aside to go after vain things which can’t profit nor deliver, for they are vain."}}, {"id": 979, "coll": "무장 900구절", "sub": ["경계", "헛된 것을 의지함"], "book": "욥기", "chap": 31, "verse": "24", "ref": "욥기 31:24", "texts": {"krv": "내가 언제 금으로 내 소망을 삼고 정금더러 너는 내 의뢰하는 바라 하였던가 언제 재물의 풍부함과 손으로 얻은 것이 많음으로 기뻐하였던가", "kkjv": "만일 내가 금을 내 소망으로 삼았거나 정금에게 이르기를, 너는 내가 확실히 믿는 바라, 하였다면", "web": "“If I have made gold my hope, and have said to the fine gold, ‘You are my confidence;’"}}, {"id": 980, "coll": "무장 900구절", "sub": ["경계", "헛된 것을 의지함"], "book": "시편", "chap": 39, "verse": "6", "ref": "시편 39:6", "texts": {"krv": "진실로 각 사람은 그림자 같이 다니고 헛된 일에 분요하며 재물을 쌓으나 누가 취할는지 알지 못하나이다", "kkjv": "분명히 모든 사람은 헛된 모습 속에서 걷나니 분명히 그들은 헛되이 소동하나이다. 그가 재물을 쌓으나 누가 그것을 거둘지 알지 못하나이다, 하였도다.", "web": "“Surely every man walks like a shadow. Surely they busy themselves in vain. He heaps up, and doesn’t know who shall gather."}}, {"id": 981, "coll": "무장 900구절", "sub": ["경계", "헛된 것을 의지함"], "book": "시편", "chap": 146, "verse": "3", "ref": "시편 146:3", "texts": {"krv": "방백들을 의지하지 말며 도울 힘이 없는 인생도 의지하지 말지니", "kkjv": "통치자들을 신뢰하지 말며 도움을 주지 못하는 사람의 아들도 신뢰하지 말라.", "web": "Don’t put your trust in princes, each a son of man in whom there is no help."}}, {"id": 982, "coll": "무장 900구절", "sub": ["경계", "헛된 것을 의지함"], "book": "이사야", "chap": 2, "verse": "22", "ref": "이사야 2:22", "texts": {"krv": "너희는 인생을 의지하지 말라 그의 호흡은 코에 있나니 수에 칠 가치가 어디 있느뇨", "kkjv": "너희는 사람을 의지하지 말라. 그의 숨은 그의 콧구멍에 있나니 어떤 점에서 그를 수에 넣어야 하겠느냐?", "web": "Stop trusting in man, whose breath is in his nostrils; for of what account is he?"}}, {"id": 983, "coll": "무장 900구절", "sub": ["경계", "헛된 것을 의지함"], "book": "예레미야", "chap": 17, "verse": "5", "ref": "예레미야 17:5", "texts": {"krv": "나 여호와가 이같이 말하노라 무릇 사람을 믿으며 혈육으로 그 권력을 삼고 마음이 여호와에게서 떠난 그 사람을 저주를 받을 것이라", "kkjv": "¶주가 이같이 말하노라. 사람을 신뢰하며 육체를 자기 무기로 삼고 마음이 주로부터 떠난 사람은 저주를 받으리라.", "web": "Thus says Yahweh: Cursed is the man who trusts in man, and makes flesh his arm, and whose heart departs from Yahweh."}}, {"id": 984, "coll": "무장 900구절", "sub": ["경계", "사람에게 영광을 구함"], "book": "마태복음", "chap": 6, "verse": "1", "ref": "마태복음 6:1", "texts": {"krv": "사람에게 보이려고 그들 앞에서 너희 의를 행치 않도록 주의하라 그렇지 아니하면 하늘에 계신 너희 아버지께 상을 얻지 못하느니라", "kkjv": "너희는 사람들에게 보이려고 그들 앞에서 구제하지 아니하도록 주의하라. 그렇지 않으면 하늘에 계신 너희 아버지께 너희가 보상을 받지 못하느니라.", "web": "“Be careful that you don’t do your charitable giving before men, to be seen by them, or else you have no reward from your Father who is in heaven."}}, {"id": 985, "coll": "무장 900구절", "sub": ["경계", "사람에게 영광을 구함"], "book": "마태복음", "chap": 23, "verse": "28", "ref": "마태복음 23:28", "texts": {"krv": "이와 같이 너희도 겉으로는 사람에게 옳게 보이되 안으로는 외식과 불법이 가득하도다", "kkjv": "이와 같이 너희도 겉으로는 사람들에게 의롭게 보이나 속에는 위선과 불법으로 가득하도다.", "web": "Even so you also outwardly appear righteous to men, but inwardly you are full of hypocrisy and iniquity."}}, {"id": 986, "coll": "무장 900구절", "sub": ["경계", "사람에게 영광을 구함"], "book": "누가복음", "chap": 16, "verse": "15", "ref": "누가복음 16:15", "texts": {"krv": "예수께서 이르시되 너희는 사람 앞에서 스스로 옳다 하는 자이나 너희 마음을 하나님께서 아시나니 사람 중에 높임을 받는 그것은 하나님 앞에 미움을 받는 것이니라", "kkjv": "그분께서 그들에게 이르시되, 너희는 사람들 앞에서 너희 자신을 의롭게 만드는 자들이나 너희 마음을 하나님께서 아시나니 사람들 가운데서 높이 평가받는 것은 하나님 보시기에 가증한 것이니라.", "web": "He said to them, “You are those who justify yourselves in the sight of men, but God knows your hearts. For that which is exalted among men is an abomination in the sight of God."}}, {"id": 987, "coll": "무장 900구절", "sub": ["경계", "사람에게 영광을 구함"], "book": "요한복음", "chap": 5, "verse": "41", "ref": "요한복음 5:41", "texts": {"krv": "나는 사람에게 영광을 취하지 아니하노라", "kkjv": "나는 사람들에게서 존귀를 받지 아니하노라.", "web": "I don’t receive glory from men."}}, {"id": 988, "coll": "무장 900구절", "sub": ["경계", "사람에게 영광을 구함"], "book": "요한복음", "chap": 12, "verse": "43", "ref": "요한복음 12:43", "texts": {"krv": "저희는 사람의 영광을 하나님의 영광보다 더 사랑하였더라", "kkjv": "이는 그들이 사람들의 칭찬을 하나님의 칭찬보다 더 사랑하였기 때문이더라.", "web": "for they loved men’s praise more than God’s praise."}}, {"id": 989, "coll": "무장 900구절", "sub": ["경계", "사람에게 영광을 구함"], "book": "데살로니가전서", "chap": 2, "verse": "6", "ref": "데살로니가전서 2:6", "texts": {"krv": "우리가 그리스도의 사도로 능히 존중할 터이나 그러나 너희에게든지 다른 이에게든지 사람에게는 영광을 구치 아니하고", "kkjv": "우리가 그리스도의 사도로서 부담을 줄 수도 있었으나 너희에게서든지 다른 사람들에게서든지 우리가 사람들에게서는 영광을 구하지 아니하였고", "web": "nor seeking glory from men (neither from you nor from others), when we might have claimed authority as apostles of Christ."}}, {"id": 990, "coll": "무장 900구절", "sub": ["Leadership", "Man of God"], "book": "출애굽기", "chap": 33, "verse": "11", "ref": "출애굽기 33:11", "texts": {"krv": "사람이 그 친구와 이야기함 같이 여호와께서는 모세와 대면하여 말씀하시며 모세는 진으로 돌아오나 그 수종자 눈의 아들 청년 여호수아는 회막을 떠나지 아니하니라", "kkjv": "주께서는 마치 사람이 자기 친구와 이야기하듯 모세와 얼굴을 마주 대하여 말씀하시니라. 그는 다시 진영으로 돌아왔으나 그의 종 곧 눈의 아들 청년 여호수아는 성막 밖으로 떠나지 아니하였더라.", "web": "Yahweh spoke to Moses face to face, as a man speaks to his friend. He turned again into the camp, but his servant Joshua, the son of Nun, a young man, didn’t depart from the Tent."}}, {"id": 991, "coll": "무장 900구절", "sub": ["Leadership", "Man of God"], "book": "에스라", "chap": 7, "verse": "10", "ref": "에스라 7:10", "texts": {"krv": "에스라가 여호와의 율법을 연구하여 준행하며 율례와 규례를 이스라엘에게 가르치기로 결심하였었더라", "kkjv": "이는 에스라가 주의 율법을 구하고 그것을 행하며 이스라엘에서 법규와 판단의 법도를 가르치려고 자기 마음을 예비하였기 때문이더라.", "web": "For Ezra had set his heart to seek Yahweh’s law, and to do it, and to teach in Israel statutes and ordinances."}}, {"id": 992, "coll": "무장 900구절", "sub": ["Leadership", "Man of God"], "book": "다니엘", "chap": 6, "verse": "10", "ref": "다니엘 6:10", "texts": {"krv": "다니엘이 이 조서에 어인이 찍힌 것을 알고도 자기 집에 돌아가서는 그 방의 예루살렘으로 향하여 열린 창에서 전에 행하던 대로 하루 세번씩 무릎을 꿇고 기도하며 그 하나님께 감사하였더라", "kkjv": "¶그런데 다니엘은 그 조서에 도장이 찍힌 것을 알고도 자기 집에 들어가 자기 방에서 예루살렘을 향하여 창문을 열고 전에 하던 대로 하루에 세 번씩 무릎을 꿇고 기도하며 자기 하나님 앞에서 감사를 드리더라.", "web": "When Daniel knew that the writing was signed, he went into his house (now his windows were open in his room toward Jerusalem) and he kneeled on his knees three times a day, and prayed, and gave thanks before his God, as he did before."}}, {"id": 993, "coll": "무장 900구절", "sub": ["Leadership", "Man of God"], "book": "누가복음", "chap": 4, "verse": "8", "ref": "누가복음 4:8", "texts": {"krv": "예수께서 대답하여 가라사대 기록하기를 주 너의 하나님께 경배하고 다만 그를 섬기라 하였느니라", "kkjv": "예수님께서 그에게 응답하여 이르시되, 사탄아, 너는 내 뒤로 물러가라. 기록된바, 너는 주 네 하나님께 경배하고 오직 그분만을 섬길지니라, 하였느니라, 하시더라.", "web": "Jesus answered him, “Get behind me Satan! For it is written, ‘You shall worship the Lord your God, and you shall serve him only.’”"}}, {"id": 994, "coll": "무장 900구절", "sub": ["Leadership", "Man of God"], "book": "요한복음", "chap": 5, "verse": "30", "ref": "요한복음 5:30", "texts": {"krv": "내가 아무것도 스스로 할 수 없노라 듣는 대로 심판하노니 나는 나의 원대로 하려 하지 않고 나를 보내신 이의 원대로 하려는 고로 내 심판은 의로우니라", "kkjv": "나는 아무것도 스스로 할 수 없노라. 나는 듣는 대로 심판하노니 내가 내 뜻을 구하지 아니하고 나를 보내신 아버지의 뜻을 구하므로 내 심판은 의로우니라.", "web": "I can of myself do nothing. As I hear, I judge, and my judgment is righteous; because I don’t seek my own will, but the will of my Father who sent me."}}, {"id": 995, "coll": "무장 900구절", "sub": ["Leadership", "Man of God"], "book": "사도행전", "chap": 5, "verse": "29", "ref": "사도행전 5:29", "texts": {"krv": "베드로와 사도들이 대답하여 가로되 사람보다 하나님을 순종하는 것이 마땅하니라", "kkjv": "¶이에 베드로와 다른 사도들이 응답하여 이르되, 우리가 사람들보다 하나님께 순종하는 것이 마땅하니라.", "web": "But Peter and the apostles answered, “We must obey God rather than men."}}, {"id": 996, "coll": "무장 900구절", "sub": ["Leadership", "Servant Leadership"], "book": "열왕기상", "chap": 12, "verse": "7", "ref": "열왕기상 12:7", "texts": {"krv": "대답하여 가로되 왕이 만일 오늘날 이 백성의 종이 되어 저희를 섬기고 좋은 말로 대답하여 이르시면 저희가 영영히 왕의 종이 되리이다 하나", "kkjv": "그들이 그에게 말하여 이르되, 왕이 만일 이 날 이 백성의 종이 되어 그들을 섬기고 그들에게 좋은 말로 대답하여 이르시면 그들이 영원토록 왕의 종이 되리이다, 하니라.", "web": "They spoke to him, saying, “If you will be a servant to this people this day, and will serve them, and answer them, and speak good words to them, then they will be your servants forever.”"}}, {"id": 997, "coll": "무장 900구절", "sub": ["Leadership", "Servant Leadership"], "book": "마태복음", "chap": 25, "verse": "40", "ref": "마태복음 25:40", "texts": {"krv": "임금이 대답하여 가라사대 내가 진실로 너희에게 이르노니 너희가 여기 내 형제 중에 지극히 작은 자 하나에게 한 것이 곧 내게 한 것이니라 하시고", "kkjv": "왕이 그들에게 대답하여 이르되, 진실로 내가 너희에게 이르노니, 너희가 이들 내 형제들 중에서 가장 작은 자 하나에게 그것을 하였은즉 내게 하였느니라, 하고", "web": "“The King will answer them, ‘Most certainly I tell you, because you did it to one of the least of these my brothers, you did it to me.’"}}, {"id": 998, "coll": "무장 900구절", "sub": ["Leadership", "Servant Leadership"], "book": "요한복음", "chap": 13, "verse": "14", "ref": "요한복음 13:14", "texts": {"krv": "내가 주와 또는 선생이 되어 너희 발을 씻겼으니 너희도 서로 발을 씻기는 것이 옳으니라", "kkjv": "그런즉 너희 주와 선생인 내가 너희 발을 씻어 주었으니 너희도 서로 발을 씻어 주는 것이 마땅하니라.", "web": "If I then, the Lord and the Teacher, have washed your feet, you also ought to wash one another’s feet."}}, {"id": 999, "coll": "무장 900구절", "sub": ["Leadership", "Servant Leadership"], "book": "사도행전", "chap": 20, "verse": "35", "ref": "사도행전 20:35", "texts": {"krv": "범사에 너희에게 모본을 보였노니 곧 이같이 수고하여 약한 사람들을 돕고 또 주 예수의 친히 말씀하신 바 주는 것이 받는 것보다 복이 있다 하심을 기억하여야 할지니라", "kkjv": "내가 너희에게 모든 것을 보여 주되 곧 너희가 마땅히 이렇게 수고하여 약한 자들을 지원하고 또 주 예수님께서 말씀하신 것 즉, 주는 것이 받는 것보다 더 복되도다, 하신 그분의 말씀을 기억하게 하였느니라.", "web": "In all things I gave you an example, that so laboring you ought to help the weak, and to remember the words of the Lord Jesus, that he himself said, ‘It is more blessed to give than to receive.’”"}}, {"id": 1000, "coll": "무장 900구절", "sub": ["Leadership", "Servant Leadership"], "book": "고린도후서", "chap": 12, "verse": "15", "ref": "고린도후서 12:15", "texts": {"krv": "내가 너희 영혼을 위하여 크게 기뻐함으로 재물을 허비하고 또 내 자신까지 허비하리니 너희를 더욱 사랑할수록 나는 덜 사랑을 받겠느냐", "kkjv": "너희를 더욱 넘치게 사랑할수록 내가 덜 사랑받는다 할지라도 나는 너희를 위하여 가진 것을 매우 기쁘게 쓰고 나 자신을 쓰리라.", "web": "I will most gladly spend and be spent for your souls. If I love you more abundantly, am I loved the less?"}}, {"id": 1001, "coll": "무장 900구절", "sub": ["Leadership", "Servant Leadership"], "book": "갈라디아서", "chap": 4, "verse": "19", "ref": "갈라디아서 4:19", "texts": {"krv": "나의 자녀들아 너희 속에 그리스도의 형상이 이루기까지 다시 너희를 위하여 해산하는 수고를 하노니", "kkjv": "나의 어린 자녀들아, 너희 속에 그리스도께서 형성되실 때까지 내가 다시 너희를 위해 해산하는 수고를 겪노라.", "web": "My little children, of whom I am again in travail until Christ is formed in you—"}}, {"id": 1002, "coll": "무장 900구절", "sub": ["Leadership", "Shepherd Leadership"], "book": "잠언", "chap": 27, "verse": "23", "ref": "잠언 27:23", "texts": {"krv": "네 양떼의 형편을 부지런히 살피며 네 소떼에 마음을 두라", "kkjv": "너는 네 양 떼의 형편을 부지런히 알아보며 네 소 떼를 잘 보살피라.", "web": "Know well the state of your flocks, and pay attention to your herds:"}}, {"id": 1003, "coll": "무장 900구절", "sub": ["Leadership", "Shepherd Leadership"], "book": "이사야", "chap": 40, "verse": "11", "ref": "이사야 40:11", "texts": {"krv": "그는 목자 같이 양 무리를 먹이시며 어린 양을 그 팔로 모아 품에 안으시며 젖 먹이는 암컷들을 온순히 인도하시리로다", "kkjv": "그분께서는 목자같이 자기 양 떼를 먹이시고 어린양들을 자기 팔로 모아 품에 안아 옮기시며 어린것들과 함께하는 어미들을 부드럽게 인도하시리로다.", "web": "He will feed his flock like a shepherd. He will gather the lambs in his arm, and carry them in his bosom. He will gently lead those who have their young."}}, {"id": 1004, "coll": "무장 900구절", "sub": ["Leadership", "Shepherd Leadership"], "book": "예레미야", "chap": 3, "verse": "15", "ref": "예레미야 3:15", "texts": {"krv": "내가 또 내 마음에 합하는 목자를 너희에게 주리니 그들이 지식과 명철로 너희를 양육하리라", "kkjv": "내가 또 내 마음에 맞는 목양자들을 너희에게 주리니 그들이 지식과 명철로 너희를 먹이리라.", "web": "I will give you shepherds according to my heart, who shall feed you with knowledge and understanding."}}, {"id": 1005, "coll": "무장 900구절", "sub": ["Leadership", "Shepherd Leadership"], "book": "요한복음", "chap": 10, "verse": "11-12", "ref": "요한복음 10:11-12", "texts": {"krv": "나는 선한 목자라 선한 목자는 양들을 위하여 목숨을 버리거니와 삯꾼은 목자도 아니요 양도 제 양이 아니라 이리가 오는 것을 보면 양을 버리고 달아나나니 이리가 양을 늑탈하고 또 헤치느니라", "kkjv": "나는 선한 목자니라. 선한 목자는 양들을 위해 자기 생명을 주거니와 목자가 아닌 삯군 곧 양들이 자기 것이 아닌 자는 이리가 오는 것을 보면 양들을 버리고 도망하나니 이리가 그것들을 붙잡아가고 또 양들을 헤치느니라.", "web": "I am the good shepherd.The good shepherd lays down his life for the sheep. He who is a hired hand, and not a shepherd, who doesn’t own the sheep, sees the wolf coming, leaves the sheep, and flees. The wolf snatches the sheep, and scatters them."}}, {"id": 1006, "coll": "무장 900구절", "sub": ["Leadership", "Shepherd Leadership"], "book": "사도행전", "chap": 20, "verse": "28", "ref": "사도행전 20:28", "texts": {"krv": "너희는 자기를 위하여 또는 온 양떼를 위하여 삼가라 성령이 저들 가운데 너희로 감독자를 삼고 하나님이 자기 피로 사신 교회를 치게 하셨느니라", "kkjv": "¶그러므로 너희 자신과 온 양 떼에게 주의를 기울이라. 성령님께서 너희를 그들의 감독자로 삼으사 하나님의 교회 곧 그분께서 자신의 피로 사신 교회를 먹이게 하셨느니라.", "web": "Take heed, therefore, to yourselves, and to all the flock, in which the Holy Spirit has made you overseers, to shepherd the assembly of the Lord and  God which he purchased with his own blood."}}, {"id": 1007, "coll": "무장 900구절", "sub": ["Leadership", "Shepherd Leadership"], "book": "베드로전서", "chap": 5, "verse": "2-4", "ref": "베드로전서 5:2-4", "texts": {"krv": "너희 중에 있는 하나님의 양 무리를 치되 부득이함으로 하지 말고 오직 하나님의 뜻을 좇아 자원함으로 하며 더러운 이를 위하여 하지 말고 오직 즐거운 뜻으로 하며 맡기운 자들에게 주장하는 자세를 하지 말고 오직 양 무리의 본이 되라 그리하면 목자장이 나타나실 때에 시들지 아니하는 영광의 면류관을 얻으리라", "kkjv": "너희 가운데 있는 하나님의 양 떼를 먹이고 감독하되 억지로 하지 말고 자진해서 하며 더러운 이익을 위해 하지 말고 오직 준비된 마음으로 하며 하나님의 상속 백성 위에 주인처럼 군림하지 말고 오직 양 떼에게 본이 되라. 그리하면 목자장께서 나타나실 때에 너희가 사라지지 아니하는 영광의 관을 받으리라.", "web": "Shepherd the flock of God which is among you, exercising the oversight, not under compulsion, but voluntarily, not for dishonest gain, but willingly; neither as lording it over those entrusted to you, but making yourselves examples to the flock. When the chief Shepherd is revealed, you will receive the crown of glory that doesn’t fade away."}}, {"id": 1008, "coll": "무장 900구절", "sub": ["Leadership", "Steward Leadership"], "book": "시편", "chap": 78, "verse": "72", "ref": "시편 78:72", "texts": {"krv": "이에 저가 그 마음의 성실함으로 기르고 그 손의 공교함으로 지도하였도다", "kkjv": "이에 그가 자기 마음의 순전함에 따라 그들을 먹이고 자기 손의 능숙함으로 그들을 지도하였도다.", "web": "So he was their shepherd according to the integrity of his heart, and guided them by the skillfulness of his hands."}}, {"id": 1009, "coll": "무장 900구절", "sub": ["Leadership", "Steward Leadership"], "book": "마태복음", "chap": 24, "verse": "45", "ref": "마태복음 24:45", "texts": {"krv": "충성되고 지혜 있는 종이 되어 주인에게 그 집 사람들을 맡아 때를 따라 양식을 나눠 줄 자가 누구뇨", "kkjv": "그런즉 자기 주인으로부터 그의 집안사람들을 넘겨받아 다스리며 제 때에 그들에게 양식을 나누어 줄 신실하고 지혜로운 종이 누구냐?", "web": "“Who then is the faithful and wise servant, whom his lord has set over his household, to give them their food in due season?"}}, {"id": 1010, "coll": "무장 900구절", "sub": ["Leadership", "Steward Leadership"], "book": "누가복음", "chap": 16, "verse": "10", "ref": "누가복음 16:10", "texts": {"krv": "지극히 작은 것에 충성된 자는 큰 것에도 충성되고 지극히 작은 것에 불의한 자는 큰 것에도 불의하니라", "kkjv": "가장 적은 것에 신실한 자는 또한 많은 것에 신실하고 가장 적은 것에 불의한 자는 또한 많은 것에 불의하니라.", "web": "He who is faithful in a very little is faithful also in much. He who is dishonest in a very little is also dishonest in much."}}, {"id": 1011, "coll": "무장 900구절", "sub": ["Leadership", "Steward Leadership"], "book": "누가복음", "chap": 19, "verse": "16-17", "ref": "누가복음 19:16-17", "texts": {"krv": "그 첫째가 나아와 가로되 주여 주의 한 므나로 열 므나를 남겼나이다 주인이 이르되 잘하였다 착한 종이여 네가 지극히 작은 것에 충성하였으니 열 고을 권세를 차지하라 하고", "kkjv": "이에 첫째가 와서 이르되, 주여, 주의 일 므나로 십 므나를 벌었나이다, 하매 그가 그에게 이르되, 잘하였도다, 선한 종아, 네가 매우 작은 일에 신실하였은즉 열 도시를 다스릴 권세를 차지하라, 하니라.", "web": "The first came before him, saying, ‘Lord, your mina has made ten more minas.’ “He said to him, ‘Well done, you good servant! Because you were found faithful with very little, you shall have authority over ten cities.’"}}, {"id": 1012, "coll": "무장 900구절", "sub": ["Leadership", "Steward Leadership"], "book": "고린도전서", "chap": 4, "verse": "1-2", "ref": "고린도전서 4:1-2", "texts": {"krv": "사람이 마땅히 우리를 그리스도의 일군이요 하나님의 비밀을 맡은 자로 여길지어다 그리고 맡은 자들에게 구할 것은 충성이니라", "kkjv": "사람이 마땅히 우리를 그리스도의 사역자요, 하나님의 신비들을 맡은 청지기로 여길지어다. 또한 청지기들에게 요구되는 것은 신실한 사람으로 드러나는 것이라.", "web": "So let a man think of us as Christ’s servants, and stewards of God’s mysteries. Here, moreover, it is required of stewards, that they be found faithful."}}, {"id": 1013, "coll": "무장 900구절", "sub": ["Leadership", "Steward Leadership"], "book": "베드로전서", "chap": 4, "verse": "10", "ref": "베드로전서 4:10", "texts": {"krv": "각각 은사를 받은 대로 하나님의 각양 은혜를 맡은 선한 청지기 같이 서로 봉사하라", "kkjv": "각 사람이 선물을 받은 대로 하나님의 여러 가지 은혜를 맡은 선한 청지기로서 서로 그 선물을 써서 섬기라.", "web": "As each has received a gift, employ it in serving one another, as good managers of the grace of God in its various forms."}}, {"id": 1014, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 찾음"], "book": "시편", "chap": 42, "verse": "1", "ref": "시편 42:1", "texts": {"krv": "하나님이여 사슴이 시냇물을 찾기에 갈급함 같이 내 영혼이 주를 찾기에 갈급하니이다", "kkjv": "오 하나님이여, 사슴이 물 시내를 찾기에 갈급함같이 내 혼이 주를 찾기에 갈급하나이다.", "web": "As the deer pants for the water brooks, so my soul pants after you, God."}}, {"id": 1015, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 찾음"], "book": "시편", "chap": 105, "verse": "3-4", "ref": "시편 105:3-4", "texts": {"krv": "그 성호를 자랑하라 무릇 여호와를 구하는 자는 마음이 즐거울지로다 여호와와 그 능력을 구할지어다 그 얼굴을 항상 구할지어다", "kkjv": "너희는 그분의 거룩한 이름을 자랑하라. 주를 구하는 자들의 마음은 기뻐할지어다. 주와 그분의 능력을 구할지어다. 항상 그분의 얼굴을 구할지어다.", "web": "Glory in his holy name. Let the heart of those who seek Yahweh rejoice. Seek Yahweh and his strength. Seek his face forever more."}}, {"id": 1016, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 찾음"], "book": "시편", "chap": 145, "verse": "18", "ref": "시편 145:18", "texts": {"krv": "여호와께서는 자기에게 간구하는 모든 자 곧 진실하게 간구하는 모든 자에게 가까이 하시는도다", "kkjv": "주께서는 자신을 부르는 모든 자 곧 진리 안에서 자신을 부르는 모든 자에게 가까이 계시는도다.", "web": "Yahweh is near to all those who call on him, to all who call on him in truth."}}, {"id": 1017, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 찾음"], "book": "잠언", "chap": 8, "verse": "17", "ref": "잠언 8:17", "texts": {"krv": "나를 사랑하는 자들이 나의 사랑을 입으며 나를 간절히 찾는 자가 나를 만날 것이니라", "kkjv": "나를 사랑하는 자들을 내가 사랑하나니 일찍 나를 찾는 자들이 나를 만나리라.", "web": "I love those who love me. Those who seek me diligently will find me."}}, {"id": 1018, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 찾음"], "book": "이사야", "chap": 55, "verse": "6", "ref": "이사야 55:6", "texts": {"krv": "너희는 여호와를 만날 만한 때에 찾으라 가까이 계실 때에 그를 부르라", "kkjv": "¶너희는 주를 만날 만한 때에 그분을 찾으라. 그분께서 가까이 계실 때에 그분을 부르라.", "web": "Seek Yahweh while he may be found; call you on him while he is near:"}}, {"id": 1019, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 찾음"], "book": "예레미야", "chap": 29, "verse": "12-13", "ref": "예레미야 29:12-13", "texts": {"krv": "너희는 내게 부르짖으며 와서 내게 기도하면 내가 너희를 들을 것이요 너희가 전심으로 나를 찾고 찾으면 나를 만나리라", "kkjv": "그때에는 너희가 나를 부르고 가서 내게 기도하리니 내가 너희 말에 귀를 기울이리라. 또 너희가 너희 마음을 다하여 나를 찾으면 나를 찾고 나를 만나리라.", "web": "You shall call on me, and you shall go and pray to me, and I will listen to you. You shall seek me, and find me, when you shall search for me with all your heart."}}, {"id": 1020, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 경외함"], "book": "창세기", "chap": 22, "verse": "12", "ref": "창세기 22:12", "texts": {"krv": "사자가 가라사대 그 아이에게 네 손을 대지 말라 아무 일도 그에게 하지 말라 네가 네 아들 네 독자라도 내게 아끼지 아니하였으니 내가 이제야 네가 하나님을 경외하는 줄을 아노라", "kkjv": "그가 이르되, 네 손을 그 아이에게 대지 말라. 너는 아무 일도 그에게 하지 말라. 네가 네 아들 곧 네 유일한 아들을 내게 아끼지 아니하였으므로 네가 하나님을 두려워하는 줄 내가 이제 아노라, 하니라.", "web": "He said, “Don’t lay your hand on the boy, neither do anything to him. For now I know that you fear God, since you have not withheld your son, your only son, from me.”"}}, {"id": 1021, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 경외함"], "book": "시편", "chap": 34, "verse": "9", "ref": "시편 34:9", "texts": {"krv": "너희 성도들아 여호와를 경외하라 저를 경외하는 자에게는 부족함이 없도다", "kkjv": "오 주의 성도들아, 너희는 그분을 두려워하라. 그분을 두려워하는 자들에게는 부족함이 없도다.", "web": "Oh fear Yahweh, you his saints, for there is no lack with those who fear him."}}, {"id": 1022, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 경외함"], "book": "시편", "chap": 103, "verse": "17", "ref": "시편 103:17", "texts": {"krv": "여호와의 인자하심은 자기를 경외하는 자에게 영원부터 영원까지 이르며 그의 의는 자손의 자손에게 미치리니", "kkjv": "주의 긍휼은 그분을 두려워하는 자들에게 영원부터 영원까지 임하며 그분의 의는 자손의 자손에게 미치나니", "web": "But Yahweh’s loving kindness is from everlasting to everlasting with those who fear him, his righteousness to children’s children;"}}, {"id": 1023, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 경외함"], "book": "잠언", "chap": 19, "verse": "23", "ref": "잠언 19:23", "texts": {"krv": "여호와를 경외하는 것은 사람으로 생명에 이르게 하는 것이라 경외하는 자는 족하게 지내고 재앙을 만나지 아니하느니라", "kkjv": "주를 두려워함이 생명에 이르게 하나니 그것을 지닌 자는 흡족히 지내고 재앙으로 징벌을 받지 아니하리라.", "web": "The fear of Yahweh leads to life, then contentment; he rests and will not be touched by trouble."}}, {"id": 1024, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 경외함"], "book": "잠언", "chap": 23, "verse": "17-18", "ref": "잠언 23:17-18", "texts": {"krv": "네 마음으로 죄인의 형통을 부러워하지 말고 항상 여호와를 경외하라 정녕히 네 장래가 있겠고 네 소망이 끊어지지 아니하리라", "kkjv": "너는 마음에서 죄인들을 부러워하지 말며 종일토록 주를 두려워하라. 분명히 끝이 있고 너의 기대하는 바가 끊어지지 아니하리로다.", "web": "Don’t let your heart envy sinners; but rather fear Yahweh all the day long. Indeed surely there is a future hope, and your hope will not be cut off."}}, {"id": 1025, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 경외함"], "book": "전도서", "chap": 12, "verse": "13", "ref": "전도서 12:13", "texts": {"krv": "일의 결국을 다 들었으니 하나님을 경외하고 그 명령을 지킬지어다 이것이 사람의 본분이니라", "kkjv": "¶우리가 전체 일의 결론을 들을지니 하나님을 두려워하고 그분의 명령들을 지킬지어다. 이것이 사람의 온전한 의무이니라.", "web": "This is the end of the matter. All has been heard. Fear God, and keep his commandments; for this is the whole duty of man."}}, {"id": 1026, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 사랑함"], "book": "신명기", "chap": 6, "verse": "5", "ref": "신명기 6:5", "texts": {"krv": "너는 마음을 다하고 성품을 다하고 힘을 다하여 네 하나님 여호와를 사랑하라", "kkjv": "너는 네 마음을 다하고 혼을 다하고 힘을 다하여 주 네 하나님을 사랑하라.", "web": "You shall love Yahweh your God with all your heart, with all your soul, and with all your might."}}, {"id": 1027, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 사랑함"], "book": "여호수아", "chap": 23, "verse": "11", "ref": "여호수아 23:11", "texts": {"krv": "그러므로 스스로 조심하여 너희 하나님 여호와를 사랑하라", "kkjv": "그러므로 너희는 스스로 매우 조심하여 주 너희 하나님을 사랑하라.", "web": "Take good heed therefore to yourselves, that you love Yahweh your God."}}, {"id": 1028, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 사랑함"], "book": "사무엘상", "chap": 12, "verse": "24", "ref": "사무엘상 12:24", "texts": {"krv": "너희는 여호와께서 너희를 위하여 행하신 그 큰 일을 생각하여 오직 그를 경외하며 너희의 마음을 다하여 진실히 섬기라", "kkjv": "주께서 너희를 위하여 얼마나 큰일들을 행하셨는지 깊이 생각하여 오직 그분을 두려워하며 너희 마음을 다해 진리 안에서 그분을 섬기라.", "web": "Only fear Yahweh, and serve him in truth with all your heart; for consider how great things he has done for you."}}, {"id": 1029, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 사랑함"], "book": "시편", "chap": 31, "verse": "23", "ref": "시편 31:23", "texts": {"krv": "너희 모든 성도들아 여호와를 사랑하라 여호와께서 성실한 자를 보호하시고 교만히 행하는 자에게 엄중히 갚으시느니라", "kkjv": "오 주의 모든 성도들아, 너희는 그분을 사랑하라. 주께서 신실한 자는 보존하시되 교만히 행하는 자는 넘치게 되갚아 주시느니라.", "web": "Oh love Yahweh, all you his saints! Yahweh preserves the faithful, and fully recompenses him who behaves arrogantly."}}, {"id": 1030, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 사랑함"], "book": "고린도전서", "chap": 8, "verse": "3", "ref": "고린도전서 8:3", "texts": {"krv": "또 누구든지 하나님을 사랑하면 이 사람은 하나님의 아시는 바 되었느니라", "kkjv": "그러나 어떤 사람이 하나님을 사랑하면 그분께서도 바로 그 사람을 아시느니라.", "web": "But if anyone loves God, the same is known by him."}}, {"id": 1031, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 사랑함"], "book": "요한일서", "chap": 5, "verse": "3", "ref": "요한일서 5:3", "texts": {"krv": "하나님을 사랑하는 것은 이것이니 우리가 그의 계명들을 지키는 것이라 그의 계명들은 무거운 것이 아니로다", "kkjv": "우리가 그분의 명령들을 지키는 것, 이것이 곧 하나님을 사랑하는 것이니라. 그분의 명령들은 무겁지 아니하니라.", "web": "For this is the love of God, that we keep his commandments. His commandments are not grievous."}}, {"id": 1032, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 앙망함"], "book": "시편", "chap": 25, "verse": "15", "ref": "시편 25:15", "texts": {"krv": "내 눈이 항상 여호와를 앙망함은 내 발을 그물에서 벗어나게 하실 것임이로다", "kkjv": "주께서 내 발을 그물에서 빼내실 터이므로 내 눈이 항상 그분을 향하는도다.", "web": "My eyes are ever on Yahweh, for he will pluck my feet out of the net."}}, {"id": 1033, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 앙망함"], "book": "시편", "chap": 42, "verse": "2", "ref": "시편 42:2", "texts": {"krv": "내 영혼이 하나님 곧 생존하시는 하나님을 갈망하나니 내가 어느 때에 나아가서 하나님 앞에 뵈올꼬", "kkjv": "내 혼이 하나님 곧 살아 계신 하나님을 찾기에 목이 타니 내가 어느 때에 가서 하나님 앞에 보이리요?", "web": "My soul thirsts for God, for the living God. When shall I come and appear before God?"}}, {"id": 1034, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 앙망함"], "book": "시편", "chap": 73, "verse": "25", "ref": "시편 73:25", "texts": {"krv": "하늘에서는 주 외에 누가 내게 있으리요 땅에서는 주밖에 나의 사모할 자 없나이다", "kkjv": "하늘에서는 주 외에 누가 내게 있나이까? 땅에서는 주 외에 내가 사모할 자가 아무도 없나이다.", "web": "Whom do I have in heaven? There is no one on earth whom I desire besides you."}}, {"id": 1035, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 앙망함"], "book": "이사야", "chap": 33, "verse": "2", "ref": "이사야 33:2", "texts": {"krv": "여호와여 우리에게 은혜를 베푸소서 우리가 주를 앙망하오니 주는 아침마다 우리의 팔이 되시며 환난 때에 우리의 구원이 되소서", "kkjv": "오 주여, 우리에게 은혜를 베푸소서. 우리가 주를 기다렸사오니 주께서는 아침마다 그들의 팔이 되시오며 고난의 때에 또한 우리의 구원이 되시옵소서.", "web": "Yahweh, be gracious to us. We have waited for you. Be our strength every morning, our salvation also in the time of trouble."}}, {"id": 1036, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 앙망함"], "book": "이사야", "chap": 40, "verse": "31", "ref": "이사야 40:31", "texts": {"krv": "오직 여호와를 앙망하는 자는 새 힘을 얻으리니 독수리의 날개 치며 올라감 같을 것이요 달음박질하여도 곤비치 아니하겠고 걸어가도 피곤치 아니하리로다", "kkjv": "오직 주를 우러러 바라는 자들은 자기 힘을 회복하리니 그들은 독수리같이 날개 치며 올라갈 것이요, 달려가도 피곤하지 아니하고 걸어가도 기진하지 아니하리로다.", "web": "But those who wait for Yahweh will renew their strength. They will mount up with wings like eagles. They will run, and not be weary. They will walk, and not faint."}}, {"id": 1037, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 앙망함"], "book": "디모데전서", "chap": 4, "verse": "10", "ref": "디모데전서 4:10", "texts": {"krv": "이를 위하여 우리가 수고하고 진력하는 것은 우리 소망을 살아 계신 하나님께 둠이니 곧 모든 사람 특히 믿는 자들의 구주시라", "kkjv": "이런 까닭에 우리가 수고하고 치욕을 당하나니 이는 우리가 살아 계신 하나님을 신뢰하기 때문이라. 그분은 모든 사람의 구원자시요 특히 믿는 자들의 구원자시니라.", "web": "For to this end we both labor and suffer reproach, because we have set our trust in the living God, who is the Savior of all men, especially of those who believe."}}, {"id": 1038, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 의뢰함"], "book": "시편", "chap": 22, "verse": "5", "ref": "시편 22:5", "texts": {"krv": "저희가 주께 부르짖어 구원을 얻고 주께 의뢰하여 수치를 당치 아니하였나이다", "kkjv": "그들이 주께 부르짖어 구출을 받았고 주를 신뢰하여 당황하지 아니하였나이다.", "web": "They cried to you, and were delivered. They trusted in you, and were not disappointed."}}, {"id": 1039, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 의뢰함"], "book": "시편", "chap": 55, "verse": "22", "ref": "시편 55:22", "texts": {"krv": "네 짐을 여호와께 맡겨 버리라 너를 붙드시고 의인의 요동함을 영영히 허락지 아니하시리로다", "kkjv": "네 짐을 주께 맡기라. 그러면 그분께서 너를 붙드시고 의로운 자가 흔들리는 것을 결코 허락하지 아니하시리로다.", "web": "Cast your burden on Yahweh, and he will sustain you. He will never allow the righteous to be moved."}}, {"id": 1040, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 의뢰함"], "book": "전도서", "chap": 12, "verse": "1", "ref": "전도서 12:1", "texts": {"krv": "너는 청년의 때 곧 곤고한 날이 이르기 전 나는 아무 낙이 없다고 할 해가 가깝기 전에 너의 창조자를 기억하라", "kkjv": "이제 네 젊은 시절에 네 창조자를 기억하라. 곧 재난의 날들이 이르기 전에 혹은 네가 말하기를, 내가 이 해들을 기뻐하지 아니하노라, 하는 그런 해들이 가까이 이르기 전에", "web": "Remember also your Creator in the days of your youth,  before the evil days come, and the years draw near, when you will say, “I have no pleasure in them”;"}}, {"id": 1041, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 의뢰함"], "book": "이사야", "chap": 50, "verse": "10", "ref": "이사야 50:10", "texts": {"krv": "너희 중에 여호와를 경외하며 그 종의 목소리를 청종하는 자가 누구뇨 흑암 중에 행하여 빛이 없는 자라도 여호와의 이름을 의뢰하며 자기 하나님께 의지할지어다", "kkjv": "¶너희 가운데 누가 주를 두려워하고 그분의 종의 목소리에 순종하며 빛이 없이 어둠 속에 다니느냐? 그는 주의 이름을 신뢰하고 자기 하나님을 의지할지니라.", "web": "Who is among you who fears Yahweh, who obeys the voice of his servant? He who walks in darkness, and has no light, let him trust in Yahweh’s name, and rely on his God."}}, {"id": 1042, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 의뢰함"], "book": "고린도후서", "chap": 1, "verse": "9", "ref": "고린도후서 1:9", "texts": {"krv": "우리 마음에 사형 선고를 받은 줄 알았으니 이는 우리로 자기를 의뢰하지 말고 오직 죽은 자를 다시 살리시는 하나님만 의뢰하게 하심이라", "kkjv": "우리 속에 죽음의 선고를 받았으니 이것은 우리가 우리 자신을 신뢰하지 아니하고 죽은 자들을 일으키시는 하나님을 신뢰하게 하려 함이라.", "web": "Yes, we ourselves have had the sentence of death within ourselves, that we should not trust in ourselves, but in God who raises the dead,"}}, {"id": 1043, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 의뢰함"], "book": "디모데후서", "chap": 1, "verse": "12", "ref": "디모데후서 1:12", "texts": {"krv": "이를 인하여 내가 또 이 고난을 받되 부끄러워하지 아니함은 나의 의뢰한 자를 내가 알고 또한 나의 의탁한 것을 그 날까지 저가 능히 지키실 줄을 확신함이라", "kkjv": "이런 까닭에 나도 이 일들로 고난을 당하되 그럼에도 불구하고 부끄러워하지 아니하노니 나는 내가 믿어 온 분을 알며 또 내가 그 날을 대비하여 그분께 맡긴 것을 그분께서 능히 지키실 줄 확신하노라.", "web": "For this cause I also suffer these things.   Yet I am not ashamed, for I know him whom I have believed, and I am persuaded that he is able to guard that which I have committed to him against that day."}}, {"id": 1044, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 기쁘시게 함"], "book": "잠언", "chap": 16, "verse": "7", "ref": "잠언 16:7", "texts": {"krv": "사람의 행위가 여호와를 기쁘시게 하면 그 사람의 원수라도 그로 더불어 화목하게 하시느니라", "kkjv": "사람의 길들이 주를 기쁘게 하면 그분께서 그의 원수들까지도 그와 화목하게 하시느니라.", "web": "When a man’s ways please Yahweh, he makes even his enemies to be at peace with him."}}, {"id": 1045, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 기쁘시게 함"], "book": "고린도후서", "chap": 5, "verse": "9", "ref": "고린도후서 5:9", "texts": {"krv": "그런즉 우리는 거하든지 떠나든지 주를 기쁘시게 하는 자 되기를 힘쓰노라", "kkjv": "그러므로 우리는 함께 있든지 떨어져 있든지 그분께서 받아 주시는 자가 되려고 수고하노라.", "web": "Therefore also we make it our aim, whether at home or absent, to be well pleasing to him."}}, {"id": 1046, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 기쁘시게 함"], "book": "에베소서", "chap": 5, "verse": "10", "ref": "에베소서 5:10", "texts": {"krv": "주께 기쁘시게 할 것이 무엇인가 시험하여 보라", "kkjv": "주께서 받으실 만한 것이 무엇인지 입증하라.", "web": "proving what is well pleasing to the Lord."}}, {"id": 1047, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 기쁘시게 함"], "book": "골로새서", "chap": 1, "verse": "10", "ref": "골로새서 1:10", "texts": {"krv": "주께 합당히 행하여 범사에 기쁘시게 하고 모든 선한 일에 열매를 맺게 하시며 하나님을 아는 것에 자라게 하시고", "kkjv": "주께 합당하게 걸어 모든 일에서 그분을 기쁘게 하고 모든 선한 일에서 열매를 맺으며 하나님을 아는 것에서 자라나고", "web": "that you may walk worthily of the Lord, to please him in all respects, bearing fruit in every good work, and increasing in the knowledge of God;"}}, {"id": 1048, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 기쁘시게 함"], "book": "히브리서", "chap": 12, "verse": "28", "ref": "히브리서 12:28", "texts": {"krv": "그러므로 우리가 진동치 못할 나라를 받았은즉 은혜를 받자 이로 말미암아 경건함과 두려움으로 하나님을 기쁘시게 섬길지니", "kkjv": "그러므로 우리가 움직일 수 없는 왕국을 받을진대 은혜를 소유하자. 이 은혜를 힘입어 우리가 공경하는 마음과 하나님께 속한 두려움을 가지고 받으실 만하게 하나님을 섬길지니", "web": "Therefore, receiving a Kingdom that can’t be shaken, let us have grace, through which we serve God acceptably, with reverence and awe,"}}, {"id": 1049, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 기쁘시게 함"], "book": "요한일서", "chap": 3, "verse": "22", "ref": "요한일서 3:22", "texts": {"krv": "무엇이든지 구하는 바를 그에게 받나니 이는 우리가 그의 계명들을 지키고 그 앞에서 기뻐하시는 것을 행함이라", "kkjv": "무엇이든지 우리가 구하는 것을 그분에게서 받나니 이는 우리가 그분의 명령들을 지키고 그분의 눈앞에서 기쁨이 되는 그 일들을 행하기 때문이라.", "web": "and whatever we ask, we receive from him, because we keep his commandments and do the things that are pleasing in his sight."}}, {"id": 1050, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 기뻐함"], "book": "느헤미야", "chap": 8, "verse": "10", "ref": "느헤미야 8:10", "texts": {"krv": "느헤미야가 또 이르기를 너희는 가서 살진 것을 먹고 단 것을 마시되 예비치 못한 자에게는 너희가 나누어 주라 이 날은 우리 주의 성일이니 근심하지 말라 여호와를 기뻐하는 것이 너희의 힘이니라 하고", "kkjv": "그때에 그가 그들에게 이르기를, 너희 길로 가서 기름진 것을 먹고 단 것을 마시며 아무것도 예비하지 못한 자들에게 일부를 보내라. 이 날은 우리 주께 거룩한 날이니라. 너희는 또한 슬퍼하지 말라. 주의 기쁨이 너희의 힘이니라, 하고", "web": "Then he said to them, “Go your way. Eat the fat, drink the sweet, and send portions to him for whom nothing is prepared; for this day is holy to our Lord. Don’t be grieved; for the joy of Yahweh is your strength.”"}}, {"id": 1051, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 기뻐함"], "book": "시편", "chap": 5, "verse": "11", "ref": "시편 5:11", "texts": {"krv": "오직 주에게 피하는 자는 다 기뻐하며 주의 보호로 인하여 영영히 기뻐 외치며 주의 이름을 사랑하는 자들은 주를 즐거워하리이다", "kkjv": "그러나 주를 신뢰하는 모든 자들은 기뻐하며 주께서 그들을 보호하심으로 인해 항상 기뻐 외치게 하소서. 또 주의 이름을 사랑하는 자들도 주를 기뻐하게 하소서.", "web": "But let all those who take refuge in you rejoice, Let them always shout for joy, because you defend them. Let them also who love your name be joyful in you."}}, {"id": 1052, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 기뻐함"], "book": "시편", "chap": 32, "verse": "11", "ref": "시편 32:11", "texts": {"krv": "너희 의인들아 여호와를 기뻐하며 즐거워 할지어다 마음이 정직한 너희들아 다 즐거이 외칠지어다", "kkjv": "의로운 자들아, 너희는 주를 기뻐하며 즐거워할지어다. 마음이 올바른 모든 자들아, 너희는 기쁘게 외칠지어다.", "web": "Be glad in Yahweh, and rejoice, you righteous! Shout for joy, all you who are upright in heart!"}}, {"id": 1053, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 기뻐함"], "book": "시편", "chap": 34, "verse": "2", "ref": "시편 34:2", "texts": {"krv": "내 영혼이 여호와로 자랑하리니 곤고한 자가 이를 듣고 기뻐하리로다", "kkjv": "내 혼이 주를 자랑하리니 겸손한 자들이 그것을 듣고 즐거워하리로다.", "web": "My soul shall boast in Yahweh. The humble shall hear of it, and be glad."}}, {"id": 1054, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 기뻐함"], "book": "이사야", "chap": 61, "verse": "10", "ref": "이사야 61:10", "texts": {"krv": "내가 여호와로 인하여 크게 기뻐하며 내 영혼이 나의 하나님으로 인하여 즐거워하리니 이는 그가 구원의 옷으로 내게 입히시며 의의 겉옷으로 내게 더하심이 신랑이 사모를 쓰며 신부가 자기 보물로 단장함 같게 하셨음이라", "kkjv": "내가 주를 크게 기뻐하며 내 혼이 내 하나님을 기뻐하리니 이는 마치 신랑이 장식으로 자기를 꾸미고 신부가 보석으로 자기를 단장하는 것 같이 그분께서 구원의 옷으로 나를 입히시고 의의 겉옷으로 나를 덮으셨기 때문이라.", "web": "I will greatly rejoice in Yahweh, my soul shall be joyful in my God; for he has clothed me with the garments of salvation, he has covered me with the robe of righteousness, as a bridegroom decks himself with a garland, and as a bride adorns herself with her jewels."}}, {"id": 1055, "coll": "무장 900구절", "sub": ["Leadership", "하나님을 기뻐함"], "book": "하박국", "chap": 3, "verse": "17-18", "ref": "하박국 3:17-18", "texts": {"krv": "비록 무화과나무가 무성치 못하며 포도나무에 열매가 없으며 감람나무에 소출이 없으며 밭에 식물이 없으며 우리에 양이 없으며 외양간에 소가 없을지라도 나는 여호와를 인하여 즐거워하며 나의 구원의 하나님을 인하여 기뻐하리로다", "kkjv": "¶비록 무화과나무가 꽃을 피우지 못하고 포도나무에 열매가 없으며 올리브나무에 수고의 열매가 없고 밭이 먹을 것을 내지 아니하며 우리에서 양 떼가 끊어지고 외양간에 소 떼가 없을지라도 나는 여전히 주를 기뻐하며 내 구원의 하나님을 기뻐하리로다.", "web": "For though the fig tree doesn’t flourish, nor fruit be in the vines; the labor of the olive fails, the fields yield no food; the flocks are cut off from the fold, and there is no herd in the stalls: yet I will rejoice in Yahweh. I will be joyful in the God of my salvation!"}}, {"id": 1056, "coll": "무장 900구절", "sub": ["Leadership", "하나님께 영광을 돌림"], "book": "시편", "chap": 22, "verse": "23", "ref": "시편 22:23", "texts": {"krv": "여호와를 두려워하는 너희여 그를 찬송할지어다 야곱의 모든 자손이여 그에게 영광을 돌릴지어다 너희 이스라엘 모든 자손이여 그를 경외할지어다", "kkjv": "주를 두려워하는 자들아, 너희는 그분을 찬양하라. 야곱의 모든 씨야, 너희는 그분께 영광을 돌릴지어다. 이스라엘의 모든 씨야, 너희는 그분을 두려워할지어다.", "web": "You who fear Yahweh, praise him! All you descendants of Jacob, glorify him! Stand in awe of him, all you descendants of Israel!"}}, {"id": 1057, "coll": "무장 900구절", "sub": ["Leadership", "하나님께 영광을 돌림"], "book": "시편", "chap": 29, "verse": "2", "ref": "시편 29:2", "texts": {"krv": "여호와의 이름에 합당한 영광을 돌리며 거룩한 옷을 입고 여호와께 경배할지어다", "kkjv": "주의 이름에 합당한 영광을 그분께 드리며 거룩함의 아름다움으로 주께 경배할지어다.", "web": "Ascribe to Yahweh the glory due to his name. Worship Yahweh in holy array."}}, {"id": 1058, "coll": "무장 900구절", "sub": ["Leadership", "하나님께 영광을 돌림"], "book": "시편", "chap": 50, "verse": "15", "ref": "시편 50:15", "texts": {"krv": "환난 날에 나를 부르라 내가 너를 건지리니 네가 나를 영화롭게 하리로다", "kkjv": "고난의 날에 나를 부르라. 내가 너를 건지리니 네가 나를 영화롭게 하리로다.", "web": "Call on me in the day of trouble. I will deliver you, and you will honor me.”"}}, {"id": 1059, "coll": "무장 900구절", "sub": ["Leadership", "하나님께 영광을 돌림"], "book": "시편", "chap": 66, "verse": "2", "ref": "시편 66:2", "texts": {"krv": "그 이름의 영광을 찬양하고 영화롭게 찬송할지어다", "kkjv": "그분의 이름의 존귀하심을 노래하고 영화롭게 그분을 찬양할지어다.", "web": "Sing to the glory of his name! Offer glory and praise!"}}, {"id": 1060, "coll": "무장 900구절", "sub": ["Leadership", "하나님께 영광을 돌림"], "book": "시편", "chap": 96, "verse": "3", "ref": "시편 96:3", "texts": {"krv": "그 영광을 열방 중에 그 기이한 행적을 만민 중에 선포할지어다", "kkjv": "그분의 영광을 이교도들 가운데, 그분의 이적들을 모든 백성들 가운데 밝히 알릴지어다.", "web": "Declare his glory among the nations, his marvelous works among all the peoples."}}, {"id": 1061, "coll": "무장 900구절", "sub": ["Leadership", "하나님께 영광을 돌림"], "book": "고린도전서", "chap": 6, "verse": "19-20", "ref": "고린도전서 6:19-20", "texts": {"krv": "너희 몸은 너희가 하나님께로부터 받은 바 너희 가운데 계신 성령의 전인 줄을 알지 못하느냐 너희는 너희의 것이 아니라 값으로 산 것이 되었으니 그런즉 너희 몸으로 하나님께 영광을 돌리라", "kkjv": "도대체 무슨 말이냐? 너희 몸이 너희가 하나님에게서 받은바 너희 안에 계신 성령님의 전인 줄을 너희가 알지 못하느냐? 너희는 너희 자신의 것이 아니니 주께서 값을 치르고 너희를 사셨느니라. 그런즉 하나님의 것인 너희 몸과 너희 영으로 하나님께 영광을 돌리라.", "web": "Or don’t you know that your body is a temple of the Holy Spirit which is in you, which you have from God? You are not your own, for you were bought with a price. Therefore glorify God in your body and in your spirit, which are God’s."}}, {"id": 1062, "coll": "무장 900구절", "sub": ["하나님을 알아감", "크신 하나님"], "book": "신명기", "chap": 3, "verse": "24", "ref": "신명기 3:24", "texts": {"krv": "주 여호와여 주께서 주의 크심과 주의 권능을 주의 종에게 나타내시기를 시작하였사오니 천지간에 무슨 신이 능히 주의 행하신 일 곧 주의 큰 능력으로 행하신 일 같이 행할 수 있으리이까", "kkjv": "오 주 하나님이여, 주께서 주의 위대하심과 주의 강한 손을 주의 종에게 보여 주기 시작하셨사오니 하늘이나 땅의 어떤 신이 능히 주께서 행하신 일과 주의 크신 능력과 같이 행할 수 있사오리이까?", "web": "“Lord Yahweh, you have begun to show your servant your greatness, and your strong hand. For what god is there in heaven or in earth that can do works like yours, and mighty acts like yours?"}}, {"id": 1063, "coll": "무장 900구절", "sub": ["하나님을 알아감", "크신 하나님"], "book": "사무엘상", "chap": 12, "verse": "22", "ref": "사무엘상 12:22", "texts": {"krv": "여호와께서는 너희로 자기 백성 삼으신 것을 기뻐하신 고로 그 크신 이름을 인하여 자기 백성을 버리지 아니하실 것이요", "kkjv": "주께서 너희를 자신의 백성으로 삼으신 것을 기뻐하셨으므로 자신의 크신 이름으로 인하여 주께서 자신의 백성을 버리지 아니하실 것이요,", "web": "For Yahweh will not forsake his people for his great name’s sake, because it has pleased Yahweh to make you a people to himself."}}, {"id": 1064, "coll": "무장 900구절", "sub": ["하나님을 알아감", "크신 하나님"], "book": "역대하", "chap": 2, "verse": "5", "ref": "역대하 2:5", "texts": {"krv": "내가 건축하고자 하는 전은 크니 우리 하나님은 모든 신보다 크심이라", "kkjv": "내가 건축하는 집은 크니 우리 하나님은 모든 신보다 위대하시나이다.", "web": "“The house which I build is great; for our God is great above all gods."}}, {"id": 1065, "coll": "무장 900구절", "sub": ["하나님을 알아감", "크신 하나님"], "book": "시편", "chap": 95, "verse": "3", "ref": "시편 95:3", "texts": {"krv": "대저 여호와는 크신 하나님이시요 모든 신 위에 크신 왕이시로다", "kkjv": "주는 위대한 하나님이시요, 모든 신들보다 위에 계신 위대한 왕이시로다.", "web": "For Yahweh is a great God, a great King above all gods."}}, {"id": 1066, "coll": "무장 900구절", "sub": ["하나님을 알아감", "크신 하나님"], "book": "이사야", "chap": 40, "verse": "15", "ref": "이사야 40:15", "texts": {"krv": "보라 그에게는 열방은 통의 한 방울 물 같고 저울의 적은 티끌 같으며 섬들은 떠오르는 먼지 같으니", "kkjv": "보라, 민족들은 물통의 한 방울 물 같고 저울의 작은 먼지같이 여겨지느니라. 보라, 그분께서는 매우 작은 것을 드시듯 섬들을 드시나니", "web": "Behold, the nations are like a drop in a bucket, and are regarded as a speck of dust on a balance. Behold, he lifts up the islands like a very little thing."}}, {"id": 1067, "coll": "무장 900구절", "sub": ["하나님을 알아감", "크신 하나님"], "book": "예레미야", "chap": 10, "verse": "6", "ref": "예레미야 10:6", "texts": {"krv": "여호와여 주와 같은 자 없나이다 주는 크시니 주의 이름이 그 권능으로 인하여 크시니이다", "kkjv": "오 주여, 주와 같으신 이가 없사오니 주는 크시며 주의 이름은 권능이 크시나이다.", "web": "There is no one like you, Yahweh; you are great, and your name is great in might."}}, {"id": 1068, "coll": "무장 900구절", "sub": ["하나님을 알아감", "창조주 하나님"], "book": "시편", "chap": 89, "verse": "11", "ref": "시편 89:11", "texts": {"krv": "하늘이 주의 것이요 땅도 주의 것이라 세계와 그 중에 충만한 것을 주께서 건설하셨나이다", "kkjv": "하늘들이 주의 것이요, 땅도 주의 것이니이다. 세상과 거기의 충만한 것으로 말하건대 주께서 그것들을 세우셨나이다.", "web": "The heavens are yours. The earth also is yours; the world and its fullness. You have founded them."}}, {"id": 1069, "coll": "무장 900구절", "sub": ["하나님을 알아감", "창조주 하나님"], "book": "시편", "chap": 100, "verse": "3", "ref": "시편 100:3", "texts": {"krv": "여호와가 우리 하나님이신줄 너희는 알지어다 그는 우리를 지으신 자시요 우리는 그의 것이니 그의 백성이요 그의 기르시는 양이로다", "kkjv": "주 그분께서 하나님이심을 너희는 알지어다. 우리를 만드신 이는 그분이시요, 우리 자신이 아니니 우리는 그분의 백성이요, 그분의 초장의 양이로다.", "web": "Know that Yahweh, he is God. It is he who has made us, and we are his. We are his people, and the sheep of his pasture."}}, {"id": 1070, "coll": "무장 900구절", "sub": ["하나님을 알아감", "창조주 하나님"], "book": "이사야", "chap": 40, "verse": "26", "ref": "이사야 40:26", "texts": {"krv": "너희는 눈을 높이 들어 누가 이 모든 것을 창조하였나 보라 주께서는 수효대로 만상을 이끌어 내시고 각각 그 이름을 부르시나니 그의 권세가 크고 그의 능력이 강하므로 하나도 빠짐이 없느니라", "kkjv": "너희 눈을 높이 들어 누가 이것들을 창조하였나 보라. 그분께서 수효대로 그것들의 군대를 이끌어 내시고 자신의 크신 능력으로 그것들 모두를 이름대로 부르시나니 그분의 권능이 강하므로 하나도 빠지지 아니하느니라.", "web": "Lift up your eyes on high, and see who has created these, who brings out their army by number. He calls them all by name. by the greatness of his might, and because he is strong in power, Not one is lacking."}}, {"id": 1071, "coll": "무장 900구절", "sub": ["하나님을 알아감", "창조주 하나님"], "book": "이사야", "chap": 44, "verse": "24", "ref": "이사야 44:24", "texts": {"krv": "네 구속자요 모태에서 너를 조성한 나 여호와가 말하노라 나는 만물을 지은 여호와라 나와 함께 한 자 없이 홀로 하늘을 폈으며 땅을 베풀었고", "kkjv": "네 구속자요, 태에서부터 너를 지은 주가 이같이 말하노라. 나는 모든 것을 만드는 주니 곧 홀로 하늘들을 펼치고 홀로 땅을 넓게 펴시며", "web": "Thus says Yahweh, your Redeemer, and he who formed you from the womb: “I am Yahweh, who makes all things; who alone stretches out the heavens; who spreads out the earth by myself;"}}, {"id": 1072, "coll": "무장 900구절", "sub": ["하나님을 알아감", "창조주 하나님"], "book": "이사야", "chap": 45, "verse": "18", "ref": "이사야 45:18", "texts": {"krv": "여호와는 하늘을 창조하신 하나님이시며 땅도 조성하시고 견고케 하시되 헛되이 창조치 아니하시고 사람으로 거하게 지으신 자시니라 그 말씀에 나는 여호와라 나 외에 다른 이가 없느니라", "kkjv": "하늘들을 창조한 주가 이같이 말하노라. 하나님은 친히 땅을 조성하고 만들며 견고하게 하였으되 땅을 헛되이 창조하지 아니하고 사람이 거주하도록 조성하였느니라. 나는 주니라. 나 외에 다른 이가 없느니라.", "web": "For thus says Yahweh who created the heavens, the God who formed the earth and made it, who established it and didn’t create it a waste, who formed it to be inhabited: “I am Yahweh; and there is no other."}}, {"id": 1073, "coll": "무장 900구절", "sub": ["하나님을 알아감", "창조주 하나님"], "book": "요한계시록", "chap": 4, "verse": "11", "ref": "요한계시록 4:11", "texts": {"krv": "우리 주 하나님이여 영광과 존귀와 능력을 받으시는 것이 합당하오니 주께서 만물을 지으신지라 만물이 주의 뜻대로 있었고 또 지으심을 받았나이다 하더라", "kkjv": "오 주여, 주는 영광과 존귀와 권능을 받기에 합당하시오니 주께서 모든 것을 창조하셨고 또 그것들이 주를 기쁘게 하려고 존재하며 창조되었나이다, 하더라.", "web": "“Worthy are you, our Lord and God, the Holy One, to receive the glory, the honor, and the power, for you created all things, and because of your desire they existed, and were created!”"}}, {"id": 1074, "coll": "무장 900구절", "sub": ["하나님을 알아감", "도우시는 하나님"], "book": "시편", "chap": 37, "verse": "40", "ref": "시편 37:40", "texts": {"krv": "여호와께서 저희를 도와 건지시되 악인에게서 건져 구원하심은 그를 의지한 연고로다", "kkjv": "주께서 그들을 도우시며 그들을 건지시리니 그들이 그분을 신뢰하므로 그분께서 그들을 사악한 자들에게서 건지시고 구원하시리로다.", "web": "Yahweh helps them, and rescues them. He rescues them from the wicked, and saves them, Because they have taken refuge in him."}}, {"id": 1075, "coll": "무장 900구절", "sub": ["하나님을 알아감", "도우시는 하나님"], "book": "시편", "chap": 46, "verse": "5", "ref": "시편 46:5", "texts": {"krv": "하나님이 그 성중에 거하시매 성이 요동치 아니할 것이라 새벽에 하나님이 도우시리로다", "kkjv": "하나님께서 그녀의 한가운데 계시매 그녀가 흔들리지 아니할 것이요, 하나님께서 그녀를 도우시되 이른 새벽에 도우시리로다.", "web": "God is in her midst. She shall not be moved. God will help her at dawn."}}, {"id": 1076, "coll": "무장 900구절", "sub": ["하나님을 알아감", "도우시는 하나님"], "book": "시편", "chap": 79, "verse": "9", "ref": "시편 79:9", "texts": {"krv": "우리 구원의 하나님이여 주의 이름의 영광을 위하여 우리를 도우시며 주의 이름을 위하여 우리를 건지시며 우리 죄를 사하소서", "kkjv": "오 우리의 구원의 하나님이여, 주의 이름의 영광을 위하여 우리를 도우시며 주의 이름을 위하여 우리를 건지시고 우리의 죄들을 깨끗하게 하소서.", "web": "Help us, God of our salvation, for the glory of your name. Deliver us, and forgive our sins, for your name’s sake."}}, {"id": 1077, "coll": "무장 900구절", "sub": ["하나님을 알아감", "도우시는 하나님"], "book": "이사야", "chap": 44, "verse": "1-2", "ref": "이사야 44:1-2", "texts": {"krv": "나의 종 야곱 나의 택한 이스라엘아 이제 들으라 너를 지으며 너를 모태에서 조성하고 너를 도와줄 여호와가 말하노라 나의 종 야곱 나의 택한 여수룬아 두려워 말라", "kkjv": "그러나, 오 나의 종 야곱아, 내가 택한 이스라엘아, 이제 들으라. 너를 만들고 태에서부터 너를 지은 주 곧 너를 도울 자가 이같이 말하노라. 오 나의 종 야곱아, 내가 택한 여수룬아, 너는 두려워하지 말라.", "web": "Yet listen now, Jacob my servant, and Israel, whom I have chosen. This is what Yahweh who made you, and formed you from the womb, who will help you says: “Don’t be afraid, Jacob my servant; and you, Jeshurun, whom I have chosen."}}, {"id": 1078, "coll": "무장 900구절", "sub": ["하나님을 알아감", "도우시는 하나님"], "book": "이사야", "chap": 50, "verse": "9", "ref": "이사야 50:9", "texts": {"krv": "주 여호와께서 나를 도우시리니 나를 정죄할 자 누구뇨 그들은 다 옷과 같이 해어지며 좀에게 먹히리라", "kkjv": "보라, 주 하나님께서 나를 도우시리니 나를 정죄할 자가 누구냐? 보라, 그들은 다 옷같이 해어질 것이요, 좀이 그들을 먹으리라.", "web": "Behold, the Lord Yahweh will help me; who is he who shall condemn me? Behold, all they shall wax old as a garment, the moth shall eat them up."}}, {"id": 1079, "coll": "무장 900구절", "sub": ["하나님을 알아감", "도우시는 하나님"], "book": "로마서", "chap": 8, "verse": "26", "ref": "로마서 8:26", "texts": {"krv": "이와 같이 성령도 우리 연약함을 도우시나니 우리가 마땅히 빌 바를 알지 못하나 오직 성령이 말할 수 없는 탄식으로 우리를 위하여 친히 간구하시느니라", "kkjv": "이와 같이 성령께서도 우리의 연약함을 도우시나니 우리가 마땅히 기도할 바를 알지 못하나 성령께서 말로 할 수 없는 신음으로 친히 우리를 위해 중보하시느니라.", "web": "In the same way, the Spirit also helps our weaknesses, for we don’t know how to pray as we ought. But the Spirit himself makes intercession for us with groanings which can’t be uttered."}}, {"id": 1080, "coll": "무장 900구절", "sub": ["하나님을 알아감", "신실하신 하나님"], "book": "신명기", "chap": 7, "verse": "9", "ref": "신명기 7:9", "texts": {"krv": "그런즉 너는 알라 오직 네 하나님 여호와는 하나님이시요 신실하신 하나님이시라 그를 사랑하고 그 계명을 지키는 자에게는 천대까지 그 언약을 이행하시며 인애를 베푸시되", "kkjv": "그런즉 너는 주 네 하나님 그분이 하나님이시요, 신실한 하나님이신 줄 알라. 그분께서는 자신을 사랑하고 자신의 명령을 지키는 자들에게는 천대까지 언약을 지키시며 긍휼을 베푸시되", "web": "Know therefore that Yahweh your God himself is God, the faithful God, who keeps covenant and loving kindness with them who love him and keep his commandments to a thousand generations,"}}, {"id": 1081, "coll": "무장 900구절", "sub": ["하나님을 알아감", "신실하신 하나님"], "book": "느헤미야", "chap": 1, "verse": "5", "ref": "느헤미야 1:5", "texts": {"krv": "가로되 하늘의 하나님 여호와 크고 두려우신 하나님이여 주를 사랑하고 주의 계명을 지키는 자에게 언약을 지키시며 긍휼을 베푸시는 주여 간구하나이다", "kkjv": "이르되, 간청하건대 오 주 하늘의 하나님 곧 자신을 사랑하고 자신의 명령들을 지키는 자들을 위해 언약을 지키시며 긍휼을 베푸시는 크고 두려우신 하나님이여,", "web": "and said, “I beg you, Yahweh, the God of heaven, the great and awesome God, who keeps covenant and loving kindness with those who love him and keep his commandments:"}}, {"id": 1082, "coll": "무장 900구절", "sub": ["하나님을 알아감", "신실하신 하나님"], "book": "시편", "chap": 105, "verse": "8-10", "ref": "시편 105:8-10", "texts": {"krv": "그는 그 언약 곧 천대에 명하신 말씀을 영원히 기억하셨으니 이것은 아브라함에게 하신 언약이며 이삭에게 하신 맹세며 야곱에게 세우신 율례 곧 이스라엘에게 하신 영영한 언약이라", "kkjv": "그분께서 자신의 언약 곧 친히 천대에 이르기까지 명령하신 그 말씀을 영원히 기억하셨으니 이 언약은 그분께서 아브라함과 맺으신 것이며 이삭에게 친히 하신 맹세라. 그분께서 바로 그것을 야곱에게 법으로 확정하시고 이스라엘에게 영존하는 언약으로 확정하셨나니", "web": "He has remembered his covenant forever, the word which he commanded to a thousand generations, the covenant which he made with Abraham, his oath to Isaac, and confirmed the same to Jacob for a statute; to Israel for an everlasting covenant,"}}, {"id": 1083, "coll": "무장 900구절", "sub": ["하나님을 알아감", "신실하신 하나님"], "book": "다니엘", "chap": 9, "verse": "4", "ref": "다니엘 9:4", "texts": {"krv": "내 하나님 여호와께 기도하며 자복하여 이르기를 크시고 두려워할 주 하나님 주를 사랑하고 주의 계명을 지키는 자를 위하여 언약을 지키시고 그에게 인자를 베푸시는 자시여", "kkjv": "내가 주 내 하나님께 기도하고 자백하며 이르기를, 오 주여, 하나님을 사랑하고 하나님의 명령들을 지키는 자들에게 언약을 지키시며 긍휼을 베푸시는 크고 두려우신 하나님이여,", "web": "I prayed to Yahweh my God, and made confession, and said, Oh, Lord, the great and dreadful God, who keeps covenant and loving kindness with those who love him and keep his commandments,"}}, {"id": 1084, "coll": "무장 900구절", "sub": ["하나님을 알아감", "신실하신 하나님"], "book": "고린도전서", "chap": 1, "verse": "9", "ref": "고린도전서 1:9", "texts": {"krv": "너희를 불러 그의 아들 예수 그리스도 우리 주로 더불어 교제케 하시는 하나님은 미쁘시도다", "kkjv": "너희를 부르사 자신의 아들 예수 그리스도 우리 주와 교제하게 하시는 하나님은 신실하시도다.", "web": "God is faithful, through whom you were called into the fellowship of his Son, Jesus Christ, our Lord."}}, {"id": 1085, "coll": "무장 900구절", "sub": ["하나님을 알아감", "신실하신 하나님"], "book": "히브리서", "chap": 10, "verse": "23", "ref": "히브리서 10:23", "texts": {"krv": "또 약속하신 이는 미쁘시니 우리가 믿는 도리의 소망을 움직이지 말고 굳게 잡아", "kkjv": "(약속하신 분께서 신실하시니) 우리의 믿음의 고백을 흔들림 없이 굳게 잡고", "web": "let us hold fast the confession of our hope without wavering; for he who promised is faithful."}}, {"id": 1086, "coll": "무장 900구절", "sub": ["하나님을 알아감", "영원하신 하나님"], "book": "시편", "chap": 90, "verse": "2", "ref": "시편 90:2", "texts": {"krv": "산이 생기기 전 땅과 세계도 주께서 조성하시기 전 곧 영원부터 영원까지 주는 하나님이시니이다", "kkjv": "산들이 생기기 전 혹은 주께서 땅과 세상을 조성하시기 전 곧 영원부터 영원까지 주는 하나님이시니이다.", "web": "Before the mountains were born, before you had formed the earth and the world, even from everlasting to everlasting, you are God."}}, {"id": 1087, "coll": "무장 900구절", "sub": ["하나님을 알아감", "영원하신 하나님"], "book": "시편", "chap": 135, "verse": "13", "ref": "시편 135:13", "texts": {"krv": "여호와여 주의 이름이 영원하시니이다 여호와여 주의 기념이 대대에 이르리이다", "kkjv": "오 주여, 주의 이름은 영원히 지속되나이다. 오 주여, 주를 기념함은 모든 세대에 두루 미치오니", "web": "Your name, Yahweh, endures forever; your renown, Yahweh, throughout all generations."}}, {"id": 1088, "coll": "무장 900구절", "sub": ["하나님을 알아감", "영원하신 하나님"], "book": "이사야", "chap": 44, "verse": "6", "ref": "이사야 44:6", "texts": {"krv": "이스라엘의 왕인 여호와 이스라엘의 구속자인 만군의 여호와가 말하노라 나는 처음이요 나는 마지막이라 나 외에 다른 신이 없느니라", "kkjv": "이스라엘의 왕인 주 곧 그의 구속자인 만군의 주가 이같이 말하노라. 나는 처음이요, 나는 마지막이니라. 나 외에 다른 신이 없느니라.", "web": "This is what Yahweh, the King of Israel, and his Redeemer, Yahweh of Armies, says: “I am the first, and I am the last; and besides me there is no God."}}, {"id": 1089, "coll": "무장 900구절", "sub": ["하나님을 알아감", "영원하신 하나님"], "book": "예레미야", "chap": 10, "verse": "10", "ref": "예레미야 10:10", "texts": {"krv": "오직 여호와는 참 하나님이시요 사시는 하나님이시요 영원한 왕이시라 그 진노하심에 땅이 진동하며 그 분노하심을 열방이 능히 당치 못하느니라", "kkjv": "그러나 주께서는 참 하나님이시니 그분은 살아 계신 하나님이시요, 영존하는 왕이시로다. 그분의 진노에 땅이 떨고 민족들이 능히 그분의 격노를 견디지 못하리로다.", "web": "But Yahweh is the true God; he is the living God, and an everlasting King: at his wrath the earth trembles, and the nations are not able to withstand his indignation."}}, {"id": 1090, "coll": "무장 900구절", "sub": ["하나님을 알아감", "영원하신 하나님"], "book": "예레미야애가", "chap": 5, "verse": "19", "ref": "예레미야애가 5:19", "texts": {"krv": "여호와여 주는 영원히 계시오며 주의 보좌는 세세에 미치나이다", "kkjv": "오 주여, 주는 영원토록 계시오며 주의 왕좌는 대대에 이르나이다.", "web": "You, Yahweh, remain forever; Your throne is from generation to generation."}}, {"id": 1091, "coll": "무장 900구절", "sub": ["하나님을 알아감", "영원하신 하나님"], "book": "요한계시록", "chap": 1, "verse": "8", "ref": "요한계시록 1:8", "texts": {"krv": "주 하나님이 가라사대 나는 알파와 오메가라 이제도 있고 전에도 있었고 장차 올 자요 전능한 자라 하시더라", "kkjv": "나는 알파와 오메가요 시작과 끝마침이라. 지금도 있고 전에도 있었고 앞으로 올 주 곧 전능자가 말하노라.", "web": "“I am the Alpha and the Omega,” says the Lord God, “who is and who was and who is to come, the Almighty.”"}}, {"id": 1092, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인자하신 하나님"], "book": "시편", "chap": 6, "verse": "3-4", "ref": "시편 6:3-4", "texts": {"krv": "나의 영혼도 심히 떨리나이다 여호와여 어느 때까지니이까 여호와여 돌아와 나의 영혼을 건지시며 주의 인자하심을 인하여 나를 구원하소서", "kkjv": "나의 혼도 몹시 괴로워하나이다. 그러나, 오 주여, 어느 때까지니이까? 오 주여, 돌아오사 나의 혼을 건지시옵소서. 오 주의 긍휼로 인하여 나를 구원하소서.", "web": "My soul is also in great anguish. But you, Yahweh—how long? Return, Yahweh. Deliver my soul, and save me for your loving kindness’ sake."}}, {"id": 1093, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인자하신 하나님"], "book": "시편", "chap": 13, "verse": "5", "ref": "시편 13:5", "texts": {"krv": "나는 오직 주의 인자하심을 의뢰하였사오니 내 마음은 주의 구원을 기뻐하리이다", "kkjv": "그러나 내가 주의 긍휼을 신뢰하였사오니 내 마음이 주의 구원을 기뻐하리이다.", "web": "But I trust in your loving kindness. My heart rejoices in your salvation."}}, {"id": 1094, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인자하신 하나님"], "book": "시편", "chap": 23, "verse": "6", "ref": "시편 23:6", "texts": {"krv": "나의 평생에 선하심과 인자하심이 정녕 나를 따르리니 내가 여호와의 집에 영원히 거하리로다", "kkjv": "내 평생에 선하심과 긍휼이 정녕 나를 따르리니 내가 주의 집에 영원히 거하리로다.", "web": "Surely goodness and loving kindness shall follow me all the days of my life, and I will dwell in Yahweh’s house forever."}}, {"id": 1095, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인자하신 하나님"], "book": "시편", "chap": 31, "verse": "7", "ref": "시편 31:7", "texts": {"krv": "내가 주의 인자하심을 기뻐하며 즐거워할 것은 주께서 나의 곤란을 감찰하사 환난 중에 있는 내 영혼을 아셨고", "kkjv": "내가 주의 긍휼을 기뻐하고 즐거워하리니 주께서 나의 고난을 깊이 살피사 역경에 처한 내 혼을 아셨으며", "web": "I will be glad and rejoice in your loving kindness, for you have seen my affliction. You have known my soul in adversities."}}, {"id": 1096, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인자하신 하나님"], "book": "시편", "chap": 66, "verse": "20", "ref": "시편 66:20", "texts": {"krv": "하나님을 찬송하리로다 저가 내 기도를 물리치지 아니하시고 그 인자하심을 내게서 거두지도 아니하셨도다", "kkjv": "하나님을 찬송하리로다. 그분께서 내 기도를 물리치지 아니하시고 자신의 긍휼도 내게서 거두지 아니하셨도다.", "web": "Blessed be God, who has not turned away my prayer, nor his loving kindness from me."}}, {"id": 1097, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인자하신 하나님"], "book": "시편", "chap": 103, "verse": "10-11", "ref": "시편 103:10-11", "texts": {"krv": "우리의 죄를 따라 처치하지 아니하시며 우리의 죄악을 따라 갚지 아니하셨으니 이는 하늘이 땅에서 높은 같이 그를 경외하는 자에게 그 인자하심이 크심이로다", "kkjv": "그분께서 우리의 죄들에 따라 우리를 다루지 아니하시고 우리의 불법들에 따라 우리에게 갚지 아니하셨으니 하늘이 땅에서 높음같이 그분을 두려워하는 자들을 향한 그분의 긍휼이 크시도다.", "web": "He has not dealt with us according to our sins, nor repaid us for our iniquities. For as the heavens are high above the earth, so great is his loving kindness toward those who fear him."}}, {"id": 1098, "coll": "무장 900구절", "sub": ["하나님을 알아감", "전능하신 하나님"], "book": "창세기", "chap": 17, "verse": "1", "ref": "창세기 17:1", "texts": {"krv": "아브람의 구십 구세 때에 여호와께서 아브람에게 나타나서 그에게 이르시되 나는 전능한 하나님이라 너는 내 앞에서 행하여 완전하라", "kkjv": "아브람이 구십구 세였을 때에 주께서 아브람에게 나타나 그에게 이르시되, 나는 전능자 하나님이니라. 너는 내 앞에서 걸으며 완전할지니라.", "web": "When Abram was ninety-nine years old, Yahweh appeared to Abram, and said to him, “I am God Almighty. Walk before me, and be blameless."}}, {"id": 1099, "coll": "무장 900구절", "sub": ["하나님을 알아감", "전능하신 하나님"], "book": "창세기", "chap": 18, "verse": "14", "ref": "창세기 18:14", "texts": {"krv": "여호와께 능치 못한 일이 있겠느냐 기한이 이를 때에 내가 네게로 돌아오리니 사라에게 아들이 있으리라", "kkjv": "주에게 너무 어려운 일이 있느냐? 생명의 때를 따라 내가 정한 때에 네게 돌아오리니 사라에게 한 아들이 있으리라, 하시니라.", "web": "Is anything too hard for Yahweh? At the set time I will return to you, when the season comes round, and Sarah will have a son.”"}}, {"id": 1100, "coll": "무장 900구절", "sub": ["하나님을 알아감", "전능하신 하나님"], "book": "창세기", "chap": 28, "verse": "3", "ref": "창세기 28:3", "texts": {"krv": "전능하신 하나님이 네게 복을 주어 너로 생육하고 번성케 하사 너로 여러 족속을 이루게 하시고", "kkjv": "하나님 곧 전능자께서 네게 복을 주셔서 너를 다산하게 하고 번성하게 하사 네가 수많은 백성이 되게 하시고", "web": "May God Almighty bless you, and make you fruitful, and multiply you, that you may be a company of peoples,"}}, {"id": 1101, "coll": "무장 900구절", "sub": ["하나님을 알아감", "전능하신 하나님"], "book": "예레미야", "chap": 32, "verse": "27", "ref": "예레미야 32:27", "texts": {"krv": "나는 여호와요 모든 육체의 하나님이라 내게 능치 못한 일이 있겠느냐", "kkjv": "보라, 나는 주요, 모든 육체의 하나님이니라. 내게 너무 어려운 일이 있느냐?", "web": "Behold, I am Yahweh, the God of all flesh: is there anything too hard for me?"}}, {"id": 1102, "coll": "무장 900구절", "sub": ["하나님을 알아감", "전능하신 하나님"], "book": "누가복음", "chap": 18, "verse": "27", "ref": "누가복음 18:27", "texts": {"krv": "가라사대 무릇 사람의 할 수 없는 것을 하나님은 하실 수 있느니라", "kkjv": "그분께서 이르시되, 사람들에게는 불가능한 것들이 하나님께는 가능하니라, 하시니라.", "web": "But he said, “The things which are impossible with men are possible with God.”"}}, {"id": 1103, "coll": "무장 900구절", "sub": ["하나님을 알아감", "전능하신 하나님"], "book": "고린도후서", "chap": 6, "verse": "18", "ref": "고린도후서 6:18", "texts": {"krv": "너희에게 아버지가 되고 너희는 내게 자녀가 되리라 전능하신 주의 말씀이니라 하셨느니라", "kkjv": "너희에게 아버지가 되고 너희는 내 아들딸이 되리라. 주 곧 전능자가 말하노라, 하셨느니라.", "web": "I will be to you a Father. You will be to me sons and daughters,’    says the Lord Almighty.”"}}, {"id": 1104, "coll": "무장 900구절", "sub": ["하나님을 알아감", "전지하신 하나님"], "book": "열왕기상", "chap": 8, "verse": "39", "ref": "열왕기상 8:39", "texts": {"krv": "주는 계신 곳 하늘에서 들으시고 사유하시며 각 사람의 마음을 아시오니 그 모든 행위대로 행하사 갚으시옵소서 주만 홀로 인생의 마음을 다 아심이니이다", "kkjv": "그때에 주께서는 하늘 곧 주의 거처에서 들으시고 용서하시며 또 주께서 각 사람의 마음을 아시오니 각 사람에게 그의 길들대로 행하사 갚으시옵소서. (주 곧 주만 홀로 사람들의 모든 자녀들의 마음을 아시나이다.)", "web": "then hear in heaven, your dwelling place, and forgive, and do, and render to every man according to all his ways, whose heart you know; (for you, even you only, know the hearts of all the children of men;)"}}, {"id": 1105, "coll": "무장 900구절", "sub": ["하나님을 알아감", "전지하신 하나님"], "book": "역대상", "chap": 28, "verse": "9", "ref": "역대상 28:9", "texts": {"krv": "내 아들 솔로몬아 너는 네 아비의 하나님을 알고 온전한 마음과 기쁜 뜻으로 섬길지어다 여호와께서는 뭇 마음을 감찰하사 모든 사상을 아시나니 네가 저를 찾으면 만날 것이요 버리면 저가 너를 영원히 버리시리라", "kkjv": "¶내 아들 솔로몬아, 너는 네 아버지의 하나님을 알고 완전한 마음과 자원하는 생각으로 그분을 섬길지어다. 주께서 모든 마음을 살피시고 생각으로 상상하는 모든 것을 아시나니 네가 만일 그분을 찾으면 만날 것이로되 네가 만일 그분을 버리면 그분께서 너를 영원히 버리시리라.", "web": "You, Solomon my son, know the God of your father, and serve him with a perfect heart and with a willing mind; for Yahweh searches all hearts, and understands all the imaginations of the thoughts. If you seek him, he will be found by you; but if you forsake him, he will cast you off forever."}}, {"id": 1106, "coll": "무장 900구절", "sub": ["하나님을 알아감", "전지하신 하나님"], "book": "시편", "chap": 139, "verse": "1-4", "ref": "시편 139:1-4", "texts": {"krv": "여호와여 주께서 나를 감찰하시고 아셨나이다 주께서 나의 앉고 일어섬을 아시며 멀리서도 나의 생각을 통촉하시오며 나의 길과 눕는 것을 감찰하시며 나의 모든 행위를 익히 아시오니 여호와여 내 혀의 말을 알지 못하시는 것이 하나도 없으시니이다", "kkjv": "오 주여, 주께서 나를 살피시고 나를 아셨나이다. 주께서 나의 앉고 일어서는 것을 아시고 멀리서도 나의 생각을 이해하시오며 나의 행로와 나의 눕는 것을 둘러싸시므로 나의 모든 길을 익히 아시오니 보소서, 오 주여, 내 혀의 말 중에 주께서 알지 못하는 것이 단 하나도 없나이다.", "web": "Yahweh, you have searched me, and you know me. You know my sitting down and my rising up. You perceive my thoughts from afar. You search out my path and my lying down, and are acquainted with all my ways. For there is not a word on my tongue, but, behold, Yahweh, you know it altogether."}}, {"id": 1107, "coll": "무장 900구절", "sub": ["하나님을 알아감", "전지하신 하나님"], "book": "잠언", "chap": 24, "verse": "12", "ref": "잠언 24:12", "texts": {"krv": "네가 말하기를 나는 그것을 알지 못하였노라 할지라도 마음을 저울질하시는 이가 어찌 통찰하지 못하시겠으며 네 영혼을 지키시는 이가 어찌 알지 못하시겠느냐 그가 각 사람의 행위대로 보응하시리라", "kkjv": "말하기를, 보라, 우리는 그것을 알지 못하였노라, 할지라도 마음을 살피시는 이가 그것을 깊이 생각하지 아니하시겠느냐? 또 네 혼을 지키시는 이가 그것을 알지 아니하시겠느냐? 그분께서 각 사람의 행위대로 각 사람에게 보응하지 아니하시겠느냐?", "web": "If you say, “Behold, we didn’t know this”; doesn’t he who weighs the hearts consider it? He who keeps your soul, doesn’t he know it? Shall he not render to every man according to his work?"}}, {"id": 1108, "coll": "무장 900구절", "sub": ["하나님을 알아감", "전지하신 하나님"], "book": "요한복음", "chap": 2, "verse": "25", "ref": "요한복음 2:25", "texts": {"krv": "또 친히 사람의 속에 있는 것을 아시므로 사람에 대하여 아무의 증거도 받으실 필요가 없음이니라", "kkjv": "또 사람에 대하여 누구의 증언도 받을 필요가 없으셨으니 이는 그분께서 사람 속에 있던 것을 아셨기 때문이라.", "web": "and because he didn’t need for anyone to testify concerning man; for he himself knew what was in man."}}, {"id": 1109, "coll": "무장 900구절", "sub": ["하나님을 알아감", "전지하신 하나님"], "book": "요한일서", "chap": 3, "verse": "20", "ref": "요한일서 3:20", "texts": {"krv": "우리 마음이 혹 우리를 책망할 일이 있거든 하물며 우리 마음보다 크시고 모든 것을 아시는 하나님일까 보냐", "kkjv": "만일 우리 마음이 우리를 정죄한다면 하나님은 우리 마음보다 크시고 모든 것을 아시느니라.", "web": "because if our heart condemns us, God is greater than our heart, and knows all things."}}, {"id": 1110, "coll": "무장 900구절", "sub": ["하나님을 알아감", "공의로우신 하나님"], "book": "욥기", "chap": 8, "verse": "3", "ref": "욥기 8:3", "texts": {"krv": "하나님이 어찌 심판을 굽게 하시겠으며 전능하신 이가 어찌 공의를 굽게 하시겠는가", "kkjv": "하나님께서 판단의 공의를 굽게 하시느냐? 전능자께서 정의를 굽게 하시느냐?", "web": "Does God pervert justice? Or does the Almighty pervert righteousness?"}}, {"id": 1111, "coll": "무장 900구절", "sub": ["하나님을 알아감", "공의로우신 하나님"], "book": "시편", "chap": 9, "verse": "8", "ref": "시편 9:8", "texts": {"krv": "공의로 세계를 심판하심이여 정직으로 만민에게 판단을 행하시리로다", "kkjv": "그분께서 세상을 의로 심판하시며 올바름으로 백성들에게 심판을 베푸시리로다.", "web": "He will judge the world in righteousness. He will administer judgment to the peoples in uprightness."}}, {"id": 1112, "coll": "무장 900구절", "sub": ["하나님을 알아감", "공의로우신 하나님"], "book": "시편", "chap": 33, "verse": "5", "ref": "시편 33:5", "texts": {"krv": "저는 정의와 공의를 사랑하심이여 세상에 여호와의 인자하심이 충만하도다", "kkjv": "그분께서 의와 판단의 공의를 사랑하시나니 땅은 주의 선하심으로 가득하도다.", "web": "He loves righteousness and justice. The earth is full of the loving kindness of Yahweh."}}, {"id": 1113, "coll": "무장 900구절", "sub": ["하나님을 알아감", "공의로우신 하나님"], "book": "시편", "chap": 37, "verse": "28", "ref": "시편 37:28", "texts": {"krv": "여호와께서 공의를 사랑하시고 그 성도를 버리지 아니하심이로다 저희는 영영히 보호를 받으나 악인의 자손은 끊어지리로다", "kkjv": "주께서 판단의 공의를 사랑하시고 자신의 성도들을 버리지 아니하시나니 그들은 영원히 보존되나 사악한 자의 씨는 끊어지리로다.", "web": "For Yahweh loves justice, and doesn’t forsake his saints. They are preserved forever, but the children of the wicked shall be cut off."}}, {"id": 1114, "coll": "무장 900구절", "sub": ["하나님을 알아감", "공의로우신 하나님"], "book": "시편", "chap": 89, "verse": "14", "ref": "시편 89:14", "texts": {"krv": "의와 공의가 주의 보좌의 기초라 인자함과 진실함이 주를 앞서 행하나이다", "kkjv": "정의와 판단의 공의가 주의 왕좌의 처소이며 긍휼과 진리가 주의 얼굴 앞에서 가리이다.", "web": "Righteousness and justice are the foundation of your throne. Loving kindness and truth go before your face."}}, {"id": 1115, "coll": "무장 900구절", "sub": ["하나님을 알아감", "공의로우신 하나님"], "book": "시편", "chap": 99, "verse": "4", "ref": "시편 99:4", "texts": {"krv": "왕의 능력은 공의를 사랑하는 것이라 주께서 공평을 견고히 세우시고 야곱 중에서 공과 의를 행하시나이다", "kkjv": "왕의 능력이 또한 판단의 공의를 사랑하오니 주께서 공평을 굳게 세우시며 야곱 안에서 판단의 공의와 의를 집행하시나이다.", "web": "The King’s strength also loves justice. You do establish equity. You execute justice and righteousness in Jacob."}}, {"id": 1116, "coll": "무장 900구절", "sub": ["하나님을 알아감", "동행하시는 하나님"], "book": "창세기", "chap": 28, "verse": "15", "ref": "창세기 28:15", "texts": {"krv": "내가 너와 함께 있어 네가 어디로 가든지 너를 지키며 너를 이끌어 이 땅으로 돌아오게 할지라 내가 네게 허락한 것을 다 이루기까지 너를 떠나지 아니하리라 하신지라", "kkjv": "또, 보라, 내가 너와 함께 있어 네가 가는 모든 곳에서 너를 지키며 너를 이 땅으로 다시 데려오리라. 내가 네게 말한 것을 행할 때까지 너를 떠나지 아니하리라, 하시니라.", "web": "Behold, I am with you, and will keep you, wherever you go, and will bring you again into this land. For I will not leave you, until I have done that which I have spoken of to you.”"}}, {"id": 1117, "coll": "무장 900구절", "sub": ["하나님을 알아감", "동행하시는 하나님"], "book": "신명기", "chap": 31, "verse": "6", "ref": "신명기 31:6", "texts": {"krv": "너는 마음을 강하게 하고 담대히 하라 그들을 두려워 말라 그들 앞에서 떨지 말라 이는 네 하나님 여호와 그가 너와 함께 행하실 것임이라 반드시 너를 떠나지 아니하시며 버리지 아니하시리라 하고", "kkjv": "마음을 강하게 하고 크게 용기를 내라. 두려워하지 말라. 그들을 무서워하지 말라. 주 네 하나님은 곧 너와 함께 가시는 그분이시니라. 그분께서 너를 떠나지 아니하시며 버리지 아니하시리라, 하니라.", "web": "Be strong and courageous. Don’t be afraid or scared of them; for Yahweh your God himself is who goes with you. He will not fail you nor forsake you.”"}}, {"id": 1118, "coll": "무장 900구절", "sub": ["하나님을 알아감", "동행하시는 하나님"], "book": "여호수아", "chap": 1, "verse": "5", "ref": "여호수아 1:5", "texts": {"krv": "너의 평생에 너를 능히 당할 자 없으리니 내가 모세와 함께 있던것 같이 너와 함께 있을 것임이라 내가 너를 떠나지 아니하며 버리지 아니하리니", "kkjv": "네 평생 동안 능히 아무도 네 앞에 서지 못하리니 내가 모세와 함께하던 것 같이 너와 함께하리라. 내가 너를 떠나지 아니하며 버리지 아니하리니", "web": "No man will be able to stand before you all the days of your life. As I was with Moses, so I will be with you. I will not fail you nor forsake you."}}, {"id": 1119, "coll": "무장 900구절", "sub": ["하나님을 알아감", "동행하시는 하나님"], "book": "시편", "chap": 91, "verse": "15", "ref": "시편 91:15", "texts": {"krv": "저가 내게 간구하리니 내가 응답하리라 저희 환난 때에 내가 저와 함께 하여 저를 건지고 영화롭게 하리라", "kkjv": "그가 나를 부르리니 내가 그에게 응답하리라. 고난당할 때에 내가 그와 함께하여 그를 건지고 존귀하게 하리라.", "web": "He will call on me, and I will answer him. I will be with him in trouble. I will deliver him, and honor him."}}, {"id": 1120, "coll": "무장 900구절", "sub": ["하나님을 알아감", "동행하시는 하나님"], "book": "시편", "chap": 94, "verse": "14", "ref": "시편 94:14", "texts": {"krv": "여호와께서는 그 백성을 버리지 아니하시며 그 기업을 떠나지 아니하시리로다", "kkjv": "주께서 자신의 백성을 버리지 아니하시며 자신의 상속 백성을 저버리지 아니하시리로다.", "web": "For Yahweh won’t reject his people, neither will he forsake his inheritance."}}, {"id": 1121, "coll": "무장 900구절", "sub": ["하나님을 알아감", "동행하시는 하나님"], "book": "예레미야", "chap": 32, "verse": "40", "ref": "예레미야 32:40", "texts": {"krv": "내가 그들에게 복을 주기 위하여 그들을 떠나지 아니하리라 하는 영영한 언약을 그들에게 세우고 나를 경외함을 그들의 마음에 두어 나를 떠나지 않게 하고", "kkjv": "또 내가 그들에게 복을 주기 위하여 그들에게서 떠나 돌아서지 아니하리라는 영존하는 언약을 내가 그들과 더불어 맺고 나를 두려워함을 그들의 마음속에 두어 그들이 나를 떠나지 아니하게 하리라.", "web": "and I will make an everlasting covenant with them, that I will not turn away from following them, to do them good; and I will put my fear in their hearts, that they may not depart from me."}}, {"id": 1122, "coll": "무장 900구절", "sub": ["하나님을 알아감", "변하지 않으시는 하나님"], "book": "사무엘상", "chap": 15, "verse": "29", "ref": "사무엘상 15:29", "texts": {"krv": "이스라엘의 지존자는 거짓이나 변개함이 없으시니 그는 사람이 아니시므로 결코 변개치 않으심이니이다", "kkjv": "또한 이스라엘의 힘이신 이는 거짓말을 하거나 뜻을 돌이키지 아니하시리니 그분은 사람이 아니므로 뜻을 돌이키지 아니하시나이다.", "web": "Also the Strength of Israel will not lie nor repent; for he is not a man, that he should repent.”"}}, {"id": 1123, "coll": "무장 900구절", "sub": ["하나님을 알아감", "변하지 않으시는 하나님"], "book": "시편", "chap": 89, "verse": "34", "ref": "시편 89:34", "texts": {"krv": "내 언약을 파하지 아니하며 내 입술에서 낸 것도 변치 아니하리로다", "kkjv": "내 언약을 깨뜨리거나 내 입술에서 나간 것을 변개하지 아니하리로다.", "web": "I will not break my covenant, nor alter what my lips have uttered."}}, {"id": 1124, "coll": "무장 900구절", "sub": ["하나님을 알아감", "변하지 않으시는 하나님"], "book": "시편", "chap": 102, "verse": "26-27", "ref": "시편 102:26-27", "texts": {"krv": "천지는 없어지려니와 주는 영존하시겠고 그것들은 다 옷 같이 낡으리니 의복 같이 바꾸시면 바뀌려니와 주는 여상하시고 주의 연대는 무궁하리이다", "kkjv": "그것들은 사라지려니와 오직 주께서는 지속하시겠고 참으로 그것들은 다 옷같이 낡아지리니 주께서 의복같이 그것들을 바꾸시면 그것들이 바뀌려니와 주께서는 동일하시고 주의 햇수는 끝이 없으리이다.", "web": "They will perish, but you will endure. Yes, all of them will wear out like a garment. You will change them like a cloak, and they will be changed. But you are the same. Your years will have no end."}}, {"id": 1125, "coll": "무장 900구절", "sub": ["하나님을 알아감", "변하지 않으시는 하나님"], "book": "말라기", "chap": 3, "verse": "6", "ref": "말라기 3:6", "texts": {"krv": "나 여호와는 변역지 아니하니니 그러므로 야곱의 자손들아 너희가 소멸되지 아니하느니라", "kkjv": "나는 주라 변치 아니하나니 그러므로 너희 야곱의 아들들이 소멸되지 아니하였느니라.", "web": "“For I, Yahweh, don’t change; therefore you, sons of Jacob, are not consumed."}}, {"id": 1126, "coll": "무장 900구절", "sub": ["하나님을 알아감", "변하지 않으시는 하나님"], "book": "히브리서", "chap": 13, "verse": "8", "ref": "히브리서 13:8", "texts": {"krv": "예수 그리스도는 어제나 오늘이나 영원토록 동일하시니라", "kkjv": "예수 그리스도는 어제도 오늘도 영원토록 동일하시니라.", "web": "Jesus Christ is the same yesterday, today, and forever."}}, {"id": 1127, "coll": "무장 900구절", "sub": ["하나님을 알아감", "변하지 않으시는 하나님"], "book": "야고보서", "chap": 1, "verse": "17", "ref": "야고보서 1:17", "texts": {"krv": "각양 좋은 은사와 온전한 선물이 다 위로부터 빛들의 아버지께로서 내려오나니 그는 변함도 없으시고 회전하는 그림자도 없으시니라", "kkjv": "모든 좋은 선물과 모든 완전한 선물은 위에서 오며 빛들의 아버지로부터 내려오거니와 그분께는 변함도 없고 회전하는 그림자도 없느니라.", "web": "Every good gift and every perfect gift is from above, coming down from the Father of lights, with whom can be no variation, nor turning shadow."}}, {"id": 1128, "coll": "무장 900구절", "sub": ["하나님을 알아감", "오래 참으시는 하나님"], "book": "시편", "chap": 46, "verse": "10", "ref": "시편 46:10", "texts": {"krv": "이르시기를 너희는 가만히 있어 내가 하나님됨을 알지어다 내가 열방과 세계 중에서 높임을 받으리라 하시도다", "kkjv": "가만히 있으라. 그리고 내가 하나님인 줄을 알지어다. 내가 이교도들 가운데서 높여지고 땅에서 높여지리로다.", "web": "“Be still, and know that I am God. I will be exalted among the nations. I will be exalted in the earth.”"}}, {"id": 1129, "coll": "무장 900구절", "sub": ["하나님을 알아감", "오래 참으시는 하나님"], "book": "시편", "chap": 103, "verse": "8", "ref": "시편 103:8", "texts": {"krv": "여호와는 자비로우시며 은혜로우시며 노하기를 더디 하시며 인자하심이 풍부하시도다", "kkjv": "주께서는 긍휼이 많으시고 은혜로우시며 분노하기를 더디 하시고 긍휼이 풍성하시니", "web": "Yahweh is merciful and gracious, slow to anger, and abundant in loving kindness."}}, {"id": 1130, "coll": "무장 900구절", "sub": ["하나님을 알아감", "오래 참으시는 하나님"], "book": "이사야", "chap": 48, "verse": "9", "ref": "이사야 48:9", "texts": {"krv": "내 이름을 위하여 내가 노하기를 더디 할 것이며 내 영예를 위하여 내가 참고 너를 멸절하지 아니하리라", "kkjv": "¶내 이름을 위하여 내가 내 분노를 늦추며 내 찬양을 위하여 내가 너를 참고 끊어 버리지 아니하리라.", "web": "For my name’s sake will I defer my anger, and for my praise will I refrain for you, that I not cut you off."}}, {"id": 1131, "coll": "무장 900구절", "sub": ["하나님을 알아감", "오래 참으시는 하나님"], "book": "로마서", "chap": 2, "verse": "4", "ref": "로마서 2:4", "texts": {"krv": "혹 네가 하나님의 인자하심이 너를 인도하여 회개케 하심을 알지 못하여 그의 인자하심과 용납하심과 길이 참으심의 풍성함을 멸시하느뇨", "kkjv": "혹은 하나님의 선하심이 너를 인도하여 회개하게 함을 알지 못한 채 네가 그분의 선하심과 관대하심과 오래 참으심의 풍성함을 멸시하느냐?", "web": "Or do you despise the riches of his goodness, forbearance, and patience, not knowing that the goodness of God leads you to repentance?"}}, {"id": 1132, "coll": "무장 900구절", "sub": ["하나님을 알아감", "오래 참으시는 하나님"], "book": "로마서", "chap": 3, "verse": "25", "ref": "로마서 3:25", "texts": {"krv": "이 예수를 하나님이 그의 피로 인하여 믿음으로 말미암는 화목 제물로 세우셨으니 이는 하나님께서 길이 참으시는 중에 전에 지은 죄를 간과하심으로 자기의 의로우심을 나타내려 하심이니", "kkjv": "그분을 하나님께서 그분의 피를 믿는 믿음을 통한 화해 헌물로 제시하셨으니 이것은 하나님께서 참으심을 통해 과거의 죄들을 사면하심으로써 자신의 의를 밝히 드러내려 하심이요,", "web": "whom God sent to be an atoning sacrifice, through faith in his blood, for a demonstration of his righteousness through the passing over of prior sins, in God’s forbearance;"}}, {"id": 1133, "coll": "무장 900구절", "sub": ["하나님을 알아감", "오래 참으시는 하나님"], "book": "베드로후서", "chap": 3, "verse": "9", "ref": "베드로후서 3:9", "texts": {"krv": "주의 약속은 어떤 이의 더디다고 생각하는것 같이 더딘 것이 아니라 오직 너희를 대하여 오래 참으사 아무도 멸망치 않고 다 회개하기에 이르기를 원하시느니라", "kkjv": "주께서는 자신의 약속에 대해 어떤 사람들이 더디다고 생각하는 것 같이 더디지 아니하시며 오직 우리를 향하여 오래 참으사 아무도 멸망하지 아니하고 모두 회개에 이르기를 원하시느니라.", "web": "The Lord is not slow concerning his promise, as some count slowness; but is patient with us, not wishing that any should perish, but that all should come to repentance."}}, {"id": 1134, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인도하시는 하나님"], "book": "출애굽기", "chap": 6, "verse": "8", "ref": "출애굽기 6:8", "texts": {"krv": "내가 아브라함과 이삭과 야곱에게 주기로 맹세한 땅으로 너희를 인도하고 그 땅을 너희에게 주어 기업을 삼게 하리라 나는 여호와로라 하셨다 하라", "kkjv": "내가 아브라함과 이삭과 야곱에게 주기로 맹세한 땅으로 너희를 데리고 들어가 그 땅을 너희에게 유산으로 주리라. 나는 주니라, 하라.", "web": "I will bring you into the land which I swore to give to Abraham, to Isaac, and to Jacob; and I will give it to you for a heritage: I am Yahweh.’”"}}, {"id": 1135, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인도하시는 하나님"], "book": "출애굽기", "chap": 15, "verse": "17", "ref": "출애굽기 15:17", "texts": {"krv": "주께서 백성을 인도하사 그들을 주의 기업의 산에 심으시리이다 여호와여 이는 주의 처소를 삼으시려고 예비하신 것이라 주여 이것이 주의 손으로 세우신 성소로소이다", "kkjv": "주께서 그들을 데려오사 주의 상속 재산의 산에 심으시리니, 오 주여, 그곳은 주께서 친히 거하시려고 만드신 곳이니이다. 오 주여, 그곳은 주의 손이 세우신 성소로소이다.", "web": "You shall bring them in, and plant them in the mountain of your inheritance, the place, Yahweh, which you have made for yourself to dwell in; the sanctuary, Lord, which your hands have established."}}, {"id": 1136, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인도하시는 하나님"], "book": "시편", "chap": 32, "verse": "8", "ref": "시편 32:8", "texts": {"krv": "내가 너의 갈 길을 가르쳐 보이고 너를 주목하여 훈계하리로다", "kkjv": "내가 너를 훈계하며 네가 가야 할 길로 너를 가르치고 내 눈으로 너를 지도하리로다.", "web": "I will instruct you and teach you in the way which you shall go. I will counsel you with my eye on you."}}, {"id": 1137, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인도하시는 하나님"], "book": "시편", "chap": 43, "verse": "3", "ref": "시편 43:3", "texts": {"krv": "주의 빛과 주의 진리를 보내어 나를 인도하사 주의 성산과 장막에 이르게 하소서", "kkjv": "오 주의 빛과 주의 진리를 보내사 그것들이 나를 인도하게 하시며 주의 거룩한 산과 주의 장막들로 나를 데려가게 하소서.", "web": "Oh, send out your light and your truth. Let them lead me. Let them bring me to your holy hill, To your tents."}}, {"id": 1138, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인도하시는 하나님"], "book": "시편", "chap": 48, "verse": "14", "ref": "시편 48:14", "texts": {"krv": "이 하나님은 영영히 우리 하나님이시니 우리를 죽을 때까지 인도하시리로다", "kkjv": "이 하나님은 영원무궁토록 우리의 하나님이시니 그분은 우리가 죽을 때까지 우리의 인도자가 되시리로다.", "web": "For this God is our God forever and ever. He will be our guide even to death."}}, {"id": 1139, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인도하시는 하나님"], "book": "시편", "chap": 73, "verse": "24", "ref": "시편 73:24", "texts": {"krv": "주의 교훈으로 나를 인도하시고 후에는 영광으로 나를 영접하시리니", "kkjv": "주께서 주의 권고로 나를 인도하시고 나중에는 영광으로 나를 받아주시리니", "web": "You will guide me with your counsel, and afterward receive me to glory."}}, {"id": 1140, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인도하시는 하나님"], "book": "시편", "chap": 107, "verse": "6-7", "ref": "시편 107:6-7", "texts": {"krv": "이에 저희가 그 근심 중에 여호와께 부르짖으매 그 고통에서 건지시고 또 바른 길로 인도하사 거할 성에 이르게 하셨도다", "kkjv": "그때에 그들이 고난 중에 주께 부르짖으매 그분께서 그들의 고통에서 그들을 건지시고 또 바른 길로 그들을 인도하사 그들이 거주할 도시에 이르게 하셨도다.", "web": "Then they cried to Yahweh in their trouble, and he delivered them out of their distresses, he led them also by a straight way, that they might go to a city to live in."}}, {"id": 1141, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인도하시는 하나님"], "book": "시편", "chap": 107, "verse": "30", "ref": "시편 107:30", "texts": {"krv": "저희가 평온함을 인하여 기뻐하는 중에 여호와께서 저희를 소원의 항구로 인도하시는도다", "kkjv": "파도들이 조용하므로 그때에 그들이 즐거워하나니 이처럼 그분께서 그들이 원하는 항구로 그들을 데려가시는도다.", "web": "Then they are glad because it is calm, so he brings them to their desired haven."}}, {"id": 1142, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인도하시는 하나님"], "book": "잠언", "chap": 16, "verse": "9", "ref": "잠언 16:9", "texts": {"krv": "사람이 마음으로 자기의 길을 계획할지라도 그 걸음을 인도하는 자는 여호와시니라", "kkjv": "사람의 마음이 그의 길을 계획할지라도 주께서 그의 걸음을 인도하시느니라.", "web": "A man’s heart plans his course, but Yahweh directs his steps."}}, {"id": 1143, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인도하시는 하나님"], "book": "이사야", "chap": 42, "verse": "16", "ref": "이사야 42:16", "texts": {"krv": "내가 소경을 그들의 알지 못하는 길로 이끌며 그들의 알지 못하는 첩경으로 인도하며 흑암으로 그 앞에 광명이 되게 하며 굽은 데를 곧게 할 것이라 내가 이 일을 행하여 그들을 버리지 아니하리니", "kkjv": "또 내가 눈먼 자들을 그들이 알지 못하던 길로 데려가고 그들이 알지 못하던 행로들로 그들을 인도하며 또 어둠이 그들 앞에서 빛이 되게 하고 구부러진 것들을 곧게 하리라. 내가 이런 일들을 그들에게 행하여 그들을 버리지 아니하리라.", "web": "I will bring the blind by a way that they don’t know. I will lead them in paths that they don’t know. I will make darkness light before them, and crooked places straight. I will do these things, and I will not forsake them."}}, {"id": 1144, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인도하시는 하나님"], "book": "이사야", "chap": 46, "verse": "4", "ref": "이사야 46:4", "texts": {"krv": "너희가 노년에 이르기까지 내가 그리하겠고 백발이 되기까지 내가 너희를 품을 것이라 내가 지었은즉 안을 것이요 품을 것이요 구하여 내리라", "kkjv": "너희가 노년에 이를 때까지 나는 그니라. 백발이 될 때까지 내가 너희를 업으리라. 내가 만들었은즉 내가 안을 것이요, 내가 너희를 업고 건져 내리라.", "web": "and even to old age I am he, and even to gray hairs will I carry you. I have made, and I will bear; yes, I will carry, and will deliver."}}, {"id": 1145, "coll": "무장 900구절", "sub": ["하나님을 알아감", "인도하시는 하나님"], "book": "이사야", "chap": 48, "verse": "17", "ref": "이사야 48:17", "texts": {"krv": "너희의 구속자시요 이스라엘의 거룩하신 자이신 여호와께서 가라사대 나는 네게 유익하도록 가르치고 너를 마땅히 행할 길로 인도하는 너희 하나님 여호와라", "kkjv": "네 구속자요, 이스라엘의 거룩하신 이인 주가 이같이 말하노라. 나는 너를 가르쳐 유익하게 하고 네가 마땅히 가야 할 길로 너를 인도하는 주 네 하나님이니라.", "web": "Thus says Yahweh, your Redeemer, the Holy One of Israel: I am Yahweh your God, who teaches you to profit, who leads you by the way that you should go."}}, {"id": 1146, "coll": "무장 900구절", "sub": ["하나님을 알아감", "은혜로우신 하나님"], "book": "느헤미야", "chap": 9, "verse": "31", "ref": "느헤미야 9:31", "texts": {"krv": "주의 긍휼이 크시므로 저희를 아주 멸하지 아니하시며 버리지도 아니하셨사오니 주는 은혜로우시고 긍휼히 여기시는 하나님이심이니이다", "kkjv": "그럼에도 불구하고 주의 크신 긍휼로 인하여 주께서 그들을 진멸하지 아니하시며 버리지도 아니하셨사오니 주는 은혜로우시고 긍휼이 많으신 하나님이시니이다.", "web": "“Nevertheless in your manifold mercies you did not make a full end of them, nor forsake them; for you are a gracious and merciful God."}}, {"id": 1147, "coll": "무장 900구절", "sub": ["하나님을 알아감", "은혜로우신 하나님"], "book": "시편", "chap": 31, "verse": "19", "ref": "시편 31:19", "texts": {"krv": "주를 두려워하는 자를 위하여 쌓아두신 은혜 곧 인생 앞에서 주께 피하는 자를 위하여 베푸신 은혜가 어찌 그리 큰지요", "kkjv": "오 주를 두려워하는 자들을 위하여 주께서 쌓아 두신 주의 선하심 곧 사람들의 아들들 앞에서 주를 신뢰하는 자들을 위하여 주께서 이루신 그 선하심이 어찌 그리 큰지요!", "web": "Oh how great is your goodness, which you have laid up for those who fear you, which you have worked for those who take refuge in you, before the sons of men!"}}, {"id": 1148, "coll": "무장 900구절", "sub": ["하나님을 알아감", "은혜로우신 하나님"], "book": "시편", "chap": 116, "verse": "12", "ref": "시편 116:12", "texts": {"krv": "여호와께서 내게 주신 모든 은혜를 무엇으로 보답할꼬", "kkjv": "주께서 내게 베푸신 모든 은택으로 인하여 내가 그분께 무엇으로 보답하리요?", "web": "What will I give to Yahweh for all his benefits toward me?"}}, {"id": 1149, "coll": "무장 900구절", "sub": ["하나님을 알아감", "은혜로우신 하나님"], "book": "시편", "chap": 145, "verse": "17", "ref": "시편 145:17", "texts": {"krv": "여호와께서는 그 모든 행위에 의로우시며 그 모든 행사에 은혜로우시도다", "kkjv": "주께서는 자신의 모든 길에서 의로우시며 자신의 모든 일에서 거룩하시도다.", "web": "Yahweh is righteous in all his ways, and gracious in all his works."}}, {"id": 1150, "coll": "무장 900구절", "sub": ["하나님을 알아감", "은혜로우신 하나님"], "book": "이사야", "chap": 60, "verse": "10", "ref": "이사야 60:10", "texts": {"krv": "내가 노하여 너를 쳤으나 이제는 나의 은혜로 너를 긍휼히 여겼은즉 이방인들이 네 성벽을 쌓을 것이요 그 왕들이 너를 봉사할 것이며", "kkjv": "그때에 타국인들의 아들들이 네 성벽을 쌓고 그들의 왕들이 너를 섬기리니 이는 내가 진노하여 너를 쳤으나 내 호의로 네게 긍휼을 베풀었기 때문이니라.", "web": "“Foreigners shall build up your walls, and their kings shall minister to you: for in my wrath I struck you, but in my favor have I had mercy on you."}}, {"id": 1151, "coll": "무장 900구절", "sub": ["하나님을 알아감", "은혜로우신 하나님"], "book": "고린도후서", "chap": 6, "verse": "2", "ref": "고린도후서 6:2", "texts": {"krv": "가라사대 내가 은혜 베풀 때에 너를 듣고 구원의 날에 너를 도왔다 하셨으니 보라 지금은 은혜 받을만한 때요 보라 지금은 구원의 날이로다", "kkjv": "(그분께서 이르시되, 받아 주는 때에 내가 네 말을 들었고 구원의 날에 내가 너를 구조하였노라, 하시나니, 보라, 지금이 받아 주시는 때요, 보라, 지금이 구원의 날이로다.)", "web": "for he says,  “At an acceptable time I listened to you, in a day of salvation I helped you.”    Behold, now is the acceptable time. Behold, now is the day of salvation."}}, {"id": 1152, "coll": "무장 900구절", "sub": ["하나님을 알아감", "절대주권의 하나님"], "book": "창세기", "chap": 50, "verse": "20", "ref": "창세기 50:20", "texts": {"krv": "당신들은 나를 해하려 하였으나 하나님은 그것을 선으로 바꾸사 오늘과 같이 만민의 생명을 구원하게 하시려 하셨나니", "kkjv": "오직 당신들로 말하건대 당신들은 내게 악을 행하려고 생각하였으나 오히려 하나님은 그 일을 선이 되도록 계획하시고 이루셔서 이 날과 같이 많은 사람을 살려 두게 하셨나니", "web": "As for you, you meant evil against me, but God meant it for good, to bring to pass, as it is this day, to save many people alive."}}, {"id": 1153, "coll": "무장 900구절", "sub": ["하나님을 알아감", "절대주권의 하나님"], "book": "욥기", "chap": 1, "verse": "21", "ref": "욥기 1:21", "texts": {"krv": "가로되 내가 모태에서 적신이 나왔사온즉 또한 적신이 그리로 돌아가올지라 주신 자도 여호와시요 취하신 자도 여호와시오니 여호와의 이름이 찬송을 받으실지니이다 하고", "kkjv": "이르되, 내가 내 어머니 태에서 벌거벗고 나왔은즉 또한 벌거벗은 채 그리로 돌아가리라. 주신 분도 주시요 가져가신 분도 주시니 주의 이름이 찬송을 받을지어다, 하고", "web": "He said, “Naked I came out of my mother’s womb, and naked shall I return there. Yahweh gave, and Yahweh has taken away. Blessed be Yahweh’s name.”"}}, {"id": 1154, "coll": "무장 900구절", "sub": ["하나님을 알아감", "절대주권의 하나님"], "book": "시편", "chap": 135, "verse": "5-6", "ref": "시편 135:5-6", "texts": {"krv": "내가 알거니와 여호와께서는 광대하시며 우리 주는 모든 신보다 높으시도다 여호와께서 무릇 기뻐하시는 일을 천지와 바다와 모든 깊은데서 다 행하셨도다", "kkjv": "또 내가 알거니와 주께서는 위대하시며 우리 주께서는 모든 신들보다 높으시니 주께서는 무엇이든지 기뻐하시는 일을 친히 하늘과 땅과 바다들과 모든 깊은 곳에서 행하셨도다.", "web": "For I know that Yahweh is great, that our Lord is above all gods. Whatever Yahweh pleased, that he has done, in heaven and in earth, in the seas and in all deeps;"}}, {"id": 1155, "coll": "무장 900구절", "sub": ["하나님을 알아감", "절대주권의 하나님"], "book": "잠언", "chap": 19, "verse": "21", "ref": "잠언 19:21", "texts": {"krv": "사람의 마음에는 많은 계획이 있어도 오직 여호와의 뜻이 완전히 서리라", "kkjv": "사람의 마음에 많은 계획이 있을지라도 주의 뜻, 그것만 서리라.", "web": "There are many plans in a man’s heart, but Yahweh’s counsel will prevail."}}, {"id": 1156, "coll": "무장 900구절", "sub": ["하나님을 알아감", "절대주권의 하나님"], "book": "이사야", "chap": 45, "verse": "7", "ref": "이사야 45:7", "texts": {"krv": "나는 빛도 짓고 어두움도 창조하며 나는 평안도 짓고 환난도 창조하나니 나는 여호와라 이 모든 일을 행하는 자니라 하였노라", "kkjv": "나는 빛도 짓고 어둠도 창조하며 평안도 만들고 재앙도 창조하나니 나 주가 이 모든 일을 행하느니라.", "web": "I form the light, and create darkness. I make peace, and create calamity. I am Yahweh, who does all these things."}}, {"id": 1157, "coll": "무장 900구절", "sub": ["하나님을 알아감", "절대주권의 하나님"], "book": "요한복음", "chap": 3, "verse": "27", "ref": "요한복음 3:27", "texts": {"krv": "요한이 대답하여 가로되 만일 하늘에서 주신 바 아니면 사람이 아무것도 받을 수 없느니라", "kkjv": "요한이 응답하여 이르되, 하늘에서 주지 아니하시면 사람이 아무것도 받을 수 없느니라.", "web": "John answered, “A man can receive nothing, unless it has been given him from heaven."}}, {"id": 1158, "coll": "무장 900구절", "sub": ["하나님을 알아감", "지혜로우신 하나님"], "book": "욥기", "chap": 12, "verse": "13", "ref": "욥기 12:13", "texts": {"krv": "지혜와 권능이 하나님께 있고 모략과 명철도 그에게 속하였나니", "kkjv": "지혜와 힘이 그분께 있고 계략과 명철도 그분께 있나니", "web": "“With God is wisdom and might. He has counsel and understanding."}}, {"id": 1159, "coll": "무장 900구절", "sub": ["하나님을 알아감", "지혜로우신 하나님"], "book": "시편", "chap": 104, "verse": "24", "ref": "시편 104:24", "texts": {"krv": "여호와여 주의 하신 일이 어찌 그리 많은지요 주께서 지혜로 저희를 다 지으셨으니 주의 부요가 땅에 가득하니이다", "kkjv": "오 주여, 주께서 행하신 일들이 어찌 그리 많은지요! 주께서 지혜로 그것들을 다 만드셨사오니 주의 부요하심이 땅에 가득하나이다.", "web": "Yahweh, how many are your works! In wisdom have you made them all. The earth is full of your riches."}}, {"id": 1160, "coll": "무장 900구절", "sub": ["하나님을 알아감", "지혜로우신 하나님"], "book": "시편", "chap": 147, "verse": "5", "ref": "시편 147:5", "texts": {"krv": "우리 주는 광대하시며 능력이 많으시며 그 지혜가 무궁하시도다", "kkjv": "우리 주는 위대하시고 권능이 크시며 그분의 명철은 무한하시도다.", "web": "Great is our Lord, and mighty in power. His understanding is infinite."}}, {"id": 1161, "coll": "무장 900구절", "sub": ["하나님을 알아감", "지혜로우신 하나님"], "book": "잠언", "chap": 21, "verse": "30", "ref": "잠언 21:30", "texts": {"krv": "지혜로도 명철로도 모략으로도 여호와를 당치 못하느니라", "kkjv": "주를 대적할 수 있는 지혜나 명철이나 계략은 없느니라.", "web": "There is no wisdom nor understanding nor counsel against Yahweh."}}, {"id": 1162, "coll": "무장 900구절", "sub": ["하나님을 알아감", "지혜로우신 하나님"], "book": "이사야", "chap": 40, "verse": "28", "ref": "이사야 40:28", "texts": {"krv": "너는 알지 못하였느냐 듣지 못하였느냐 영원하신 하나님 여호와 땅 끝까지 창조하신 자는 피곤치 아니하시며 곤비치 아니하시며 명철이 한이 없으시며", "kkjv": "¶너는 알지 못하였느냐? 너는 듣지 못하였느냐? 영존하시는 하나님, 주 곧 땅 끝들의 창조자는 기진하지 아니하시고 피곤하지 아니하시며 그분의 명철은 찾을 길이 없도다.", "web": "Haven’t you known? Haven’t you heard? The everlasting God, Yahweh, The Creator of the ends of the earth, doesn’t faint. He isn’t weary. His understanding is unsearchable."}}, {"id": 1163, "coll": "무장 900구절", "sub": ["하나님을 알아감", "지혜로우신 하나님"], "book": "예레미야", "chap": 10, "verse": "12", "ref": "예레미야 10:12", "texts": {"krv": "여호와께서 그 권능으로 땅을 지으셨고 그 지혜로 세계를 세우셨고 그 명철로 하늘들을 펴셨으며", "kkjv": "그분께서 자신의 권능으로 땅을 만드시고 자신의 지혜로 세상을 굳게 세우시며 자신의 분별로 하늘들을 펼치셨도다.", "web": "He has made the earth by his power, he has established the world by his wisdom, and by his understanding has he stretched out the heavens:"}}, {"id": 1164, "coll": "무장 900구절", "sub": ["하나님을 알아감", "힘을 주시는 하나님"], "book": "시편", "chap": 18, "verse": "1", "ref": "시편 18:1", "texts": {"krv": "나의 힘이 되신 여호와여 내가 주를 사랑하나이다", "kkjv": "오 나의 힘이 되시는 주여, 내가 주를 사랑하리이다.", "web": "I love you, Yahweh, my strength."}}, {"id": 1165, "coll": "무장 900구절", "sub": ["하나님을 알아감", "힘을 주시는 하나님"], "book": "시편", "chap": 18, "verse": "32", "ref": "시편 18:32", "texts": {"krv": "이 하나님이 힘으로 내게 띠 띠우시며 내 길을 완전케 하시며", "kkjv": "이 하나님은 곧 능력으로 내게 띠를 두르시며 내 길을 완전하게 하시는 이시로다.", "web": "the God who arms me with strength, and makes my way perfect?"}}, {"id": 1166, "coll": "무장 900구절", "sub": ["하나님을 알아감", "힘을 주시는 하나님"], "book": "시편", "chap": 29, "verse": "11", "ref": "시편 29:11", "texts": {"krv": "여호와께서 자기 백성에게 힘을 주심이여 여호와께서 자기 백성에게 평강의 복을 주시리로다", "kkjv": "주께서 자신의 백성에게 힘을 주시리니 주께서 자신의 백성에게 화평으로 복을 주시리로다.", "web": "Yahweh will give strength to his people. Yahweh will bless his people with peace."}}, {"id": 1167, "coll": "무장 900구절", "sub": ["하나님을 알아감", "힘을 주시는 하나님"], "book": "시편", "chap": 84, "verse": "5", "ref": "시편 84:5", "texts": {"krv": "주께 힘을 얻고 그 마음에 시온의 대로가 있는 자는 복이 있나이다", "kkjv": "주 안에서 힘을 얻는 자는 복이 있나니 그의 마음 안에 그들의 길들이 있나이다.", "web": "Blessed are those whose strength is in you; who have set their hearts on a pilgrimage."}}, {"id": 1168, "coll": "무장 900구절", "sub": ["하나님을 알아감", "힘을 주시는 하나님"], "book": "시편", "chap": 84, "verse": "7", "ref": "시편 84:7", "texts": {"krv": "저희는 힘을 얻고 더 얻어 나아가 시온에서 하나님 앞에 각기 나타나리이다", "kkjv": "그들은 더욱 더 힘 있게 나가 그들 각 사람이 시온에서 하나님 앞에 나타나나이다.", "web": "They go from strength to strength. Everyone of them appears before God in Zion."}}, {"id": 1169, "coll": "무장 900구절", "sub": ["하나님을 알아감", "힘을 주시는 하나님"], "book": "이사야", "chap": 40, "verse": "29", "ref": "이사야 40:29", "texts": {"krv": "피곤한 자에게는 능력을 주시며 무능한 자에게는 힘을 더하시나니", "kkjv": "그분께서 기진한 자들에게 능력을 주시며 힘이 없는 자들에게 힘을 더하시느니라.", "web": "He gives power to the weak. He increases the strength of him who has no might."}}, {"id": 1170, "coll": "무장 900구절", "sub": ["하나님을 알아감", "보호자 되시는 하나님"], "book": "룻기", "chap": 2, "verse": "12", "ref": "룻기 2:12", "texts": {"krv": "여호와께서 네 행한 일을 보응하시기를 원하며 이스라엘의 하나님 여호와께서 그 날개 아래 보호를 받으러 온 네게 온전한 상 주시기를 원하노라", "kkjv": "주께서 네가 행한 일에 보답해 주시기를 원하며 주 이스라엘의 하나님께서 자신의 날개 아래로 의지하러 온 네게 충분히 보상해 주시기를 원하노라, 하거늘", "web": "May Yahweh repay your work, and a full reward be given you from Yahweh, the God of Israel, under whose wings you have come to take refuge.”"}}, {"id": 1171, "coll": "무장 900구절", "sub": ["하나님을 알아감", "보호자 되시는 하나님"], "book": "시편", "chap": 12, "verse": "5", "ref": "시편 12:5", "texts": {"krv": "여호와의 말씀에 가련한 자의 눌림과 궁핍한 자의 탄식을 인하여 내가 이제 일어나 저를 그 원하는 안전 지대에 두리라 하시도다", "kkjv": "주께서 말씀하시기를, 가난한 자의 학대받는 것과 궁핍한 자의 탄식하는 것으로 인하여 이제 내가 일어나 그를 향해 우쭐대는 자로부터 그를 떼 내어 안전하게 두리라, 하시는도다.", "web": "“Because of the oppression of the weak and because of the groaning of the needy, I will now arise,” says Yahweh; “I will set him in safety from those who malign him.”"}}, {"id": 1172, "coll": "무장 900구절", "sub": ["하나님을 알아감", "보호자 되시는 하나님"], "book": "시편", "chap": 17, "verse": "8", "ref": "시편 17:8", "texts": {"krv": "나를 눈동자 같이 지키시고 주의 날개 그늘 아래 감추사", "kkjv": "나를 눈동자같이 지키시고 주의 날개 그늘 밑에 숨기사", "web": "Keep me as the apple of your eye. Hide me under the shadow of your wings,"}}, {"id": 1173, "coll": "무장 900구절", "sub": ["하나님을 알아감", "보호자 되시는 하나님"], "book": "시편", "chap": 23, "verse": "4", "ref": "시편 23:4", "texts": {"krv": "내가 사망의 음침한 골짜기로 다닐지라도 해를 두려워하지 않을 것은 주께서 나와 함께 하심이라 주의 지팡이와 막대기가 나를 안위하시나이다", "kkjv": "참으로 내가 사망의 그늘진 골짜기를 다닐지라도 해악을 두려워하지 아니하리니 주께서 나와 함께 계시며 주의 막대기와 주의 지팡이가 나를 위로하시나이다.", "web": "Even though I walk through the valley of the shadow of death, I will fear no evil, for you are with me. Your rod and your staff, they comfort me."}}, {"id": 1174, "coll": "무장 900구절", "sub": ["하나님을 알아감", "보호자 되시는 하나님"], "book": "시편", "chap": 27, "verse": "5", "ref": "시편 27:5", "texts": {"krv": "여호와께서 환난 날에 나를 그 초막 속에 비밀히 지키시고 그 장막 은밀한 곳에 나를 숨기시며 바위 위에 높이 두시리로다", "kkjv": "고난의 때에 그분께서 자신의 천막 속에 나를 숨기시고 자신의 장막의 은밀한 곳에 나를 숨기시며 반석 위에 세우시리로다.", "web": "For in the day of trouble he will keep me secretly in his pavilion. In the covert of his tabernacle he will hide me. He will lift me up on a rock."}}, {"id": 1175, "coll": "무장 900구절", "sub": ["하나님을 알아감", "보호자 되시는 하나님"], "book": "시편", "chap": 34, "verse": "7", "ref": "시편 34:7", "texts": {"krv": "여호와의 사자가 주를 경외하는 자를 둘러 진치고 저희를 건지시는도다", "kkjv": "주의 천사가 그분을 두려워하는 자들을 둘러 진을 치고 그들을 건지는도다.", "web": "Yahweh’s angel encamps around those who fear him, and delivers them."}}, {"id": 1176, "coll": "무장 900구절", "sub": ["하나님을 알아감", "보호자 되시는 하나님"], "book": "시편", "chap": 121, "verse": "3", "ref": "시편 121:3", "texts": {"krv": "여호와께서 너로 실족지 않게 하시며 너를 지키시는 자가 졸지 아니하시리로다", "kkjv": "그분께서 네 발이 흔들리지 아니하게 하시며 너를 지키시는 이가 졸지 아니하시리로다.", "web": "He will not allow your foot to be moved. He who keeps you will not slumber."}}, {"id": 1177, "coll": "무장 900구절", "sub": ["하나님을 알아감", "보호자 되시는 하나님"], "book": "시편", "chap": 121, "verse": "5", "ref": "시편 121:5", "texts": {"krv": "여호와는 너를 지키시는 자라 여호와께서 네 우편에서 네 그늘이 되시나니", "kkjv": "주는 너를 지키시는 이시로다. 주께서 네 오른쪽에서 네 그늘이 되시나니", "web": "Yahweh is your keeper. Yahweh is your shade on your right hand."}}, {"id": 1178, "coll": "무장 900구절", "sub": ["하나님을 알아감", "보호자 되시는 하나님"], "book": "시편", "chap": 125, "verse": "2", "ref": "시편 125:2", "texts": {"krv": "산들이 예루살렘을 두름과 같이 여호와께서 그 백성을 지금부터 영원까지 두르시리로다", "kkjv": "산들이 사방에서 예루살렘을 두름 같이 주께서 자신의 백성을 지금부터 영원토록 두르시는도다.", "web": "As the mountains surround Jerusalem, so Yahweh surrounds his people from this time forward and forever more."}}, {"id": 1179, "coll": "무장 900구절", "sub": ["하나님을 알아감", "보호자 되시는 하나님"], "book": "이사야", "chap": 27, "verse": "3", "ref": "이사야 27:3", "texts": {"krv": "나 여호와는 포도원지기가 됨이여 때때로 물을 주며 밤낮으로 간수하여 아무든지 상해하지 못하게 하리로다", "kkjv": "나 주가 그것을 지키고 내가 매 순간 거기에 물을 주며 밤낮으로 그것을 지켜 아무도 그것을 해치지 못하게 하리로다.", "web": "I, Yahweh, am its keeper. I will water it every moment. Lest anyone damage it, I will keep it night and day."}}, {"id": 1180, "coll": "무장 900구절", "sub": ["하나님을 알아감", "보호자 되시는 하나님"], "book": "이사야", "chap": 43, "verse": "2", "ref": "이사야 43:2", "texts": {"krv": "네가 물 가운데로 지날 때에 내가 함께 할 것이라 강을 건널 때에 물이 너를 침몰치 못할 것이며 네가 불 가운데로 행할 때에 타지도 아니할 것이요 불꽃이 너를 사르지도 못하리니", "kkjv": "네가 물 가운데로 지나갈 때에 내가 너와 함께하리라. 강들을 건널 때에 강들이 네 위로 넘쳐흐르지 못하며 네가 불 속을 걸어갈 때에 타지도 아니하고 불꽃이 너를 사르지도 못하리니", "web": "When you pass through the waters, I will be with you; and through the rivers, they will not overflow you. When you walk through the fire, you will not be burned, and flame will not scorch you."}}, {"id": 1181, "coll": "무장 900구절", "sub": ["하나님을 알아감", "보호자 되시는 하나님"], "book": "유다서", "chap": 1, "verse": "24", "ref": "유다서 1:24", "texts": {"krv": "능히 너희를 보호하사 거침이 없게 하시고 너희로 그 영광 앞에 흠이 없이 즐거움으로 서게 하실 자", "kkjv": "이제 능히 너희를 보호하사 넘어지지 아니하게 하시고 넘치는 기쁨으로 자신의 영광이 있는 곳 앞에 흠 없이 너희를 제시하시는 분", "web": "Now to him who is able to keep them from stumbling, and to present you faultless before the presence of his glory in great joy,"}}, {"id": 1182, "coll": "무장 900구절", "sub": ["하나님을 알아감", "안식을 주시는 하나님"], "book": "여호수아", "chap": 21, "verse": "44", "ref": "여호수아 21:44", "texts": {"krv": "여호와께서 그들의 사방에 안식을 주셨으되 그 열조에게 맹세하신 대로 하셨으므로 그 모든 대적이 그들을 당한 자가 하나도 없었으니 이는 여호와께서 그들의 모든 대적을 그들의 손에 붙이셨음이라", "kkjv": "주께서 그들의 조상들에게 맹세하신 모든 것에 따라 사방에서 그들에게 안식을 주셨으므로 그들의 모든 원수들 중의 한 사람도 그들 앞에 서지 못하였더라. 주께서 그들의 모든 원수들을 그들의 손에 넘겨주시매", "web": "Yahweh gave them rest all around, according to all that he swore to their fathers. Not a man of all their enemies stood before them. Yahweh delivered all their enemies into their hand."}}, {"id": 1183, "coll": "무장 900구절", "sub": ["하나님을 알아감", "안식을 주시는 하나님"], "book": "시편", "chap": 4, "verse": "8", "ref": "시편 4:8", "texts": {"krv": "내가 평안히 눕고 자기도 하리니 나를 안전히 거하게 하시는 이는 오직 여호와시니이다", "kkjv": "내가 평안히 눕고 자기도 하리니, 주여, 오직 주께서만 나를 안전히 거하게 하시나이다.", "web": "In peace I will both lay myself down and sleep, for you, Yahweh alone, make me live in safety."}}, {"id": 1184, "coll": "무장 900구절", "sub": ["하나님을 알아감", "안식을 주시는 하나님"], "book": "시편", "chap": 23, "verse": "1-2", "ref": "시편 23:1-2", "texts": {"krv": "여호와는 나의 목자시니 내가 부족함이 없으리로다 그가 나를 푸른 초장에 누이시며 쉴 만한 물가으로 인도하시는도다", "kkjv": "주는 나의 목자시니 내게 부족함이 없으리로다. 그분께서 나를 푸른 초장에 누이시며 잔잔한 물가로 인도하시고", "web": "Yahweh is my shepherd: I shall lack nothing. He makes me lie down in green pastures. He leads me beside still waters."}}, {"id": 1185, "coll": "무장 900구절", "sub": ["하나님을 알아감", "안식을 주시는 하나님"], "book": "마태복음", "chap": 11, "verse": "28", "ref": "마태복음 11:28", "texts": {"krv": "수고하고 무거운 짐진 자들아 다 내게로 오라 내가 너희를 쉬게 하리라", "kkjv": "¶수고하고 무거운 짐 진 모든 자들아, 너희는 내게로 오라. 내가 너희에게 안식을 주리라.", "web": "“Come to me, all you who labor and are heavily burdened, and I will give you rest."}}, {"id": 1186, "coll": "무장 900구절", "sub": ["하나님을 알아감", "안식을 주시는 하나님"], "book": "마가복음", "chap": 2, "verse": "27-28", "ref": "마가복음 2:27-28", "texts": {"krv": "또 가라사대 안식일은 사람을 위하여 있는 것이요 사람이 안식일을 위하여 있는 것이 아니니 이러므로 인자는 안식일에도 주인이니라", "kkjv": "또 그들에게 이르시되, 안식일은 사람을 위해 만들어졌으며 사람이 안식일을 위해 만들어지지 아니하였나니 이러므로 사람의 아들은 또한 안식일의 주니라, 하시니라.", "web": "He said to them, “The Sabbath was made for man, not man for the Sabbath. Therefore the Son of Man is lord even of the Sabbath.”"}}, {"id": 1187, "coll": "무장 900구절", "sub": ["하나님을 알아감", "안식을 주시는 하나님"], "book": "히브리서", "chap": 4, "verse": "10", "ref": "히브리서 4:10", "texts": {"krv": "이미 그의 안식에 들어간 자는 하나님이 자기 일을 쉬심과 같이 자기 일을 쉬느니라", "kkjv": "그분의 안식에 이미 들어간 자는 또한 하나님께서 자신의 일들을 그치신 것 같이 이미 자기 일들을 그쳤느니라.", "web": "For he who has entered into his rest has himself also rested from his works, as God did from his."}}, {"id": 1188, "coll": "무장 900구절", "sub": ["하나님을 알아감", "앞서 행하시는 하나님"], "book": "출애굽기", "chap": 23, "verse": "20", "ref": "출애굽기 23:20", "texts": {"krv": "내가 사자를 네 앞서 보내어 길에서 너를 보호하여 너로 내가 예비한 곳에 이르게 하리니", "kkjv": "¶보라, 내가 한 천사를 네 앞에 보내어 길에서 너를 보호하게 하며 내가 예비한 곳으로 너를 데리고 들어가게 하리니", "web": "“Behold, I send an angel before you, to keep you by the way, and to bring you into the place which I have prepared."}}, {"id": 1189, "coll": "무장 900구절", "sub": ["하나님을 알아감", "앞서 행하시는 하나님"], "book": "신명기", "chap": 1, "verse": "30", "ref": "신명기 1:30", "texts": {"krv": "너희 앞서 행하시는 너희 하나님 여호와께서 애굽에서 너희를 위하여 너희 목전에서 모든 일을 행하신것 같이 이제도 너희를 위하여 싸우실 것이며", "kkjv": "너희보다 앞서가시는 주 너희 하나님께서 이집트에서 너희를 위하여 너희 눈앞에서 행하신 모든 것에 따라 친히 너희를 위하여 싸우시리라.", "web": "Yahweh your God who goes before you, he will fight for you, according to all that he did for you in Egypt before your eyes,"}}, {"id": 1190, "coll": "무장 900구절", "sub": ["하나님을 알아감", "앞서 행하시는 하나님"], "book": "신명기", "chap": 1, "verse": "33", "ref": "신명기 1:33", "texts": {"krv": "그는 너희 앞서 행하시며 장막 칠 곳을 찾으시고 밤에는 불로 낮에는 구름으로 너희의 행할 길을 지시하신 자니라", "kkjv": "그분은 길에서 너희보다 앞서 가시며 너희를 위해 너희의 장막을 칠 곳을 찾으시고 밤에는 불로 낮에는 구름으로 너희가 가야 할 길을 보여 주신 분이시니라.", "web": "who went before you on the way, to seek out a place for you to pitch your tents in, in fire by night, to show you by what way you should go, and in the cloud by day."}}, {"id": 1191, "coll": "무장 900구절", "sub": ["하나님을 알아감", "앞서 행하시는 하나님"], "book": "신명기", "chap": 31, "verse": "8", "ref": "신명기 31:8", "texts": {"krv": "여호와 그가 네 앞서 행하시며 너와 함께 하사 너를 떠나지 아니하시며 버리지 아니하시리니 너는 두려워 말라 놀라지 말라", "kkjv": "주 그분께서 너보다 앞서 가시고 너와 함께하사 너를 떠나지 아니하시며 버리지 아니하시리니 두려워하지 말라. 놀라지 말라, 하니라.", "web": "Yahweh himself is who goes before you. He will be with you. He will not fail you nor forsake you. Don’t be afraid. Don’t be discouraged.”"}}, {"id": 1192, "coll": "무장 900구절", "sub": ["하나님을 알아감", "앞서 행하시는 하나님"], "book": "여호수아", "chap": 3, "verse": "6", "ref": "여호수아 3:6", "texts": {"krv": "여호수아가 또 제사장들에게 일러 가로되 언약궤를 메고 백성 앞서 건너라 하매 곧 언약궤를 메고 백성 앞서 나아가니라", "kkjv": "여호수아가 또 제사장들에게 말하여 이르되, 언약 궤를 메고 백성 앞에서 건너라, 하매 그들이 언약 궤를 취하고 백성 앞에서 가니라.", "web": "Joshua spoke to the priests, saying, “Take up the ark of the covenant, and pass over before the people.” They took up the ark of the covenant, and went before the people."}}, {"id": 1193, "coll": "무장 900구절", "sub": ["하나님을 알아감", "앞서 행하시는 하나님"], "book": "이사야", "chap": 45, "verse": "2", "ref": "이사야 45:2", "texts": {"krv": "내가 네 앞서 가서 험한 곳을 평탄케 하며 놋문을 쳐서 부수며 쇠빗장을 꺾고", "kkjv": "내가 너보다 앞서 가서 구부러진 곳들을 곧게 하고 놋 문들을 쳐서 산산조각 내며 쇠 빗장을 꺾고", "web": "“I will go before you, and make the rough places smooth. I will break the doors of brass in pieces, and cut apart the bars of iron."}}, {"id": 1194, "coll": "무장 900구절", "sub": ["하나님을 알아감", "중심을 보시는 하나님"], "book": "신명기", "chap": 10, "verse": "17", "ref": "신명기 10:17", "texts": {"krv": "너희의 하나님 여호와는 신의 신이시며 주의 주시요 크고 능하시며 두려우신 하나님이시라 사람을 외모로 보지 아니하시며 뇌물을 받지 아니하시고", "kkjv": "주 너희 하나님은 신들의 신이시요, 주들의 주시며 위대하시고 능하시며 두려우신 하나님이시니라. 그분은 사람들의 외모를 중히 여기지 아니하시며 대가를 받지 아니하시고", "web": "For Yahweh your God, he is God of gods, and Lord of lords, the great God, the mighty, and the awesome, who doesn’t respect persons, nor takes reward."}}, {"id": 1195, "coll": "무장 900구절", "sub": ["하나님을 알아감", "중심을 보시는 하나님"], "book": "사무엘상", "chap": 16, "verse": "7", "ref": "사무엘상 16:7", "texts": {"krv": "여호와께서 사무엘에게 이르시되 그 용모와 신장을 보지 말라 내가 이미 그를 버렸노라 나의 보는 것은 사람과 같지 아니하니 사람은 외모를 보거니와 나 여호와는 중심을 보느니라", "kkjv": "주께서 사무엘에게 이르시되, 그의 용모나 키의 크기를 보지 말라. 내가 이미 그를 버렸노라. 주는 사람이 보는 것처럼 보지 아니하나니 사람은 겉모습을 보나 주는 마음을 보느니라.", "web": "But Yahweh said to Samuel, “Don’t look on his face, or on the height of his stature; because I have rejected him: for I see not as man sees; for man looks at the outward appearance, but Yahweh looks at the heart.”"}}, {"id": 1196, "coll": "무장 900구절", "sub": ["하나님을 알아감", "중심을 보시는 하나님"], "book": "잠언", "chap": 20, "verse": "27", "ref": "잠언 20:27", "texts": {"krv": "사람의 영혼은 여호와의 등불이라 사람의 깊은 속을 살피느니라", "kkjv": "사람의 영은 주의 등잔불로서 배 속의 모든 부분을 살피느니라.", "web": "The spirit of man is Yahweh’s lamp, searching all his innermost parts."}}, {"id": 1197, "coll": "무장 900구절", "sub": ["하나님을 알아감", "중심을 보시는 하나님"], "book": "누가복음", "chap": 20, "verse": "21", "ref": "누가복음 20:21", "texts": {"krv": "그들이 물어 가로되 선생님이여 우리가 아노니 당신은 바로 말씀하시고 가르치시며 사람을 외모로 취치 아니하시고 오직 참으로써 하나님의 도를 가르치시나이다", "kkjv": "그들이 그분께 물어 이르되, 선생님이여, 우리가 알기에 선생님은 바르게 말씀하시고 가르치시며 아무도 외모로 받아들이지 아니하시고 오직 하나님의 길을 참되게 가르치시나이다.", "web": "They asked him, “Teacher, we know that you say and teach what is right, and aren’t partial to anyone, but truly teach the way of God."}}, {"id": 1198, "coll": "무장 900구절", "sub": ["하나님을 알아감", "중심을 보시는 하나님"], "book": "요한복음", "chap": 7, "verse": "24", "ref": "요한복음 7:24", "texts": {"krv": "외모로 판단하지 말고 공의의 판단으로 판단하라 하시니라", "kkjv": "겉모양으로 판단하지 말고 의로운 판단으로 판단하라, 하시니라.", "web": "Don’t judge according to appearance, but judge righteous judgment.”"}}, {"id": 1199, "coll": "무장 900구절", "sub": ["하나님을 알아감", "중심을 보시는 하나님"], "book": "사도행전", "chap": 10, "verse": "34-35", "ref": "사도행전 10:34-35", "texts": {"krv": "베드로가 입을 열어 가로되 내가 참으로 하나님은 사람의 외모를 취하지 아니하시고 각 나라 중 하나님을 경외하며 의를 행하는 사람은 하나님이 받으시는 줄 깨달았도다", "kkjv": "¶이에 베드로가 입을 열어 말하되, 내가 진실로 하나님은 사람들의 외모를 중시하지 아니하시고 모든 민족 중에서 자신을 두려워하며 의를 행하는 사람을 받아 주시는 줄을 깨달았도다.", "web": "Peter opened his mouth and said, “Truly I perceive that God doesn’t show favoritism; but in every nation he who fears him and works righteousness is acceptable to him."}}, {"id": 1200, "coll": "무장 900구절", "sub": ["하나님을 알아감", "피난처 되시는 하나님"], "book": "시편", "chap": 18, "verse": "2", "ref": "시편 18:2", "texts": {"krv": "여호와는 나의 반석이시오 나의 요새시요 나를 건지시는 자시요 나의 하나님이시요 나의 피할 바위시요 나의 방패시요 나의 구원의 뿔이시오 나의 산성이시로다", "kkjv": "주는 나의 반석이시요, 나의 요새시요, 나의 구출자시요, 나의 하나님이시요, 내가 신뢰할 나의 힘이시요, 나의 방패시요, 나의 구원의 뿔이시요, 나의 높은 망대시로다.", "web": "Yahweh is my rock, my fortress, and my deliverer; my God, my rock, in whom I take refuge; my shield, and the horn of my salvation, my high tower."}}, {"id": 1201, "coll": "무장 900구절", "sub": ["하나님을 알아감", "피난처 되시는 하나님"], "book": "시편", "chap": 32, "verse": "7", "ref": "시편 32:7", "texts": {"krv": "주는 나의 은신처이오니 환난에서 나를 보호하시고 구원의 노래로 나를 에우시리이다", "kkjv": "주는 나의 은신처시오니 주께서 고난에서 나를 보존하시고 구출의 노래들로 나를 에워싸시리이다. 셀라.", "web": "You are my hiding place. You will preserve me from trouble. You will surround me with songs of deliverance. Selah."}}, {"id": 1202, "coll": "무장 900구절", "sub": ["하나님을 알아감", "피난처 되시는 하나님"], "book": "시편", "chap": 36, "verse": "7", "ref": "시편 36:7", "texts": {"krv": "하나님이여 주의 인자하심이 어찌 그리 보배로우신지요 인생이 주의 날개 그늘 아래 피하나이다", "kkjv": "오 하나님이여, 주의 인자하심이 어찌 그리 뛰어나신지요! 그런즉 사람들의 자녀들이 주의 날개 그늘 밑에서 주를 신뢰하나이다.", "web": "How precious is your loving kindness, God! The children of men take refuge under the shadow of your wings."}}, {"id": 1203, "coll": "무장 900구절", "sub": ["하나님을 알아감", "피난처 되시는 하나님"], "book": "시편", "chap": 46, "verse": "1", "ref": "시편 46:1", "texts": {"krv": "하나님은 우리의 피난처시요 힘이시니 환난 중에 만날 큰 도움이시라", "kkjv": "하나님은 우리의 피난처시요 힘이시니 참으로 고난 중에 즉시 만날 도움이시라.", "web": "God is our refuge and strength, a very present help in trouble."}}, {"id": 1204, "coll": "무장 900구절", "sub": ["하나님을 알아감", "피난처 되시는 하나님"], "book": "시편", "chap": 62, "verse": "8", "ref": "시편 62:8", "texts": {"krv": "성들아 시시로 저를 의지하고 그 앞에 마음을 토하라 하나님은 우리의 피난처시로다", "kkjv": "백성들아, 너희는 언제나 그분을 신뢰하고 그분 앞에 너희 마음을 쏟아 놓으라. 하나님은 우리를 위한 피난처시로다. 셀라.", "web": "Trust in him at all times, you people. Pour out your heart before him. God is a refuge for us. Selah."}}, {"id": 1205, "coll": "무장 900구절", "sub": ["하나님을 알아감", "피난처 되시는 하나님"], "book": "시편", "chap": 91, "verse": "9-10", "ref": "시편 91:9-10", "texts": {"krv": "네가 말하기를 여호와는 나의 피난처시라 하고 지존자로 거처를 삼았으므로 화가 네게 미치지 못하며 재앙이 네 장막에 가까이 오지 못하리니", "kkjv": "나의 피난처 되시는 주 곧 지극히 높으신 이를 네가 네 처소로 삼았으므로 어떤 재앙도 네게 닥치지 못하며 어떤 역병도 네 거처에 가까이 오지 못하리니", "web": "Because you have made Yahweh your refuge, and the Most High your dwelling place, no evil shall happen to you, neither shall any plague come near your dwelling."}}, {"id": 1206, "coll": "무장 900구절", "sub": ["하나님을 알아감", "긍휼을 베푸시는 하나님"], "book": "시편", "chap": 51, "verse": "17", "ref": "시편 51:17", "texts": {"krv": "하나님의 구하시는 제사는 상한 심령이라 하나님이여 상하고 통회하는 마음을 주께서 멸시치 아니하시리이다", "kkjv": "하나님께서 구하시는 희생물은 상한 영이라. 오 하나님이여, 상하고 통회하는 마음을 주께서 멸시하지 아니하시리이다.", "web": "The sacrifices of God are a broken spirit. A broken and contrite heart, O God, you will not despise."}}, {"id": 1207, "coll": "무장 900구절", "sub": ["하나님을 알아감", "긍휼을 베푸시는 하나님"], "book": "시편", "chap": 103, "verse": "13", "ref": "시편 103:13", "texts": {"krv": "아비가 자식을 불쌍히 여김 같이 여호와께서 자기를 경외하는 자를 불쌍히 여기시나니", "kkjv": "아버지가 자기 자식들을 불쌍히 여기는 것 같이 주께서 자신을 두려워하는 자들을 불쌍히 여기시나니", "web": "Like a father has compassion on his children, so Yahweh has compassion on those who fear him."}}, {"id": 1208, "coll": "무장 900구절", "sub": ["하나님을 알아감", "긍휼을 베푸시는 하나님"], "book": "시편", "chap": 145, "verse": "9", "ref": "시편 145:9", "texts": {"krv": "여호와께서는 만유를 선대하시며 그 지으신 모든 것에 긍휼을 베푸시는도다", "kkjv": "주께서는 모든 것에게 선하시니 그분의 친절한 긍휼은 그분께서 지으신 모든 것 위에 있도다.", "web": "Yahweh is good to all. His tender mercies are over all his works."}}, {"id": 1209, "coll": "무장 900구절", "sub": ["하나님을 알아감", "긍휼을 베푸시는 하나님"], "book": "이사야", "chap": 54, "verse": "7-8", "ref": "이사야 54:7-8", "texts": {"krv": "내가 잠시 너를 버렸으나 큰 긍휼로 너를 모을 것이요 내가 넘치는 진노로 내 얼굴을 네게서 잠시 가리웠으나 영원한 자비로 너를 긍휼히 여기리라 네 구속자 여호와의 말이니라", "kkjv": "내가 아주 잠시 동안 너를 버렸으나 큰 긍휼로 너를 모을 것이요, 내가 조금 진노하는 가운데 내 얼굴을 잠시 네게 숨겼으나 영존하는 친절로 네게 긍휼을 베풀리라. 주 네 구속자가 말하노라.", "web": "“For a small moment have I forsaken you; but with great mercies will I gather you. In overflowing wrath I hid my face from you for a moment; but with everlasting loving kindness will I have mercy on you,” says Yahweh your Redeemer."}}, {"id": 1210, "coll": "무장 900구절", "sub": ["하나님을 알아감", "긍휼을 베푸시는 하나님"], "book": "이사야", "chap": 54, "verse": "10", "ref": "이사야 54:10", "texts": {"krv": "산들은 떠나며 작은 산들은 옮길지라도 나의 인자는 네게서 떠나지 아니하며 화평케 하는 나의 언약은 옮기지 아니하리라 너를 긍휼히 여기는 여호와의 말이니라", "kkjv": "산들이 떠나가고 작은 산들이 움직일지라도 내 친절은 너를 떠나지 아니하며 내 화평의 언약도 움직이지 아니하리라. 네게 긍휼을 베푸는 주가 말하노라.", "web": "For the mountains may depart, and the hills be removed; but my loving kindness shall not depart from you, neither shall my covenant of peace be removed,” says Yahweh who has mercy on you."}}, {"id": 1211, "coll": "무장 900구절", "sub": ["하나님을 알아감", "긍휼을 베푸시는 하나님"], "book": "이사야", "chap": 55, "verse": "7", "ref": "이사야 55:7", "texts": {"krv": "악인은 그 길을 불의한 자는 그 생각을 버리고 여호와께로 돌아오라 그리하면 그가 긍휼히 여기시리라 우리 하나님께로 나아오라 그가 널리 용서하시리라", "kkjv": "사악한 자는 자기 길을 버리고 불의한 자는 자기 생각을 버리고 주께로 돌아오라. 그리하면 그분께서 그에게 긍휼을 베푸시리라. 우리 하나님께로 돌아오라. 그분께서 풍성하게 용서하시리라.", "web": "let the wicked forsake his way, and the unrighteous man his thoughts; and let him return to Yahweh, and he will have mercy on him; and to our God, for he will abundantly pardon."}}, {"id": 1212, "coll": "무장 900구절", "sub": ["하나님을 알아감", "기도를 들으시는 하나님"], "book": "사무엘상", "chap": 7, "verse": "9", "ref": "사무엘상 7:9", "texts": {"krv": "사무엘이 젖 먹는 어린 양을 취하여 온전한 번제를 여호와께 드리고 이스라엘을 위하여 여호와께 부르짖으매 여호와께서 응답하셨더라", "kkjv": "¶사무엘이 젖 먹는 어린양을 취해 전체를 번제 헌물로 주께 드리고 이스라엘을 위해 주께 부르짖으매 주께서 그의 말을 들으셨더라.", "web": "Samuel took a suckling lamb, and offered it for a whole burnt offering to Yahweh: and Samuel cried to Yahweh for Israel; and Yahweh answered him."}}, {"id": 1213, "coll": "무장 900구절", "sub": ["하나님을 알아감", "기도를 들으시는 하나님"], "book": "시편", "chap": 34, "verse": "4", "ref": "시편 34:4", "texts": {"krv": "내가 여호와께 구하매 내게 응답하시고 내 모든 두려움에서 나를 건지셨도다", "kkjv": "내가 주를 찾으매 그분께서 내 말을 들으시고 내 모든 두려움에서 나를 건지셨도다.", "web": "I sought Yahweh, and he answered me, and delivered me from all my fears."}}, {"id": 1214, "coll": "무장 900구절", "sub": ["하나님을 알아감", "기도를 들으시는 하나님"], "book": "시편", "chap": 120, "verse": "1", "ref": "시편 120:1", "texts": {"krv": "내가 환난 중에 여호와께 부르짖었더니 내게 응답하셨도다", "kkjv": "내가 고통 중에 주께 부르짖었더니 그분께서 내 말을 들으셨도다.", "web": "In my distress, I cried to Yahweh. He answered me."}}, {"id": 1215, "coll": "무장 900구절", "sub": ["하나님을 알아감", "기도를 들으시는 하나님"], "book": "시편", "chap": 145, "verse": "19", "ref": "시편 145:19", "texts": {"krv": "저는 자기를 경외하는 자의 소원을 이루시며 또 저희 부르짖음을 들으사 구원하시리로다", "kkjv": "그분께서 자신을 두려워하는 자들의 소원을 이루시며 또 그들의 부르짖음을 들으사 그들을 구원하시리로다.", "web": "He will fulfill the desire of those who fear him. He also will hear their cry, and will save them."}}, {"id": 1216, "coll": "무장 900구절", "sub": ["하나님을 알아감", "기도를 들으시는 하나님"], "book": "이사야", "chap": 65, "verse": "24", "ref": "이사야 65:24", "texts": {"krv": "그들이 부르기 전에 내가 응답하겠고 그들이 말을 마치기 전에 내가 들을 것이며", "kkjv": "그때에는 그들이 부르기 전에 내가 응답하며 그들이 아직 말하는 도중에 내가 들으리라.", "web": "It shall happen that, before they call, I will answer; and while they are yet speaking, I will hear."}}, {"id": 1217, "coll": "무장 900구절", "sub": ["하나님을 알아감", "기도를 들으시는 하나님"], "book": "미가", "chap": 7, "verse": "7", "ref": "미가 7:7", "texts": {"krv": "오직 나는 여호와를 우러러보며 나를 구원하시는 하나님을 바라보나니 나의 하나님이 나를 들으시리로다", "kkjv": "그러므로 나는 주를 바라보며 내 구원의 하나님을 기다리리니 내 하나님께서 내 말을 들으시리로다.", "web": "But as for me, I will look to Yahweh. I will wait for the God of my salvation. My God will hear me."}}, {"id": 1218, "coll": "무장 900구절", "sub": ["하나님을 알아감", "일을 성취하시는 하나님"], "book": "여호수아", "chap": 21, "verse": "45", "ref": "여호수아 21:45", "texts": {"krv": "여호와께서 이스라엘 족속에게 말씀하신 선한 일이 하나도 남음이 없이 다 응하였더라", "kkjv": "주께서 이스라엘의 집에게 말씀하신 선한 일 중의 하나도 빠지지 않고 다 이루어지니라.", "web": "Nothing failed of any good thing which Yahweh had spoken to the house of Israel. All came to pass."}}, {"id": 1219, "coll": "무장 900구절", "sub": ["하나님을 알아감", "일을 성취하시는 하나님"], "book": "욥기", "chap": 23, "verse": "13-14", "ref": "욥기 23:13-14", "texts": {"krv": "그는 뜻이 일정하시니 누가 능히 돌이킬까 그 마음에 하고자 하시는 것이면 그것을 행하시나니 그런즉 내게 작정하신 것을 이루실 것이라 이런 일이 그에게 많이 있느니라", "kkjv": "오직 그분은 생각이 한결 같으시니 누가 그분을 돌이킬 수 있으리요? 그분께서는 자신의 혼이 원하는 것 바로 그것을 행하시나니 그분께서는 나를 위하여 정하신 일을 이루시느니라. 그분께는 그러한 일이 많이 있느니라.", "web": "But he stands alone, and who can oppose him? What his soul desires, even that he does. For he performs that which is appointed for me. Many such things are with him."}}, {"id": 1220, "coll": "무장 900구절", "sub": ["하나님을 알아감", "일을 성취하시는 하나님"], "book": "이사야", "chap": 10, "verse": "23", "ref": "이사야 10:23", "texts": {"krv": "이미 작정 되었은즉 주 만군의 여호와께서 온 세계 중에 끝까지 행하시리라", "kkjv": "이는 주 만군의 하나님이 이미 작정한 멸망을 온 땅의 한가운데서 이룰 것이기 때문이라.", "web": "For the Lord, Yahweh of Armies, will make a full end, and that determined, in the midst of all the earth."}}, {"id": 1221, "coll": "무장 900구절", "sub": ["하나님을 알아감", "일을 성취하시는 하나님"], "book": "이사야", "chap": 14, "verse": "24", "ref": "이사야 14:24", "texts": {"krv": "만군의 여호와께서 맹세하여 가라사대 나의 생각한 것이 반드시 되며 나의 경영한 것이 반드시 이루리라", "kkjv": "¶만군의 주께서 맹세하여 이르시되, 내가 생각한 대로 반드시 그것이 이루어지며 내가 계획한 대로 그것이 서리니", "web": "Yahweh of Armies has sworn, saying, “Surely, as I have thought, so shall it happen; and as I have purposed, so shall it stand:"}}, {"id": 1222, "coll": "무장 900구절", "sub": ["하나님을 알아감", "일을 성취하시는 하나님"], "book": "예레미야", "chap": 33, "verse": "2", "ref": "예레미야 33:2", "texts": {"krv": "일을 행하는 여호와 그것을 지어 성취하는 여호와 그 이름을 여호와라 하는 자가 이같이 이르노라", "kkjv": "그것을 만든 자 주, 그것을 조성하고 굳게 세운 자 주가 이같이 말하노니 주가 그의 이름이니라.", "web": "Thus says Yahweh who does it, Yahweh who forms it to establish it; Yahweh is his name:"}}, {"id": 1223, "coll": "무장 900구절", "sub": ["하나님을 알아감", "일을 성취하시는 하나님"], "book": "빌립보서", "chap": 1, "verse": "6", "ref": "빌립보서 1:6", "texts": {"krv": "너희 속에 착한 일을 시작하신 이가 그리스도 예수의 날까지 이루실 줄을 우리가 확신하노라", "kkjv": "너희 안에서 선한 일을 시작하신 분께서 예수 그리스도의 날까지 그 일을 이루실 것 바로 이것을 나는 확신하노라.", "web": "being confident of this very thing, that he who began a good work in you will complete it until the day of Jesus Christ."}}, {"id": 1224, "coll": "무장 900구절", "sub": ["하나님을 알아감", "좋은 것을 주시는 하나님"], "book": "시편", "chap": 34, "verse": "8", "ref": "시편 34:8", "texts": {"krv": "너희는 여호와의 선하심을 맛보아 알지어다 그에게 피하는 자는 복이 있도다", "kkjv": "오 주께서 선하신 것을 맛보고 알지어다. 그분을 신뢰하는 사람은 복이 있도다.", "web": "Oh taste and see that Yahweh is good. Blessed is the man who takes refuge in him."}}, {"id": 1225, "coll": "무장 900구절", "sub": ["하나님을 알아감", "좋은 것을 주시는 하나님"], "book": "시편", "chap": 84, "verse": "11", "ref": "시편 84:11", "texts": {"krv": "여호와 하나님은 해요 방패시라 여호와께서 은혜와 영화를 주시며 정직히 행하는 자에게 좋은 것을 아끼지 아니하실 것임이니이다", "kkjv": "주 하나님은 해와 방패가 되시나이다. 주께서 은혜와 영광을 주시며 곧바르게 걷는 자들에게 좋은 것을 아끼지 아니하시리이다.", "web": "For Yahweh God is a sun and a shield. Yahweh will give grace and glory. He withholds no good thing from those who walk blamelessly."}}, {"id": 1226, "coll": "무장 900구절", "sub": ["하나님을 알아감", "좋은 것을 주시는 하나님"], "book": "시편", "chap": 103, "verse": "5", "ref": "시편 103:5", "texts": {"krv": "좋은 것으로 네 소원을 만족케 하사 네 청춘으로 독수리 같이 새롭게 하시는도다", "kkjv": "좋은 것들로 네 입을 만족하게 하사 네 젊음을 독수리의 젊음같이 새롭게 하시는도다.", "web": "who satisfies your desire with good things, so that your youth is renewed like the eagle’s."}}, {"id": 1227, "coll": "무장 900구절", "sub": ["하나님을 알아감", "좋은 것을 주시는 하나님"], "book": "시편", "chap": 107, "verse": "9", "ref": "시편 107:9", "texts": {"krv": "저가 사모하는 영혼을 만족케 하시며 주린 영혼에게 좋은 것으로 채워주심이로다", "kkjv": "그분께서 사모하는 혼에게 만족을 주시며 주린 혼을 선하심으로 채워 주시는도다.", "web": "For he satisfies the longing soul. He fills the hungry soul with good."}}, {"id": 1228, "coll": "무장 900구절", "sub": ["하나님을 알아감", "좋은 것을 주시는 하나님"], "book": "이사야", "chap": 55, "verse": "2", "ref": "이사야 55:2", "texts": {"krv": "너희가 어찌하여 양식 아닌 것을 위하여 은을 달아 주며 배부르게 못할 것을 위하여 수고하느냐 나를 청종하라 그리하면 너희가 좋은 것을 먹을 것이며 너희 마음이 기름진 것으로 즐거움을 얻으리라", "kkjv": "너희가 어찌하여 빵이 아닌 것을 위해 돈을 허비하느냐? 또 배부르게 하지 못할 것을 위해 수고하느냐? 내 말에 부지런히 귀를 기울이라. 또 너희는 좋은 것을 먹고 너희 혼으로 하여금 스스로 기름진 것을 기뻐하게 할지어다.", "web": "Why do you spend money for that which is not bread? and your labor for that which doesn’t satisfy? listen diligently to me, and eat you that which is good, and let your soul delight itself in fatness."}}, {"id": 1229, "coll": "무장 900구절", "sub": ["하나님을 알아감", "좋은 것을 주시는 하나님"], "book": "마태복음", "chap": 7, "verse": "11", "ref": "마태복음 7:11", "texts": {"krv": "너희가 악한 자라도 좋은 것으로 자식에게 줄줄 알거든 하물며 하늘에 계신 너희 아버지께서 구하는 자에게 좋은 것으로 주시지 않겠느냐", "kkjv": "그런즉 너희가 악할지라도 너희 자녀들에게 좋은 선물들을 줄 줄 알거든 하물며 하늘에 계신 너희 아버지께서 자기에게 구하는 자들에게 좋은 것들을 얼마나 더 많이 주시겠느냐?", "web": "If you then, being evil, know how to give good gifts to your children, how much more will your Father who is in heaven give good things to those who ask him!"}}, {"id": 1230, "coll": "무장 900구절", "sub": ["하나님을 알아감", "심은 대로 거두게 하시는 하나님"], "book": "잠언", "chap": 1, "verse": "31", "ref": "잠언 1:31", "texts": {"krv": "그러므로 자기 행위의 열매를 먹으며 자기 꾀에 배부르리라", "kkjv": "그러므로 그들이 자기 길에서 난 열매를 먹으며 자기 계략들로 채워지리니", "web": "Therefore they will eat of the fruit of their own way, and be filled with their own schemes."}}, {"id": 1231, "coll": "무장 900구절", "sub": ["하나님을 알아감", "심은 대로 거두게 하시는 하나님"], "book": "예레미야", "chap": 17, "verse": "9-10", "ref": "예레미야 17:9-10", "texts": {"krv": "만물보다 거짓되고 심히 부패한 것은 마음이라 누가 능히 이를 알리요마는 나 여호와는 심장을 살피며 폐부를 시험하고 각각 그 행위와 그 행실대로 보응하나니", "kkjv": "¶마음은 모든 것보다 거짓되고 극도로 사악하니 누가 그것을 알 수 있으리요? 나 주는 마음을 살피며 속 중심을 시험하여 각 사람의 길들과 그 사람의 행위들의 열매대로 그 사람에게 주느니라.", "web": "The heart is deceitful above all things, and it is exceedingly corrupt: who can know it? I, Yahweh, search the mind, I try the heart, even to give every man according to his ways, according to the fruit of his doings."}}, {"id": 1232, "coll": "무장 900구절", "sub": ["하나님을 알아감", "심은 대로 거두게 하시는 하나님"], "book": "마태복음", "chap": 16, "verse": "27", "ref": "마태복음 16:27", "texts": {"krv": "인자가 아버지의 영광으로 그 천사들과 함께 오리니 그 때에 각 사람의 행한 대로 갚으리라", "kkjv": "사람의 아들이 자기 아버지의 영광 중에 자기 천사들과 함께 올 것이요, 그때에 그가 각 사람에게 그의 행위대로 갚아 주리라.", "web": "For the Son of Man will come in the glory of his Father with his angels, and then he will render to everyone according to his deeds."}}, {"id": 1233, "coll": "무장 900구절", "sub": ["하나님을 알아감", "심은 대로 거두게 하시는 하나님"], "book": "로마서", "chap": 2, "verse": "6-7", "ref": "로마서 2:6-7", "texts": {"krv": "하나님께서 각 사람에게 그 행한대로 보응하시되 참고 선을 행하여 영광과 존귀와 썩지 아니함을 구하는 자에게는 영생으로 하시고", "kkjv": "그분께서 각 사람에게 그의 행위대로 갚으시되 참고 꾸준히 잘 행함으로 영광과 존귀와 죽지 아니함을 구하는 자들에게는 영원한 생명으로 갚으시고", "web": "who “will pay back to everyone according to their works:” to those who by patience in well-doing seek for glory, honor, and incorruptibility, eternal life;"}}, {"id": 1234, "coll": "무장 900구절", "sub": ["하나님을 알아감", "심은 대로 거두게 하시는 하나님"], "book": "갈라디아서", "chap": 6, "verse": "7", "ref": "갈라디아서 6:7", "texts": {"krv": "스스로 속이지 말라 하나님은 만홀히 여김을 받지 아니하시나니 사람이 무엇으로 심든지 그대로 거두리라", "kkjv": "속지 말라. 하나님은 조롱당하지 아니하시나니 사람이 무엇을 심든지 또한 그것을 거두리라.", "web": "Don’t be deceived. God is not mocked, for whatever a man sows, that he will also reap."}}, {"id": 1235, "coll": "무장 900구절", "sub": ["하나님을 알아감", "심은 대로 거두게 하시는 하나님"], "book": "요한계시록", "chap": 3, "verse": "10", "ref": "요한계시록 3:10", "texts": {"krv": "네가 나의 인내의 말씀을 지켰은즉 내가 또한 너를 지키어 시험의 때를 면하게 하리니 이는 장차 온 세상에 임하여 땅에 거하는 자들을 시험할 때라", "kkjv": "네가 나의 인내의 말을 지켰은즉 나도 너를 지켜 시험의 시간을 면하게 하리니 그것은 곧 앞으로 온 세상에 임하여 땅에 거하는 자들을 시험하는 시간이라.", "web": "Because you kept my command to endure, I also will keep you from the hour of testing, which is to come on the whole world, to test those who dwell on the earth."}}, {"id": 1236, "coll": "무장 900구절", "sub": ["하나님을 알아감", "풍성하게 채우시는 하나님"], "book": "이사야", "chap": 44, "verse": "3-4", "ref": "이사야 44:3-4", "texts": {"krv": "대저 내가 갈한 자에게 물을 주며 마른 땅에 시내가 흐르게 하며 나의 신을 네 자손에게 나의 복을 네 후손에게 내리리니 그들이 풀 가운데서 솟아나기를 시냇가의 버들 같이 할 것이라", "kkjv": "내가 목마른 자에게 물을 부어 주며 마른 땅에 큰물들을 부어 주고 내 영을 네 씨에게 내 복을 네 후손에게 부어 주리니 그들이 풀 가운데 있는 것 같이 솟아나며 수로 옆의 버드나무같이 솟아나리라.", "web": "For I will pour water on him who is thirsty, and streams on the dry ground. I will pour my Spirit on your seed, and my blessing on your offspring: and they will spring up among the grass, as willows by the watercourses."}}, {"id": 1237, "coll": "무장 900구절", "sub": ["하나님을 알아감", "풍성하게 채우시는 하나님"], "book": "이사야", "chap": 51, "verse": "3", "ref": "이사야 51:3", "texts": {"krv": "대저 나 여호와가 시온을 위로하되 그 모든 황폐한 곳을 위로하여 그 광야로 에덴 같고 그 사막으로 여호와의 동산 같게 하였나니 그 가운데 기뻐함과 즐거워함과 감사함과 창화하는 소리가 있으리라", "kkjv": "주가 시온을 위로하되 그녀의 모든 피폐한 곳을 위로하여 그녀의 광야를 에덴같이, 그녀의 사막을 주의 동산같이 만들리니 그 안에 기쁨과 즐거움과 감사와 노래 가락 소리가 있으리라.", "web": "For Yahweh has comforted Zion; he has comforted all her waste places, and has made her wilderness like Eden, and her desert like the garden of Yahweh; joy and gladness shall be found therein, thanksgiving, and the voice of melody."}}, {"id": 1238, "coll": "무장 900구절", "sub": ["하나님을 알아감", "풍성하게 채우시는 하나님"], "book": "이사야", "chap": 54, "verse": "11-12", "ref": "이사야 54:11-12", "texts": {"krv": "너 곤고하며 광풍에 요동하여 안위를 받지 못한 자여 보라 내가 화려한 채색으로 네 돌 사이에 더하며 청옥으로 네 기초를 쌓으며 홍보석으로 네 성첩을 지으며 석류석으로 네 성문을 만들고 네 지경을 다 보석으로 꾸밀 것이며", "kkjv": "¶오 고난당하며 폭풍에 밀려다녀 위로를 받지 못한 자여, 너는 보라. 내가 아름다운 색깔로 네 돌들을 쌓으며 사파이어로 네 기초를 놓고 마노로 네 창문을 만들며 홍옥으로 네 성문을 만들고 네 모든 경계를 아름다운 돌들로 꾸미리라.", "web": "“You afflicted, tossed with storms, and not comforted, behold, I will set your stones in beautiful colors, and lay your foundations with sapphires. I will make your pinnacles of rubies, and your gates of sparkling jewels, and all your walls of precious stones."}}, {"id": 1239, "coll": "무장 900구절", "sub": ["하나님을 알아감", "풍성하게 채우시는 하나님"], "book": "이사야", "chap": 61, "verse": "3", "ref": "이사야 61:3", "texts": {"krv": "무릇 시온에서 슬퍼하는 자에게 화관을 주어 그 재를 대신하며 희락의 기름으로 그 슬픔을 대신하며 찬송의 옷으로 그 근심을 대신하시고 그들로 의의 나무 곧 여호와의 심으신 바 그 영광을 나타낼 자라 일컬음을 얻게 하려 하심이니라", "kkjv": "또 시온에서 애곡하는 자들에게 정하여 주되 곧 그들에게 재 대신 아름다움을 주고 애곡 대신 기쁨의 기름을 주며 근심의 영 대신 찬양의 옷을 주게 하려 함이라. 그리함으로 그들이 주께서 심으신 의의 나무라 불릴 것이요, 이로써 그분께서 영광을 받으시리라.", "web": "to appoint to those who mourn in Zion, to give to them a garland for ashes, the oil of joy for mourning, the garment of praise for the spirit of heaviness; that they may be called trees of righteousness, the planting of Yahweh, that he may be glorified."}}, {"id": 1240, "coll": "무장 900구절", "sub": ["하나님을 알아감", "풍성하게 채우시는 하나님"], "book": "이사야", "chap": 61, "verse": "7", "ref": "이사야 61:7", "texts": {"krv": "너희가 수치 대신에 배나 얻으며 능욕 대신에 분깃을 인하여 즐거워할 것이라 그리하여 고토에서 배나 얻고 영영한 기쁨이 있으리라", "kkjv": "¶너희가 너희 수치 대신 보상을 두 배나 얻으며 그들이 혼돈 대신 자기들의 몫을 기뻐하리라. 그러므로 그들이 자기들의 땅에서 두 배를 소유하고 영존하는 기쁨이 그들에게 있으리라.", "web": "Instead of your shame you shall have double; and instead of dishonor they shall rejoice in their portion: therefore in their land they shall possess double; everlasting joy shall be to them."}}, {"id": 1241, "coll": "무장 900구절", "sub": ["하나님을 알아감", "풍성하게 채우시는 하나님"], "book": "요한복음", "chap": 10, "verse": "10", "ref": "요한복음 10:10", "texts": {"krv": "도적이 오는 것은 도적질하고 죽이고 멸망시키려는 것뿐이요 내가 온 것은 양으로 생명을 얻게 하고 더 풍성히 얻게 하려는 것이라", "kkjv": "도둑이 오는 것은 다만 도둑질하고 죽이고 멸망시키려 함이거니와 내가 온 것은 양들이 생명을 얻게 하고 또 생명을 더욱 풍성히 얻게 하려 함이라.", "web": "The thief only comes to steal, kill, and destroy. I came that they may have life, and may have it abundantly."}}, {"id": 1242, "coll": "무장 900구절", "sub": ["하나님을 알아감", "나를 기억하고 아시는 하나님"], "book": "욥기", "chap": 7, "verse": "17-18", "ref": "욥기 7:17-18", "texts": {"krv": "사람이 무엇이관대 주께서 크게 여기사 그에게 마음을 두시고 아침마다 권징하시며 분초마다 시험하시나이까", "kkjv": "사람이 무엇이기에 주께서 그를 크게 만드시나이까? 또 주께서 주의 마음을 그에게 두시나이까? 또 주께서 아침마다 그를 찾아보시고 매 순간 단련하시나이까?", "web": "What is man, that you should magnify him, that you should set your mind on him, that you should visit him every morning, and test him every moment?"}}, {"id": 1243, "coll": "무장 900구절", "sub": ["하나님을 알아감", "나를 기억하고 아시는 하나님"], "book": "시편", "chap": 103, "verse": "14", "ref": "시편 103:14", "texts": {"krv": "이는 저가 우리의 체질을 아시며 우리가 진토임을 기억하심이로다", "kkjv": "그분께서는 우리의 구조를 아시며 우리가 먼지임을 기억하시는도다.", "web": "For he knows how we are made. He remembers that we are dust."}}, {"id": 1244, "coll": "무장 900구절", "sub": ["하나님을 알아감", "나를 기억하고 아시는 하나님"], "book": "이사야", "chap": 40, "verse": "27", "ref": "이사야 40:27", "texts": {"krv": "야곱아 네가 어찌하여 말하며 이스라엘아 네가 어찌하여 이르기를 내 사정은 여호와께 숨겨졌으며 원통한 것은 내 하나님에게서 수리하심을 받지 못한다 하느냐", "kkjv": "오 야곱아, 어찌하여 네가 말하며, 오 이스라엘아, 어찌하여 네가 이르기를, 내 길은 주께 숨겨졌으며 나에 대한 판단의 공의는 내 하나님을 떠나 지나가 버렸다, 하느냐?", "web": "Why do you say, Jacob, and speak, Israel, “My way is hidden from Yahweh, and the justice due me is disregarded by my God?”"}}, {"id": 1245, "coll": "무장 900구절", "sub": ["하나님을 알아감", "나를 기억하고 아시는 하나님"], "book": "이사야", "chap": 44, "verse": "21", "ref": "이사야 44:21", "texts": {"krv": "야곱아 이스라엘아 이 일을 기억하라 너는 내 종이니라 내가 너를 지었으니 너는 내 종이니라 이스라엘아 너는 나의 잊음이 되지 아니하리라", "kkjv": "¶오 야곱 곧 이스라엘아, 너는 내 종이니 이것들을 기억하라. 내가 너를 지었으니 너는 내 종이니라. 오 이스라엘아, 너는 내게서 잊히지 아니하리라.", "web": "Remember these things, Jacob and Israel; for you are my servant. I have formed you. You are my servant. Israel, you will not be forgotten by me."}}, {"id": 1246, "coll": "무장 900구절", "sub": ["하나님을 알아감", "나를 기억하고 아시는 하나님"], "book": "이사야", "chap": 49, "verse": "14-15", "ref": "이사야 49:14-15", "texts": {"krv": "오직 시온이 이르기를 여호와께서 나를 버리시며 주께서 나를 잊으셨다 하였거니와 여인이 어찌 그 젖 먹는 자식을 잊겠으며 자기 태에서 난 아들을 긍휼히 여기지 않겠느냐 그들은 혹시 잊을지라도 나는 너를 잊지 아니할 것이라", "kkjv": "그러나 시온은 이르기를, 주께서 나를 버리셨으며 내 주께서 나를 잊으셨다, 하였거니와 여인이 자기의 젖 먹는 자식을 잊을 수 있겠으며 자기 태에서 난 아들을 불쌍히 여기지 않을 수 있겠느냐? 참으로 그들은 혹시 잊을지라도 나는 너를 잊지 아니하리라.", "web": "But Zion said, “Yahweh has forsaken me, and the Lord has forgotten me.” “Can a woman forget her nursing child, that she should not have compassion on the son of her womb? Yes, these may forget, yet I will not forget you!"}}, {"id": 1247, "coll": "무장 900구절", "sub": ["하나님을 알아감", "나를 기억하고 아시는 하나님"], "book": "누가복음", "chap": 12, "verse": "6", "ref": "누가복음 12:6", "texts": {"krv": "참새 다섯이 앗사리온 둘에 팔리는 것이 아니냐 그러나 하나님 앞에는 그 하나라도 잊어버리시는 바 되지 아니하는도다", "kkjv": "참새 다섯 마리가 이 앗사리온에 팔리지 아니하느냐? 그러나 하나님 앞에서는 그것들 중의 하나도 잊히지 아니하느니라.", "web": "“Aren’t five sparrows sold for two assaria coins? Not one of them is forgotten by God."}}, {"id": 1248, "coll": "무장 900구절", "sub": ["하나님을 알아감", "열심히 일하시는 하나님"], "book": "열왕기하", "chap": 19, "verse": "31", "ref": "열왕기하 19:31", "texts": {"krv": "남은 자는 예루살렘에서부터 나올 것이요 피하는 자는 시온산에서부터 나오리니 여호와의 열심이 이 일을 이루리라 하셨나이다", "kkjv": "남은 자가 예루살렘에서 나오며 피하는 자들이 시온 산에서 나오리라. 만군의 주의 열심이 이 일을 행하리라.", "web": "For out of Jerusalem a remnant will go out, and out of Mount Zion those who shall escape. The zeal of Yahweh will perform this.’"}}, {"id": 1249, "coll": "무장 900구절", "sub": ["하나님을 알아감", "열심히 일하시는 하나님"], "book": "예레미야", "chap": 7, "verse": "25", "ref": "예레미야 7:25", "texts": {"krv": "너희 열조가 애굽 땅에서 나온 날부터 오늘까지 내가 내 종 선지자들을 너희에게 보내었으되 부지런히 보내었으나", "kkjv": "너희 조상들이 이집트 땅에서 나온 날부터 이 날에 이르기까지 내가 날마다 일찍 일어나 너희에게 나의 모든 종 대언자들을 보내고 보내었으나", "web": "Since the day that your fathers came out of the land of Egypt to this day, I have sent to you all my servants the prophets, daily rising up early and sending them:"}}, {"id": 1250, "coll": "무장 900구절", "sub": ["하나님을 알아감", "열심히 일하시는 하나님"], "book": "에스겔", "chap": 39, "verse": "25", "ref": "에스겔 39:25", "texts": {"krv": "그러므로 나 주 여호와가 말하노라 내가 이제 내 거룩한 이름을 위하여 열심을 내어 야곱의 사로잡힌 자를 돌아오게 하며 이스라엘 온 족속에게 긍휼을 베풀지라", "kkjv": "그러므로 주 하나님이 이같이 말하노라. 이제 내가 야곱의 포로 된 자들을 다시 데려오고 이스라엘의 온 집에게 긍휼을 베풀며 내 거룩한 이름을 위하여 질투하리라.", "web": "Therefore thus says the Lord Yahweh: Now will I bring back the captivity of Jacob, and have mercy on the whole house of Israel; and I will be jealous for my holy name."}}, {"id": 1251, "coll": "무장 900구절", "sub": ["하나님을 알아감", "열심히 일하시는 하나님"], "book": "요한복음", "chap": 2, "verse": "17", "ref": "요한복음 2:17", "texts": {"krv": "제자들이 성경 말씀에 주의 전을 사모하는 열심이 나를 삼키리라 한 것을 기억하더라", "kkjv": "그분의 제자들이 기록된바, 주의 집에 대한 열심이 나를 삼켰나이다, 한 것을 기억하더라.", "web": "His disciples remembered that it was written, “Zeal for your house will eat me up.”"}}, {"id": 1252, "coll": "무장 900구절", "sub": ["하나님을 알아감", "열심히 일하시는 하나님"], "book": "요한복음", "chap": 5, "verse": "17", "ref": "요한복음 5:17", "texts": {"krv": "예수께서 저희에게 이르시되 내 아버지께서 이제까지 일하시니 나도 일한다 하시매", "kkjv": "¶그러나 예수님께서 그들에게 응답하시되, 내 아버지께서 지금까지 일하시니 나도 일한다, 하시매", "web": "But Jesus answered them, “My Father is still working, so I am working, too.”"}}, {"id": 1253, "coll": "무장 900구절", "sub": ["하나님을 알아감", "열심히 일하시는 하나님"], "book": "요한복음", "chap": 9, "verse": "4", "ref": "요한복음 9:4", "texts": {"krv": "때가 아직 낮이매 나를 보내신 이의 일을 우리가 하여야 하리라 밤이 오리니 그때는 아무도 일할 수 없느니라", "kkjv": "낮일 때에 내가 반드시 나를 보내신 분의 일들을 하여야 하리라. 밤이 오면 그때는 아무도 일할 수 없느니라.", "web": "I must work the works of him who sent me, while it is day. The night is coming, when no one can work."}}, {"id": 1254, "coll": "DEP 242구절", "sub": ["구원의 확신", "확신할 수 있음"], "book": "고린도후서", "chap": 13, "verse": "5", "ref": "고린도후서 13:5", "texts": {"krv": "너희가 믿음에 있는가 너희 자신을 시험하고 너희 자신을 확증하라 예수 그리스도께서 너희 안에 계신 줄을 너희가 스스로 알지 못하느냐 그렇지 않으면 너희가 버리운 자니라", "kkjv": "너희가 믿음 안에 있는지 너희 자신을 살펴보고 너희 자신을 입증하라. 예수 그리스도께서 너희 안에 계시는 줄을 너희가 스스로 알지 못하느냐? 그렇지 않으면 너희는 버림받은 자니라.", "web": "Test your own selves, whether you are in the faith. Test your own selves. Or don’t you know as to your own selves, that Jesus Christ is in you?—unless indeed you are disqualified."}}, {"id": 1255, "coll": "DEP 242구절", "sub": ["구원의 확신", "확신할 수 있음"], "book": "요한일서", "chap": 5, "verse": "11,12", "ref": "요한일서 5:11,12", "texts": {"krv": "또 증거는 이것이니 하나님이 우리에게 영생을 주신 것과 이 생명이 그의 아들 안에 있는 그것이니라 아들이 있는 자에게는 생명이 있고 하나님의 아들이 없는 자에게는 생명이 없느니라", "kkjv": "또 그 증언은 이것이니 곧 하나님께서 우리에게 영원한 생명을 주신 것과 이 생명이 그분의 아들 안에 있다는 것이니라. 아들이 있는 자에게는 생명이 있고 하나님의 아들이 없는 자에게는 생명이 없느니라.", "web": "The testimony is this, that God gave to us eternal life, and this life is in his Son. He who has the Son has the life. He who doesn’t have God’s Son doesn’t have the life."}}, {"id": 1256, "coll": "DEP 242구절", "sub": ["구원의 확신", "영생이 있음을 앎"], "book": "요한일서", "chap": 5, "verse": "13", "ref": "요한일서 5:13", "texts": {"krv": "내가 하나님의 아들의 이름을 믿는 너희에게 이것을 쓴 것은 너희로 하여금 너희에게 영생이 있음을 알게 하려 함이라", "kkjv": "내가 하나님의 아들의 이름을 믿는 너희에게 이것들을 쓴 것은 너희에게 영원한 생명이 있음을 너희가 알게 하고 또 하나님의 아들의 이름을 너희가 믿게 하려 함이라.", "web": "These things I have written to you who believe in the name of the Son of God, that you may know that you have eternal life, and that you may continue to believe in the name of the Son of God."}}, {"id": 1257, "coll": "DEP 242구절", "sub": ["구원의 확신", "영생이 있음을 앎"], "book": "요한복음", "chap": 6, "verse": "47", "ref": "요한복음 6:47", "texts": {"krv": "진실로 진실로 너희에게 이르노니 믿는 자는 영생을 가졌나니", "kkjv": "진실로 진실로 내가 너희에게 이르노니, 나를 믿는 자에게는 영존하는 생명이 있느니라.", "web": "Most certainly, I tell you, he who believes in me has eternal life."}}, {"id": 1258, "coll": "DEP 242구절", "sub": ["구원의 확신", "죄 사함을 받음"], "book": "에베소서", "chap": 1, "verse": "7", "ref": "에베소서 1:7", "texts": {"krv": "우리가 그리스도 안에서 그의 은혜의 풍성함을 따라 그의 피로 말미암아 구속 곧 죄 사함을 받았으니", "kkjv": "그 사랑하시는 자 안에서 우리가 그분의 풍성한 은혜에 따라 그분의 피를 통해 구속 곧 죄들의 용서를 받았도다.", "web": "in whom we have our redemption through his blood, the forgiveness of our trespasses, according to the riches of his grace,"}}, {"id": 1259, "coll": "DEP 242구절", "sub": ["구원의 확신", "죄 사함을 받음"], "book": "로마서", "chap": 8, "verse": "1", "ref": "로마서 8:1", "texts": {"krv": "그러므로 이제 그리스도 예수 안에 있는 자에게는 결코 정죄함이 없나니", "kkjv": "그러므로 이제 그리스도 예수님 안에 있는 자들에게는 정죄함이 없나니 그들은 육신을 따라 걷지 아니하고 성령을 따라 걷느니라.", "web": "There is therefore now no condemnation to those who are in Christ Jesus, who don’t walk according to the flesh, but according to the Spirit."}}, {"id": 1260, "coll": "DEP 242구절", "sub": ["구원의 확신", "의롭게 됨"], "book": "로마서", "chap": 3, "verse": "24", "ref": "로마서 3:24", "texts": {"krv": "그리스도 예수 안에 있는 구속으로 말미암아 하나님의 은혜로 값없이 의롭다 하심을 얻은 자 되었느니라", "kkjv": "그리스도 예수님 안에 있는 구속(救贖)을 통해 하나님의 은혜로 값없이 의롭게 되었느니라.", "web": "being justified freely by his grace through the redemption that is in Christ Jesus;"}}, {"id": 1261, "coll": "DEP 242구절", "sub": ["구원의 확신", "의롭게 됨"], "book": "로마서", "chap": 5, "verse": "1", "ref": "로마서 5:1", "texts": {"krv": "그러므로 우리가 믿음으로 의롭다 하심을 얻었은즉 우리 주 예수 그리스도로 말미암아 하나님으로 더불어 화평을 누리자", "kkjv": "그러므로 우리가 믿음으로 의롭게 되어 우리 주 예수 그리스도를 통해 하나님과의 화평을 누리는도다.", "web": "Being therefore justified by faith, we have peace with God through our Lord Jesus Christ;"}}, {"id": 1262, "coll": "DEP 242구절", "sub": ["구원의 확신", "그리스도 안에서 거듭남"], "book": "베드로전서", "chap": 1, "verse": "3", "ref": "베드로전서 1:3", "texts": {"krv": "찬송하리로다 우리 주 예수 그리스도의 아버지 하나님이 그 많으신 긍휼대로 예수 그리스도의 죽은 자 가운데서 부활하심으로 말미암아 우리를 거듭나게 하사 산 소망이 있게 하시며", "kkjv": "하나님 곧 우리 주 예수 그리스도의 아버지를 찬송하리로다. 그분께서 자신의 풍성하신 긍휼에 따라 죽은 자들로부터 예수 그리스도를 부활하게 하심으로 우리를 다시 낳으사 산 소망에 이르게 하셨으며", "web": "Blessed be the God and Father of our Lord Jesus Christ, who according to his great mercy became our father again to a living hope through the resurrection of Jesus Christ from the dead,"}}, {"id": 1263, "coll": "DEP 242구절", "sub": ["구원의 확신", "그리스도 안에서 거듭남"], "book": "디도서", "chap": 3, "verse": "5", "ref": "디도서 3:5", "texts": {"krv": "우리를 구원하시되 우리의 행한 바 의로운 행위로 말미암지 아니하고 오직 그의 긍휼하심을 좇아 중생의 씻음과 성령의 새롭게 하심으로 하셨나니", "kkjv": "그분께서 우리를 구원하시되 우리가 행한 의로운 행위로 하지 아니하시고 오직 자신의 긍휼에 따라 다시 태어남의 씻음과 성령님의 새롭게 하심으로 하셨고", "web": "not by works of righteousness, which we did ourselves, but according to his mercy, he saved us, through the washing of regeneration and renewing by the Holy Spirit,"}}, {"id": 1264, "coll": "DEP 242구절", "sub": ["구원의 확신", "하나님의 자녀가 됨"], "book": "갈라디아서", "chap": 3, "verse": "26", "ref": "갈라디아서 3:26", "texts": {"krv": "너희가 다 믿음으로 말미암아 그리스도 예수 안에서 하나님의 아들이 되었으니", "kkjv": "너희가 다 그리스도 예수님을 믿는 믿음으로 말미암아 하나님의 아이들이 되었나니", "web": "For you are all children of God, through faith in Christ Jesus."}}, {"id": 1265, "coll": "DEP 242구절", "sub": ["구원의 확신", "하나님의 자녀가 됨"], "book": "로마서", "chap": 8, "verse": "14", "ref": "로마서 8:14", "texts": {"krv": "무릇 하나님의 영으로 인도함을 받는 그들은 곧 하나님의 아들이라", "kkjv": "하나님의 영에 의해 인도 받는 자들은 다 하나님의 아들들이니", "web": "For as many as are led by the Spirit of God, these are children of God."}}, {"id": 1266, "coll": "DEP 242구절", "sub": ["구원의 확신", "믿는 자 안에 거하시는 성령"], "book": "로마서", "chap": 8, "verse": "9", "ref": "로마서 8:9", "texts": {"krv": "만일 너희 속에 하나님의 영이 거하시면 너희가 육신에 있지 아니하고 영에 있나니 누구든지 그리스도의 영이 없으면 그리스도의 사람이 아니라", "kkjv": "그러나 너희 안에 하나님의 영께서 거하시면 너희가 육신 안에 있지 아니하고 성령 안에 있나니 이제 어떤 사람에게 그리스도의 영이 없으면 그는 그분의 사람이 아니니라.", "web": "But you are not in the flesh but in the Spirit, if it is so that the Spirit of God dwells in you. But if any man doesn’t have the Spirit of Christ, he is not his."}}, {"id": 1267, "coll": "DEP 242구절", "sub": ["구원의 확신", "믿는 자 안에 거하시는 성령"], "book": "요한복음", "chap": 14, "verse": "16,17", "ref": "요한복음 14:16,17", "texts": {"krv": "내가 아버지께 구하겠으니 그가 또 다른 보혜사를 너희에게 주사 영원토록 너희와 함께 있게 하시리니 저는 진리의 영이라 세상은 능히 저를 받지 못하나니 이는 저를 보지도 못하고 알지도 못함이라 그러나 너희는 저를 아나니 저는 너희와 함께 거하심이요 또 너희 속에 계시겠음이라", "kkjv": "내가 아버지께 구할 터인즉 그분께서 다른 위로자를 너희에게 주사 그분께서 영원토록 너희와 함께 거하게 하시리니 곧 진리의 영이시라. 세상은 그분을 받아들이지 못하나니 이는 세상이 그분을 보지도 못하고 알지도 못하기 때문이라. 그러나 너희는 그분을 아나니 이는 그분께서 너희와 함께 거하시며 또 너희 속에 계실 것이기 때문이라.", "web": "I will pray to the Father, and he will give you another Counselor, that he may be with you forever,— the Spirit of truth, whom the world can’t receive; for it doesn’t see him, neither knows him. You know him, for he lives with you, and will be in you."}}, {"id": 1268, "coll": "DEP 242구절", "sub": ["구원의 확신", "빼앗기지 않는 구원"], "book": "요한복음", "chap": 10, "verse": "28,29", "ref": "요한복음 10:28,29", "texts": {"krv": "내가 저희에게 영생을 주노니 영원히 멸망치 아니할 터이요 또 저희를 내 손에서 빼앗을 자가 없느니라 저희를 주신 내 아버지는 만유보다 크시매 아무도 아버지 손에서 빼앗을 수 없느니라", "kkjv": "내가 그들에게 영원한 생명을 주노니 그들이 결코 멸망하지 않을 것이요 또 아무도 내 손에서 그들을 빼앗지 못하리라. 그들을 내게 주신 내 아버지는 모든 것보다 크시매 아무도 내 아버지 손에서 능히 그들을 빼앗지 못하느니라.", "web": "I give eternal life to them. They will never perish, and no one will snatch them out of my hand. My Father, who has given them to me, is greater than all. No one is able to snatch them out of my Father’s hand."}}, {"id": 1269, "coll": "DEP 242구절", "sub": ["구원의 확신", "빼앗기지 않는 구원"], "book": "로마서", "chap": 8, "verse": "39", "ref": "로마서 8:39", "texts": {"krv": "높음이나 깊음이나 다른 아무 피조물이라도 우리를 우리 주 그리스도 예수 안에 있는 하나님의 사랑에서 끊을 수 없으리라", "kkjv": "높음이나 깊음이나 다른 어떤 창조물이라도 능히 우리를 그리스도 예수 우리 주 안에 있는 하나님의 사랑에서 떼어 놓지 못하리라.", "web": "nor height, nor depth, nor any other created thing, will be able to separate us from the love of God, which is in Christ Jesus our Lord."}}, {"id": 1270, "coll": "DEP 242구절", "sub": ["구원의 확신", "말씀에 근거한 확신"], "book": "베드로전서", "chap": 1, "verse": "23", "ref": "베드로전서 1:23", "texts": {"krv": "너희가 거듭난 것이 썩어질 씨로 된 것이 아니요 썩지 아니할 씨로 된 것이니 하나님의 살아 있고 항상 있는 말씀으로 되었느니라", "kkjv": "너희가 다시 태어난 것은 썩을 씨에서 난 것이 아니요 썩지 아니할 씨에서 난 것이니 살아 있고 영원히 거하는 하나님의 말씀으로 된 것이니라.", "web": "having been born again, not of corruptible seed, but of incorruptible, through the word of God, which lives and remains forever."}}, {"id": 1271, "coll": "DEP 242구절", "sub": ["구원의 확신", "말씀에 근거한 확신"], "book": "에베소서", "chap": 1, "verse": "13", "ref": "에베소서 1:13", "texts": {"krv": "그 안에서 너희도 진리의 말씀 곧 너희의 구원의 복음을 듣고 그 안에서 또한 믿어 약속의 성령으로 인치심을 받았으니", "kkjv": "너희도 진리의 말씀 곧 너희의 구원의 복음을 들은 뒤에 그분을 신뢰하였고 너희가 믿은 뒤에 또한 그분 안에서 약속의 저 거룩하신 영으로 봉인되었느니라.", "web": "in whom you also, having heard the word of the truth, the Good News of your salvation—in whom, having also believed, you were sealed with the Holy Spirit of promise,"}}, {"id": 1272, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT 왜 가져야 하는가?", "하나님이 교제를 원하심"], "book": "고린도전서", "chap": 1, "verse": "9", "ref": "고린도전서 1:9", "texts": {"krv": "너희를 불러 그의 아들 예수 그리스도 우리 주로 더불어 교제케 하시는 하나님은 미쁘시도다", "kkjv": "너희를 부르사 자신의 아들 예수 그리스도 우리 주와 교제하게 하시는 하나님은 신실하시도다.", "web": "God is faithful, through whom you were called into the fellowship of his Son, Jesus Christ, our Lord."}}, {"id": 1273, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT 왜 가져야 하는가?", "하나님이 교제를 원하심"], "book": "이사야", "chap": 30, "verse": "18", "ref": "이사야 30:18", "texts": {"krv": "그러나 여호와께서 기다리시나니 이는 너희에게 은혜를 베풀려 하심이요 일어나시리니 이는 저희를 긍휼히 여기려 하심이라 대저 여호와는 공의의 하나님이심이라 무릇 그를 기다리는 자는 복이 있도다", "kkjv": "¶그러므로 주께서 기다리시리니 이것은 그분께서 너희에게 은혜를 베풀려 하심이라. 그러므로 그분께서 높여지시리니 이것은 그분께서 너희에게 긍휼을 베풀려 하심이라. 주는 공의의 하나님이시니 그분을 기다리는 모든 자들은 복이 있도다.", "web": "Therefore Yahweh will wait, that he may be gracious to you; and therefore he will be exalted, that he may have mercy on you, for Yahweh is a God of justice. Blessed are all those who wait for him."}}, {"id": 1274, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT 왜 가져야 하는가?", "하나님의 명령"], "book": "이사야", "chap": 55, "verse": "6", "ref": "이사야 55:6", "texts": {"krv": "너희는 여호와를 만날 만한 때에 찾으라 가까이 계실 때에 그를 부르라", "kkjv": "¶너희는 주를 만날 만한 때에 그분을 찾으라. 그분께서 가까이 계실 때에 그분을 부르라.", "web": "Seek Yahweh while he may be found; call you on him while he is near:"}}, {"id": 1275, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT 왜 가져야 하는가?", "하나님의 명령"], "book": "시편", "chap": 27, "verse": "8", "ref": "시편 27:8", "texts": {"krv": "너희는 내 얼굴을 찾으라 하실 때에 내 마음이 주께 말하되 여호와여 내가 주의 얼굴을 찾으리이다 하였나이다", "kkjv": "주께서, 너희는 내 얼굴을 찾으라, 하셨을 때에 내 마음이 주께 아뢰기를, 주여, 내가 주의 얼굴을 찾으리이다, 하였나이다.", "web": "When you said, “Seek my face,” my heart said to you, “I will seek your face, Yahweh.”"}}, {"id": 1276, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT 왜 가져야 하는가?", "축복의 약속"], "book": "요한복음", "chap": 15, "verse": "5", "ref": "요한복음 15:5", "texts": {"krv": "나는 포도나무요 너희는 가지니 저가 내 안에, 내가 저 안에 있으면 이 사람은 과실을 많이 맺나니 나를 떠나서는 너희가 아무 것도 할 수 없음이라", "kkjv": "나는 포도나무요 너희는 가지니라. 사람이 내 안에 거하고 내가 그 안에 거하면 바로 그 사람은 많은 열매를 맺나니 나 없이는 너희가 아무것도 할 수 없느니라.", "web": "I am the vine. You are the branches. He who remains in me, and I in him, the same bears much fruit, for apart from me you can do nothing."}}, {"id": 1277, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT 왜 가져야 하는가?", "축복의 약속"], "book": "시편", "chap": 34, "verse": "10", "ref": "시편 34:10", "texts": {"krv": "젊은 사자는 궁핍하여 주릴지라도 여호와를 찾는 자는 모든 좋은 것에 부족함이 없으리로다", "kkjv": "젊은 사자들은 부족하여 굶주릴지라도 주를 찾는 자들에게는 모든 좋은 것이 부족하지 아니하리로다.", "web": "The young lions do lack, and suffer hunger, but those who seek Yahweh shall not lack any good thing."}}, {"id": 1278, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT 왜 가져야 하는가?", "하나님의 뜻을 알고 행하기 위해"], "book": "하박국", "chap": 2, "verse": "1", "ref": "하박국 2:1", "texts": {"krv": "내가 내 파수하는 곳에 서며 성루에 서리라 그가 내게 무엇이라 말씀하실는지 기다리고 바라보며 나의 질문에 대하여 어떻게 대답하실는지 보리라 그리하였더니", "kkjv": "내가 나의 파수 보는 곳에 서며 나를 망대에 세우고 그분께서 내게 무어라 말씀하실지 또 내가 책망 받을 때에 무어라 대답할지 보려고 깨어 있으리라, 하였더니", "web": "I will stand at my watch, and set myself on the ramparts, and will look out to see what he will say to me, and what I will answer concerning my complaint."}}, {"id": 1279, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT 왜 가져야 하는가?", "하나님의 뜻을 알고 행하기 위해"], "book": "시편", "chap": 143, "verse": "8,10", "ref": "시편 143:8,10", "texts": {"krv": "아침에 나로 주의 인자한 말씀을 듣게 하소서 내가 주를 의뢰함이니이다 나의 다닐 길을 알게 하소서 내가 내 영혼을 주께 받듦이니이다 주는 나의 하나님이시니 나를 가르쳐 주의 뜻을 행케 하소서 주의 신이 선하시니 나를 공평한 땅에 인도하소서", "kkjv": "내가 주를 신뢰하오니 아침에 나로 하여금 주의 인자하심에 대하여 듣게 하소서. 내가 주를 향해 내 혼을 들어 올리오니 나로 하여금 내가 마땅히 가야 할 길을 알게 하소서. 주는 나의 하나님이시오니 나를 가르쳐 주의 뜻을 행하게 하소서. 주의 영은 선하시오니 나를 곧바른 땅으로 인도하소서.", "web": "Cause me to hear your loving kindness in the morning, for I trust in you. Cause me to know the way in which I should walk, for I lift up my soul to you. Teach me to do your will, for you are my God. Your Spirit is good. Lead me in the land of uprightness."}}, {"id": 1280, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "주님을 바라보는 것"], "book": "히브리서", "chap": 12, "verse": "2", "ref": "히브리서 12:2", "texts": {"krv": "믿음의 주요 또 온전케 하시는 이인 예수를 바라보자 저는 그 앞에 있는 즐거움을 위하여 십자가를 참으사 부끄러움을 개의치 아니하시더니 하나님 보좌 우편에 앉으셨느니라", "kkjv": "우리의 믿음의 창시자요 또 완성자이신 예수님을 바라보자. 그분께서는 자기 앞에 놓인 기쁨으로 인해 십자가를 견디사 그 수치를 멸시하시더니 이제 하나님의 왕좌 오른편에 앉으셨느니라.", "web": "looking to Jesus, the author and perfecter of faith, who for the joy that was set before him endured the cross, despising its shame, and has sat down at the right hand of the throne of God."}}, {"id": 1281, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "주님을 바라보는 것"], "book": "시편", "chap": 42, "verse": "11", "ref": "시편 42:11", "texts": {"krv": "내 영혼아 네가 어찌하여 낙망하며 어찌하여 내 속에서 불안하여 하는고 너는 하나님을 바라라 나는 내 얼굴을 도우시는 내 하나님을 오히려 찬송하리로다", "kkjv": "오 내 혼아, 어찌하여 네가 낙심하느냐? 어찌하여 네가 내 속에서 불안해하느냐? 너는 하나님께 소망을 두라. 내 얼굴의 건강이시요, 내 하나님이신 그분을 내가 여전히 찬양하리로다.", "web": "Why are you in despair, my soul? Why are you disturbed within me? Hope in God! For I shall still praise him, the saving help of my countenance, and my God."}}, {"id": 1282, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "갈급함으로 주님께 나아가는 것"], "book": "시편", "chap": 42, "verse": "1", "ref": "시편 42:1", "texts": {"krv": "하나님이여 사슴이 시냇물을 찾기에 갈급함 같이 내 영혼이 주를 찾기에 갈급하니이다", "kkjv": "오 하나님이여, 사슴이 물 시내를 찾기에 갈급함같이 내 혼이 주를 찾기에 갈급하나이다.", "web": "As the deer pants for the water brooks, so my soul pants after you, God."}}, {"id": 1283, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "갈급함으로 주님께 나아가는 것"], "book": "시편", "chap": 130, "verse": "5,6", "ref": "시편 130:5,6", "texts": {"krv": "나 곧 내 영혼이 여호와를 기다리며 내가 그 말씀을 바라는도다 파수꾼이 아침을 기다림보다 내 영혼이 주를 더 기다리나니 참으로 파수꾼의 아침을 기다림보다 더하도다", "kkjv": "내가 주를 기다리고 내 혼이 기다리며 내가 그분의 말씀에 소망을 두는도다. 내 혼이 주를 기다림이 파수 보는 자들이 아침을 기다림보다 더하나니 내가 말하거니와 파수 보는 자들이 아침을 기다림보다 더하도다.", "web": "I wait for Yahweh. My soul waits. I hope in his word. My soul longs for the Lord more than watchmen long for the morning; more than watchmen for the morning."}}, {"id": 1284, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "우리 짐을 주님께 맡기는 것"], "book": "시편", "chap": 55, "verse": "22", "ref": "시편 55:22", "texts": {"krv": "네 짐을 여호와께 맡겨 버리라 너를 붙드시고 의인의 요동함을 영영히 허락지 아니하시리로다", "kkjv": "네 짐을 주께 맡기라. 그러면 그분께서 너를 붙드시고 의로운 자가 흔들리는 것을 결코 허락하지 아니하시리로다.", "web": "Cast your burden on Yahweh, and he will sustain you. He will never allow the righteous to be moved."}}, {"id": 1285, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "우리 짐을 주님께 맡기는 것"], "book": "시편", "chap": 68, "verse": "19", "ref": "시편 68:19", "texts": {"krv": "날마다 우리 짐을 지시는 주 곧 우리의 구원이신 하나님을 찬송할지로다", "kkjv": "날마다 우리에게 은택을 더하시는 주 곧 우리의 구원의 하나님을 찬송하리로다. 셀라.", "web": "Blessed be the Lord, who daily bears our burdens, even the God who is our salvation. Selah."}}, {"id": 1286, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "주님께 피하고 쉬는 것"], "book": "시편", "chap": 91, "verse": "9,10", "ref": "시편 91:9,10", "texts": {"krv": "네가 말하기를 여호와는 나의 피난처시라 하고 지존자로 거처를 삼았으므로 화가 네게 미치지 못하며 재앙이 네 장막에 가까이 오지 못하리니", "kkjv": "나의 피난처 되시는 주 곧 지극히 높으신 이를 네가 네 처소로 삼았으므로 어떤 재앙도 네게 닥치지 못하며 어떤 역병도 네 거처에 가까이 오지 못하리니", "web": "Because you have made Yahweh your refuge, and the Most High your dwelling place, no evil shall happen to you, neither shall any plague come near your dwelling."}}, {"id": 1287, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "주님께 피하고 쉬는 것"], "book": "마태복음", "chap": 11, "verse": "28,29", "ref": "마태복음 11:28,29", "texts": {"krv": "수고하고 무거운 짐진 자들아 다 내게로 오라 내가 너희를 쉬게 하리라 나는 마음이 온유하고 겸손하니 나의 멍에를 메고 내게 배우라 그러면 너희 마음이 쉼을 얻으리니", "kkjv": "¶수고하고 무거운 짐 진 모든 자들아, 너희는 내게로 오라. 내가 너희에게 안식을 주리라. 나는 마음이 온유하고 겸손하니 너희 위에 내 멍에를 메고 내게 배우라. 그리하면 너희가 너희 혼을 위한 안식을 찾으리니", "web": "“Come to me, all you who labor and are heavily burdened, and I will give you rest. Take my yoke upon you, and learn from me, for I am gentle and lowly in heart; and you will find rest for your souls."}}, {"id": 1288, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "말씀과 기도로 주님과 교제하는 것"], "book": "시편", "chap": 119, "verse": "147,148", "ref": "시편 119:147,148", "texts": {"krv": "내가 새벽 전에 부르짖으며 주의 말씀을 바랐사오며 주의 말씀을 묵상하려고 내 눈이 야경이 깊기 전에 깨었나이다", "kkjv": "내가 아침이 밝기 전에 일어나 부르짖었고 주의 말씀에 소망을 두었사오며 주의 말씀을 묵상하려고 내 눈이 밤의 경점들보다 앞서 가나이다.", "web": "I rise before dawn and cry for help. I put my hope in your words. My eyes stay open through the night watches, that I might meditate on your word."}}, {"id": 1289, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "말씀과 기도로 주님과 교제하는 것"], "book": "시편", "chap": 5, "verse": "3", "ref": "시편 5:3", "texts": {"krv": "여호와여 아침에 주께서 나의 소리를 들으시리니 아침에 내가 주께 기도하고 바라리이다", "kkjv": "오 주여, 아침에 주께서 내 목소리를 들으시리니 아침에 내가 내 기도를 주께로 향하게 하고 위를 바라보리이다.", "web": "Yahweh, in the morning you shall hear my voice. In the morning I will lay my requests before you, and will watch expectantly."}}, {"id": 1290, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "주님을 예배하는 것"], "book": "시편", "chap": 95, "verse": "6", "ref": "시편 95:6", "texts": {"krv": "오라 우리가 굽혀 경배하며 우리를 지으신 여호와 앞에 무릎을 꿇자", "kkjv": "오 오라, 우리가 경배하고 절하며 우리를 만드신 분 곧 주 앞에 무릎을 꿇자.", "web": "Oh come, let’s worship and bow down. Let’s kneel before Yahweh, our Maker,"}}, {"id": 1291, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "주님을 예배하는 것"], "book": "히브리서", "chap": 13, "verse": "15", "ref": "히브리서 13:15", "texts": {"krv": "이러므로 우리가 예수로 말미암아 항상 찬미의 제사를 하나님께 드리자 이는 그 이름을 증거하는 입술의 열매니라", "kkjv": "그러므로 우리가 그분으로 말미암아 계속해서 찬양의 희생을 하나님께 드리자. 그것은 곧 그분의 이름에 감사를 드리는 우리 입술의 열매니라.", "web": "Through him, then, let us offer up a sacrifice of praise to God  continually, that is, the fruit of lips which proclaim allegiance to his name."}}, {"id": 1292, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "매일의 만족을 얻는 것"], "book": "시편", "chap": 90, "verse": "14", "ref": "시편 90:14", "texts": {"krv": "아침에 주의 인자로 우리를 만족케 하사 우리 평생에 즐겁고 기쁘게 하소서", "kkjv": "오 일찍 주의 긍휼로 우리를 만족하게 하사 우리가 평생토록 기뻐하고 즐거워하게 하소서.", "web": "Satisfy us in the morning with your loving kindness, that we may rejoice and be glad all our days."}}, {"id": 1293, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT무엇인가?", "매일의 만족을 얻는 것"], "book": "시편", "chap": 107, "verse": "9", "ref": "시편 107:9", "texts": {"krv": "저가 사모하는 영혼을 만족케 하시며 주린 영혼에게 좋은 것으로 채워주심이로다", "kkjv": "그분께서 사모하는 혼에게 만족을 주시며 주린 혼을 선하심으로 채워 주시는도다.", "web": "For he satisfies the longing soul. He fills the hungry soul with good."}}, {"id": 1294, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT의 본", "하루의 첫 시간에 기도하신 예수님"], "book": "마가복음", "chap": 1, "verse": "35", "ref": "마가복음 1:35", "texts": {"krv": "새벽 오히려 미명에 예수께서 일어나 나가 한적한 곳으로 가사 거기서 기도하시더니", "kkjv": "새벽에 아직 날이 밝기 훨씬 전에 그분께서 일어나 나가서 외진 곳으로 떠나 거기서 기도하시더라.", "web": "Early in the morning, while it was still dark, he rose up and went out, and departed into a deserted place, and prayed there."}}, {"id": 1295, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT의 본", "친밀한 교제를 가진 모세"], "book": "출애굽기", "chap": 33, "verse": "11", "ref": "출애굽기 33:11", "texts": {"krv": "사람이 그 친구와 이야기함 같이 여호와께서는 모세와 대면하여 말씀하시며 모세는 진으로 돌아오나 그 수종자 눈의 아들 청년 여호수아는 회막을 떠나지 아니하니라", "kkjv": "주께서는 마치 사람이 자기 친구와 이야기하듯 모세와 얼굴을 마주 대하여 말씀하시니라. 그는 다시 진영으로 돌아왔으나 그의 종 곧 눈의 아들 청년 여호수아는 성막 밖으로 떠나지 아니하였더라.", "web": "Yahweh spoke to Moses face to face, as a man speaks to his friend. He turned again into the camp, but his servant Joshua, the son of Nun, a young man, didn’t depart from the Tent."}}, {"id": 1296, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT의 본", "생명보다 귀히 여긴 다니엘"], "book": "다니엘", "chap": 6, "verse": "10", "ref": "다니엘 6:10", "texts": {"krv": "다니엘이 이 조서에 어인이 찍힌 것을 알고도 자기 집에 돌아가서는 그 방의 예루살렘으로 향하여 열린 창에서 전에 행하던 대로 하루 세 번씩 무릎을 꿇고 기도하며 그 하나님께 감사하였더라", "kkjv": "¶그런데 다니엘은 그 조서에 도장이 찍힌 것을 알고도 자기 집에 들어가 자기 방에서 예루살렘을 향하여 창문을 열고 전에 하던 대로 하루에 세 번씩 무릎을 꿇고 기도하며 자기 하나님 앞에서 감사를 드리더라.", "web": "When Daniel knew that the writing was signed, he went into his house (now his windows were open in his room toward Jerusalem) and he kneeled on his knees three times a day, and prayed, and gave thanks before his God, as he did before."}}, {"id": 1297, "coll": "DEP 242구절", "sub": ["경건의 시간", "QT의 본", "주님과 함께 함으로 깨달음을 얻은 제자들"], "book": "마가복음", "chap": 4, "verse": "34", "ref": "마가복음 4:34", "texts": {"krv": "비유가 아니면 말씀하지 아니하시고 다만 혼자 계실 때에 그 제자들에게 모든 것을 해석하시더라", "kkjv": "비유가 없이는 그들에게 말씀하지 아니하시고 그들이 따로 있을 때에 모든 것을 풀어 자기 제자들에게 설명해 주시더라.", "web": "Without a parable he didn’t speak to them; but privately to his own disciples he explained everything."}}, {"id": 1298, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 권위", "하나님의 감동으로 된 말씀"], "book": "디모데후서", "chap": 3, "verse": "16", "ref": "디모데후서 3:16", "texts": {"krv": "모든 성경은 하나님의 감동으로 된 것으로 교훈과 책망과 바르게 함과 의로 교육하기에 유익하니", "kkjv": "모든 성경 기록은 하나님의 영감으로 주신 것으로 교리와 책망과 바로잡음과 의로 교육하기에 유익하니", "web": "Every Scripture is God-breathed and profitable for teaching, for reproof, for correction, and for instruction in righteousness,"}}, {"id": 1299, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 권위", "하나님의 감동으로 된 말씀"], "book": "베드로후서", "chap": 1, "verse": "21", "ref": "베드로후서 1:21", "texts": {"krv": "예언은 언제든지 사람의 뜻으로 낸 것이 아니요 오직 성령의 감동하심을 입은 사람들이 하나님께 받아 말한 것임이니라", "kkjv": "대언은 옛적에 사람의 뜻으로 말미암아 나오지 아니하였고 오직 하나님의 거룩한 사람들은 성령님께서 자기들을 움직이시는 대로 말하였느니라.", "web": "For no prophecy ever came by the will of man: but holy men of God spoke, being moved by the Holy Spirit."}}, {"id": 1300, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 권위", "영원 불변한 말씀"], "book": "마태복음", "chap": 24, "verse": "35", "ref": "마태복음 24:35", "texts": {"krv": "천지는 없어지겠으나 내 말은 없어지지 아니하리라", "kkjv": "하늘과 땅은 없어지겠으나 내 말들은 없어지지 아니하리라.", "web": "Heaven and earth will pass away, but my words will not pass away."}}, {"id": 1301, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 권위", "영원 불변한 말씀"], "book": "베드로전서", "chap": 1, "verse": "24,25", "ref": "베드로전서 1:24,25", "texts": {"krv": "그러므로 모든 육체는 풀과 같고 그 모든 영광이 풀의 꽃과 같으니 풀은 마르고 꽃은 떨어지되 오직 주의 말씀은 세세토록 있도다 하였으니 너희에게 전한 복음이 곧 이 말씀이니라", "kkjv": "모든 육체는 풀과 같고 사람의 모든 영광은 풀의 꽃과 같으니라. 풀은 마르고 그것의 꽃은 떨어지되 오직 주의 말씀은 영원토록 지속되나니 복음으로 너희에게 선포된 말씀이 이 말씀이니라.", "web": "For,  “All flesh is like grass, and all of man’s glory like the flower in the grass. The grass withers, and its flower falls; but the Lord’s word endures forever.”    This is the word of Good News which was preached to you."}}, {"id": 1302, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 권위", "진리의 말씀"], "book": "요한복음", "chap": 17, "verse": "17", "ref": "요한복음 17:17", "texts": {"krv": "저희를 진리로 거룩하게 하옵소서 아버지의 말씀은 진리니이다", "kkjv": "아버지의 진리로 그들을 거룩히 구별하옵소서. 아버지의 말씀은 진리이니이다.", "web": "Sanctify them in your truth. Your word is truth."}}, {"id": 1303, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 권위", "진리의 말씀"], "book": "사무엘하", "chap": 7, "verse": "28", "ref": "사무엘하 7:28", "texts": {"krv": "주 여호와여 오직 주는 하나님이시며 말씀이 참되시니이다 주께서 이 좋은 것으로 종에게 허락하셨사오니", "kkjv": "이제, 오 주 하나님이여, 주는 그 하나님이시며 주의 말씀들은 참되나이다. 주께서 이 선한 일을 주의 종에게 약속하셨사오니", "web": "“Now, O Lord Yahweh, you are God, and your words are truth, and you have promised this good thing to your servant."}}, {"id": 1304, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 권위", "능력의 말씀"], "book": "예레미야", "chap": 23, "verse": "29", "ref": "예레미야 23:29", "texts": {"krv": "나 여호와가 말하노라 내 말이 불같지 아니하냐 반석을 쳐서 부스러뜨리는 방망이 같지 아니하냐", "kkjv": "주가 말하노라. 내 말이 불 같지 아니하냐? 바위를 산산조각 부수는 쇠망치 같지 아니하냐?", "web": "Isn’t my word like fire? says Yahweh; and like a hammer that breaks the rock in pieces?"}}, {"id": 1305, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 권위", "능력의 말씀"], "book": "디모데후서", "chap": 2, "verse": "9", "ref": "디모데후서 2:9", "texts": {"krv": "복음을 인하여 내가 죄인과 같이 매이는 데까지 고난을 받았으나 하나님의 말씀은 매이지 아니하니라", "kkjv": "이 복음으로 인하여 내가 악을 행하는 자처럼 매이는 데까지 고난을 당하나 하나님의 말씀은 매이지 아니하느니라.", "web": "in which I suffer hardship to the point of chains as a criminal. But God’s word isn’t chained."}}, {"id": 1306, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 권위", "예수님도 말씀에 권위를 두심"], "book": "마태복음", "chap": 4, "verse": "4", "ref": "마태복음 4:4", "texts": {"krv": "예수께서 대답하여 가라사대 기록되었으되 사람이 떡으로만 살 것이 아니요 하나님의 입으로 나오는 모든 말씀으로 살 것이라 하였느니라 하시니", "kkjv": "그분께서 응답하여 이르시되, 기록된바, 사람이 빵으로만 살 것이 아니요, 하나님의 입에서 나오는 모든 말씀으로 살 것이라, 하였느니라, 하시더라.", "web": "But he answered, “It is written, ‘Man shall not live by bread alone, but by every word that proceeds out of the mouth of God.’”"}}, {"id": 1307, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 권위", "예수님도 말씀에 권위를 두심"], "book": "누가복음", "chap": 24, "verse": "27", "ref": "누가복음 24:27", "texts": {"krv": "이에 모세와 및 모든 선지자의 글로 시작하여 모든 성경에 쓴 바 자기에 관한 것을 자세히 설명하시니라", "kkjv": "모세와 모든 대언자들의 글에서 시작하여 모든 성경 기록들에서 자기에 관한 것들을 그들에게 풀어 설명해 주시니라.", "web": "Beginning from Moses and from all the prophets, he explained to them in all the Scriptures the things concerning himself."}}, {"id": 1308, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 가치", "거듭나게 함"], "book": "베드로전서", "chap": 1, "verse": "23", "ref": "베드로전서 1:23", "texts": {"krv": "너희가 거듭난 것이 썩어질 씨로 된 것이 아니요 썩지 아니할 씨로 된 것이니 하나님의 살아 있고 항상 있는 말씀으로 되었느니라", "kkjv": "너희가 다시 태어난 것은 썩을 씨에서 난 것이 아니요 썩지 아니할 씨에서 난 것이니 살아 있고 영원히 거하는 하나님의 말씀으로 된 것이니라.", "web": "having been born again, not of corruptible seed, but of incorruptible, through the word of God, which lives and remains forever."}}, {"id": 1309, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 가치", "거듭나게 함"], "book": "야고보서", "chap": 1, "verse": "18", "ref": "야고보서 1:18", "texts": {"krv": "그가 그 조물 중에 우리로 한 첫 열매가 되게 하시려고 자기의 뜻을 좇아 진리의 말씀으로 우리를 낳으셨느니라", "kkjv": "그분께서 자신의 뜻에 따라 진리의 말씀으로 우리를 낳으셨으니 이것은 우리가 그분의 창조물 중의 첫 열매 종류가 되게 하려 하심이라.", "web": "Of his own will he gave birth to us by the word of truth, that we should be a kind of first fruits of his creatures."}}, {"id": 1310, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 가치", "성장하게 함"], "book": "베드로전서", "chap": 2, "verse": "2", "ref": "베드로전서 2:2", "texts": {"krv": "갓난 아이들 같이 순전하고 신령한 젖을 사모하라 이는 이로 말미암아 너희로 구원에 이르도록 자라게 하려 함이라", "kkjv": "새로 태어난 아기들로서 말씀의 순수한 젖을 사모하라. 이것은 너희가 그 젖으로 말미암아 성장하게 하려 함이라.", "web": "as newborn babies, long for the pure milk of the Word, that with it you may grow,"}}, {"id": 1311, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 가치", "성장하게 함"], "book": "사도행전", "chap": 20, "verse": "32", "ref": "사도행전 20:32", "texts": {"krv": "지금 내가 너희를 주와 및 그 은혜의 말씀께 부탁하노니 그 말씀이 너희를 능히 든든히 세우사 거룩케 하심을 입은 모든 자 가운데 기업이 있게 하시리라", "kkjv": "이제 형제들아, 내가 너희를 하나님과 그분의 은혜의 말씀에 맡기노니 이 말씀이 너희를 능히 든든히 세워 거룩히 구별된 모든 자들 가운데서 너희에게 상속 유업을 주리라.", "web": "Now, brothers, I entrust you to God, and to the word of his grace, which is able to build up, and to give you the inheritance among all those who are sanctified."}}, {"id": 1312, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 가치", "인도해 주심"], "book": "시편", "chap": 119, "verse": "105", "ref": "시편 119:105", "texts": {"krv": "주의 말씀은 내 발에 등이요 내 길에 빛이니이다", "kkjv": "주의 말씀은 내 발에 등불이요, 내 길에 빛이니이다.", "web": "Your word is a lamp to my feet, and a light for my path."}}, {"id": 1313, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 가치", "인도해 주심"], "book": "잠언", "chap": 6, "verse": "22,23", "ref": "잠언 6:22,23", "texts": {"krv": "그것이 너의 다닐 때에 너를 인도하며 너의 잘 때에 너를 보호하며 너의 깰 때에 너로 더불어 말하리니 대저 명령은 등불이요 법은 빛이요 훈계의 책망은 곧 생명의 길이라", "kkjv": "그것이 네가 다닐 때에 너를 인도하고 네가 잘 때에 너를 보호하며 네가 깰 때에 너와 말하리니 그 명령은 등불이요, 그 법은 빛이며 훈계하는 책망들은 생명의 길이니라.", "web": "When you walk, it will lead you. When you sleep, it will watch over you. When you awake, it will talk with you. For the commandment is a lamp, and the law is light. Reproofs of instruction are the way of life,"}}, {"id": 1314, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 가치", "문제를 해결해 주심"], "book": "시편", "chap": 107, "verse": "20", "ref": "시편 107:20", "texts": {"krv": "저가 그 말씀을 보내어 저희를 고치사 위경에서 건지시는도다", "kkjv": "자신의 말씀을 보내어 그들을 고치시며 멸망들에서 그들을 건지셨도다.", "web": "He sends his word, and heals them, and delivers them from their graves."}}, {"id": 1315, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 가치", "문제를 해결해 주심"], "book": "마태복음", "chap": 8, "verse": "8", "ref": "마태복음 8:8", "texts": {"krv": "백부장이 대답하여 가로되 주여 내 집에 들어오심을 나는 감당치 못하겠사오니 다만 말씀으로만 하옵소서 그러면 내 하인이 낫겠삽나이다", "kkjv": "백부장이 응답하여 이르되, 주여, 주께서 내 지붕 아래로 오심을 내가 감당할 자격이 없사온즉 오직 말씀만 하옵소서. 그러면 내 종이 낫겠나이다.", "web": "The centurion answered, “Lord, I’m not worthy for you to come under my roof. Just say the word, and my servant will be healed."}}, {"id": 1316, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 가치", "기쁨과 즐거움이 됨"], "book": "예레미야", "chap": 15, "verse": "16", "ref": "예레미야 15:16", "texts": {"krv": "만군의 하나님 여호와시여 나는 주의 이름으로 일컬음을 받는 자라 내가 주의 말씀을 얻어 먹었사오니 주의 말씀은 내게 기쁨과 내 마음의 즐거움이오나", "kkjv": "내가 주의 말씀들을 발견하고 그것들을 먹으매 주의 말씀이 내게 기쁨과 마음의 즐거움이 되었사오니, 오 주 만군의 하나님이여, 나는 주의 이름으로 불리나이다.", "web": "Your words were found, and I ate them; and your words were to me a joy and the rejoicing of my heart: for I am called by your name, Yahweh, God of Armies."}}, {"id": 1317, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 가치", "기쁨과 즐거움이 됨"], "book": "시편", "chap": 119, "verse": "111", "ref": "시편 119:111", "texts": {"krv": "주의 증거로 내가 영원히 기업을 삼았사오니 이는 내 마음의 즐거움이 됨이니이다", "kkjv": "내가 주의 증언들을 영원히 유산으로 삼았사오니 그것들은 내 마음의 기쁨이니이다.", "web": "I have taken your testimonies as a heritage forever, for they are the joy of my heart."}}, {"id": 1318, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 가치", "영적 무기가 됨"], "book": "에베소서", "chap": 6, "verse": "17", "ref": "에베소서 6:17", "texts": {"krv": "구원의 투구와 성령의 검 곧 하나님의 말씀을 가지라", "kkjv": "구원의 투구와 성령의 검 곧 하나님의 말씀을 취하라.", "web": "And take the helmet of salvation, and the sword of the Spirit, which is the word of God;"}}, {"id": 1319, "coll": "DEP 242구절", "sub": ["말씀", "말씀의 가치", "영적 무기가 됨"], "book": "히브리서", "chap": 4, "verse": "12", "ref": "히브리서 4:12", "texts": {"krv": "하나님의 말씀은 살았고 운동력이 있어 죄우에 날선 어떤 검보다도 예리하여 혼과 영과 및 관절과 골수를 찔러 쪼개기까지 하며 또 마음의 생각과 뜻을 감찰하나니", "kkjv": "하나님의 말씀은 살아 있고 권능이 있으며 양날 달린 어떤 검보다도 예리하여 혼과 영과 및 관절과 골수를 찔러 둘로 나누기까지 하고 또 마음의 생각과 의도를 분별하는 분이시니", "web": "For the word of God is living, and active, and sharper than any two-edged sword, and piercing even to the dividing of soul and spirit, of both joints and marrow, and is able to discern the thoughts and intentions of the heart."}}, {"id": 1320, "coll": "DEP 242구절", "sub": ["말씀", "말씀에 대한 태도", "날마다 말씀을 상고함"], "book": "사도행전", "chap": 17, "verse": "11", "ref": "사도행전 17:11", "texts": {"krv": "베뢰아 사람은 데살로니가에 있는 사람보다 더 신사적이어서 간절한 마음으로 말씀을 받고 이것이 그러한가 하여 날마다 성경을 상고하므로", "kkjv": "이들은 데살로니가에 있던 자들보다 더 고귀하여 온전히 준비된 마음으로 말씀을 받아들이고 그것들이 그러한가 하여 날마다 성경 기록들을 탐구하므로", "web": "Now these were more noble than those in Thessalonica, in that they received the word with all readiness of the mind, examining the Scriptures daily to see whether these things were so."}}, {"id": 1321, "coll": "DEP 242구절", "sub": ["말씀", "말씀에 대한 태도", "종일 말씀을 묵상함"], "book": "시편", "chap": 119, "verse": "97", "ref": "시편 119:97", "texts": {"krv": "내가 주의 법을 어찌 그리 사랑하는지요 내가 그것을 종일 묵상하나이다", "kkjv": "오 내가 주의 법을 얼마나 사랑하는지요! 그 법이 종일토록 나의 묵상이 되나이다.", "web": "How I love your law! It is my meditation all day."}}, {"id": 1322, "coll": "DEP 242구절", "sub": ["말씀", "말씀에 대한 태도", "말씀을 행하고 가르침"], "book": "에스라", "chap": 7, "verse": "10", "ref": "에스라 7:10", "texts": {"krv": "에스라가 여호와의 율법을 연구하여 준행하며 율례와 규례를 이스라엘에게 가르치기로 결심하였었더라", "kkjv": "이는 에스라가 주의 율법을 구하고 그것을 행하며 이스라엘에서 법규와 판단의 법도를 가르치려고 자기 마음을 예비하였기 때문이더라.", "web": "For Ezra had set his heart to seek Yahweh’s law, and to do it, and to teach in Israel statutes and ordinances."}}, {"id": 1323, "coll": "DEP 242구절", "sub": ["말씀", "말씀에 대한 태도", "일정한 음식보다 말씀을 더 귀히 여김"], "book": "욥기", "chap": 23, "verse": "12", "ref": "욥기 23:12", "texts": {"krv": "내가 그의 입술의 명령을 어기지 아니하고 일정한 음식보다 그 입의 말씀을 귀히 여겼구나", "kkjv": "내가 그분의 입술의 명령에서 돌이키지 아니하고 내게 필요한 음식보다 그분의 입의 말씀들을 더 귀히 여겼도다.", "web": "I haven’t gone back from the commandment of his lips. I have treasured up the words of his mouth more than my necessary food."}}, {"id": 1324, "coll": "DEP 242구절", "sub": ["말씀", "말씀에 대한 태도", "말씀을 믿고 순종함"], "book": "누가복음", "chap": 5, "verse": "5,6", "ref": "누가복음 5:5,6", "texts": {"krv": "시몬이 대답하여 가로되 선생이여 우리들이 밤이 맞도록 수고를 하였으되 얻은 것이 없지마는 말씀에 의지하여 내가 그물을 내리리이다 하고 그리한즉 고기를 에운 것이 심히 많아 그물이 찢어지는지라", "kkjv": "시몬이 응답하여 그분께 이르되, 선생님이여, 우리가 밤새도록 수고하였어도 아무것도 잡지 못하였으나 그럼에도 불구하고 선생님의 말씀에 따라 내가 그물을 내리리이다, 하고 그들이 이 일을 행하니 심히 많은 물고기가 잡혀 그들의 그물이 찢어지니라.", "web": "Simon answered him, “Master, we worked all night, and took nothing; but at your word I will let down the net.” When they had done this, they caught a great multitude of fish, and their net was breaking."}}, {"id": 1325, "coll": "DEP 242구절", "sub": ["말씀", "말씀 섭취의 방법", "듣기"], "book": "로마서", "chap": 10, "verse": "17", "ref": "로마서 10:17", "texts": {"krv": "그러므로 믿음은 들음에서 나며 들음은 그리스도의 말씀으로 말미암았느니라", "kkjv": "그런즉 이와 같이 믿음은 들음에 의해 오며 들음은 하나님의 말씀에 의해 오느니라.", "web": "So faith comes by hearing, and hearing by the word of God."}}, {"id": 1326, "coll": "DEP 242구절", "sub": ["말씀", "말씀 섭취의 방법", "듣기"], "book": "누가복음", "chap": 11, "verse": "28", "ref": "누가복음 11:28", "texts": {"krv": "예수께서 가라사대 오히려 하나님의 말씀을 듣고 지키는 자가 복이 있느니라 하시니라", "kkjv": "그분께서 이르시되, 그러하다. 그러나 하나님의 말씀을 듣고 그것을 지키는 자들이 복이 있느니라, 하시니라.", "web": "But he said, “On the contrary, blessed are those who hear the word of God, and keep it.”"}}, {"id": 1327, "coll": "DEP 242구절", "sub": ["말씀", "말씀 섭취의 방법", "읽기"], "book": "요한계시록", "chap": 1, "verse": "3", "ref": "요한계시록 1:3", "texts": {"krv": "이 예언의 말씀을 읽는 자와 듣는 자들과 그 가운데 기록한 것을 지키는 자들이 복이 있나니 때가 가까움이라", "kkjv": "이 대언의 말씀들을 읽는 자와 듣고 그 안에 기록된 그것들을 지키는 자들은 복이 있나니 이는 때가 가깝기 때문이라.", "web": "Blessed is he who reads and those who hear the words of the prophecy, and keep the things that are written in it, for the time is at hand."}}, {"id": 1328, "coll": "DEP 242구절", "sub": ["말씀", "말씀 섭취의 방법", "읽기"], "book": "신명기", "chap": 17, "verse": "19", "ref": "신명기 17:19", "texts": {"krv": "평생에 자기 옆에 두고 읽어서 그 하나님 여호와 경외하기를 배우며 이 율법의 모든 말과 이 규례를 지켜 행할 것이라", "kkjv": "평생토록 자기 곁에 두고 그 안의 것을 읽어서 주 자기 하나님 두려워하기를 배우며 이 율법의 모든 말과 이 법규를 지키고 행할 것이니라.", "web": "It shall be with him, and he shall read from it all the days of his life; that he may learn to fear Yahweh his God, to keep all the words of this law and these statutes, to do them;"}}, {"id": 1329, "coll": "DEP 242구절", "sub": ["말씀", "말씀 섭취의 방법", "공부"], "book": "사도행전", "chap": 17, "verse": "11", "ref": "사도행전 17:11", "texts": {"krv": "베뢰아 사람은 데살로니가에 있는 사람보다 더 신사적이어서 간절한 마음으로 말씀을 받고 이것이 그러한가 하여 날마다 성경을 상고하므로", "kkjv": "이들은 데살로니가에 있던 자들보다 더 고귀하여 온전히 준비된 마음으로 말씀을 받아들이고 그것들이 그러한가 하여 날마다 성경 기록들을 탐구하므로", "web": "Now these were more noble than those in Thessalonica, in that they received the word with all readiness of the mind, examining the Scriptures daily to see whether these things were so."}}, {"id": 1330, "coll": "DEP 242구절", "sub": ["말씀", "말씀 섭취의 방법", "공부"], "book": "디모데후서", "chap": 2, "verse": "15", "ref": "디모데후서 2:15", "texts": {"krv": "네가 진리의 말씀을 옳게 분변하여 부끄러울 것이 없는 일꾼으로 인정된 자로 자신을 하나님 앞에 드리기를 힘쓰라", "kkjv": "너는 진리의 말씀을 바르게 나누어 네 자신을 하나님께 인정받은 자로, 부끄러울 것이 없는 일꾼으로 나타내도록 연구하라.", "web": "Give diligence to present yourself approved by God, a workman who doesn’t need to be ashamed, properly handling the Word of Truth."}}, {"id": 1331, "coll": "DEP 242구절", "sub": ["말씀", "말씀 섭취의 방법", "암송"], "book": "신명기", "chap": 6, "verse": "6", "ref": "신명기 6:6", "texts": {"krv": "오늘날 내가 네게 명하는 이 말씀을 너는 마음에 새기고", "kkjv": "이 날 내가 네게 명령하는 이 말씀들을 네 마음속에 두고", "web": "These words, which I command you this day, shall be on your heart;"}}, {"id": 1332, "coll": "DEP 242구절", "sub": ["말씀", "말씀 섭취의 방법", "암송"], "book": "잠언", "chap": 7, "verse": "1-3", "ref": "잠언 7:1-3", "texts": {"krv": "내 아들아 내 말을 지키며 내 명령을 네게 간직하라 내 명령을 지켜서 살며 내 법을 네 눈동자처럼 지키라 이것을 네 손가락에 매며 이것을 네 마음판에 새기라", "kkjv": "내 아들아, 내 말들을 지키며 내 명령들을 네게 쌓아 두라. 내 명령들을 지켜서 살며 내 법을 네 눈동자처럼 지키라. 그것들을 네 손가락에 묶으며 네 마음 판에 기록하라.", "web": "My son, keep my words. Lay up my commandments within you. Keep my commandments and live! Guard my teaching as the apple of your eye. Bind them on your fingers. Write them on the tablet of your heart."}}, {"id": 1333, "coll": "DEP 242구절", "sub": ["말씀", "말씀 섭취의 방법", "묵상"], "book": "시편", "chap": 1, "verse": "1,2", "ref": "시편 1:1,2", "texts": {"krv": "복 있는 사람은 악인의 꾀를 좇지 아니하며 죄인의 길에 서지 아니하며 오만한 자의 자리에 앉지 아니하고 오직 여호와의 율법을 즐거워하여 그 율법을 주야로 묵상하는 자로다", "kkjv": "경건치 아니한 자들의 계획대로 걷지 아니하고 죄인들의 길에 서지 아니하며 조롱하는 자들의 자리에 앉지 아니하는 사람은 복이 있나니 그는 주의 율법을 기뻐하며 그분의 율법을 밤낮으로 묵상하는도다.", "web": "Blessed is the man who doesn’t walk in the counsel of the wicked, nor stand on the path of sinners, nor sit in the seat of scoffers; but his delight is in Yahweh’s law. On his law he meditates day and night."}}, {"id": 1334, "coll": "DEP 242구절", "sub": ["말씀", "말씀 섭취의 방법", "묵상"], "book": "여호수아", "chap": 1, "verse": "8", "ref": "여호수아 1:8", "texts": {"krv": "이 율법책을 네 입에서 떠나지 말게 하며 주야로 그것을 묵상하여 그 가운데 기록한대로 다 지켜 행하라 그리하면 네 길이 평탄하게 될 것이라 네가 형통하리라", "kkjv": "너는 이 율법 책을 네 입에서 떠나지 말게 하며 밤낮으로 그것을 묵상하여 그 안에 기록된 모든 것에 따라 지켜 행하라. 그리하면 네가 네 길을 형통하게 하며 또한 크게 성공하리라.", "web": "This book of the law shall not depart out of your mouth, but you shall meditate on it day and night, that you may observe to do according to all that is written therein: for then you shall make your way prosperous, and then you shall have good success."}}, {"id": 1335, "coll": "DEP 242구절", "sub": ["기도", "기도의 명령", "쉬지 말고 기도할 것"], "book": "데살로니가전서", "chap": 5, "verse": "17", "ref": "데살로니가전서 5:17", "texts": {"krv": "쉬지 말고 기도하라", "kkjv": "쉬지 말고 기도하라.", "web": "Pray without ceasing."}}, {"id": 1336, "coll": "DEP 242구절", "sub": ["기도", "기도의 명령", "기도를 힘쓸 것"], "book": "골로새서", "chap": 4, "verse": "2", "ref": "골로새서 4:2", "texts": {"krv": "기도를 항상 힘쓰고 기도에 감사함으로 깨어 있으라", "kkjv": "항상 기도하고 기도 중에 감사를 드리며 깨어 있으라.", "web": "Continue steadfastly in prayer, watching therein with thanksgiving;"}}, {"id": 1337, "coll": "DEP 242구절", "sub": ["기도", "기도의 명령", "깨어 기도할 것"], "book": "베드로전서", "chap": 4, "verse": "7", "ref": "베드로전서 4:7", "texts": {"krv": "만물의 마지막이 가까웠으니 그러므로 너희는 정신을 차리고 근신하여 기도하라", "kkjv": "오직 모든 것의 끝이 가까이 왔으니 그러므로 너희는 정신을 차리고 깨어 기도하라.", "web": "But the end of all things is near. Therefore be of sound mind, self-controlled, and sober in prayer."}}, {"id": 1338, "coll": "DEP 242구절", "sub": ["기도", "기도의 명령", "모든 사람을 위하여 기도할 것"], "book": "디모데전서", "chap": 2, "verse": "1,2", "ref": "디모데전서 2:1,2", "texts": {"krv": "그러므로 내가 첫째로 권하노니 모든 사람을 위하여 간구와 기도와 도고와 감사를 하되 임금들과 높은 지위에 있는 모든 사람을 위하여 하라 이는 우리가 모든 경건과 단정한 중에 고요하고 평안한 생활을 하려 함이니라", "kkjv": "그러므로 내가 권면하노니 무엇보다 먼저 모든 사람을 위하여 간구와 기도와 중보와 감사를 드리되 왕들과 권위를 가진 모든 사람을 위하여 하라. 이것은 우리가 전적으로 하나님을 따르며 정직한 가운데 조용하고 평화로운 삶을 살고자 함이라.", "web": "I exhort therefore, first of all, that petitions, prayers, intercessions, and givings of thanks, be made for all men: for kings and all who are in high places; that we may lead a tranquil and quiet life in all godliness and reverence."}}, {"id": 1339, "coll": "DEP 242구절", "sub": ["기도", "기도의 약속과 축복", "응답의 약속"], "book": "요한복음", "chap": 14, "verse": "13,14", "ref": "요한복음 14:13,14", "texts": {"krv": "너희가 내 이름으로 무엇을 구하든지 내가 시행하리니 이는 아버지로 하여금 아들을 인하여 영광을 얻으시게 하려 함이라 내 이름으로 무엇이든지 내게 구하면 내가 시행하리라", "kkjv": "너희가 내 이름으로 무엇을 구하든지 내가 그것을 행하리니 이것은 아버지께서 아들 안에서 영광을 받게 하려 함이라. 너희가 내 이름으로 무엇이든지 구하면 내가 그것을 행하리라.", "web": "Whatever you will ask in my name, that will I do, that the Father may be glorified in the Son. If you will ask anything in my name, I will do it."}}, {"id": 1340, "coll": "DEP 242구절", "sub": ["기도", "기도의 약속과 축복", "넘치는 응답"], "book": "에베소서", "chap": 3, "verse": "20", "ref": "에베소서 3:20", "texts": {"krv": "우리 가운데서 역사하시는 능력대로 우리의 온갖 구하는 것이나 생각하는 것에 더 넘치도록 능히 하실 이에게", "kkjv": "이제 우리 안에서 일하는 권능에 따라 우리가 구하거나 생각하는 모든 것 이상으로 심히 넘치도록 능히 행하실 분에게", "web": "Now to him who is able to do exceedingly abundantly above all that we ask or think, according to the power that works in us,"}}, {"id": 1341, "coll": "DEP 242구절", "sub": ["기도", "기도의 약속과 축복", "하나님의 뜻을 알게 됨"], "book": "예레미야", "chap": 33, "verse": "3", "ref": "예레미야 33:3", "texts": {"krv": "너는 내게 부르짖으라 내가 네게 응답하겠고 네가 알지 못하는 크고 비밀한 일을 네게 보이리라", "kkjv": "나를 부르라. 그리하면 내가 네게 응답하고 네가 알지 못하는 크고 능력 있는 일들을 네게 보이리라.", "web": "Call to me, and I will answer you, and will show you great things, and difficult, which you don’t know."}}, {"id": 1342, "coll": "DEP 242구절", "sub": ["기도", "기도의 약속과 축복", "지혜를 주심"], "book": "야고보서", "chap": 1, "verse": "5", "ref": "야고보서 1:5", "texts": {"krv": "너희 중에 누구든지 지혜가 부족하거든 모든 사람에게 후히 주시고 꾸짖지 아니하시는 하나님께 구하라 그리하면 주시리라", "kkjv": "너희 중에 어떤 사람이 지혜가 부족하거든 모든 사람에게 너그러이 주시고 꾸짖지 아니하시는 하나님께 구하라. 그리하면 그것을 그에게 주시리라.", "web": "But if any of you lacks wisdom, let him ask of God, who gives to all liberally and without reproach; and it will be given to him."}}, {"id": 1343, "coll": "DEP 242구절", "sub": ["기도", "기도의 약속과 축복", "두려움에서 건져 주심"], "book": "시편", "chap": 34, "verse": "4", "ref": "시편 34:4", "texts": {"krv": "내가 여호와께 구하매 내게 응답하시고 내 모든 두려움에서 나를 건지셨도다", "kkjv": "내가 주를 찾으매 그분께서 내 말을 들으시고 내 모든 두려움에서 나를 건지셨도다.", "web": "I sought Yahweh, and he answered me, and delivered me from all my fears."}}, {"id": 1344, "coll": "DEP 242구절", "sub": ["기도", "기도의 약속과 축복", "환난에서 건져 주심"], "book": "시편", "chap": 50, "verse": "15", "ref": "시편 50:15", "texts": {"krv": "환난 날에 나를 부르라 내가 너를 건지리니 네가 나를 영화롭게 하리로다", "kkjv": "고난의 날에 나를 부르라. 내가 너를 건지리니 네가 나를 영화롭게 하리로다.", "web": "Call on me in the day of trouble. I will deliver you, and you will honor me.”"}}, {"id": 1345, "coll": "DEP 242구절", "sub": ["기도", "기도의 약속과 축복", "담대함을 주심"], "book": "사도행전", "chap": 4, "verse": "31", "ref": "사도행전 4:31", "texts": {"krv": "빌기를 다하매 모인 곳이 진동하더니 무리가 다 성령이 충만하여 담대히 하나님의 말씀을 전하니라", "kkjv": "¶그들이 기도하기를 마치매 그들이 함께 모인 곳이 흔들리더니 그들이 다 성령님으로 충만하여 담대히 하나님의 말씀을 말하니라.", "web": "When they had prayed, the place was shaken where they were gathered together. They were all filled with the Holy Spirit, and they spoke the word of God with boldness."}}, {"id": 1346, "coll": "DEP 242구절", "sub": ["기도", "기도의 약속과 축복", "전도의 기회를 주심"], "book": "골로새서", "chap": 4, "verse": "3", "ref": "골로새서 4:3", "texts": {"krv": "또한 우리를 위하여 기도하되 하나님이 전도할 문을 우리에게 열어주사 그리스도의 비밀을 말하게 하시기를 구하라 내가 이것을 인하여 매임을 당하였노라", "kkjv": "아울러 또한 우리를 위해 기도하되 하나님께서 말할 수 있는 문을 우리에게 열어 주사 그리스도의 신비를 말하게 하실 것을 구하라. 내가 또한 그것을 위해 결박당하였나니", "web": "praying together for us also, that God may open to us a door for the word, to speak the mystery of Christ, for which I am also in bonds;"}}, {"id": 1347, "coll": "DEP 242구절", "sub": ["기도", "응답받는 기도의 조건", "예수님의 이름으로 기도할 것"], "book": "요한복음", "chap": 16, "verse": "24", "ref": "요한복음 16:24", "texts": {"krv": "지금까지는 너희가 내 이름으로 아무 것도 구하지 아니하였으나 구하라 그리하면 받으리니 너희 기쁨이 충만하리라", "kkjv": "지금까지는 너희가 내 이름으로 아무것도 구하지 아니하였으나 구하라. 그리하면 너희가 받으리니 이로써 너희 기쁨이 충만하리라.", "web": "Until now, you have asked nothing in my name. Ask, and you will receive, that your joy may be made full."}}, {"id": 1348, "coll": "DEP 242구절", "sub": ["기도", "응답받는 기도의 조건", "믿음으로 기도할 것"], "book": "마태복음", "chap": 21, "verse": "22", "ref": "마태복음 21:22", "texts": {"krv": "너희가 기도할 때에 무엇이든지 믿고 구하는 것은 다 받으리라 하시니라", "kkjv": "너희가 믿고 기도할 때에 무엇을 구하든지 모든 것을 받으리라, 하시니라.", "web": "All things, whatever you ask in prayer, believing, you will receive.”"}}, {"id": 1349, "coll": "DEP 242구절", "sub": ["기도", "응답받는 기도의 조건", "성령을 의뢰함으로 기도할 것"], "book": "에베소서", "chap": 6, "verse": "18", "ref": "에베소서 6:18", "texts": {"krv": "모든 기도와 간구로 하되 무시로 성령 안에서 기도하고 이를 위하여 깨어 구하기를 항상 힘쓰며 여러 성도를 위하여 구하고", "kkjv": "모든 기도와 간구로 성령 안에서 항상 기도하되 모든 성도를 위해 모든 인내와 간구로 그 일에 깨어 있고", "web": "with all prayer and requests, praying at all times in the Spirit, and being watchful to this end in all perseverance and requests for all the saints:"}}, {"id": 1350, "coll": "DEP 242구절", "sub": ["기도", "응답받는 기도의 조건", "하나님의 뜻대로 기도할 것"], "book": "요한일서", "chap": 5, "verse": "14-15", "ref": "요한일서 5:14-15", "texts": {"krv": "그를 향하여 우리의 가진 바 담대한 것이 이것이니 그의 뜻대로 무엇을 구하면 들으심이라 우리가 무엇이든지 구하는 바를 들으시는 줄을 안즉 우리가 그에게 구한 그것을 얻은 줄을 또한 아느니라", "kkjv": "그분 안에서 우리가 가진 확신은 이것이니 곧 우리가 그분의 뜻대로 무엇이든 구하면 그분께서 우리 말을 들으신다는 것이라. 우리가 무엇을 구하든지 그분께서 우리 말을 들으시는 줄 우리가 알진대 우리가 그분께 구하여 청원한 것들을 얻는 줄 우리가 아느니라.", "web": "This is the boldness which we have toward him, that, if we ask anything according to his will, he listens to us. And if we know that he listens to us, whatever we ask, we know that we have the petitions which we have asked of him."}}, {"id": 1351, "coll": "DEP 242구절", "sub": ["기도", "응답받는 기도의 조건", "죄를 자백하고 버릴 것"], "book": "시편", "chap": 66, "verse": "18", "ref": "시편 66:18", "texts": {"krv": "내가 내 마음에 죄악을 품으면 주께서 듣지 아니하시리라", "kkjv": "내가 마음속으로 불법에 관심을 두면 주께서 내 말을 듣지 아니하시리라.", "web": "If I cherished sin in my heart, the Lord wouldn’t have listened."}}, {"id": 1352, "coll": "DEP 242구절", "sub": ["기도", "응답받는 기도의 조건", "순종할 것"], "book": "요한일서", "chap": 3, "verse": "22", "ref": "요한일서 3:22", "texts": {"krv": "무엇이든지 구하는 바를 그에게 받나니 이는 우리가 그의 계명들을 지키고 그 앞에서 기뻐하시는 것을 행함이라", "kkjv": "무엇이든지 우리가 구하는 것을 그분에게서 받나니 이는 우리가 그분의 명령들을 지키고 그분의 눈앞에서 기쁨이 되는 그 일들을 행하기 때문이라.", "web": "and whatever we ask, we receive from him, because we keep his commandments and do the things that are pleasing in his sight."}}, {"id": 1353, "coll": "DEP 242구절", "sub": ["기도", "응답받는 기도의 조건", "합심하여 기도할 것"], "book": "마태복음", "chap": 18, "verse": "19", "ref": "마태복음 18:19", "texts": {"krv": "진실로 다시 너희에게 이르노니 너희 중에 두 사람이 땅에서 합심하여 무엇이든지 구하면 하늘에 계신 내 아버지께서 저희를 위하여 이루게 하시리라", "kkjv": "내가 다시 너희에게 이르노니, 너희 중의 두 사람이 자기들이 구할 어떤 것에 대하여 땅에서 한마음이 되면 하늘에 계신 내 아버지께서 그들을 위해 그것을 행하시리라.", "web": "Again, assuredly I tell you, that if two of you will agree on earth concerning anything that they will ask, it will be done for them by my Father who is in heaven."}}, {"id": 1354, "coll": "DEP 242구절", "sub": ["기도", "응답받는 기도의 조건", "적극적으로 기도할 것"], "book": "마태복음", "chap": 7, "verse": "7-8", "ref": "마태복음 7:7-8", "texts": {"krv": "구하라 그러면 너희에게 주실 것이요 찾으라 그러면 찾을 것이요 문을 두드리라 그러면 너희에게 열릴 것이니 구하는 이마다 얻을 것이요 찾는 이가 찾을 것이요 두드리는 이에게 열릴 것이니라", "kkjv": "¶구하라. 그러면 너희에게 주실 것이요, 찾으라. 그러면 너희가 찾을 것이요, 두드리라. 그러면 너희에게 열릴 것이니 구하는 자마다 받고 찾는 자는 찾으며 두드리는 자에게 열릴 것이니라.", "web": "“Ask, and it will be given you. Seek, and you will find. Knock, and it will be opened for you. For everyone who asks receives. He who seeks finds. To him who knocks it will be opened."}}, {"id": 1355, "coll": "DEP 242구절", "sub": ["기도", "응답받는 기도의 조건", "전심으로 부르짖을 것"], "book": "예레미야", "chap": 29, "verse": "12-13", "ref": "예레미야 29:12-13", "texts": {"krv": "너희는 내게 부르짖으며 와서 내게 기도하면 내가 너희를 들을 것이요 너희가 전심으로 나를 찾고 찾으면 나를 만나리라", "kkjv": "그때에는 너희가 나를 부르고 가서 내게 기도하리니 내가 너희 말에 귀를 기울이리라. 또 너희가 너희 마음을 다하여 나를 찾으면 나를 찾고 나를 만나리라.", "web": "You shall call on me, and you shall go and pray to me, and I will listen to you. You shall seek me, and find me, when you shall search for me with all your heart."}}, {"id": 1356, "coll": "DEP 242구절", "sub": ["기도", "응답받는 기도의 조건", "약속을 주장하며 기도할 것"], "book": "느헤미야", "chap": 1, "verse": "9", "ref": "느헤미야 1:9", "texts": {"krv": "만일 내게로 돌아와서 내 계명을 지켜 행하면 너희 쫓긴 자가 하늘 끝에 있을지라도 내가 거기서부터 모아 내 이름을 두려고 택한 곳에 돌아오게 하리라 하신 말씀을 이제 청컨대 기억하옵소서", "kkjv": "그러나 만일 너희가 내게로 돌아와 내 명령들을 지키고 행하면 너희 중에서 하늘 맨 끝 지역에까지 쫓겨난 자들이 있을지라도 내가 거기서부터 그들을 모아 내 이름을 두려고 내가 택한 곳으로, 거기로 데려오리라, 하셨나이다.", "web": "but if you return to me, and keep my commandments and do them, though your outcasts were in the uttermost part of the heavens, yet will I gather them from there, and will bring them to the place that I have chosen, to cause my name to dwell there.’"}}, {"id": 1357, "coll": "DEP 242구절", "sub": ["기도", "기도의 본", "모험적인 기도"], "book": "다니엘", "chap": 6, "verse": "10", "ref": "다니엘 6:10", "texts": {"krv": "다니엘이 이 조서에 어인이 찍힌 것을 알고도 자기 집에 돌아가서는 그 방의 예루살렘으로 향하여 열린 창에서 전에 행하던 대로 하루 세 번씩 무릎을 꿇고 기도하며 그 하나님께 감사하였더라", "kkjv": "¶그런데 다니엘은 그 조서에 도장이 찍힌 것을 알고도 자기 집에 들어가 자기 방에서 예루살렘을 향하여 창문을 열고 전에 하던 대로 하루에 세 번씩 무릎을 꿇고 기도하며 자기 하나님 앞에서 감사를 드리더라.", "web": "When Daniel knew that the writing was signed, he went into his house (now his windows were open in his room toward Jerusalem) and he kneeled on his knees three times a day, and prayed, and gave thanks before his God, as he did before."}}, {"id": 1358, "coll": "DEP 242구절", "sub": ["기도", "기도의 본", "우선순위를 둔 기도"], "book": "누가복음", "chap": 5, "verse": "15-16", "ref": "누가복음 5:15-16", "texts": {"krv": "예수의 소문이 더욱 퍼지매 허다한 무리가 말씀도 듣고 자기 병도 나음을 얻고자 하여 모여 오되 예수는 물러가사 한적한 곳에서 기도하시니라", "kkjv": "그러나 그분의 명성이 더욱 널리 퍼지매 큰 무리들이 함께 와서 말씀도 듣고 또 그분을 통해 자기들의 병약함도 고치려 하더라. ¶그분께서 광야로 물러가사 기도하시더라.", "web": "But the report concerning him spread much more, and great multitudes came together to hear, and to be healed by him of their infirmities. But he withdrew himself into the desert, and prayed."}}, {"id": 1359, "coll": "DEP 242구절", "sub": ["기도", "기도의 본", "밤을 새워 한 기도"], "book": "누가복음", "chap": 6, "verse": "12", "ref": "누가복음 6:12", "texts": {"krv": "이 때에 예수께서 기도하시러 산으로 가사 밤이 맞도록 하나님께 기도하시고", "kkjv": "그 무렵에 그분께서 기도하러 산으로 들어가사 밤새도록 하나님께 기도하시니라.", "web": "In these days, he went out to the mountain to pray, and he continued all night in prayer to God."}}, {"id": 1360, "coll": "DEP 242구절", "sub": ["기도", "기도의 본", "간절한 기도"], "book": "야고보서", "chap": 5, "verse": "17-18", "ref": "야고보서 5:17-18", "texts": {"krv": "엘리야는 우리와 성정이 같은 사람이로되 저가 비 오지 않기를 간절히 기도한즉 삼 년 육 개월 동안 땅에 비가 아니오고 디시 기도한즉 하늘이 비를 주고 땅이 열매를 내었느니라", "kkjv": "엘리야는 우리와 같이 동일한 성정의 지배를 받은 사람이로되 비가 오지 않기를 그가 간절히 기도하니 삼 년 육 개월 동안이나 땅에 비가 오지 아니하였고 그가 다시 기도하니 하늘이 비를 주고 땅이 자기 열매를 내었느니라.", "web": "Elijah was a man with a nature like ours, and he prayed earnestly that it might not rain, and it didn’t rain on the earth for three years and six months. He prayed again, and the sky gave rain, and the earth produced its fruit."}}, {"id": 1361, "coll": "DEP 242구절", "sub": ["기도", "기도의 본", "곤경 중의 기도"], "book": "사도행전", "chap": 16, "verse": "25", "ref": "사도행전 16:25", "texts": {"krv": "밤중쯤 되어 바울과 실라가 기도하고 하나님을 찬미하매 죄수들이 듣더라", "kkjv": "¶한밤중에 바울과 실라가 기도하고 노래로 하나님을 찬양하매 죄수들이 그들의 말을 듣는데", "web": "But about midnight Paul and Silas were praying and singing hymns to God, and the prisoners were listening to them."}}, {"id": 1362, "coll": "DEP 242구절", "sub": ["기도", "기도의 손 예화", "찬양"], "book": "역대상", "chap": 29, "verse": "11-13", "ref": "역대상 29:11-13", "texts": {"krv": "여호와여 광대하심과 권능과 영광과 이김과 위엄이 다 주께 속하였사오니 천지에 있는 것이 다 주의 것이로소이다 여호와여 주권도 주께 속하였사오니 주는 높으사 만유의 머리심이니이다 부와 귀가 주께로 말미암고 또 주는 만유의 주재가 되사 손에 권세와 능력이 있사오니 모든 자를 크게 하심과 강하게 하심이 주의 손에 있나이다 우리 하나님이여 이제 우리가 주께 감사하오며 주의 영화로운 이름을 찬양하나이다", "kkjv": "오 주여, 광대하심과 권능과 영광과 승리와 위엄이 주의 것이오니 하늘과 땅에 있는 모든 것이 주의 것이니이다. 오 주여, 왕국도 주의 것이오니 주께서는 모든 것 위에 머리로서 높여지셨나이다. 재물과 명예가 다 주에게서 나오며 또 주께서는 모든 것을 통치하시나이다. 주의 손에 권능과 능력이 있사오니 사람을 크게 하심과 모든 사람에게 기력을 주심이 주의 손에 있나이다. 그러므로 우리 하나님이여, 이제 우리가 주께 감사하오며 주의 영화로운 이름을 찬양하나이다.", "web": "Yours, Yahweh, is the greatness, the power, the glory, the victory, and the majesty! For all that is in the heavens and in the earth is yours. Yours is the kingdom, Yahweh, and you are exalted as head above all. Both riches and honor come from you, and you rule over all; and in your hand is power and might; and it is in your hand to make great, and to give strength to all. Now therefore, our God, we thank you, and praise your glorious name."}}, {"id": 1363, "coll": "DEP 242구절", "sub": ["기도", "기도의 손 예화", "중보"], "book": "디모데전서", "chap": 2, "verse": "1-2", "ref": "디모데전서 2:1-2", "texts": {"krv": "그러므로 내가 첫째로 권하노니 모든 사람을 위하여 간구와 기도와 도고와 감사를 하되 임금들과 높은 지위에 있는 모든 사람을 위하여 하라 이는 우리가 모든 경건과 단정한 중에 고요하고 평안한 생활을 하려 함이니라", "kkjv": "그러므로 내가 권면하노니 무엇보다 먼저 모든 사람을 위하여 간구와 기도와 중보와 감사를 드리되 왕들과 권위를 가진 모든 사람을 위하여 하라. 이것은 우리가 전적으로 하나님을 따르며 정직한 가운데 조용하고 평화로운 삶을 살고자 함이라.", "web": "I exhort therefore, first of all, that petitions, prayers, intercessions, and givings of thanks, be made for all men: for kings and all who are in high places; that we may lead a tranquil and quiet life in all godliness and reverence."}}, {"id": 1364, "coll": "DEP 242구절", "sub": ["기도", "기도의 손 예화", "감사"], "book": "데살로니가전서", "chap": 5, "verse": "18", "ref": "데살로니가전서 5:18", "texts": {"krv": "범사에 감사하라 이는 그리스도 예수 안에서 너희를 향하신 하나님의 뜻이니라", "kkjv": "모든 일에서 감사하라. 이것이 그리스도 예수님 안에서 너희에 대한 하나님의 뜻이니라.", "web": "In everything give thanks, for this is the will of God in Christ Jesus toward you."}}, {"id": 1365, "coll": "DEP 242구절", "sub": ["기도", "기도의 손 예화", "자백"], "book": "요한일서", "chap": 1, "verse": "9", "ref": "요한일서 1:9", "texts": {"krv": "만일 우리가 우리 죄를 자백하면 저는 미쁘시고 의로우사 우리 죄를 사하시며 모든 불의에서 우리를 깨끗케 하실 것이요", "kkjv": "만일 우리가 우리의 죄들을 자백하면 그분께서는 신실하시고 의로우사 우리의 죄들을 용서하시며 모든 불의에서 우리를 깨끗하게 하시느니라.", "web": "If we confess our sins, he is faithful and righteous to forgive us the sins, and to cleanse us from all unrighteousness."}}, {"id": 1366, "coll": "DEP 242구절", "sub": ["기도", "기도의 손 예화", "간구"], "book": "빌립보서", "chap": 4, "verse": "6-7", "ref": "빌립보서 4:6-7", "texts": {"krv": "아무 것도 염려하지 말고 오직 모든 일에 기도와 간구로, 너희 구할 것을 감사함으로 하나님께 아뢰라 그리하면 모든 지각에 뛰어난 하나님의 평강이 그리스도 예수 안에서 너희 마음과 생각을 지키시리라", "kkjv": "아무것도 염려하지 말고 오직 모든 일에서 기도와 간구로 너희가 요청할 것들을 감사와 더불어 하나님께 알리라. 그리하면 모든 이해를 뛰어넘는 하나님의 평강이 그리스도 예수님을 통해 너희 마음과 생각을 지키시리라.", "web": "In nothing be anxious, but in everything, by prayer and petition with thanksgiving, let your requests be made known to God. And the peace of God, which surpasses all understanding, will guard your hearts and your thoughts in Christ Jesus."}}, {"id": 1367, "coll": "DEP 242구절", "sub": ["교제", "교제의 기초", "그리스도의 보혈"], "book": "에베소서", "chap": 2, "verse": "13", "ref": "에베소서 2:13", "texts": {"krv": "이제는 전에 멀리 있던 너희가 그리스도 예수 안에서 그리스도의 피로 가까워졌느니라", "kkjv": "한 때 멀리 떨어져 있던 너희가 이제는 그리스도 예수님 안에서 그리스도의 피로 가까워졌느니라.", "web": "But now in Christ Jesus you who once were far off are made near in the blood of Christ."}}, {"id": 1368, "coll": "DEP 242구절", "sub": ["교제", "교제의 기초", "그리스도의 보혈"], "book": "골로새서", "chap": 1, "verse": "20", "ref": "골로새서 1:20", "texts": {"krv": "그의 십자가의 피로 화평을 이루사 만물 곧 땅에 있는 것들이나 하늘에 있는 것들을 그로 말미암아 자기와 화목케 되기를 기뻐하심이라", "kkjv": "그분의 십자가의 피를 통해 화평을 이루사 그분으로 말미암아 모든 것들이 즉 내가 말하노니 그분으로 말미암아 땅에 있는 것들이나 하늘에 있는 것들이 자신과 화해하게 하셨느니라.", "web": "and through him to reconcile all things to himself, by him, whether things on the earth, or things in the heavens, having made peace through the blood of his cross."}}, {"id": 1369, "coll": "DEP 242구절", "sub": ["교제", "교제의 기초", "하나님-성부,성자,성령"], "book": "요한일서", "chap": 1, "verse": "3", "ref": "요한일서 1:3", "texts": {"krv": "우리가 보고 들은 바를 너희에게도 전함은 너희로 우리와 사귐이 있게 하려 함이니 우리의 사귐은 아버지와 그 아들 예수 그리스도와 함께 함이라", "kkjv": "우리가 보고 들은 그것을 너희에게 밝히 드러냄은 너희 또한 우리와 교제하게 하려 함이니 참으로 우리의 교제는 아버지와 함께하는 것이며 그분의 아들 예수 그리스도와 함께하는 것이니라.", "web": "that which we have seen and heard we declare to you, that you also may have fellowship with us. Yes, and our fellowship is with the Father, and with his Son, Jesus Christ."}}, {"id": 1370, "coll": "DEP 242구절", "sub": ["교제", "교제의 기초", "하나님-성부,성자,성령"], "book": "고린도후서", "chap": 13, "verse": "13", "ref": "고린도후서 13:13", "texts": {"krv": "주 예수 그리스도의 은혜와 하나님의 사랑과 성령의 교통하심이 너희 무리와 함께 있을지어다", "kkjv": "모든 성도들이 너희에게 문안하느니라.", "web": "All the saints greet you."}}, {"id": 1371, "coll": "DEP 242구절", "sub": ["교제", "교제의 중요성", "함께 하심의 약속"], "book": "마태복음", "chap": 18, "verse": "20", "ref": "마태복음 18:20", "texts": {"krv": "두세 사람이 내 이름으로 모인 곳에는 나도 그들 중에 있느니라", "kkjv": "두세 사람이 내 이름으로 함께 모인 곳에 나도 거기에 그들의 한가운데 있느니라, 하시니라.", "web": "For where two or three are gathered together in my name, there I am in their midst.”"}}, {"id": 1372, "coll": "DEP 242구절", "sub": ["교제", "교제의 중요성", "복을 명하심"], "book": "시편", "chap": 133, "verse": "1-3", "ref": "시편 133:1-3", "texts": {"krv": "형제가 연합하여 동거함이 어찌 그리 선하고 아름다운고 머리에 있는 보배로운 기름이 수염 곧 아론의 수염에 흘러서 그 옷깃까지 내림 같고 헐몬의 이슬이 시온의 산들에 내림 같도다 거기서 여호와께서 복을 명하셨니 곧 영생이로다", "kkjv": "보라, 형제들이 하나가 되어 동거함이 어찌 그리 좋으며 어찌 그리 기쁜가! 그것은 마치 수염 곧 아론의 수염 위로 흘러내려 그의 옷자락까지 내려간 머리 위의 귀중한 기름 같고 헤르몬의 이슬과 시온의 산들에 내린 이슬과도 같도다. 주께서 거기서 복을 명령하셨나니 곧 영원한 생명이로다.", "web": "See how good and how pleasant it is for brothers to live together in unity! It is like the precious oil on the head, that ran down on the beard, even Aaron’s beard; that came down on the edge of his robes; like the dew of Hermon, that comes down on the hills of Zion: for there Yahweh gives the blessing, even life forever more."}}, {"id": 1373, "coll": "DEP 242구절", "sub": ["교제", "교제의 중요성", "죄로부터 보호됨"], "book": "히브리서", "chap": 3, "verse": "13", "ref": "히브리서 3:13", "texts": {"krv": "오직 오늘이라 일컫는 동안에 매일 피차 권면하여 너희 중에 누구든지 죄의 유혹으로 강퍅케 됨을 면하라", "kkjv": "오직 오늘이라 불리는 때에 서로 날마다 권면하여 너희 중의 아무도 죄의 속임수를 통해 강퍅하게 되지 아니하도록 하라.", "web": "but exhort one another day by day, so long as it is called “today”; lest any one of you be hardened by the deceitfulness of sin."}}, {"id": 1374, "coll": "DEP 242구절", "sub": ["교제", "교제의 중요성", "서로 일으켜 줌"], "book": "전도서", "chap": 4, "verse": "9-10", "ref": "전도서 4:9-10", "texts": {"krv": "두 사람이 한 사람보다 나음은 저희가 수고함으로 좋은 상을 얻을 것임이라 혹시 저희가 넘어지면 하나가 그 동무를 붙들어 일으키려니와 홀로 있어 넘어지고 붙들어 일으킬 자가 없는 자에게는 화가 있으리라", "kkjv": "¶두 사람이 한 사람보다 나음은 그들이 자기들의 수고로 인하여 좋은 보상을 받기 때문이라. 혹시 그들이 넘어지면 한 사람이 자기 동료를 일으켜 세우려니와 홀로 있는 자는 넘어질 때에 화가 있으리니 그를 도와서 일으킬 다른 자가 그에게 없도다.", "web": "Two are better than one, because they have a good reward for their labor. For if they fall, the one will lift up his fellow; but woe to him who is alone when he falls, and doesn’t have another to lift him up."}}, {"id": 1375, "coll": "DEP 242구절", "sub": ["교제", "교제의 중요성", "경건한 삶을 훈련함"], "book": "디모데후서", "chap": 2, "verse": "22", "ref": "디모데후서 2:22", "texts": {"krv": "또한 네가 청년의 정욕을 피하고 주를 깨끗한 마음으로 부르는 자들과 함께 믿음과 사랑과 화평을 좇으라", "kkjv": "또한 청년의 정욕을 피하고 오직 순수한 마음으로 주를 부르는 자들과 함께 의와 믿음과 사랑과 화평을 따르라.", "web": "Flee from youthful lusts; but pursue righteousness, faith, love, and peace with those who call on the Lord out of a pure heart."}}, {"id": 1376, "coll": "DEP 242구절", "sub": ["교제", "교제의 중요성", "인격을 계발함"], "book": "잠언", "chap": 27, "verse": "17,19", "ref": "잠언 27:17,19", "texts": {"krv": "철이 철을 날카롭게 하는 것 같이 사람이 그 친구의 얼굴을 빛나게 하느니라 물에 비취이면 얼굴이 서로 같은 것 같이 사람의 마음도 서로 비취느니라", "kkjv": "쇠가 쇠를 예리하게 하는 것 같이 사람이 자기 친구의 얼굴을 예리하게 하느니라. 물에서 얼굴이 얼굴과 일치하는 것 같이 사람의 마음도 사람과 일치하느니라.", "web": "Iron sharpens iron; so a man sharpens his friend’s countenance. Like water reflects a face, so a man’s heart reflects the man."}}, {"id": 1377, "coll": "DEP 242구절", "sub": ["교제", "교제의 중요성", "지혜를 얻음"], "book": "잠언", "chap": 13, "verse": "20", "ref": "잠언 13:20", "texts": {"krv": "지혜로운 자와 동행하면 지혜를 얻고 미련한 자와 사귀면 해를 받느니라", "kkjv": "지혜로운 자들과 함께 걷는 자는 지혜로우려니와 어리석은 자들의 벗이 되는 자는 멸망을 당하리라.", "web": "One who walks with wise men grows wise, but a companion of fools suffers harm."}}, {"id": 1378, "coll": "DEP 242구절", "sub": ["교제", "교제의 중요성", "성장케 됨"], "book": "에베소서", "chap": 4, "verse": "13", "ref": "에베소서 4:13", "texts": {"krv": "우리가 다 하나님의 아들을 믿는 것과 아는 일에 하나가 되어 온전한 사람을 이루어 그리스도의 장성한 분량이 충만한 데까지 이르리니", "kkjv": "마침내 우리가 다 믿음과 하나님의 아들을 아는 것에서 하나가 되어 완전한 사람에 이르고 그리스도의 충만하심의 장성한 분량에까지 이르리니", "web": "until we all attain to the unity of the faith, and of the knowledge of the Son of God, to a full grown man, to the measure of the stature of the fullness of Christ;"}}, {"id": 1379, "coll": "DEP 242구절", "sub": ["교제", "교제의 중요성", "사역의 열매를 맺음"], "book": "사도행전", "chap": 2, "verse": "42,47", "ref": "사도행전 2:42,47", "texts": {"krv": "저희가 사도의 가르침을 받아 서로 교제하며 떡을 떼며 기도하기를 전혀 힘쓰니라 하나님을 찬미하며 또 온 백성에게 칭송을 받으니 주께서 구원 받는 사람을 날마다 더하게 하시니라", "kkjv": "그들이 흔들리지 아니하며 사도들의 교리와 교제 안에 머물고 빵을 떼며 기도하더라. 하나님을 찬양하며 온 백성에게 호감을 얻으니 주께서 구원받아야 할 자들을 날마다 교회에 더하시니라.", "web": "They continued steadfastly in the apostles’ teaching and fellowship, in the breaking of bread, and prayer. praising God, and having favor with all the people. The Lord added to the assembly day by day those who were being saved."}}, {"id": 1380, "coll": "DEP 242구절", "sub": ["교제", "교제의 요소", "복음 중심의 삶에 드려짐"], "book": "빌립보서", "chap": 1, "verse": "5,27", "ref": "빌립보서 1:5,27", "texts": {"krv": "첫날부터 이제까지 복음에서 너희가 교제함을 인함이라 오직 너희는 그리스도 복음에 합당하게 생활하라 이는 내가 너희를 가 보나 떠나 있으나 너희가 일심으로 서서 한 뜻으로 복음의 신앙을 위하여 협력하는 것과", "kkjv": "첫날부터 지금까지 너희가 복음 안에서 교제하였기 때문이라. 오직 너희 행실을 그리스도의 복음에 합당하게 하라. 그리하면 너희에 대한 일들 곧 내가 가서 너희를 보든지 떠나 있든지 너희가 한 영 안에 굳게 서서 복음의 믿음을 위하여 한마음으로 함께 싸우며", "web": "for your partnership in furtherance of the Good News from the first day until now; Only let your way of life be worthy of the Good News of Christ, that, whether I come and see you or am absent, I may hear of your state, that you stand firm in one spirit, with one soul striving for the faith of the Good News;"}}, {"id": 1381, "coll": "DEP 242구절", "sub": ["교제", "교제의 요소", "사랑과 선행을 격려함"], "book": "히브리서", "chap": 10, "verse": "24,25", "ref": "히브리서 10:24,25", "texts": {"krv": "서로 돌아보아 사랑과 선행을 격려하며 모이기를 폐하는 어떤 사람들의 습관과 같이 하지 말고 오직 권하여 그 날이 가까움을 볼수록 더욱 그리하자", "kkjv": "서로를 살펴보아 사랑과 선한 행위에 이르도록 격려하며 어떤 사람들의 습관과 같이 우리의 함께 모이는 일을 폐하지 말고 서로 권면하되 그 날이 다가옴을 너희가 볼수록 더욱 그리하자.", "web": "Let us consider how to provoke one another to love and good works, not forsaking our own assembling together, as the custom of some is, but exhorting one another; and so much the more, as you see the Day approaching."}}, {"id": 1382, "coll": "DEP 242구절", "sub": ["교제", "교제의 요소", "필요를 채워 줌"], "book": "고린도후서", "chap": 8, "verse": "3-4", "ref": "고린도후서 8:3-4", "texts": {"krv": "내가 증거하노니 저희가 힘대로 할 뿐 아니라 힘에 지나도록 자원하여 이 은혜와 성도 섬기는 일에 참여함에 대하여 우리에게 간절히 구하니", "kkjv": "내가 증언하노니 그들이 힘닿는 데까지 하였을 뿐 아니라 참으로 힘에 넘치도록 자원하여 하였고 우리가 그 선물을 받아 줄 것과 또 성도들을 섬기는 교제의 일을 맡아 줄 것을 우리에게 매우 간절히 구하였노라.", "web": "For according to their power, I testify, yes and beyond their power, they gave of their own accord, begging us with much entreaty to receive this grace and the fellowship in the service to the saints."}}, {"id": 1383, "coll": "DEP 242구절", "sub": ["교제", "교제의 요소", "그리스도의 고난에 동참함"], "book": "베드로전서", "chap": 4, "verse": "13", "ref": "베드로전서 4:13", "texts": {"krv": "오직 너희가 그리스도의 고난에 참예하는 것으로 즐거워하라 이는 그의 영광을 나타내실 때에 너희로 즐거워하고 기뻐하게 하려 함이라", "kkjv": "오히려 너희가 그리스도의 고난에 참여하는 자가 되었으므로 기뻐하라. 이것은 그분의 영광이 드러날 때에 너희가 넘치는 기쁨으로 또한 즐거워하게 하려 함이니라.", "web": "But because you are partakers of Christ’s sufferings, rejoice; that at the revelation of his glory you also may rejoice with exceeding joy."}}, {"id": 1384, "coll": "DEP 242구절", "sub": ["교제", "교제의 요소", "서로의 짐을 짐"], "book": "갈라디아서", "chap": 6, "verse": "2", "ref": "갈라디아서 6:2", "texts": {"krv": "너희가 짐을 서로 지라 그리하여 그리스도의 법을 성취하라", "kkjv": "너희는 서로 남의 짐들을 지라. 그리하여 그리스도의 법을 성취하라.", "web": "Bear one another’s burdens, and so fulfill the law of Christ."}}, {"id": 1385, "coll": "DEP 242구절", "sub": ["교제", "교제의 태도", "마음을 같이 할 것"], "book": "빌립보서", "chap": 2, "verse": "1-2", "ref": "빌립보서 2:1-2", "texts": {"krv": "그러므로 그리스도 안에 무슨 권면이나 사랑에 무슨 위로나 성령의 무슨 교제나 긍휼이나 자비가 있거든 마음을 같이 하여 같은 사랑을 가지고 뜻을 합하며 한 마음을 품어", "kkjv": "그러므로 그리스도 안에서 무슨 안위나 사랑의 무슨 위로나 성령의 무슨 교제나 무슨 인정이나 긍휼이 있거든 너희는 같은 생각을 품고 같은 사랑을 가지며 한 마음과 한 생각이 되어 내 기쁨을 성취하라.", "web": "If there is therefore any exhortation in Christ, if any consolation of love, if any fellowship of the Spirit, if any tender mercies and compassion, make my joy full, by being like-minded, having the same love, being of one accord, of one mind;"}}, {"id": 1386, "coll": "DEP 242구절", "sub": ["교제", "교제의 태도", "겸손할 것"], "book": "빌립보서", "chap": 2, "verse": "3-4", "ref": "빌립보서 2:3-4", "texts": {"krv": "아무 일에든지 다툼이나 허영으로 하지 말고 오직 겸손한 마음으로 각각 자기보다 남을 낫게 여기고 각각 자기 일을 돌아볼 뿐더러 또한 각각 다른 사람들의 일을 돌아보아 나의 기쁨을 충만케 하라", "kkjv": "어떤 일도 다툼이나 헛된 영광으로 하지 말고 오직 겸손한 생각으로 각각 자기보다 남을 더 낫게 여기며 각 사람이 자기 일들만 돌아보지 말고 각 사람이 남의 일들도 돌아보라.", "web": "doing nothing through rivalry or through conceit, but in humility, each counting others better than himself; each of you not just looking to his own things, but each of you also to the things of others."}}, {"id": 1387, "coll": "DEP 242구절", "sub": ["교제", "교제의 태도", "마음을 넓힐 것"], "book": "고린도후서", "chap": 6, "verse": "12-13", "ref": "고린도후서 6:12-13", "texts": {"krv": "너희가 우리 안에서 좁아진 것이 아니라 오직 너희 심정에서 좁아진 것이니라 내가 자녀에게 말하듯 하노니 보답하는 양으로 너희도 마음을 넓히라", "kkjv": "너희는 우리 안에서 좁혀지지 아니하고 오직 너희 속 중심에서 좁혀졌느니라. (내가 내 자녀에게 하듯 말하노니) 이제 너희도 같은 것을 보답하는 뜻으로 마음을 넓게 열라.", "web": "You are not restricted by us, but you are restricted by your own affections. Now in return, I speak as to my children, you also be open wide."}}, {"id": 1388, "coll": "DEP 242구절", "sub": ["교제", "교제의 태도", "피차 복종할 것"], "book": "에베소서", "chap": 5, "verse": "21", "ref": "에베소서 5:21", "texts": {"krv": "그리스도를 경외함으로 피차 복종하라", "kkjv": "하나님을 두려워하는 가운데 서로에게 복종하라.", "web": "subjecting yourselves one to another in the fear of Christ."}}, {"id": 1389, "coll": "DEP 242구절", "sub": ["교제", "교제의 태도", "비교하지 말 것"], "book": "마가복음", "chap": 9, "verse": "34-35", "ref": "마가복음 9:34-35", "texts": {"krv": "저희가 잠잠하니 이는 노중에서 서로 누가 크냐 하고 쟁론하였음이라 예수께서 앉으사 열두 제자를 불러서 이르시되 아무든지 첫째가 되고자 하면 뭇사람의 끝이 되며 뭇사람을 섬기는 자가 되어야 하리라 하시고", "kkjv": "그들이 잠잠하니 이는 그들이 길에서 누가 가장 큰 자인가 하는 일로 자기들끼리 논쟁하였기 때문이라. 그분께서 앉으사 열두 제자를 불러 그들에게 이르시되, 어떤 사람이 첫째가 되고자 하면 바로 그 사람은 모든 사람의 말째가 되며 모든 사람의 종이 되어야 할지니라, 하시고", "web": "But they were silent, for they had disputed one with another on the way about who was the greatest. He sat down, and called the twelve; and he said to them, “If any man wants to be first, he shall be last of all, and servant of all.”"}}, {"id": 1390, "coll": "DEP 242구절", "sub": ["교제", "교제의 태도", "쓴 뿌리를 갖지 말 것"], "book": "히브리서", "chap": 12, "verse": "15", "ref": "히브리서 12:15", "texts": {"krv": "너희는 돌아보아 하나님 은혜에 이르지 못하는 자가 있는가 두려워하고 또 쓴 뿌리가 나서 괴롭게 하고 많은 사람이 이로 말미암아 더러움을 입을까 두려워하고", "kkjv": "부지런히 살펴 하나님의 은혜에 이르지 못하는 자가 없게 하고 쓴 뿌리가 돋아나 너희를 괴롭게 하거나 그것으로 말미암아 많은 사람이 더럽게 되지 않도록 할지니", "web": "looking carefully lest there be any man who falls short of the grace of God; lest any root of bitterness springing up trouble you, and many be defiled by it;"}}, {"id": 1391, "coll": "DEP 242구절", "sub": ["교제", "교제의 태도", "열매 없는 일에서 떠날 것"], "book": "에베소서", "chap": 5, "verse": "11", "ref": "에베소서 5:11", "texts": {"krv": "너희는 열매 없는 어두움의 일에 참예하지 말고 도리어 책망하라", "kkjv": "열매 없는 어둠의 일들에 참여하지 말고 도리어 그것들을 책망하라.", "web": "Have no fellowship with the unfruitful works of darkness, but rather even reprove them."}}, {"id": 1392, "coll": "DEP 242구절", "sub": ["교제", "교제의 태도", "자기 일에 얽매이지 말 것"], "book": "디모데후서", "chap": 2, "verse": "4", "ref": "디모데후서 2:4", "texts": {"krv": "군사로 다니는 자는 자기 생활에 얽매이는 자가 하나도 없나니 이는 군사로 모집한 자를 기쁘게 하려 함이라", "kkjv": "전쟁을 하는 어떤 사람도 이 세상 삶의 일에 얽매이지 아니하나니 이것은 그가 자기를 군사로 택한 자를 기쁘게 하려 함이라.", "web": "No soldier on duty entangles himself in the affairs of life, that he may please him who enrolled him as a soldier."}}, {"id": 1393, "coll": "DEP 242구절", "sub": ["교제", "교제에서의 문제해결", "성도와의 관계"], "book": "마태복음", "chap": 5, "verse": "23-24", "ref": "마태복음 5:23-24", "texts": {"krv": "그러므로 예물을 제단에 드리다가 거기서 네 형제에게 원망들을 만한 일이 있는 줄 생각나거든 예물을 제단 앞에 두고 먼저 가서 형제와 화목하고 그 후에 와서 예물을 드리라", "kkjv": "그러므로 네가 네 예물을 제단으로 가져오다가 너를 대적할 어떤 일이 네 형제에게 있음을 거기서 기억하거든 네 예물을 거기에, 제단 앞에 두고 네 길로 가서 맨 먼저 네 형제와 화해하고 그 뒤에 와서 네 예물을 드리라.", "web": "“If therefore you are offering your gift at the altar, and there remember that your brother has anything against you, leave your gift there before the altar, and go your way. First be reconciled to your brother, and then come and offer your gift."}}, {"id": 1394, "coll": "DEP 242구절", "sub": ["교제", "교제에서의 문제해결", "성도와의 관계"], "book": "마태복음", "chap": 18, "verse": "15", "ref": "마태복음 18:15", "texts": {"krv": "네 형제가 죄를 범하거든 가서 너와 그 사람과만 상대하여 권고하라 만일 들으면 네가 네 형제를 얻은 것이요", "kkjv": "¶또한 만일 네 형제가 네게 범법하거든 가서 너와 그만 따로 있을 때에 그의 허물을 그에게 일러 주라. 만일 그가 네 말을 들으면 네가 네 형제를 얻었느니라.", "web": "“If your brother sins against you, go, show him his fault between you and him alone. If he listens to you, you have gained back your brother."}}, {"id": 1395, "coll": "DEP 242구절", "sub": ["교제", "교제에서의 문제해결", "하나님과의 관계"], "book": "요한일서", "chap": 1, "verse": "9", "ref": "요한일서 1:9", "texts": {"krv": "만일 우리가 우리 죄를 자백하면 저는 미쁘시고 의로우사 우리 죄를 사하시며 모든 불의에서 우리를 깨끗케 하실 것이요", "kkjv": "만일 우리가 우리의 죄들을 자백하면 그분께서는 신실하시고 의로우사 우리의 죄들을 용서하시며 모든 불의에서 우리를 깨끗하게 하시느니라.", "web": "If we confess our sins, he is faithful and righteous to forgive us the sins, and to cleanse us from all unrighteousness."}}, {"id": 1396, "coll": "DEP 242구절", "sub": ["교제", "교제에서의 문제해결", "하나님과의 관계"], "book": "잠언", "chap": 28, "verse": "13", "ref": "잠언 28:13", "texts": {"krv": "자기의 죄를 숨기는 자는 형통치 못하나 죄를 자복하고 버리는 자는 불쌍히 여김을 받으리라", "kkjv": "자기 죄들을 숨기는 자는 형통하지 못하려니와 누구든지 그것들을 자백하고 버리는 자는 긍휼을 얻으리라.", "web": "He who conceals his sins doesn’t prosper, but whoever confesses and renounces them finds mercy."}}, {"id": 1397, "coll": "DEP 242구절", "sub": ["증거", "전도는 누구의 책임인가?", "모든 그리스도인"], "book": "사도행전", "chap": 1, "verse": "8", "ref": "사도행전 1:8", "texts": {"krv": "오직 성령이 너희에게 임하시면 너희가 권능을 받고 예루살렘과 온 유대와 사마리아 땅 끝까지 이르러 내 증인이 되리라 하시니라", "kkjv": "오직 성령님께서 너희에게 임하신 뒤에 너희가 권능을 받고 예루살렘과 온 유대와 사마리아에서 그리고 땅의 맨 끝 지역까지 이르러 나를 위한 증인이 되리라, 하시니라.", "web": "But you will receive power when the Holy Spirit has come upon you. You will be witnesses to me in Jerusalem, in all Judea and Samaria, and to the uttermost parts of the earth.”"}}, {"id": 1398, "coll": "DEP 242구절", "sub": ["증거", "전도는 누구의 책임인가?", "모든 그리스도인"], "book": "고린도후서", "chap": 5, "verse": "18-19", "ref": "고린도후서 5:18-19", "texts": {"krv": "모든 것이 하나님께로 났나니 저가 그리스도로 말미암아 우리를 자기와 화목하게 하시고 또 우리에게 화목하게 하는 직책을 주셨으니 이는 하나님께서 그리스도 안에 계시사 세상을 자기와 화목하게 하시며 저희의 죄를 저희에게 돌리지 아니하시고 화목하게 하는 말씀을 우리에게 부탁하셨느니라", "kkjv": "또 모든 것이 하나님에게서 났으며 그분께서 예수 그리스도를 통하여 우리를 자신과 화해하게 하시고 또 화해하게 하는 사역을 우리에게 주셨으니 곧 하나님께서 그리스도 안에 계시사 세상을 자신과 화해하게 하시며 그들의 범법을 그들에게 돌리지 아니하시고 화해하게 하는 말씀을 우리에게 맡기셨느니라.", "web": "But all things are of God, who reconciled us to himself through Jesus Christ, and gave to us the ministry of reconciliation; namely, that God was in Christ reconciling the world to himself, not reckoning to them their trespasses, and having committed to us the word of reconciliation."}}, {"id": 1399, "coll": "DEP 242구절", "sub": ["증거", "왜 전도를 해야 하나?", "하나님의 명령"], "book": "디모데후서", "chap": 4, "verse": "1-2", "ref": "디모데후서 4:1-2", "texts": {"krv": "하나님 앞과 산 자와 죽은 자를 심판하실 그리스도 예수 앞에서 그의 나타나실 것과 그의 나라를 두고 엄히 명하노니 너는 말씀을 전파하라 때를 얻든지 못 얻든지 항상 힘쓰라 범사에 오래 참음과 가르침으로 경책하며 경계하며 권하라", "kkjv": "그러므로 내가 하나님 앞과 주 예수 그리스도 앞에서 곧 친히 나타나실 때에 자신의 왕국에서 산 자와 죽은 자를 심판하실 분 앞에서 네게 명하노니 말씀을 선포하라. 때에 맞든지 맞지 아니하든지 긴급히 하라. 모든 오래 참음과 교리로 책망하고 꾸짖고 권면하라.", "web": "I command you therefore before God and the Lord Jesus Christ, who will judge the living and the dead at his appearing and his Kingdom: preach the word; be urgent in season and out of season; reprove, rebuke, and exhort, with all patience and teaching."}}, {"id": 1400, "coll": "DEP 242구절", "sub": ["증거", "왜 전도를 해야 하나?", "잃어버린 자에 대한 사랑"], "book": "누가복음", "chap": 19, "verse": "10", "ref": "누가복음 19:10", "texts": {"krv": "인자의 온 것은 잃어버린 자를 찾아 구원하려 함이니라", "kkjv": "사람의 아들은 잃어버린 것을 찾아 구원하러 왔느니라, 하시니라.", "web": "For the Son of Man came to seek and to save that which was lost.”"}}, {"id": 1401, "coll": "DEP 242구절", "sub": ["증거", "왜 전도를 해야 하나?", "복음 전할 부탁을 받음"], "book": "데살로니가전서", "chap": 2, "verse": "4", "ref": "데살로니가전서 2:4", "texts": {"krv": "오직 하나님의 옳게 여기심을 입어 복음 전할 부탁을 받았으니 우리가 이와 같이 말함은 사람을 기쁘게 하려 함이 아니요 오직 우리 마음을 감찰하시는 하나님을 기쁘시게 하려 함이라", "kkjv": "다만 우리는 하나님의 허락을 받아 복음을 위탁받은 대로 말하노니 이것은 사람들을 기쁘게 하려 함이 아니요 오직 우리의 마음을 시험하시는 하나님을 기쁘게 하려 함이라.", "web": "But even as we have been approved by God to be entrusted with the Good News, so we speak; not as pleasing men, but God, who tests our hearts."}}, {"id": 1402, "coll": "DEP 242구절", "sub": ["증거", "왜 전도를 해야 하나?", "부득불 할 일이므로"], "book": "고린도전서", "chap": 9, "verse": "16", "ref": "고린도전서 9:16", "texts": {"krv": "내가 복음을 전할지라도 자랑할 것이 없음은 내가 부득불 할 일임이라 만일 복음을 전하지 아니하면 내게 화가 있을 것임이로라", "kkjv": "내가 복음을 선포할지라도 자랑할 것이 없나니 이는 필연적으로 내가 해야 하기 때문이라. 만일 내가 복음을 선포하지 아니하면 참으로 내게 화가 있으리로다!", "web": "For if I preach the Good News, I have nothing to boast about; for necessity is laid on me; but woe is to me, if I don’t preach the Good News."}}, {"id": 1403, "coll": "DEP 242구절", "sub": ["증거", "왜 전도를 해야 하나?", "전파해야 믿게 되므로"], "book": "로마서", "chap": 10, "verse": "14", "ref": "로마서 10:14", "texts": {"krv": "그런즉 저희가 믿지 아니하는 이를 어찌 부르리요 듣지도 못한 이를 어찌 믿으리요 전파하는 자가 없이 어찌 들으리요", "kkjv": "그런즉 그들이 자기들이 믿지 아니한 분을 어찌 부르리요? 자기들이 듣지 못한 분을 어찌 믿으리요? 선포자가 없이 어찌 들으리요?", "web": "How then will they call on him in whom they have not believed? How will they believe in him whom they have not heard? How will they hear without a preacher?"}}, {"id": 1404, "coll": "DEP 242구절", "sub": ["증거", "왜 전도를 해야 하나?", "모든 사람이 구원받길 원하시므로"], "book": "디모데전서", "chap": 2, "verse": "4", "ref": "디모데전서 2:4", "texts": {"krv": "하나님은 모든 사람이 구원을 받으며 진리를 아는 데 이르기를 원하시느니라", "kkjv": "그분은 모든 사람이 구원을 받고 진리를 아는 데 이르기를 원하시느니라.", "web": "who desires all people to be saved and come to full knowledge of the truth."}}, {"id": 1405, "coll": "DEP 242구절", "sub": ["증거", "왜 전도를 해야 하나?", "사람을 가장 아끼시므로"], "book": "요나", "chap": 4, "verse": "10-11", "ref": "요나 4:10-11", "texts": {"krv": "여호와께서 가라사대 네가 수고도 아니하였고 배양도 아니하였고 하룻밤에 났다가 하룻밤에 망한 이 박 넝쿨을 네가 아꼈거든 하물며 이 큰 성읍 니느웨에는 좌우를 분변치 못하는 자가 십이만여 명이요 육축도 많이 있나니 내가 아끼는 것이 어찌 합당치 아니하냐", "kkjv": "그때에 주께서 이르시되, 네가 수고하지도 아니하고 자라게 하지도 아니한 박 곧 하룻밤 사이에 났다가 하룻밤 사이에 없어진 그 박을 불쌍히 여겼거든 오른손과 왼손을 분간하지 못하는 자가 십이만 명이 넘고 또 많은 가축이 있는 저 큰 도시 니느웨를 내가 아껴야 하지 아니하겠느냐? 하시니라.", "web": "Yahweh said, “You have been concerned for the vine, for which you have not labored, neither made it grow; which came up in a night, and perished in a night. Shouldn’t I be concerned for Nineveh, that great city, in which are more than one hundred twenty thousand persons who can’t discern between their right hand and their left hand; and also much livestock?”"}}, {"id": 1406, "coll": "DEP 242구절", "sub": ["증거", "왜 전도를 해야 하나?", "죄인 하나의 회개를 기뻐하시므로"], "book": "누가복음", "chap": 15, "verse": "7", "ref": "누가복음 15:7", "texts": {"krv": "내가 너희에게 이르노니 이와 같이 죄인 하나가 회개하면 하늘에서는 회개할 것 없는 의인 아흔아홉을 인하여 기뻐하는 것보다 더하리라", "kkjv": "내가 너희에게 이르노니, 이와 같이 하늘에서는 회개할 필요가 없는 의로운 아흔아홉 사람보다 회개하는 한 죄인으로 인하여 더 기쁨이 있으리라.", "web": "I tell you that even so there will be more joy in heaven over one sinner who repents, than over ninety-nine righteous people who need no repentance."}}, {"id": 1407, "coll": "DEP 242구절", "sub": ["증거", "왜 전도를 해야 하나?", "주 안에서의 축복된 교제를 위해"], "book": "요한일서", "chap": 1, "verse": "3", "ref": "요한일서 1:3", "texts": {"krv": "우리가 보고 들은 바를 너희에게도 전함은 너희로 우리와 사귐이 있게 하려 함이니 우리의 사귐은 아버지와 그 아들 예수 그리스도와 함께 함이라", "kkjv": "우리가 보고 들은 그것을 너희에게 밝히 드러냄은 너희 또한 우리와 교제하게 하려 함이니 참으로 우리의 교제는 아버지와 함께하는 것이며 그분의 아들 예수 그리스도와 함께하는 것이니라.", "web": "that which we have seen and heard we declare to you, that you also may have fellowship with us. Yes, and our fellowship is with the Father, and with his Son, Jesus Christ."}}, {"id": 1408, "coll": "DEP 242구절", "sub": ["증거", "왜 전도를 해야 하나?", "영원한 영광이 있음"], "book": "다니엘", "chap": 12, "verse": "3", "ref": "다니엘 12:3", "texts": {"krv": "지혜 있는 자는 궁창의 빛과 같이 빛날 것이요 많은 사람을 옳은 데로 돌아오게 한 자는 별과 같이 영원토록 비취리라", "kkjv": "지혜로운 자들은 궁창의 광채같이 빛나고 많은 사람을 의로 돌아서게 하는 자들은 별들과 같이 영원무궁토록 빛나리라.", "web": "Those who are wise shall shine as the brightness of the expanse; and those who turn many to righteousness as the stars forever and ever."}}, {"id": 1409, "coll": "DEP 242구절", "sub": ["증거", "어떻게 전도 해야 하나?", "먼저 주님을 따를 것"], "book": "마태복음", "chap": 4, "verse": "19", "ref": "마태복음 4:19", "texts": {"krv": "말씀하시되 나를 따라 오너라 내가 너희로 사람을 낚는 어부가 되게 하리라 하시니", "kkjv": "그분께서 그들에게 이르시되, 나를 따르라. 내가 너희를 사람들을 낚는 어부가 되게 하리라, 하시니", "web": "He said to them, “Come after me, and I will make you fishers for men.”"}}, {"id": 1410, "coll": "DEP 242구절", "sub": ["증거", "어떻게 전도 해야 하나?", "선한 간증의 삶을 살 것"], "book": "빌립보서", "chap": 2, "verse": "15-16", "ref": "빌립보서 2:15-16", "texts": {"krv": "이는 너희가 흠이 없고 순전하여 어그러지고 거스리는 세대 가운데서 하나님의 흠 없는 자녀로 세상에서 그들 가운데 빛들로 나타내며 생명의 말씀을 밝혀 나의 달음질도 헛되지 아니하고 수고도 헛되지 아니함으로 그리스도의 날에 나로 자랑할 것이 있게 하려 함이라", "kkjv": "이것은 너희가 흠이 없고 무해한 자 곧 구부러지고 비뚤어진 민족 가운데서 책망 받을 것이 없는 하나님의 아들들이 되게 하려 함이라. 그런 민족 가운데서 너희가 세상에서 빛들로 빛나며 생명의 말씀을 제시하나니 이로써 나는 내가 헛되이 달음질하지 아니하고 헛되이 수고하지 아니한 것에 대해 그리스도의 날에 기뻐하리라.", "web": "that you may become blameless and harmless, children of God without defect in the midst of a crooked and perverse generation, among whom you are seen as lights in the world, holding up the word of life; that I may have something to boast in the day of Christ, that I didn’t run in vain nor labor in vain."}}, {"id": 1411, "coll": "DEP 242구절", "sub": ["증거", "어떻게 전도 해야 하나?", "기도할 것"], "book": "에베소서", "chap": 6, "verse": "19", "ref": "에베소서 6:19", "texts": {"krv": "또 나를 위하여 구할 것은 내게 말씀을 주사 나로 입을 벌려 복음의 비밀을 담대히 알리게 하옵소서 할 것이니", "kkjv": "또 나를 위하여는 내게 말하는 것을 허락하사 내가 담대히 입을 열어 복음의 신비를 알리도록 구하라.", "web": "on my behalf, that utterance may be given to me in opening my mouth, to make known with boldness the mystery of the Good News,"}}, {"id": 1412, "coll": "DEP 242구절", "sub": ["증거", "어떻게 전도 해야 하나?", "대답할 것을 예비할 것"], "book": "베드로전서", "chap": 3, "verse": "15", "ref": "베드로전서 3:15", "texts": {"krv": "너희 마음에 그리스도를 주로 삼아 거룩하게 하고 너희 속에 있는 소망에 관한 이유를 묻는 자에게는 대답할 것을 항상 예비하되 온유와 두려움으로 하고", "kkjv": "오직 너희 마음속에서 주 하나님을 거룩히 구별하고 너희에게 너희 속에 있는 소망의 이유를 묻는 모든 사람에게 온유함과 두려움으로 대답할 것을 항상 예비하며", "web": "But sanctify the Lord God in your hearts; and always be ready to give an answer to everyone who asks you a reason concerning the hope that is in you, with humility and fear:"}}, {"id": 1413, "coll": "DEP 242구절", "sub": ["증거", "어떻게 전도 해야 하나?", "간증을 사용할 것"], "book": "요한복음", "chap": 4, "verse": "39", "ref": "요한복음 4:39", "texts": {"krv": "여자의 말이 그가 나의 행한 모든 것을 내게 말하였다 증거하므로 그 동리 중에 많은 사마리아인이 예수를 믿는지라", "kkjv": "¶여자의 말이, 지금까지 내가 행한 모든 일을 그분께서 내게 말하였다, 하고 증언하므로 그 도시의 사마리아 사람들 중의 많은 이들이 그분을 믿더라.", "web": "From that city many of the Samaritans believed in him because of the word of the woman, who testified, “He told me everything that I did.”"}}, {"id": 1414, "coll": "DEP 242구절", "sub": ["증거", "어떻게 전도 해야 하나?", "말씀의 능력을 믿고 전할 것"], "book": "히브리서", "chap": 4, "verse": "12", "ref": "히브리서 4:12", "texts": {"krv": "하나님의 말씀은 살았고 운동력이 있어 죄우에 날선 어떤 검보다도 예리하여 혼과 영과 및 관절과 골수를 찔러 쪼개기까지 하며 또 마음의 생각과 뜻을 감찰하나니", "kkjv": "하나님의 말씀은 살아 있고 권능이 있으며 양날 달린 어떤 검보다도 예리하여 혼과 영과 및 관절과 골수를 찔러 둘로 나누기까지 하고 또 마음의 생각과 의도를 분별하는 분이시니", "web": "For the word of God is living, and active, and sharper than any two-edged sword, and piercing even to the dividing of soul and spirit, of both joints and marrow, and is able to discern the thoughts and intentions of the heart."}}, {"id": 1415, "coll": "DEP 242구절", "sub": ["증거", "어떻게 전도 해야 하나?", "말씀의 결과를 믿고 전할 것"], "book": "이사야", "chap": 55, "verse": "11", "ref": "이사야 55:11", "texts": {"krv": "내 입에서 나가는 말도 헛되이 내게로 돌아오지 아니하고 나의 뜻을 이루며 나의 명하여 보낸 일에 형통하리라", "kkjv": "내 입에서 나아가는 내 말도 그러하여 그것이 헛되이 내게로 되돌아오지 아니하고 내가 기뻐하는 것을 이루며 내가 그 말을 보내어 이루게 하려는 일에서 형통하리니", "web": "so shall my word be that goes out of my mouth: it shall not return to me void, but it shall accomplish that which I please, and it shall prosper in the thing I sent it to do."}}, {"id": 1416, "coll": "DEP 242구절", "sub": ["증거", "어떻게 전도 해야 하나?", "전도의 초점을 예수님께 둘 것"], "book": "고린도전서", "chap": 1, "verse": "23-24", "ref": "고린도전서 1:23-24", "texts": {"krv": "우리는 십자가에 못 박힌 그리스도를 전하니 유대인에게는 거리끼는 것이요 이방인에게는 미련한 것이로되 오직 부르심을 입은 자들에게는 유대인이나 헬라인이나 그리스도는 하나님의 능력이요 하나님의 지혜니라", "kkjv": "우리는 십자가에 못 박히신 그리스도를 선포하노니 그분은 유대인들에게는 걸려 넘어지게 하는 것이요 그리스인들에게는 어리석은 것이로되 부르심을 받은 자들에게는 유대인들에게나 그리스인들에게나 그리스도는 하나님의 권능이시요 하나님의 지혜이시니라.", "web": "but we preach Christ crucified; a stumbling block to Jews, and foolishness to Greeks, but to those who are called, both Jews and Greeks, Christ is the power of God and the wisdom of God."}}, {"id": 1417, "coll": "DEP 242구절", "sub": ["증거", "어떻게 전도 해야 하나?", "능력과 확신으로 전할 것"], "book": "데살로니가전서", "chap": 1, "verse": "5", "ref": "데살로니가전서 1:5", "texts": {"krv": "이는 우리 복음이 말로만 너희에게 이른 것이 아니라 오직 능력과 성령과 큰 확신으로 된 것이니 우리가 너희 가운데서 너희를 위하여 어떠한 사람이 된 것은 너희 아는 바와 같으니라", "kkjv": "이는 우리의 복음이 말로만 너희에게 이르지 아니하고 권능과 성령님과 큰 확신으로 이르렀기 때문이니라. 우리가 너희를 위해 너희 가운데서 어떤 사람이 되었는지는 너희가 아는 바와 같으니라.", "web": "and that our Good News came to you not in word only, but also in power, and in the Holy Spirit, and with much assurance. You know what kind of men we showed ourselves to be among you for your sake."}}, {"id": 1418, "coll": "DEP 242구절", "sub": ["증거", "어떻게 전도 해야 하나?", "영접하도록 도울 것"], "book": "로마서", "chap": 10, "verse": "9-10", "ref": "로마서 10:9-10", "texts": {"krv": "네가 만일 네 입으로 예수를 주로 시인하며 또 하나님께서 그를 죽은 자 가운데서 살리신 것을 네 마음에 믿으면 구원을 얻으리니 사람이 마음으로 믿어 의에 이르고 입으로 시인하여 구원에 이르느니라", "kkjv": "네가 만일 네 입으로 주 예수님을 시인하고 하나님께서 그분을 죽은 자들로부터 살리신 것을 네 마음속으로 믿으면 구원을 받으리니 사람이 마음으로 믿어 의에 이르고 입으로 시인하여 구원에 이르느니라.", "web": "that if you will confess with your mouth that Jesus is Lord, and believe in your heart that God raised him from the dead, you will be saved. For with the heart, one believes unto righteousness; and with the mouth confession is made unto salvation."}}, {"id": 1419, "coll": "DEP 242구절", "sub": ["증거", "어떻게 전도 해야 하나?", "미루지 않도록 도울 것"], "book": "고린도후서", "chap": 6, "verse": "2", "ref": "고린도후서 6:2", "texts": {"krv": "가라사대 내가 은혜 베풀 때에 너를 듣고 구원의 날에 너를 도왔다 하셨으니 보라 지금은 은혜 받을 만한 때요 보라 지금은 구원의 날이로다", "kkjv": "(그분께서 이르시되, 받아 주는 때에 내가 네 말을 들었고 구원의 날에 내가 너를 구조하였노라, 하시나니, 보라, 지금이 받아 주시는 때요, 보라, 지금이 구원의 날이로다.)", "web": "for he says,  “At an acceptable time I listened to you, in a day of salvation I helped you.”    Behold, now is the acceptable time. Behold, now is the day of salvation."}}, {"id": 1420, "coll": "DEP 242구절", "sub": ["증거", "어떻게 전도 해야 하나?", "구원을 확증토록 할 것"], "book": "고린도후서", "chap": 13, "verse": "5", "ref": "고린도후서 13:5", "texts": {"krv": "너희가 믿음에 있는가 너희 자신을 시험하고 너희 자신을 확증하라 예수 그리스도께서 너희 안에 계신 줄을 너희가 스스로 알지 못하느냐 그렇지 않으면 너희가 버리운 자니라", "kkjv": "너희가 믿음 안에 있는지 너희 자신을 살펴보고 너희 자신을 입증하라. 예수 그리스도께서 너희 안에 계시는 줄을 너희가 스스로 알지 못하느냐? 그렇지 않으면 너희는 버림받은 자니라.", "web": "Test your own selves, whether you are in the faith. Test your own selves. Or don’t you know as to your own selves, that Jesus Christ is in you?—unless indeed you are disqualified."}}, {"id": 1421, "coll": "DEP 242구절", "sub": ["증거", "어떻게 전도 해야 하나?", "전도 성경공부를 할 것"], "book": "사도행전", "chap": 17, "verse": "2-3", "ref": "사도행전 17:2-3", "texts": {"krv": "바울이 자기의 규례대로 저희에게로 들어가서 세 안식일에 성경을 가지고 강론하며 뜻을 풀어 그리스도가 해를 받고 죽은 자 가운데서 다시 살아야 할 것을 증명하고 이르되 내가 너희에게 전하는 이 예수가 곧 그리스도라 하니", "kkjv": "바울이 자기 관례대로 그들에게로 들어가 세 안식일에 성경 기록들을 인용하여 그들과 토론하며 그리스도께서 반드시 고난을 받고 죽은 자들로부터 다시 일어났어야 함을 설명하고 주장하며 또 내가 너희에게 선포하는 이 예수님이 그리스도시라 하니", "web": "Paul, as was his custom, went in to them, and for three Sabbath days reasoned with them from the Scriptures, explaining and demonstrating that the Christ had to suffer and rise again from the dead, and saying, “This Jesus, whom I proclaim to you, is the Christ.”"}}, {"id": 1422, "coll": "DEP 242구절", "sub": ["증거", "전도의 모범", "바울"], "book": "사도행전", "chap": 20, "verse": "24", "ref": "사도행전 20:24", "texts": {"krv": "나의 달려갈 길과 주 예수께 받은 사명 곧 하나님의 은혜의 복음 증거하는 일을 마치려 함에는 나의 생명을 조금도 귀한 것으로 여기지 아니하노라", "kkjv": "이 일들 중 어떤 것도 결코 나를 움직이지 못하며 또한 내가 나의 생명도 내게 귀한 것으로 여기지 아니하노니 이것은 내가 나의 달려갈 길과 주 예수님께 받은 사역 곧 하나님의 은혜의 복음을 증언하는 일을 기쁨으로 끝마치고자 함이라.", "web": "But these things don’t count; nor do I hold my life dear to myself, so that I may finish my race with joy, and the ministry which I received from the Lord Jesus, to fully testify to the Good News of the grace of God."}}, {"id": 1423, "coll": "DEP 242구절", "sub": ["증거", "전도의 모범", "빌립"], "book": "사도행전", "chap": 8, "verse": "29-30", "ref": "사도행전 8:29-30", "texts": {"krv": "성령이 빌립더러 이르시되 이 병거로 가까이 나아가라 하시거늘 빌립이 달려가서 선지자 이사야의 글 읽는 것을 듣고 말하되 읽는 것을 깨닫느뇨", "kkjv": "그때에 성령께서 빌립에게 이르시되, 가까이 가서 이 병거에 합류하라, 하시거늘 빌립이 거기로 내시에게로 달려가 그가 대언자 이사야의 글을 읽는 것을 듣고 이르되, 그대가 읽는 것을 깨닫느냐? 하매", "web": "The Spirit said to Philip, “Go near, and join yourself to this chariot.” Philip ran to him, and heard him reading Isaiah the prophet, and said, “Do you understand what you are reading?”"}}, {"id": 1424, "coll": "DEP 242구절", "sub": ["증거", "전도의 모범", "베드로와 요한"], "book": "사도행전", "chap": 4, "verse": "20", "ref": "사도행전 4:20", "texts": {"krv": "우리는 보고 들은 것을 말하지 아니할 수 없다 하니", "kkjv": "우리는 우리가 보고 들은 것들을 말할 수밖에 없노라, 하니라.", "web": "for we can’t help telling the things which we saw and heard.”"}}, {"id": 1425, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "하나님의 형상으로 지음받음"], "book": "창세기", "chap": 1, "verse": "27", "ref": "창세기 1:27", "texts": {"krv": "하나님이 자기 형상 곧 하나님의 형상대로 사람을 창조하시되 남자와 여자를 창조하시고", "kkjv": "이처럼 하나님께서 자신의 형상으로 사람을 창조하시되 하나님의 형상으로 그를 창조하시고 그들을 남성과 여성으로 창조하시니라.", "web": "God created man in his own image. In God’s image he created him; male and female he created them."}}, {"id": 1426, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "죄로 인해 하나님과 분리됨"], "book": "이사야", "chap": 59, "verse": "1-2", "ref": "이사야 59:1-2", "texts": {"krv": "여호와의 손이 짧아 구원치 못하심도 아니요 귀가 둔하여 듣지 못하심도 아니라 오직 너희 죄악이 너희와 너희 하나님 사이를 내었고 너희 죄가 그 얼굴을 가리워서 너희를 듣지 않으시게 함이니", "kkjv": "보라, 주의 손이 짧아져서 구원하지 못하는 것도 아니요, 그분의 귀가 둔하여서 듣지 못하는 것도 아니라. 오직 너희 불법들이 너희와 너희 하나님 사이를 갈라놓았고 너희 죄들이 그분의 얼굴을 너희에게 숨겼으므로 그분께서 듣지 아니하시리라.", "web": "Behold, Yahweh’s hand is not shortened, that it can’t save; neither his ear heavy, that it can’t hear: but your iniquities have separated between you and your God, and your sins have hidden his face from you, so that he will not hear."}}, {"id": 1427, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 상태 – 죄인"], "book": "로마서", "chap": 5, "verse": "12", "ref": "로마서 5:12", "texts": {"krv": "이러므로 한 사람으로 말미암아 죄가 세상에 들어오고 죄로 말미암아 사망이 왔나니 이와 같이 모든 사람이 죄를 지었으므로 사망이 모든 사람에게 이르렀느니라", "kkjv": "그러므로 한 사람으로 말미암아 죄가 세상에 들어오고 죄로 말미암아 사망이 들어왔나니 이와 같이 모든 사람이 죄를 지었으므로 사망이 모든 사람에게 임하였느니라.", "web": "Therefore as sin entered into the world through one man, and death through sin; and so death passed to all men, because all sinned."}}, {"id": 1428, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 상태 – 죄인"], "book": "로마서", "chap": 3, "verse": "23", "ref": "로마서 3:23", "texts": {"krv": "모든 사람이 죄를 범하였으매 하나님의 영광에 이르지 못하더니", "kkjv": "모든 사람이 죄를 지어 하나님의 영광에 이르지 못하더니", "web": "for all have sinned, and fall short of the glory of God;"}}, {"id": 1429, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 상태 – 심판"], "book": "히브리서", "chap": 9, "verse": "27", "ref": "히브리서 9:27", "texts": {"krv": "한번 죽는 것은 사람에게 정하신 것이요 그 후에는 심판이 있으리니", "kkjv": "한 번 죽는 것은 사람들에게 정해진 것이요 이것 뒤에는 심판이 있나니", "web": "Inasmuch as it is appointed for men to die once, and after this, judgment,"}}, {"id": 1430, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 상태 – 심판"], "book": "데살로니가후서", "chap": 1, "verse": "8-9", "ref": "데살로니가후서 1:8-9", "texts": {"krv": "하나님을 모르는 자들과 우리 주 예수의 복음을 복종치 않는 자들에게 형벌을 주시리니 이런 자들이 주의 얼굴과 그의 힘의 영광을 떠나 영원한 멸망의 형벌을 받으리로다", "kkjv": "하나님을 알지 못하는 자들과 우리 주 예수 그리스도의 복음에 순종하지 아니하는 자들에게 타오르는 불로 징벌하실 때에 그리하시리라. 그들은 주의 앞과 그분의 권능의 영광에서 떠나 영존하는 파멸로 형벌을 받으리로다.", "web": "giving vengeance to those who don’t know God, and to those who don’t obey the Good News of our Lord Jesus, who will pay the penalty: eternal destruction from the face of the Lord and from the glory of his might,"}}, {"id": 1431, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 상태 – 사망"], "book": "로마서", "chap": 6, "verse": "23", "ref": "로마서 6:23", "texts": {"krv": "죄의 삯은 사망이요 하나님의 은사는 그리스도 예수 우리 주 안에 있는 영생이니라", "kkjv": "죄의 삯은 사망이나 하나님의 선물은 예수 그리스도 우리 주를 통해 얻는 영원한 생명이니라.", "web": "For the wages of sin is death, but the free gift of God is eternal life in Christ Jesus our Lord."}}, {"id": 1432, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 상태 – 사망"], "book": "요한계시록", "chap": 21, "verse": "8", "ref": "요한계시록 21:8", "texts": {"krv": "그러나 두려워하는 자들과 믿지 아니하는 자들과 흉악한 자들과 살인자들과 행음자들과 술객들과 우상 숭배자들과 모든 거짓말하는 자들은 불과 유황으로 타는 못에 참예하리니 이것이 둘째 사망이라", "kkjv": "그러나 두려워하는 자들과 믿지 않는 자들과 가증한 자들과 살인자들과 음행을 일삼는 자들과 마법사들과 우상 숭배자들과 모든 거짓말쟁이들은 불과 유황으로 타는 호수에서 자기 몫을 받으리니 이것은 둘째 사망이니라.", "web": "But for the cowardly, unbelieving, sinners, abominable, murderers, sexually immoral, sorcerers,idolaters, and all liars, their part is in the lake that burns with fire and sulfur, which is the second death.”"}}, {"id": 1433, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 힘으로 구원받지 못함 – 행위"], "book": "에베소서", "chap": 2, "verse": "8-9", "ref": "에베소서 2:8-9", "texts": {"krv": "너희가 그 은혜를 인하여 믿음으로 말미암아 구원을 얻었나니 이것이 너희에게서 난 것이 아니요 하나님의 선물이라 행위에서 난 것이 아니니 이는 누구든지 자랑치 못하게 함이니라", "kkjv": "너희가 믿음을 통해 은혜로 구원을 받았나니 그것은 너희 자신에게서 난 것이 아니요 하나님의 선물이니라. 행위에서 난 것이 아니니 이것은 아무도 자랑하지 못하게 하려 함이라.", "web": "for by grace you have been saved through faith, and that not of yourselves; it is the gift of God, not of works, that no one would boast."}}, {"id": 1434, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 힘으로 구원받지 못함 – 행위"], "book": "갈라디아서", "chap": 2, "verse": "21", "ref": "갈라디아서 2:21", "texts": {"krv": "내가 하나님의 은혜를 폐하지 아니하노니 만일 의롭게 되는 것이 율법으로 말미암으면 그리스도께서 헛되이 죽으셨느니라", "kkjv": "내가 하나님의 은혜를 헛되게 하지 아니하노니 만일 의가 율법으로 말미암아 온다면 그리스도께서 헛되이 죽으셨느니라.", "web": "I don’t make void the grace of God. For if righteousness is through the law, then Christ died for nothing!”"}}, {"id": 1435, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 힘으로 구원받지 못함 – 종교"], "book": "사도행전", "chap": 4, "verse": "12", "ref": "사도행전 4:12", "texts": {"krv": "다른 이로서는 구원을 얻을 수 없나니 천하 인간에 구원을 얻을 만한 다른 이름을 우리에게 주신 일이 없음이니라 하였더라", "kkjv": "다른 사람 안에는 구원이 없나니 하늘 아래에서 우리를 구원할 다른 이름을 사람들 가운데 주지 아니하셨느니라, 하였더라.", "web": "There is salvation in none other, for neither is there any other name under heaven, that is given among men, by which we must be saved!”"}}, {"id": 1436, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 힘으로 구원받지 못함 – 돈"], "book": "베드로전서", "chap": 1, "verse": "18", "ref": "베드로전서 1:18", "texts": {"krv": "너희가 알거니와 너희 조상의 유전한 망령된 행실에서 구속된 것은 은이나 금 같이 없어질 것으로 한 것이 아니요", "kkjv": "너희가 알거니와 너희 조상들로부터 전통으로 물려받은 너희의 헛된 행실에서 너희가 구속받은 것은 은이나 금같이 썩을 것들로 된 것이 아니요,", "web": "knowing that you were redeemed, not with corruptible things, with silver or gold, from the useless way of life handed down from your fathers,"}}, {"id": 1437, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 힘으로 구원받지 못함 - 신비의 체험"], "book": "고린도전서", "chap": 1, "verse": "22-23", "ref": "고린도전서 1:22-23", "texts": {"krv": "유대인은 표적을 구하고 헬라인은 지혜를 찾으나 우리는 십자가에 못 박힌 그리스도를 전하니 유대인에게는 거리끼는 것이요 이방인에게는 미련한 것이로되", "kkjv": "유대인들은 표적을 요구하고 그리스인들은 지혜를 추구하나 우리는 십자가에 못 박히신 그리스도를 선포하노니 그분은 유대인들에게는 걸려 넘어지게 하는 것이요 그리스인들에게는 어리석은 것이로되", "web": "For Jews ask for signs, Greeks seek after wisdom, but we preach Christ crucified; a stumbling block to Jews, and foolishness to Greeks,"}}, {"id": 1438, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 힘으로 구원받지 못함 - 지혜"], "book": "고린도전서", "chap": 1, "verse": "21", "ref": "고린도전서 1:21", "texts": {"krv": "하나님의 지혜에 있어서는 이 세상이 자기 지혜로 하나님을 알지 못하는 고로 하나님께서 전도의 미련한 것으로 믿는 자들을 구원하시기를 기뻐하셨도다", "kkjv": "하나님의 지혜에 있어서는 세상이 지혜로 하나님을 알지 못하였으므로 하나님께서 복음 선포의 어리석은 것으로 믿는 자들 구원하시는 것을 기뻐하셨도다.", "web": "For seeing that in the wisdom of God, the world through its wisdom didn’t know God, it was God’s good pleasure through the foolishness of the preaching to save those who believe."}}, {"id": 1439, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 힘으로 구원받지 못함 - 학문과 전통"], "book": "골로새서", "chap": 2, "verse": "8", "ref": "골로새서 2:8", "texts": {"krv": "누가 철학과 헛된 속임수로 너희를 노략할까 주의하라 이것이 사람의 유전과 세상의 초등학문을 좇음이요 그리스도를 좇음이 아니니라", "kkjv": "어떤 사람이 철학과 헛된 속임수로 너희를 노략하지 못하도록 조심하라. 그것들은 사람들의 전통과 세상의 유치한 원리들을 따르는 것이요 그리스도를 따르는 것이 아니니라.", "web": "Be careful that you don’t let anyone rob you through his philosophy and vain deceit, after the tradition of men, after the elements of the world, and not after Christ."}}, {"id": 1440, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 힘으로 구원받지 못함 – 혈통"], "book": "요한복음", "chap": 1, "verse": "13", "ref": "요한복음 1:13", "texts": {"krv": "이는 혈통으로나 육정으로나 사람의 뜻으로 나지 아니하고 오직 하나님께로서 난 자들이니라", "kkjv": "이들은 혈통으로나 육신의 뜻으로나 사람의 뜻으로 나지 아니하고 오직 하나님에게서 태어난 자들이니라.", "web": "who were born not of blood, nor of the will of the flesh, nor of the will of man, but of God."}}, {"id": 1441, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 힘으로 구원받지 못함 - 육은 무익함"], "book": "요한복음", "chap": 3, "verse": "6-7", "ref": "요한복음 3:6-7", "texts": {"krv": "육으로 난 것은 육이요 성령으로 난 것은 영이니 내가 네게 거듭나야 하겠다 하는 말을 기이히 여기지 말라", "kkjv": "육에서 난 것은 육이요 성령에게서 난 것은 영이니 내가 네게 이르기를, 너희가 반드시 다시 태어나야 하리라, 한 것에 놀라지 말라.", "web": "That which is born of the flesh is flesh. That which is born of the Spirit is spirit. Don’t marvel that I said to you, ‘You must be born anew.’"}}, {"id": 1442, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 힘으로 구원받지 못함 - 육은 무익함"], "book": "요한복음", "chap": 6, "verse": "63", "ref": "요한복음 6:63", "texts": {"krv": "살리는 것은 영이니 육은 무익하니라 내가 너희에게 이른 말이 영이요 생명이라", "kkjv": "살리는 것은 영이며 육은 아무것도 유익하게 하지 못하느니라. 내가 너희에게 이르는 말들은 곧 영이요 생명이니라.", "web": "It is the spirit who gives life. The flesh profits nothing. The words that I speak to you are spirit, and are life."}}, {"id": 1443, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "하나님의 해결 - 하나님께로 인도하는 다리"], "book": "베드로전서", "chap": 3, "verse": "18", "ref": "베드로전서 3:18", "texts": {"krv": "그리스도께서도 한 번 죄를 위하여 죽으사 의인으로서 불의한 자를 대신하셨으니 이는 우리를 하나님 앞으로 인도하려 하심이라 육체로는 죽임을 당하시고 영으로는 살리심을 받으셨으니", "kkjv": "그리스도께서도 죄들로 인하여 한 번 고난을 받으사 의로운 자로서 불의한 자를 대신하셨으니 이것은 그분께서 육체 안에서 죽임을 당하셨으되 성령으로 말미암아 살아나셔서 우리를 하나님께로 데려가려 하심이라.", "web": "Because Christ also suffered for sins once, the righteous for the unrighteous, that he might bring you to God; being put to death in the flesh, but made alive in the spirit;"}}, {"id": 1444, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "하나님의 해결 - 독생자를 주심"], "book": "요한복음", "chap": 3, "verse": "16", "ref": "요한복음 3:16", "texts": {"krv": "하나님이 세상을 이처럼 사랑하사 독생자를 주셨으니 이는 저를 믿는 자마다 멸망치 않고 영생을 얻게 하려 하심이니라", "kkjv": "¶하나님께서 세상을 이처럼 사랑하사 자신의 독생자를 주셨으니 이것은 누구든지 그를 믿는 자는 멸망하지 않고 영존하는 생명을 얻게 하려 하심이라.", "web": "For God so loved the world, that he gave his one and only Son, that whoever believes in him should not perish, but have eternal life."}}, {"id": 1445, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "하나님의 해결 - 죄를 위해 죽으심"], "book": "로마서", "chap": 5, "verse": "8", "ref": "로마서 5:8", "texts": {"krv": "우리가 아직 죄인 되었을 때에 그리스도께서 우리를 위하여 죽으심으로 하나님께서 우리에게 대한 자기의 사랑을 확증하셨느니라", "kkjv": "우리가 아직 죄인이었을 때에 그리스도께서 우리를 위해 죽으심으로 하나님께서 우리를 향한 자신의 사랑을 당당히 제시하시느니라.", "web": "But God commends his own love toward us, in that while we were yet sinners, Christ died for us."}}, {"id": 1446, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "하나님의 해결 – 부활하심"], "book": "고린도전서", "chap": 15, "verse": "3-4", "ref": "고린도전서 15:3-4", "texts": {"krv": "내가 받은 것을 먼저 너희에게 전하였노니 이는 성경대로 그리스도께서 우리 죄를 위하여 죽으시고 장사 지낸 바 되었다가 성경대로 사흘 만에 다시 살아나사", "kkjv": "내가 또한 받은 것을 무엇보다 먼저 너희에게 전하였노니 그것은 곧 성경 기록대로 그리스도께서 우리의 죄들로 인하여 죽으시고 묻히셨다가 성경 기록대로 셋째 날에 다시 살아나시고", "web": "For I delivered to you first of all that which I also received: that Christ died for our sins according to the Scriptures, that he was buried, that he was raised on the third day according to the Scriptures,"}}, {"id": 1447, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "하나님의 해결 - 모든 죄를 사하심"], "book": "골로새서", "chap": 2, "verse": "13", "ref": "골로새서 2:13", "texts": {"krv": "또 너희의 범죄와 육체의 무할례로 죽었던 너희를 하나님이 그와 함께 살리시고 우리에게 모든 죄를 사하시고", "kkjv": "또 너희의 죄들과 너희 육체의 무할례 가운데서 죽었던 너희를 하나님께서 그분과 함께 살리시고 너희의 모든 범법을 용서하셨으며", "web": "You were dead through your trespasses and the uncircumcision of your flesh. He made you alive together with him, having forgiven us all our trespasses,"}}, {"id": 1448, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 책임 - 듣고 믿어야 함"], "book": "요한복음", "chap": 5, "verse": "24", "ref": "요한복음 5:24", "texts": {"krv": "내가 진실로 진실로 너희에게 이르노니 내 말을 듣고 또 나 보내신 이를 믿는 자는 영생을 얻었고 심판에 이르지 아니하나니 사망에서 생명으로 옮겼느니라", "kkjv": "진실로 진실로 내가 너희에게 이르노니, 내 말을 듣고 또 나를 보내신 분을 믿는 자는 영존하는 생명이 있고 또 정죄에 이르지 아니하리니 사망에서 생명으로 옮겨졌느니라.", "web": "“Most certainly I tell you, he who hears my word, and believes him who sent me, has eternal life, and doesn’t come into judgment, but has passed out of death into life."}}, {"id": 1449, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 책임 - 영접해야 함"], "book": "요한복음", "chap": 1, "verse": "12", "ref": "요한복음 1:12", "texts": {"krv": "영접하는 자 곧 그 이름을 믿는 자들에게는 하나님의 자녀가 되는 권세를 주셨으니", "kkjv": "그분을 받아들인 자들 곧 그분의 이름을 믿는 자들에게는 다 하나님의 아들이 되는 권능을 그분께서 주셨으니", "web": "But as many as received him, to them he gave the right to become God’s children, to those who believe in his name:"}}, {"id": 1450, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 책임 - 영접해야 함"], "book": "요한계시록", "chap": 3, "verse": "20", "ref": "요한계시록 3:20", "texts": {"krv": "볼지어다 내가 문 밖에 서서 두드리노니 누구든지 내 음성을 듣고 문을 열면 내가 그에게로 들어가 그로 더불어 먹고 그는 나로 더불어 먹으리라", "kkjv": "보라, 내가 문에 서서 두드리노니 누구든지 내 음성을 듣고 문을 열면 내가 그에게로 들어가 그와 함께 만찬을 먹고 그는 나와 함께 먹으리라.", "web": "Behold, I stand at the door and knock. If anyone hears my voice and opens the door, then I will come in to him, and will dine with him, and he with me."}}, {"id": 1451, "coll": "DEP 242구절", "sub": ["증거", "다리예화", "인간의 책임 - 영접 기도"], "book": "로마서", "chap": 10, "verse": "9-10", "ref": "로마서 10:9-10", "texts": {"krv": "네가 만일 네 입으로 예수를 주로 시인하며 또 하나님께서 그를 죽은 자 가운데서 살리신 것을 네 마음에 믿으면 구원을 얻으리니 사람이 마음으로 믿어 의에 이르고 입으로 시인하여 구원에 이르느니라", "kkjv": "네가 만일 네 입으로 주 예수님을 시인하고 하나님께서 그분을 죽은 자들로부터 살리신 것을 네 마음속으로 믿으면 구원을 받으리니 사람이 마음으로 믿어 의에 이르고 입으로 시인하여 구원에 이르느니라.", "web": "that if you will confess with your mouth that Jesus is Lord, and believe in your heart that God raised him from the dead, you will be saved. For with the heart, one believes unto righteousness; and with the mouth confession is made unto salvation."}}, {"id": 1452, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정해야 함", "창조의 주 되신 그리스도"], "book": "요한복음", "chap": 1, "verse": "2-3", "ref": "요한복음 1:2-3", "texts": {"krv": "그가 태초에 하나님과 함께 계셨고 만물이 그로 말미암아 지은 바 되었으니 지은 것이 하나도 그가 없이는 된 것이 없느니라", "kkjv": "바로 그분께서 처음에 하나님과 함께 계셨고 모든 것이 그분에 의해 만들어졌으니 만들어진 것 중에 그분 없이 만들어진 것은 하나도 없었더라.", "web": "The same was in the beginning with God. All things were made through him. Without him was not anything made that has been made."}}, {"id": 1453, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정해야 함", "만물의 주 되신 그리스도"], "book": "골로새서", "chap": 1, "verse": "16-17", "ref": "골로새서 1:16-17", "texts": {"krv": "만물이 그에게 창조되되 하늘과 땅에서 보이는 것들과 보이지 않는 것들과 혹은 보좌들이나 주관들이나 정사들이나 권세들이나 만물이 다 그로 말미암고 그를 위하여 창조되었고 또한 그가 만물보다 먼저 계시고 만물이 그 안에 함께 섰느니라", "kkjv": "이는 그분에 의해 모든 것이 창조되었기 때문이라. 하늘에 있는 것들과 땅에 있는 것들, 보이는 것들과 보이지 아니하는 것들 곧 왕좌들이나 통치들이나 정사들이나 권능들이나 모든 것이 그분에 의해 창조되고 그분을 위하여 창조되었노라. 또 그분께서는 모든 것보다 먼저 계시고 모든 것은 그분으로 말미암아 존재하느니라.", "web": "For by him all things were created, in the heavens and on the earth, things visible and things invisible, whether thrones or dominions or principalities or powers; all things have been created through him, and for him. He is before all things, and in him all things are held together."}}, {"id": 1454, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정해야 함", "교회의 머리 되신 그리스도"], "book": "골로새서", "chap": 1, "verse": "18", "ref": "골로새서 1:18", "texts": {"krv": "그는 몸인 교회의 머리라 그가 근본이요 죽은 자들 가운데서 먼저 나신 자니 이는 친히 만물의 으뜸이 되려 하심이요", "kkjv": "그분께서는 몸 곧 교회의 머리시니라. 그분께서 시작이시요 죽은 자들로부터 처음 난 자이시니 이것은 그분께서 모든 것에서 으뜸이 되려 하심이라.", "web": "He is the head of the body, the assembly, who is the beginning, the firstborn from the dead; that in all things he might have the preeminence."}}, {"id": 1455, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정해야 함", "모든 권세 위에 뛰어나신 그리스도"], "book": "에베소서", "chap": 1, "verse": "21", "ref": "에베소서 1:21", "texts": {"krv": "모든 정사와 권세와 능력과 주관하는 자와 이 세상뿐 아니라 오는 세상에 일컫는 모든 이름 위에 뛰어나게 하시고", "kkjv": "그분을 모든 정사와 권능과 강력과 통치와 이 세상뿐만 아니라 오는 세상에서 불리는 모든 이름보다 훨씬 위에 두셨고", "web": "far above all rule, and authority, and power, and dominion, and every name that is named, not only in this age, but also in that which is to come."}}, {"id": 1456, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정해야 함", "모든 사람의 주님 되신 그리스도"], "book": "빌립보서", "chap": 2, "verse": "10-11", "ref": "빌립보서 2:10-11", "texts": {"krv": "하늘에 있는 자들과 땅에 있는 자들과 땅 아래 있는 자들로 모든 무릎을 예수의 이름에 꿇게 하시고 모든 입으로 예수 그리스도를 주라 시인하여 하나님 아버지께 영광을 돌리게 하셨느니라", "kkjv": "하늘에 있는 것들과 땅에 있는 것들과 땅 아래 있는 것들의 모든 무릎이 예수라는 이름에 굴복하게 하시고 또 모든 혀가 예수 그리스도는 주시라고 시인하여 하나님 아버지께 영광을 돌리게 하셨느니라.", "web": "that at the name of Jesus every knee should bow, of those in heaven, those on earth, and those under the earth, and that every tongue should confess that Jesus Christ is Lord, to the glory of God the Father."}}, {"id": 1457, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정해야 함", "산 자와 죽은 자의 주님 되심"], "book": "로마서", "chap": 14, "verse": "9", "ref": "로마서 14:9", "texts": {"krv": "이를 위하여 그리스도께서 죽었다가 다시 살으셨으니 곧 죽은 자와 산 자의 주가 되려 하심이니라", "kkjv": "이 목적을 위해 그리스도께서 죽으시고 일어나사 다시 살아나셨으니 이것은 그분께서 죽은 자와 산 자의 주가 되려 하심이라.", "web": "For to this end Christ died, rose, and lived again, that he might be Lord of both the dead and the living."}}, {"id": 1458, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정해야 함", "피 값으로 우리를 사심"], "book": "고린도전서", "chap": 6, "verse": "19-20", "ref": "고린도전서 6:19-20", "texts": {"krv": "너희 몸은 너희가 하나님께로부터 받은 바 너희 가운데 계신 성령의 전인 줄을 알지 못하느냐 너희는 너희의 것이 아니라 값으로 산 것이 되었으니 그런즉 너희 몸으로 하나님께 영광을 돌리라", "kkjv": "도대체 무슨 말이냐? 너희 몸이 너희가 하나님에게서 받은바 너희 안에 계신 성령님의 전인 줄을 너희가 알지 못하느냐? 너희는 너희 자신의 것이 아니니 주께서 값을 치르고 너희를 사셨느니라. 그런즉 하나님의 것인 너희 몸과 너희 영으로 하나님께 영광을 돌리라.", "web": "Or don’t you know that your body is a temple of the Holy Spirit which is in you, which you have from God? You are not your own, for you were bought with a price. Therefore glorify God in your body and in your spirit, which are God’s."}}, {"id": 1459, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정해야 함", "헌신의 결단을 할 것"], "book": "고린도후서", "chap": 5, "verse": "15", "ref": "고린도후서 5:15", "texts": {"krv": "저가 모든 사람을 대신하여 죽으심은 산 자들로 하여금 다시는 저희 자신을 위하여 살지 않고 오직 저희를 대신하여 죽었다가 다시 사신 자를 위하여 살게 하려 함이니라", "kkjv": "그분께서 모든 사람을 위하여 죽으신 것은 살아 있는 자들이 이제부터는 자기들을 위하여 살지 아니하고 오직 자기들을 위하여 죽었다가 다시 일어나신 분을 위하여 살게 하려 함이니라.", "web": "He died for all, that those who live should no longer live to themselves, but to him who for their sakes died and rose again."}}, {"id": 1460, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 축복", "필요를 채워 주심"], "book": "마태복음", "chap": 6, "verse": "33", "ref": "마태복음 6:33", "texts": {"krv": "너희는 먼저 그의 나라와 그의 의를 구하라 그리하면 이 모든 것을 너희에게 더하시리라", "kkjv": "오직 너희는 첫째로 하나님의 왕국과 그분의 의를 구하라. 그리하면 이 모든 것을 너희에게 더하시리라.", "web": "But seek first God’s Kingdom, and his righteousness; and all these things will be given to you as well."}}, {"id": 1461, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 축복", "넘치는 보상"], "book": "마가복음", "chap": 10, "verse": "29-30", "ref": "마가복음 10:29-30", "texts": {"krv": "예수께서 가라사대 내가 진실로 너희에게 이르노니 나와 및 복음을 위하여 집이나 형제나 자매나 어미나 아비나 자식이나 전토를 버린 자는 금세에 있어 집과 형제와 자매와 모친과 자식과 전토를 백 배나 받되 핍박을 겸하여 받고 내세에 영생을 받지 못할 자가 없느니라", "kkjv": "예수님께서 응답하여 이르시되, 진실로 내가 너희에게 이르노니, 나와 복음을 위하여 집이나 형제나 자매나 아버지나 어머니나 아내나 자녀나 토지를 버린 자는 지금 이 시대에서 집과 형제와 자매와 어머니와 자녀와 토지를 백 배나 받되 핍박과 함께 받고 오는 세상에서는 영원한 생명을 받으리라.", "web": "Jesus said, “Most certainly I tell you, there is no one who has left house, or brothers, or sisters, or father, or mother, or wife, or children, or land, for my sake, and for the sake of the Good News, but he will receive one hundred times more now in this time, houses, brothers, sisters, mothers, children, and land, with persecutions; and in the age to come eternal life."}}, {"id": 1462, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 축복", "약속을 주심"], "book": "창세기", "chap": 22, "verse": "16-17", "ref": "창세기 22:16-17", "texts": {"krv": "가라사대 여호와께서 이르시기를 내가 나를 가리켜 맹세하노니 네가 이같이 행하여 네 아들 네 독자를 아끼지 아니하였은즉 내가 네게 큰 복을 주고 네 씨로 그게 성하여 하늘의 별과 같고 바닷가의 모래와 같게 하리니 네 씨가 그 대적의 문을 얻으리라", "kkjv": "이르되, 주가 말하노라. 내가 나를 두고 맹세하였노라. 곧 네가 이 일을 행하여 네 아들 즉 네 유일한 아들을 아끼지 아니하였으므로 내가 네게 복을 주고 복을 주며 또 네 씨를 하늘의 별들같이 바닷가의 모래같이 번성하게 하고 번성하게 하리니 네 씨가 자기 원수들의 문을 소유하리라.", "web": "and said, “I have sworn by myself, says Yahweh, because you have done this thing, and have not withheld your son, your only son, that I will bless you greatly, and I will multiply your seed greatly like the stars of the heavens, and like the sand which is on the seashore. Your seed will possess the gate of his enemies."}}, {"id": 1463, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 축복", "함께해 주심"], "book": "역대상", "chap": 28, "verse": "9", "ref": "역대상 28:9", "texts": {"krv": "내 아들 솔로몬아 너는 네 아비의 하나님을 알고 온전한 마음과 기쁜 뜻으로 섬길지어다 여호와께서는 뭇 마음을 감찰하사 모든 사상을 아시나니 네가 저를 찾으면 만날 것이요 버리면 저가 너를 영원히 버리시리라", "kkjv": "¶내 아들 솔로몬아, 너는 네 아버지의 하나님을 알고 완전한 마음과 자원하는 생각으로 그분을 섬길지어다. 주께서 모든 마음을 살피시고 생각으로 상상하는 모든 것을 아시나니 네가 만일 그분을 찾으면 만날 것이로되 네가 만일 그분을 버리면 그분께서 너를 영원히 버리시리라.", "web": "You, Solomon my son, know the God of your father, and serve him with a perfect heart and with a willing mind; for Yahweh searches all hearts, and understands all the imaginations of the thoughts. If you seek him, he will be found by you; but if you forsake him, he will cast you off forever."}}, {"id": 1464, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 축복", "능력을 베푸심"], "book": "역대하", "chap": 16, "verse": "9상", "ref": "역대하 16:9상", "texts": {"krv": "여호와의 눈은 온 땅을 두루 감찰하사 전심으로 자기에게 향하는 자를 위하여 능력을 베푸시나니 이 일은 왕이 망령되이 행하였은즉 이후부터는 왕에게 전쟁이 있으리이다 하매", "kkjv": "주의 눈은 온 땅을 두루 이리저리 달리며 완전한 마음으로 그분을 향하는 자들을 위하여 그분의 강하심을 보이시나니 이 일로 왕이 어리석게 행하였은즉 이제부터는 왕에게 전쟁이 있으리이다, 하매", "web": "For the eyes of Yahweh run back and forth throughout the whole earth, to show himself strong in the behalf of them whose heart is perfect toward him. Herein you have done foolishly; for from henceforth you shall have wars.”"}}, {"id": 1465, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 축복", "보호해 주심"], "book": "시편", "chap": 91, "verse": "14", "ref": "시편 91:14", "texts": {"krv": "하나님이 가라사대 저가 나를 사랑한즉 내가 저를 건지리라 저가 내 이름을 안즉 내가 저를 높이리라", "kkjv": "그가 내게 사랑을 품었으니 그러므로 내가 그를 건지리라. 그가 내 이름을 알았은즉 내가 그를 높이 세우리라.", "web": "“Because he has set his love on me, therefore I will deliver him. I will set him on high, because he has known my name."}}, {"id": 1466, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 축복", "귀히 여겨 주심"], "book": "사무엘상", "chap": 2, "verse": "30하", "ref": "사무엘상 2:30하", "texts": {"krv": "그러므로 이스라엘의 하나님 나 여호와가 말하노라 내가 전에 네 집과 네 조상의 집이 내 앞에 영영히 행하리라 하였으나 이제 나 여호와가 말하노니 결단코 그렇게 아니하리라 나를 존중히 여기는 자를 내가 존중히 여기고 나를 멸시하는 자를 내가 경멸히 여기리라", "kkjv": "그러므로 주 이스라엘의 하나님이 말하노라. 참으로 내가 말하기를, 네 집과 네 조상의 집이 내 앞에서 영원히 걸으리라, 하였으나 이제 주가 말하노라. 내가 결단코 그리하지 아니하리라. 나를 존중히 여기는 자들을 내가 존중히 여기고 나를 멸시하는 자들을 소홀히 여기리라.", "web": "“Therefore Yahweh, the God of Israel, says, ‘I said indeed that your house, and the house of your father, should walk before me forever.’ But now Yahweh says, ‘Be it far from me; for those who honor me I will honor, and those who despise me shall be lightly esteemed."}}, {"id": 1467, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 영역", "자기 자신"], "book": "누가복음", "chap": 9, "verse": "23", "ref": "누가복음 9:23", "texts": {"krv": "또 무리에게 이르시되 아무든지 나를 따라 오려거든 자기를 부인하고 날마다 제 십자가를 지고 나를 좇을 것이니라", "kkjv": "¶또 그분께서 그들 모두에게 이르시되, 어떤 사람이 나를 따라오려거든 자기를 부인하고 날마다 자기 십자가를 지고 나를 따를지니라.", "web": "He said to all, “If anyone desires to come after me, let him deny himself, take up his cross,and follow me."}}, {"id": 1468, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 영역", "대인 관계"], "book": "잠언", "chap": 16, "verse": "7", "ref": "잠언 16:7", "texts": {"krv": "사람의 행위가 여호와를 기쁘시게 하면 그 사람의 원수라도 그로 더불어 화목하게 하시느니라", "kkjv": "사람의 길들이 주를 기쁘게 하면 그분께서 그의 원수들까지도 그와 화목하게 하시느니라.", "web": "When a man’s ways please Yahweh, he makes even his enemies to be at peace with him."}}, {"id": 1469, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 영역", "장래 진로"], "book": "잠언", "chap": 3, "verse": "5-6", "ref": "잠언 3:5-6", "texts": {"krv": "너는 마음을 다하여 여호와를 의뢰하고 네 명철을 의지하지 말라 너는 범사에 그를 인정하라 그리하면 네 길을 지도하시리라", "kkjv": "¶네 마음을 다하여 주를 신뢰하고 네 자신의 명철을 의지하지 말지어다. 네 모든 길에서 그분을 인정하라. 그리하면 그분께서 네 행로들을 지도하시리라.", "web": "Trust in Yahweh with all your heart, and don’t lean on your own understanding. In all your ways acknowledge him, and he will make your paths straight."}}, {"id": 1470, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 영역", "세상 욕심"], "book": "에베소서", "chap": 4, "verse": "22-24", "ref": "에베소서 4:22-24", "texts": {"krv": "너희는 유혹의 욕심을 따라 썩어져 가는 구습을 좇는 옛 사람을 벗어버리고 오직 심령으로 새롭게 되어 하나님을 따라 의와 진리의 거룩함으로 지으심을 받은 새 사람을 입으라", "kkjv": "이전 행실에 관하여는 너희가 속이는 것으로 가득한 욕심들에 따라 부패한 옛 사람을 벗어 버릴 것을 가르침을 받았으니 너희의 생각의 영 속에서 새롭게 되라. 또 너희가 하나님을 따라 의와 참된 거룩함으로 창조된 새 사람을 입을 것을 가르침을 받았으니", "web": "that you put away, as concerning your former way of life, the old man, that grows corrupt after the lusts of deceit; and that you be renewed in the spirit of your mind, and put on the new man, who in the likeness of God has been created in righteousness and holiness of truth."}}, {"id": 1471, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 영역", "정욕"], "book": "디모데후서", "chap": 2, "verse": "22", "ref": "디모데후서 2:22", "texts": {"krv": "또한 네가 청년의 정욕을 피하고 주를 깨끗한 마음으로 부르는 자들과 함께 믿음과 사랑과 화평을 좇으라", "kkjv": "또한 청년의 정욕을 피하고 오직 순수한 마음으로 주를 부르는 자들과 함께 의와 믿음과 사랑과 화평을 따르라.", "web": "Flee from youthful lusts; but pursue righteousness, faith, love, and peace with those who call on the Lord out of a pure heart."}}, {"id": 1472, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 영역", "재물"], "book": "디모데전서", "chap": 6, "verse": "7-9", "ref": "디모데전서 6:7-9", "texts": {"krv": "우리가 세상에 아무 것도 가지고 온 것이 없으매 또한 아무 것도 가지고 가지 못하리니 우리가 먹을 것과 입을 것이 있은즉 족한 줄로 알 것이니라 부하려 하는 자들은 시험과 올무와 여러 가지 어리석고 해로운 정욕에 떨어지나니 곧 사람으로 침륜과 멸망에 빠지게 하는 것이라", "kkjv": "우리가 이 세상에 아무것도 가지고 오지 아니하였은즉 아무것도 가지고 가지 못할 것이 확실하니 먹을 것과 입을 것이 있은즉 우리가 그것으로 만족할 것이니라. 그러나 부유하게 되고자 하는 자들은 사람들을 파멸과 멸망에 빠지게 하는 시험과 올무와 여러 가지 어리석고 해로운 욕심에 떨어지느니라.", "web": "For we brought nothing into the world, and we certainly can’t carry anything out. But having food and clothing, we will be content with that. But those who are determined to be rich fall into a temptation and a snare and many foolish and harmful lusts, such as drown men in ruin and destruction."}}, {"id": 1473, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 영역", "시간 사용"], "book": "에베소서", "chap": 5, "verse": "15-16", "ref": "에베소서 5:15-16", "texts": {"krv": "그런즉 너희가 어떻게 행할 것을 자세히 주의하여 지혜 없는 자 같이 말고 오직 지혜 있는 자 같이 하여 세월을 아끼라 때가 악하니라", "kkjv": "그런즉 너희는 주의하여 어리석은 자가 아니라 지혜로운 자로서 조심스럽게 걸어 시간을 되찾으라. 날들이 악하니라.", "web": "Therefore watch carefully how you walk, not as unwise, but as wise; redeeming the time, because the days are evil."}}, {"id": 1474, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정할 때의 영역", "부르심"], "book": "마가복음", "chap": 1, "verse": "20", "ref": "마가복음 1:20", "texts": {"krv": "곧 부르시니 그 아비 세베대를 삯꾼들과 함께 배에 버려두고 예수를 따라가니라", "kkjv": "즉시 그분께서 그들을 부르시니 그들이 자기들의 아버지 세베대를 품꾼들과 함께 배에 남겨 두고 그분을 따라가니라.", "web": "Immediately he called them, and they left their father, Zebedee, in the boat with the hired servants, and went after him."}}, {"id": 1475, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정한 삶의 모범", "바울"], "book": "빌립보서", "chap": 1, "verse": "20", "ref": "빌립보서 1:20", "texts": {"krv": "나의 간절한 기대와 소망을 따라 아무 일에든지 부끄럽지 아니하고 오직 전과 같이 이제도 온전히 담대하여 살든지 죽든지 내 몸에서 그리스도가 존귀히 되게 하려 하나니", "kkjv": "나의 간절한 기대와 소망에 따라 내가 아무 일에든지 부끄러워하지 아니하고 항상 그러하였듯이 지금도 온전히 담대하여 살든지 죽든지 내 몸에서 그리스도를 높이고자 하나니", "web": "according to my earnest expectation and hope, that I will in no way be disappointed, but with all boldness, as always, now also Christ will be magnified in my body, whether by life, or by death."}}, {"id": 1476, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정한 삶의 모범", "디모데"], "book": "빌립보서", "chap": 2, "verse": "21-22", "ref": "빌립보서 2:21-22", "texts": {"krv": "저희가 다 자기 일을 구하고 그리스도 예수의 일을 구하지 아니하되 디모데의 연단을 너희가 아나니 자식이 아비에게 함 같이 나와 함께 복음을 위하여 수고하였느니라", "kkjv": "모든 사람이 자기의 일을 추구하고 예수 그리스도의 일들을 추구하지 아니하되 오직 그의 증거를 너희가 아나니 아들이 아버지에게 하듯 그가 나와 함께 복음 안에서 섬겨 왔느니라.", "web": "For they all seek their own, not the things of Jesus Christ. But you know the proof of him, that, as a child serves a father, so he served with me in furtherance of the Good News."}}, {"id": 1477, "coll": "DEP 242구절", "sub": ["주재권", "주재권을 인정한 삶의 모범", "믿음의 용사들"], "book": "히브리서", "chap": 11, "verse": "36-38상", "ref": "히브리서 11:36-38상", "texts": {"krv": "또 어떤 이들은 희롱과 채찍질뿐 아니라 결박과 옥에 갇히는 시험도 받았으며 돌로 치는 것과 톱으로 켜는 것과 시험과 칼에 죽는 것을 당하고 양과 염소의 가죽을 입고 유리하여 궁핍과 환난과 학대를 받았으니 (이런 사람은 세상이 감당치 못하도다) 저희가 광야와 산중과 암혈과 토굴에 유리하였느니라", "kkjv": "또 다른 이들은 심한 조롱과 채찍질뿐 아니라 참으로 또한 결박과 옥에 갇히는 시련도 겪었으며 돌로 맞기도 하고 톱으로 잘리기도 하며 시험을 받기도 하고 칼로 죽임을 당하기도 하며 양 가죽과 염소 가죽을 입고 떠돌아다니며 궁핍과 고난과 고통을 당하였으니 (세상은 이런 사람들에게 합당치 아니하였느니라.) 그들이 사막과 산과 동굴과 땅굴에서 떠돌아다녔느니라.", "web": "Others were tried by mocking and scourging, yes, moreover by bonds and imprisonment. They were stoned. They were sawn apart. They were tempted. They were slain with the sword. They went around in sheep skins and in goat skins; being destitute, afflicted, ill-treated (of whom the world was not worthy), wandering in deserts, mountains, caves, and the holes of the earth."}}, {"id": 1478, "coll": "DEP 242구절", "sub": ["세계비젼", "세계를 위한 하나님의 관심과 약속"], "book": "창세기", "chap": 12, "verse": "2-3", "ref": "창세기 12:2-3", "texts": {"krv": "내가 너로 큰 민족을 이루고 네게 복을 주어 네 이름을 창대케 하리니 너는 복의 근원이 될지라 너를 축복하는 자에게는 내가 복을 내리고 너를 저주하는 자에게는 내가 저주하리니 땅의 모든 족속이 너를 인하여 복을 얻을 것이니라 하신지라", "kkjv": "내가 너로부터 큰 민족을 만들고 네게 복을 주어 네 이름을 크게 하리니 네가 복이 되리라. 너를 축복하는 자들에게는 내가 복을 주고 너를 저주하는 자에게는 저주를 내리리니 네 안에서 땅의 모든 가족들이 복을 받으리라, 하셨더라.", "web": "I will make of you a great nation. I will bless you and make your name great. You will be a blessing. I will bless those who bless you, and I will curse him who curses you. All of the families of the earth will be blessed in you.”"}}, {"id": 1479, "coll": "DEP 242구절", "sub": ["세계비젼", "세계를 위한 하나님의 관심과 약속"], "book": "이사야", "chap": 49, "verse": "6", "ref": "이사야 49:6", "texts": {"krv": "그가 가라사대 네가 나의 종이 되어 야곱의 지파들을 일으키며 이스라엘 중에 보전된 자를 돌아오게 할 것은 오히려 경한 일이라 내가 또 너로 이방의 빛을 삼아 나의 구원을 베풀어서 땅 끝까지 이르게 하리라", "kkjv": "그분께서 또 이르시되, 네가 나의 종이 되어 야곱의 지파들을 일으켜 세우며 이스라엘에서 보존된 자들을 회복시키는 것은 쉬운 일이라. 내가 또한 너를 이방인들의 빛으로 주리니 이것은 네가 땅 끝까지 이르러 나의 구원이 되게 하려 함이라, 하셨느니라.", "web": "yes, he says, “It is too light a thing that you should be my servant to raise up the tribes of Jacob, and to restore the preserved of Israel: I will also give you for a light to the nations, that you may be my salvation to the end of the earth.”"}}, {"id": 1480, "coll": "DEP 242구절", "sub": ["세계비젼", "지상사명"], "book": "마태복음", "chap": 28, "verse": "19-20", "ref": "마태복음 28:19-20", "texts": {"krv": "그러므로 너희는 가서 모든 족속으로 제자를 삼아 아버지와 아들과 성령의 이름으로 침례를 주고 내가 너희에게 분부한 모든 것을 가르쳐 지키게 하라 볼지어다 내가 세상 끝날까지 너희와 항상 함께 있으리라 하시니라", "kkjv": "¶그러므로 너희는 가서 모든 민족들을 가르치고 아버지와 아들과 성령의 이름으로 그들에게 침례를 주며 무엇이든지 내가 너희에게 명령한 모든 것을 그들에게 가르쳐 지키게 하라. 보라, 내가 세상의 끝까지 항상 너희와 함께 있느니라, 하시니라. 아멘.", "web": "Go,and make disciples of all nations, baptizing them in the name of the Father and of the Son and of the Holy Spirit, teaching them to observe all things that I commanded you. Behold, I am with you always, even to the end of the age.” Amen."}}, {"id": 1481, "coll": "DEP 242구절", "sub": ["세계비젼", "지상사명"], "book": "사도행전", "chap": 1, "verse": "8", "ref": "사도행전 1:8", "texts": {"krv": "오직 성령이 너희에게 임하시면 너희가 권능을 받고 예루살렘과 온 유대와 사마리아 땅 끝까지 이르러 내 증인이 되리라 하시니라", "kkjv": "오직 성령님께서 너희에게 임하신 뒤에 너희가 권능을 받고 예루살렘과 온 유대와 사마리아에서 그리고 땅의 맨 끝 지역까지 이르러 나를 위한 증인이 되리라, 하시니라.", "web": "But you will receive power when the Holy Spirit has come upon you. You will be witnesses to me in Jerusalem, in all Judea and Samaria, and to the uttermost parts of the earth.”"}}, {"id": 1482, "coll": "DEP 242구절", "sub": ["세계비젼", "선교에 헌신할 것"], "book": "이사야", "chap": 6, "verse": "8", "ref": "이사야 6:8", "texts": {"krv": "내가 또 주의 목소리를 들은즉 이르시되 내가 누구를 보내며 누가 우리를 위하여 갈꼬 그 때에 내가 가로되 내가 여기 있나이다 나를 보내소서", "kkjv": "또한 내가 주의 음성을 들었는데 이르시기를, 내가 누구를 보내며 누가 우리를 위하여 갈까? 하시더라. 그때에 내가 이르되, 내가 여기 있나이다. 나를 보내소서, 하였더라.", "web": "I heard the Lord’s voice, saying, “Whom shall I send, and who will go for us?”   Then I said, “Here I am. Send me!”"}}, {"id": 1483, "coll": "DEP 242구절", "sub": ["세계비젼", "선교에 헌신할 것"], "book": "로마서", "chap": 15, "verse": "16", "ref": "로마서 15:16", "texts": {"krv": "이 은혜는 곧 나로 이방인을 위하여 그리스도 예수의 일꾼이 되어 하나님의 복음의 제사장 직무를 하게 하사 이방인을 제물로 드리는 그것이 성령 안에서 거룩하게 되어 받으심직하게 하려 하심이라", "kkjv": "이것은 내가 이방인들을 향한 예수 그리스도의 사역자가 되어 하나님의 복음을 제공함으로써 이방인들을 바치는 일이 성령님을 통해 거룩히 구별되어 주께서 받으실 만하게 하려 함이라.", "web": "that I should be a servant of Christ Jesus to the Gentiles, serving as a priest the Good News of God, that the offering up of the Gentiles might be made acceptable, sanctified by the Holy Spirit."}}, {"id": 1484, "coll": "DEP 242구절", "sub": ["세계비젼", "세계를 위해 기도할 것"], "book": "시편", "chap": 2, "verse": "8", "ref": "시편 2:8", "texts": {"krv": "내게 구하라 내가 열방을 유업으로 주리니 네 소유가 땅 끝까지 이르리로다", "kkjv": "내게 구하라. 그리하면 내가 이교도들을 네게 상속물로 주고 땅의 맨 끝 지역들을 네게 소유물로 주리라.", "web": "Ask of me, and I will give the nations for your inheritance, the uttermost parts of the earth for your possession."}}, {"id": 1485, "coll": "DEP 242구절", "sub": ["세계비젼", "세계를 위해 기도할 것"], "book": "시편", "chap": 57, "verse": "5", "ref": "시편 57:5", "texts": {"krv": "하나님이여 주는 하늘 위에 높이 들리시며 주의 영광은 온 세계 위에 높아지기를 원하나이다", "kkjv": "오 하나님이여, 주께서 하늘들 위로 높여지시며 주의 영광이 온 땅 위로 높여지기 원하나이다.", "web": "Be exalted, God, above the heavens! Let your glory be above all the earth!"}}, {"id": 1486, "coll": "DEP 242구절", "sub": ["세계비젼", "전도할 것"], "book": "디도서", "chap": 1, "verse": "2-3", "ref": "디도서 1:2-3", "texts": {"krv": "영생의 소망을 인함이라 이 영생은 거짓이 없으신 하나님이 영원한 때 전부터 약속하신 것인데 자기 때에 자기의 말씀을 전도로 나타내셨으니 이 전도는 우리 구주 하나님의 명대로 내게 맡기신 것이라", "kkjv": "영원한 생명의 소망 안에서 사도가 되었는데 이 생명은 거짓말하실 수 없는 하나님께서 세상이 시작되기 전에 약속하셨으나 자신의 말씀은 하나님 곧 우리의 구원자의 명령에 따라 내게 맡겨진 복음 선포를 통하여 정하신 때에 드러내셨느니라.", "web": "in hope of eternal life, which God, who can’t lie, promised before time began; but in his own time revealed his word in the message with which I was entrusted according to the commandment of God our Savior;"}}, {"id": 1487, "coll": "DEP 242구절", "sub": ["세계비젼", "전도할 것"], "book": "디모데후서", "chap": 4, "verse": "17", "ref": "디모데후서 4:17", "texts": {"krv": "주께서 내 곁에 서서 나를 강건케 하심은 나로 말미암아 전도의 말씀이 온전히 전파되어 이방인으로 듣게 하려 하심이니 내가 사자의 입에서 건지웠느니라", "kkjv": "그럼에도 불구하고 주께서 나와 함께 서서 나를 강건하게 하셨으니 이것은 나로 말미암아 그 선포한 말씀이 온전히 알려져서 모든 이방인들이 듣게 하려 하심이라. 내가 사자의 입에서 구출되었느니라.", "web": "But the Lord stood by me, and strengthened me, that through me the message might be fully proclaimed, and that all the Gentiles might hear; and I was delivered out of the mouth of the lion."}}, {"id": 1488, "coll": "DEP 242구절", "sub": ["세계비젼", "성장을 도울 것"], "book": "골로새서", "chap": 1, "verse": "28-29", "ref": "골로새서 1:28-29", "texts": {"krv": "우리가 그를 전파하여 각 사람을 권하고 모든 지혜로 각 사람을 가르침은 각 사람을 그리스도 안에서 완전한 자로 세우려 함이니 이를 위하여 나도 내 속에서 능력으로 역사하시는 이의 역사를 따라 힘을 다하여 수고하노라", "kkjv": "우리가 그분을 선포하며 각 사람에게 경고하고 모든 지혜로 각 사람을 가르침은 우리가 각 사람을 그리스도 예수님 안에서 완전한 자로 드리고자 함이니라. 이 일을 위해 나도 내 속에서 강력하게 일하시는 그분의 활동에 따라 싸우며 수고하노라.", "web": "whom we proclaim, admonishing every man and teaching every man in all wisdom, that we may present every man perfect in Christ Jesus; for which I also labor, striving according to his working, which works in me mightily."}}, {"id": 1489, "coll": "DEP 242구절", "sub": ["세계비젼", "성장을 도울 것"], "book": "빌립보서", "chap": 1, "verse": "9-11", "ref": "빌립보서 1:9-11", "texts": {"krv": "내가 기도하노라 너희 사랑을 지식과 모든 총명으로 점점 더 풍성하게 하사 너희로 지극히 선한 것을 분별하며 또 진실하여 허물 없이 그리스도의 날까지 이르고 예수 그리스도로 말미암아 의의 열매가 가득하여 하나님의 영광과 찬송이 되게 하시기를 구하노라", "kkjv": "내가 이것을 기도하노니 곧 너희의 사랑이 지식과 모든 판단에서 여전히 더욱더 풍성해지고 너희가 뛰어난 것들을 입증하며 그리스도의 날까지 성실하고 실족거리가 없는 사람이 되며 예수 그리스도로 말미암은 의의 열매들로 가득하여 하나님의 영광과 찬양이 되기를 구하노라.", "web": "This I pray, that your love may abound yet more and more in knowledge and all discernment; so that you may approve the things that are excellent; that you may be sincere and without offense to the day of Christ; being filled with the fruits of righteousness, which are through Jesus Christ, to the glory and praise of God."}}, {"id": 1490, "coll": "DEP 242구절", "sub": ["세계비젼", "영적 배가를 할 것"], "book": "디모데후서", "chap": 2, "verse": "2", "ref": "디모데후서 2:2", "texts": {"krv": "또 네가 많은 증인 앞에서 내게 들은 바를 충성된 사람들에게 부탁하라 저희가 또 다른 사람들을 가르칠 수 있으리라", "kkjv": "또 네가 많은 증인들 가운데서 내게 들은 것들 바로 그것들을 신실한 사람들에게 맡기라. 그들이 또한 다른 사람들을 가르칠 수 있으리라.", "web": "The things which you have heard from me among many witnesses, commit the same to faithful men, who will be able to teach others also."}}, {"id": 1491, "coll": "DEP 242구절", "sub": ["세계비젼", "영적 배가를 할 것"], "book": "이사야", "chap": 60, "verse": "22", "ref": "이사야 60:22", "texts": {"krv": "그 작은 자가 천을 이루겠고 그 약한 자가 강국을 이룰 것이라 때가 되면 나 여호와가 속히 이루리라", "kkjv": "어린 자 하나가 천 명이 되고 작은 자가 강한 민족이 되리라. 나 주가 자신의 때에 그 일을 속히 이루리라.", "web": "The little one shall become a thousand, and the small one a strong nation; I, Yahweh, will hasten it in its time.”"}}, {"id": 1492, "coll": "DEP 242구절", "sub": ["세계비젼", "단순한 삶과 전심의 삶을 살 것"], "book": "히브리서", "chap": 12, "verse": "1", "ref": "히브리서 12:1", "texts": {"krv": "이러므로 우리에게 구름 같이 둘러싼 허다한 증인들이 있으니 모든 무거운 것과 얽매이기 쉬운 죄를 벗어 버리고 인내로써 우리 앞에 당한 경주를 경주하며", "kkjv": "그러므로 증인들이 이렇게 큰 구름을 이루며 또한 우리를 둘러싸고 있으니 모든 무거운 것과 너무 쉽게 우리를 얽어매는 죄를 우리가 떨쳐 버리고 인내로 우리 앞에 놓인 경주를 달리며", "web": "Therefore let us also, seeing we are surrounded by so great a cloud of witnesses, lay aside every weight and the sin which so easily entangles us, and let us run with patience the race that is set before us,"}}, {"id": 1493, "coll": "DEP 242구절", "sub": ["세계비젼", "단순한 삶과 전심의 삶을 살 것"], "book": "역대하", "chap": 16, "verse": "9상", "ref": "역대하 16:9상", "texts": {"krv": "여호와의 눈은 온 땅을 두루 감찰하사 전심으로 자기에게 향하는 자를 위하여 능력을 베푸시나니 이 일은 왕이 망령되이 행하였은즉 이후부터는 왕에게 전쟁이 있으리이다 하매", "kkjv": "주의 눈은 온 땅을 두루 이리저리 달리며 완전한 마음으로 그분을 향하는 자들을 위하여 그분의 강하심을 보이시나니 이 일로 왕이 어리석게 행하였은즉 이제부터는 왕에게 전쟁이 있으리이다, 하매", "web": "For the eyes of Yahweh run back and forth throughout the whole earth, to show himself strong in the behalf of them whose heart is perfect toward him. Herein you have done foolishly; for from henceforth you shall have wars.”"}}, {"id": 1494, "coll": "DEP 242구절", "sub": ["세계비젼", "약속 성취의 영광"], "book": "하박국", "chap": 2, "verse": "14", "ref": "하박국 2:14", "texts": {"krv": "대저 물이 바다를 덮음 같이 여호와의 영광을 인정하는 것이 세상에 가득하리라", "kkjv": "물들이 바다를 덮는 것 같이 주의 영광을 아는 지식이 땅에 가득하리로다.", "web": "For the earth will be filled with the knowledge of Yahweh’s glory, as the waters cover the sea."}}, {"id": 1495, "coll": "DEP 242구절", "sub": ["세계비젼", "약속 성취의 영광"], "book": "말라기", "chap": 1, "verse": "11", "ref": "말라기 1:11", "texts": {"krv": "만군의 여호와가 이르노라 해 뜨는 곳에서부터 해 지는 곳까지의 이방 민족 중에서 내 이름이 크게 될 것이라 각처에서 내 이름을 위하여 분향하며 깨끗한 제물을 드리리니 이는 내 이름이 이방 민족 중에서 크게 될 것임이니라", "kkjv": "해 뜨는 곳에서부터 해 지는 곳까지의 이방인들 가운데서 내 이름이 크게 되며 모든 곳에서 내 이름을 위해 향을 드리고 정결한 헌물을 드리리니 내 이름이 이교도들 가운데서 크게 되리라. 만군의 주가 말하노라.", "web": "For from the rising of the sun even to the going down of the same, my name is great among the nations, and in every place incense will be offered to my name, and a pure offering: for my name is great among the nations,” says Yahweh of Armies."}}]};
